-- Tibåt Mårqe tables export from torah.db
-- Restore into a torah.db that already has a verses(id) table.

DROP TABLE IF EXISTS tm_sections;
CREATE TABLE tm_sections (
            id         INTEGER PRIMARY KEY,
            book       TEXT NOT NULL,          -- 'I'..'VI'
            section    TEXT NOT NULL,          -- '1','1a','47'...
            book_title TEXT,                   -- Hebrew memar title
            sort_key   INTEGER NOT NULL,
            aramaic    TEXT,
            english    TEXT,
            hebrew     TEXT,
            UNIQUE(book, section)
        );
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (1,'I','35','ספר פליהתה',1000351,'ביספרה סדיר אתהו ספרה שרי אלף בה דינין לפרעה שמע מני אתה ועזר על אהרן כיי מתרגם קדם פרעה מלך דמצרים קום לך אה משה בר ביתי דאנה בעי מלף יתך פליאן שרוי פליאתה דאתה עתיד עבד קדם פרעה מלכה עול את ואהרן לידה וארמי אטרה קמיו ויהי לתנין כמה דאתפך נחש קדמיך וערקת מנה מן רב דחלתה כן הוא בפרי יתעבד ופרעה וכל עבדיו מבלדין מנה כי באדך עמי בה פליאן וכל דו מתקף דינה מתחיל עליו 36] [ נשמע למשה ולאה מן רזי דכתבין והוא אמר לאהרן שרר ית קנומך סב , אטרה דבידי ועל עמי ליד פרעה מלכה כיתך עביד לה תנין קדמיו קעמו תריון בזריזו רבה ואתו אל תרח מלכה בעין מעולה לידה שלם לוכון כדו עבדיו דמלכה בעין אנן מנוכון תסבון לנן ארשו שעתה דע › מ ‹ ותון קעומיה בתרחה עלו מזרזין אנדו ארשו ואמר » ו « לה » אה « מלכה ארשי לנן כדו בגלל יתון תריה דעלו לידך מציבעד ואמרו לך בדיל תשלח ישראל יומה דעלו לידך ורישיון מרכנין ומללו עמך בדחלה רבה יומה קעומים על תרחה דמלכה וריש › י ‹ ון זקיפין כאריה ולביה ואנון בעין מנך רשו עד ייעלו לקדמיך הן בעיך כן אב לון רשו','“The school is set; you are the teacher. Begin therein to teach judgments 
on Pharaoh. Hearken to me and repeat to Aaron, and indeed he will interpret 
before Pharaoh, the king of Egypt. Arise, go, O Moses, son of My house, for I 
intend to teach you wonders. (This is) the beginning of the wonders that you are 
about to do before Pharaoh the king: Go, you and Aaron, to him and throw the 
rod in front of him. It will become a serpent, as it turned into a serpent before 
you and you ﬂed from it out of great fear. Thus will it be; soon will it be made, 
and Pharaoh and all his servants will be frightened by it. Indeed, it is in your 
power to show wonders through it, and the more he hardens (his heart), the 
more the judgment will harden for him.”','"בית הספר מוכן; אתה המורה. החל ללמד בו משפטים על פרעה. שמע אלי וחזור לאהרן, ואכן הוא יתרגם לפני פרעה מלך מצרים. קום לך, משה, בן ביתי, כי בדעתי ללמדך נפלאות. זה הוא ראשית הנפלאות שאתה עתיד לעשות לפני פרעה המלך: לך, אתה ואהרן, אליו, והשלך את המטה לפניו. הוא יהפוך לנחש, כשם שנהפך לנחש לפניך ונסת ממנו מפחד גדול. כך יהיה; מהרה ייעשה, ופרעה וכל עבדיו יבהלו ממנו. אכן, בידך להראות נפלאות על ידו, וכל שיקשה לבו, כן יקשה עליו המשפט."');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (2,'I','13','ספר פליהתה',1000131,'אהנו ריש ממללה חכימיה יהוה אלהה דאבהתכון אתחזי לידי בנהר מדילה ובצביה מגדלה ] יהוה [ אל דאב ] אתחזי [ לי ] די [ ברבין חסדה ובסג › א ‹ י קשטה יה אלה אבהתכ אתחזי לידי בשרירות טובה ובגברות חילה יה אל דאבהתכ אתחזי לידי בנוראות חזוה ויקירות רבינה יה אל דאבהת אתחזי לידי בחסד מדילה ואיקר ממדלה עקר לית לחילה נוף לית לשלטנה והוא האקר לעלמה ונוף לבריתה לית חכים לה שרוי תדיר לא ריש ולא עקב דו ידע מה הוה וידע מה יהי מתחזי בגאו והו כסי מכלה ולא מתחזי זעק לאברהם והתהלך בתרה וליתו מנשי לה ועלמה עלם דרש ליצחק ועקד גרמה קדמיו וליתו מעלם עליו בכל דרין פסק ליעקב פסיקן רברבאן וליתו רמי בה ולא חסך לין מנה בדיל כן דכרן אדכר לקהלה וליתי שבק לון בלבטה דמצראי סכומה מטי ולית בה רוח אריכה דאנה משתלח בגללכון והוא מסק יתכון ממצרים לארעה דאפסק לתלתי שלמיה','This is the beginning of the speech: “O, the elders! The Lord, the God of 
your fathers has revealed Himself to me (Exod. 3:16) by His own light and by the 
will of His greatness. (The Lord, the God of your fathers has revealed Himself to 
me) in the greatness of His grace and the eminence of His truth. The Lord, the 
God of your fathers has revealed Himself to me in the might of His goodness and 
the strength of His power. The Lord, the God of your fathers has revealed Himself 
to me in the awe of His vision and the glory of His greatness. The Lord, the God of 
your fathers has revealed Himself to me in His own favor and His own glory. There 
is no origin to His power, nor oﬀshoot to His dominion, and He is the origin of 
the world and the culmination of the Creation. Nobody knows His beginning. He 
is eternal, He has no beginning and no end. Lo, He knows what has been and 
knows what will be. He reveals Himself in majesty, but is concealed from all and 
never seen. He called to Abraham, and he walked afer Him, and He will not 
forget him for as long as the world exists. He requested Isaac, and he bound 
himself before Him, and He will not ignore him throughout all generations. He 
bestowed on Jacob a great portion and he did not deceive Him and (God) will not 
deny them from him: ‘Therefore I utterly remember the congregation and will 
not leave them within the aﬄiction of the Egyptians.’ The end draws near 
without delay. I am sent on your behalf, and He is going to bring you out of 
Egypt, to the land that He bestowed on the Three Perfect Ones.”','זוהי תחילת הדברים: "הו, הזקנים! ה'' אלוהי אבותיכם נגלה אליי (שמות ג,טז) באורו שלו וברצון גדולתו. (ה'' אלוהי אבותיכם נגלה אליי) בגדולת חסדו וברוממות אמתו. ה'' אלוהי אבותיכם נגלה אליי בעוז טובו ובתוקף כוחו. ה'' אלוהי אבותיכם נגלה אליי באימת מראהו ובכבוד גדולתו. ה'' אלוהי אבותיכם נגלה אליי ברצונו שלו ובכבודו שלו. אין מקור לכוחו ואין ענף לממשלתו, והוא מקור העולם וסוף הבריאה. אין איש יודע את ראשיתו. הוא נצחי, אין לו תחילה ואין לו סוף. הנה, הוא יודע מה שהיה ויודע מה שיהיה. הוא נגלה בהדר, אך נסתר מכל ואינו נראה לעולם. הוא קרא לאברהם, והוא הלך אחריו, ולא ישכחהו כל זמן שהעולם קיים. הוא ביקש את יצחק, והוא כפת את עצמו לפניו, ולא יתעלם ממנו בכל הדורות. הוא הנחיל ליעקב חלק גדול, והוא לא רימה אותו, ו(האל) לא ימנע אותם ממנו: ''לפיכך אני זוכר את העדה זכירה מלאה ולא אעזבה בתוך צרת המצרים.'' הקץ מתקרב ללא עיכוב. אני שלוח בשבילכם, והוא עומד להוציאכם ממצרים אל הארץ שהנחיל לשלושת התמימים."');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (3,'I','70','ספר פליהתה',1000701,'וכד אשכחו מצראי בכוריון קטילין אתו כהלון ליד פרעה וצבעו קדמיו צבעה חיולה ואמרו לה שגר ית עמה הדן ומשה ואהרן קעמין מתחננין לקדם מרון עגלו לבתרון עמו שליחיה משלחין לידון מן אקר פרעה בזריזו רבה קעמו קדמיו ורשותה מכבשה וטרחותה מרכנה שעתה דעלו לגו תרחה אמלי ביתה נהר מן חזבון אמר לון פרעה בנפש מעיסה פוקו מגו עמי אתון וקהליכון זרוז רב עבד משה ואהרן כד אמר לון פרעה פוקו מגו עמי אנפקו משמעין בין כנשת ישראל פוקו בשלם לית בה רוח אריכה התקפו מצראי עליהון בחרון למזרזה למשלחתון מן ארעה שעאלו מנון כל דבעת נפשהתון ונפקו אזלין והנון לבשין יתה שעילה דהות מרירה עד מותר רוקנת משילה ואפלת שעולה שעילה דהות מרירה עד מותר אדירת רוקנה במדורה דמשילה שעילה דהות מרירה עד מותר כתבת על שעולה חוב לא ממחק מלגוה הות רוקנת מצראי ומנה אתעבדת מפולית ישראל ורוקנו למצראי אתמר למשילה והפקד עליהון חובין אתמר לשעולה ארורה יתה שעילתה לעלם דחדדת לן חוב לא ימחק 71] [ ונטלו ברי ישראל מרעמסס לסכות עננה עליהון ואשתה קמיון ושת מון דאלפ נטלין בשעבוד וטובה וחסדה מסמכין לון תמן קביעה הות סכות על שבילה רבה אתר לותה כל געוזיה חסידין הוו כוכביו דאברהם ונהירין מותר גוזליה דשרה מכללין הוו רביו דיצחק משכללין הוו אלימיה דרחל שפירין הוו ארזיו דיעקב וסדירין הוו סדריה דלאה דמיה הות סכות לגן עדן ובני ישראל אילניה דבה דמיה הות בי אשתבעת לתיבו וגוזליה דשרה בקנוניה ודכרה דיצחק מטעיאל לגוה נכש בקרניו כל דין דמכה לה עללתה דבי אשתבעת מדגנה ומצמתה ומגדישה באדרעה דטובה ומכנשה ביד תלתה אריסין יקירין סיעגה בתלתה סיעגין רברבין בעננה ובאשתה וברוחה דקדשה אחד נגד ואחד מניר ואחד מנפנף עללה טבה דלית סוף לרבותה זרעיה בפלשתים ומדגנה בארץ מצר וכתרת מפרנסה מבתר דאזדרעת ארבע מון שנה ותלתים שנה אתשקלו שניה במוזן קשט פלגון בארע מצר ופלגון בארע כנען לסכום אלין שניה אתכנשת ואתעבדת כרי במישרה דסכות טבין הוו יתון אריסי רחותה דגלת רבותון ביני כל בוראי עלמה','When the Egyptians found their ﬁrstborn slain, they all came to 
Pharaoh and cried out a mighty cry before him and said to him: “Let this people 
go.” As Moses and Aaron stood praying before their Master, they looked behind 
them and saw messengers sent to them from Pharaoh in great haste. They stood 
before him, his rebellion subdued, and his obstinacy bent. When they entered 
the gate, the house became ﬁlled with light from their appearance. Pharaoh said 
to them with a depressed soul: “Go forth from among my people (Exod. 12:31), 
you and your congregation.” Moses and Aaron made great haste when Pharaoh 
said to them: “Go forth from among my people.” They went out proclaiming 
amongst the assembly of Israel: “Go forth safely, he (Pharaoh) has no patience.” 
The Egyptians urged them in wrath to make haste sending them away from the 
land. They borrowed from them whatever their souls desired, and set forth while 
they were wearing that borrowing. It was exceedingly bitter. It striped the lender 
and threw down the borrower. A borrowing which was exceedingly bitter – it in-
stalled emptiness in the lender’s house. A borrowing that was exceedingly bitter 
– it wrote on the borrower a guilt that will never be deleted. From it came the 
stripping of the Egyptians and from it came the downfall of Israel. They stripped 
the Egyptians (Exod. 12:36) – it was said concerning the lender; I will bring them 
to account for (their) sins (Exod. 32:34) – it was said concerning the borrower. 
Cursed is that borrowing forever, for it brought an ineﬀaceable sin upon us.','כאשר מצאו המצרים את בכוריהם הרוגים, באו כולם אל פרעה וזעקו לפניו זעקה גדולה ואמרו לו: "שלח את העם הזה." כאשר עמדו משה ואהרן מתפללים לפני אדונם, הביטו מאחוריהם וראו שליחים שנשלחו אליהם מפרעה בחיפזון גדול. עמדו לפניו, מרדו שבור ועקשנותו כפופה. כאשר נכנסו לשער, נתמלא הבית אורה מהופעתם. אמר להם פרעה בנפש עגומה: "צאו מתוך עמי (שמות יב,לא), אתם וקהלכם." מיהרו משה ואהרן מאוד כאשר אמר להם פרעה: "צאו מתוך עמי." יצאו ובישרו בקהל ישראל: "צאו לשלום, אין לו עוד סבלנות." המצרים דחפו אותם בחימה למהר ולצאת מן הארץ. שאלו מהם כל אשר חפצה נפשם, ויצאו כשהם לבושים את אותה שאלה. שאלה מרה עד מאוד הייתה. פשטה את המלווה והפילה את הלווה. שאלה מרה עד מאוד – הכניסה ריק לבית המלווה. שאלה מרה עד מאוד – חרתה על הלווה אשמה שלא תימחה לעולם. ממנה באה שלילת המצרים, וממנה באה נפילת ישראל. וינצלו את המצרים (שמות יב,לו) – נאמר על המלווה; ופקדתי עליהם חטאתם (שמות לב,לד) – נאמר על הלווה. ארורה אותה שאלה לעולם, כי הביאה עלינו חטא שלא יימחה.');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (4,'I','71','ספר פליהתה',1000711,NULL,'And the people of Israel journeyed from Rameses to Sukkot (Exod. 12:37), 
the Cloud above them, the Fire before them. Six hundred thousand journey in 
humility, while Goodness and Grace accompany them. There was Sukkot situ-
ated on the highway, a place where everyone passes. Gracious were the stars of 
Abraham, the ﬂedglings of Sarah were exceedingly shining. Crowned were the 
youngsters of Isaac, perfect were the young of Rachel. Beautiful were the cedar 
trees of Jacob, arranged were the arrays of Leah. Sukkot was like the Garden of 
Eden and the people of Israel like the trees in it. “By Myself I swear” was like an 
ark, and the ﬂedglings of Sarah in its booths. The ram of Isaac was strolling 
therein, goring with his horns any ruler who would smite him. The crop of “By 
Myself I swear” is reaped, gathered and heaped by the arm of the Good One, and 
is collected by three honorable yeomen, hedged in by three great fences: the 
Cloud, the Fire, and the Holy Spirit; one leading, one illumining, and one pro-
tecting. An excellent crop, the greatness of which has no limit, sown in (the land 
of) Philistines and reaped in the land of Egypt, and tarried in cultivation afer 
being sown four hundred and thirty years. The years were weighed in just 
balances (Lev. 19:36): half of them in the land of Egypt and half of them in the 
land of Canaan. At the end of these years, they were gathered together and 
became a foundation in the plain of Sukkot. Good were those yeomen of the 
Divine Favor, whose greatness was revealed among all the creatures of the world.','ובני ישראל נסעו מרעמסס סוכֹּתָה (שמות יב,לז), הענן מעליהם והאש לפניהם. שש מאות אלף נוסעים בענווה, וטוב וחסד מלווים אותם. וסוכות הייתה ממוקמת על דרך המלך, מקום שכל אדם עובר בו. מחוננים היו כוכבי אברהם, וצאצאי שרה זרחו מאוד. מוכתרים היו נערי יצחק, תמימים היו צעירי רחל. יפים היו עצי הארז של יעקב, ערוכים היו מערכות לאה. סוכות הייתה כגן עדן, ובני ישראל כעצים שבו. "בי נשבעתי" היה כתיבה, וצאצאי שרה בסוכותיו. איל יצחק היה מטייל בתוכו, נוגח בקרניו כל שליט שיבוא לפגוע בו. יבול "בי נשבעתי" נקצר ונאסף ונערם בזרוע הטוב, ונאגר בידי שלושה איכרים נכבדים, מוקף בשלושה גדרות גדולות: הענן, האש, ורוח הקודש — אחד מוביל, אחד מאיר, ואחד שומר. יבול נעלה שגדולתו אין לה קץ, נזרע בארץ פלשתים ונקצר בארץ מצרים, ושהה בעיבוד לאחר זריעתו ארבע מאות ושלושים שנה. השנים נשקלו במאזני צדק (ויקרא יט,לו): מחציתן בארץ מצרים ומחציתן בארץ כנען. בסוף שנים אלו נקבצו יחדיו והיו לאבן יסוד בבקעת סוכות. טובים היו אותם איכרי חסד האלוהי, אשר גדולתם נגלתה לפני כל ברואי עולם.');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (5,'I','47','ספר פליהתה',1000471,'קרצו שלמיה הך דאמר לון מרון ואשכחו פרעה קעום על נהרה אסתכל פרעה ועמתון הוה בבלוד רב לא כותה עגל לרבניו ואמר לון בטמר עבדנן עבידה ומה אכשרנן נפקת למיה סכית אערק מנון ואד אנון נפיקין לזימוני לאכה לא אתפג הן בידון ברי מן רזי קסמיה יחכמון בון רזי לבביה לא שכנת רוחי מן צדותה דאתמל והן צדת יומה כי עקתי רבה שלם לך מלכה אמרו נבייה אתינן לידך באגרה מן קשטה כדן אמר יה שלח ית עמי וישמשני אתמל אמרת לנן אקדמו בצפרה ואנה מגיב לכון בשביו דמדע אתינן אכה לידך בזרוז אמר לן מה בחשבתך תעבד עמנן אם מחי אתה למשלח ית עמי דאנן מחין נהרה ויתעבד אדם ואת עתיד משתנק אתה וקהלך וכל ארע מצרים לקיה על דדיך כל דבה רוח חיים לגו מיה מאת ויתסרון ויתעבד אדם','The perfect ones rose early as their Master told them, and they found 
Pharaoh standing by the river. Pharaoh looked and saw them, and was in great 
dismay, never (was there) anything like it. He looked at his chiefains and said to 
them in secret: “We have done a deed and what have we achieved? I went out to 
the water seeking to ﬂee from them, and then they come out to meet me here. I 
am in no doubt that they possess something of the secrets of the magicians, 
through which they know the secrets of the hearts. My spirit would not rest from 
the fear of yesterday, and if I am afraid today, indeed my distress is great.” 
“Greetings to you, O, king”, said the prophets. “We came to you with a message 
from the True One: Thus spoke the Lord: ‘Let My people go, that they may worship 
me’ (Exod. 7:16). Yesterday you said to us: ‘Rise early in the morning and I will 
answer you with soundness of mind.’ We have come now to you in haste; tell us 
what you intend to do with us. If you refuse to let My people go (Exod. 10:4), we 
will strike the river and it will become blood; you are about to be aﬄicted, you 
along with your people. And the whole land of Egypt will be struck because of 
you. Everything in which there is breath of life in the water will die, and (the 
water) will stink and become blood.”','השלמים השכימו כאשר ציוָּם אדונם, ומצאו את פרעה עומד על שפת היאור. פרעה הביט וראה אותם, ונפל עליו פחד גדול, מעולם לא היה דבר כזה. הביט בשריו ואמר להם בסתר: "עשינו מעשה ומה השגנו? יצאתי אל המים לבקש להימלט מהם, והם יוצאים לקראתי כאן. אין בי ספק שיש בידם דבר מסודות החרטומים, שבאמצעותם יודעים הם את סתרי הלבבות. רוחי לא נחה מיראת אתמול, ואם אפחד גם היום, אכן צרתי גדולה." "שלום לך, הו מלך", אמרו הנביאים. "באנו אליך בדבר מן האמת: כה אמר ה'': שַׁלַּח אֶת עַמִּי וְיַעַבְדֻנִי (שמות ז,טז). אתמול אמרת לנו: ''השכימו בבוקר ואענה אתכם בישוב הדעת.'' באנו עתה אליך בחפזה; הגד לנו מה בדעתך לעשות עמנו. אם תמאן לשלח את עמי (שמות י,ד), נכה את היאור ויהפוך לדם; עומד אתה להיענש, אתה עם עמך. וכל ארץ מצרים תינגף בגללך. כל אשר בו נשמת חיים במים ימות, ויבאש ויהפוך לדם."');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (6,'I','6','ספר פליהתה',1000061,'הלא חכמת ית מחיה גבי פריתה מפרעה וכל עמה הלא חכמת ית מחיה כי שלט › נ ‹ י נחת אל מצרים בפלי הלא חכמת ית מחיה אזל אבד סיעתון דמרדה הלא חכמת 24* ית מחיה לית לאוי מנשי מה עבדו רחמי הלא חכמת ית מחיה עיני דאברהם בין אריה ולביה הלא חכמת ית מחיה גוזליה דשרה משלמין לדבב › ה ‹ הלא חכמת ית מחיה פרדס יצחק שביק דלא מפרנס הלא חכמת ית מחיה סחנת יעקב משנתה ובאירה הלא חכמת ית מחיה כלילה דיוסף שביק לית לה ירות הלא חכמת ית מחיה ארע כנען שתיקה מן קראי הלא חכמת ית מחיה ] הרגריזים [ שביק לית בה צלו הלא חכמת ית מחיה דאני מזזע לקיאמי רחמי','“For I know his suﬀering (Exod. 3:7) – take revenge on Pharaoh and all his 
people. For I know his suﬀering – indeed, my ruler goes down to Egypt with a 
wonder. For I know his suﬀering – go and destroy the gang of the rebellious. For I 
know his suﬀering – it is not appropriate to forget what my devotees have done. 
For I know his suﬀering – the eyes of Abraham are between the lion and the lion-
ess. For I know his suﬀering – the ﬂedglings of Sarah are submitted to the enemy. 
For I know his suﬀering – the garden of Isaac is forsaken, without a caretaker. For 
I know his suﬀering – the estate of Jacob is ruined and laid waste. For I know his 
suﬀering – the crown of Joseph is forsaken, it has no heir. For I know his suﬀering 
– the Land of Canaan is silenced from (anyone) who calls (to God). For I know his 
suﬀering – Mount Gerizim is deserted, there is no prayer on it. For I know his suf-
fering – I reinstate the covenants with my devotees.”','"כִּי יָדַעְתִּי אֶת-מַכְאֹבָיו (שמות ג,ז) – קַח נָקָם מִפַּרְעֹה וּמִכָּל עַמּוֹ. כִּי יָדַעְתִּי אֶת-מַכְאֹבָיו – אָכֵן, שַׁלִּיטִי יוֹרֵד לְמִצְרַיִם עִם פֶּלֶא. כִּי יָדַעְתִּי אֶת-מַכְאֹבָיו – לֵךְ וְהַשְׁמֵד אֶת חֶבְרַת הַמּוֹרְדִים. כִּי יָדַעְתִּי אֶת-מַכְאֹבָיו – אֵין זֶה רָאוּי לִשְׁכֹּחַ אֵת אֲשֶׁר עָשׂוּ חֲסִידַי. כִּי יָדַעְתִּי אֶת-מַכְאֹבָיו – עֵינֵי אַבְרָהָם נְתוּנוֹת בֵּין הָאַרְיֵה וְהַלָּבִיא. כִּי יָדַעְתִּי אֶת-מַכְאֹבָיו – גּוֹזָלֵי שָׂרָה נִמְסְרוּ בְּיַד הָאוֹיֵב. כִּי יָדַעְתִּי אֶת-מַכְאֹבָיו – גַּן יִצְחָק נֶעֱזַב, אֵין לוֹ שׁוֹמֵר. כִּי יָדַעְתִּי אֶת-מַכְאֹבָיו – נַחֲלַת יַעֲקֹב חֲרֵבָה וּשְׁמָמָה. כִּי יָדַעְתִּי אֶת-מַכְאֹבָיו – כֶּתֶר יוֹסֵף נֶעֱזַב, אֵין לוֹ יוֹרֵשׁ. כִּי יָדַעְתִּי אֶת-מַכְאֹבָיו – אֶרֶץ כְּנַעַן נֶאֱלְמָה מִקּוֹרֵא. כִּי יָדַעְתִּי אֶת-מַכְאֹבָיו – הַר גְּרִזִּים שָׁמֵם, אֵין עָלָיו תְּפִלָּה. כִּי יָדַעְתִּי אֶת-מַכְאֹבָיו – אֲנִי מַחְזִיר אֶת הַבְּרִיתוֹת עִם חֲסִידַי."');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (7,'I','39','ספר פליהתה',1000391,'אמרו אה מלכה לינן בעין מנך כלום אלא תשמע מנן מה דאמר עבודן אכהן אמר שגר ית ישראל כמה דאמר לך בזבנה קמאה ואנן משגרין בידה כדו לידך עד תשלח ישראל עמנן ידעין אנן לינן אקרך כלום אלא אנן שלחין מן מרה דכל כלום ענה ואמר אהן מלכה דאתון ] שלחי [ ן מדילה מה הי פליתה דבידכו ] ן [ כדו מנ ] ה [ ] אנית בידכון סימן אי , פלי עד יעבד קמיכון כותה לא שגרנן לידך אלא בסימן ופלי עד תהי מהימן דו אלה מהימן אלו הוה אקרך קשט לא שלח בעי מנך אהן עמה משכון הוא בידה מן סגי על מלה וזבנה [ מטי ] וב [ עי ] יפד [ ינה מרה דמשכונה אכה בפנאה והו בעי מסבנה שבי למסחנה','They said: “O king, we want nothing from you, except that you hear 
from us what our Maker has said. Thus He said: ‘Let Israel go’, as he said to you 
the ﬁrst time. We are sent by Him to you that you may let Israel go with us. We 
know that to you we are nothing, but we are sent from the Master of everything.” 
He answered and said: “This king, that you are sent by, what wonder is in your 
hands from him now? If there is any sign or wonder from Him in your hands, let 
the likes of it be performed by your presence.” “He did not send us to you except 
with a sign and a wonder, so that you may believe that He is a truthful God. Had 
truth been with you, He would not have sent to request this people from you. 
They have been a pledge by His authority for a long time, by a word, and time 
has come, and its master wants to redeem it. For the pledge is now in disfavor 
and He wants to take it into His ownership at once.”','אמרו: "הו מלך, אין אנו חפצים ממך דבר, אלא שתשמע מאתנו את אשר אמר עושֵׁנו. כה אמר: ''שלח את ישראל'', כפי שאמר לך בפעם הראשונה. אנו שלוחים ממנו אליך, למען תשלח את ישראל עמנו. אנו יודעים שבעיניך אנו אינם כלום, אך שלוחים אנו מאדון הכל." ענה ואמר: "אותו מלך שנשלחתם מאתו, איזה נפלא יש בידכם ממנו עתה? אם יש בידכם אות או מופת ממנו, שייעשה כמוהו בפניכם." "לא שלח אותנו אליך אלא באות ובמופת, למען תאמין כי הוא אל אמת. לוּ הייתה האמת עמך, לא היה שולח לבקש ממך עם זה. זמן רב היו כמשכון ברשותו, בדבר, והגיע העת, ובעליו רוצה לגאול אותו. כי המשכון נמצא עתה בדִּסְפָּבוֹר, והוא רוצה לקחתו לרשותו מיד."');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (8,'I','12a','ספר פליהתה',1000122,'נסכת לימה ונשמע הך הו ממלל עם נביה רבה משה בדיל פרעה דצמת כל תועבאתה לית בי מטמי לה ובעמה ולא תהי דכהותי קבר לון לעלם הגיבה נביה רבה משה מה אתה מצמת טבין כיתך קטול בישיה ימה הך אמר מן צמת גנואן הך יתעבד קברה בי משה הך אמר לה הן אצטדיך בון כיתך חדי בשלמות בני זכאי ימה הך אמר הוי אנה קבר לטמא בגוני טמואן מה חנאה במגוז טביה משה כאמור לה מדמי מגוזון למי נדה קדש מדכי מכל טמא תמן שתק ימה לקבל אלין מליה וחכם דו מתבחר לכן','Let us listen to the sea and hear as it speaks with the great prophet 
Moses about Pharaoh who amassed all abominations: “I cannot deﬁle myself by 
him and his people. My purity will not be an eternal grave for them.” The great 
prophet Moses replied to it: “Do you not amass good things? Indeed, you will 
slay the wicked.” It was as though the sea was saying: “The one who amasses 
shameful things, how should his grave be made in me?” It was as though Moses 
said to it: “If you are afraid of them (now), be sure that you will rejoice at the safe 
(crossing) of the children of the righteous.” It was as though the sea was saying: 
“I am to be the grave for one made unclean through all kinds of deﬁlements. 
What proﬁt is there in the crossing of the good ones?” It was as though Moses 
said to it: “Their crossing resembles Water of Puriﬁcation, sanctity that cleanses 
from all impurity.” Then the sea became silent at these words and recognized 
that it was chosen for this.','הבה נקשיב לים ונשמע כשהוא מדבר עם משה הנביא הגדול על פרעה שאסף את כל התועבות: "אינני יכול לטמא את עצמי בו ובעמו. טהרתי לא תהיה קבר נצחי להם." ענה לו משה הנביא הגדול: "האם אין אתה אוסף דברים טובים? שכן אתה תמית את הרשעים." והיה כאילו הים אומר: "מי שאוסף דברים מביישים, כיצד ייעשה בי קברו?" והיה כאילו אמר לו משה: "אם אתה ירא מהם עתה, דע כי תשמח על מעבר בני הצדיקים בשלום." והיה כאילו הים אומר: "אני עתיד להיות קבר למי שנטמא בכל מיני טומאות. מה תועלת יש במעבר הטובים?" והיה כאילו אמר לו משה: "מעברם דומה למי טהרה, קדושה שמטהרת מכל טומאה." ואז שתק הים לדברים אלה והכיר שנבחר לכך.');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (9,'I','56','ספר פליהתה',1000561,NULL,'Moses prayed to the Lord and the raven departed. Yet (Pharaoh’s) heart 
stiﬀened, and he did not want to listen to them. The greater the punishments for 
Pharaoh, the more his heart was hardened and his rebellion renewed. Afer this, 
the ﬁfh punishment: the hand of God was stretched forth to kill their cattle. The 
more his heart was hardened, the stronger the punishment on him. Moses testi-
ﬁed to him and swore to him that whenever he lets the people go, no punish-
ment will touch him. He ignored the word and (God) destroyed all their cattle. 
But not one of the cattle of the people of Israel died (Exod. 9:6). Praised be the 
One who does what He wants. And the Lord said to Moses and Aaron, take ashes 
from the kiln, and let Moses throw it toward the heaven (Exod. 9:8). And Moses 
took ashes from the kiln and threw it toward heaven, and it became spreading 
boils by which living bodies were burnt. And a great curse fell amongst all the 
Egyptians. They drank the bitterness of death while they were (still) alive. Their 
bodies died, and their spirits were aﬄicted. And the magicians were not able to 
stand before Moses, for they were shaking because of this sign, their ﬂesh in-
ﬂamed and their tongue confused and their souls oppressed and their bodies 
crushed. But Pharaoh was hardening even as punishment increased upon him, 
and he would not release the people.','הִתְפַּלֵּל מֹשֶׁה אֶל יְהוָה וְהֶעָרוֹב סָר. אַךְ לִבּוֹ הִתְחַזֵּק, וְלֹא אָבָה לִשְׁמֹעַ אֲלֵיהֶם. כָּל שֶׁגָּדְלוּ הָעֳנָשִׁים עַל פַּרְעֹה, כֵּן הִתְאַמֵּץ לִבּוֹ וְחָדְשָׁה מְרִיָּתוֹ. אַחֲרֵי כֵן, הַמַּכָּה הַחֲמִישִׁית: יַד הָאֱלֹהִים נִשְׁטְחָה לְהָמִית אֶת מִקְנֵהֶם. כָּל שֶׁהִתְחַזֵּק לִבּוֹ, כֵּן כָּבְדָה הַמַּכָּה עָלָיו. מֹשֶׁה הֵעִיד בּוֹ וְנִשְׁבַּע לוֹ שֶׁאִם יְשַׁלַּח אֶת הָעָם לֹא תִּגַּע בּוֹ כָּל מַכָּה. בָּזָה לַדָּבָר וַה'' הִשְׁחִית אֶת כָּל מִקְנֵהֶם. וּמִמִּקְנֵה בְּנֵי יִשְׂרָאֵל לֹא מֵת אֶחָד (שמות ט,ו). בָּרוּךְ הָעוֹשֶׂה מַה שֶּׁרְצוֹנוֹ. וַיֹּאמֶר יְהוָה אֶל מֹשֶׁה וְאֶל אַהֲרֹן קְחוּ לָכֶם מְלֹא חָפְנֵיכֶם פִּיחַ כִּבְשָׁן, וּזְרָקוֹ מֹשֶׁה הַשָּׁמַיְמָה (שמות ט,ח). וַיִּקַּח מֹשֶׁה פִּיחַ הַכִּבְשָׁן וַיִּזְרֹק אֹתוֹ הַשָּׁמַיְמָה, וַיְהִי שְׁחִין פֹּרֵחַ אֲשֶׁר שָׂרַף גּוּפוֹת חַיִּים. וְקִלְלָה גְּדוֹלָה נָפְלָה בְּכָל הַמִּצְרִים. שָׁתוּ אֶת מַרֵי הַמָּוֶת כַּאֲשֶׁר עוֹדָם חַיִּים. גּוּפֵיהֶם מֵתוּ וְרוּחוֹתָם נֻגָּעוּ. וְהַחַרְטֻמִּים לֹא יָכְלוּ לַעֲמֹד לִפְנֵי מֹשֶׁה, כִּי הָיוּ רוֹעֲדִים מִפְּנֵי הָאוֹת הַזֶּה, בְּשָׂרָם בּוֹעֵר וּלְשׁוֹנָם נִבְלְלָה וְנַפְשׁוֹתָם מְעֻנּוֹת וּגְוִיָּתָם כְּתוּתָה. אַךְ פַּרְעֹה הִתְחַזֵּק אַף כִּי גָּבְרָה עָלָיו הַמַּכָּה, וְלֹא שִׁלַּח אֶת הָעָם.');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (10,'I','75','ספר פליהתה',1000751,NULL,'The great prophet Moses opened the coﬃn with his right hand and bent 
over him (Joseph’s corpse) and kissed him and wept. At that moment, he began 
to eulogize him and said: “Let your spirit rest, O most honored of the house of 
his father.” And all the congregation stood eulogizing him and said: “Let your 
spirit rest, O Joseph, the liberated.” (Moses said:) “Does your spirit know that 
you are about to be carried by me, while six hundred thousand glorify you? The 
Cloud and the Fire lead (the way) before you, and your oﬀshoots carry you at the 
end of the hundred and forty years during which you were buried in the land of 
Egypt. Afer all these years, you are about to depart to the land which is ap-
pointed to you. Let your spirit rest, O Son of Abundance, Joseph the King, wearer 
of freedom, which granted you great glory during your life and afer your death. 
During your life you were wholly praised, and the sons of the wives bowed down 
before you. And afer your death you are praised even more than that, for you are 
exalted by the Cloud and the Fire.” When Moses ﬁnished his eulogy, he said to 
the House of Ephraim: “You will carry him.” Joshua approached and carried him 
and proclaimed saying: “Let your spirit rest, O father, the most honored of the 
house of his father, the heir who inherited a crown from his own substance and 
bequeathed to his oﬀshoots a chariot of glory.”','משה הנביא הגדול פתח את הארון בידו הימנית, וכפף עצמו עליו ונישקו ובכה. באותה שעה החל לקונן עליו ואמר: "תנוח רוחך, הנכבד שבבית אביו." וכל הקהל עמד מקונן עליו ואמר: "תנוח רוחך, יוסף החופשי." אמר משה: "האם יודעת רוחך שאתה עומד להיות נשא על ידי, בעוד שש מאות אלף מפארים אותך? הענן והאש מובילים לפניך, וצאצאיך נושאים אותך בסוף מאה וארבעים השנים שהיית קבור בארץ מצרים. לאחר כל השנים הללו, אתה עומד לצאת אל הארץ הנועדת לך. תנוח רוחך, בן השפע, יוסף המלך, לובש החירות, שהעניקה לך כבוד גדול בחייך ולאחר מותך. בחייך היית מהולל לגמרי, ובני הנשים כרעו לפניך. ולאחר מותך אתה מהולל אף יותר מכך, כי אתה מוקרן על ידי הענן והאש." כאשר סיים משה את ההספד, אמר לבית אפרים: "אתם תשאו אותו." ניגש יהושע ונשאו וקרא לאמור: "תנוח רוחך, אבי, הנכבד שבבית אביו, היורש שירש כתר מעצמותו והוריש לצאצאיו מרכבת כבוד."');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (11,'I','76','ספר פליהתה',1000761,'שעתה דסתבל ביד בניו הלך עננה ואשתה קמיון ונטלו מן סכות ושרו באתם קריבין לתרח מדברה ביום ההוא מלל יה למשה כון ית עמה לקדם פי חירתה בין מגדלה ובין ימה לקבל בעל צפון ואנה מגיח עליון ברחמו דאנה בעי מיפך לב פרעה עליון כי רדף בתרון וגנותה מתגליה ידע אנה כי אמיר לה במצרים מסרבכין אנון בארעה צניק עליון מדברה קום רדף בתרון עד נעזרנון לתשמישתן כד חסלו מצראי ממקבר בניון אתעירו משנת צוקתון אתו ליד פר מלכה ואמרו לה וילן ומה עבדנן דשגרנן ישראל קום אסר מרכבתך וכהלן נרדף עמך עד נמטינון ונעזר יתון לתשמישתן עבדין אנון לן ולאבהתן מקמינן ולמה נשבקנון יפקון ממצרים ועוד נעזר חנאיתה דשעאלו מנן ושבקונן רוקנין','When he was carried by his sons, the Cloud and the Fire went before 
them. And they moved on from Sukkot, and encamped at Etham (Exod. 13:20), 
near to the gate of the wilderness. On that day, God called Moses: “Prepare the 
people in front of Pi-ha-hiroth, between Migdal and the sea, in front of Baal-
Zephon (Exod. 14:2), and I will ﬁght for them with aﬀection, for I want to turn the 
heart of Pharaoh against them. Therefore, he will pursue them, and his blame 
will be revealed. I know that it is being told to him in Egypt: ‘They are entangled 
in the land; the wilderness has shut them in (Exod. 14:3); stand up, pursue them, 
so that we bring them back to our service.’” When the Egyptians ﬁnished bury-
ing their sons, they woke up from the sleep of their distress. They went to 
Pharaoh the king and said to him: “Woe to us; what is this we have done, that we 
have let Israel go (Exod. 14:5). Stand up, make ready your chariots, and all of us 
will pursue them with you until we reach them and turn them back to our 
service. They are our servants, and those of our fathers before us. Why should we 
let them depart from Egypt? Moreover, we shall return the goods which they bor-
rowed from us and they lef us empty.”','כאשר נשאוהו בניו, הלכו הענן והאש לפניהם. ויסעו מסוכות ויחנו באתם (שמות יג,כ), סמוך לפתח המדבר. באותו יום קרא אלוהים למשה: "הכן את העם מול פי-החירות, בין מגדל ובין הים, מול בעל-צפון (שמות יד,ב), ואני אלחם למענם באהבה, כי חפצתי להפוך את לב פרעה נגדם. לפיכך ירדוף אחריהם, ויתגלה חטאו. יודע אני כי נאמר לו במצרים: ''נבוכים הם בארץ, סגר עליהם המדבר (שמות יד,ג); קום, רדוף אחריהם, ונשיבם לעבודתנו.''" כאשר גמרו המצרים לקבור את בניהם, נעורו משנת צרתם. הלכו אל פרעה המלך ואמרו לו: "אוי לנו; מה זה עשינו, כי שלחנו את ישראל (שמות יד,ה). קום, אסור את מרכבותיך, וכולנו נרדוף אחריהם עמך עד שנשיגם ונשיבם לעבודתנו. עבדינו הם, ועבדי אבותינו לפנינו. מדוע נניחם לצאת ממצרים? ועוד, נחזיר את הרכוש שלוו מאיתנו והניחונו ריקם."');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (12,'I','40','ספר פליהתה',1000401,'אנית בידכון סימן אי פלי גלותון כיי אעמי אנית רזיכון קשיטין אם לא וכד שמע › ו ‹ ממללה דמלכה שררו לבון ואתחילו שריר וארמה אהרן ית אטרה לקדם פרעה ואתעבד תנין מעמיתה דחלה אסתכל פרעה וכל ס › י ‹ עתיו לידה ונפלת עליון אימה רבה פתח תנינה פמה לכבון פרעה הך אתי בעי מבלענה אסתכל פרעה לכל יתיביה ושרי ממל } ל { ך מה יעבד עגל לכתלי ביתה דהוה לג ] וה [ אן הוה יכל יערק אם לית אמרו ית ] יביה [ לפרעה מ ] לכה אנן [ עצירין וכֿ ] ן אתה [ הדה פלי ר ] בה [ כותה לא עמ ] ינן [ בכל ארע מצרי ] ם [ שלח כדו זע ] ק [ לחרשיה כ ] י [ יחכמון לך מה היא הדה פליתה ואנית הות עבידה דחרשין כי בידון מימרה לך','(Pharaoh said:) “If there is in your hand a sign or a wonder, reveal them 
so that I may see whether your mysteries are true or not.” When they heard the 
speech of the king, they strengthened their hearts and invigorated themselves 
greatly, and Aaron threw down his rod before Pharaoh […] and it became a serpent 
(Exod. 7:10) – its sight (was) dread. Pharaoh and all his companies looked at it, 
and great horror fell upon them. The serpent opened its mouth towards Pharaoh 
as if it came wanting to swallow him up. Pharaoh looked at all his counsellors 
and began to seek advice what to do. He looked at the walls of the house in 
which he was to see whether he can ﬂee or not. The counsellors said to Pharaoh 
the king: “We are constricted, and so are you. This is a great wonder, the likes of 
which it we have not seen in the whole land of Egypt. Send now, convoke the 
magicians; surely, they will inform you as to what this wonder is. If it is a matter 
for magicians, indeed, they can tell you.”','(אמר פרעה:) "אם יש בידכם אות או מופת, גלו אותם למען אראה אם אמת סודותיכם אם לאו." כשמשמעו שמעו את דבר המלך, חיזקו את לבם ואמצו את עצמם מאוד, ואהרן השליך את מטהו לפני פרעה [...] ויהי לנחש (שמות ז,י) – ומראהו אימה. פרעה וכל חבריו הביטו בו, ואימה גדולה נפלה עליהם. הנחש פתח את פיו לעבר פרעה כאילו בא רוצה לבולעו. פרעה הביט בכל יועציו והחל לבקש עצה מה לעשות. הביט אל קירות הבית שבו היה לראות אם יוכל לברוח אם לאו. אמרו היועצים אל פרעה המלך: "אנו לחוצים, וכמונו גם אתה. זהו מופת גדול אשר כמותו לא ראינו בכל ארץ מצרים. שלח עתה, כנס את החרטומים; הם ודאי יודיעוך מהו מופת זה. אם דבר הוא לחרטומים, אמנם יוכלו לספר לך."');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (13,'I','45','ספר פליהתה',1000451,'וכד עמה פרעה חרשיה נצעין צרך ישלם נפשה למשה ולאהרן ואמר לון זרזו במפוק אהן תנינה מביתי רוחי מבלדה מנה ואנה בצער רב ומה דאתון בעים כיי עביד לוכון אורכו רוחיכון עלי כי רמשה קריב ולית הוה רוח ביומה למימר ולשמע דאהן תנין חיול ולבי מצדי מנה הפקותה כדו מקבלי אן אמן שעה קבלי כיי מית הוית צדי מנה ללא יבלע כלום וכד בלע אטריה אתוזפת צדו בלע כלה } ולא { ולא אתוזף בה כלום והוא כפן בעי יבלע יתי לית רוחי שכנה והוא עמי במדורה אברי גויתי רקיפין קבלה קשיטה היא הדה פליתה דפרסיכון סבותה ואזלו ואקרצו בצפרה ואני אימר לוכון קשטה דהדה סימנה מחכם בקשט אנתח אה › ר ‹ ן אדה ואנסבה והא הו בידה אטר הך מה דהוה ישתבח עבוד פליהתה','When Pharaoh saw the magicians defeated, he had to yield to Moses 
and to Aaron, and he said to them: “Drive oﬀ at once this serpent from my house. 
My spirit is frightened because of him, and I am in great distress. What you de-
mand, indeed will be done for you. Be patient with me, for evening draws near 
and there is no room during the day to negotiate, for this serpent is mighty, and 
my heart is afraid of it. Drive it away from my presence. If it persists before me for 
a while, indeed I shall die. I was afraid of it lest it swallows up something, and 
when it swallowed the rods, fear increased, for he swallowed all and nothing 
was added to it(s size). And it is (still) hungry, willing to swallow me. My spirit 
will not rest for as long as it stays with me in the (same) abode. The limbs of my 
body are trembling in front of it. This wonder that you have demonstrated is true. 
Take it and go, and rise early in the morning, and I shall tell you the truth. For 
this sign is an assertion of truth.” Aaron stretched out his hand and grabbed it, 
and behold, it (became) in his hand a rod, as it had been (before). Praised be the 
Doer of wonders.','כאשר ראה פרעה את החרטומים מנוצחים, נאלץ להיכנע למשה ולאהרן, ואמר להם: "הרחיקו מיד את הנחש הזה מביתי. רוחי נבהלה מפניו, ואני בצרה גדולה. מה שתדרשו, אכן יֵעשה לכם. היו סבלניים עמי, שכן הערב קרב ואין מקום ביום לנהל משא ומתן, כי הנחש הזה אדיר, ולבי ירא ממנו. הרחיקוהו מלפני. אם יעמוד לפני עוד שעה, אכן אמות. יראתי ממנו שמא יבלע דבר מה, וכאשר בלע את המטות, גברה היראה, כי בלע את הכל ולא נוסף לו. ועדיין הוא רעב ומבקש לבולעי. לא תנוח רוחי כל עוד ישהה עמי תחת קורת גג אחת. אברי גופי רועדים לנגדו. הפלא הזה שהראיתם הוא אמת. קחוהו ולכו, והשכימו בבוקר, ואגיד לכם את האמת. כי האות הזה הוא עדות לאמת." פשט אהרן את ידו ואחזו, והנה נהפך בידו למטה, כאשר היה מתחילה. ברוך עושה הנפלאות.');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (14,'I','59','ספר פליהתה',1000591,NULL,'Then the Lord said to Moses: “Stretch out your hand toward heaven that 
there may be obscure darkness over all the land of Egypt” (Exod. 10:21–22). For 
three days they saw no light. The prison of darkness is an exceedingly bitter 
prison, and all the evildoers were imprisoned in it. An obscure prison with no 
windows for light, and all the prisoners are entangled in it. The Hebrews – 
before them light shines to them, whereas the Egyptians were as if fettered in 
iron behind them. Pharaoh summoned Moses on the third day and cried out be-
fore him, not seeing him: “Open up the prison in which I am, and let me out, and 
I will let your people out of Egypt.” Moses the prophet opened the prison of dark-
ness and let out Pharaoh and the company of Egyptians. He rose early in the 
morning and stood before him and said to him: “Let the people go, as you said.” 
Pharaoh answered him with great treachery: “Leave behind your belongings and 
go to sacriﬁce.” Moses said to him: “We cannot go out except with our cattle, for 
we intend to make oﬀerings from them.” And the heart of Pharaoh was hardened 
and refused to let them go. “Get away from me; never see my face again; for if I 
see you again, I shall order your death.” The Pillar of Cloud descended with 
great glory, and his Master spoke to him, in his hearing.','וַיֹּאמֶר ה'' אֶל מֹשֶׁה: "נְטֵה יָדְךָ עַל הַשָּׁמַיִם וִיהִי חֹשֶׁךְ אֲפֵלָה עַל כָּל אֶרֶץ מִצְרַיִם" (שמות י,כא-כב). שְׁלֹשָׁה יָמִים לֹא רָאוּ אוֹר. בֵּית הַכֶּלֶא שֶׁל הַחֹשֶׁךְ הוּא בֵּית כֶּלֶא מַר בְּיוֹתֵר, וְכָל הָרְשָׁעִים נֶאֶסְרוּ בְתוֹכוֹ. בֵּית כֶּלֶא אָפֵל בְּלִי חַלּוֹנוֹת לָאוֹר, וְכָל הָאֲסוּרִים נְסוּכִים בְּתוֹכוֹ. לִפְנֵי הָעִבְרִים הָאִיר לָהֶם אוֹר, וְהַמִּצְרִים הָיוּ כַּאֲסוּרִים בַּרְזֶל מֵאֲחוֹרֵיהֶם. וַיִּקְרָא פַּרְעֹה לְמֹשֶׁה בַּיּוֹם הַשְּׁלִישִׁי וַיִּצְעַק לְפָנָיו מִבְּלִי לִרְאוֹתוֹ: "פְּתַח אֶת בֵּית הַכֶּלֶא אֲשֶׁר אֲנִי בוֹ, וְהוֹצִיאֵנִי מִמֶּנּוּ, וַאֲנִי אֲשַׁלַּח אֶת עַמְּךָ מִמִּצְרָיִם." פָּתַח מֹשֶׁה הַנָּבִיא אֶת בֵּית כֶּלֶא הַחֹשֶׁךְ וַיּוֹצֵא אֶת פַּרְעֹה וְאֶת קְהַל הַמִּצְרִים. הִשְׁכִּים בַּבֹּקֶר וַיַּעֲמֹד לְפָנָיו וַיֹּאמֶר לוֹ: "שַׁלַּח אֶת הָעָם, כַּאֲשֶׁר אָמָרְתָּ." עָנָה פַּרְעֹה בְּבַגְדָנוּת גְּדוֹלָה: "עִזְבוּ רְכוּשְׁכֶם וּלְכוּ לִזְבֹּחַ." אָמַר לוֹ מֹשֶׁה: "לֹא נוּכַל לָצֵאת אֶלָּא עִם מִקְנֵנוּ, שֶׁכֵּן בְּדַעְתֵּנוּ לְהַקְרִיב מֵהֶם קָרְבָּנוֹת." וַיֶּחֱזַק לֵב פַּרְעֹה וַיְמָאֵן לְשַׁלְּחָם. "לֵךְ מֵעָלַי, הִשָּׁמֶר לְךָ אַל תּוֹסֶף רְאוֹת פָּנַי; כִּי בְּיוֹם רְאֹתְךָ פָנַי אֲצַוֶּה לַהֲמִיתְךָ." וַיֵּרֶד עַמּוּד הֶעָנָן בְּכָבוֹד גָּדוֹל, וַיְדַבֵּר אֲדֹנָיו אֵלָיו לְאָזְנָיו.');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (15,'I','53','ספר פליהתה',1000531,NULL,'And the Lord said to Moses and to Aaron aferwards: “Strike the dust of 
the earth, and it shall turn to gnats (Exod. 8:12)”, and they did as the Lord had 
commanded. The gnats were scampering throughout the Land of Egypt. All the 
dust of the earth turned to gnats (Exod. 8:13), exasperating humans and aﬄicting 
animals. The magicians saw themselves defeated, for they tried to drive them oﬀ 
but failed. When the magicians saw themselves defeated, they said to Pharaoh: 
“This is the ﬁnger of God (Exod, 8:15). It is not in our power to ﬁght with these 
prophets. Know that their God does wonders. They are able to destroy and build, 
while we destroy but cannot build.” Pharaoh said to them: “What is the use of 
you? I am authorized to abolish your allotment from me.” “Do not fatigue your-
self today, calm your anger, for punishments greater than these are prepared for 
you.” He was angry with them, and they departed leaving him disturbed and his 
face distraught.','וַיֹּאמֶר יְהוָה אֶל מֹשֶׁה וְאֶל אַהֲרֹן אַחֲרֵי כֵן: "הַךְ אֶת עֲפַר הָאָרֶץ וְהָיָה לְכִנִּים (שמות ח,יב)", וַיַּעֲשׂוּ כֵּן כַּאֲשֶׁר צִוָּה יְהוָה. הַכִּנִּים שָׁטוּ בְּכָל אֶרֶץ מִצְרַיִם. כָּל עֲפַר הָאָרֶץ הָיָה לְכִנִּים (שמות ח,יג), מַצִּיקִים לִבְנֵי אָדָם וּמְעַנִּים אֶת הַבְּהֵמוֹת. הַחַרְטֻמִּים רָאוּ עַצְמָם מֻכִּים, שֶׁנִּסּוּ לְגָרֵשׁ אֶת הַכִּנִּים אַךְ לֹא יָכְלוּ. כַּאֲשֶׁר רָאוּ הַחַרְטֻמִּים כִּי הֻכּוּ, אָמְרוּ אֶל פַּרְעֹה: "אֶצְבַּע אֱלֹהִים הִוא (שמות ח,טו). אֵין בְּיָדֵנוּ לְהִלָּחֵם עִם נְבִיאִים אֵלֶּה. דַּע כִּי אֱלֹהֵיהֶם עֹשֶׂה נִפְלָאוֹת. בְּיָדָם לְהַשְׁחִית וְלִבְנוֹת, בְּעוֹד אָנוּ מַשְׁחִיתִים אַךְ אֵינֶנּוּ יְכוֹלִים לִבְנוֹת." אָמַר לָהֶם פַּרְעֹה: "מַה תּוֹעַלְתְּכֶם לִי? מֻסְמַךְ אֲנִי לְבַטֵּל אֶת חֶלְקְכֶם מֵאִתִּי." "אַל תִּיגַע עַצְמְךָ הַיּוֹם, הָשֵׁב חֲמָתְךָ, כִּי עֳנָשִׁים גְּדוֹלִים מֵאֵלֶּה מְזֻמָּנִים לְךָ." כָּעַס עֲלֵיהֶם, וְהֵם הָלְכוּ וְהִנִּיחוּהוּ נִסְעָר וּפָנָיו עֲוּוּתִים.');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (16,'I','68','ספר פליהתה',1000681,'אתמר לפרעה מלכה ליליה ההיא קרבה ושבה על ברה נטורין מן רמשה והיאץ עליון הן לא ידמכו שעה חדה ופקדון יסדרו קרבה ברגז אן עמיכון תמן חרב שנין קעמו באפיו וכרזו בקל רם אתו נטוריה ובידון חרבין שלופין שנינין וקעמו עלוי בכורה דפרעה דלא ינכס ומחבלה נחת בפלגות ליליה וקטל כל בכוריה ואנון לא ידעין כל } כל { בכור דהוה לגו ארע מצרים אתחבל ביתה ליליה ואלהה דפרעה עם בכורה ויתון נטוריה דקעמין עלויו כד אמטת שעתה נחת מחבלה אפל אלהיה וקטל בכוריה עגלו בתר כן לבכור פרעה אשקחותה קטיל ואדמה לגוה אכשבי רוחיון ואצטערת לבביון כד עמו יתה קטיל ואלהה נפיל','Pharaoh the king was told: “That night will be war.” He appointed 
guards over his son from the evening and urged them that they must not sleep 
even for a moment and commanded them to ﬁght with ardor: “If you see there a 
sharp sword, stand up against it and shout loudly.” The guards came with 
unsheathed sharp swords in their hands, and they stood by the ﬁrstborn of 
Pharaoh, so that he should not be slain. The Destroyer descended at midnight 
and slew all the ﬁrstborn, while they did not know. Every ﬁrstborn in the land of 
Egypt was slain that night, along with Pharaoh’s god, and his ﬁrstborn, and 
those guards who stood by him. When the time came, the Destroyer descended, 
threw the gods down, and slew the ﬁrstborn. They looked aferwards for the ﬁrst-
born of Pharaoh and found him slain, and his blood still in him. Their spirits 
were oppressed, and their hearts were anguished, when they saw him slain and 
his god thrown down.','הובא דבר לפרעה המלך: "הלילה תהיה מלחמה." הוא מינה שומרים על בנו מן הערב והזהירם שלא יישנו אפילו רגע אחד, וציווה אותם להילחם בחריצות: "אם תראו שם חרב חדה, עמדו נגדה וצעקו בקול גדול." באו השומרים עם חרבות חדות שלופות בידיהם, ועמדו ליד בכור פרעה, כדי שלא יישחט. המשחית ירד בחצות הלילה והרג את כל הבכורות, בעוד הם לא ידעו. כל בכור בארץ מצרים נהרג בלילה ההוא, יחד עם אלוהי פרעה, ובכורו, והשומרים שעמדו לידו. כאשר הגיעה השעה, ירד המשחית, הפיל את האלילים, והמית את הבכורות. חיפשו לאחר מכן את בכור פרעה ומצאוהו מת, ודמו עדיין בתוכו. רוחם כבדה ולבם השתוחח, כאשר ראו אותו שחוט ואלוהיו מוטל ארצה.');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (17,'I','9','ספר פליהתה',1000091,'ויהי לך » דן « סימן אטר מן אשתה גלי בגללך ויהי לך דן סימנה דלגוה שלטנו 27* רבה וחיולה ויהי דן לך סי חרבה דת קטול בה כפורין ויהי לך דן סימ מנה את › משקה ‹ מי בור למצראי ויהי לך דן סימ גבי בה פרית מצראי משלם ויהי לך דן סימ בה אתה עביד גוני פליאן ויהי לך דן סימ בה את קטול גיחון ברה דעדן ויהי לך דן סי בה נהרה עתיד מקבל מחואן ויהי לך דן סי עפרה דארעה מכשב בשלטנו ויהי לך דן סי שומיה עתידין מזדזעין בדילה ויהי לך דן סי לית אנש קעם קמיך והוא באדך','“This will be the sign for you (Exod. 3:13) – a rod from the ﬁre is revealed 
for your sake. This will be the sign for you – in it there is great and powerful au-
thority. This will be the sign for you – the sword with which you will slay the un-
believers. This will be the sign for you – from it you will make the Egyptians drink 
the ‘ordeal water’. This will be the sign for you – (by it) you will take complete 
revenge on the Egyptians. This will be the sign for you – with it you will do all 
kinds of wonders. This will be the sign for you – with it you will kill Gihon, the 
son of Eden. This will be the sign for you – by means of it the river (Nile) is about 
to receive blows. This will be the sign for you – the dust of the earth (Exod. 8:13) 
will be subdued by force. This will be the sign for you – the heavens are about to 
be shaken because of it. This will be the sign for you – no one shall withstand you 
while it is in your hand.”','"וְזֶה לְּךָ הָאוֹת (שמות ג,יג) – מַטֶּה מן האש נגלה למענך. וזה לך האות – בו סמכות גדולה ועצומה. וזה לך האות – החרב שבה תכרית את הכופרים. וזה לך האות – ממנו תשקה את המצרים מי המרים. וזה לך האות – בו תיקח נקמה שלמה מן המצרים. וזה לך האות – בו תעשה כל מיני נפלאות. וזה לך האות – בו תהרוג את גיחון בן עדן. וזה לך האות – על ידו עתיד הנהר (הנילוס) לקבל מכות. וזה לך האות – עֲפַר הָאָרֶץ (שמות ח,יג) יכנע בכוח. וזה לך האות – השמים עתידים להזדעזע בגללו. וזה לך האות – לא יעמוד איש בפניך כל עוד הוא בידך."');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (18,'I','26','ספר פליהתה',1000261,NULL,'Let us set forth a division but not investigate about it (any further), nor 
deviate from the way in which we are set. The Lord said to Aaron go to meet 
(Exod. 4:27) your brother and receive the secrets he holds from him. The Lord 
said to Aaron go to meet your brother, for you are about to become his prophet. 
The Lord said to Aaron go to meet your brother, and surely you will wage with 
him the war (against) Pharaoh the king. The Lord said to Aaron go to meet your 
brother, surely seeing you his heart will be invigorated. The Lord said to Aaron go 
to meet your brother, for his sons and wife departed from him, and he is alone, 
lef on the way all by himself, and if (you) do not welcome him, then his heart 
will be frightened. I know that in your heart there is something greater than this, 
and with you he will prevail in the battle there. I have given him My name so that 
he will not fear, and I extended him a rod out of the ﬁre. I have shown him My 
signs, so that his heart will not sink. Afer all this he said: “I am slow of tongue 
(Exod. 4:10).” Then I said to him concerning you: “He will be your prophet, 
saying and hearing my words.” He was relieved. Happy is the swif one! Arise in 
the morning to meet your brother in the wilderness (afer Exod. 4:27).','הבה נציב חלוקה ולא נחקור בה יותר, ולא נסטה מן הדרך שבה אנו מונחים. ה'' אמר לאהרן לֵךְ לִקְרַאת (שמות ד,כז) אחיך וקבל ממנו את הסודות שברשותו. ה'' אמר לאהרן לֵךְ לִקְרַאת אחיך, כי אתה עתיד להיות נביאו. ה'' אמר לאהרן לֵךְ לִקְרַאת אחיך, ובוודאי תנהל עמו את המלחמה נגד פרעה המלך. ה'' אמר לאהרן לֵךְ לִקְרַאת אחיך, ובוודאי כאשר יראה אותך ייתחזק ליבו. ה'' אמר לאהרן לֵךְ לִקְרַאת אחיך, כי בניו ואשתו פרשו ממנו, והוא לבדו, עזוב בדרך לגמרי, ואם לא תצא לקראתו ייבהל ליבו. אני יודע שבלבך יש דבר גדול מזה, ועמך יצלח בקרב שם. נתתי לו את שמי כדי שלא ייירא, והושטתי לו מטה מתוך האש. הראיתי לו את אותותי כדי שלא ישקע ליבו. ואחרי כל זאת אמר: "כְּבַד פֶּה אָנֹכִי (שמות ד,י)." אז אמרתי לו עליך: "הוא יהיה נביאך, אומר ושומע את דברי." ונרגע. אשרי הממהר! קום בבוקר לקראת אחיך במדבר (על פי שמות ד,כז).');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (19,'I','19','ספר פליהתה',1000191,NULL,'“Begin now to see the second sign.” Again, the Lord said to him (Exod. 
4:6) – great is God who spoke thus, and happy is the hearer on account of what 
he heard from his Master: “Put your hand into your bosom (ibid.) and do not 
tarry, My prophet, hurry in your action.” He heard what his Maker said to him, 
and put it into his bosom with vigorous haste, not knowing what was going to be 
done to it. He brought it out aferwards, as (his Master) told him, and saw it dead 
amongst all his ﬂesh. And he stood there in great, strong fright, contemplating 
his hand, unable to speak. At the (wonder of the) rod he could have ﬂed, without 
his heart turning away from the intensity of its fear. Having in mind his ﬂight 
from the rod, he saw in the (case of) his right (hand) something more tremen-
dous than it. He looked at his right (hand) and the sight of it (was) frightening. 
He was unable to ﬂee (so that he may) not see it. He could not throw his right 
(hand) away from him, for he was appointed to do wonders with it.','"החל נא לראות את האות השני." ויוסף ה'' לדבר אליו (שמות ד,ו) – גדול האל שדיבר כך, ואשרי השומע על אשר שמע מאדונו: "הכנס ידך בחיקך (שם) ואל תתמהמה, נביאי, מהר במעשיך." שמע את אשר אמר לו עושהו, והכניסה לחיקו בחיפזון נמרץ, מבלי לדעת מה עתיד להיעשות לה. הוציאה לאחר מכן כאשר ציווה אדונו, וראה אותה מתה בתוך כל בשרו. עמד שם בפחד גדול ועצום, מתבונן בידו, ואינו יכול לדבר. למראה המטה יכול היה לנוס, ולבו לא נסוג מעוצמת פחדו. כשזכר בלבו את בריחתו מן המטה, ראה בימינו דבר נורא ממנה עוד יותר. הביט בימינו ומראה הייתה מחרידה. לא יכול היה לברוח כדי שלא לראות אותה. לא יכול היה להשליך את ימינו מעליו, שכן היה מיועד לעשות בה נפלאות.');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (20,'I','43','ספר פליהתה',1000431,'קום אסתקף בעודנך אמרו חכימיה לא תדחל מנה קריב הו אזל תקף שבי לבך אמרו מכשפיה יכלין אנחן עבדין כותה לא יתגלגון אלין עליך באהן אנן נעבד כות ] ה [ קבלך אנית דאה פלענ ] תה [ דחרשך אנן אנון ] רישי [ חרשיה דהדה בהתה למלך כותך ישתפל לבך מן עובדה דחרשיה כדו נעבד דמותה לחזותך ואת ידע מנו נצעיה מנן','“Rise, straighten up in your posture”, said the sages. “Do not be afraid 
of it, soon it will depart. Strengthen your heart at once.” The magicians said: 
“We are able to do the like of it. Let these (men) not boast over you with this. We 
shall do the like of it before you. If this is the deed of your magicians, then we are 
the chiefs of the magicians. It is shame for a king like you to have your heart 
lowered because of the deed of the magicians. We shall now do the like of it in 
your presence, and you will know who are the defeated among us.”','"קום, זקוף את קומתך", אמרו החכמים. "אל תירא ממנו, עוד מעט יחלוף. חזק את לבבך מיד." אמרו החרטומים: "ביכולתנו לעשות כמוהו. אל יתפארו עליך האנשים האלה בדבר הזה. נעשה כמוהו לפניך. אם זה מעשה ידי חרטומיך, הרי אנחנו ראשי החרטומים. חרפה היא למלך כמוך להכניע את לבבו מפני מעשה החרטומים. נעשה עתה כמוהו לנגד עיניך, ותדע מי הם המנוצחים מבינינו."');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (21,'I','22','ספר פליהתה',1000221,NULL,'Let us now set forth a great division and relate the words of God and of 
the prophet. And the Lord said to him (Exod. 4:11) with mighty sovereignty, and 
the world was full of fear: “Who has shaped the body and arranged it? Who has 
sealed the spirit within it? Who has founded reason within the spirit? Who has 
made the soul within the heart? Who has advanced the conscience within 
thought? Who has planted the speech in the mouth? Who has made the word ﬂy 
from the voice? Is it not I, the Lord? (ibid.) O My servant, since you know that I 
have done all these (things), why have you answered me with all this talk? If not 
for My longing for you from the beginning, My anger would have reached you. 
Behold, I send your brother to you to meet you, because his tongue is more expe-
rienced than yours. Listen to My words and repeat them to your brother, and he 
will speak to the Egyptians and to the congregation. You will be My second, and 
he will be your prophet (Exod. 7:1). You are the messengers of righteousness, 
(which are) about to reveal the desolation of Egypt. Two great luminaries, Aaron 
and Moses, will illuminate the congregation of Israel. You will take the divine 
rod in your hand and you will not stop, for the time of deliverance draws near.”','נבוא כעת לחלק גדול ונספר את דברי האל ואת דברי הנביא. ויאמר ה'' אליו (שמות ד,יא) בשלטון עז, והעולם היה מלא יראה: "מי עיצב את הגוף וסידרו? מי חתם בתוכו את הרוח? מי ייסד את התבונה בתוך הרוח? מי עשה את הנפש בתוך הלב? מי הקדים את המצפון בתוך המחשבה? מי נטע את הדיבור בפה? מי הגביה את המילה מן הקול? האם לא אני ה''? (שם) הו עבדי, כיוון שאתה יודע שאני עשיתי את כל אלה, מדוע ענית אותי בכל הדברים האלה? אלמלא כיסופיי אליך מראשית, הייתה חרוני מגיעה אליך. הנה אני שולח אליך את אחיך לקראתך, כי לשונו מנוסה משלך. שמע את דברי וחזור עליהם לאחיך, והוא ידבר אל המצרים ואל העדה. אתה תהיה משנה לי, והוא יהיה נביאך (שמות ז,א). אתם הם שליחי הצדק, העתידים לגלות את שממת מצרים. שני מאורות גדולים, אהרן ומשה, יאירו לעדת ישראל. תיקח את מטה האלוהים בידך ולא תחדל, כי עת הגאולה קרבה."');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (22,'I','69','ספר פליהתה',1000691,'והוה לפלגות ליליה ויהוה קטל בכורין טמאין ואלהין מסיבין והוה בפלגות ליליה ויהוה קטל אילנים דהוו רבים על טמתה והוה בפלגות ליליה ויהוה קטל שבשבהתה דהות נציבה על סובתה והוה בפלגות ליליה ויהוה קטל קלולעיה דאקלעו לגו אילני בישתה והוה בפלגות ליליה ויהוה קטל בכורי דהוו מקרבין לשידין והוה בפלגות ליליה ויהוה קטל אלהין שתיקין וסגודיון אלילין והוה בפלגות ליליה ויהוה קטל עללתה דהות זריעה זרעה דכובין הלא לית בית דלית תמן מית וצבעתה ראמה ומתחילה עד מותר בניו דחם בקצף רב וקשי ובניו דשם תמן בחדו רבה בניו דחם לגו מצרים קטילים ובכוריו דשם מקדשין באתרון פרדיסה דחם מחרב ברגזה ופרדיסה דשם מפרנס בטובה אלהה דחם מפל בדינה ואלהה דשם מתרבי ומתרומם אדגנה דחם עביד בפרי יביש ואדגן דשם עביד בפרי רטיב מלכותה דחם תמן חסילה ומלכותה דשם תמן משריאה הלא לית בית דלית תמן מית בכירין קטילין ואלהיון מפלין הלא לית בית דלית תמן מית נהרה מסתלק מנון וחשכה רמי עליהון הלא לית בית דלית תמן מית צבעתה ראמה ואיעשה אחיד הלא לית בית דלית תמן מית דרש תרח רגזה פתיח על דדיון הלא לית בית דלית תמן מית אפלותה דסדם מפלה עליהון','At midnight (Exod. 12:29) the Lord slew unclean ﬁrstborn and impure 
gods. At midnight ] the Lord destroyed trees that grew on impurity. At midnight – 
the Lord destroyed the branches planted on deﬁlement. At midnight – the Lord 
destroyed sprouts that stemmed amongst the trees of wickedness. At midnight – 
the Lord slew ﬁrstborn who were oﬀering to demons. At midnight – the Lord slew 
mute (gods) and their deceiving images. At midnight – the Lord destroyed the 
crops that were sown amidst a sowing of thorns. For there is no house where there 
is not someone dead (Exod. 12:30) – the outcry is high and becomes over-
whelmingly stronger. The children of Ham fall under a great and hard wrath, 
while the children of Shem are there in great joy. The children of Ham are slain 
within Egypt, while the ﬁrstborn of Shem are sanctiﬁed in their stead. The gar-
den of Ham is destroyed by wrath, while the garden of Shem subsists well. The 
god of Ham is thrown down, while the God of Shem is gloriﬁed and exalted. The 
seed of Ham became quickly dry, while the seed of Shem became quickly fresh. 
The kingdom of Ham ends, while the kingdom of Shem begins. For there is no 
house where there is not someone dead – ﬁrstborn are slain, and their gods are 
thrown down. For there is no house where there is not someone dead – the light is 
withdrawn from them and the darkness is cast upon them. For there is no house 
where there is not someone dead – the outcry is high and despair seizes. For there 
is no house where there is not someone dead – the door of the gate of wrath is 
opened for them. For there is no house where there is not someone dead – the 
downfall of Sodom befell them.','בחצות הלילה (שמות יב,כט) הכה ה'' בכורות טמאים ואלים אטומים. בחצות הלילה – ה'' השחית עצים שגדלו בטומאה. בחצות הלילה – ה'' השחית ענפים שנטעו בשיקוץ. בחצות הלילה – ה'' השחית נצרים שצמחו בין עצי הרשע. בחצות הלילה – ה'' הרג בכורות שהקריבו לשדים. בחצות הלילה – ה'' הרג אילמים וצלמי מרמתם. בחצות הלילה – ה'' השחית יבול שנזרע בתוך זריעת קוצים. כי אין בית אשר אין שם מת (שמות יב,ל) – הצעקה גבוהה ומתחזקת עד מאוד. בני חם נופלים תחת חרון גדול וקשה, ובני שם שם בשמחה רבה. בני חם נהרגים בתוך מצרים, ובכורות שם מתקדשים תחתם. גן חם חרב בזעם, וגן שם עומד בטוב. אלוהי חם מוטל ארצה, ואלוהי שם מפואר ומרומם. זרע חם יבש במהרה, וזרע שם התחדש במהרה. ממלכת חם נגמרת וממלכת שם מתחילה. כי אין בית אשר אין שם מת – בכורות נהרגים ואליליהם מוטלים ארצה. כי אין בית אשר אין שם מת – האור נסתלק מהם והחושך ירד עליהם. כי אין בית אשר אין שם מת – הצעקה גבוהה והייאוש אוחז. כי אין בית אשר אין שם מת – דלת שער החרון נפתחה להם. כי אין בית אשר אין שם מת – מפלת סדום פקדה אותם.');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (23,'I','21','ספר פליהתה',1000211,'כד שמע משה אלין מליה אגיב בדחלה יתרה עבדך אנה אה מרה דעלמה ליתי עצי למליך לעלם עלמין אלא דאנה בעי מימר קמיך מהי רגילותי דאנה מסחן לה ידע אנה בלבי כל דאתה אמר לי אלא דרגילותי זעורה מן הדה לשני יקיר בממללה ולית לי רגילו בהדה שלטנותה נהי עלי אמר ושמע עמך בפרי ועם פרעה מלכה לית בי מימר ומשמע ליתו אקרי חיול מנך לא אמרת לית בי מימר ומשמע עמך מן עדן סגי נפקת ממצרים למדין ומה דהוה בידי מרזיון נשית בבית פרעה הרבית ואגמלת ואנפקת רבי לא אשתננת לשון ביש ולית לי בה רגילו הלא יקיר פם ויקיר לשן אנה 22] [ נתן אפרשו גדילה ונימר ממללה דאלהים ונביה ואמר יה לה בשלטנו חיולה ועלמה מלי דחלה מן צער גויתה וסדרה מן חתם רוחה לגוה מן יסד מדעה ברוחה מן עבד נפשה בלבה מן אסע יצרה בחשבה מן נצב לשנה בפמה מן אפרע ממללה מקלה אלא אנה יהוה אה עבדי מן דאת ידע הלא אנה עבדת כל אלין למה הגיבתני בכל הדה מימרה אלולי ריוחתי בך מקדם אמטה בך רגזי האנה משגר לך אחוך לזימונך כי לשנה מרגל סגי מנך שמע אתה ממללי ועזרין על אחוך והוא ימלל מצראי והקהל ותהי אתה תניאנותי והו יהי לך נביא אתון אנון מלאכי זכותה עתידין גלין חרבנה דמצרים תרי מאוריה רברביה אהרן ומשה מנירין על קהל ישראל אטר אלהותה תסב באדך ולא תקום דפרקנה אתקרב זבנה','When Moses heard these words, he answered with excessive fear: “I am 
Your servant, O Master of the world; I will never disobey Your words, but I wish 
to tell before You what is my habit, that I possess. I perceive in my heart all that 
You say to me, but my habit is more modest than that. My tongue is sluggish in 
its speaking, and I have no familiarity with such missions. It is easy for me to 
converse with You at once, but with Pharaoh the king I cannot negotiate. He is 
not mightier than You in my eyes; (rather) I did not say that I cannot deal with 
You. A long time ago I lef Egypt for Midian, and whatever habits of theirs I pos-
sessed I forgot. In Pharaoh’s house I was fostered and weaned, but I lef as a 
youngster. I was not taught bad language and I have no habit with it. I am slow 
of speech and slow of tongue (Exod. 4:10).”','כאשר שמע משה את הדברים האלה, ענה בפחד יתר: "אני עבדך, הו אדון העולם; לא אמרה לבי למרות דבריך לעולם, אך ברצוני לומר לפניך מה שהוא טבעי, שיש בי. אני מבין בלבי את כל אשר אתה אומר לי, אך טבעי צנוע מכך. לשוני כבדה בדיבורה, ואין לי הרגל בשליחויות כאלה. קל לי לשוחח עמך מיד, אך עם פרעה המלך אינני יכול לנהל משא ומתן. לא גדול הוא ממך בעיני; אלא שלא אמרתי שאינני יכול להתמודד עמך. לפני זמן רב עזבתי את מצרים למדיין, וכל ההרגלים שלהם שהיו בי – שכחתים. בבית פרעה גודלתי ונגמלתי, אך עזבתי כשעדיין נער הייתי. לא למדתי לשון חצופה ואין לי הרגל בה. כבד פה וכבד לשון אנכי (שמות ד,י)."');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (24,'I','18','ספר פליהתה',1000181,'לא אסכם משה ממללה עם לבה איי מגיב ביד נצוחה רבה דלית עמה אל חורן לא תבלד מנה נביאה דעלמה ד › ב ‹ גבורתי רבתה מברי חיול מנה שרר לבך נביי על כל פליהתה דאת צריך קעם על מה דו רב מכן שלח אדך ואתחיד בעקבה דאתה עמי תמחה דבגבורתי שוי אשקלה בימינה התפך הך מה דהוה לא אוזף ולא פחת תמן התמח נב רבה משה ואמר מיני רבואן לחילה רבה עבוד כל מה דחני לה ומחליף עובדיו בחילה דרבותה אהן סימנה דעמית לך כדו בדיל יאמנו דאנהו עבודון ואלה אבהתון אברהם ויצחק ויעקב תלתי שלמיה דקיאמת לון עמית לך אה נביי סימנה קמאה ותמחת מנה ודחלת שריר 19] [ שרי עמי כדו סימנה תניאנה פרט ואמר יה לה עורי רב חילה דכן אמר ואשפיר לשמועה ומה שמע מן מרה אעל ני אדך בבלוזך ולא תדלס נביי זרז בעבידתך ושמע מה דאמר לה עבודה ואעלה לחבה בזרוז חיול והו לא ידע מה יתעבד לה ואפקה בתר כן כמה דאמר לה ועמה יתה מיתה מלבין כל בסרה וקעם תמן בבלוד רב וחיול מסתכל לאדה ולא יכל ממלל באטרה הוה יכל ערק ולא יסטי לבה מן חיל דחלתה על דדי מערקתה דערק מן אטרה עמה בימינה מה דו חיול מנה עגל הוא לימינה וחזותה דחלה ולא יכל ערק ולא יעמינה ולא יכל יטלק ימינה מן עליו דהוה עתיד עביד בה פליאן','Moses had not ﬁnished talking to himself, (when) at once he was 
answered by the Great Victor, alongside whom there is no other god: “Do not be 
frightened of it, O prophet of the world, for in My great power I can create (some-
thing) more powerful than it. Strengthen your heart, My prophet, in the face of 
all wonders, for you ought to face even greater than this. Put out your hand and 
grab its tail (Exod. 4:4), for you will see a wonder made from My power.” 
Straightaway he lifed it up with his right (hand) – it turned back to what it was, 
no more and no less. Then the great prophet Moses wondered and said (all) 
kinds of praises to the Great God, who does all that pleases Him and changes His 
deeds by the power of His greatness. “This sign which I have shown to you now 
(is done) that they may believe (Exod. 4:5) that I am their maker and the God of 
their fathers Abraham and Isaac and Jacob, the Three Perfect Ones, with whom I 
covenanted. I have shown to you, O My prophet, the ﬁrst sign, and you won-
dered and were exceedingly afraid.”','משה טרם סיים לדבר עם עצמו, כאשר מיד ענה אותו המנצח הגדול, שאין אל אחר לצדו: "אל תירא ממנו, הו נביא העולם, כי בגדולת כוחי אני יכול לברוא דבר חזק ממנו. חזק את לבבך, נביאי, לנוכח כל הנפלאות, שכן עליך להתמודד אף עם גדולות מזו. שלח ידך ואחוז בזנבו (שמות ד,ד), כי תראה נפלא הנעשה מכוחי." מיד הרים אותו בימינו – וחזר לאשר היה, לא יותר ולא פחות. אז השתאה משה הנביא הגדול ואמר כל מיני שבחים לאל הגדול, העושה כל אשר חפץ ומשנה את מעשיו בעוצמת גדולתו. "האות הזה אשר הראיתי לך עתה הוא למען יאמינו (שמות ד,ה) כי אני הוא עושם ואלוהי אבותיהם אברהם ויצחק ויעקב, שלושת השלמים, אשר כרתי עמם ברית. הראיתי לך, הו נביאי, את האות הראשון, ואתה השתאית ויראת מאוד."');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (25,'I','27','ספר פליהתה',1000271,'ואזל ואפגעה בטור האלהים תרי מאוריה מפקין דן לדן ואזל ו ] אפגע [ ה בטור האלהים שמשה וזהרה דמן עמרם ויוכב › ד ‹ אזדמנו ואזל ואפגעה בטור האלהים דקל ופרת השוו תריון יאי מע › מ ‹ יהון תמן מגפפין וחדותה ראמה ביניון נשק דן לדן ובכותה בעיניון ורחמותה דכל אחד כמרי על חברה אתי בשלם אחי אמר לה אהרן לי שנין סגי בתרך מתלת שעתה דבסרי אלהה דעלמה בשמך שפרת חדותי ואתחילת שריר ישתבח חילה דצמתן אכה מבתר שהותה רבה כי זומנותה בתר שהותה משררה רחמה רבה','He went and met him at the mountain of God (Exod. 4:27) – two luminar-
ies embrace each other. He went and met him at the mountain of God – the sun 
and the moon (who originate) from Amram and Jochebed joined together. He 
went and met him at the mountain of God – Tigris and Euphrates met together. It 
is good to see them there embracing, while joy rose between them. They kissed 
each other, with tears in their eyes, having compassion for each other. “Come in 
peace, my brother”, said Aaron to him, “for many years I was anxious about you. 
When the God of the world announced me your name, my joy improved and was 
exceedingly increased. Praised be God who assembled us here afer much delay, 
for the gathering afer tarrying increases a great love.”','וַיֵּלֶךְ וַיִּפְגְּשֵׁהוּ בְּהַר הָאֱלֹהִים (שמות ד,כז) – שני מאורות מחבקים זה את זה. וַיֵּלֶךְ וַיִּפְגְּשֵׁהוּ בְּהַר הָאֱלֹהִים – השמש והירח שיצאו מעמרם ויוכבד נפגשו יחדיו. וַיֵּלֶךְ וַיִּפְגְּשֵׁהוּ בְּהַר הָאֱלֹהִים – חידקל ופרת נפגשו יחדיו. נאה לראותם שם מחובקים, כאשר שמחה עלתה ביניהם. נשקו זה לזה, בדמעות בעיניהם, מרחמים זה על זה. "בוא בשלום, אחי," אמר לו אהרן, "כי שנים רבות דאגתי לך. כאשר אלהי העולם הודיע לי את שמך, שמחתי עד מאד וגדלה מאוד. ברוך האל שאסף אותנו כאן לאחר עיכוב רב, כי הפגישה לאחר האיחור מגדילה את האהבה."');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (26,'I','4','ספר פליהתה',1000041,'נתן אפרשו גדילה דחילה לבין אלהותה ונביותה ויאמר אנכי אלהי אבהתך סב מני אלהו ושרר בה נביותך אנהו דחוית אדם בתר דמית ועבדת לה רתו כד אמר ית קלך 26* שמעת בגנה ודחלת ותכסיתה תניאנית במה דהוה לאוי פלטת לאנוש ועבדת לה דכרן ליתו משתק ועלמה עלם פלטת לנח ויסדתה ארש וירתתה עלם ואשקחת יתה מלוא פלטת לאברהם ויתבתה אקר וגלית לה אימנו ילפנה לזרעה בתרה פלטת ליצחק בדכר ויהבת לה תלתה ברכהן רברבהן פלטת ליעקב מן אחו ושרית דבבותון שוי ברחמו פלטת ליוסף ויהבת לה חסד וארכני כל אמיה קדמיו 5] [ נטרת יתך אף בנהרה דמ ורביתך בבית דבבך בשלום אתהו עקב זכאי עלמה 24* בעי אנה מגלי חוניתון על אדיך ביד טובי מקים עם אבהתון קיאם וליני מנשי לה ועלמה עלם בניון משכונים במצרי מסגי על מלה דשגו בה אברהם באור כשדים ופסקלת עמה דו עד תחום חכים וסכומה שוי מטי למפרק מן לבטה א › י ‹ ד לי כדו יהב לך דמיתה למפרק › כי ‹ » ז « מן יובילה קריב ד › ה ‹ וא בתשניק רב וחיול מיום דאשכנתה וצבעתה סלקה לידי בתנחו דלה תלתה פס » ק « ולין רברבים ביד יתון טביה דגעזו','Let us set out a great, awesome separation between the divinity and the 
prophethood. He said: “I am the God of your fathers (Exod. 3:6), take divinity 
from me and strengthen your prophecy with it. I am the One who resuscitated 
Adam afer he died, and showed mercy to him when he said: I heard the sound of 
You in the garden and I was afraid (Gen. 3:10), and I covered him again as it was 
appropriate. I delivered Enosh and made for him a memorial which will not 
cease for as long as the world lasts. I saved Noah and established him as a foun-
dation, and I made a world his inheritance, for I found him worthy (of it). I res-
cued Abraham and established him as a root and revealed a faith to him, that he 
will teach to his oﬀspring afer him. I redeemed Isaac through a ram and gave 
him three great blessings. I saved Jacob from his brother and instantaneously 
dissolved their enmity into love. I rescued Joseph and gave him grace, and all 
nations bowed before him.”','נציב הפרדה גדולה ונוראה בין האלוהות לנבואה. אמר: "אנכי אלוהי אבותיך (שמות ג,ו), קח ממני את האלוהות וחזק בה את נבואתך. אני הוא שהחיה את אדם לאחר מותו, וריחמתי עליו כשאמר: את קולך שמעתי בגן ואירא (בראשית ג,י), וכיסיתיו שוב כפי שהיה ראוי. הצלתי את אנוש ועשיתי לו זכרון שלא יפסק כל עוד העולם קיים. הושעתי את נח וביססתיו כיסוד, ועשיתי עולם נחלתו, כי מצאתיו ראוי לכך. הצלתי את אברהם וביססתיו כשורש וגיליתי לו אמונה שילמד לצאצאיו אחריו. גאלתי את יצחק באמצעות איל ונתתי לו שלוש ברכות גדולות. הושעתי את יעקב מאחיו ומיד הפכתי את איבתם לאהבה. הצלתי את יוסף ונתתי לו חן, וכל הגויים השתחוו לפניו."');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (27,'I','37','ספר פליהתה',1000371,'אמר מלכה ליתיביה אקרה מה נתן לון ארשו עד ייעלון אחכם יתון אנה תרי אחין אנון וממללין עמי ממלל רב מנון אמר › ו ‹ יתיביה ארשי לון ייעלו ושמע מימרון ותן לון אגבון קעומי תרחה אמרו לון יבאו עד נשמע ממללון אנפקו עבדיה לידון בזרוז ואמרו לון אעלו ליד מלכה עלו בשלם אה תרי אחיה ואמרו למלכה כל דאתון צריכין','The king said to the counsellors: “Should we grant them permission to 
enter? I know them. They are two brothers, and they will address a speech to me 
that is greater than their rank.” The counsellors said: “Let them enter and listen 
to their speech and give them an answer.” “Doorkeepers, tell them to come in, 
that we may hear their speech.” The servants went out to them in haste and said 
to them: “Come in to the king, come in peace, O two brothers, and say to the king 
what you need (to say).”','אמר המלך ליועצים: "האם לתת להם רשות להיכנס? אני מכירם. הם שני אחים, ויפנו אלי בדברים הגדולים ממעמדם." אמרו היועצים: "יכנסו ונשמע את דבריהם ונשיב להם תשובה." "שוערים, אמרו להם לבוא, ונשמע את דבריהם." יצאו העבדים אליהם בחפזון ואמרו להם: "בואו אל המלך, בואו בשלום, שני אחים, ואמרו למלך את אשר תצטרכו לומר."');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (28,'I','17','ספר פליהתה',1000171,'לא אסכם משה מרמי יתה מן אדה איי עביד נחש חזותה מבלדה ורחש והלך ומן חיל דחלתה ערק משה מנה וקעם בבלוד רב לא הוה כותה וארתע לבה שריר ולא יכל יתקרב לידה שבי אמר תמן ולבה מלי צדו דאהן תמח חיול ולית בי משומנה דהדה גבורה רבה קיצם נגיב יהי נחש מטעיל קבלי מבלד למדעי ולית בי משומנה דו יקיר עד מותר לית עפרה כלום כל דמנה צדו לית בעי לה מעבד גבורה מבלדה אנה מנה מצל מכן לית בי משומנה ואלולי יהוה יקירה נפלת ולא יכלת קעם לקבלה שעה חדה אלא ערקת עד לא אחזינה ארתע לבי שריר ושפפי עיני מעגל לצורתה','Moses had not ﬁnished casting it from his hand, (when) swifly it became 
a serpent (Exod. 4:3). Its sight was terrifying. It crawled and advanced, and out of 
the force of fear Moses ﬂed from it (ibid.) and stood in great fright, the likes 
which had never been (before). His heart trembled exceedingly and he was 
unable to approach it straightaway. He said then, his heart full of fear: “This is a 
mighty wonder, and I cannot comprehend it, for this is a great power: a dry 
wood becomes a serpent moving in front of me, terrifying my mind, and I cannot 
comprehend it, for it is exceedingly immense. The dust is (worth) nothing; every-
thing that (comes) from it is dread. It is not advisable to act on frightful bravery. I 
am going to save myself from it because of this. I cannot comprehend it, and had 
it not been for glorious God, I would have fallen, unable to stand up before it for 
a moment – but I would ﬂee so that I might not see it. My heart trembled greatly, 
and my eyes lowered away from seeing its form.”','משה עוד לא סיים להשליכו מידו, כאשר נהפך במהירות לנחש (שמות ד,ג). מראהו היה מבעית. הוא זחל והתקדם, ומתוך עוצמת הפחד וַיָּנָס מֹשֶׁה מִפָּנָיו (שם) ועמד באימה גדולה, כמוה לא הייתה מעולם. לבו רעד מאוד ולא יכול היה להתקרב אליו מיד. אמר אז, לבו מלא פחד: "זהו פלא עצום ואיני יכול להבינו, כי זוהי כוח גדול: עץ יבש נהפך לנחש המתנועע לפני, מבעית את נפשי, ואיני יכול להבינו כי הוא עצום מאוד. העפר אינו כלום; כל היוצא ממנו הוא אימה. אין זה ראוי לפעול מתוך גבורה מפחידה. עלי להציל עצמי ממנו מפני זה. אינני יכול להבינו, ולולא האלוהים המהולל כבר הייתי נופל ואינני יכול לעמוד לפניו אפילו רגע — כי הייתי בורח שלא לראותו. לבי רעד מאוד ועיני הורדו מלהביט בצורתו."');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (29,'I','55','ספר פליהתה',1000551,'הגיבו תריון כחדה ואמרו אה מלכה לא נרשי למעבד דן ממללה אתון אמרין הן בעלמה תרי אלהין אחד בשומיה ועורנה בארעה ואנן אמרין לית אלה אלא אחד קני שומיה וארעה לקלומה אתון אמרין דרוחיה מערבהן בין שתיקיה ובין מלליה ואנן אמרין בנפשה וברוחה נפשה לגויתה ורוחה לממללה פרנוס בני אדם בנפשה וברוחה ופרנוס שתיקיה בנפשה מיסתה אתון אמרים לית שרי מיכל בסר ואנן בעין נקרב לאלהן בסר אתון סגדין לדמות בהמהן ואנן בעין ננכס בהמהן ארחקו רבה בינן ובינכון ולא לאוי לנן נדבח אלא לגו מדברה הן נזבח ית גנות מצר לחזותון כיון בעין מרגמנן אורח תלתה יומין נהך במדברה ונדבח ליהוה אלהנן צלו כדו ליהוה יסטי ערבה הדה דאנה מנה אעש ולבי וגויתי מנשין הא אנהן מצלין ומסטין לה מן עלויך ולא תשקר בנן יומה הך דת אלוף 56] [ צלה משה ליה וסטה ערבה ואתיקר לבה ולא צבה שמע לון כל דהוו דיניה סגין על פרעה הוה לבה מיקר ומחדד מרדה מבתר אהן חמישה אשתלחת אד יה למקטל קניאניון כל דהוה לבה מתקף הוה דינה מתגבר עליו אסיד בה משה ואשתבע לה בזבן הן שגר ית עמה לית דין קרב לה עלם על ממללה ואבד כל קניאניהון וממקנה ישראל לא מת סהד אחד ישתבח העבוד למה דו בעי ואמר יה למשה ולא סבו לוכון פיח אתונה וידינה משה צית שומיה ונסב משה פיח אתונה וזרקה לעללה ואתעבד שחין פרח אתוקד בה פגרי קעימין והוה סכפן רב ביני כל מצראי שתו מרתה דמותה ואנון קעימין ומיתת פגריון ואשתנקת רוחיון ולא יכלו חרשיה למקעם קדם משה דהוו נאדים באדן סימנה בסרון משלביק ולשנון מבלבל ונפשהתון מעיקה וגויתון מעיסה ופרעה מקשי ודינה ראם עליו ולא צבי משלח ית עמה 57] [ ואמר יה אל משה נתח אדך צית שומ » י « ה ויהי ברד ואנתח משה ית אדה והוה ברד בכל ארע מצרים מקטל קניאנין ומאבד מתונין והוה ברד בכל ארע מצרים משלי שרשין ומערטלאי נופים והוה ברד בכל ארע מצרים מפל כל אריסין ומשנת כל עללאן והוה ברד בכל ארע מצרים מגבי דחיביה דלא אימנו באלה כל דהוו בבראה מן אנש סעד בהמה נעת עלון ברדה ומתו הך ארפו קנאה רבה הות לגו ארץ מצרים אילנין תבירים ועסבין קטילין ועללהן משנתין אשתה מתלקחה לגו לבה דברדה מוקדה מללה ושתיקה ותקיפה ורכיכה ושמינה ורזה ומן רב דחלתה דדחל פרעה ענה ואמר למשה ולאהרן יהוה זכאה ואנה ועמי חיביה צבע קמי משה מלגו לבה ואמר צלי ליה יקץ אהן ברדה וישדך אהן קלה דלבי מצדי מנה ואנה אשלח ית עמה וידבחון ליה פרס משה נביה כפיו קמיו מרה והקץ ברדה והמטרה והשדכו קליה 58] [ ויקר ית לבה אף ביתה זבנה ולא שלח ית עמה כמד פקד יהוה ואמר יה אל משה אנתח ית אדך על ארע מצרים בגובה ואנתח משה ית אדה וסלק גובה על כל ארע מצרים מגבי מצראי מגביה רבה והות מגביתה על פרעה ועל עמה סגי מן שבעתי דיניה דמקמיו אמצץ אילניה ורעו עסביה וחרב בתיה ורוקן מזוניה אתלחצת בה רוח פרעה ועקבה מותה דו מריר כותה כרז למשה ולאהרן ואמר צלו ליה ויסטי מן עלוי ית מותה הדן שאל משה מרה וקבל בעותה והפך רוח מערב ועסקה ים סוף 59] [ ואמר יה אל משה אנתח ית אדך צית שומיה ויהי חשך קבל בכל ארע מצרים תלתה יומין לא עמו בה נאר חבוש מריר עד מותר חבושה דחשכה וכל בני מומה חבישין לגוה בית אסור קביל דלא קני נאר וכל אסיריה דלגוה נביכים עבראי קבלון נאר מניר לון ומצראיה הך כבילין בברזל באתרון זעק פרעה למשה ביומה תליתה וצבע קדמיו והוא לא עמי לה פתח בית אסורה דאני בה ואפקי ואנה מפק ית עמך ממצרים פתח משה נביה בית אסורה דחשכה ואפק לפרעה וסיעת מצראי קרץ בצפרה וקעם לקדמיו ואמר לה שלח עמה כמה דאמרת אגיבה פרעה בערימו רבה שבקו מדלכון וזלו דבחו אמר לה משה לית בנן נפק אלא בנכסינן דאנן בעין נקרב מנון קרבנין ואתקף לב פרעה ולא צבה משלחתון זל מן עלוי לא תחזי אפי הן עמיתך עורי ארשית בקטלך נחת עמוד עננה ברבו רבה וממללה מרה במשמעתה 60] [ ואמר יה אל משה בתר כל אלין עוד מכתש חד אתי על פרעה ועל מצראי מבתר אהן דינה עסיראה הו משלח יתכון זריז כמן לה צורכה ישלח אליה כדן הוא ישגרכון מן ארעה כפלגות ליליה שלטני נחת ויקטל כל בכור דלגו ארע מצרים מבכור פרעה דיתיב על כרסיה ועד בכור אמתה דאחר רחימה וישתמע תמן צבעה רבה לא הוה כותה ולא יהי לעלם עזר משה ואה מליה על פרעה מסידין בה בדיל יהונו זכאין מנה כדן אמר יהוה שגר ית עמי וישמשני ואלית משגרה כדו לתשמשתה הלא הו קטול ברך בכורך עלם על ממללה ולא שמע ותקף ית לבה ולא שלח ית עמה 61] [ ואמר יה אל משה ולאהרן מבתר אשתעתי דיניה דגעזו אהן ירחה לוכון ריש ירחיה חסולה דלבטה ושרוי אנשמותה ירחה אדן לכון ריש ירחיה מפתוחה דרחותה ומצנוקה דפנותה ירחה אדן לכון ריש ירחיה חסול תשניקה ושרוי אנשמותה ירחה אדן לכון ריש ירחיה ארש קיומה וספוקה דבטולה ירחה אדן לכון ריש ירחיה מעולה דטבהתה ומפוקה דבשהתה ירחה אדן לכון ריש ירחיה שביל מטרתה ואורח אימנותה ירחה אדן לכון ריש ירחיה תרח ברכתה וחתמת קללתה ירחה אדן לכון ריש ירחיה חסול עבדותה ושרוי ממלכותה על ברי דו קדם לירחי שתה מנה הנגדי כל שנ » י « ה לעלמה בה ברית עלמה בה אנדית מבולה בה דרית מגדלה בה אפכת סדם בה בסרת אברהם בה ברכת יעקב בה שרית דיניה בה אנה מחסלון בה אנה מחרב למצרים','They both answered together and said: “O King, we cannot do this thing. 
You say that in the world there are two gods, one in heaven and another on the 
earth, and we say, there is no god but One, creator of heaven and earth by Him-
self. You say that spirits are shared among animals and humans, and we say 
about the soul and the spirit that the soul is for the body, while the spirit is for 
the human. The conduct of humans is by the soul and the spirit, while the con-
duct of animals is by the soul alone. You say that it is not permitted to eat meat, 
but we want to sacriﬁce meat to our God. You worship the likeness of animals, 
while we want to slaughter animals. There is a great distance between us and 
you, and it is not appropriate for us to sacriﬁce anywhere except in the desert. If 
we sacriﬁce that which is abominable to the Egyptians before their very eyes 
(Exod. 8:22), indeed they will seek to stone us. Let us go a distance of three days 
into the wilderness and sacriﬁce to the Lord our God (Exod. 8:23).” (Pharaoh said:) 
“Pray now to the Lord that He may remove the raven, because of which I am in 
despair and my heart and my body are weakened.” (They answered:) “Behold, 
we shall pray and remove it from you, but do not deceive us today, as you are 
used to.”','עָנוּ שְׁנֵיהֶם יַחְדָּו וְאָמְרוּ: "הַמֶּלֶךְ, לֹא נוּכַל לַעֲשׂוֹת אֶת הַדָּבָר הַזֶּה. אַתָּה אוֹמֵר כִּי בָּעוֹלָם יֵשׁ שְׁנֵי אֱלֹהִים, אֶחָד בַּשָּׁמַיִם וְאֶחָד בָּאָרֶץ, וַאֲנַחְנוּ אוֹמְרִים אֵין אֱלֹהִים אֶלָּא אֶחָד, בּוֹרֵא שָׁמַיִם וָאָרֶץ בְּעַצְמוֹ. אַתָּה אוֹמֵר כִּי הָרוּחוֹת מְשֻׁתָּפוֹת בֵּין בְּהֵמָה לְאָדָם, וַאֲנַחְנוּ אוֹמְרִים עַל הַנֶּפֶשׁ וְהָרוּחַ כִּי הַנֶּפֶשׁ הִיא לַגּוּף וְהָרוּחַ הִיא לָאָדָם. הִתְנַהֲגוּת בְּנֵי הָאָדָם הִיא עַל פִּי הַנֶּפֶשׁ וְהָרוּחַ, בְּעוֹד הִתְנַהֲגוּת הַבְּהֵמָה הִיא עַל פִּי הַנֶּפֶשׁ בִּלְבַד. אַתָּה אוֹמֵר כִּי אָסוּר לֶאֱכֹל בָּשָׂר, אַךְ אֲנַחְנוּ רוֹצִים לִזְבֹּחַ בָּשָׂר לֵאלֹהֵינוּ. אַתָּה עוֹבֵד דְּמוּת בְּהֵמוֹת, בְּעוֹד אֲנַחְנוּ רוֹצִים לִשְׁחֹט בְּהֵמוֹת. רָחוֹק הַמֶּרְחָק בֵּינֵינוּ לְבֵינֵיכֶם, וְאֵין זֶה רָאוּי לָנוּ לִזְבֹּחַ בְּכָל מָקוֹם אֶלָּא בַּמִּדְבָּר. אִם נִזְבַּח אֶת תּוֹעֲבַת הַמִּצְרִים לְעֵינֵיהֶם (שמות ח,כב), הֲלֹא יְבַקְשׁוּ לְסַקְּלֵנוּ. נֵלֵךְ דֶּרֶךְ שְׁלֹשֶׁת יָמִים בַּמִּדְבָּר וְזָבַחְנוּ לַיהוָה אֱלֹהֵינוּ (שמות ח,כג)." (אָמַר פַּרְעֹה:) "הַעְתִּירוּ נָא אֶל יְהוָה שֶׁיָּסִיר אֶת הֶעָרוֹב, אֲשֶׁר אֲנִי נִשְׁבָּר מִמֶּנּוּ וְלִבִּי וּגְוִיָּתִי נֶחְלָשׁוּ." (עָנוּ:) "הִנֵּה נִתְפַּלֵּל וּנְסִירֶנּוּ מֵעָלֶיךָ, אַךְ אַל תְּכַזֵּב לָנוּ הַיּוֹם כְּדַרְכְּךָ."');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (30,'I','50','ספר פליהתה',1000501,'ואתפנה פרעה ועלל לביתה ונפשה תקיפה לתקוף רגזה עליו ואתפנה פרעה ועל לביתה דבב לעלמה וסן לבוראיה ואתפנה פרעה ועל לביתה מבתר דכעס מללין ושתיקין ואתפנה פרעה ועל לביתה וכל מצראי עבישין מנה בלחצה ואתפנה פרעה ועל לביתה כריך לה חובי קעימין ומאתין שבעה יומים כתרו מצראי משתנקין מותר ומתלחצין שריר ומשה ואהרן כמאורין מנירים על בני עבראי ונהרון ליתו קצץ אגרתה תליתה פריסה קמיון יס › ב ‹ ונה ויקרונה קדם מלך מצרים רחטו בה זריז וקרותה קדמיו והו לא יצבי ישמע 51] [ אכהן אמר יה שלח ית עמי וישמשני ואם מחי אתה למשלחתה כי עביד בך פלי רב וחיול האנה מכתש ית כל תחומך בערדניה אמר טובי מלה ליתו מבטל לה י ] סקון [ וייעלון לגו בתיך וייכלון מזונך ולית בך מכלי יתון ובגבאי משכביך ועל ערסהאתך ינכו אדניך וינטון שנתך ובתנוריך ובמלשהתך ונפשך מתלחצה ולית דידבקנך ] ובך ובע [ בדיך ] ובכל עמ [ ך ] יסקון ע [ רדניה ] אה אסידנ [ ן בך ] אדלא [ תגבי ] הן לא [ תשמע ] קנומך את [ מכה ] אביז ממל [ לון ] ולא שא [ מון כלום ] ו [ תקף ] לבה ורבה מ [ רדה','Pharaoh turned and went into his house (Exod. 7:23) – his spirit is hard-
ened, so that anger may harden over him. Pharaoh turned and went into his 
house – an enemy to the world and a foe to the creatures. Pharaoh turned and 
went into his house – afer he had vexed everyone. Pharaoh turned and went into 
his house – all the Egyptians are conﬁned to aﬄiction because of him. Pharaoh 
turned and went into his house – the sins of the living and the dead engulfed to 
him. Seven days the Egyptians waited exceedingly tormented and extremely 
oppressed. And Moses and Aaron like luminaries shone over the sons of the 
Hebrews, and their light never ceases. The third letter is spread before them, so 
that they take it and read it before the king of Egypt. They ran with it in haste 
and read it before him, and he refused to listen.','וַיִּפֶן פַּרְעֹה וַיָּבֹא אֶל בֵּיתוֹ (שמות ז,כג) – רוּחוֹ הוּקְשָׁה כְּדֵי שֶׁתִּקְשֶׁה עָלָיו הָחֵמָה. וַיִּפֶן פַּרְעֹה וַיָּבֹא אֶל בֵּיתוֹ – אוֹיֵב לָעוֹלָם וְשׂוֹנֵא לַבְּרִיּוֹת. וַיִּפֶן פַּרְעֹה וַיָּבֹא אֶל בֵּיתוֹ – אַחֲרֵי שֶׁהִכְעִיס אֶת כֻּלָּם. וַיִּפֶן פַּרְעֹה וַיָּבֹא אֶל בֵּיתוֹ – כָּל הַמִּצְרִים נְתוּנִים בְּצָרָה בְּגִינוֹ. וַיִּפֶן פַּרְעֹה וַיָּבֹא אֶל בֵּיתוֹ – חַטֹּאות הַחַיִּים וְהַמֵּתִים בָּאוּ עָלָיו. שִׁבְעָה יָמִים חִכּוּ הַמִּצְרִים מְיֻסָּרִים מְאֹד וּדְכוּאִים עַד מְאֹד. וּמֹשֶׁה וְאַהֲרֹן כִּמְאוֹרוֹת זָרְחוּ עַל בְּנֵי הָעִבְרִים, וְאוֹרָם לֹא יָפוּג לְעוֹלָם. הָאֶגֶּרֶת הַשְּׁלִישִׁית פְּרוּשָׂה לִפְנֵיהֶם, כְּדֵי שֶׁיִּקְחוּהָ וְיִקְרְאוּהָ לִפְנֵי מֶלֶךְ מִצְרַיִם. רָצוּ בָהּ בִּמְהִירוּת וּקְרָאוּהָ לְפָנָיו, וְהוּא מֵאֵן לִשְׁמֹעַ.');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (31,'I','1','ספר פליהתה',1000011,'רב חילה רבה דממן לעלם נלבש דחלתה אדלא ממללה רז מנה לא פלי וכלה לגו שלטנה ידע מה הוה ומה כדו ומה יהי קעימה לגרמה דלא צריך לכלום והוא חכם כל רזין בלא מחכם ולא מתחזי והו עבוד מה דו בעי ולא מלך ולא שלטן יכל ימעי לה יהוה הוא האלהים ולית חורי לבר מנה רב דלא רב וכל רבינה דילה','Great is the Great Power who endures forever! Let us wear awe of Him 
before talking. No secret is remote from Him, and everything is under His domin-
ion. He knows what has been, and what is now, and what will be. He is the self 
subsisting one who has no need of anything. And He knows all secrets without 
being informed and without being shown. And He does what He wants, and no 
king and no ruler can oppose him. The Lord is God and there is none except Him 
(Deut. 4:35). He is great beyond limit, and all greatness is His.','גדולה היא הכוח הגדול המתמיד לעולם! נלבש יראתו בטרם נדבר. אין סוד נסתר ממנו, והכל תחת שלטונו. הוא יודע מה שהיה, ומה שהוא עתה, ומה שיהיה. הוא הקיים מעצמו אשר אינו נזקק לדבר. והוא יודע כל הסודות מבלי שיודיעוהו ומבלי שיראוהו. והוא עושה את רצונו, ואין מלך ואין שליט שיוכל לעמוד נגדו. ה'' הוא האלוהים ואין עוד מלבדו (דברים ד,לה). גדול הוא עד אין גבול, וכל הגדולה שלו.');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (32,'I','16a','ספר פליהתה',1000162,'עמו נביות משה הך הו משרי למקרי מקרא אנוש דרבה בה בקשטה טטע שרי למקרי בשם יהוה בריש שירתה טטע מדי ט עבידה פרדיס גדיל קשטה אמרה ואברהם חדדה ויטע יהוה אלהים קשטה אמר ויטע אברהם אשל קשטה כתב כן שרי משה ואמר בגו ימה ועבד שירתה פרדיס כלה תשבחן אמר טטע לגדל פרדיס טב אילנ » י « ו חיים ועורי שרי קרי מלת אז בריאתה אתחדדת אכה אז צמת בה בראשית ושבתה קוממו יתרה כהלה איטבו הלא אקימו אלה על אקר בריאתה מכן שרי וקרי ברבו אז בראשית פתח כלה איטבו שבתה מדינה כהלה ברכה בראשית אקר כהלה רוח שבתה אתר כהלה קדיש אכה מדע משה התחזי לעלמה וזאן לקעימיה ולמאתיה דעה','See the prophetic status of Moses, how he began to proclaim in the 
words of Enosh by which he magniﬁed the True One: at that time he began to call 
upon the name of the Lord (Gen. 4:26). At the beginning of the Song is ( טטעExod. 
15:1), טwas made a great garden. The True One said it and Abraham renewed it. 
And the Lord God planted (Gen. 2:8) – He spoke truth. And Abraham planted a 
tamarisk tree (Gen. 21:33) – He wrote truth. Thus Moses began and spoke in the 
sea; he made his Song a garden of praises. He said טטעto cultivate a ﬁne garden 
whose trees are living. Also he began to call the word ;אזCreation was renewed 
here. אזincluded Creation and the Sabbath – an excellent monument, all of it 
good, for God established it at the foundation of Creation. Therefore (Moses) 
began and proclaimed in might: – בראשית .אזan opening, wholly of good. The 
Sabbath – a domain, wholly of blessing. – בראשיתan origin, wholly of ease. The 
Sabbath – a place, wholly sacred. Here the knowledge of Moses was revealed to 
the world and it provided knowledge for the living and the dead.','ראה את מעמדו הנבואי של משה, כיצד החל להכריז בדברי אנוש שבהם הגדיל את האמיתי: אָז הוּחַל לִקְרֹא בְּשֵׁם ה'' (בראשית ד,כו). בראשית השירה עומד "אָז יָשִׁיר" (שמות טו,א) — א"ז נעשה גן גדול. האמיתי אמרו ואברהם חידשו. וַיִּטַּע ה'' אֱלֹהִים (בראשית ב,ח) — אמת דיבר. וַיִּטַּע אֶשֶׁל בִּבְאֵר שָׁבַע (בראשית כא,לג) — אמת כתב. כך החל משה ודיבר בים; הפך את שירתו לגן של תהילות. אמר "אָז יָשִׁיר" לטפח גן נאה שאילנותיו חיים. גם החל לקרוא במילה "אָז" — הבריאה התחדשה כאן. "אָז" כלל את הבריאה ואת השבת — אנדרטה נעלה, כולה טובה, כי האלוהים כוננה ביסוד הבריאה. לפיכך החל והכריז בגבורה: "בְּרֵאשִׁית" — "אָז" פתיחה, כולה טוב. השבת — ממשלה, כולה ברכה. "בְּרֵאשִׁית" — ראשית, כולה נחת. השבת — מקום, כולו קדוש. כאן נתגלתה לעולם דעתו של משה, והיא נתנה דעה לחיים ולמתים.');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (33,'I','73','ספר פליהתה',1000731,'ברעמסס דבחו ולסכותה נטלו ואתו בעין מפק מנה ולא יכלו קעם עמוד עננה ואשתה קמיון דלא יפקון מתחומה דסכות ומשה ואהרן עמין ודחלין וכל קהלה מבלדין מהו אהן רזה אמר משה לאהרן דחכים דבקהלה עביד אסכלה נזעק לחכימיה אמרו דן אל דן כיינן מרערין על אהן שפטה אתו חכימיה ליד משה ואהרן ולבביון רתתין שריר אמר לון משה טיעאלו בשלם חכימיה ושאלו לכל שבט מהו אף אהן רזה ליתי מהימן דחרשיה יכלין יכפתו בחרשיון בני שבועתה לית אהן אלא ברי ולא קעמנן עליו וארום קריב הוא קשטה יגלינה בשלם הבסקו חכימיה ביני קהלה ושרו שאלין כל שבט ושבט','In Rameses they oﬀered a sacriﬁce and they journeyed to Sukkot and 
sought to leave it, but were unable. The Pillar of Cloud and of Fire had stopped in 
front of them, such that they could not exit from the territory of Sukkot. Moses 
and Aaron were watching afraid, and all the congregation were frightened. 
“What is this mystery”, said Moses to Aaron, for it was clear that a foolish deed 
had been done within the congregation. “Let us call the Elders”, they said to one 
another, “that we may enquire this case.” The Elders came to Moses and Aaron, 
their hearts trembling exceedingly. Moses said to them: “Walk in peace, O Elders, 
and enquire in every tribe as to what this mystery is. I do not believe that the 
magicians (of Pharaoh) can obstruct with spells the Children of the Oath. This is 
nothing but something that we do not understand. Nonetheless the truth is near, 
(God) will reveal it in peace.” The Elders split up among the congregation and 
began to enquire in every tribe.','ברעמסס הקריבו קרבן ונסעו לסוכות, וביקשו לצאת ממנה אך לא יכלו. עמוד הענן והאש עצר לפניהם, כך שלא יכלו לצאת מתחום סוכות. משה ואהרן הביטו מפוחדים, וכל הקהל נמלא פחד. "מה הוא הסוד הזה", אמר משה לאהרן, שכן היה ברור שדבר פחזות נעשה בתוך הקהל. "נקרא לזקנים", אמרו זה לזה, "כדי שנחקור עניין זה." הזקנים באו אל משה ואהרן, לבבם חרד מאוד. אמר להם משה: "לכו לשלום, זקנים, וחקרו בכל שבט מהו הסוד הזה. אינני מאמין שמכשפי פרעה יכולים לעצור בכישוף את בני השבועה. אין זה אלא דבר שאין אנו מבינים. ואף על פי כן האמת קרובה, ויגלה אותה האלוהים לשלום." נפרדו הזקנים אל תוך הקהל והחלו לחקור בכל שבט.');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (34,'I','25','ספר פליהתה',1000251,'אברהם קרץ בצפרה ושוה חמרה מתהלך בזכו חיולה ] משה קרץ בצפרה ושוה חמורה מתהלך בנביו חיולה [ אברהם נסב ית יצחק ותרי רביו עמה למיזל אל בית אל , לדבחה תמן משה נסב אתתה ובניו אזל לטור סיני למקעם קמי מרה אברהם בבאר שבע זיאן גרמה למיזל לאתרה דאמר לה אלהה משה במדין שרר קנומה אזל לאתרה דאמר לה אהיה רביו דאברהם לא סלקו אל בית אל ובניו דמשה לא סלקו לטור סיני רביו דאברהם יתבו מרחיק עד עזר אברהם ובניו דמשה עזרו מקריב הלא דחלו ביתה ליליה ] מ [ מה חזו 26] [ נתן אפרשו ולא נרער על כן ולא נסטי מן אורחה דאנן יהיבין בה ואמר יה לאהרן ‹ זל לזימון אחוך וקבל מנה רזיה דבידה ואמר יה › לאהרן זל לזימון אחוך דאתה עתיד מתעבד נביה ואמר יה לאהרן זל לזימון אחוך וכיתך נצח עמה קרבה דפרעה מלכה וא יה לאהרן זל לזימון אחוך כי עמי לך ולבה יתקף וא יה לא זל לזימון אחוך כי בניו ואתתה עזרו מנה והוא יחידאה שביק בשבילה לגרמה ואלית קדם לה כי לבה מתלת ידע אנה כי בלבך ברי סגי מנה ובך מנצע תמן קרבה יהבת לה שמי בדיל לא ידחל ואפשטת לה אטר מן אשתה עמיתה סימני בדיל לא ישתפל לבה ובתר כן אמר יקיר לשן אנה אמרת לה בדילך הו יהי נביך אמר ושמע ממללי נשם אשפיר מרגלה ואקרץ בצפרה לזימון אחוך למדברה','Abraham rose early in the morning and saddled his ass (Gen. 22:3) walk-
ing in mighty righteousness. [Moses rose early in the morning and saddled his 
ass, walking in mighty prophethood.] Abraham took Isaac, and two of his ser-
vants with him, to go to Beth El to sacriﬁce him there. Moses took his wife and 
sons to go to Mount Sinai to stand before his Master. Abraham girdled himself in 
Beer Sheba to go to the place which God told him. Moses in Midian strengthened 
himself to go to the place which I am told him. The servants of Abraham did not 
ascend to Beth El and the sons of Moses did not ascend to Mount Sinai. The ser-
vants of Abraham stood afar until he returned, and Moses’ sons turned back 
from nearby, as they were afraid of what they saw that night.','וַיַּשְׁכֵּם אַבְרָהָם בַּבֹּקֶר וַיַּחֲבֹשׁ אֶת חֲמֹרוֹ (בראשית כב,ג) הולך בצדקה עצומה. [וישכם משה בבוקר ויחבוש את חמורו, הולך בנבואה עצומה.] אברהם לקח את יצחק ושניים מנעריו עמו, ללכת לבית אל לזבוח אותו שם. משה לקח את אשתו ואת בניו ללכת אל הר סיני לעמוד לפני אדונו. אברהם חגר את מותניו בבאר שבע ללכת אל המקום אשר אמר לו האלהים. משה במדיין התחזק ללכת אל המקום אשר אמר לו "אֶהְיֶה". נעריו של אברהם לא עלו לבית אל ובניו של משה לא עלו אל הר סיני. נעריו של אברהם עמדו מרחוק עד שובו, ובניו של משה פנו לאחור מקרוב, כי יראו ממה שראו באותו הלילה.');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (35,'I','15','ספר פליהתה',1000151,'ומבתר דת קרי קמי חכימיה אלין מליה דקרתין קדמיך סבון ועל לות פרעה מלכה וקעמו קמיו ואמרו לה יה אלהי עבראי מזמן עלינן נהך במדברה שביל תלתה יומין והו אמר לך שלח עמה בזרוז וידבחון לה תמן בנצירו ידע אנה אה נביי ליתו משלח לה אלא בפליאן רברבאן כי לבה מתקשי ודינה ראם עליו ולא יסטי מן מדעה כלום והן כפר בי מלגו לב שפיף הוא אמר מן חיל דחלתה לא אשלח אנה מקשי לבה ולא יסטי לית לה עלי רנין הן כפר בשמי שרוי פליהתה דאתה עתיד עבד ואתן ית חן עמה בעיני מצר וישילנון דלון ויפקון בשלם וירוקנון יתון מדהלון','“Afer you proclaim before the elders these words which I have pro-
nounced before you, take them and go to Pharaoh the king and stand before him 
and say to him: ‘The Lord, the God of the Hebrews appoints us; let us go in the 
desert a journey of three days (Exod. 5:3).’ And He says to you: ‘Let the people go 
at once that they may sacriﬁce to Him there with devotion.’ I know, O My proph-
et, that he will not release them except because of great wonders, for his heart is 
hardened, and the punishment prevails over him, and nothing is displaced from 
his mind. Behold, he denies me. Out of an aﬄicted heart he says, out of the 
power of his fear: ‘I will not let go!’ I am hardening his heart, that he may not 
change course. He has no complaint towards Me, if he denies My name. The ﬁrst 
of the wonders that you are about to perform: I shall give the people’s favor in the 
sight of the Egyptians (Exod. 3:21), and they will let them their possessions, and 
they will exit peacefully, depriving them of their possessions.”','"לאחר שתכריז לפני הזקנים את הדברים האלה שהגיתי לפניך, קח אותם ולך אל פרעה המלך, עמוד לפניו ואמור לו: ''ה'' אלוהי העברים שולח אותנו; נלכה במדבר מהלך שלושת ימים (שמות ה,ג).'' והוא אומר לך: ''שלח את העם מיד כדי שיזבחו לו שם בדבקות.'' אני יודע, נביאי, שלא ישחרר אותם אלא מחמת נפלאות גדולות, כי לבו קשה, והעונש שולט בו, ואין דבר מוסר מדעתו. הנה, הוא כופר בי. מתוך לב מיוסר הוא אומר, מתוך כוח פחדו: ''לא אשלח!'' אני מקשה את לבו כדי שלא ישנה את דרכו. אין לו תרעומת עליי אם הוא כופר בשמי. הראשונה מן הנפלאות שאתה עומד לעשות: אתן את חן העם בעיני המצרים (שמות ג,כא), והם יניחו להם את רכושם, והם ייצאו בשלום, כשהם שוללים את רכושם."');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (36,'I','78','ספר פליהתה',1000781,'עסרה זבנים אתקטלו מצראי בגו ימה בדיל דכפרו בעסרתי פליאתה מרכבת פרעה וחיליה זרגל בימה אדמה שפיך בה הך נהרה דמצרים תהומיה טמרונון הך מד כסית יתון ארדעניה נחתו בצברה כות כיף הך דהוו כלמיה נחתין בבסרון תשגר תקופך יסיפון כקסה הך דהוה ערבה אכל פגריהון וברוח רגזך אתערמו מיה הך דהות אד יהוה מנערה בהמהתון אתקוממו כות טמי נוזלים הך דהוו קעמין בדינה דשחינה קרשו תהומיה בלבה דימה הך דהוה ברדה מקפע לון בבראה נשפת ברוחך טמרנון ימה הך מה כסה יתון גובה טמעו כעברה במים אסנין הך מד טמעו בחשך קפיל אנתחת יכילתך בלעתון ארעה הך מד בלע מחבלה רוחי כל בכוריהון עסרה זבנין כפרו במצרים ועסרה זבנים אקטלו בימה וישראל נפיק ממצרים ביד רמה ומגעז בה ביבש ברבו רבה תמן אשיר משה וכל עמה לאלה אלהיה ורבון דרברביה ישתבח ויכבד ויתרומם דו עבוד פליאתה וממן לעלם ברוך אלהינו לעולם וברוך שמו לעולם .5 9–17) §§ , ( :','Ten times the Egyptians were slain in the sea, because they disregarded 
the ten wonders. Pharaoh’s chariots and his army He has cast into the sea (Exod. 
15:4), their blood was shed in it, just as the River of Egypt. The deeps covered 
them (Exod. 15:5), just as the frogs covered them. They went down into the depths 
like a stone (ibid.), just as the gnats sunk into their ﬂesh. You send forth Your fury, 
they were consumed like straw (Exod. 15:7), just as the raven ate their bodies. At 
the blast of Your nostrils the waters piled up (Exod. 15:7), just as the might of the 
Lord shattered their cattle. The ﬂoods stood straight like a block (ibid.), just as 
they were standing during the plague of boils. The deeps froze in the heart of the 
sea (ibid.), just as the hail was freezing them in the ﬁelds. You made Your wind 
blow, the sea covered them (Exod. 15:10), just as the locusts covered them. They 
sank like lead in the majestic waters (ibid.), just as they sank in tenebrous 
darkness. You stretched out Your vigor, the earth swallowed them (Exod. 15:12), 
just as the Destroyer swallowed the spirits of their ﬁrstborn. Ten times they 
disbelieved in Egypt and ten times they were slain in the sea. And Israel went 
forth from Egypt boldly and passed through on dry land in great glory. Then 
Moses and all the people sang to the God of gods, the Ruler of rulers: “Praised 
and gloriﬁed and exalted be He, for He is the doer of wonders and He is constant 
forever. Blessed be our God forever and blessed be His name forever.”
Appendix: (Book II, §§ 9–17)','עשר פעמים הוכו המצרים בים, כי בזו לעשרת המופתים. מרכבות פרעה וחילו ירה בים (שמות טו,ד), דמם נשפך בו כמו נהר מצרים. תהומות יכסיומו (שמות טו,ה), כשם שכיסו אותם הצפרדעים. ירדו במצולות כמו אבן (שם), כשם שהכינים שקעו בבשרם. שלחת חרונך יאכלמו כקש (שמות טו,ז), כשם שאכל הערוב את גופותיהם. וברוח אפיך נערמו מים (שמות טו,ח), כשם שגבורת ה'' השמידה את מקניהם. נצבו כמו נד נוזלים (שם), כשם שעמדו בעת מכת השחין. קפאו תהומות בלב ים (שם), כשם שהברד הקפיא אותם בשדות. נשפת ברוחך כסמו ים (שמות טו,י), כשם שכיסו אותם הארבה. צללו כעופרת במים אדירים (שם), כשם שצללו בחושך האפלה. נטית ימינך תבלעמו ארץ (שמות טו,יב), כשם שבלע המשחית את נפשות בכוריהם. עשר פעמים כפרו במצרים ועשר פעמים הוכו בים. וישראל יצאו ממצרים ביד רמה ועברו ביבשה בכבוד רב. אז שרו משה וכל העם לאלוהי האלוהים, שליט השליטים: "הלל וכבוד ורוממות לו, כי הוא עושה נפלאות והוא קיים לנצח. ברוך אלוהינו לעולם וברוך שמו לעולם."');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (37,'I','13a','ספר פליהתה',1000132,'תמן קשטה לישראל בשלם אתון סבלין לי ואנה מרבי יתכון רחמיה אמרים לון לינן פסחים מנוכון אם נוקרנוכון האן תיזלון עמוד עננה מרבי חנותיכון עד לא יתחזי לוכון מום עמוד אשתה מניר לון עד יתגלי מנון כל גשוש מלאכיה אף הלכין עמון מאבדין בישיה דיקומו קדמון כבודה רבה מגיח עליון וגלי רבותון ביני כל אמיה שרי ימה ממלל עם ישראל ממלל מרבי למן דבעי יילף אתי בשלם עמה קדישה עבר בי בשלם דקמיך כרוזים חיולים ורמים אתי בשלם אה מן הדמי לאבהתה והגלה אלה ופרקה בחילה אה נגודים טבים קמיך מרגלים עד תגוז בשלם ותמלך בקשט אתי בשלם ולא תשתפל דאנה כדו עתיד למגוזך בגוי','Then the True One (said) to Israel: “You will be carried safely for me, 
and I will exalt you.” The Mercy said to them: “I shall not step away from you, 
but I shall glorify you wherever you go. The pillar of cloud will magnify your 
nature, so that no blemish will be seen in you. The pillar of ﬁre will shine on 
them, that every one of them who strays may be seen. The angels too will go with 
them, destroying the evil ones who would oppose them. The Great Glory will 
ﬁght for them and manifest their greatness among all the nations.” The sea be-
gan to address Israel with words that beneﬁt those who seek to learn: “Come 
safely, holy people. Cross over me in safety, for mighty and exalted heralds are 
before you. Come safely, you who resemble your fathers, to whom God revealed 
Himself and with His power delivered them. Behold, good leaders are before you, 
seeking (the way) that you may cross over safely and acquire rightly. Come safely 
and do not be humble, for I am now going to let you cross me.”','אז אמר האמיתי לישראל: "תישאו בשלום למעני, ואני ארוממכם." אמרה להם הרחמים: "לא אסור מכם, אלא אכבד אתכם בכל אשר תלכו. עמוד הענן ירומם את טבעכם, כך שלא יראה בכם כל פגם. עמוד האש יאיר עליהם, כדי שייראה כל אחד מהם שיסטה מן הדרך. גם המלאכים ילכו עמהם, ויכחידו את הרשעים שיתנגדו להם. הכבוד הגדול ילחם בעדם ויגלה את גדולתם בין כל העמים." הים פתח לדבר עם ישראל דברים המועילים למבקשי לימוד: "בואו בשלום, עם קדוש. עִברו בי בשלום, כי שליחים אדירים ורוממים לפניכם. בואו בשלום, אתם הדומים לאבותיכם, שאליהם נגלה האל ובכוחו הצילם. הנה, מנהיגים טובים לפניכם, מבקשים את הדרך כדי שתעברו בשלום ותזכו כראוי. בואו בשלום ואל תיכנעו, כי עתה אני עתיד לתת לכם לעבור בי."');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (38,'I','33','ספר פליהתה',1000331,NULL,'When Moses and Aaron heard this speech, they were in great distress. 
Moses said to the Lord, his heart full of fear: “O Master, tell me what this mystery 
is. Ever since I came to Pharaoh to speak in Your name he has done evil to this 
people (Exod. 5:23), a very great evil, and the people are in torment. He increases 
their aﬄictions more than before, and misery is renewed every day more than 
(in) the previous day.” The Lord said to Moses (Exod. 6:1): “My prophet, no delay! 
Soon you will see great wonders in him. Indeed, I shall harden his heart, and at 
the end even the memory of him will be uprooted. Lo, I reveal to you My great 
name, ,יהוהwhich I did not reveal (even) to the Righteous of the world. By אל שדי
I appeared to Abraham, Isaac, and Jacob, and this great name I did not reveal to 
them, for it is a glorious name, which ﬁlls the whole creation and by which the 
world is bonded together. My covenants (with) the Righteous are tied to it forever 
– I shall not forget it for as long as the world exists. Since I have found you to be 
supreme out of the whole world, I therefore revealed to you My great name.”','כאשר שמעו משה ואהרן את הדברים האלה, היו בצרה גדולה.
אמר משה לאדון, ולבו מלא פחד: "אדוני, הגד לי מה הוא הסוד הזה. מאז באתי אל פרעה לדבר בשמך הרע לעם הזה (שמות ה,כג), רעה גדולה מאוד, והעם מתייסר. הוא מרבה את עינוייהם יותר מבראשונה, והצרה מתחדשת בכל יום יותר מן היום שלפניו." אמר ה'' אל משה (שמות ו,א): "נביאי, אל תתמהמה! עוד מעט תראה נפלאות גדולות בו. אכן, אני אקשה את לבו, ולבסוף אף זכרו יעקר. הנה, אני מגלה לך את שמי הגדול, יהוה, אשר לא גיליתי אפילו לצדיקי עולם. באל שדי נגליתי לאברהם, ליצחק וליעקב, ואת השם הגדול הזה לא גיליתי להם, כי הוא שם מפואר המלא את כל הבריאה ושבו העולם קשור יחד. בריתותי עם הצדיקים קשורות בו לעולם — לא אשכחנו כל עוד העולם קיים. מאחר שמצאתיך עליון מכל העולם, לפיכך גיליתי לך את שמי הגדול."');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (39,'I','67','ספר פליהתה',1000671,'כד רעטת בסרתה בקהלה עתדו קנומיכון לזבנה מפוקה וזעק משה לכל סהבי ישראל מימר לון שביל גזירת פסחה וזעק משה לכל חכימי ישראל יגדון אענין וינכסון הך דאמיר לון וזעק משה לכל חכמי ישראל יגלון לקהלה מועדה קמאה וזעקו חכימיה בקהלה אפקו דבחיה דבמטרתה ועתדו כי זבנה מטי וקרבה דמחבלה לילן סדיר וסבו מסירה דאזוב ואדו מן אדמה על שקופה ועל תרי מזוזהתה לילן מחבלה נחת ומחרב כל בית דלית עליו סימן מן אדמה ואזלו ועבדו בני ישראל טליה עתידין מיתי לביספרון ואזלו ועבדו בני ישראל כוכביה דאברהם סדירין ברקיע ואזלו ועבדו בני ישראל עללתה דיצחק גדישה בגרנה ואזלו ועבדו בני ישראל אילניו דיעקב נציבין בפרדיסיה כמה פקד יהוה ית משה וית אהרן כן עבדו ועקדו וסגדו','As the message ran amongst the congregation, “Prepare yourself for the 
time of the exit”, Moses summoned all the elders of Israel (Exod. 12:21) to tell 
them the way of the Law of Passover. And Moses summoned all the elders of 
Israel, that they should lead sheep and slaughter as they had been told. And 
Moses summoned all the elders of Israel, that they should reveal to the congrega-
tion the ﬁrst festival. The Elders called among the congregation: “Bring out the 
sacriﬁces which are kept under watch and prepare, for the time has come near 
and the battle of the Destroyer will take place tonight. Take a bundle of hyssop 
and sprinkle the blood to the lintel and the two doorposts. Tonight, the Destroyer 
will descend and destroy every house which does not bear the sign of the blood.” 
The people of Israel went and did so (Exod. 12:28) – the youngsters are prepared 
to go to their schools; the stars of Abraham arrayed in the ﬁrmament. The people 
of Israel went and did so – [the crop of Isaac is heaped up in the threshing-ﬂoor. 
The people of Israel went and did so – the trees of Jacob planted in the gardens. 
As the Lord had commanded Moses and Aaron, so they did (ibid.). And they 
bowed and prostrated themselves.','כאשר עברה הבשורה בקהל – "הכינו עצמכם לשעת היציאה" – קרא משה לכל זקני ישראל (שמות יב,כא) כדי להודיעם את דרך תורת הפסח. וקרא משה לכל זקני ישראל, שיוציאו צאן וישחטו כפי שנצטוו. וקרא משה לכל זקני ישראל, שיגלו לקהל את המועד הראשון. הזקנים קראו בקהל: "הוציאו את הקרבנות השמורים במשמרת והכינו, כי הגיעה העת ומלחמת המשחית תהיה הלילה. קחו אגודת אזוב וזרקו את הדם על המשקוף ועל שתי המזוזות. הלילה ירד המשחית וישחית כל בית שאין עליו אות הדם." ויעשו כן בני ישראל (שמות יב,כח) – הצעירים מוכנים ללכת לבתי ספרם; כוכבי אברהם ערוכים ברקיע. ויעשו כן בני ישראל – יבול יצחק ערום בגורן. ויעשו כן בני ישראל – עצי יעקב נטועים בגנות. כאשר ציווה ה'' את משה ואת אהרן, כן עשו (שם). וישתחוו ויכרעו.');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (40,'I','20','ספר פליהתה',1000201,'כד עמה יתה מרה קעום בצדו רבה אמתן גרמה מן דחלתה ואמר אעאל ני אדך בחבך תנינאות ואשלע מן לבך כל אהן בלודה אמת דת מיעל לה לא תשיח בחבך אפקה באפרי וכי תמחך ראם עבד נביה הך דאמר לה מרה ואעלה ואפקה ואה היא כמה דהות תמן אמתן גרמה מן יתה דחלתה ושבח למרה דעלמה עבוד כל פליה ואמר לה אלין סימנין רמין עד מותר בראי הו לבה דלא מהימן בכל עובדיך ולית סוף ליכלותך אה מלכה דעלמה סב נביי אלין תרי סימניה אם לא יימנון בון דאקרי חיול מנון עבד קמיהון קמאה ותניאנה כמה דעבדת יתון קדמיך אם לא יימנון לתרי סימניה כי בפליאתי מכבשה רשותון כי מטי לך ותסב ממימי נהרה ותשפך ביבשתה ויהונו לדם ביכלות שלטני פליאן רברבן מזזעהן כל לבביה לית לאוי יעבדנון אלא את דאתהו תניאני בעלמה דלרע','When his Master saw him standing in great dread, He relieved him of his 
fear and said: “Put your hand back into your bosom (Exod. 4:7) and remove from 
your heart all this fright. When you place it in, do not keep it long in your bosom. 
Bring it out at once, and indeed, your wonder will be great.” The prophet did as 
his Master told him, and he inserted it and withdrew it, and behold, it was as it 
had been (formerly). Then he relieved himself of dread, and he praised the 
Master of the world, doer of every wonder, and said to him: “These are exceed-
ingly great signs. Alien is the heart that does not believe in all Your deeds. There 
is no end to Your might, O King of the world.” “Take, My prophet, these two 
signs. If they will not believe (Exod. 4:8), indeed, (there are even) mightier than 
them in My possession. Perform before them the ﬁrst one and the second one, as 
I performed them before you. If they will not believe the two signs (Exod. 4:9), 
surely their rebelliousness will be subdued by My wonders, as it seems appropri-
ate to you. And you shall take some water from the river and pour on the dry land 
[…] and they will become blood (ibid.). Within the power of My sovereignty (there 
are) great wonders, terrifying all hearts. It is not appropriate that anyone perform 
them except you, for you are My second in the lower world.”','כאשר ראה אדונו אותו עומד בחרדה גדולה, הסיר ממנו את פחדו ואמר: "השב ידך אל חיקך (שמות ד,ז) והסר מלבך את כל הבהלה הזאת. כאשר תכניסנה, אל תשהה בחיקך זמן רב. הוצאה מיד, ואכן גדולה תהיה השתאותך." עשה הנביא כאשר אמר לו אדונו, הכניסה והוציאה, והנה הייתה כאשר הייתה מקודם. אז נשתחרר מן החרדה, ושיבח את אדון העולם, עושה כל נפלא, ואמר לו: "אלה אותות גדולים מאוד. זר הוא הלב שאינו מאמין בכל מעשיך. אין קץ לגבורתך, הו מלך העולם." "קח, נביאי, את שני האותות הללו. אם לא יאמינו (שמות ד,ח), הנה חזקים מהם ברשותי. עשה לפניהם את הראשון ואת השני, כאשר עשיתים לפניך. ואם לא יאמינו לשני האותות (שמות ד,ט), בוודאי תיכנע סרבנותם על ידי נפלאותי, כפי שנראה בעיניך לנכון. ותיקח מעט מים מן הנהר ותשפוך על היבשה [...] והיו לדם (שם). בעוצמת שלטוני נפלאות גדולות, המחרידות את כל הלבבות. אין זה ראוי שאיש יעשם מלבדך, כי אתה הוא משנה לי בעולם התחתון."');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (41,'I','17a','ספר פליהתה',1000172,'ועזר ואמר ישיר מלה גדילה ליתה מתחלפה אה מלין רמין נהר מניר אז ישיר בריה ואשמעה אז רזה גדיל דמס לא יסתתר בראשית חדדת ושבתה הגלת וברית אברהם במספר ז הגלה עמי מלת ישר דשרא בה נביה רבה משה ועבדה מגן באפי כל ערוי חמש מאות ועשרה צמתת תלתה חלקים שני גירותה דלאהבהתה ושני עבדותה לבניון ושני נביותה דבה אמטה משה להדה מיתוביתה','He then said – ישירa great word which is unalterable. Behold, promi-
nent words like shining light. – אז ישירcreation and proclamation. – אזits signiﬁ-
cance is great, a foundation that cannot be destroyed. בראשיתwas created and 
Sabbath revealed. The covenant with Abraham was manifested in the number .ז
See the word ישירwith which the great prophet Moses began. He made it a shield 
in the face of all mishap – ﬁve hundred and ten. It comprises three sections: the 
years of the sojourning of the ancestors, the years of the slavery of their children, 
the years of the prophethood by which Moses reached this status.]','אז אמר — "יָשִׁיר" — מילה גדולה שאין לשנותה. הנה, דברים נכבדים כאור מבהיק. "אָז יָשִׁיר" — בריאה והכרזה. "אָז" — משמעותו גדולה, יסוד שאין להשמידו. "בְּרֵאשִׁית" נברא והשבת נתגלה. הברית עם אברהם התבטאה במספר ז''. ראה את המילה "יָשִׁיר" שבה פתח משה הנביא הגדול. הפכה למגן מפני כל אסון — חמש מאות ועשר. היא כוללת שלושה חלקים: שנות נדודי האבות, שנות עבדות בניהם, ושנות הנבואה שבהן הגיע משה למעמד זה.');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (42,'I','41','ספר פליהתה',1000411,'שמעו מה אגיב לון פרעה ולבה מלי צדו רב עבדיה דקעמין עלוי › ב ‹ ביתה לא , ירשון ] מפוק [ כדו מן תרחה ללבר ידע אנה דלבון הצקי כותי ולא יכלו ילכו לא ימין ולא שמאל וכל עבדיה דהוו מלבר נפלו על אפיון מן רב דחלתה והן ארמית קל גנו עלי וכל מן שמע יתמח וילי ומה עמית קדמי יכל הוא בלע לי ואתון עמין דאני מדמי לעלול לקרב נציע בין דבביו ולא ידע בון','Hear how Pharaoh answered them, his heart full of great consternation, 
(while) the servants who stood by him in the house could not exit now from the 
door (to go) outside: “I know their heart is in fear, like mine, and they are unable 
to go to right or lef.” And all the servants who were outside fell on their faces 
out of great fear. “And if I raise my voice, blame on me, and anyone who hear 
will wonder. Woe to me (because of) what I have seen before me. (The serpent) is 
able to swallow me, and you see that I resemble one who engages in battle, and 
is subdued between his enemies, whom he did not even perceive.”','שמעו כיצד ענה אותם פרעה, לבו מלא בהלה גדולה, כשהמשרתים שעמדו עמו בבית לא יכלו לצאת עתה מן הפתח החוצה: "אני יודע שלבם בפחד, כמוני, ואינם יכולים ללכת לימין או לשמאל." וכל המשרתים שהיו בחוץ נפלו על פניהם מפחד גדול. "ואם ארים את קולי, האשמה עליי, וכל שומע יתמה. אוי לי על אשר ראיתי לפניי. (הנחש) יכול לבולעני, ואתם רואים שאני דומה לאחד היוצא למלחמה ומובס בין אויביו, אשר לא הבחין בהם אפילו."');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (43,'I','8','ספר פליהתה',1000081,'שמעו מה הגיב משה נביה למרה אמת דשמע אלין מליה מן אנה אה רבי ומרה 25* דכל עלמה עד איזל ליד פרעה מלכה ליני עמי גרמי קמיו כלום דאנה זעור ונשיש והוא › רב ‹ מני מה חיל בר תורין רך וטוב קמי אריה אמת דו נצח עמה קרב דכל מלכי ארעה דחלין מן דכרה לית בי קעם קמיו שמעו מה אגיבה מרה ידע אנה דאתה זעור לב ורכיך יכל אנא מחלף נשישך בשרירו אידלי מפק לך אטר מן אשתה כיתך מתפך לה לכל גון דאת בעי עמיתה בעיניך ורזיתה בלבך ואת עתיד מפרסי מלגוה פליאן','Hear how the prophet Moses replied to his Lord when he heard these 
words. “Who am I, O my Master and Lord of the whole world, that I should go to 
Pharaoh the king? (Exod. 3:11) I do not see myself as anything before him, for I 
am small and weak, while he is greater than I. What is the power of a calf, tender 
and good (Gen. 18:7) to a lion when they ﬁght? For all the kings of the earth be-
come afraid at mention of him; I cannot confront him.” Hear what his Lord 
replied to him: “I know that you are small of heart and feeble. I can change your 
weakness into strength. Behold, I bring out for you a rod from the ﬁre, that you 
transform into any form you want. See it with your eyes and understand its sense 
with your heart, for you are going to disclose wonders by means of it.”','שמע כיצד נביא האלוהים משה השיב לאדונו כששמע את הדברים הללו. "מִי אָנֹכִי, אֲדֹנִי וְרִבּוֹן כָּל הָעוֹלָם, כִּי אֵלֵךְ אֶל פַּרְעֹה הַמֶּלֶךְ? (שמות ג,יא) אינני רואה את עצמי כלום בפניו, כי קטן אני וחלש, ואילו הוא גדול ממני. מה כוחו של בֶּן בָּקָר רַךְ וָטוֹב (בראשית יח,ז) נגד אריה כשהם נלחמים? כי כל מלכי הארץ יחרדים לשמעו; אינני יכול לעמוד מולו." שמע מה השיב לו אדונו: "יודע אני שקטן אתה בלב ורפה כוח. ביכולתי להפוך חולשתך לעוז. הנה, אוציא לך מַטֶּה מן האש, שתוכל להפוך לכל צורה שתחפוץ. ראה אותו בעיניך והבן את משמעותו בלבבך, כי עתיד אתה לגלות בו נפלאות."');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (44,'I','14','ספר פליהתה',1000141,'אמת דאת קרי קמיון אלין מליה על ברי אנון שמעין ] למ [ ליך כי מדעיה כרזין ואמרין אלולי פסקולה דהוינן אבדין דעמן רזין מן אברהם וסימנין ומן דאנון עמן פרקנה קריב','When you proclaim these words before them, they will indeed listen to 
your words, for the sages will declare saying, “Were it not for the Covenant, we 
would have perished, for we have secrets from Abraham and signs; since they 
are with us, the deliverance is near.”','כאשר תכריז את הדברים האלה לפניהם, ישמעו אכן לדבריך, שכן החכמים יאמרו לאמור: "לולא הברית, היינו אובדים, כי יש לנו סודות מאברהם ואותות; מאחר שהם עמנו, הגאולה קרובה."');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (45,'I','10a','ספר פליהתה',1000102,'ולבה דפרעה מתקף ואבדנה הך אמר לה אתי אתגזי ווילך פרעה בישה ומה עבדת בנפשך לאהן אזל מדעך המזל מן עבד בישאתה חלקה הך יהי לה קוממו בעלמה וילה פרעה בישה ומה עתיד לה ביד נביה רבה משה לה אמר משה אישה האן קסמיה ייתון יחזון יתי אכהן הך אנה מאבדך בפי מרי מה אמרו לך דאני לגו ימה אביד בידון בדיל מרבאתון יומם יחזון מנו דיאבד בימה ויתעבסון הן מרן דו גדול זל אה חיב וכון כרמך כיינן תחזי גזוי כל עובדיך ומרן מאבדנך בגוני תשניקיה אנית קסמיה אמרו לך דאנה אביד בימה מרי חכמני דאתה בה תאבד ותעמי אידן ממלל יהי קשט ממלל קסמיה אי ממלל מרן','Pharaoh’s heart was hardened, and it was as if Destruction said to him: 
“Come and face retribution; woe to you, Pharaoh the wicked. What you have 
done to yourself! To where has your unworthy mind gone? To one whose share is 
evildoing, how can he have existence in the world?” Woe to Pharaoh the wicked, 
(given) what is appointed to him by the great prophet Moses! Moses the Man said 
to him: “Where are the magicians? Let them come and see me here, how I 
destroy you at my Lord’s command. Did they not say to you that I would perish 
by them in the sea, so that they would be gloriﬁed? Today they shall see who will 
perish in the sea. They shall learn that it is our Lord who is superior. Go, O 
sinner, and prepare yourself, and indeed you will see the reward of all your 
doings. Our Lord will destroy you with all kinds of aﬄictions. If the magicians 
said to you that I will perish in the sea, my Lord has informed me that you are 
the one who will perish in the sea. You will see which statement is true, that of 
the magicians or that of our Lord.”','לבו של פרעה התקשה, והיה כאילו אמרה לו ההשמדה: "בוא וקבל את גמולך; אוי לך, פרעה הרשע. מה עשית לעצמך! לאן הלך שכלך הנפסד? למי שחלקו הוא עוולה, כיצד תיתכן לו קיומה בעולם?" אוי לפרעה הרשע, על מה שנגזר עליו על ידי משה הנביא הגדול! משה איש האלוהים אמר לו: "היכן הם החרטומים? שיבואו ויראוני כאן, כיצד אני מאבד אותך בפקודת אדוני. האם לא אמרו לך שאני אאבד על ידיהם בים, כדי שייתפארו? היום יראו מי יאבד בים. הם ילמדו כי אדוננו הוא העליון. לך, חוטא, והתכונן, ואכן תראה את שכר כל מעשיך. אדוננו יאבד אותך בכל מיני מכות. אם אמרו לך החרטומים שאני אאבד בים, אדוני הודיע לי שאתה הוא אשר יאבד בים. תראה איזו אמירה אמת, זו של החרטומים או זו של אדוננו."');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (46,'I','23','ספר פליהתה',1000231,'עזר משה ליד יתרו מזרז ויהבנה בשלם מקדם ייזל ואמר לה לי אחין במצרים לא עמיתון מיום דנפקת מן אקרון ואנה בעי איזל אעמינון אנית הוו בעלמה חיים אדכיר לטב יתרו על ממללה דאגיב והכתבת רבותה ואמר יתרו לך לשלום ואמר יהוה לה במדין 7923 . משררה ללבה דלא ידחל זל עזר למצרים ולא תשפל גרמך הלא מתו כל גבריה דהוו בעין ית נפשך סב מני שלטנו ושותה בלבך כי כל דבביך קדמיך נפילים לא תדחל מנון הלא באדך אנון באטרה דיהבת לך אתה מכבש לון ומן יכל קעם בך ושמי רבה עמך כי כל דבב קמיך נפל הך עטף עם אפי רמשה הות כריזתה בליליה עתד קנומה למיזל 24] [ ואנסב משה ית אתתה וית בנ ביתה צפרה דבתר כריזתה ואנסב משה ית אתתה וית בניו נצוחה אזל מפק לקרבה ואנסב מ ית את וית בנ אריסה בעי מיזל לסחנתה ואנסב משה ית אתתה וית בניו חכימה אזל מסק לדרגה ואנסב משה ית אתתה וית בניו רחמה משלח ליד רחימה ושקע ית חמרה וסבל ית אתתה ובריו למעזרה','Moses returned to Jethro in haste and greeted him before departing. He 
said to him: “I have brethren in Egypt whom I have not seen since the day that I 
departed from them and I wish to go to see, whether they are alive in the world.” 
Of blessed memory be Jethro for the word (with) which he answered – his glory 
has been recorded. Jethro said: “Go in peace (Exod. 4:18).” And the Lord said to 
him in Midian (Exod. 4:19) – strengthening his heart so that he would not fear: 
“Go back to Egypt (ibid.), do not lower yourself, for all the men who sought to kill 
you are dead (ibid.). Take from me authority and set it in your heart, for all your 
enemies will fall before you. Do not fear them, for they have been submitted to 
you. With the rod that I gave you, you will subdue them. Who can withstand you 
while My great name is with you? Indeed, every enemy will fall before you in-
stantly.” In the evening the summon came; during the night he prepared himself 
to go.','משה שב ליתרו בחיפזון ונפרד ממנו בטרם עזב. אמר לו: "יש לי אחים במצרים אשר לא ראיתים מאז היום שעזבתי אותם, וברצוני ללכת לראות אם הם עודם חיים בעולם." ברוך זכרו של יתרו על הדברים שהשיב – כבודו נרשם. אמר לו יתרו: "לֵךְ לְשָׁלוֹם (שמות ד,יח)." וה'' אמר לו במדיין (שמות ד,יט) – מחזק את ליבו כדי שלא יירא: "לֵךְ שׁוּב מִצְרַיִם (שם), אל תשפיל את עצמך, כי כל האנשים אשר בקשו את נפשך מֵתוּ (שם). קח ממני סמכות ושים אותה בלבך, כי כל אויביך ייפלו לפניך. אל תיראם, כי הם נמסרו לידך. במטה שנתתי לך תכניעם. מי יוכל לעמוד בפניך כאשר שמי הגדול עמך? כי כל אויב ייפול לפניך ברגע אחד." בערב בא הקריאה; בלילה הכין את עצמו לצאת לדרך.');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (47,'I','31','ספר פליהתה',1000311,'כד עמו פרעה מתגבר קמיון נפקו משמעין לגו קהלה לא אסכמו תרי נבייה נפקים אלא וכרוזים במצרים כל ספר דלגו ביספרה פעלין לא יתן לון תבן בעבידת לבנה עוד סכומה דלבנה דהוו עבדין לא יפחת מנה כלום ברן יתעצמון סגי ממה דהוו ותכבד עבידתון סגי ממה דהות בצפרה קרצו סבלין צוקה מרירה עליהון ובכותה בעיניון אנפקו מטיעלין לגו ארע מצרים למקשש קש לתבן ומעבד לבניה ומפלחיה עצימין בון סגי ממה דהוו וקנאתון ראמה שריר וילן ומה עביד לן אמרו דן לדן השתוי עלינן עקה רבה עד מותר לאוי לא עמינן משה ואהרן כי סכינן הנפוש נפלנן בארצם רב אתו טרדונון אמרו עמה לא עמינן לחצה אלא מן יומה דאתו קרצו ברנונה אמרו מדעיה לית עקה אלא ולה ‹} אסכמ › ו ה { אנית אנון יומה סחדו דלית סחדו אלא ולה עקב','When they saw that Pharaoh acted haughtily towards them they depar-
ted, making (this) known to the congregation. No sooner had the two prophets 
departed, than heralds went out in Egypt (proclaiming): “Let any leader in 
whose congregation there are workers give them no straw for the manufacture of 
bricks. Moreover, the quota of bricks they used to make will not be reduced at all. 
But (if) they complain more than they used to, let work be heavier upon them 
than previously.” In the morning they rose early, bearing bitter despair on them-
selves, and weeping in their eyes. They went about walking in the land of Egypt 
to gather stubble for straw (Exod. 5:12) and to make bricks. And the taskmasters 
urged them (Exod. 5:13) more than before, and their zeal increased exceedingly. 
“Woe to us, for what happened to us”, they said to one another. “An exceedingly 
great aﬄiction has been imposed upon us. Would that we had never seen Moses 
and Aaron. Surely, we had sought relief but have fallen into great anguish. Let us 
drive them away”, said the people, “We had not experienced aﬄiction except 
from the day they came in haste with (their) complaint.” The sages said: “There 
is no aﬄiction unless it has an end. If they gather (upon us) today, there is no 
gathering unless it has an end.”','כשראו שפרעה התנשא עליהם, יצאו והודיעו דבר זה לעדה. בלי שהספיקו שני הנביאים לצאת, יצאו כרוזים במצרים ומכריזים: "כל שוטר שיש בעדתו פועלים — אל ייתן להם תבן לייצור הלבנים. ויתר על כן, מכסת הלבנים שהיו עושים לא תצומצם כלל. אך אם יתלוננו יותר מן הרגיל, תכבד עליהם העבודה יותר מלפנים." בבוקר השכימו, נושאים בתוכם יאוש מר, ובכי בעיניהם. הלכו ושוטטו בארץ מצרים לְלַקֵּט קַשׁ לַתֶּבֶן (שמות ה,יב) ולעשות לבנים. וַיָּאִיצוּ בָהֶם הַנֹּגְשִׂים (שמות ה,יג) יותר מלפנים, ומרצם גבר מאוד. "אוי לנו על מה שאירע לנו", אמרו איש לרעהו. "עינוי גדול מאוד הוטל עלינו. מוטב שלא ראינו מעולם את משה ואת אהרן. ודאי ביקשנו הקלה ונפלנו לצרה גדולה. נגרש אותם", אמר העם, "לא ידענו צרה אלא מהיום שבאו בחיפזון בתלונתם." אמרו החכמים: "אין צרה שאין לה סוף. אם הם נאספים עלינו היום, אין קיבוץ שאין לו סוף."');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (48,'I','77','ספר פליהתה',1000771,'נפקו כרוזין לגו ארע מצרים ואצטמתו כל עלולי קרבה אסר ית מרכביה ועמה אנסב עמה ותת מון רכב בחור אזדינו עמה לקרבה כל רכב מצרים ותליתאין על כלה ורדפו בתר ישראל ומטו בון ואנון שרין על ימה קעם פר מלכה לקדם בעל - צפון ואקרב לה תמן קרבן דערימו דהוה בעל - צפון אלה } י { מן יתון אלהיה דהוה רחיץ עליהון רב הו תלישה דקעמו בה תלישין מעזרה למצרים אמרו למשה בדחלה חיולה חכים דאתהו קטולה דישראל הך אנן עבדין ומה בידן נעבד דבבה בתרן וימה קמינן הלית מללנן לך במצרים למימר קץ ני מנן ונשמש ית מצראי מה דאה עבדת לנן במפוקן ממצרים הלא כלנן קטילין כארפות עין ואמר לון משה לא תדחלון ליתכון חזין מצראי לעלם אתקוממו וחזו ית פצות יהו יהוה יגיח לכון ואתון תשתקון ובתר כן נסב משה מן מרה ארשו ואקש לימה באטרה ופלגה שעתה דפתח ימה דסוף קמיון הלכו ועננה וכבודה נגידין לון ירומון יתון טליה דרחותה דאתיבש ימה קמיון והלכו ועלו מצראי בתרון בימה ואצטנק עליון ולא אנפקו מלגוה עמו המפרש לבין תרים עללו נביה רבה משה עלל ופרעה מלך מצרים עלל משה עלל וכבודה קמיו מרבי לה ופרעה עלל ומחבלה קמיו מ ] בג [ לל אבדנה ] משה [ עלל ] ואלהו [ תה מרביה לה פרעה עלל ואלהותה מגביה לה משה עלל ומלאכיה לה משמשין 7923 . פרעה עלל מלאכיה לה משנקים כמשה לא קעם ולא יקום לעלם','Heralds went forth in the land of Egypt, and all the warriors assembled, 
he made ready his chariot and took his men with him (Exod. 14:6). And six hundred 
of his picked chariots took up arms with him for war, and the chariots of Egypt, 
with oﬃcers in all of them (Exod. 14:7). They pursued Israel and reached them as 
they were encamped by the sea (Exod. 14:9). Pharaoh the king stood up before 
Baal Zephon and oﬀered to it there a sacriﬁce of deceit, for Baal Zephon was one 
of those gods in which he trusted. Great was the dismay in which they stood 
there dismayed (lest they have) to return to Egypt. They said to Moses in mighty 
fear: “Know that you are the murderer of Israel. What should we do, and what 
can we do? The enemy is behind us and the sea is in front of us. Is this not the 
very thing we told you in Egypt, saying, let us be, and we will serve the Egyptians 
(Exod. 14:12). What have you done to us, taking us out of Egypt? (Exod. 14:11) We 
will be all killed, in a wink of an eye.” And Moses said to them: “Fear not. You 
will not see the Egyptians (again). Stand by, and see the deliverance of the Lord 
(Exod. 14:3), the Lord will ﬁght for you, and you have only to be still (Exod. 14:14).” 
Aferwards Moses took permission from his Master, and he struck the sea with 
his rod and divided it. When the Sea of Reeds was opened before them, the 
Cloud and the Glory went leading them. Exalted be the Youngsters of the Divine 
Favor, before whom the sea was dried up and they walked (in). And the Egyp-
tians entered afer them into the sea, and it closed in on them, and they did not 
come out from it. See the diﬀerence between the two who entered. Moses entered 
and Pharaoh the king of Egypt entered. Moses entered – the Glory in front of him 
exalting him. Pharaoh entered – the Destroyer in front of him for his destruction. 
Moses entered – the Divinity elevates him. Pharaoh entered – the Divinity takes 
vengeance on him. Moses entered and the angels attended to him. Pharaoh 
entered and the angels chastised him. Like Moses none has arisen and will never 
arise.','יצאו כרוזים בארץ מצרים, ונאספו כל הלוחמים, אסר את מרכבתו ולקח את אנשיו עמו (שמות יד,ו). ושש מאות מרכבות בחורות לבשו נשק עמו למלחמה, ומרכבות מצרים עם פקידים בכולן (שמות יד,ז). רדפו אחרי ישראל והשיגום כאשר חנו על הים (שמות יד,ט). עמד פרעה המלך לפני בעל-צפון והקריב לו שם קרבן שקר, כי בעל-צפון היה אחד האלים שבהם בטח. גדולה הייתה הבהלה שבה עמדו שם נבהלים, שמא יצטרכו לשוב למצרים. אמרו למשה בפחד עצום: "דע כי אתה הוא רוצח ישראל. מה נעשה ומה נוכל לעשות? האויב מאחורינו והים לפנינו. הלא זה הוא הדבר אשר דיברנו אליך במצרים לאמור: חדל ממנו ונעבוד את המצרים (שמות יד,יב). מה עשית לנו, הוציאך אותנו ממצרים? (שמות יד,יא) כולנו נֵהרג כהרף עין." ואמר משה אליהם: "אל תיראו. לא תוסיפו עוד לראות את המצרים. התייצבו וראו את ישועת ה'' (שמות יד,יג), ה'' ילחם לכם ואתם תחרישון (שמות יד,יד)." לאחר מכן נטל משה רשות מאדונו, והכה את הים במטהו ויבקעהו. כאשר נפתח ים-סוף לפניהם, הלכו הענן והכבוד לפניהם. מרומם יהי בכורי החסד האלוהי, אשר לפניהם יבש הים ובתוכו הלכו. והמצרים נכנסו אחריהם לתוך הים, וסגר עליהם ולא יצאו ממנו. ראה את ההבדל בין שני הנכנסים. משה נכנס ופרעה מלך מצרים נכנס. משה נכנס – הכבוד לפניו לרוממו. פרעה נכנס – המשחית לפניו לאבדו. משה נכנס – האלוהות מגביהה אותו. פרעה נכנס – האלוהות נוקמת ממנו. משה נכנס והמלאכים שרתו אותו. פרעה נכנס והמלאכים ייסרו אותו. כמשה לא קם ולא יקום לעולם.');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (49,'I','7','ספר פליהתה',1000071,'וכדו אתי ואשלחנך ליד פרעה באהן פלענה דבידי גלי לך תקף רגליך ולא יקרב 25* לין נשש דבי משררהתין סגי מעל כל יבשתה יתב אדיך ויקרון כי בי מתקפהתין סגי מן עלמה חיץ לבך שריר ולא תשפלנה כי בי מעיצאתה הך שמשה וזהרה חיל לשנך ולא יקרב לה משתוק דבי מחילתה הך גללי ימה הפתח אדניך ומליתון נהירו דבי מפתחנון כות תהו ובהו דבביך עתידין מכפתין למליך ולא מנון יכל קעם לקבליך סניך עתידין ממעסין קמיך ולית בון תקומה סימה אנה בעי מעבד יומן ומסק דרכיך מכדו לדאתי אתהו דגבי פרית כל קהלה ופרק לון בשמי בחיל רב עד מותר','“Now come, I will send you to Pharaoh (Exod. 3:10) – by this (passage) the 
mission in My power is revealed to you. Fortify your feet, so that no weakness 
may approach them; indeed, I can fortify them more than anything on earth. 
Secure your hands and harden them; indeed, I can strengthen them more than 
anything in the world. Toughen your heart exceedingly and do not let it sink; 
indeed, I can toughen it like the (eternal) sun and moon. Empower your tongue 
so that dumbness never approach it; indeed, I can empower it, like the waves of 
the sea. Open up your ears and ﬁll them with understanding, for I can open them 
like the Formless and Void (Gen. 1:2). Your foes are about to be chained to your 
words, and there is not one among them able to withstand you. Your enemies are 
about to be crushed before you; they have no means of recovery. I am going to 
make a sign today (in order) to raise your rank from this moment on. You are the 
one who will take revenge for the entire congregation, and deliver them in my 
name with exceedingly great power.”','"לֵךְ נָא וְאֶשְׁלָחֲךָ אֶל פַּרְעֹה (שמות ג,י) – בפסוק זה נגלית לך השליחות שבכוחי. חַזֵּק את רגליך, כדי שלא תתקרב אליהן כל חולשה; אכן, ביכולתי לחזקן יותר מכל דבר שבארץ. הַבְטֵח את ידיך והקשה אותן; אכן, ביכולתי לאמצן יותר מכל דבר שבעולם. הַקְשֵׁח את לבבך מאוד ואל תיתן לו לשקוע; אכן, ביכולתי להקשיחו כשמש וירח הנצחיים. הַעֲצֵם את לשונך כדי שלא תיגש אליה לעולם אִלְּמוּת; אכן, ביכולתי להעצימה כגלי הים. פְּתַח את אוזניך ומַלֵּא אותן בינה, כי ביכולתי לפותחן כתֹהוּ וָבֹהוּ (בראשית א,ב). אויביך עומדים להיות כבולים לדבריך, ואין בהם אחד שיוכל לעמוד מולך. שונאיך עומדים להידכא לפניך; אין להם כל תקומה. אני עומד לעשות היום אות להרים את מעמדך מרגע זה ואילך. אתה הוא שייקח נקמה עבור כל העדה, ויושיעה בשמי בכוח גדול מאוד."');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (50,'I','48','ספר פליהתה',1000481,'עבד רוח רמה ולא צבה שמע לון לבה מתקף בדיל דישתנק עבד רוח רמה ולא צבה שמע לון מדעה מתיקר בגלל דיתלחץ עבד רוח רמה ולא צבה שמע לון לשנה מקשי עדהן דיתלבט עבד רוח רמה ולא צבה שמע לון פמה › ד ‹ ישפע רגז יתשקי מי מרה עבד רוח רמה ולא צבה שמע לון חשבה ] ת [ ה מצמחין נ ] ו [ ר יתוקד ב ] ה [ עבד רוח רמה ולא צבה ש ] מע [ לון קלה מגבר יתעקר דכרנה כד עמו נבייה עצינה דגלה לון עצפו במעבד מה אמר לון מרון 49] [ ואמר יה אל משה אמר אל אהרן › א ‹ נתח ית אד ] ך [ על נהר ] ה ו [ מחיתה ויה ] י [ אדם בכל ארע מצר בקיצמיה ובאבניה שפיר למאתה דקטל קעים באדה ] ואת [ עבד רבו רב ] ה [ בכל ארע מצרים פרעה קעם עליו והוא ממחי ולא יכל דבק לה ואלה כרז בכסי אה חיבה למה אתה קטול קעים בלא חוב אנית ברה דעדן יומה ממחי כי הוא מעזר הך דהוה ואתה מתקטל ולא תתוחי וגנותך כתיבה לדריה לעלם איעש רב מותר הוה לגו ארע מצר שעתה דאמחי נהרה וגוזליו פישון תלימה ודקל ונהר } ו { פרת אתמסרו למגבי פריתה וכד נלאו מן המיתי אל ארע מצר תלו קלה לברואה דברא תהו ובהו אנן בעין מנך אה מרה דעלמה תגבי לנן פרית תלימן מן פרעה זלו בשלם אמר לון דיאנה קשיטה אנהו דמגבי לה בעקבה','He exhibited arrogance and refused to listen to them – his heart was 
hardened so that he might be aﬄicted. He exhibited arrogance and refused to 
listen to them – his mind was hardened, so that he might be oppressed. He ex-
hibited arrogance and refused to listen to them – his tongue was hardened so 
that he might suﬀer. He exhibited arrogance and refused to listen to them – the 
mouth that pours out wrath will be given water of bitterness to drink. He exhib-
ited arrogance and refused to listen to them – his thoughts sprout forth ﬁre (but) 
he will be burnt by it. He exhibited arrogance and refused to listen to them – his 
voice is insolent, even the memory of him will be uprooted. When the two 
prophets saw the rebellion that he revealed to them, they exerted themselves to 
do what their Master commanded them.','הוא הפגין יהירות וסירב לשמוע להם – לבו הוקשה כדי שיוסר. הוא הפגין יהירות וסירב לשמוע להם – דעתו הוקשה כדי שיידכא. הוא הפגין יהירות וסירב לשמוע להם – לשונו הוקשה כדי שיסבול. הוא הפגין יהירות וסירב לשמוע להם – הפה השופך חמה ישקה מי מרירות. הוא הפגין יהירות וסירב לשמוע להם – מחשבותיו מצמיחות אש, ובה יישרף. הוא הפגין יהירות וסירב לשמוע להם – קולו עז פנים, ואף זכרו יעקר. כאשר ראו שני הנביאים את המרי שגילה לפניהם, השתדלו לעשות את אשר ציווה אותם אדונם.');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (51,'I','5','ספר פליהתה',1000051,NULL,'“I also kept you in the river of Egypt and brought you up safely in the 
house of your foe. You are the last of the world’s Righteous. I want to reveal their 
nature through you. By my goodness, I established a covenant with their fathers 
and I shall not forget it as long as the world lasts. Their children are pledged to 
Egypt for a long time, on account of the matter regarding which Abraham erred 
in “Ur Chasdim”, and I covenanted with him that this (will last) up to a certain 
limit. The time comes quickly to deliver (them) from distress. I can give you now 
its term for deliverance, for the time of the jubilee is near. He (Israel) has been in 
great and severe torment, ever since the day I have pledged him, and his outcry 
reached me with a sigh. For he has three great covenants (communicated) 
through those Righteous who passed away.”','"גם אותך שמרתי ביאור מצרים והעליתיך בשלום בביתו של אויבך. אתה האחרון בצדיקי העולם. אני רוצה לגלות את טבעם דרכך. בטובי כרתי ברית עם אבותיהם ולא אשכחנה כל עוד העולם קיים. בניהם משועבדים למצרים זמן רב, בשל הדבר שבו טעה אברהם באור כשדים, וכרתי עמו ברית שיימשך הדבר עד גבול מסוים. הזמן מגיע במהרה לגאולתם מן המצוקה. אוכל לתת לך עתה את מועד גאולתם, כי זמן היובל קרוב. הוא שהה בייסורים גדולים וקשים מאותו יום שמשכנתיו, וזעקתו הגיעה אלי באנחה. כי יש לו שלוש בריתות גדולות שנמסרו על ידי אותם צדיקים שחלפו."');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (52,'I','24','ספר פליהתה',1000241,NULL,'Moses took his wife and sons (Exod. 4:20) – the very morning afer the 
summon. Moses took his wife and sons – the warrior departs setting forth for 
battle. Moses took his wife and sons – the farmer seeks to go to his estate. Moses 
took his wife and sons – the elder goes to ascend to his rank. Moses took his wife 
and sons – the lover is sent to his beloved. Moses took his wife and sons – he sad-
dled his ass and took his wife and sons to go back.','וַיִּקַּח מֹשֶׁה אֶת אִשְׁתּוֹ וְאֶת בָּנָיו (שמות ד,כ) – בבוקר שלמחרת הקריאה. וַיִּקַּח מֹשֶׁה אֶת אִשְׁתּוֹ וְאֶת בָּנָיו – הלוחם יוצא ומכין עצמו לקרב. וַיִּקַּח מֹשֶׁה אֶת אִשְׁתּוֹ וְאֶת בָּנָיו – האיכר מבקש ללכת לנחלתו. וַיִּקַּח מֹשֶׁה אֶת אִשְׁתּוֹ וְאֶת בָּנָיו – הזקן הולך לעלות למעמדו. וַיִּקַּח מֹשֶׁה אֶת אִשְׁתּוֹ וְאֶת בָּנָיו – האוהב נשלח אל אהובתו. וַיִּקַּח מֹשֶׁה אֶת אִשְׁתּוֹ וְאֶת בָּנָיו – חבש את חמורו ולקח את אשתו ואת בניו לשוב.');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (53,'I','74','ספר פליהתה',1000741,'וכד אתרמי קלה לגו שבט אשר נפקת שרח לידון בזרוז ואמרת לית לכון כלום ביש האנה מפרסיה לוכון מהו אהן רזה סמכו בה ואתו ליד משה נביה וקעמת קדמיו והו הך זהר בגדלה אמרת שלם לך משה יקרון דאנשה שמע מני אהן רזה דאת בלש ישר לאלין תריה דאנהרו לעביבי ואתון נשיכונה אלולי דקעמו עמוד עננה ואשתה הויכון נפקין והוא שביק במצר נהירה אנה ליומה דמית בה והוא משבע לכל עמה יסקון גרמיו שפיר ליך שרח נהירתון דנשיה מן יומן ולעל תתני רבותיך אתרמי קלה בין קהלה ואתמר לון הן יוסף אתי נפק עמון כל שבט אפרים פעלהתה דשרח ומשה ואהרן מהלכין בתרון הלכת שרח קמיון וקעמת על אתרה דהוא טמיר לגוה וגלו על ארונה וסבלותה ופרקת שרח למשה ולאהרן 75] [ פתח נב רבה משה ארונה בימינה וגען עליו ואנשקה ובכה ושרי ביתה שעתה מבכי לה ואמר ניחח רוחך יקירה דבית אביו וכל קהלה קעם מבכי לה ואמר ניחח רוחך יוסף מסחן חרותה אה תדע רוחך דאתה סביל בידי ושת מון דאלף מקלסין גרמך עננה ואשתה נגידין קמיך ונופיה דמנך סבלין יתך לסכום מאה שתה וארבעים שתה אתה טמיר לגו ארע מצר ובתר כל אלין שניה את נפיק לארעה דפסיקה לך ניחח היא רוחך ברה דפרותה יוסף מלכה לבושה דחרותה דעביד לך רבו רבה בחייך ובמותך בחייך הויך מגלג בשלם דסגדו לך בניה דנשיה ובתר מותך את מגלג סגי מכן דאת מקלס בעננה ובאשתה כד אסכם נביה מן בכותה אמר לבית אפרים סבלותה אתון אתקדם יהושע וסבלה והוא כרז ואמר ניחח רוחך אבאה יקירה דבית אביו ירותה דירת כליל מן קנומה וירת לזרעה מרכבה דרוממו','When the rumor was spread within the tribe of Asher, Sherah came out 
to them in haste and said: “There is nothing wrong with you. I shall reveal to you 
what this mystery is.” They accompanied her and went to Moses the prophet. 
She stood before him, and he was like the full moon. She said: “Greetings to you, 
Moses, the glorious among men, hear from me about this mystery you enquire 
about. Strong be (the power of) those two who remembered my uncle, while you 
have forgotten him. Had not the Pillar of Cloud and Fire stopped, you would 
have gone forth, while he would have been lef behind in Egypt. I remember the 
day when he died and took an oath from the whole people to carry up his 
bones.” “It is good for you, Sherah, the most enlightened of women (said Moses). 
From this day on your greatness will be recounted.” The rumor spread among 
the congregation, and they were told that Joseph was going to exit with them. All 
the tribe of Ephraim were around Sherah, and Moses and Aaron followed them. 
Sherah was walking before them, and she stopped at the place where he was 
buried. They uncovered the coﬃn and lifed it up. And Sherah departed from 
Moses and Aaron.','כאשר פשטה השמועה בתוך שבט אשר, יצאה שרח אליהם בחיפזון ואמרה: "אין כל רע בכם. אני אגלה לכם מהו הסוד הזה." לִוּוה אותה והלכו אל משה הנביא. עמדה לפניו, והוא היה כירח מלא. אמרה: "שלום לך, משה, המפואר שבבני אדם, שמע ממני על הסוד שאתה חוקר. יחוזקו אלו השניים שזכרו את דודי, בעוד אתם שכחתם אותו. לולא עצר עמוד הענן והאש, הייתם יוצאים ואילו הוא היה נשאר מאחור במצרים. אני זוכרת את היום בו מת ונשבע את כל העם להעלות את עצמותיו." "כבוד לך, שרח, המשכילה שבנשים," אמר לה משה, "מיום זה תִּסּפר גדולתך." פשטה השמועה בקהל, ונאמר להם שיוסף עתיד לצאת עמם. כל שבט אפרים נקבץ סביב לשרח, ומשה ואהרן הלכו אחריהם. שרח הלכה לפניהם ועצרה במקום בו היה קבור. גילו את הארון ונשאו אותו. ושרח נפרדה ממשה ואהרן.');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (54,'I','32','ספר פליהתה',1000321,'רחטו רחיטה ליד משה ואהרן וקעמו קמיון באפין מלין עכר ואמרו לון יחזי יהוה ] ע [ ליכון וידין דאנדיכ } נ { ון לנן כל הדה עקתה אנשימין הוינן בעמל לבניה מיום דאתיתון אתחילת עקתן קט } ו {› י ‹ לין אנן באדיכון הלא אסרתון ריחנן בכל ארע מצר דהדה גנוה רבה למלך מצר ישלח שת מון דאלף עם כותכון על ממללה דמללתון לו שקח בידה חרב קטלנן הך ארפו עין 33] [ כד שמע משה ואהרן אהן מימרה הוו בצער חיול ואמר משה ליה ולבה מלי דחלה אה מרי אמר לי מהו אהן רזה מטט עלית לפרעה לממלל בשמך הבאש לעמה הדן בישו רבה לחדה ועמה בתשניק מוזף עליו עקין סגי ממה דהוו ולבט מתחדד כל יום סגי מן יומה דקדמה ואמר יהוה אל משה נביי לא מטרן קריב את עמי בה פליהן רברבן כי לבה אנה מתקף ובעקבה יתעקר דכרנה האנה גלי לך שמי רבה יה לא גליתה לזכאי עלמה באל שדי אתחזית לאבר › ה ‹ ם ליצ וליעקב ואהן שמי רבה לא גליתה לון דו שם יקיר מלי מצ } ת {› כל בריתה ובה עלמה ט ‹ עד וכל קיאמי זכאי קטיר לה לעלם ולינה מנשי לה ועלמה עלם דת משקח בידי עליון כל עלמה בדיל דן גלית לך שמי רבה','They ran in haste to Moses and Aaron, and stood before them with faces 
full of distress, and said to them: “May the Lord look upon you and judge (Exod. 
5:21), for you brought upon us all this aﬄiction. We were (quite) relaxed while 
producing bricks; from the day you came our aﬄiction increased. We are slain at 
your hands, for you made us loathsome (Exod. 5:21) throughout the land of 
Egypt. For this would be a great shame on the part of the king of Egypt, if he 
were to let six hundred thousand go with the like of you because of the speech 
you spoke. If he had a sword in his hand, he would slay us in a ﬂash.”','רצו בחיפזון אל משה ואל אהרן, ועמדו לפניהם כשפניהם מלאות מצוקה, ואמרו להם: "יֵרֶא ה'' עֲלֵיכֶם וְיִשְׁפֹּט (שמות ה,כא), כי הבאתם עלינו את כל הצרה הזו. היינו רגועים בעשיית הלבנים; מיום שבאתם גברה צרתנו. אנחנו הרוגים בידיכם, כי הִבְאַשְׁתֶּם אֶת-רֵיחֵנוּ (שמות ה,כא) בכל ארץ מצרים. שכן יהיה זה קלון גדול מצד מלך מצרים לשלח שש מאות אלף בגללכם ובגלל הדברים שאמרתם. לו הייתה חרב בידו, היה שוחט אותנו ברגע אחד."');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (55,'I','12','ספר פליהתה',1000121,'אכהן תימר לבני ישראל אהיה שלחני אליכם לשלם חיולה דקיאם עם אברהם וימה ליצחק ופסק עם יעקב דן שמי לעלם ודן דכרי לדר ודור קעים דלא מאת ויצוב לא פני באהן שמה רבה חילת לון ולא עבראי שמעין כדו בה סב אטרה באדך ואזל למצרים וידעון דאת שליח מדילי ושעתה דתמטי כנש ית חכימי ישראל שוי דאת זעק לון ומיתב לון סדר פרס ית אגרתי קמיון ואימר כל מה דאמרת לך בסניה בשלם אמר לון תמן ברבו חיולה','“Thus shall you speak to the people of Israel: ‘‘I am’ sent me to you (Exod. 
3:14) in peace; the Mighty One who covenanted with Abraham, and swore an 
oath to Isaac, and bestowed upon Jacob.’ This is My name for ever, and thus I am 
to be remembered throughout all generations (Exod. 3:15), the Living One who 
does not die, the Stable One who does not vanish. (If) by this great name you 
have strengthened them, and the Hebrews do not now hearken to it, take the rod 
in your hand and go to Egypt, that they may know that you are a messenger of 
mine. When you arrive, gather the elders of Israel (Exod. 3:16). As soon as you 
summon them and settle them in order, spread out my message before them and 
say everything that I have told you in the bush, in entirety. Speak to them there 
with strong greatness.”','"כה תאמר לבני ישראל: ''אֶהְיֶה שלחני אליכם (שמות ג,יד) בשלום; הגיבור שכרת ברית עם אברהם, ונשבע לישחק, ורחם על יעקב.'' זֶה שְּׁמִי לְעֹלָם וְזֶה זִכְרִי לְדֹר דֹּר (שמות ג,טו), החי שאינו מת, הנצחי שאינו חולף. אם בשם הגדול הזה תחזקם, ועתה לא ישמעו לו העברים, קח את המטה בידך ולך למצרים, כדי שידעו שאתה שליחי. כשתגיע, אסוף את זקני ישראל (שמות ג,טז). מיד כשתזמנם ותסדר אותם כסדרם, פרוש לפניהם את דברי ואמור את כל אשר אמרתי לך בסנה, כולו. דבר אליהם שם בגדולה ובעוז."');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (56,'I','58','ספר פליהתה',1000581,NULL,'And (Pharaoh) stiﬀened his heart that time again and he did not let the 
people go, as the Lord had commanded. The Lord said to Moses: “Stretch out 
your hand over the land of Egypt for the locusts” (Exod. 10:12). So, Moses 
stretched out his hand and locusts came up over all the land of Egypt, punishing 
the Egyptians with great punishment. And the plague (that struck) Pharaoh and 
his people was greater than the seven plagues that preceded it. It consumed the 
trees and destroyed the grass and ruined the houses and emptied (them) of food. 
The spirit of Pharaoh was oppressed by it and he named it death, for like death it 
was bitter. He summoned Moses and Aaron and said: “Pray to the Lord that He 
removes […] this death from me (Exod. 10:17).” Moses supplicated his Master, and 
He accepted his request. He turned a west wind and drowned them into the Sea of 
Reeds (Exod. 10:19).','וַיַּקְשֵׁ (פַּרְעֹה) אֶת לִבּוֹ בַּפַּעַם הַהִיא שׁוּב, וְלֹא שִׁלַּח אֶת הָעָם, כַּאֲשֶׁר צִוָּה ה''. וַיֹּאמֶר ה'' אֶל מֹשֶׁה: "נְטֵה יָדְךָ עַל אֶרֶץ מִצְרַיִם בָּאַרְבֶּה" (שמות י,יב). וַיֵּט מֹשֶׁה אֶת יָדוֹ וַיַּעַל אַרְבֶּה עַל כָּל אֶרֶץ מִצְרַיִם, וַיַּכֶּה אֶת הַמִּצְרִים מַכָּה גְדוֹלָה. וְהַמַּכָּה אֲשֶׁר הִכְּתָה אֶת פַּרְעֹה וְאֶת עַמּוֹ הָיְתָה גְדוֹלָה מִשֶּׁבַע הַמַּכּוֹת שֶׁקָּדְמוּ לָהּ. אָכַל אֶת הָעֵצִים וְשִׁחֵת אֶת הָעֵשֶׂב וְקִלְקֵל אֶת הַבָּתִּים וְרוֹקְנָם מֵאֹכֶל. וְרוּחַ פַּרְעֹה נִלְחֲצָה מִפָּנָיו, וַיִּקְרָא לָהּ מָוֶת, שֶׁכַּמָּוֶת מָרָה הִיא. וַיִּקְרָא לְמֹשֶׁה וּלְאַהֲרֹן וַיֹּאמֶר: "עִתְּרוּ אֶל ה'' וְיָסֵר [...] הַמָּוֶת הַזֶּה מֵעָלַי" (שמות י,יז). וַיִּתְפַּלֵּל מֹשֶׁה אֶל אֲדֹנָיו, וַיִּשְׁמַע תְּפִלָּתוֹ. וַיַּהֲפֹךְ רוּחַ יָם וַיִּטְבְּעֵם בְּיַם סוּף (שמות י,יט).');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (57,'I','60','ספר פליהתה',1000601,NULL,'And the Lord said to Moses afer all these (events): “I will bring but one 
more plague upon Pharaoh and upon the Egyptians (Exod. 11:1). Afer this tenth 
plague he will let you go in haste. Like one who needs something and sends for 
it, like this he will send you (away) from his land. About midnight (Exod. 11:4), 
my delegate will descend and slay all the ﬁrstborn within the land of Egypt, from 
the ﬁrstborn of Pharaoh who sits on his throne to the ﬁrstborn of the maidservant 
who is behind the millstones (SP Exod. 11:5). A great cry shall be heard there, such 
as has never been and never will be again.” Moses and Aaron repeated these 
words to Pharaoh, warning him, so that they might be exempt from him: “Thus 
said the Lord, let My people go, that they may worship Me (Exod. 7:16). And if you 
do not let them go to worship, then He will kill your ﬁrstborn.” He ignored the 
speech and did not listen, and hardened his heart, and did not let the people go.','וַיֹּאמֶר ה'' אֶל מֹשֶׁה אַחֲרֵי כָּל הַדְּבָרִים הָאֵלֶּה: "עוֹד נֶגַע אֶחָד אָבִיא עַל פַּרְעֹה וְעַל מִצְרַיִם" (שמות יא,א). אַחֲרֵי הַמַּכָּה הָעֲשִׂירִית הַזֹּאת יְשַׁלַּחֲכֶם בְּחִפָּזוֹן. כְּמִי שֶׁזָּקוּק לְדָבָר מָה וְשׁוֹלֵחַ לְהָבִיאוֹ, כֵּן יְשַׁלַּחֲכֶם מֵאַרְצוֹ. "כַּחֲצוֹת הַלַּיְלָה" (שמות יא,ד) יֵרֵד שְׁלוּחִי וְיַךְ אֶת כָּל בְּכוֹר בְּאֶרֶץ מִצְרָיִם, מִבְּכוֹר פַּרְעֹה הַיּוֹשֵׁב עַל כִּסְאוֹ וְעַד בְּכוֹר הַשִּׁפְחָה אֲשֶׁר אַחַר הָרֵחַיִם (נוסח שומרוני שמות יא,ה). צְעָקָה גְדוֹלָה תִּשָּׁמַע שָׁם, כַּאֲשֶׁר לֹא הָיְתָה כָמוֹהָ וְלֹא תֹסֶף עוֹד." חָזְרוּ מֹשֶׁה וְאַהֲרֹן עַל הַדְּבָרִים הָאֵלֶּה לִפְנֵי פַּרְעֹה, וְהִזְהִירוּהוּ, לְמַעַן יִנָּקוּ מִמֶּנּוּ: "כֹּה אָמַר ה'', שַׁלַּח אֶת עַמִּי וְיַעַבְדֻנִי" (שמות ז,טז). "וְאִם לֹא תְשַׁלְּחֵם לַעֲבֹד, יַמִּית אֶת בְּכֹרְךָ." בָּזָה לַדְּבָרִים וְלֹא שָׁמַע, וַיַּקְשֵׁ אֶת לִבּוֹ, וְלֹא שִׁלַּח אֶת הָעָם.');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (58,'I','28','ספר פליהתה',1000281,'יעקב אזדמן לעשו בתר שנין סגים ורמת חדותון ושרת דבבותון בנקירות תקפה קעמו תריון ברחמו חיולה וחוה משה לאהרן כל ממללי יהוה ועמתה יתון סימניה ועבדו › ן ‹ לחזותה וכד שמע אלין מליה מן משה ] ש [ רי מימר ] תש [ בחן לאלהה ] דע [ למה אשפיר לך אחי במה דגלה לך מן אלין רזיה מה ] טב מע [ מינון ] עלי [ ן ] למ [ צרים ] הך תרי מ [ לאכיה דעלו ל [ סדם ] ועלו ת [ רי מלאכ ] ] לסדם ברמ [ שה ] משגרין למ [ פתח ] אוצר רג [ זה ] על כל דיא [ ריה ] דלג [ וה ועלו משה ואהרן למצר ברמשה משגרין מפתח אוצר דינה לגוה מלאכיה הוו לבישין אלהו ומשה ואהרן לבישין שלטנו מלאכיה משלחין למחבל סדם ומשה ואהרן משלחין למחבל מצרים מלאכיה אכלו פטיר לגו סדם ומשה ואהרן קבעו במצרים חג פטיר מלאכיה אוקדו גוזלין מתהומה ומשה ואהרן קטלו פישון ברה דעדן מלאכיה הפקו ללוט בצפרה ומשה ואהרן הפקו ישראל מקדם צפרה','Jacob met with Esau afer many years, and their joy rose, and their ha-
tred dissolved. In the clef of the rock (Exod. 33:22) they both stood in mighty af-
fection, and Moses told Aaron all the words of the Lord (Exod. 4:28) and showed 
those signs and performed them in his sight. When he heard these words from 
Moses, he began to speak praises to the God of the world. “Happy are you, my 
brother, for what (God) revealed to you of these secrets.” How good to see them 
enter Egypt like the two angels who entered Sodom. The two angels entered 
Sodom in the evening (Gen. 19:1) – sent to open the storehouse of wrath upon all 
the inhabitants therein. Moses and Aaron entered Egypt in the evening, sent to 
open the storehouse of punishment in it. The angels were wrapped in divinity, 
and Moses and Aaron were wrapped in authority. The angels were sent to de-
stroy Sodom, and Moses and Aaron were sent to destroy Egypt. The angels ate 
unleavened bread in Sodom, and Moses and Aaron established in Egypt the feast 
of unleavened bread. The angels burnt children of the depth, Moses and Aaron 
smote Pishon, the son of Eden. The angels drove Lot out in the morning, and 
Moses and Aaron drove Israel out before morning.','יעקב פגש את עשו לאחר שנים רבות, ושמחתם גברה ושנאתם נמוגה. בנקרת הסלע (שמות לג,כב) עמדו שניהם באהבה עזה, וַיַּגֵּד משה לאהרן את כל דברי ה'' (שמות ד,כח) והראה לו את האותות ועשה אותם לעיניו. כששמע אהרן את הדברים הללו ממשה, פצח בשבחים לאלוהי העולם. "אשריך, אחי, על מה שנגלה לך מסודות אלה." מה טוב לראותם נכנסים למצרים כשני המלאכים שנכנסו לסדום. שני המלאכים באו סדומה בערב (בראשית יט,א) — שלוחים לפתוח את אוצר החרון על כל יושביה. משה ואהרן נכנסו למצרים בערב, שלוחים לפתוח בה את אוצר העונש. המלאכים היו עטויים באלוהות, ומשה ואהרן היו עטויים בסמכות. המלאכים נשלחו לאבד את סדום, ומשה ואהרן נשלחו לאבד את מצרים. המלאכים אכלו מצות בסדום, ומשה ואהרן תיקנו במצרים את חג המצות. המלאכים שרפו את בני התהום, משה ואהרן הכו את פישון בן עדן. המלאכים הוציאו את לוט בבוקר, ומשה ואהרן הוציאו את ישראל לפני הבוקר.');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (59,'I','38','ספר פליהתה',1000381,'יאי מעמינון עלין ליד מלכה וטובה › וחסדה ‹ מסמכין לון כד ברטו לידה וקעמו קדמיו יהבו לה שלם ולסיע ] ת [ ה דיתיבים תלא מלכה עיניו ועמה יתון קעמין באפין זקיפין סגי ממה דהוו אמרו בעותכון עד ישמעון כל יתיביה וכד עמו יתון סיעת מלכה תמחו מנון תמח רב יתיר ואמרו ] ל [ מלכה לית ] אכה [ כותון לית ] לגו מ [ צרי ] ם נ [ הירי ] ן [ דמותון ] ג [ ליתון ] מעמיה [ כסיאתו ] ן [ אמר לון פרעה שמעו הך ממללון רב מנון האנה מרשי לון כדו ימללון מה דאנון בעין מן ממללה עמי אמרו בעותכון אה תרי אחיה והן הוה נהי עלי עבדת','It is good to see them going in to the king, while Goodness and Grace ac-
company them. When they reached him and stood before him, they gave greet-
ings to him and to the company of counsellors. Pharaoh lifed up his eyes and 
saw them standing with upright faces, more so than before. “Speak your request, 
that all the counsellors may hear.” When the king’s company saw them, they 
were very greatly amazed, and they said to the king: “There is none like them 
here. There is none within Egypt enlightened like them. Their appearance shows 
their innerness.” Pharaoh said to them: “Listen to how their speech is greater 
than their rank. Behold, I permit them now to speak what they want to speak to 
me.” “Tell your request, O two brothers, and if it is convenient for me, I will do it.”','טוב לראותם נכנסים אל המלך, כשהטוב והחסד מלווים אותם. כשהגיעו אליו ועמדו לפניו, נתנו ברכת שלום לו ולחבר היועצים. פרעה נשא את עיניו וראה אותם עומדים בפנים זקופות, יותר מבפעם הקודמת. "אמרו את בקשתכם, למען ישמעו כל היועצים." כשראה חבר המלך אותם, השתוממו השתוממות עצומה, ואמרו למלך: "אין כמותם כאן. אין בכל מצרים נבון כמותם. מראם מגלה את פנימיותם." אמר להם פרעה: "שמעו כיצד דבריהם גדולים ממעמדם. הרי אני מרשה להם עתה לדבר את אשר יחפצו לדבר אליי." "אמרו את בקשתכם, שני האחים, ואם היא נוחה לי, אעשנה."');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (60,'I','11a','ספר פליהתה',1000112,'נסתכל ימה ונשמע לה הך הו אמר עסלי ממעבד מה יכעס לקשטה לא אתברית למרד ולא לתמרי אלא לשעבוד למימר קשטה ונביה רבה משה אמר לימה אשדך כיינך מתעבד דיאן תדין בקשט וימה כאמר למשה בארכנו מה דאתה מרשי לי ליתי יכל עצינך דאתה חכמת ביד קשטה מן שרוי דבראתך מרך גדלך וחילך על כלה בגוי אתרמית ואתה טלי ואמתן יתי קשטה עד אסתבלת מני ומשה כאמר לה בארשותה דקשטה רבה דתמן הגלה אכהן אתחדד אנית לגוך נגלא סימן אחד בגללי כי בידי בגוך סימנים תתעבד אנית סבלתני ואנה טלי כייך סבל לי וכל רבבות קדשה עמי אנית מצרים הבלדת ואנה בך רמי כיי תבלד ואנה בך געז אנית מצרים השדכת ביד קסמיה כינה מתחרבה ביד קשיטיה אנית פרעה חדי במלי גדפים כינה אביד במלי צדיקים אשדך אה ימה כיינן לידך אתין ומרן אקימך דיאן תדין בקשט וימה כאמור אה טובי בכן דתשקחת מלוא במד לי ירשי ליתי מתרשי אלא במד קשטה רחם ודיהי מלוך בכן מתבסר בכל ומשה הך אמר לה אשדך כינך מתרים במד בך מתעבד מפצי ומאבד אה איקר יתיר מתרים בתריה ביני כל בוראיה דכל אמי עלמה לא חזו אהן ולא שמעו דאהן אתעבד כי פרעה אתרבה בבישו יתרה והגדל בה על בישיה דגעזו מכן מגביה יתר על כלה','Let us contemplate the sea and listen to it as it speaks: “Far be it from 
me to do anything to provoke the True One! I was not created for rebellion or dis-
obedience, but for subservience to the word of the True One.” The great prophet 
Moses said to the sea: “Be still, indeed you will become a judge, and you will 
judge justly.” It was as though the sea was saying with submissiveness to Moses: 
“What you command me I cannot disobey, for you know by the True One, since 
the beginning when your Master created you, (what is) your greatness and 
strength above all. You were cast into me while yet a child, and the True One 
eased me, until you were lifed out of me.” It was as though Moses was saying to 
it: “By the will of the mighty True One who was revealed there, be the same 
again. If there was one wonder once manifested in you on my account, indeed 
through me (many) marvels will yet be done in you. If you bore me when I was a 
child, indeed you shall bear me while all the holy myriads accompany me. If 
Egypt was terriﬁed when I was cast into you, indeed it will be terriﬁed while I 
pass through you. If Egypt was at peace through the magicians, indeed it will be 
devastated through the righteous. If Pharaoh rejoiced at the words of blasphe-
mers, indeed he will perish at the words of the righteous. Be still, O sea, for 
indeed we are coming into you, and our Lord has appointed you to be a judge, 
(so that) you judge justly.” And it was as though the sea was saying: “Happy am I 
because of this, for I have been found worthy of that which He commands me to 
do. I am only commanded to do what the True One desires. He who possesses 
this will receive every tiding.” And it was as though Moses said to it: “Be still. 
Indeed you will be exalted through what will be wrought in you by (the) 
Deliverer and (the) Destroyer. Behold, an excessive glory to be exalted by the two 
among all creatures, for all the peoples of the world have not seen this nor have 
they heard that this has taken place. Indeed, Pharaoh magniﬁed himself by 
excessive evil and has become exalted in it more than the evildoers who passed 
away. Therefore, his punishment exceeds all.”','הבה נתבונן בים ונקשיב לו כשהוא מדבר: "חלילה לי לעשות דבר כדי לקצוף על האמת! לא נבראתי למרד או לסרבנות, אלא לשרת את דבר האמת." אמר לו משה הנביא הגדול: "שקוט, שכן תהיה לשופט ותשפוט משפט צדק." והיה כאילו הים אומר בהכנעה למשה: "את אשר תצווה עלי אינני יכול לסרב לו, כי אתה יודע על פי האמת, מאז הראשית כשבראך אדונך, את גדולתך ועוצמתך מעל לכל. הושלכת אלי עודך ילד, והאמת הרגיעני, עד שהורמת ממני." והיה כאילו משה אומר לו: "ברצון האמת האדירה שנגלתה שם, היה כבתחילה. אם נס אחד נתגלה בך פעם בזכותי, אכן על ידי יעשו בך עוד נפלאות. אם נשאת אותי כשהייתי ילד, אכן תישאני בעוד כל הרבבות הקדושות מלוות אותי. אם מצרים נבעתה עת הושלכתי אליך, אכן תיבעת בעוברי דרכך. אם מצרים שקטה על ידי החרטומים, אכן תיחרב על ידי הצדיקים. אם פרעה שמח לדברי המגדפים, אכן יאבד לדברי הצדיקים. שקוט, ים, כי אכן אנו באים אליך, ואדוננו ייעד אותך להיות שופט, כדי שתשפוט משפט צדק." והיה כאילו הים אומר: "אשרי בזאת, שנמצאתי ראוי לדבר שהוא מצווה עלי לעשות. אינני מצווה אלא לעשות מה שהאמת חפצה בו. מי שיש לו זאת יקבל כל בשורה." והיה כאילו אמר לו משה: "שקוט. אכן תתעלה על ידי מה שייעשה בך על ידי המציל והממית. הנה כבוד עצום להתעלות על ידי השניים מכל היצורים, כי כל עמי העולם לא ראו זאת ולא שמעו כי דבר זה אירע. שכן פרעה גידל את עצמו בסגולת הרוע וניתרומם בה מעל כל הרשעים שחלפו. לכן עונשו עולה על הכל."');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (61,'I','42','ספר פליהתה',1000421,'כד שמעו עבדיה דלמבר מלכה מצטער בלבה אתו וקעמו קבלה ואמרו לו מרחיק אמר לן כל מה תתריח אמר זרזו לי בחכימיה וכל מכשפיה רחטו בזריזו רבה ולבביון מלין דחלה הך ארפות עין ואמרו לון זרזו אתו לות מלכה דו בבלוד רב וקשי וגויתה מעיקה ורוחה מעיסה קעמו באתרון בתלש חיול ואדיקו על תרחה ועמותה במרטוש וכל עבדיו כותה רישיון מרכנין פסקו ועלו ליד מלכה ] ואש [ קחו יתה ] עכי [ ר ותנינה ] קדמיו [ מתגבר ] והוא [ דחל מנה ] דלא יבל [ ענה ] ומשה ו [ אהרן ] הך תרי מ [ אורין ] אפיון [ מנירים ] לגו מדו [ רה דפרעה ] מ [ לכה','When the servants outside heard that the king’s heart was in distress, 
they came and stood before him and said to him from afar: “Tell us all what you 
want (us to do).” He said: “Quickly bring to me the sages and all the magicians.” 
They ran in great haste, in a wink of an eye, their hearts full of fear, and told 
them: “Come in haste to the king, for he is in a great and hard anxiety. His body 
is oppressed and his spirit crushed.” They stood in their place in mighty dismay. 
They looked over the gate and saw him in distress, and all his servants alike, 
their heads lowered. They made a decision and entered to the king, and found 
him disturbed, and the serpent in front of him grew stronger, while he fears it 
lest it should swallow him. And Moses and Aaron like two luminaries, their faces 
shining within the abode of Pharaoh the king.','כששמעו המשרתים שבחוץ שלב המלך בצרה, באו ועמדו לפניו ואמרו לו מרחוק: "אמור לנו כל אשר תחפוץ." אמר: "מהרו והביאו לי את החכמים ואת כל החרטומים." רצו בחפזה גדולה, כהרף עין, לבם מלא פחד, ואמרו להם: "בואו בחפזה אל המלך, כי הוא נתון בדאגה גדולה וקשה. גופו לחוץ ורוחו שבורה." עמדו במקומם בתדהמה עצומה. הציצו מעבר לשער וראו אותו בצרה, וכן כל משרתיו, ראשיהם מושפלים. החליטו ונכנסו אל המלך, ומצאוהו נסער, והנחש לפניו הולך ומתחזק, והוא יָרֵא ממנו פן יבלענו. ומשה ואהרן כשני מאורות, פניהם מאירות בתוך ארמון פרעה המלך.');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (62,'I','14a','ספר פליהתה',1000142,'עזר נביה רבה משה ממללה עם פרעה ומצראי מה דן מיתיה דאתיכון כדו עתיד לוכון מגוי לית יקום בה אלא אתון וכל ההלך בתרכון עמו נביה רבה משה דאתחיל רבינה תלא אדה על ימה ברבו רבו עמו אדה דאתעבדת כרי לסימניה מתליה על ימה דסוף ברבו רבה עמו פמה דקדש מיום דאתברא אתרבה קדושה מיום דאזדעק ושבח למרה כד תלא אדה על ימה ופלגה אה אימה רבה לבשה ימה כד תלא משה אדה עליו ומללה ברבו השדך למי בך יגוז } י { הגיבה בדחלה רבה וארכנו יתרה פי מרי ליתי מעלם עליו כיתי עסרתיתה דשרת בי מן רמשה עד צפרה מלתה דקות מימי ואורה דבי אניר ורוחה דנשפי ואשתה דיבשת יתי וסימניה דבקעוני ואותתיה דסגרו יתי ובריאתה דנדנדוני וקדומה דנגבותי ורגזה דבי שרי ואפילותה דאתעבדת ריש לכ » ל « דהוה ומשה הך אמר לה לא תצטעדי מן הדה אלולי אתבחרת לכן לא הזדמן בך ואנתח משה ית אדה על ימה וקשטה כאמור לה רבותך תתני בכל דרי עלמה','The great prophet Moses conversed again with Pharaoh and the Egyp-
tians. “What is the point of your coming now? Punishment is made ready for 
you. No one shall be subjected to it except you and those who follow you.” See 
the great prophet Moses, whose greatness was reinforced, raising his hand over 
the sea with great might. See his hand, which was made a source of wonders, 
uplifed over the Sea of Reeds with great might. See his holy mouth, from the day 
he was created its holiness was increased; since the day he was called, it praised 
his Master. When he raised his hand over the sea, he divided it. Behold a great 
terror which the sea put on when Moses raised his hand over it and addressed it 
in greatness: “Be still for those who are to cross you.” It answered him with great 
fear and excessive submissiveness: “I cannot contradict the command of my 
Lord, because of the ten (things) which were wrought in me from evening till 
morning: (1) the word that brought my waters together; (2) and the light that 
shone on me; (3) and the wind that blew on me; (4) and the ﬁre that dried me up; 
(5) and the signs that divided me; (6) and the wonders that shut me in; (7) and 
the miracles that shook me; (8) and the east wind that dried me up; (9) and the 
fury that resided in me; (10) and the darkness that became the starting-point of 
all that happened.” And it was as though Moses was saying to it: “Do not be 
afraid of this. If you had not been chosen for this, it would not have been 
appointed for you.” Moses stretched out his hand over the sea and it was as 
though the True One said to him: “Your greatness will be recounted throughout 
the generations of the world!”','הנביא הגדול משה שוחח שוב עם פרעה והמצרים. "מה טעם בואכם עתה? העונש מוכן לכם. לא יהיה נתון בו איש זולתכם ואלה שהולכים אחריכם." ראו את הנביא הגדול משה, שגדולתו התחזקה, מרים את ידו על הים בכוח רב. ראו את ידו, שנעשתה מקור לנפלאות, מורמת על ים סוף בכוח רב. ראו את פיו הקדוש, שמיום שנברא גדלה קדושתו; מיום שנקרא, שיבח את אדונו. כשהרים את ידו על הים, בקעו. הנה אימה גדולה שלבש הים כאשר הרים משה את ידו עליו ופנה אליו בגדולה: "הירגע לפני אלה שעברו בך." ענה אותו ביראה גדולה ובהכנעה יתרה: "איני יכול לסתור את פקודת אדוני, מפני עשרת (הדברים) שנעשו בי מערב עד בוקר: (1) הדבר שכינס את מימיי; (2) והאור שזרח עליי; (3) והרוח שנשבה עליי; (4) והאש שייבשה אותי; (5) והאותות שבקעו אותי; (6) והנפלאות שסגרו אותי; (7) והנסים שהרעידו אותי; (8) ורוח הקדים שייבשה אותי; (9) והחמה שישבה בי; (10) והחושך שהיה ראשית כל שאירע." והיה כאילו משה אמר לו: "אל תירא מזאת. לוּ לא נבחרת לכך, לא היה נועד לך." משה נטה את ידו על הים, והיה כאילו האמיתי אמר לו: "גדולתך תסופר בכל דורות העולם!"');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (63,'I','11','ספר פליהתה',1000111,'ארתת עלמה וכל } וכל { בוראי דלגוה אמת דאמר אלה למשה אהיה אשר אהיה הוה ויי אקר דלא שרוי אהיה אשר אהיה קעומה דבראשית וטור סיני אהיה אשר אהיה אמור עלמה וזעוק בוראיה אהיה אשר אהיה צעורה דגויתה ויסדה דנפשה אהיה אשר 7923 . אהיה נצובה דגנתה ושלואה דסדם אהיה אשר אהיה פרנס חייה ואריסה דמותה אהיה אשר אהיה אלהון דזכאי ומרה דעבראי אמת דאנון שמעין מנך אהן שמה רבה כהלון עתידין שמעין ועבדין','The world and every creature in it trembled when God said to Moses: “I 
am who I am (Exod. 3:14) – who was and will be, a fundament without begin-
ning. I am who I am – the Master of בראשיתand Mount Sinai. I am who I am – the 
Creator of the world and summoner of creatures. I am who I am – the shaper of 
bodies and the founder of souls. I am who I am – the planter of the Garden and 
the uprooter of Sodom. I am who I am – the supporter of life and the planter of 
death. I am who I am – the God of the Righteous and the Master of the Hebrews. 
Whenever they hear from you this great name, they will all be ready to listen and 
act.”','העולם וכל יצור שבו רעדו כאשר אמר אלוהים למשה: "אֶהְיֶה אֲשֶׁר אֶהְיֶה (שמות ג,יד) – אשר היה ויהיה, יסוד ללא ראשית. אֶהְיֶה אֲשֶׁר אֶהְיֶה – אדון הבראשית והר סיני. אֶהְיֶה אֲשֶׁר אֶהְיֶה – בורא העולם וקורא היצורים לחיים. אֶהְיֶה אֲשֶׁר אֶהְיֶה – יוצר הגופות ומייסד הנשמות. אֶהְיֶה אֲשֶׁר אֶהְיֶה – נוטע הגן ועוקר סדום. אֶהְיֶה אֲשֶׁר אֶהְיֶה – מחיה החיים ונוטע המוות. אֶהְיֶה אֲשֶׁר אֶהְיֶה – אלוהי הצדיקים ואדון העברים. בכל עת שישמעו ממך את השם הגדול הזה, יהיו כולם נכונים לשמוע ולעשות."');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (64,'I','30','ספר פליהתה',1000301,'› ו ‹ מבתר דאפטרו עמה באשגלון עלו נבייה ליד פרעה מלכה דרשו ארשו אדלא עלו לידה והגיבון ועלו וקעמו קדמיו וטובה מימינון וחסדה משמאלון אמר אהרן בארשותך אה מלכה אמלל קדמיך מלה חדה אמר › מלל ‹ אמר כדן אמר יה אלהה דישראל שגר ית עמי ויעבדני אתלש פרעה כד שמע ממללה וצפה לון ברגז חיול מנו אהן מלכה דאתיכון בשמה שמעת בכל מלכי עלמה ובשמה דאהן מלכה לא שמעת אלולי » אגור « דלא יהי גנו עלי ארשית בקטלכון אדלא תפקון לית אעמיכון כלום והן קטלת יתכון גנו עלי אנית לוכון במצרים סבלין איזלו לידון אדלא יתקף רגזי בוכון אלו אצטמתו מלכי עלמה למסב ישראל מני } לא { לא יכלו וילוכון אתון עבראים נשישים וזעורים בעינה קלילין בלבה ] ת [ סכון דאני אמר לוכון זלו סבו ישראל ופוקו','Afer the people had departed to their work, the prophets came to 
Pharaoh the king. They asked permission before entering to him, and he replied 
(favorably). They entered and stood before him, Goodness on their right, and 
Grace on their lef. Aaron said: “With your permission, O King, I will speak to 
you one word.” (Pharaoh) said: “Speak!” (Aaron) spoke: “Thus says the Lord, the 
God of Israel, Let My people go that they may worship me (Exod. 5:1).” Pharaoh 
was dismayed when he heard the utterance, and looked at them in a mighty 
rage. (He said): “Who is this king in whose name you have come? I have heard 
about all the kings of the world, but the name of this king I have not heard. Were 
it not (my fear) lest blame would be on me, I would order for you to be killed be-
fore you leave. I see you as nothing, and if I kill you, blame on me. If you have 
burdens in Egypt, go to them before my anger against you becomes stronger. If 
the kings of the world were to gather together to take Israel from me, they would 
not be able. Woe to you, Hebrews, weak and small to sight, feeble of heart. Do 
you expect that I shall say to you: Go, take Israel and depart?”','לאחר שהלך העם לעבודתו, באו הנביאים אל פרעה המלך. ביקשו רשות לפני שנכנסו אליו, והוא הסכים. נכנסו ועמדו לפניו, הטוב לימינם והחן לשמאלם. אמר אהרן: "ברשותך, אדוני המלך, אדבר אליך דבר אחד." אמר (פרעה): "דַּבֵּר!" דיבר (אהרן): "כה אמר ה'' אלוהי ישראל, שַׁלַּח אֶת-עַמִּי וְיַחֹגּוּ לִי (שמות ה,א)." נבהל פרעה כששמע את הדברים, והביט בהם בזעם עצום. אמר: "מי הוא המלך הזה שבשמו באתם? שמעתי על כל מלכי העולם, אך שמו של מלך זה לא שמעתי. לולא חששתי שתיפול עלי ביקורת, הייתי מצווה להורגכם בטרם תצאו. אני רואה אתכם כאפס, ואם אהרוג אתכם — תיפול עלי ביקורת. אם יש לכם עול במצרים, לכו אליו לפני שכעסי עליכם יגבר. אילו נאספו מלכי העולם כולם לקחת את ישראל ממני, לא יכלו. אוי לכם, עברים, חלשים וקטנים למראה, קטני לב. האם אתם מצפים שאומר לכם: לכו, קחו את ישראל וצאו?"');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (65,'I','57','ספר פליהתה',1000571,NULL,'And the Lord said to Moses: “Stretch forth your hand toward heaven, that 
there may be hail.” (Exod. 9:22) And Moses stretched forth his hand and there 
was hail throughout the land of Egypt (afer Exod. 9:22), killing cattle and destroy-
ing fruits. And there was hail throughout the land of Egypt, uprooting roots and 
stripping branches. And there was hail throughout the land of Egypt, throwing 
down all farmers and wasting all crops. And there was hail throughout the land of 
Egypt, the punishment of the guilty who did not believe in God. Everything that 
was in the ﬁeld, both man and beast (Exod. 9:25), the hail fell over them and they 
died in a wink (of an eye). Great anger was in the land of Egypt; shattered trees, 
destroyed grass and ruined crops. Fire ﬂashing in the midst of the hail (Exod. 
9:24), burning humans and animals, strong and weak, fat and meager. Out of 
great fear Pharaoh feared, he answered and said to Moses and Aaron: The Lord is 
in the right, and I and my people are in the wrong (Exod. 9:27). He cried out before 
Moses from his heart and said: “Pray to the Lord that He may stop this hail, and 
quieten this thunder, of which my heart is frightened, and I shall let the people 
go, that they may sacriﬁce to the Lord.” Moses the prophet stretched out his 
hands before his Master, and the hail and the rain ceased, and the thunders 
quietened.','וַיֹּאמֶר יְהוָה אֶל מֹשֶׁה: "נְטֵה יָדְךָ עַל הַשָּׁמַיִם וִיהִי בָרָד" (שמות ט,כב). וַיֵּט מֹשֶׁה אֶת יָדוֹ וַיְהִי בָרָד בְּכָל אֶרֶץ מִצְרַיִם (על פי שמות ט,כב), הָרַג בְּהֵמוֹת וְהִשְׁחִית פֵּרוֹת. וַיְהִי בָרָד בְּכָל אֶרֶץ מִצְרַיִם, עֹקֵר שָׁרָשִׁים וּמְפַשֵּׁט עֲנָפִים. וַיְהִי בָרָד בְּכָל אֶרֶץ מִצְרַיִם, מַפִּיל אֶת כָּל הָאִכָּרִים וּמְאַבֵּד אֶת כָּל הַתְּבוּאָה. וַיְהִי בָרָד בְּכָל אֶרֶץ מִצְרַיִם, עֹנֶשׁ הָאֲשֵׁמִים שֶׁלֹּא הֶאֱמִינוּ בָּאֱלֹהִים. כֹּל אֲשֶׁר בַּשָּׂדֶה מֵהָאָדָם וְעַד הַבְּהֵמָה (שמות ט,כה), הַבָּרָד נָפַל עֲלֵיהֶם וּמֵתוּ כְּהֶרֶף עָיִן. זַעַם גָּדוֹל הָיָה בְּאֶרֶץ מִצְרַיִם; עֵצִים שְׁבוּרִים, עֵשֶׂב מָחוּץ וְקְצִיר כָּלֶה. וְאֵשׁ מִתְלַקַּחַת בְּתוֹךְ הַבָּרָד (שמות ט,כד), שׂוֹרֶפֶת אֲנָשִׁים וּבְהֵמוֹת, חֲזָקִים וַחֲלָשִׁים, שְׁמֵנִים וּרְזִים. מִגֹּדֶל פַּחְדּוֹ חָרַד פַּרְעֹה, עָנָה וְאָמַר אֶל מֹשֶׁה וְאֶל אַהֲרֹן: יְהוָה הַצַּדִּיק וַאֲנִי וְעַמִּי הָרְשָׁעִים (שמות ט,כז). צָעַק לִפְנֵי מֹשֶׁה מִקֶּרֶב לִבּוֹ וְאָמַר: "הַעְתִּירוּ אֶל יְהוָה שֶׁיַּחְדַּל הַבָּרָד, וְיַשְׁקִיט אֶת הַקֹּלוֹת הַמַּחֲרִידִים אֶת לִבִּי, וַאֲשַׁלֵּחַ אֶת הָעָם לִזְבֹּחַ לַיהוָה." פָּרַשׂ מֹשֶׁה הַנָּבִיא אֶת יָדָיו לִפְנֵי אֲדֹנָיו, וַיֶּחְדַּל הַבָּרָד וְהַגֶּשֶׁם, וְהַקֹּלוֹת שָׁקָטוּ.');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (66,'I','49','ספר פליהתה',1000491,NULL,'And the Lord said to Moses: “Say to Aaron: ‘Stretch your hand out over 
the river and smite it’, and it will become blood throughout the land of Egypt, 
(even) among the trees and the stones.” Is it appropriate for the dead who killed 
one living with his own hand, that he become a great glory throughout the land 
of Egypt? Pharaoh is standing by (the river) being smitten, and he cannot rescue 
it. God proclaims in secret: “O sinner, why do you kill the living based on no 
guilt? If the Son of Eden is struck today, indeed, it will return (to be) as it was and 
you will be killed and will not live, and your shame will be recorded for gen-
erations, forever.” There was exceedingly great despair throughout the land of 
Egypt, when the river and its oﬀshoots were smitten. Pishon its brother and 
Tigris and the river of Euphrates dedicated themselves to take revenge. When 
they wearied of coming to the land of Egypt, they lifed up their voice to the 
Creator who created: “We ask You, O Master of the world, to take revenge for our 
brother on Pharaoh.” “Go in peace”, the truthful Judge told them. “It is I that 
takes revenge in the end.”','וַיֹּאמֶר ה'' אֶל מֹשֶׁה: "אֱמֹר אֶל אַהֲרֹן: ''נְטֵה יָדְךָ עַל הַיְאֹר וְהַכֵּהוּ''", וְיֵהָפֵךְ לְדָם בְּכָל אֶרֶץ מִצְרַיִם, אֲפִילוּ בָּעֵצִים וּבָאֲבָנִים. הַאִם רָאוּי הוּא לַמֵּת שֶׁהָרַג חַי בְּיָדוֹ, שֶׁיִּהְיֶה לְכָבוֹד גָּדוֹל בְּכָל אֶרֶץ מִצְרַיִם? פַּרְעֹה עוֹמֵד לְיַד הַיְאֹר בְּעֵת הַכָּאָתוֹ, וְאֵינוֹ יָכוֹל לְהַצִּילוֹ. אֱלֹהִים מַכְרִיז בַּסֵּתֶר: "חוֹטֵא, מַדּוּעַ תַּהֲרֹג אֶת הַחַי בְּלֹא אַשְׁמָה? אִם בֶּן עֵדֶן יֻכֶּה הַיּוֹם, הֲרֵי יָשׁוּב לִהְיוֹת כַּאֲשֶׁר הָיָה, וְאַתָּה תֵּהָרֵג וְלֹא תִחְיֶה, וּבָשְׁתְּךָ תִּיכָּתֵב לְדוֹרוֹת, לְעוֹלָם." הָיְתָה יֵאוּשׁ גָּדוֹל מְאֹד בְּכָל אֶרֶץ מִצְרַיִם בְּעֵת שֶׁהֻכָּה הַיְאֹר וְיוֹבְלָיו. פִּישׁוֹן אָחִיו וְחִדֶּקֶל וּנְהַר פְּרָת הִתְנַדְּבוּ לִנְקֹם נְקָמָה. כַּאֲשֶׁר נֶעְיוּ מִבּוֹא אֶל אֶרֶץ מִצְרַיִם, נָשְׂאוּ קוֹלָם אֶל הַבּוֹרֵא שֶׁבָּרָא: "מְבַקְּשִׁים אֲנַחְנוּ מִמְּךָ, אֲדוֹן הָעוֹלָם, לִנְקֹם אֶת נִקְמַת אָחִינוּ מִפַּרְעֹה." "לְכוּ לְשָׁלוֹם", אָמַר לָהֶם הַשּׁוֹפֵט הָאֱמֶת. "אֲנִי הוּא הַנּוֹקֵם בְּסוֹף."');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (67,'I','51','ספר פליהתה',1000511,NULL,'“Thus said the Lord: ‘Let My people go that they may worship Me (Exod. 
5:1). If you refuse to let My people go (Exod. 10:4), indeed a great and mighty 
wonder will be done to you. Behold, I will plague all your territory with frogs 
(Exod. 7:27)’ – the Good One declared a word which He will not abolish. They 
shall come up and enter your houses (Exod. 7:28), they will devour your food and 
you will not be able to hold them back. And into your bedchamber and on your 
bed (ibid.), they will strike your ears and trouble your sleep. And into your ovens 
and your kneading bowls (ibid.), your soul will be oppressed, and there is none to 
rescue you. The frogs shall come upon you and on all your servants and on your 
people. Behold, we have warned you before you are punished. If you do not 
obey, you smite yourself.” He despised their speech and considered them as 
nothing, and his heart toughened, and his rebellion increased.','"כֹּה אָמַר ה'': ''שַׁלַּח אֶת עַמִּי וְיַעַבְדֻנִי (שמות ה,א). אִם מָאֵן אַתָּה לְשַׁלַּח אֶת עַמִּי (שמות י,ד), הִנֵּה יֵעָשֶׂה לְךָ פֶּלֶא גָּדוֹל וְחָזָק. הִנֵּה אָנֹכִי נֹגֵף אֶת כָּל גְּבוּלְךָ בַּצְפַרְדְּעִים (שמות ז,כז)'' – הַטּוֹב הִכְרִיז דָּבָר אֲשֶׁר לֹא יְבַטְּלֶנּוּ. וְשָׁרְצוּ הַיְאֹר צְפַרְדְּעִים וְעָלוּ וּבָאוּ בְּבֵיתֶךָ (שמות ז,כח), יֹאכְלוּ אֶת מִזּוֹנְךָ וְלֹא תוּכַל לְעָצְרָן. וּבַחֲדַר מִשְׁכָּבְךָ וְעַל מִטָּתְךָ (שם), יַכּוּ אֶת אָזְנֶיךָ וְיַפְרִיעוּ אֶת שְׁנָתֶךָ. וּבְתַנּוּרֶיךָ וּבְמִשְׁאֲרוֹתֶיךָ (שם), נַפְשְׁךָ תֵּעָנֶה וְאֵין מוֹשִׁיעַ. הַצְפַרְדְּעִים יַעֲלוּ בְךָ וּבְכָל עֲבָדֶיךָ וּבְכָל עַמֶּךָ. הִנֵּה הִזְהַרְנוּ אוֹתְךָ בְּטֶרֶם תֵּעָנֶשׁ. אִם לֹא תִשְׁמַע, אַתָּה מַכֶּה אֶת עַצְמְךָ." הוּא בָּזָה לְדִבְרֵיהֶם וְחָשַׁב אוֹתָם כְּלָאו כְּלוּם, וְלִבּוֹ הִתְקַשָּׁה וּמִרְיוֹ גָּבַר.');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (68,'I','72','ספר פליהתה',1000721,'טור סיני הוה כרז לון אתיכון חדין טליה דרחותה ים סוף הוה כרז לון עברו בשלם ליתי עתיד מסגר מי מרה הוה כרז לון אתו בזרוז כיי לוכון מתחלי תקפה הוה כרז לון על } י {» ו « ליתי עתיד עצי בדילכון הוה כרז לון אתו דאנה נחת לסעד לבוכון ירדנה הוה כרז לון עברו חדין עתיד אנה מנשף הרגריז הוה כרז לון אסקו בשלם קראי ברכתה גלגליה הוו כרזין לון אתקוממו כדו סדרי רחותה מישר חזוה הוה כרז לון טיעלו בזהו מאורי זכותה כל אלין הוו בעין מעמינון ומתחמדין מזדמנה בון','Mount Sinai was calling them: “You are coming in joy, O children of the 
Divine Favor.” The Sea of Reeds was calling them: “Pass through in safety, I am 
not about to lock.” The Water of Mara was calling them: “Come in haste, I will be 
sweetened for you.” The Rock was calling them: “Enter, I am not about to resist 
you.” The “Tiny Stone” was calling them: “Come, for I will descend to feed you.” 
The Jordan was calling them: “Cross over gladly, I am about to be blown away.” 
Mount Gerizim was calling them: “Ascend in safety, O readers of the Blessings.” 
The heights were calling them: “Raise, O assembly of the Divine Favor.” The 
Plain of Vision was calling them: “Walk in joy, O luminaries of righteousness.” 
All these sought to see them and desired to meet them.','הר סיני קרא אליהם: "אתם באים בשמחה, ילדי חסד האלוהי." ים סוף קרא אליהם: "עִברו לבטח, אין אני עומד לנעול." מי מרה קראו אליהם: "בואו במהרה, אמתק בשבילכם." הסלע קרא אליהם: "היכנסו, אין אני עומד לעמוד נגדכם." ה"אבן הקטנה" קראה אליהם: "בואו, כי ארד להאכיל אתכם." הירדן קרא אליהם: "עִברו בשמחה, אני עומד לסחף." הר גריזים קרא אליהם: "עלו לבטח, קוראי הברכות." המרומים קראו אליהם: "הינשאו, עדת חסד האלוהי." בקעת המראה קראה אליהם: "לכו בשמחה, מאורות הצדק." כל אלה ביקשו לראותם ונכספו לפגשם.');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (69,'I','10','ספר פליהתה',1000101,'כד עמתה משה אתחיל וסטת אימתה דפרעה מלבה ונסב עם מרה ויהב במשמע כל ברי ואנסב אטרה באדה ואשקלה בימ › י ‹ נה וקעם בשרירו רבה בארשו מנך מרי , אמלל אמת דאנה עלל למצרים בארשותך ומתני לקהלה ממללך בשלם כיי אמר לון אלה ליד } ה {» אבהתכון שגרי באגרה לידכון ידע אנה דאנון תרביהת מצראי וכי בידון מימרה י « מה שמה מה אימר לון ענתה חילה רבה ואמר אשדך לבך נביי וקבל הגבותה דכל עובדיך גמ › י ‹ לים בחסד האנה מחכם לך » שמה « אשר יחכמון סימנה דבידון ירתה מן אברהם אהן וא } ס {› שמה דאנה גלי לך אה נביי סימנה דאנון חכמין לפרקן » אתבונן « ש ‹ מע מני כדו מה הוא ולא תצטדי מן מקרי יתה קמיהון','When Moses saw it, he was invigorated, and the fear of Pharaoh swerved 
away from his heart. He talked with his Master in the presence of every creature, 
and he took the rod with his hand and raised it with his right hand, and stood up 
in great strength (and said): “With your permission, my Lord, I will speak. When 
I enter Egypt by your command, and I tell the congregation the whole of your 
word, behold, I shall say to them: ‘The God of your fathers has sent me (Exod. 
3:13) to you with a message’, I know that they are a breed of Egypt, and they will 
be able to say to me: What is his name, what shall I say to them (Exod. 3:13).” The 
Great God answered him and said: “Calm your heart, my prophet, and receive 
the answer. All your deeds are rewarded with grace. Behold, I shall teach you 
«the name» they may know, the sign which they have, inheritance from 
Abraham. This name I reveal to you, O my prophet, is the sign that they may 
know; the sign of deliverance. «Consider» and hear from me now what it is, and 
do not fear from pronouncing it in their presence.”','כשראה זאת משה, התחזק, ופחד פרעה סר מלבו. דיבר עם אדונו בנוכחות כל הברואים, ואחז במַטֶּה בידו והרימו בימינו, ועמד בכוח רב ואמר: "ברשותך, אדוני, אדבר. כשאכנס למצרים על פי פקודתך, ואגיד לעדה את כל דברך, הנה אומר להם: ''אֱלֹהֵי אֲבוֹתֵיכֶם שְׁלָחַנִי (שמות ג,יג) אֲלֵיכֶם בְּמִסָּר'', יודע אני שהם מגזע מצרים, ויוכלו לומר לי: מה שמו, מה אֹמַר אֲלֵהֶם (שמות ג,יג)." ענה לו האל הגדול ואמר: "הרגע את לבבך, נביאי, וקבל את התשובה. כל מעשיך זוכים לחסד. הנה, אלמד אותך «את השם» שיוכלו לדעת, האות שיש להם, ירושה מאברהם. שם זה שאני מגלה לך, הוי נביאי, הוא האות שיוכלו לדעת; אות הגאולה. «שִׂים לב» ושמע ממני עתה מהו, ואל תירא מלהוציאו בפיך בנוכחותם."');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (70,'I','52','ספר פליהתה',1000521,'ואמר יהוה אל משה אמר אל אהרן הנתח ית אדך באטרך על נהריה ותסק ערדניה ותטמר כל ארע מצרים וישתנקו בון דבבי קהלה עבדו נבייה הך דאמר לון עבודון וסלקת ערדניה על כל ארע מצרים רב הו איעשה דהוה יהיב תמן נהרה משרץ ובתיה } יה { ממלין גויאן בתשניק ונפשאן בלחץ ולבבין עקין כד עמה פרעה דינה מפשר בה זעק לחרשיה יסטונה מנה עבדו בחרשיון כן אתוזף עליו דינה יכלו מחו ולא יכלו } י { אסו משנת הוא מלכה ומפלין חרשיה דהוא רחיץ עליון נימוסי כל אסאיה דאתין ליד מטענה ישקון לה סמנין דמה דיתאסי ויתון חרשיה אתו ליד מלכון והוא מגעל בדיניה אוזפותה דין כד עמה פרעה הן לית מנון אסו צבע לקדם משה ואהרן צלו ליהוה דאתון סגדין לה כי יסטי מן } עולי { » עלוי « אהן דינה רבה זרזו עלי כדו בצלותה ואשלח ית עמה וידבחון , ליהוה ונפקו תריון וצלו כמה אמר לון וסטת ערדניה מנה ומן עבדיו וחזה פרעה הלא הות רוחה ותק } ת {» ף « לבה ולא שמק לון נכתר על דינה ולא נשגר ית עמה וקשטה הך אמר , לה קריב הוא אבדנך 53] [ ואמר יה למשה ולאה בתר כן מחי ית עפר ארעה ויהי כלמין ועבדו כמד פקד יהוה ורחטי כלמיה בכל ארע מצר כל קטם ארעה הוה כלמין מקניאן מללין ומלבטין שתיקין חזו חרשיה קנומון נצעין › ו ‹ עצפו מפקה יתון ולא יכלו כד עמו חרשיה קנומון נצעין אמרו לפרעה אצבע אלהים היא לית בחילן מגיח באלין נבייה חכים דאלהון עבוד פליאתה יכלין אנון מסתר ומתקנה ואנן סתירין ולית בן מתקנה אמר לון פרעה מה חנאה מנוכון שרי לי מבטל גזרכון מעלי לא תדאש יומה אמתן רשותך דעתיד לך מגויאן רברבן מן אלין ארגז עליהון ונפקו ושבקותה עכיר ועוד אפיו זעיפין','[And the Lord said to Moses: “Say to Aaron: ‘Stretch out your hand with 
your rod over the rivers […], and cause frogs to come and cover all the land of 
Egypt’ (Exod. 8:1), and all the enemies of the congregation will be aﬄicted by 
them.” The prophets did as their Maker commanded them, and the frogs came up 
over all the land of Egypt (Exod. 8:2). Great is the despair that was (placed) there. 
The river swarms, and the houses are ﬁlled (with frogs). Bodies are in torment, 
souls in oppression, hearts in agony. When Pharaoh saw the punishment admin-
istered to him, he summoned the magicians to remove it from him. They 
performed their sorcery – then the punishment increased upon him. They suc-
ceeded in smiting, but were powerless in healing. The king is in distress, and the 
magicians on whom he relies are collapsing! The custom of all physicians who 
come to a patient is to give him medicines to drink, perchance he might be 
healed. Those magicians came to their king, while he was given no mercy by the 
punishments. They added to punishment. When Pharaoh saw that there was no 
cure from them, he cried before Moses and Aaron: “Pray to the Lord whom you 
worship, so that He removes from me this great punishment. Hasten for me now] 
in praying, and I shall let the people go that they may sacriﬁce to the Lord.” They 
both went out and prayed, as he requested. The frogs departed from him and 
from his servants. But when Pharaoh saw that there was a respite, he hardened his 
heart, and would not listen to them (Exod. 8:11), he said: “Let us wait for punish-
ment; we will not let the people go.” And it was as though the True One was 
saying to him: “Your ruin is near.”','[וַיֹּאמֶר ה'' אֶל מֹשֶׁה: "אֱמֹר אֶל אַהֲרֹן: ''נְטֵה אֶת יָדְךָ בְּמַטֶּךָ עַל הַיְאֹרִים [...] וְהַעַל אֶת הַצְפַרְדְּעִים עַל אֶרֶץ מִצְרַיִם'' (שמות ח,א), וְכָל אוֹיְבֵי הָעֵדָה יֵעָנְשׁוּ בָהֶן." הַנְּבִיאִים עָשׂוּ כַּאֲשֶׁר צִוָּה אוֹתָם בּוֹרְאָם, וַתַּעַל הַצְפַרְדֵּעַ עַל כָּל אֶרֶץ מִצְרַיִם (שמות ח,ב). גָּדוֹל הוּא הַיֵּאוּשׁ שֶׁהָיָה שָׁם. הַיְאֹר שׁוֹרֵץ וְהַבָּתִּים מְלֵאִים. גּוּפוֹת בְּיִסּוּרִים, נְשָׁמוֹת בְּדִכָּאוֹן, לְבָבוֹת בְּכְאֵב. כַּאֲשֶׁר רָאָה פַּרְעֹה אֶת הָעֹנֶשׁ הַמֻּטָּל עָלָיו, קָרָא לַחֲרְטֻמִּים לְהָסִיר אוֹתוֹ מֵעָלָיו. הֵם עָשׂוּ אֶת כְּשָׁפֵיהֶם – וְאָז גָּבַר עָלָיו הָעֹנֶשׁ. הִצְלִיחוּ לְהַכּוֹת, אַךְ לֹא הָיְתָה בָּהֶם יְכֹלֶת לְרַפֵּא. הַמֶּלֶךְ בְּצָרָה, וְהַחֲרְטֻמִּים שֶׁנָּשָׂן עָלֵיהֶם מִתְמוֹטְטִים! מִנְהָגָם שֶׁל כָּל הָרוֹפְאִים הַבָּאִים אֶל חוֹלֶה הוּא לָתֵת לוֹ תְּרוּפוֹת לִשְׁתּוֹת, שֶׁמָּא יֵרָפֵא. אוֹתָם חֲרְטֻמִּים בָּאוּ אֶל מַלְכָּם, בְּעוֹד שֶׁהָעֳנָשִׁים לֹא חָמְלוּ עָלָיו כְּלָל. הֵם הוֹסִיפוּ לָעֹנֶשׁ. כַּאֲשֶׁר רָאָה פַּרְעֹה שֶׁאֵין מֵהֶם מַרְפֵּא, צָעַק לִפְנֵי מֹשֶׁה וְאַהֲרֹן: "הִתְפַּלְּלוּ אֶל ה'' אֱלֹהֵיכֶם שֶׁיָּסִיר מֵעָלַי אֶת הָעֹנֶשׁ הַגָּדוֹל הַזֶּה. מַהֲרוּ לִי עַתָּה] לְהִתְפַּלֵּל, וַאֲנִי אֲשַׁלַּח אֶת הָעָם לִזְבֹּחַ לַה''." שְׁנֵיהֶם יָצְאוּ וְהִתְפַּלְּלוּ כַּאֲשֶׁר בִּקֵּשׁ. הַצְפַרְדְּעִים נָסוּ מֵעָלָיו וּמֵעַל עֲבָדָיו. אַךְ כַּאֲשֶׁר רָאָה פַּרְעֹה שֶׁהָיְתָה הֲרָוָחָה, הִכְבִּיד אֶת לִבּוֹ וְלֹא שָׁמַע אֲלֵיהֶם (שמות ח,יא), וְאָמַר: "נַמְתִּין לָעֹנֶשׁ, לֹא נְשַׁלַּח אֶת הָעָם." וְהָיָה כְּאִילּוּ אָמַר לוֹ הָאֱמֶת: "קְרוֹבָה חוּרְבָּנְךָ."');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (71,'I','62','ספר פליהתה',1000621,'סכומה מטי למפוקכון ורבותכון משתמעה ביני כל אמיה מללו שבי לכל כנשת בני ישראל יעתדון גרמון לזבנה דמפוקה בעסרה יומין לגו אהן ירחה יעתדון עורי לדבח קרבנה ויטרון יתה עד ארבע עסר יום בה ובין רמשיה ינכסון יתה כל קהלה ויסבו מן אדמה ויהבו על מדיקה ובתר כן על תרי פגיאתה וייכלון ית בסרה בליליה הדן שליק נור ופטיר על מרור ייכלונה','“The time for your exit is approaching, and your glory is heard amongst 
the nations. Speak now to the whole assembly of the people of Israel (Exod. 12:3), 
that they may prepare themselves for the time of exit. In the tenth day of this 
month they shall prepare (themselves) to oﬀer the oﬀering, and they shall keep it 
until its fourteenth day. They shall slaughter it, at twilight, the whole congre-
gation, and they shall take some of the blood and put it on the lintel and 
aferwards on the two doorposts. And they shall eat its ﬂesh this night roasted 
over ﬁre. With unleavened bread and bitter herbs shall they eat it (Exod. 12:8).”','"זְמַן יְצִיאַתְכֶם קָרֵב, וּכְבוֹדְכֶם נִשְׁמַע בֵּין הַגּוֹיִם. דַּבְּרוּ נָא אֶל כָּל עֲדַת בְּנֵי יִשְׂרָאֵל" (שמות יב,ג), לְמַעַן יָכִינוּ עַצְמָם לִזְמַן הַיְּצִיאָה. בֶּעָשׂוֹר לַחֹדֶשׁ הַזֶּה יָכִינוּ עַצְמָם לְהַקְרִיב אֶת הַקָּרְבָּן, וְיִשְׁמְרוּהוּ עַד יוֹם אַרְבָּעָה עָשָׂר בּוֹ. יִשְׁחֲטוּהוּ בֵּין הָעַרְבַּיִם, כָּל הָעֵדָה, וְיִקְחוּ מִן הַדָּם וְיִתְּנוּ עַל הַמַּשְׁקוֹף וְאַחַר כָּךְ עַל שְׁתֵּי הַמְּזוּזוֹת. וְיֹאכְלוּ אֶת בְּשָׂרוֹ בַּלַּיְלָה הַזֶּה צָלוּי בָּאֵשׁ. עַל מַצּוֹת וּמְרֹרִים יֹאכְלֻהוּ (שמות יב,ח).');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (72,'I','29','ספר פליהתה',1000291,'יקירין יתון תריה לעלם ורבותון מלת שומיה וארעה עלו למצרים דלא שאמין בה כלום וטובה עמון בכסי דלא מתעמי ודמכו ביתה ליליה וקרצו בצפרה וכנשו חכימי כנשתה בזרוז וגלה לון שמה דגלה לה מרה וחדת לבביון כד שמעו יתה אמרו דן לדן אהנו סימנה דמחכם לן מקרוב פרקנה ועבד סימניה בתר כן קמיון ואימנו כהלון דאלהים שגרון ביתה יומה שמעו רשיה וחוו לכל קהלה ואימנו כותון ועבדו אודהו ואמרו מלי תשבחן כיומה דמת בה מלכה ואתנחו וצבעו ושמעו דאלהים › נהיר ‹ ליתו מנשי כלום ועקדו וסגדו לאלהה דאבהתון','Venerable are these two forever, and their greatness ﬁlled the heaven 
and the earth. They entered Egypt without expecting anything, but the Good One 
was with them in secret, invisible. They slept that night, rose up in the morning 
and assembled the elders of the congregation in haste. And he revealed to them 
the name which his Master disclosed to him. Their hearts rejoiced when they 
heard him. They said to one another: “This is the sign that announces to us the 
approach of the deliverance.” And he performed the signs before them afer-
ward, and they all believed that God sent them. The same day the chiefs heard 
and reported to the entire congregation. And they believed likewise, and gave 
thanks and said words of praise, as on the day when Pharaoh the king died, 
(when) they sighed and cried. (Now) they proclaimed that God remembers; He 
does not forget anything, and they bowed to the God of their fathers.','נכבדים הם שניים הללו לעולם ולעולמי עולמים, וגדולתם מלאה את השמים ואת הארץ. נכנסו למצרים ללא כל ציפייה, אך הטוב היה עמם בסתר, נסתר מן העין. ישנו בלילה ההוא, קמו בבוקר וכינסו בחיפזון את זקני העדה. וגילה להם את השם שגילה לו אדונו. לבם שמח כששמעוהו. אמרו איש לרעהו: "זה הוא האות המבשר לנו את קרבת הגאולה." ואחר כך עשה לפניהם את האותות, וכולם האמינו כי אלוהים שלחם. באותו יום שמעו הנשיאים והביאו את הדבר לכל העדה. והם האמינו אף הם, והודו ואמרו דברי שבח, כביום שמת פרעה המלך, אז נאנחו ובכו. עתה הכריזו כי אלוהים זוכר; אינו שוכח דבר, וישתחוו לאלוהי אבותיהם.');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (73,'I','15a','ספר פליהתה',1000152,'כד אנתח משה אדה על ימה ארתתו כסיאתה וגליאתה וקעם עלמה תמן בדחלה לית כותה ועלל משה וכבודה קמיו מרבי מגוזה לגו ימה דסוף עמו כמה בין תרין עללו משה עלל ופרעה עלל משה עלל אלהותה מרביה יתה פרעה עלל אלהותה מהבידה לה משה עלל כבודה מחדי לבה פרעה עלל כבודה מצדי לבה משה עלל זכותה בה חדיה פרעה עלל זכותה מאבדה לה משה עלל מלאכיה מרבין לה פרעה עלל מלאכיה משנקין לה רבין משה יתר על כל אנש וכן מרה הסיד עליו כד עלל משה וישראל בימה אצטמת רוחה ואזדמן לקדמון וכד עלל פרעה ומצראי בימה אזדמן דינה לקדמון','When Moses stretched out his hand over the sea, the Concealed and the 
Overt trembled and the world was then in a (state of) fear like which there is 
none. Moses entered, and the Glory before him magniﬁed his passing through 
the Sea of Reeds. See the diﬀerence between two who entered: Moses entered 
and Pharaoh entered. Moses entered, the Divine One magnifying him. Pharaoh 
entered, the Divine One destroying him. Moses entered, Glory gladdening his 
heart. Pharaoh entered, Glory terrifying his heart. Moses entered, righteousness 
rejoicing at him. Pharaoh entered, righteousness destroying him. Moses entered, 
the angels magnifying him. Pharaoh entered, the angels aﬄicting him. The 
greatness of Moses exceeds that of any man, and thus his Master has testiﬁed 
about him. When Moses and Israel entered the sea, the wind gathered (force) to 
meet them. When Pharaoh and the Egyptians entered the sea, the judgment 
gathered (force) to meet them.','כאשר משה נטה את ידו על הים, רעדו הנסתר והנגלה, והעולם היה אז שרוי בפחד כמוהו לא היה. משה נכנס, והכבוד לפניו הגדיל את מעברו בים סוף. ראה את ההבדל בין שניים שנכנסו: משה נכנס ופרעה נכנס. משה נכנס — האלוהי הגדילו. פרעה נכנס — האלוהי השחיתו. משה נכנס — הכבוד שימח את לבו. פרעה נכנס — הכבוד הפיל אימה על לבו. משה נכנס — הצדק שש לקראתו. פרעה נכנס — הצדק השמידו. משה נכנס — המלאכים הגדילוהו. פרעה נכנס — המלאכים ענוהו. גדולתו של משה עולה על זו של כל אדם, וכך העיד עליו אדונו. כאשר נכנסו משה וישראל אל הים, כינס הרוח את כוחו לקראתם. כאשר נכנסו פרעה והמצרים אל הים, כינס הדין את כוחו לקראתם.');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (74,'I','16','ספר פליהתה',1000161,'אגיב משה למרה בתר כל אלין מליה דשמע אם לא יאמנו לי ולא יקבלו לקלי מהו סימנה דאנה מעמי לון ולית אנון כבר שמעין לקלי כי יאמרו לא אתחזי לך יה ואמר יה לה אשפיר לשמועה דשוה משמע מן מרה כל הדה שרר לבך נביי האנה גלי לך סימניה דאת עבד קדם קהלה מה דן באדך ישתבח אמורה ויתגלג שמועה דאגיבה ואמר אטר מן אשתה יהיב לי ביד טובך בשלטנו רבה כדו ארמיתה מן אדך לארעה כיינך עמי נביי מהוא מתעבד בפרי וארמה יתה ארעה בזרוז בארשו מן מרה ביצר טב מנה','Moses answered to his Master afer all these words which he had heard: 
“What if they do not believe me and do not listen to my voice (Exod. 4:1); what is 
the sign that I shall show them? They do not, in fact, listen to my voice, but say: 
‘The Lord did not appear to you’ (ibid.).” The Lord said to him, and happy is the 
hearer worthy to hear all this from his Master: “Strengthen your heart, My 
prophet, for I will reveal to you the signs which you are to perform before the 
congregation. What is in your hand? (Exod. 4:2)” Praised be the speaker and cele-
brated be the hearer, who answered: “And he said: ‘A rod (ibid.), it has been 
given to me from the ﬁre by Your goodness with great sovereignty.’” “Now, cast it 
from your hand on the ground, and indeed you will see, My prophet, what is 
happening to it straightway.” He cast it on the ground (Exod. 4:3) quickly, at his 
Master’s command, with good conscience.','משה ענה לאדונו אחרי כל הדברים האלה שיצא: "וְאִם לֹא יַאֲמִינוּ לִי וְלֹא יִשְׁמְעוּ בְּקֹלִי (שמות ד,א) — מה האות שאראה להם? הרי הם אינם שומעים בקולי, ואומרים: ''לֹא נִרְאָה אֵלֶיךָ ה'''' (שם)." ה'' אמר לו — ואשרי השומע הראוי לשמוע את כל זאת מפי אדונו: "חזק את לבך, נביאי, כי אגלה לך את האותות שתעשה לפני העדה. מַה זֶּה בְיָדֶךָ? (שמות ד,ב)" ברוך המדבר ומהולל השומע, שענה: "וַיֹּאמֶר מַטֶּה (שם) — ניתן לי מן האש בטובך בממשלה גדולה." "עתה, השלך אותו מידך ארצה, ואכן תראה, נביאי, מה קורה לו מיד." וַיַּשְׁלִכֵהוּ אַרְצָה (שמות ד,ג) במהירות, על פי פקודת אדונו, בלב שלם.');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (75,'I','46','ספר פליהתה',1000461,'עם אפי רמשה נפק משה ואהרן ולבביהון מלין חדו עמו נצחנה דמרון מעיני לון מכבש סניון קמיון אנסב פרעה מבתר דנפקו חשבה בישה ואמר לעבדיו אנה בעי מפק מטעיאל בחדו עלוי נהר מיה והן אתא משה ואהרן צפרה אמרו לון עזרו דו נפיק לקרבה פרעה ממלל בכסי לעבדיו ונצוח קרביה מפרסי טמירתה ואמר יה אל משה אקדם בצפרה ופק אל נהרה לזימון פרעה דו חשב מפק למיה בצפרה הך ערק מני דלא יפגע בוכון ומללה בשמי בלב ברי שלח ית עמי וישמשני ואם מחי את למשלחה ית עמי מי נהרה קטיל ואדמה מגלגל ואם מחי את למשלח › ה ‹ ית עמי כי גוזלי נהרה מנכסין לגוה ואם מחי את למשלח ית עמי דאת מעיק מללין ומלחץ שתיקין ואם מחי את למשלח ית עמי כי כל ארע מצרים אסירה בלחץ ואם מחי את למשלח ית עמי דאת מכה קנומך וכל מצראיה עמך האנה מחי באטרה דבאדי לנהרה ויתהפכון כל מיה דבה לאדם','In the evening Moses and Aaron departed, their hearts full with joy, see-
ing the triumph of their Master as He watches them and subdues their enemies 
before them. Afer they departed, Pharaoh schemed and said to his servants: “I 
want to go out (tomorrow) walking in joy by the river of water, and if Moses and 
Aaron come in the morning, tell them: Turn back, for he went to battle.” Pharaoh 
speaks in secret with his servants, and the Victor in Battles discloses his secrets. 
God said to Moses: “Rise early in the morning and go to the river to meet 
Pharaoh, for he has planned to depart for the water in the morning, as if he ﬂees 
from me lest he meets you. Speak to him in My name with a ﬁrm heart: Let My 
people go, that they may worship me (Exod. 7:16). If you refuse to let My people go 
(Exod. 10:4), the water of the river will be smitten and become blood. If you 
refuse to let My people go, indeed the children of the river will be slain. If you 
refuse to let My people go, you will bring distress upon speakers and oppression 
upon mutes. If you refuse to let My people go, indeed, the entire land of Egypt will 
be captive in oppression. If you refuse to let My people go, then you will smite 
yourself and all the Egyptians with you together. Behold, I shall strike with the 
rod that is in my hand the river (Exod. 7:17) and all the water therein will be 
turned into blood.”','בערב יצאו משה ואהרן, לבם מלא שמחה, כשהם רואים את נצחון אדונם הצופה בהם ומכניע את אויביהם לפניהם. לאחר שיצאו, חשב פרעה תחבולה ואמר לעבדיו: "רצוני לצאת מחר לטייל בשמחה על שפת היאור, ואם יבואו משה ואהרן בבוקר, אמרו להם: שובו לכם, כי יצא למלחמה." פרעה מדבר בסתר עם עבדיו, והמנצח בקרבות חושף את סודותיו. אמר ה'' אל משה: "השכם בבוקר ולך אל היאור לקראת פרעה, כי זמם לצאת אל המים בבוקר, כאילו הוא בורח ממני שלא ייפגש בך. דבר אליו בשמי בלב איתן: שַׁלַּח אֶת עַמִּי וְיַעַבְדֻנִי (שמות ז,טז). אם תמאן לשלח את עמי, מי היאור יוכו ויהפכו לדם. אם תמאן לשלח את עמי, אכן יֵהרגו בני היאור. אם תמאן לשלח את עמי, תביא צרה על מדברים ועושק על אילמים. אם תמאן לשלח את עמי, אכן כל ארץ מצרים תהיה שבויה בעושק. אם תמאן לשלח את עמי, הכית את עצמך ואת כל המצרים עמך יחדיו. הנה אכה במטה אשר בידי את היאור (שמות ז,יז) וכל המים אשר בו יהפכו לדם."');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (76,'I','9a','ספר פליהתה',1000092,'ומה הוה יהי מעמי נביה רבה משה קעם על ימה ממלל עם פרעה והוא מתקף לבה לבישתה אמר לה משה אה פרעה ארף רשעותך ואנשם שבק בישתך וגרשה מן לבך חזי כל מכויאתה דאתעבדו גזוי למרדך צפי סרועיה דגעזו קמיך קין וגזותיו וברה ומה עביד לה וכן דרי מבולה ומגדלאי ומה שרא בון ונמרודה דרבה צדותה וגברי סדם ויקידתון הן הוה בך מלקי חלקי מיני דיניה מזדיאנין לך אבדנה בלישך לקדמך הוא נפק ואלה זכי מנך במד בך עביד קטול נפשך אתה ודבב לגרמך אתעבדת מליך אנון מאבדין לך עובדיך אנון משנקין לך לעובדי הרע צמתה סב גזוי כלה בקשט מן זרע בישאן קצר כובין','[How good it was to see the great prophet Moses standing by the sea 
speaking with Pharaoh, while Pharaoh hardens his heart to his own harm. 
Moses said to him: “O Pharaoh, give up your evildoing and be at rest. Abandon 
your wickedness and expel it from your heart. Look at all the inﬂictions brought 
about because of your rebelliousness. Consider the evildoers who preceded you. 
Cain and his punishment; his son and what happened to him; likewise, the gen-
eration of the Flood and of the people of the Tower and what befell them; and 
Nimrod, whose desolation was great; the people of Sodom and their burning! If 
you are to be beaten, be beaten (with) the various punishments appointed to 
you. Destruction is looking for you, it is coming out to meet you! God is exempt 
from you in what is done to you. You slay yourself; you became your own enemy. 
Your own words destroy you. Your own deeds aﬄict you. You have gathered evil 
deeds and receive retribution for them, all in justice. He who sows evils harvests 
thorns.”','[כמה טוב היה לראות את הנביא הגדול משה עומד על שפת הים ומדבר עם פרעה, בעוד פרעה מקשה את לבו לרעתו הוא. אמר לו משה: "הֵי פרעה, חדל מרשעתך ושקוט. עזוב את עוולותיך וגרש אותן מלבך. ראה את כל המכות שהובאו בגלל מרדך. חשוב על הרשעים שקדמו לך. קין ועונשו; בנו ומה שאירע לו; וכן דור המבול ואנשי המגדל ומה שפקד אותם; ונמרוד, ששממתו הייתה רבה; ואנשי סדום ושריפתם! אם עליך להיענש, הֵיענש בגוני המכות השונות שנגזרו עליך. ההשחתה מחפשת אותך, היא יוצאת לקראתך! האלוהים פטור ממה שנעשה לך. אתה הורג את עצמך; נהיית לאויב עצמך. דבריך שלך מחריבים אותך. מעשיך שלך מייסרים אותך. אספת מעשי רשע ואתה מקבל גמולם, כולם בצדק. הזורע רעות קוצר קוצים."]');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (77,'I','36','ספר פליהתה',1000361,NULL,'Let us learn from Moses and Aaron – from the secrets of the letters. He 
(Moses) said to Aaron: “Strengthen yourself. Take the rod which is in my hand 
and come with me to Pharaoh the king; indeed, you may make (out of) it a ser-
pent before him.” The two of them rose in great haste and went to the gate of the 
king, seeking to go before him. “Peace be upon you now, servants of the king. We 
ask you to grant permission to us.” When the doorkeepers saw them, they went 
in haste to bring permission. They said to him: “O king, permit us now (to speak 
to you) on behalf of those two who came to you recently and spoke to you that 
you may release Israel. The day they (ﬁrst) came to you their heads were 
lowered, and they spoke with you with great fear. Today they stand at the gate of 
the king and their heads are upright, like a lion and a lioness. They request per-
mission from you to enter before you. If you wish so, grant them permission.”','נלמד ממשה ואהרן — מסודות האותיות. אמר משה לאהרן: "חזק את עצמך. קח את המטה אשר בידי ובוא עמי אל פרעה המלך; אכן, תוכל לעשות ממנו נחש לפניו." שניהם קמו בחפזון גדול והלכו אל שער המלך, ובקשו לבוא לפניו. "שלום עליכם עתה, עבדי המלך. אנו מבקשים מכם לתת לנו רשות." כאשר ראו השוערים אותם, הלכו בחפזון להביא רשות. אמרו לו: "המלך, תן לנו רשות עתה בשם אותם שניים שבאו אליך לאחרונה ודיברו אתך לשלח את ישראל. ביום שבאו אליך לראשונה היו ראשיהם שחוחים, ודיברו אתך ביראה גדולה. היום הם עומדים בשער המלך וראשיהם זקופים, כאריה ולביאה. הם מבקשים ממך רשות להיכנס לפניך. אם חפצת בכך, תן להם רשות."');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (78,'I','61','ספר פליהתה',1000611,NULL,'And the Lord said to Moses and to Aaron afer the nine punishments that 
had passed: “This month shall be for you the beginning of months (Exod. 12:2) – 
the end of aﬄiction and the beginning of relief. This month shall be for you the 
beginning of months – the opening of Favor and the closing of Disfavor. This 
month shall be for you the beginning of months – the end of torment and the 
beginning of relief. This month shall be for you the beginning of months – the 
onset of the oath and the end of its abrogation. This month shall be for you the 
beginning of months – the entrance of good and exit of evil. This month shall be 
for you the beginning of months – the path to observance and the way to faith. 
This month shall be for you the beginning of months – the gate to blessing and the 
termination of cursing. This month shall be for you the beginning of months – the 
end of slavery and the beginning of (self) rule. Indeed, it precedes the months of 
the year; from it are drawn all the years to eternity. In it I created the world. In it I 
brought the Flood, in it I scattered the Tower (of Babylon), in it I overthrew 
Sodom, in it I proclaimed to Abraham, in it I blessed Jacob, in it I began the pun-
ishments, in it I will end them, in it I will destroy Egypt.”','וַיֹּאמֶר ה'' אֶל מֹשֶׁה וְאֶל אַהֲרֹן אַחֲרֵי תֵּשַׁע הָעֳנָשִׁים שֶׁעָבְרוּ: "הַחֹדֶשׁ הַזֶּה יִהְיֶה לָכֶם רֹאשׁ חֳדָשִׁים" (שמות יב,ב) – סוֹף הַסֵּבֶל וּתְחִלַּת הָרְוָחָה. הַחֹדֶשׁ הַזֶּה יִהְיֶה לָכֶם רֹאשׁ חֳדָשִׁים – פְּתִיחַת הָרָצוֹן וּנְעִילַת הַזַּעַם. הַחֹדֶשׁ הַזֶּה יִהְיֶה לָכֶם רֹאשׁ חֳדָשִׁים – סוֹף הַיִּסּוּרִים וּתְחִלַּת הָרְוָחָה. הַחֹדֶשׁ הַזֶּה יִהְיֶה לָכֶם רֹאשׁ חֳדָשִׁים – תְּחִלַּת קִיּוּם הַשְּׁבוּעָה וְסוֹף בִּטּוּלָהּ. הַחֹדֶשׁ הַזֶּה יִהְיֶה לָכֶם רֹאשׁ חֳדָשִׁים – כְּנִיסַת הַטּוֹב וְיְצִיאַת הָרָע. הַחֹדֶשׁ הַזֶּה יִהְיֶה לָכֶם רֹאשׁ חֳדָשִׁים – הַדֶּרֶךְ לְקִיּוּם הַמִּצְווֹת וְהַנָּתִיב לָאֱמוּנָה. הַחֹדֶשׁ הַזֶּה יִהְיֶה לָכֶם רֹאשׁ חֳדָשִׁים – שַׁעַר הַבְּרָכָה וְסִיּוּם הַקְּלָלָה. הַחֹדֶשׁ הַזֶּה יִהְיֶה לָכֶם רֹאשׁ חֳדָשִׁים – סוֹף הָעַבְדּוּת וּתְחִלַּת הַשִּׁלְטוֹן. אָמְנָם הוּא קוֹדֵם לַחֳדָשֵׁי הַשָּׁנָה; מִמֶּנּוּ נִמְשָׁכִים כָּל הַשָּׁנִים עַד עוֹלָם. בּוֹ בָּרָאתִי אֶת הָעוֹלָם. בּוֹ הֵבֵאתִי אֶת הַמַּבּוּל, בּוֹ פִּזַּרְתִּי אֶת הַמִּגְדָּל (שֶׁל בָּבֶל), בּוֹ הָפַכְתִּי אֶת סְדֹם, בּוֹ בִּשַּׂרְתִּי אֶת אַבְרָהָם, בּוֹ בֵּרַכְתִּי אֶת יַעֲקֹב, בּוֹ הֵחַלּוֹתִי אֶת הַמַּכּוֹת, בּוֹ אֲסַיְּמֵם, בּוֹ אַשְׁמִיד אֶת מִצְרָיִם.');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (79,'I','3','ספר פליהתה',1000031,'ויאמר משה משה ויאמר הנני תמחי כסיאתה והתאנו כל גליאתה ויאמר משה משה מודע לה דו קעום רחותה ושלמותה ויאמר משה משה גלה לה דו לבוש נביותה ושם אלהותה ויאמר משה משה מודיע לה דו פרוק עבראי וקטול מצראי בזבן דאמר אברהם אברהם בסרה דכי דכיר ברחותה ופנותה בזבן דאמר יעקב יעקב חכמה דו מפסל גבאי ובראי בזבן דאמר בסניה משה משה חדה למה דהוה וחדה למה דאתי משה משה הך אמר לה אתה נביא דלא קם כותך בעלמה משה משה הך אמר אתהו מעתד בעלמה חייה , 26* רבה הי רבותך משה מלבין כל אנשה דתהימן רזין עתיקין וחדתין חתימה ביד קראה דטובה פריסה קדמיו על רישה דטור סיני ומלאך יהוה לגוה קרי והוא כות טלי מצית למלי ספרה נביה רבה משה נהיר כל בית אדם עזר מן דברך לינה הך מה דהויך שלף מסניך מן על רגליך דאת צריך דרס יומן בשביל קדשה עזר ענאה דבידך למסחנון דאת עתיד מפר › נ ‹ ס כוכביו דאברהם','He said Moses, Moses, and he replied Here I am (Exod. 3:4) – the Con-
cealed wondered and all the Overt rejoiced. He said Moses, Moses – He notiﬁed 
him that he is the Master of the Divine Favor and the Requital. He said Moses, 
Moses – He revealed to him that he would wear prophecy and the Name of the 
Divinity. He said Moses, Moses – He made known to him that he would deliver 
the Hebrews and slay the Egyptians. When He said Abraham, Abraham (Gen. 
22:11), he announced to him that indeed He remembers the Divine Favor and Dis-
favor. When He said Jacob, Jacob (Gen. 46:2), He informed him that he is the 
source of the Inner and the Outer. When in the bush, He said Moses, Moses, one 
(is a reference) to what had been and one to what is yet to come. Moses, Moses, 
as though He said to him: “You are a prophet like which none has risen up in the 
world.” Moses, Moses, as though He said to him: “you are called for the world of 
life; ample is your greatness amongst all men, so that you are entrusted secrets, 
old and new, sealed with the Good Proclaimer, spread out before Him on the 
summit of Mount Sinai.” The angel of the Lord was reading it, and he was listen-
ing like a child, hearkening to his teacher’s words: “O the great prophet Moses, 
the enlightened one out of the whole House of Man, turn back from your habit; it 
is no longer as it was. Remove your sandals from your feet (Exod. 3:5), for you are 
required to tread today on the path of holiness. Return the sheep that are in your 
charge to their owner, for you are about to lead the Stars of Abraham.”','אמר משה משה, והוא ענה הנני (שמות ג,ד) — הנסתר תמה וכל הגלוי שמח. אמר משה משה — הודיעו שהוא אדון החסד האלוהי והגמול. אמר משה משה — גילה לו שילבש נבואה ואת שם האלוהות. אמר משה משה — הודיעו שיוציא את העברים לחרות ויכה את המצרים. כשאמר אברהם אברהם (בראשית כב,יא), הכריז לו שאכן הוא זוכר את החסד האלוהי ואת הפורענות. כשאמר יעקב יעקב (בראשית מו,ב), הודיעו שהוא מקור הפנים והחוץ. כשאמר בסנה משה משה, האחד מתייחס למה שהיה והאחד למה שעתיד לבוא. משה משה, כאילו אמר לו: "אתה נביא שכמותו לא קם בעולם." משה משה, כאילו אמר לו: "אתה נקרא לעולם החיים; רבה גדולתך בין כל בני האדם, עד שנמסרים לך סודות ישנים וחדשים, חתומים עם המבשר הטוב, פרושים לפניו על ראש הר סיני." מלאך ה'' היה קורא בהם, והוא הקשיב כילד השומע לדברי מורו: "הו משה הנביא הגדול, המואר מכל בית האדם, שוב מהרגלך; אין הדבר עוד כפי שהיה. של נעלך מעל רגלך (שמות ג,ה), כי עליך לדרוך היום בנתיב הקדושה. החזר את הצאן שבטיפולך לבעליהם, כי אתה עומד להנהיג את כוכבי אברהם."');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (80,'I','34','ספר פליהתה',1000341,'חזי יהבתך אלהים לפרעה ואהרן אחוך יתעבד נביאך חזי יהבתך אלהים לפרעה בדיל תגבי מנה פריתה דקהלה חזי יהבתך אלהים לפרעה בגלל מאבדה קנומה וכל סיעתה חזי יהבתך אלהים לפרעה באטרה דיהבת לך למגלי בה פליאן חזי יהבתך אלהים לפרעה 7923 . בבעותי אבד כל מצראי כעטף עינה חזי יהבתך אלהים לפרעה יתה אתן באדך ותקטלנה בדינה חזי יהבתך אלהים לפרעה אתהו גאולה דאדמה דבני שלמיה חזי יהבתך אלהים לפרעה לא תדחל מנה כי באדך יהבת יתה חזי יהבתך אלהים לפרעה נציע הו קמיך ולית צריך לסעוד','“See, I make you as God to Pharaoh; and Aaron your brother shall be your 
prophet (Exod. 7:1). See, I make you as God to Pharaoh – so that you take revenge 
on him for the congregation. See, I make you as God to Pharaoh – so that you 
may destroy him and all his company. See, I make you as God to Pharaoh – 
through the rod that I gave you to perform wonders. See, I make you as God to 
Pharaoh – by My will, destroy all the Egyptians in a wink of the eye. See, I make 
you as God to Pharaoh – I shall deliver him into your hands, and you will slay 
him by judgment. See, I make you as God to Pharaoh – you are the redeemer of 
the blood of the sons of the perfect ones. See, I make you as God to Pharaoh – do 
not fear of him, for I have delivered him into your hands. See, I make you as God 
to Pharaoh – he is defeated before you, and you need no assistance.”','"ראה, נתתיך אלהים לפרעה, ואהרן אחיך יהיה נביאך (שמות ז,א). ראה, נתתיך אלהים לפרעה — כדי שתיקום בו עבור העדה. ראה, נתתיך אלהים לפרעה — כדי שתשמיד אותו ואת כל חילו. ראה, נתתיך אלהים לפרעה — על ידי המטה שנתתי לך לעשות נפלאות. ראה, נתתיך אלהים לפרעה — ברצוני, השמד את כל המצרים כהרף עין. ראה, נתתיך אלהים לפרעה — אמסור אותו בידיך, ותמיתנו במשפט. ראה, נתתיך אלהים לפרעה — אתה גואל דם בני התמימים. ראה, נתתיך אלהים לפרעה — אל תירא ממנו, כי מסרתיו בידיך. ראה, נתתיך אלהים לפרעה — הוא מובס לפניך, ואינך זקוק לעזרה."');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (81,'I','54','ספר פליהתה',1000541,'לא אסטי כלמיה מנה עד אמיר לה דערבה מזדיאן ביד אלה למגביתך עזר מן טעותך ושלח ית ישר ואלא מצרים מחבלה בידה שתק על ממללה ולא שאמה כלום ולא טמעת שמשה ביתה יומה אלא ואתא ערבה קבלו רבה אתעמית תמן ערב יקיר עד מותר משלט על מצראי קבלה רבה אתעמית תמן שותפיו דחם מחבל לבניו ואתחבלת ארעה מקדם ערבה אכל ילידיון דאנון קעימין ואתחבלת ארעה מקדם ערבה אקנהו בביתה ואשנתו בבראה כד א › ת ‹ לחץ מנה פרעה זעק למשה ולאהרן ולבה מלי עקה חיולה מה אתון בעין המפוק מן ארע מצרים זלו דבחו לאלהכון בארעה','The gnats had barely withdrawn from him, when it was said to him: 
“The raven is prepared by God for your punishment. Turn back from your stray-
ing and let Israel go, otherwise Egypt will be ruined by Him.” He remained silent 
at this utterance and would not consider it at all. The sun did not set that day be-
fore ravens came. A great darkness was seen there, with exceedingly many ra-
vens prevailing over the Egyptians. A great darkness was seen there; Ham’s part-
ner destroys his (own) sons. The land was ruined because of the raven (Exod. 
8:20), they ate the children while yet alive. The land was ruined because of the ra-
ven, anger in the houses and wrath outside. When Pharaoh was distressed by it, 
he called Moses and Aaron, his heart full of a mighty agony: “Do you indeed 
want to depart from the land of Egypt? Go sacriﬁce to your God within the land 
(Exod. 8:21).”','בְּקֹשִׁי פָּרְשׁוּ הַכִּנִּים מֵעָלָיו, כַּאֲשֶׁר נֶאֱמַר לוֹ: "הֶעָרוֹב מוּכָן מֵאֵת הָאֱלֹהִים לְעָנְשְׁךָ. שׁוּב מִתְּעִיָּתְךָ וְשַׁלַּח אֶת יִשְׂרָאֵל, פֶּן יְחָרְבֶנָּה אֶת מִצְרַיִם." שָׁתַק לַדָּבָר הַזֶּה וְלֹא שָׂם אֵלָיו לִבּוֹ כְּלָל. לֹא שָׁקַע הַשֶּׁמֶשׁ בַּיּוֹם הַהוּא בְּטֶרֶם בָּא הֶעָרוֹב. חֹשֶׁךְ גָּדוֹל נִרְאָה שָׁם, עִם עָרוֹב רַב מְאֹד שֶׁהִשְׁתַּלֵּט עַל הַמִּצְרִים. חֹשֶׁךְ גָּדוֹל נִרְאָה שָׁם; שׁוּתָפוֹ שֶׁל חָם מַשְׁחִית אֶת בָּנָיו. וַתִּשָּׁחֵת הָאָרֶץ מִפְּנֵי הֶעָרוֹב (שמות ח,כ), אָכְלוּ אֶת הַיְלָדִים כַּאֲשֶׁר הָיוּ עוֹדָם בַּחַיִּים. וַתִּשָּׁחֵת הָאָרֶץ מִפְּנֵי הֶעָרוֹב, זַעַם בַּבָּתִּים וְחֵמָה בַּחוּץ. כַּאֲשֶׁר נִלְחַץ פַּרְעֹה מֵחֲמָתוֹ, קָרָא לְמֹשֶׁה וּלְאַהֲרֹן, לִבּוֹ מָלֵא כְּאֵב עַצּוּם: "הַאֻמְנָם רְצוֹנְכֶם לָצֵאת מֵאֶרֶץ מִצְרַיִם? לְכוּ זִבְחוּ לֵאלֹהֵיכֶם בָּאָרֶץ (שמות ח,כא)."');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (82,'I','66','ספר פליהתה',1000661,'הדה היא כבר גזירת דבחה בין רמשיה יעבדון יתה כל עמה ויהי אדמה לוכון סימן על בתיה כיי מחבלה עמי לה וגעז ויהי אדמה לוכון סימן על בתיה כי רגזי עמי לה ופסח ויהי אדמה לוכון סימן על בתיה מלבר ואיקרה דאלה מלגו לית אנא צריך ליסמן אלא עד יתעבד דכרן גזרת עלם תהי לדריכון ותחגון יתה חג ליה לעלם לא יתחזי בה חמיר בתחומיכון שבעה יומין תיכלון פטיר מן דאכל לגוה חמי יתעקר וטובי ליתו מקבל לה לעלם מיומה קדמאה וסעד יומה שביעיה בכל מדוריכון פטיר תיכלון בזרוז תיכלון יתה חרציכון אסירין מסניכון ברגליכון ואטריכון באדיכון בתר כן כבודי נחת וקטל כל בכורי מצראי מן אנש סעד בהמתה ואתון נפקין ביד רמה מנגדין בעמוד עננה ואשתה מזיאנין במני מצראי כספה ודהבה ותכסיהן ואתון בון מתעתרין באיקרין רברבין ומצראיה מתרוקנין מכל מדהלון אלף אללה למשה גזירת פסחה ואתא ילפנה לקהל ישראל','“This is, indeed, the law of the sacriﬁce; at twilight the whole people 
shall oﬀer it. The blood shall be a sign to you upon the houses (Exod. 12:13), so 
that the Destroyer may see it and pass by. The blood shall be a sign to you upon 
the houses, that My anger may see it and skip (them). The blood shall be a sign to 
you upon the houses on the outside, and the Glory of God on the inside. I need no 
sign, only that it may become a memorial – an everlasting statute (Exod. 12:17) it 
shall be throughout your generations. And you shall keep it as a feast to the Lord 
(Exod. 12:14) forever. No leavened bread should be seen in your territory. Seven 
days you shall eat unleavened bread […] whoever eats leavened bread during 
them shall be cut oﬀ from Israel (Exod. 12:15; 13:7), and My Goodness will never 
accept him. From the ﬁrst day to the seventh day, in all your dwellings, you shall 
eat unleavened bread, in haste you shall eat it: your loins girded, your sandals on 
your feet, and your staﬀs in your hands (Exod. 12:11). Aferwards, My Glory will 
descend and kill all the ﬁrstborn of the Egyptians, man and beast, while you 
depart with triumph (Exod. 14:8), led by the Pillar of Cloud and Fire, provisioned 
with the objects of the Egyptians, gold and silver and garments. You will be 
enriched with great possessions while the Egyptians will be deprived of all their 
belongings.” God taught Moses the Law of Passover, who went to teach it to the 
congregation of Israel.','"זוהי, אכן, תורת הקרבן; בין הערביים יקריב אותו כל העם. והיה הדם לכם לאות על הבתים (שמות יב,יג), למען יראה המשחית ופסח. והיה הדם לכם לאות על הבתים, למען תראה זעמי ודלגה עליהם. והיה הדם לכם לאות על הבתים מבחוץ, וכבוד האל מבפנים. אין לי צורך באות, אלא שיהיה לזיכרון – חוקת עולם (שמות יב,יז) יהיה לדורותיכם. ושמרתם אותו חג לה'' (שמות יב,יד) לעולם. לא יראה שאור בכל גבולך. שבעת ימים תאכל מצות [...] כל אוכל חמץ בהם ייכרת מישראל (שמות יב,טו; יג,ז), וטובי לא תקבלנו לעולם. מהיום הראשון עד היום השביעי, בכל מושבותיכם, תאכלו מצות, בחיפזון תאכלוה: מתניכם חגורים, נעליכם ברגליכם ומקלותיכם בידיכם (שמות יב,יא). לאחר מכן תרד כבודי ותמית את כל בכורי מצרים, אדם ובהמה, ואתם תצאו בניצחון (שמות יד,ח), מובלים בעמוד הענן והאש, מצוידים בחפצי המצרים, זהב וכסף ובגדים. תתעשרו בנכסים רבים בעוד המצרים יישארו ריקם מכל רכושם." האל לימד את משה את תורת הפסח, והוא הלך ללמדה לקהל ישראל.');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (83,'I','44','ספר פליהתה',1000441,'נצחו קרבי אמר לון פרעה דאנה נציע ביד אהן תנינה ליני נטר לכון ומקומם גזריכון אלא בגלל כות הדה שעתה כי עבר עלי תמחין ופליאן וכהדה פליתה לא עמית מיומי אלולי דאנה מתפוגג תדיר בחזותכון דהות רוחי מני סטיה אנשם גרמך לא תדחל מנה כי בידן נעבד מהו רב מנה בערימו רבה ארמו אטריון ואתעבדו כהלון תנינין סחרתה אסתכל פרעה ] ו [ סיעתיו ועמו תנינ › י ‹ ה דעבדו ] חרש [ יה וזהו ] זהו [ חיולה ] לא יתגל [ גון ] עליו [ ן משה ואהרן צפה תנינה ימינה וסמאלה וחזה כל תניניה מכהרין עלויו פתח פמה ובלע כהלון כעטף עינה והפך על פרעה ובעי מבלענה נמסת רוחה וספת גויתה סגי ממה דהות והוו חרשיה בבהתה רבה ח ] שב [ ו אנון עבדין כלום מנשם לגרמה נכאו ולא יכלו','“Wage war for me”, said Pharaoh, “for I am defeated by this serpent. I 
do not keep and maintain your positions except for a time like this. Indeed, mira-
cles and wonders passed before me, but a wonder like this one I have not seen 
my whole life. Were I not always comforted by the sight of you, my spirit would 
depart from me.” “Recover yourself, do not be afraid of it, for we can do some-
thing that is greater than it.” With great skill they threw down their rods, and 
they all became serpents around it. Pharaoh and his companies looked and saw 
the serpents that the magicians made, and they rejoiced with mighty joy: Moses 
and Aaron will no longer triumph over them. The serpent looked to its right and 
to its lef and saw all the serpents ganging up against it. It opened its mouth and 
swallowed all of them in the wink of an eye. It turned towards Pharaoh and 
sought to swallow him. His spirit melted away, and his body became fainter than 
it had (before). And the magicians were in great shame. They had supposed they 
could do something to relieve him, but they were weakened and were unable (to 
do anything).','"צאו למלחמה בשבילי", אמר פרעה, "כי נוצחתי על ידי הנחש הזה. אינני שומר ומקיים את מעמדכם אלא לשעה כזו. ואמנם, נסים ונפלאות עברו לפני, אך פלא כזה לא ראיתי בכל ימי חיי. אלמלא הייתי מתנחם תמיד למראה פניכם, רוחי הייתה יוצאת ממני." "התאושש, אל תירא ממנו, כי ביכולתנו לעשות דבר גדול ממנו." במיומנות רבה השליכו את מטותיהם, וכולם נהפכו לנחשים סביבו. פרעה וחיליו הביטו וראו את הנחשים שעשו החרטומים, וישמחו שמחה גדולה מאוד: משה ואהרן לא יגברו עליהם עוד. הנחש הביט לימינו ולשמאלו וראה את כל הנחשים מתקהלים עליו. פתח את פיו ובלע את כולם כהרף עין. פנה אל פרעה ובקש לבולעו. רוחו נמסה בו, וגופו נחלש יותר מבראשונה. והחרטומים היו בבושה גדולה. חשבו שיוכלו לעשות דבר מה להקל עליו, אך נחלשו ולא יכלו.');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (84,'I','2','ספר פליהתה',1000021,'וחכם למשה רזין בסניה פרסיאת רבותה ומהי יקירותה וקדם לה מל » א « ך קעם לכבונה ומלל עמה מד הוה ומד יהי וקעם נביה משוי למה דעמתה וארקפת אבריו כד עמתה משגר ביד מרה לית על דמותה נביה עתיד ישמע וישמע עמה לית טובה מתחזי לאנש אלא על דמותה טבה כטבהתה ובישה כבישותה ומלאכיה דאתחזו לזכאיה לית אנון אלא לקבל שעה חדה ומיסתה אתחזי מנון תלתה לאברהם ובסרותה ועברו ביומה אתחזי מנון ללוט תרין באפי רמשה ועבדו מה דצרך ועברו בלילון אתחזי ליוסף אחד בבראה שוי וחכמה שבילה ולא אתחזי לה עוד כן הוה מל » א « כה דאתחזי בסניה משגר ביד אלה באגרה ליד נביא רב הוא תמחה דאתעמי תמן תלתה גונין לא דמין דן לדן אש מלבלבה וסניה לגוה מקלע ומלאכה קרי ומשה שמע וארתת','In the bush, he taught Moses teachings, (which) revealed His greatness 
and what His glory is. An angel approached him, standing before him, and 
talked with him (about) what had been and what will be. And the prophet stood 
prepared facing what he saw, and his limbs trembled when he saw the one sent 
by his Master. There is none like him, a prophet ready to discuss with him. The 
Good One does not reveal Himself to any man except according to his nature: the 
good one according to his goodness, the wicked one according to his wicked-
ness. The angels who appeared to the righteous came for one moment only. 
Three of them appeared to Abraham, and once they announced news to him 
they departed on the same day. Two of them appeared to Lot towards the evening 
and did what they had to do and lef the same night. One of them appeared 
brieﬂy to Joseph in the ﬁeld and showed him the way and never appeared to him 
again. Likewise, the angel who appeared in the bush, sent by God with a 
message to the prophet. Great was the miracle that he was shown there. Three 
things that do not resemble one another: a blazing ﬁre, the bush growing in it, 
and the angel proclaiming, while Moses listens trembling.','בסנה לימד את משה תורות שגילו את גדולתו ואת מהות כבודו. מלאך ניגש אליו, עמד לפניו, ודיבר איתו על מה שהיה ומה שעתיד להיות. והנביא עמד מוכן מול מה שראה, ואיבריו רעדו כשהבחין בשליח אדונו. אין כמוהו, נביא המוכן לדון עמו. הטוב אינו מגלה את עצמו לאיש אלא לפי טבעו: לטוב לפי טובו, לרשע לפי רשעו. המלאכים שנגלו לצדיקים באו לרגע אחד בלבד. שלושה מהם נגלו לאברהם, וכיוון שבישרו לו חדשות עזבו באותו יום. שניים מהם נגלו ללוט לעת ערב, עשו את שנדרש מהם ועזבו באותו הלילה. אחד מהם נגלה לזמן קצר ליוסף בשדה, הראה לו את הדרך ולא נגלה אליו עוד. כך גם המלאך שנגלה בסנה, שנשלח על ידי האל עם מסר לנביא. גדול היה הנס שהוראה לו שם. שלושה דברים שאינם דומים זה לזה: אש בוערת, הסנה הצומח בתוכה, והמלאך המכריז, בעוד משה מקשיב וחרד.');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (85,'II','1b','על תהומי מעין עדן',2000013,'אדכיר לטב עד לעלם נביה רבה משה דנתן בפגרה מרה סימנים עשרה לא נתנון בעורנה האחד ברגליו עד ידרס באשתה ולא יתנכי בה השני בגויתה משח זית קדש דו כהן תמים במשכן כסיאתה השלישי באדיו דבון עבד פליהתה וקבל לוחיה הרביעי בקדקדה בדיל דיקרב לערפלה דתמן האלהים החמישי בלשנה עד יתורך בממללה ומרה עבד באמירתה הששי בעיניו עד יהי צפי תמחי כסיאתה דמות גליאתה השביעי בצלמה מבלד כל עמוי ולא יתאכל מקעם קדמיו השמיני בממללה בדיל דיהי מזדוג עם ממלל מרה התשיעי בלבה עד יסחן מלי קשטה וילפנה העשירי במשמועה עד ישמע מה מרה ממלל עמה קדם אה נביה לאתרה דיתבתך בה','Of blessed memory be the great prophet Moses, in whose body his 
Master gave ten signs, which He did not give in any other. The ﬁrst in his feet, so 
that he may walk on ﬁre without being harmed by it. The second in his body, (He 
anointed him with) holy olive oil, for he is a perfect priest in the Sanctuary of the 
Concealed. The third in his hands; with them he performed the wonders and re-
ceived the Tables. The fourth in his head, so that he may draw near to the thick 
thickness where God was (Exod. 20:21). The ﬁfh in his tongue, so that he may 
last in speech, while his Master acts according to his speaking. The sixth in his 
eyes, so that he may look at the wonders of the Concealed, as (he looks at) the 
Overt. The seventh in his face, which frightens everyone who sees him – and 
(nobody) is able to resist him. The eighth in his speech, so that it may be associ-
ated with the speech of his Master. The ninth in his mind, so that he may acquire 
the words of the True One and teach them. The tenth in his hearing, so that he 
may hear what his master speaks to him: “Approach, O prophet, to the spot 
where I placed you.”','יהי זכרו ברוך של הנביא הגדול משה, אשר בגופו נתן לו אדונו עשרה אותות, שלא נתנם באחר. הראשון ברגליו, כדי שיוכל ללכת על אש מבלי שתזיק לו. השני בגופו, (משחו) בשמן זית קדוש, כי הוא כוהן שלם במקדש הנסתר. השלישי בידיו; בהן עשה המופתים וקיבל את הלוחות. הרביעי בראשו, כדי שיוכל לגשת אל הערפל אשר שם האלוהים (שמות כ,כא). החמישי בלשונו, כדי שיוכל לדבר ללא הפסק, ואדונו פועל לפי דיבורו. השישי בעיניו, כדי שיוכל להביט בנפלאות הנסתר כמו שמביט בנגלה. השביעי בפניו, המטילים אימה על כל הרואים אותו – ואין איש מסוגל לעמוד בפניו. השמיני בדיבורו, כדי שיהא קשור בדיבור אדונו. התשיעי בשכלו, כדי שיוכל לקנות את דברי האמת וללמדם. העשירי בשמיעתו, כדי שיוכל לשמוע את אשר אדונו מדבר אליו: "גש, הו נביא, אל המקום אשר הצבתיך בו."');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (86,'II','20','על תהומי מעין עדן',2000201,'החל בזכרון הסוס לשני חולקים הראש היו סוס פרעה ורכבו בים ילכו אל תוך הים למות והמצרים › י ‹ דרשו יצאו מן ימה ולא יכלו ינכו מרכביהון למוצא והשני החל במדכר המרכב מפני הרכב ליודע כי במרכב הו ] ת [ גאות המצרים פרקן רב בין גאים וגאים גאים ביהוה אנון עבראי וגאים בסוס אנון מצראי לכן אמר משה עזי וזמרתי מתפאר בעזו תמיד לעולם ויהי לי לישועה ויושיע יהו במופתיו אשר קנאם בם ויהי לי לי › ש ‹ וע › ה ‹ לה ולישראל כחדה כד בע ] ה [ פרעה לקטלה וערק למדין ] זה [ אלי ואנוהו א ] ש [ רך ישראל במן הו אלהך דלה תעבד','He started with the mention of the horse (referring) to two parts. The 
ﬁrst one: The horses of Pharaoh and his riders were entering the sea to die, and 
the Egyptians were seeking to exit the sea, but were unable – their chariots were 
damaged at the exit. The second: He started with the mention of the chariots. 
The chariot, before the rider, because it is known that resting in the chariot was 
the pride of the Egyptians. (There is) a great diﬀerence between proud ones and 
proud ones: proud ones in the Lord – (these) are the Hebrews – and proud ones 
in the horse – these are the Egyptians. This is why Moses said: He is my strength 
and praise – He is gloriﬁed in His strength always, forever. He has become my 
deliverance – The Lord saved (Exod. 14:30) with His wonders, with which He 
struck them. He has become my deliverance – to him (Moses) and to Israel alike. 
When Pharaoh sought to kill him, and he ﬂed to Midian. This is my God, and I 
will praise him (Exod. 15:2). Happy are you, O Israel, with He who is your God, 
whom you worship.','פתח בהזכרת הסוס בהתייחס לשני חלקים. הראשון: סוסי פרעה ורוכביו נכנסו אל הים למות, והמצרים ביקשו לצאת מן הים אך לא יכלו – מרכבותיהם ניזוקו ביציאה. השני: פתח בהזכרת המרכבות. המרכבה לפני הרוכב, לפי שידוע שהישיבה במרכבה הייתה גאוות המצרים. הבדל גדול יש בין גאים לגאים: גאים בה'' – אלו הם העברים – וגאים בסוס – אלו הם המצרים. לכן אמר משה: "עזי וזמרת יה" – הוא מפואר בכוחו תמיד לעולם ועד. "ויהי לי לישועה" – ה'' הושיע (שמות יד,ל) בנפלאותיו, שבהן הכה אותם. "ויהי לי לישועה" – לו (למשה) ולישראל כאחד. כשביקש פרעה להורגו, וברח למדין. "זה אלי ואנוהו" (שמות טו,ב). אשריך ישראל, שה'' הוא אלהיך, אשר אתה עובד אותו.');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (87,'II','47','על תהומי מעין עדן',2000471,'מכן טב תדע דחנוך חכמה ורחט לידה כמה דרעט אברהם וכן אנוש עליו קרא בשם יהוה ואתחיל במקרתה ונח לכבונה דבח ואתקבל דבחה וכמה דאמיר עליו אמיר על אברהם ויבן נח מזבח ויבן שם אברהם את המזבח הך מה דעבד נח ברז דקשט כן עבד אברהם ברזה דקשט רבותה לאלהנו דקבע לאבהן רזים טבים ובטובה מעיני לון ובקשטה מרבי לון יצחק עמתה ויעקב חכמה ויוסף מלכה ירתה עבידה מן אבהן לבנים טובי מלוכיה וטובי ירותיה בר ארדאי ומעזי לא הוה ביניון אלא כהלון טבים בשרואה ובעקבה עלם כלה ברכן ואצלחו עלם דהוה בה משה נרבי קנומינן בתשבחתה דמרן ולא נבטלנה ונעבדנה תורס באפינן דמה נדור בשלם ונהי מסמכין באימנותה באלה ובמשה נביה לו לא משה לא הגלת תורה ולא התודעת מצוה נרבי למרן ונהימן בגדלה ונוקר לנביה ונימן בשליחותה דמה דנסב ברכן ונמלכנון דו רחמן ורתאי מיטב לכל רחמיו','Therefore, it is good for you to know that Enoch knew it and rushed to-
wards it, just as Abraham rushed, and also that Enosh invoked the Lord by name 
and was strengthened by his invocation. And Noah oﬀered a sacriﬁce in its direc-
tion, and his sacriﬁce was accepted, and what was said about him was also said 
about Abraham: Noah built an altar (Gen. 8:20), Abraham built there the altar 
(Gen. 22:9). What Noah did with a true mind, Abraham did with a true mind. 
Greatness to our God, who planted in (our) ancestors good minds – and in His 
goodness He watches them, and in His truthfulness He gloriﬁes them. Isaac saw 
it, Jacob knew it, Joseph owned it; an inheritance from fathers to sons. Happy 
are those who possess it and those who inherit it. There was no stubborn and 
rebellious son (Deut. 21:18) among them, but all of them were good from the be-
ginning to the end. A world wholly of blessing and prosperity was the world 
Moses was in. Let us magnify ourselves by the praise of our Master, and not 
cease to do so. Let us make (praise) a shield before us, that we may dwell in 
peace, and be supported by faith in God and in Moses his prophet. If it had not 
been for Moses, the Law would not have been revealed and no precept would 
have been made known. Let us exalt our Master, and believe in his greatness, 
and give honor to His prophet, and believe in his mission, that we may receive 
blessings and possess them, for He is merciful and gracious (Exod. 34:6), who 
beneﬁts all His devotees.','לפיכך, טוב לך לדעת כי חנוך ידע זאת ומיהר לקראתה, כשם שאברהם מיהר, וכן אנוש קרא בשם ה'' והתחזק בקריאתו. ונח הקריב קרבן לעברה, וקרבנו התקבל, ומה שנאמר עליו נאמר גם על אברהם: וַיִּבֶן נֹחַ מִזְבֵּחַ (בראשית ח,כ), וַיִּבֶן שָׁם אַבְרָהָם אֶת הַמִּזְבֵּחַ (בראשית כב,ט). מה שעשה נח בלב אמת, עשה אברהם בלב אמת. גדולה לאלוהינו, אשר נטע באבותינו לבבות טובים – ובטובו הוא שומר עליהם, ובאמיתו הוא מכבדם. יצחק ראה אותה, יעקב ידעה, יוסף ירשה; נחלה מאבות לבנים. אשרי המחזיקים בה והיורשים אותה. לא היה בן סורר ומורה (דברים כא,יח) ביניהם, אלא כולם היו טובים מראשית ועד סוף. עולם שכולו ברכה ושלווה היה העולם שמשה שהה בו. נתגדל בשבח אדוננו, ולא נחדל מכך לעולם. נשים את השבח כמגן לפנינו, כדי שנשב בשלום, ונישען על האמונה באלוהים ובמשה נביאו. אלמלא משה, לא הייתה התורה נגלית ולא הייתה כל מצווה מתוודעת. נרומם את אדוננו, ונאמין בגדולתו, ונחלוק כבוד לנביאו, ונאמין בשליחותו, כדי שנזכה לברכות ונחזיק בהן, כי הוא רַחוּם וְחַנּוּן (שמות לד,ו), המיטיב לכל חסידיו.');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (88,'II','6','על תהומי מעין עדן',2000061,'והרוח אשר שרתת עשרה פעמים למשמע פתרונה הנבון יצית הראש נשא עופים רמים לטרף שנאי אלהים וזה במובא הערב השני נשחת הרוח עד בא דבר כבד מאד המית המקנים השלישי פרש השחין מיד הנביא משה בכל ארץ מצר הרביעי נשא הרבה כבד מאד אכל כל אשר הותיר הברד החמישי רוח ים חזק מאד נשא הרבה והתקעה בים סוף הששי הביא חשך אפיל במאורות וחשך כל העינים השביעי ויוליך יה את הים ברוח קדים וישם את הים לחרבה השמיני וברוח אפך ניערמו מים היה הרוח להם כות אדנים התשיעי השיב את הים לאיתנו אסרה והשרתה למות ולפליטה העשירי נשב ברוח כבודו כסהמו ים בתר פליטות עבדיו הגדלות לך יה עשה הנוראות מי יעשה כמעשיך וכגבורתיך','And the wind that served ten times – let the wise one listen in order to 
hear its explanation. The ﬁrst time (the wind) carried mighty birds to prey on the 
enemies of God – and this was at the invasion of the raven. The second time the 
wind became infected, so that a very severe pestilence came and killed the 
cattle. The third time spread the boils from the hand of the prophet Moses 
throughout the land of Egypt. The fourth time carried locusts in a dense mass 
which ate all that was lef afer the hail (Exod. 10:15). The ﬁfh time a very strong 
west wind lifed the locusts and drove them into the Sea of Reeds (Exod. 10:19). 
The sixth time brought a dense darkness over the luminaries and darkened all 
the eyes. The seventh time the Lord drove the sea back by an east wind all night, 
and made the sea dry land (Exod. 14:21). The eighth time at the blast of thy nos-
trils the waters piled up (Exod. 15:8), the wind was like pedestals for them. The 
ninth time restored the sea to its strength. (The wind) chained it and released it 
for death and for escape. The tenth time He blew with His wind of glory, the sea 
covered them (Exod. 15:10) afer the deliverance of His servants. Exaltation to 
You, O Lord, the doer of terrifying things. Who can do the like of Your deeds and 
Your mighty acts?','והרוח ששירתה עשר פעמים – ישמע החכם כדי לשמוע את פירושה. בפעם הראשונה נשאה הרוח עופות אדירים לטרוף את אויבי האל – וזה היה בפלישת הערוב. בפעם השנייה נדבקה הרוח בנגע, עד שבאה דבר כבד מאד והמית את המקנה. בפעם השלישית פיזרה את השחין מידי הנביא משה בכל ארץ מצרים. בפעם הרביעית נשאה ארבה בעב רב אשר אכל את כל שנותר אחרי הברד (שמות י,טו). בפעם החמישית נשא רוח ים חזק מאד את הארבה והטילו אל ים סוף (שמות י,יט). בפעם השישית הביאה חושך כבד על המאורות והחשיכה את כל העיניים. בפעם השביעית הוליך ה'' את הים ברוח קדים כל הלילה, וישם את הים לחרבה (שמות יד,כא). בפעם השמינית בְּרוּחַ אַפֶּיךָ נֶעֶרְמוּ מַיִם (שמות טו,ח), הרוח הייתה כמו כנים תחתיהם. בפעם התשיעית השיבה הרוח את הים לאיתנו. כבלה אותו ושחררה אותו למוות ולמנוסה. בפעם העשירית נשב ברוח כבודו, כִּסָּמוֹ יָם (שמות טו,י) אחרי הצלת עבדיו. רוממות לך, ה'', עושה הנוראות. מי יוכל לעשות כמעשיך וכגבורותיך?');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (89,'II','8','על תהומי מעין עדן',2000081,NULL,'Fourteen times the water served through him all the hosts of the Lord. 
The ﬁrst: He took some water from the Nile and poured it on the dry ground in 
the sight of all the people, so that they might believe and know that the blood of 
Pharaoh and his people will be shed likewise. Exaltation to You, O Lord, who 
keeps the covenant and the grace (Deut. 7:9). For the Lord is greater than all gods 
(Exod. 18:11). The second: He turned the water of the Nile into blood as revenge 
on all the Egyptians. In this wonder are ten wonders, and in them relief to the 
servants of God, so that their foes should know that the Lord is greater than all 
gods. The third: The water of the whole land of Egypt became red blood for all 
the Egyptians. Seven days passed (Exod. 7:25), (during which) they were unable 
to drink from its water. But for the Hebrews it was Water of Life. This water itself 
is revenge to the former, and to the latter it is life, giving life and goodness and 
mercy. For the Lord is greater than all gods. The fourth: The blood turned back 
into water afer seven days and (the water) swarmed with new frogs. At once 
they swarmed and came forth in hordes in all the places of the Egyptians. 
Exceedingly weak swarms, how had they insight to discern with righteous judg-
ment between friends and foes?! All the heroes submitted to them. For the Lord 
is greater than all gods. The ﬁfh: He rained hail and along with it He brought 
thunder and ﬁre streamed down to the ground (Exod. 9:23). And it is said that the 
ﬁre was steady amidst the hail and the water of the hail surrounded it. And it is 
said that (the ﬁre) which was among the hail in the land of Egypt was burning 
ﬂame, consuming even among the hail. The Power belongs to Him who does all 
this, for the Lord is greater than all gods. The sixth: The water of the Sea of Reeds 
was split when it saw the “Sea of Prophethood”, at the command of the Lord the 
God. And a pathway was placed in it, prepared for the hosts of the Lord – a 
wonder the like of which never was and never will be. For the Lord is greater 
than all gods. The seventh: A wall was set up in front of the moving waters, so 
that they stood straight like a high mountain. They piled up above to guard the 
way of Israel, so that they should walk in safety. For the Lord is greater than all 
gods. The eighth: (The sea) became dry – He turned the sea into dry land (Exod. 
14:21) – as though there had not been water ﬂowing in it from the day of the cre-
ation of the creatures, so that Israel would not be harmed while walking therein. 
Let us give glory to our God, for the Lord is greater than all gods. The ninth: The 
nature of all the waters in the Sea of Reeds changed. They were rising up strong-
ly from the bottom to the top. Although the nature of the water is (to ﬂow) from 
the top to the bottom, the descending water stood up (like) walls to guard the 
tribes. Blessed be the Master of greatness, for the Lord is greater than all gods. 
[The tenth: The water at that time was set up as a righteous judge who judged 
between righteous and wicked, and overthrew the wicked before him (the 
righteous) and killed him with various plagues, and delivered the righteous from 
it, and discriminated between the two of them at the command of the great Lord, 
for the Lord is greater than all gods. The eleventh: When the servants of the Lord 
came out (of the sea), while the Egyptians moved against it (Exod. 14:27), He 
locked the leaders of their chariots (Exod. 14:25) and overthrew the walls (of 
water) before them, so that He sentenced their head to conﬁnement. They 
searched for rescue, and did not ﬁnd it. Then all of them knew that the Lord is 
greater than all gods. The twelfh: The sea returned to its strength (Exod. 14:27) in 
front of Pharaoh and all his servants, while they were all still alive, and they saw 
that there is no space for escape. The Lord lifed them up by the wind, so that 
they saw the people of Israel sound on the sea shore. Afer that the Egyptians 
sank like a stone. For the Lord is greater than all gods. The thirteenth: His voice 
was heard from all corners at the time when the water moved, until the nations 
heard. By this the great prophet Moses made known to those who hear, in his 
prophecy in the section “Then sang” (Exod. 15:1–21), the message that the Lord is 
greater than all gods. The fourteenth: The water closed in over Pharaoh and all 
his people,] not one of them remained (Exod. 14:28), while all Israel went forth 
sound, kings afer being slaves, joyful in redemption, exalting the Master of their 
fathers, the God of Abraham, and Isaac, and Jacob, and they had faith in the Lord 
and in Moses, His servant (Exod. 14:31). These are the thirty three (events) in 
which (the elements) served Israel and slew all the Egyptians.','ארבע עשרה פעמים שימשו המים דרכו את כל צבאות ה''. הראשונה: לקח מעט מים מן הנילוס ויצקם על פני היבשה לעיני כל העם, למען יאמינו וידעו כי דמו של פרעה ועמו יישפך כך. הוד לך, ה'', שומר הברית והחסד (דברים ז,ט). כי גדול ה'' מכל האלהים (שמות יח,יא). השנייה: הפך את מי הנילוס לדם לנקמה בכל המצרים. בנפלא זה כלולות עשר נפלאות, ובהן הקלה לעבדי האלהים, למען ידעו אויביהם כי ה'' גדול מכל האלהים. השלישית: מי כל ארץ מצרים נהפכו לדם אדום לכל המצרים. שבעת ימים עברו (שמות ז,כה), ולא יכלו לשתות ממימיו. אך לעברים היה מי חיים. מים אלה עצמם הם נקמה לאלו, ולאלו חיים, נותנים חיים וטובה ורחמים. כי ה'' גדול מכל האלהים. הרביעית: הדם שב להיות מים לאחר שבעת ימים, והמים שרצו צפרדעים חדשות. כרגע שרצו ויצאו בהמוניהן אל כל מקומות המצרים. להקות חסרות כל כוח, כיצד היה בהן שכל להבחין בשיפוט צדיק בין אוהבים ואויבים?! כל הגיבורים נכנעו להן. כי ה'' גדול מכל האלהים. החמישית: הוריד ברד, ועמו הביא קולות ואש מתפשטת ארצה (שמות ט,כג). ונאמר שהאש הייתה יציבה בתוך הברד ומי הברד הקיפוה. ונאמר שהאש אשר הייתה בתוך הברד בארץ מצרים הייתה להבת אש בוערת, שורפת אפילו בתוך הברד. הכוח שייך לו אשר עשה כל אלה, כי ה'' גדול מכל האלהים. השישית: מי ים סוף נבקעו כשראו את "ים הנבואה", בפקודת ה'' האלהים. ונפתח בו מסלול, מוכן לצבאות ה'' – נפלא שכמוהו לא היה ולא יהיה לעולם. כי ה'' גדול מכל האלהים. השביעית: חומה הוקמה לפני המים הנעים, עד שעמדו זקופים כהר גבוה. נערמו מעלה לשמור על דרך ישראל, למען ילכו בבטחה. כי ה'' גדול מכל האלהים. השמינית: יבש – וישם את הים לחרבה (שמות יד,כא) – כאילו לא הייתה בו מים זורמים מיום בריאת הנבראים, למען לא יינזק ישראל בלכתו בתוכו. נתנה כבוד לאלהינו, כי ה'' גדול מכל האלהים. התשיעית: טבע כל המים בים סוף נשתנה. עלו בכוח מן התחתית אל הפסגה. אף כי טבע המים הוא לזרום מלמעלה למטה, המים היורדים עמדו כחומות לשמור את השבטים. ברוך אדון הגדולה, כי ה'' גדול מכל האלהים. [העשירית: המים באותה עת נקבעו כשופט צדיק ששפט בין צדיק לרשע, והפיל את הרשע לפניו (הצדיק) והרגו במכות שונות, והציל את הצדיק ממנו, והבחין בין שניהם בפקודת ה'' הגדול, כי ה'' גדול מכל האלהים. האחת עשרה: כשיצאו עבדי ה'' (מן הים), ובני מצרים בעו אחריהם (שמות יד,כז), נעל את אופני מרכבותיהם (שמות יד,כה) והפיל את החומות (של המים) לפניהם, כך שגזר על ראשיהם את עונש הכליאה. חיפשו מפלט ולא מצאו. אז ידעו כולם כי ה'' גדול מכל האלהים. השתים עשרה: הים שב לאיתנו (שמות יד,כז) לפני פרעה וכל עבדיו, בעודם עדיין חיים כולם, וראו שאין מקום למנוס. ה'' הגביהם ברוח, עד שראו את עם ישראל שלמים על שפת הים. לאחר מכן שקעו המצרים כאבן. כי ה'' גדול מכל האלהים. השלוש עשרה: קולו נשמע מכל הכיוונים בעת שהמים נעו, עד ששמעו הגויים. בזה הודיע הנביא הגדול משה לשומעים, בנבואתו בפרשת "אז ישיר" (שמות טו,א–כא), כי ה'' גדול מכל האלהים. הארבע עשרה: המים כיסו את פרעה ואת כל עמו,] לא נותר בהם אחד (שמות יד,כח), בעוד כל ישראל יצאו שלמים, מלכים לאחר שהיו עבדים, שמחים בגאולה, מרוממים את אדון אבותיהם, אלהי אברהם ויצחק ויעקב, ויאמינו בה'' ובמשה עבדו (שמות יד,לא). אלו הם שלושים ושלושת (האירועים) שבהם שימשו (היסודות) את ישראל והרגו את כל המצרים.');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (90,'II','39','על תהומי מעין עדן',2000391,'שמעו עמים וכל מה אחריה כל אלה מן נביות משה בן עמרם הנביא דפתח פמה ואמר שמעו עמים ושררה עורי במימרה ודחלו אה נביו קשיטה דאגדל בה משה ממירה מן מדע דאלה הודע תמן כד אתפלג ימה ברבו גדילה ושלטנו רמה מן ים סוף אתפלג בדילון דיארי עלמה דחלו מכן קשיט הו נביה במה דאמר דו מימר קשט מדילה דאלה שמעו עממאי ודחלו אמר ממלכת ישראל אתחדדת כדו וממלכת מצר סרת בדילון וכל אמי עלמה אתקשטו הדה תרי עובדין תמן אתעבדו כל חד מנון יתר על חברה פלוג ימה ואבדות מצראי › ו ‹ בכל אחד מנון בלוד רב וחיול כל עממאי כד שמעו אהן ממללה זעו ודחלו ואמרו בקנומון כד מצרים מחרבה מה יהי לן וקשטה הך אמר לון אתחידו כי לוכון מתעבד רב מכן הן הוה אהן בדילון עביד כי בדיל בניון יתעבד סגי מכן יתמלי עלמה דבבו לקשטה ויכעסו זכותה במד לה יעבדו ויצבע עלמה צבעה חדה בדיל בישיה דלגוה אתרבו ותסק צבעתה לקדם אלהי מעונה ויש > מ < ע וינאר ותהי צבעתה כצבעת אלין מלגו לחצה רבה וילה דרה דבה תשתמע הדה צבעתה כיינה קעום בבלוד לקבל מה יחזי וילה פניה ומה לה עתיד וטובי מהימנה במה לו מן גזואה וילון בישיה במה ילקון וטובי טביה במה יתגזון תהבה מגלי ומרבי לקשטה ומרן מתחזי ומרבי רחמיו מן ארבעת רבעת עלמה יהון אתין וילון כל דיארי עלמה ישתבח נהירה דמנהר לטבים ומגלי כל טב על דדון ישתבח נעירה דמחיל בטובה מדעי נעירים למחכום קשטה','The peoples heard (Exod. 15:14) and all that follows. All these (words) 
are from the prophecy of Moses the son of Amram, the prophet who opened his 
mouth and said: The peoples heard. And he strengthened it again with the word 
they trembled (ibid.). Behold, a true prophecy, by which Moses was exalted, pro-
vided by the knowledge of God, which he heralded there when the sea was split 
in great glory and high sovereignty. As the Sea of Reeds was split for their sake, 
the inhabitants of the earth were afraid. True is he, the prophet, in what he said, 
since it is a true utterance from God’s possession. The peoples heard and they 
trembled: (by this) he said that the kingdom of Israel has now been created and 
for their sake the kingdom of Egypt turned away, and all the nations of the world 
realized this. Two deeds were done then; each of them prevails over the other: 
the splitting of the sea and the destruction of the Egyptians. In each of them 
there is great and strong fear. All the peoples, when they heard this matter, trem-
bled and feared and said in their hearts: “Now that Egypt is destroyed, what will 
be with us?” It is as though the True One said to them: “Wait! Indeed, something 
greater than this will be done to you. If this much has been done for their sake, 
for the sake of their sons more than this will be done.” The world will be ﬁlled 
with hostility to the True One and they will irritate Righteousness by what they 
will do to Him. The world will cry out with one outcry because of the wicked who 
multiply within it, and their outcry will go up before the God of the heavenly 
abode. He will hear and remember, and the outcry will be like the outcry of 
these, out of the great oppression. Woe to the generation within which this out-
cry will be heard, for that generation stands fearful in front of what it is about to 
see. Woe to the apostate due to what is prepared for him. Happy is the faithful 
one due to what is granted to him from the recompense. Woe to the wicked due 
to what they will be struck with, and happy the good ones due to what they will 
be rewarded with. The Taheb will be revealed and he will exalt the True One. 
Our Master will appear and exalt His devotees, who will come from the four ends 
of the world. Woe to all the inhabitants of the world. Praised be the Enlightened 
One, who illuminates the good ones and reveals every good for their sake. 
Praised be the Enlightened One, who strengthens in His goodness the minds of 
the enlightened for the knowledge of truth.','הַעַמִּים שָׁמְעוּ (שמות טו,יד) וכל הַנֶּאֱמַר לְאַחַר מִכֵּן. כָּל הַדְּבָרִים הַלָּלוּ הֵם מִנְּבוּאָתוֹ שֶׁל מֹשֶׁה בֶּן עַמְרָם, הַנָּבִיא שֶׁפָּתַח אֶת פִּיו וְאָמַר: הַעַמִּים שָׁמְעוּ. וְחִזֵּק זֹאת שֵׁנִית בַּמִּלָּה יִרְגָּזוּן (שם). הִנֵּה נְבוּאָה אֲמִתִּית, שֶׁבָּהּ הִתְרוֹמֵם מֹשֶׁה, שֶׁנִּתְּנָה לוֹ מִדַּעַת הָאֵל, אֲשֶׁר בִּשֵּׂר אוֹתָהּ שָׁם בְּשָׁעָה שֶׁנִּבְקַע הַיָּם בְּתִפְאֶרֶת גְּדוֹלָה וּשְׂיִרָה רַבָּה. כַּאֲשֶׁר נִבְקַע יַם סוּף לְמַעֲנָם, יָרְאוּ יוֹשְׁבֵי הָאָרֶץ. אָמִתִּי הוּא, הַנָּבִיא, בְּכָל שֶׁאָמַר, כִּי הֲגִיגוֹ אֱמֶת מֵאֹצַר הָאֵל. הָעַמִּים שָׁמְעוּ וְיִרְגָּזוּן – בְּכָךְ אָמַר שֶׁמַּלְכוּת יִשְׂרָאֵל נוֹצְרָה עַתָּה, וּלְמַעֲנָם סָרָה מַלְכוּת מִצְרַיִם, וְכָל גּוֹיֵי הָעוֹלָם הֵבִינוּ זֹאת. שְׁנֵי מַעֲשִׂים נַעֲשׂוּ אָז; כָּל אֶחָד מֵהֶם גָּדוֹל מֵחֲבֵרוֹ: בְּקִיעַת הַיָּם וְאָבְדַן הַמִּצְרִים. בְּכָל אֶחָד מֵהֶם יֶשׁ פַּחַד גָּדוֹל וְעָצוּם. כָּל הָעַמִּים, כַּאֲשֶׁר שָׁמְעוּ אֶת הַדָּבָר הַזֶּה, חָרְדוּ וְיָרְאוּ וְאָמְרוּ בִּלְבָבָם: "עַתָּה שֶׁמִּצְרַיִם אָבְדָה, מַה יִּהְיֶה עִמָּנוּ?" כְּאִלּוּ אָמַר לָהֶם הָאֱמֶת: "הַמְתִּינוּ! אָמְנָם, דָּבָר גָּדוֹל מִזֶּה יֵעָשֶׂה לָכֶם. אִם כָּל כָּךְ נַעֲשָׂה לְמַעֲנָם, לְמַעַן בְּנֵיהֶם יֵעָשֶׂה יוֹתֵר מִזֶּה." הָעוֹלָם יִמָּלֵא עַרְעוּר כְּנֶגֶד הָאֱמֶת, וְיִרְגִּיזוּ אֶת הַצֶּדֶק בְּמַה שֶׁיַּעֲשׂוּ לוֹ. הָעוֹלָם יִזְעַק זְעָקָה אַחַת מִפְּנֵי הָרְשָׁעִים הַמַּרְבִּים בְּתוֹכוֹ, וּזְעָקָתָם תַּעֲלֶה לִפְנֵי אֱלֹהֵי מְעוֹן הַשָּׁמַיִם. יִשְׁמַע וְיִזְכֹּר, וְתִהְיֶה הַזְּעָקָה כִּזְעָקַת אֵלֶּה, מִתּוֹךְ הַדֹּחַק הַגָּדוֹל. אוֹי לַדּוֹר שֶׁתִּשָּׁמַע בְּקִרְבּוֹ הַזְּעָקָה הַזֹּאת, כִּי אוֹתוֹ הַדּוֹר עוֹמֵד בְּיִרְאָה מִפְּנֵי מַה שֶׁהוּא עָתִיד לִרְאוֹת. אוֹי לַמּוּמָר מִפְּנֵי מַה שֶּׁמּוּכָן לוֹ. אַשְׁרֵי הַנֶּאֱמָן מִפְּנֵי מַה שֶּׁנִּתָּן לוֹ מִן הַגְּמוּל. אוֹי לָרְשָׁעִים מִפְּנֵי מַה שֶׁיֻּכּוּ בוֹ, וְאַשְׁרֵי הַטּוֹבִים מִפְּנֵי מַה שֶּׁיְּשֻׁלְּמוּ לָהֶם. הַתָּאֵב יִגָּלֶה וִירוֹמֵם אֶת הָאֱמֶת. אֲדוֹנֵנוּ יֵרָאֶה וִירוֹמֵם אֶת חֲסִידָיו, אֲשֶׁר יָבוֹאוּ מֵאַרְבַּע כַּנְפוֹת הָעוֹלָם. אוֹי לְכָל יוֹשְׁבֵי הָאָרֶץ. בָּרוּךְ הַמֵּאִיר, אֲשֶׁר יֵאִיר אֶת הַטּוֹבִים וְיִגְלֶה כָּל טוֹב לְמַעֲנָם. בָּרוּךְ הַמֵּאִיר, אֲשֶׁר יְחַזֵּק בְּטוּבוֹ אֶת לִבּוֹת הַמֵּאִירִים לְדַעַת הָאֱמֶת.');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (91,'II','1a','על תהומי מעין עדן',2000012,'על תהומי מעין עדן חיי עולם נעמד בבוננו למשתי מן מימיו צמאים אנחנו למימי החיים והם לפנינו נהרים גדלים ברוך האלהים האל אשר הביא מיני הבוראים מבגלל האדם יקירה היא צורה על דמות אלהים צורת הלבב אין צורת התאר פלג מיני החיה לארבעה חולקים שלשה מבגלל החלק הרביעי מזה שם גויתו בחכמתו נציבה עד תהיה מלואה לאופעות הלבב לא יקום עד אחד באיש מזה נתן תורה תמימה לעבדיו חיים וארך ימים כי שם התורה בה תשק הנפש ועל פי הנפש ישק כל הבשר וכמה בנפש קמות אנוש בזה כן בתורה קמות הנפש תמידה כי לא על הלחם › לבדו ‹ יחיה האדם כי על כל מוצא פי יהוה יחיה האדם','By the depths of the Spring of Eden, everlasting life, let us stand with 
perception to drink of its waters. We thirst for the Waters of Life; they are before 
us (as) great rivers. Blessed be God, the God who created various creatures for 
the sake of man. Glorious is the Form in the likeness of God – the form of the 
mind, not the form of the body. He divided the kinds of living creatures into four 
species, three for the sake of the fourth species. Accordingly, He made his body 
implanted with His wisdom, so that it should be qualiﬁed to the illumination of 
the mind – A single witness may not validate against a person (Deut. 19:15). 
Therefore, He gave a perfect Law to His servants – life and longevity. Indeed, He 
made the Law by which the soul is maintained, and by the soul the body is di-
rected. And just as the existence of humans lies with the soul in this (world), 
thus the existence of the soul lies with the Law always – Man does not live by 
bread alone, but that man lives by everything that proceeds out of the mouth of the 
Lord (Deut. 8:3).','על ידי מעמקי מעיין עדן, מקור החיים הנצחיים, נעמוד בתבונה לשתות ממימיו. צמאים אנחנו למי החיים; הם לפנינו כנהרות גדולים. ברוך האל, האל שברא יצורים שונים למען האדם. נכבדה הצורה בדמות אלוהים – צורת השכל, לא צורת הגוף. חילק את מיני היצורים החיים לארבעה סוגים, שלושה למען הסוג הרביעי. לפיכך עשה את גופו שתול בחוכמתו, כדי שיהא ראוי לאור השכל – לא יקום עד אחד באיש לכל עוון (דברים יט,טו). לפיכך נתן תורה שלמה לעבדיו – חיים ואורך ימים. ואמנם עשה את התורה אשר על ידה מתקיימת הנשמה, ועל ידי הנשמה מונהה הגוף. וכשם שקיום האדם תלוי בנשמה בעולם הזה, כך קיום הנשמה תלוי בתורה לעולם – לא על הלחם לבדו יחיה האדם, כי על כל מוצא פי ה'' יחיה האדם (דברים ח,ג).');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (92,'II','7','על תהומי מעין עדן',2000071,'והששה פעמים אשר לארץ נספר אתם באזני כל עמה הראישון מטה משה פני משה היה נחש בה רז מודע כי פרעה בידו השני לפני פרעה היה תנין בלע המקילות ובו אימה ואוכחו השלישי היה כל עפר הארץ בכל ארץ מצר כנים לנקם ונפש הרביעי בהמת הארץ באת מן יער אל עיר לטרף הרשעים החמישי פחי הכבשן זרק אתו משה שחין פרח אבעבעות הששי ארץ ים סוף בלעת הרעים נטית ימינך תבלעמו הארץ הגדלות לך יהוה האל הגדול והגי והנורא אדכיר לטב עד לעלם } ל { נביה רבה משה דהושיע לקהל יה אשר לא קם כותה ולא יקום לעלם מה רב מעשיו דעשה עם שבטי הרצון ומה גלה מן אותת יהוה דשלחהו יהוה לעשות 8] [ ארבעה עשר פעמות המים אשר על ידו שרתו את כל צבאות יה הראש לקח ממימי היאר ושפך היבשה לעיני כל העם עד יאמנו וידעו כי כות זה ישתפך דם פרעה ועמו הגדלות לך יה שמר הברית והחסד כי גדול יה מכל האלהים השני הפך מי היאר דם לנקם כל המצרים ובמופת הזה עשרה מופתים בם אנשמה לעבדי יהוה ועד ידעו שנאיהם כי גדול יהוה מכל האלהים השלישי היו המים דבכל ארץ מצר לכל המצרים דם אדם וימלאו שבעת ימים לא יכלו לשתות מן מימיו והיו לעבראי מים חיים נפש המים לאלה נקם ולאלה חיים מוחים וטוב ורחמים כי גדול יהוה מכל האלהים הרביעי שב הדם למים אחרי שבעת ימים ושרץ צפרדע חדשים מן שעתם שרצו עלו גדודים גדו במקומות כל המצרים שרצים דלים עד מאד הך היה להם בינה מבדילים במשפט צדק בין אהבים ובין איבים בם כנעו כל הגבורים כי גדול יהוה מכל האלהים החמישי המטיר ברד ועמו נתן קולות ותהלך אש ארצה ואמיר כי היתה האש נכונה בתוך הברד ומי הברד בה סוביב ואמיר כי היתה ביני הברד על ארץ מצרים לפידים מן אש מוקדים בין מטר הברד היכולה לעשה כל זאת כי גדול יהוה מכל האלהים הששי נבקע מי ים סוף כאשר ראה ים נביותה על פי יה אלה ואשתוי בגוה שביל נכונה לצבאות יהוה מופת לא היה כמהו ולא יהיה עד לעלם כי גדול יהוה מכל האלהים השביעי אתקמת חומה פני המים ההלכים עד הנצבו כמו נד רם נערמו למעלה לשמר דרך ישראל עד יעבר בה בשלם כי גד י מ ה השמיני הפך יבש וישם את הים לחרבה הך לא היה בו מים הלך מיום בוראות בוראיה עד לא ינכה ישראל בהלכתו בתוכו לאלהינו נתן גדלות כי גדול יהוה מכל האלהים התשיעי אתחלפת תשבית כל המים בים סוף היו יעלו עד מאד מלמטה עד מעלה כי תשבית המים מלמעלה עד מטה והמים הרדים עמדו שורים לשמר השבטים ברוך אדון הגדלות כי גדול יהוה מכל האלהים העשירי המים בעת ההיא הוקם שופט צדק שפט בין צדיק ורשע והפך הרשע לפניו וקטלו במיני המכות ופרק הצדיק ממנו והבדיל בין זה ובין זה בפי יהוה הגדול כי גדול יהוה מכל האלהים האחד עשר כד צאו ממו עבדי יהוה ומצרים נסעים לקראתו ואסר אפן מרכבתו הפך חומות פניהם עד פשר ראשם באסור דרשו הרוח ולא מצאו שם כלם ידעו כי גדול יהוה מכל האלהים השנים עשר הים שב לאיתנו לפני פרעה וכל עבדיו וכלם חיים יראו ולית להם רחב לרוח ונשאם יהוה ברוח עד ראו בני ישראל שלומים על שפת הים ואחרי זה צללו כמו אבן כי גדול יהוה מכל האלהים השלש עשר נשמע קולו מכל הפאתים שעתה דהלכו המים עד שמעו העמים ובזה הודע נביה רבה משה בנביותו בקצת אז ישר הדבר למי ישמע מודע כי גדול יהוה מכל האלהים הרביעי עשר נסגר הים על פרעה ועל כל עמו לא נשאר בהם עד אחד וכל , ישראל צאו שלומים מלכים בתר הוו עבדים שמחים בפדיונים מרוממין לאלה אבהתון אלה דאברהם ויצ ויעקב ויאמנו ביהוה ובמשה עבדו אלה השלשה והשלשים אשר שרתו ישראל ואמיתו כל המצרים','As for the six events concerning the earth, we shall narrate them in the 
presence of the whole people. The ﬁrst: Moses’ rod. In front of Moses it became a 
snake, a secret sign that Pharaoh was in his hand. The second: In front of 
Pharaoh it was a serpent that swallowed the (sorcerers’) rods, and in it were 
terror and reproof. The third: All the dust of the earth throughout the land of 
Egypt became gnats, for revenge and relief. The fourth: The beast of the earth 
came from the forest to the city to prey on the wicked. The ﬁfh: Moses threw up 
ashes of the kiln, which became boils breaking out in sores (Exod. 9:9). The sixth: 
The earth of the Sea of Reeds swallowed the wicked – You stretched Your right 
hand, the earth swallowed them (Exod. 15:12). Exaltation to You, the great, the 
mighty, and the awesome God (Deut. 10:17). Blessed be forever the memory of the 
great prophet Moses, who delivered the congregation of the Lord. Like him none 
has arisen and will never arise. How great the deeds he performed for the tribes 
of the Divine Favor, and that he revealed from the Lord’s wonders; the wonders 
that the Lord sent him to do.','באשר לשישה אירועים הנוגעים לארץ, נספר אותם בפני כל העם. הראשון: מטה משה. לפני משה נהפך לנחש, אות סתר לכך שפרעה היה בידו. השני: לפני פרעה היה לתנין שבלע את מטות (המכשפים), ובו היו אימה ותוכחה. השלישי: כל עפר הארץ בכל ארץ מצרים נהפך לכינים, לנקמה ולהקלה. הרביעי: חיית הארץ יצאה מן היער אל העיר לטרוף את הרשעים. החמישי: משה זרק פיח הכבשן, שנהפך לשחין פורח בבועות (שמות ט,ט). השישי: ארץ ים סוף בלעה את הרשעים – נטית ימינך תבלעמו ארץ (שמות טו,יב). הוד לך, האל הגדול, הגיבור והנורא (דברים י,יז). ברוך לעולם זכרו של הנביא הגדול משה, אשר הציל את עדת ה''. כמוהו לא קם ולא יקום לעולם. כמה גדולים המעשים שעשה לשבטי החן האלוהי, ואשר גילה מנפלאות ה''; הנפלאות אשר שלחו ה'' לעשותן.');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (93,'II','48','על תהומי מעין עדן',2000481,'יאות מעמי נביה רבה משה קעום על ים סוף משרי ואמר מכון לשבתך משכנה קדישה מכון לשבתך מלאכי קדשך לא ימושו בו לא אתחזי משכן אלא עליו לא חג אלא עליו לא קרבן אלא בה לא נדר אלא לידה לא תרומה אלא לותה לא מעשר אלא בה לא נדבה אלא בה לא סגדה אלא קבלה ולא תתקבל ברכה בטבר לבר מנה לעלם אקים לה בטור סיני שבעה תחומין בעבר הירדן אחרי דרך מבוא השמש בארץ הכנעני הישב בערבה מול הגלגל אצל אל מורא מול שכם אה שבעה סהדים לית מתעלם עליהון וכל אחד מנון מסיד בקשטה','It is appropriate that we see the great prophet Moses, standing by the 
Sea of Reeds and starting by saying: a place for Your abode (Exod. 15:17) – the 
holy sanctuary. A place for Your abode – the holy angels will not depart from it. 
No (divine) abode was revealed except on it. There is no sacriﬁce except on it, no 
vow except by it, no gif-oﬀering except at it, no tithe except at it, no freewill of-
fering except on it, no worship except facing it, and no blessing received on any 
mountain except it, ever. On Mount Sinai He established seven speciﬁcations: (1) 
beyond the Jordan, (2) past the west road, (3) in the land of the Canaanites, (4) 
who live in the Arabah, (5) over against Gilgal, (6) beside the oak of Mura, (7) over 
against Shekhem (Deut. 11:30). Behold, seven witnesses, whom nobody ignores, 
and each of them testiﬁes in truth.','ראוי הוא שנביט אל הנביא הגדול משה, עומד על ים סוף ופותח באומרו: מָכוֹן לְשִׁבְתְּךָ (שמות טו,יז) – המקדש הקדוש. מכון לשבתך – מלאכי הקודש לא יסורו ממנו לעולם. לא נגלה כל מושב אלוהי אלא עליו. אין קרבן אלא בו, אין נדר אלא על ידו, אין תרומה אלא בו, אין מעשר אלא בו, אין נדבה אלא עליו, אין עבודה אלא כנגדו, ואין ברכה המתקבלת על שום הר זולתו, לעולם. בהר סיני קבע שבע הגדרות: (1) בְּעֵבֶר הַיַּרְדֵּן, (2) אַחֲרֵי דֶּרֶךְ מְבוֹא הַשֶּׁמֶשׁ, (3) בְּאֶרֶץ הַכְּנַעֲנִי, (4) הַיֹּשֵׁב בָּעֲרָבָה, (5) מוּל הַגִּלְגָּל, (6) אֵצֶל אֵלוֹנֵי מֹרֶה, (7) מוּל שְׁכֶם (דברים יא,ל). הרי שבעה עדים, שאיש אינו מתעלם מהם, וכל אחד מהם מעיד באמת.');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (94,'II','5','על תהומי מעין עדן',2000051,'האקרים שלשה ושלשים פעמים נצרו לאהבים וצררו איבים אש הכבוד דגלה למשה בסנה מבגלל פדיון השבטים ואש הברד אשר אתלקחת שם רחמים לעבראי ונקם למצראי והאש אשר שרת בין גללי ים סוף ואכלת דבבי אלה וישראל אלה השלשה הפעמים אשר שרתת אש יהוה לעבדיו','The elements thirty three times guarded the friends and oppressed the 
foes. The ﬁre of the Glory which was revealed to Moses in the bush for the re-
demption of the tribes, and the ﬁre of the hail which ﬂashed there (to be) mercy 
for the Hebrews and revenge for the Egyptians, and the ﬁre that appeared among 
the waves of the Sea of Reeds which consumed the enemies of God and of Israel 
– these are the three times that the ﬁre of the Lord served His servants.','היסודות שמרו על הידידים ולחצו על האויבים שלושים ושלוש פעמים. אש הכבוד שנגלתה למשה בסנה לגאולת השבטים, ואש הברד שבזקה שם – רחמים לעברים ונקמה למצרים – והאש שנראתה בין גלי ים סוף ואשר אכלה את אויבי הא-ל וישראל – אלו הן שלוש הפעמים שבהן אש ה'' שירתה את עבדיו.');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (95,'II','40','על תהומי מעין עדן',2000401,'נמלי לבבינן נהירו בקשט עד נהי ממי חכמו לקשטה מה רבה רבותך ישראל במה עבד לך מרך גלה כל סימן חיול בדילך ירום נביה רבה משה דחכם מד בה › א ‹ יקר לדריה גלגי נביה רבה משה נתני מן קרב לאלה הך משה אי שמע מנה מד שמע משה אי קעם האן דקעם אי עמה מה דעמה אי אתימן מה דאתימן משה אי בלש ואמטה אי אמר ועביד לה אי אכלל מדעה בנהירו ועוד צלמה לבשה מאור חיול ואתעבד כרי לסימניה ופתח כל ברכה מן עבד לה מרה דעלמה מה עבד למשה כסיאתה לה נפשו גליאתה בה חדו בוראיה לה אוקרו שומיה למליו אציתו ארעה לאמיראתה ארכנת ולה לא עצת אהן הך משה ומן מדמי › ל ‹ משה נביה לא הוה כותה ולא יהי האן הך משה ומן מדמי למשה נביה לא קעם כותה ולא › י ‹ קום עד לעלם גלגיו מן ימטי נביותה מן ישום נהימן ביהוה ובמשה עבדו עד ננשם הנה וגם שם שלום יהוה עליו לו לגו הדה שירתה עשרה נביאות עד יעבר עמך יה נחל ארנן עד יעבר עם זה קנית את ירדנה תביא ותטעמו בהר נחלתך בסרה טבה מחדיה לכל טביה 44] [ שמע כדו ממלל יוסף במדעך נהירו רבה ויצר יהוה אלה את האדם עפר מן 8° האדמה מן עפרה טבה דמן טורה טבה וביתה דאדם מתרבי ביד קשטה דו דמע מכל בוראיה וכל דמע אמסיר לקדשה לית לפגול לגוה נמי כל דמע דידמע באדי אנשים על שמה קדשה מתחיל ומתיקר וכן גויתה דאדם דמע מכל בורא מכן לא אתנסבת אלא מאשר אתקדם טורה טבה דמע מכל טוריה מן ריש בראשית עבדה נצובה וכן יעקב עורי חכם בקדושה הך מד מרן חכם בקדישות שבתה אין זה כי אם בית אלהים וכן אמר מרן ויברך אלהים','Let us ﬁll our hearts with true understanding, so that we may be among 
those who know the truth. How great is your glory, O Israel, because of what 
your Master did for you. He revealed every mighty sign on your behalf. Exalted 
be the great prophet Moses who taught (things) that contain glory for the genera-
tions. Let us tell praises of the great prophet Moses. Who approached God like 
Moses, or heard from Him what Moses heard, or stood where he stood, or saw 
what he saw, or was appointed with what Moses was appointed, or sought and 
attained, or spoke and it was done for him, or (whose) mind was adorned with 
wisdom? Moreover, his face wore a mighty light, and he became a source of 
signs and a gate of every blessing. To whom did the Master of the world do what 
He did to Moses? The Concealed made room for him, the Overt rejoiced in him, 
the creatures gloriﬁed him, heavens hearkened to his words, and the earth 
bowed down to his commands and did not rebel. Was there anybody like Moses, 
and who resembles Moses the prophet, like whom none has arisen and will 
never arise? Who can praise him fully? His prophethood – who can evaluate it? 
Let us believe in the Lord and in His servant Moses, so that we may receive peace 
here and there too. God’s peace over him. He has ten prophecies in this song: Till 
Your people cross over, O Lord (Exod. 15:16) – the river Arnon; till Your people 
cross whom You have ransomed (Exod. 15:16) – the river Jordan. You will bring 
them and plant them on the mountain in Your possession (Exod. 15:17) – good tid-
ings that gladden all the good ones.','נְמַלֵּא אֶת לְבָבֵנוּ בְּתְּבוּנָה אֲמִתִּית, לְמַעַן נִהְיֶה מִן הַיּוֹדְעִים אֶת הָאֱמֶת. כַּמָּה גָּדוֹל כְּבוֹדְךָ, יִשְׂרָאֵל, בִּגְלַל מַה שֶּׁעָשָׂה לְךָ אֲדוֹנֶיךָ. גִּלָּה עָלֶיךָ כָּל אוֹת וָמוֹפֵת. יִתְרוֹמֵם הַנָּבִיא הַגָּדוֹל מֹשֶׁה, שֶׁלִּמֵּד דְּבָרִים שֶׁיֵּשׁ בָּהֶם כָּבוֹד לַדּוֹרוֹת. נְסַפֵּר תְּהִלּוֹת הַנָּבִיא הַגָּדוֹל מֹשֶׁה. מִי קָרַב אֶל הָאֵל כְּמֹשֶׁה, אוֹ שָׁמַע מִמֶּנּוּ מַה שֶּׁשָּׁמַע מֹשֶׁה, אוֹ עָמַד בַּמָּקוֹם שֶׁעָמַד בּוֹ, אוֹ רָאָה מַה שֶּׁרָאָה, אוֹ נִתְמַנָּה בְּמַה שֶּׁנִּתְמַנָּה מֹשֶׁה, אוֹ בִּקֵּשׁ וְהִשִּׂיג, אוֹ דִּבֵּר וְנַעֲשָׂה לוֹ, אוֹ אֲשֶׁר לִבּוֹ הָיָה מְעֻטָּר בְּחָכְמָה? וְעוֹד, פָּנָיו לָבְשׁוּ אוֹר עָצוּם, וְנַעֲשָׂה מְקוֹר אוֹתוֹת וְשַׁעַר לְכָל בְּרָכָה. לְמִי עָשָׂה אֲדוֹן הָעוֹלָם מַה שֶּׁעָשָׂה לְמֹשֶׁה? הַנִּסְתָּר עָשָׂה לוֹ מָקוֹם, הַגָּלוּי שָׂמַח בּוֹ, הַבְּרִיּוֹת כִּבְּדוּהוּ, שָׁמַיִם הִקְשִׁיבוּ לִדְבָרָיו, וְהָאָרֶץ כָּרְעָה לְפִקּוּדָיו וְלֹא מָרָדָה. הֲהָיָה אִישׁ כְּמֹשֶׁה, וּמִי דּוֹמֶה לְמֹשֶׁה הַנָּבִיא, אֲשֶׁר כָּמוֹהוּ לֹא קָם וְלֹא יָקוּם לְעוֹלָם? מִי יוּכַל לְהַלְּלוֹ כָּרָאוּי? נְבוּאָתוֹ – מִי יוּכַל לְשַׁעֲרָהּ? נַאֲמִין בַּה'' וּבְעַבְדּוֹ מֹשֶׁה, לְמַעַן נְקַבֵּל שָׁלוֹם כָּאן וְגַם שָׁם. שְׁלוֹם הָאֵל עָלָיו. יֵשׁ לוֹ עֶשֶׂר נְבוּאוֹת בַּשִּׁירָה הַזֹּאת: עַד יַעֲבֹר עַמְּךָ ה'' (שמות טו,טז) – נַחַל אַרְנוֹן; עַד יַעֲבֹר עַם זוּ קָנִיתָ (שמות טו,טז) – נְהַר הַיַּרְדֵּן. תְּבִאֵמוֹ וְתִטָּעֵמוֹ בְּהַר נַחֲלָתְךָ (שמות טו,יז) – בְּשׂוֹרוֹת טוֹבוֹת הַמְּשַׂמְּחוֹת אֶת כָּל הַטּוֹבִים.');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (96,'II','45','על תהומי מעין עדן',2000451,'שבעה דמעין אנון בעלמה קשטה בחרון ועבדון לאלהותה אורה ושבתה וטורה ואדם ולוחיה ומשה וישראל אורה מן אשתה כי אשתה ארש כלה בה מפרנס ובה מתקומם ולוחיה מן דאלהו חלצון בחילה מן האן דלא הוו ושבתה דמע מלבין כל יומיה דאפרשה מרן לאלהו › ת ‹ ה מיסתה ואדם עורי דמע מדו ארש טב מנה קם בעלמה נביאם וזכאים וטורה טבה דמע מקדש בחרה מרה משריו לכבודו ומשה דמע מרבי כל דמע דכותה לא קעם ולא יקום לעלם וישראל דמע מלבין כל אמיה דמרה בחר בה ועבדה סגולה וכן כתב קשטה בדיל חנוך ויתהלך חנוך את האלהים חכם אתרה דקשטה ורחט לידה הך מד רחט אברהם בזבן דזדעק אמיר לאברהם אל הארץ אשר הראך מהוא דאריה אלא טורה טבה וכן בזבן נסיונה כד בלש ליצחק למגלי קדושה לארע מחזיה טובה וברכה חכמה אברהם וזרז לידה','There are seven choicest (things) in the world, which the True One chose 
and appointed to his Divinity: the Light, the Sabbath, the Mountain, Adam, the 
Tablets, Moses, and Israel. The Light is (the choicest) of ﬁre, for the ﬁre is a 
fundament; everything is maintained by it and exists by it. The Tablets are (the 
choicest) of the divine – He extracted them with His might from where they were 
not. The Sabbath is the choicest of all days, which our Master set apart for His 
divinity alone. Adam too is among the choicest, since he is a good fundament 
from which arose in the world prophets and righteous people. The Good Moun-
tain is the choicest sanctuary; God has chosen it as dwelling for His Glory. Moses 
is the choicest of those who praise the choicest; like him none has arisen and 
will never arise. Israel is the choicest of all the nations, for their master has 
chosen and made them treasure. Thus wrote the True One about Enoch: Enoch 
walked with God (Gen. 5:22). He knew the place of the True One and rushed to it, 
just as Abraham rushed when he was summoned. It had been said to him: to the 
land which I shall show you (Gen. 12:10). What was he shown by Him, if not the 
Good Mountain? And again, at the time of his trial, when He asked for Isaac to 
reveal His holiness to the land of Moriyya (Gen. 22:2) – good and blessed, 
Abraham knew it and rushed to it.','יֵשׁ שִׁבְעָה נִבְחָרִים בָּעוֹלָם, אֲשֶׁר בָּחַר בָּהֶם הָאֱמֶת וְיִחֲדָם לֶאֱלֹהוּתוֹ: הָאוֹר, הַשַּׁבָּת, הָהָר, אָדָם, הַלּוּחוֹת, מֹשֶׁה וְיִשְׂרָאֵל. הָאוֹר הוּא נִבְחַר הָאֵשׁ, כִּי הָאֵשׁ הִיא יְסוֹד; הַכֹּל נִשְׁמָר בָּהּ וְקַיָּם בָּהּ. הַלּוּחוֹת הֵן נִבְחַר הָאֱלֹהִי – הוֹצִיאָן בְּגְבוּרָתוֹ מִמְּקוֹם שֶׁלֹּא הָיוּ בוֹ. הַשַּׁבָּת הִיא נִבְחֶרֶת כָּל הַיָּמִים, אֲשֶׁר יִחֲדָהּ אֲדוֹנֵנוּ לֶאֱלֹהוּתוֹ בִּלְבַד. אָדָם אַף הוּא מִן הַנִּבְחָרִים, כִּי הוּא יְסוֹד טוֹב אֲשֶׁר קָמוּ מִמֶּנּוּ בָּעוֹלָם נְבִיאִים וְצַדִּיקִים. הָהָר הַטּוֹב הוּא מִקְדָּשׁ הַנִּבְחָרִים; בָּחַר בּוֹ הָאֵל לִמְשַׁכַּן כְּבוֹדוֹ. מֹשֶׁה הוּא הַנִּבְחָר מִן הַמְהַלְּלִים אֶת הַנִּבְחָרִים; כָּמוֹהוּ לֹא קָם וְלֹא יָקוּם לְעוֹלָם. יִשְׂרָאֵל הוּא הַנִּבְחָר מִכָּל הָאֻמּוֹת, כִּי אֲדוֹנָם בָּחַר בָּהֶם וַעֲשָׂאָם סְגֻלָּה. כֵּן כָּתַב הָאֱמֶת עַל חֲנוֹךְ: וַיִּתְהַלֵּךְ חֲנוֹךְ אֶת הָאֱלֹהִים (בראשית ה,כב). הוּא יָדַע אֶת מְקוֹם הָאֱמֶת וְמִהַר אֵלָיו, כְּשֵׁם שֶׁמִּהַר אַבְרָהָם כְּשֶׁנִּקְרָא. נֶאֱמַר לוֹ: אֶל הָאָרֶץ אֲשֶׁר אַרְאֶךָּ (בראשית יב,י). מֶה הֶרְאָהוּ, אִם לֹא הָהָר הַטּוֹב? וְשׁוּב, בְּשָׁעַת נִסְיוֹנוֹ, כַּאֲשֶׁר בִּקֵּשׁ אֶת יִצְחָק לְגַלּוֹת אֶת קְדֻשָּׁתוֹ לְאֶרֶץ הַמֹּרִיָּה (בראשית כב,ב) – הַטּוֹבָה וְהַמְבֹרֶכֶת – יָדַע אַבְרָהָם אוֹתָהּ וּמִהַר אֵלֶיהָ.');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (97,'II','19','על תהומי מעין עדן',2000191,'[ יתוב רב ע ] ד [ מותר יתוב מש ] ה ובני י [ שראל ] בשירה ה [ זאת ] על ים [ סוף ] היה משה עמ [ ד על הים ופניו מתפני אל הרגריזים בית אל וכל הזקנים אחריו עמדים › ו ‹ אחרי הזקנים כל בני ישראל ומשה נביה ישיר השירה חלק חלק וכאשר יכלה מכל חלק ידאם והזקנים יענו במימר אשירו ליהוה כי גוי גאה סוס ורכ רמה בים וכל ישראל יענו יחדו עזי וזמרתי ויהי לי ליש עד יה גיבור במל יה שמ ] ו [ וידמו ומשה יחל בשי ] רה [ כן היתה מרים הנביא ] ה [ תאמר אשירו ליהו › ו ‹ הנשים יאמרו עם בני ישראל עזי וזמרתי עד תם הד ] ה [ כי גוי ] נב [ ר ] פ [ רעה ] ור [ כבו דרמת גהותם על בני עבראי סוס ורכבו רמה בים','An exceedingly great arrangement is the arrangement of Moses and the 
people of Israel (when singing) this Song by the Sea of Reeds. Moses was stand-
ing by the sea, his face turned towards Mount Gerizim; Beth El, and all the El-
ders were standing behind him; behind the Elders all the people of Israel. And 
the prophet Moses sang the Song, section afer section. When he ﬁnished each 
section he was silent, and the Elders responded with the verse Sing to the Lord, 
for over a people He has triumphed, horse and its rider He has hurled into the sea 
(Exod. 15:1), and all Israel responded together (the Lord) is my strength and 
praise; He is become my deliverance (Exod. 15:2), up to The Lord is a man of war; 
the Lord is his name. (Exod. 15:3) – and (then) they were silent, and Moses began 
the Song. Likewise Miriam the prophetess was saying Sing to the Lord (Exod. 
15:21), and the women were saying with the people of Israel: (The Lord) is my 
strength and praise, up to its end. For “a proud people” (means) Pharaoh and his 
riders, whose arrogance increased over the sons of the Hebrews. Horse and rider 
He has hurled into the sea!','סדר נפלא ביותר הוא סדרם של משה ועם ישראל בשירה זו על ים סוף. משה עמד על שפת הים, פניו מופנות אל הר גריזים; בית אל, וכל הזקנים עמדו אחריו; ואחרי הזקנים כל עם ישראל. והנביא משה שר את השירה, פרשה אחר פרשה. כשסיים כל פרשה שתק, והזקנים ענו בפסוק "אשירה לה'' כי גאה גאה סוס ורכבו רמה בים" (שמות טו,א), וכל ישראל ענו יחד "עזי וזמרת יה ויהי לי לישועה" (שמות טו,ב), עד "ה'' איש מלחמה ה'' שמו" (שמות טו,ג) – ואז שתקו, ומשה חזר והחל את השירה. כמו כן מרים הנביאה אמרה "שירו לה''" (שמות טו,כא), והנשים אמרו עם עם ישראל: "עזי וזמרת יה" עד סופו. שכן "עם גאה" הם פרעה ורוכביו, שגאוותם גברה על בני העברים. סוס ורכבו רמה בים!');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (98,'II','38','על תהומי מעין עדן',2000381,'תפך האלהים אמנות העולם בגלל › ישראל בכל ‹ המקומות אלופת מיה ידרש את מנוח ] ו [ ובים סוף שם אתו י ] ע [ לה מעלה כי נערמו המים נצבו נד נאזלים כמו ההרים הגבחים ולהכין דרך בגלל לכתם בשלם אמר אויב ארדף אשיג אחלק שלל את כל המקנה והרכוש מזה אתידע רב גברות פרעה מלך מצרים כי אין אויב יקח את שלל אויביו } ו {» א « לא מבתר דיקטלה ופרעה אמר כי יהרג אתם מבתר דיקח כל שללם נשבת ברוחך רוח האף וחמה כסהמו ים במעזרה לות עמקה ודמה יתון להעופרת כי הוא ירד במהרה וישרף במהרה במים האדירים הם המים הרבים לא יכלו טפים לנורה דאכלת יתון מי כמוך באילים יהוה מי כמוך אה עשה כל המאומות ומאום לא ידמי לך מי כמוך נאדרי בקדש עשה משפט צדק קדוש ונקיא מכל אשר יאמרו הכפורים נורא תהלת עשה פליה לו שמהת קדושים ועקובהן גדלים לית לעורן בה נמי עשה פליה ארבעים מופת במצרים ובים סוף וכל מעשיו נפלאות רבות נטית ימינך תבלעמו הארץ שני פלג } י { ים בה בדבר הזה הראש נבקעת ארץ הים ובלעת פרעה ורכבו ופרשיו והשני אמיר כי כאשר מתו מצראי הוציא אתם הים אל שפתו מכן אמר וירא ישראל את מצרים מת על שפת הים וכאשר , ראו אתם מיתים › נ ‹ בקעת שפת הים ובלעת יתון ויתפלל משה בעד ישראל עד ינחלם אל הרגריזים','God reversed the order of the world for the sake of Israel. In every place 
the water’s habit is to seek its rest (downwards) but in the Sea of Reeds He made 
it go upwards, for the waters piled up, they stood straight like a ﬂowing wall 
(Exod. 15:8) – like the high mountains, to prepare a pathway for their walk in 
safety. [The enemy said: I will pursue, I will overtake, I will divide spoil (Exod. 
15:9) – all the cattle and the wealth. Hence the great might of Pharaoh, king of 
Egypt, became known since no enemy seizes the plunder of his foes unless afer 
he kills him; and Pharaoh said he would kill them afer seizing all their plunder. 
You made your wind blow (Exod. 15:10) – the wind of anger and wrath – the sea 
covered them (ibid.) on its return to its strength. He compared them with lead, 
for it sinks quickly and is burnt quickly. In mighty water (Exod. 15:10.) – these are 
the great waters which could not extinguish the ﬁre which consumed them. Who 
is like You among gods, O Lord? (Exod. 15:11) Who is like You, O maker of all 
things? Nothing resembles You. Who is like You, majestic in holiness (Exod. 15:11) 
– who judges justly. Holy and blameless of anything that the unbelievers say. 
Awesome in splendor doing wonders (Exod. 15:11) – He has holy names and great 
surnames, no other has a share (in them). Doing wonders – forty wonders in 
Egypt and by the Sea of Reeds. All His deeds are mighty wonders. You stretched 
Your right hand the earth swallowed them (Exod. 15:12). There are two parts in 
this matter. The ﬁrst one: the sea bed was split and swallowed Pharaoh and his 
chariots and his horsemen. The second one: it is said that when the Egyptians 
died, the sea cast them on the shore. Therefore he said: Israel saw the Egyptians ] 
dead on the shore of the sea (Exod. 14:30). And when they saw them dead, the 
sea shore split (again) and swallowed them. And Moses prayed for Israel, that 
(God) may lead them to Mount Gerizim.','אלוהים הפך את סדר העולם למען ישראל. בכל מקום דרך המים לבקש את מנוחתם כלפי מטה, אך בים סוף עשה אותם עולים כלפי מעלה, שכן "נערמו מים עמדו כמו נד" (שמות טו,ח) – כהרים גבוהים, לפנות דרך להם ללכת בבטחה. האויב אמר: "ארדוף אשיג אחלק שלל" (שמות טו,ט) – את כל הבקר ואת כל העושר. ומכאן נודעה גדולתו של פרעה מלך מצרים, שכן שום אויב אינו לוקח את שלל אויביו אלא לאחר שהרגם; ופרעה אמר שיהרגם לאחר שיחרים את כל שללם. "נשפת ברוחך" (שמות טו,י) – רוח הזעם והחמה – "כסמו ים" (שם) בשובו לעוצמתו. המשיל אותם לעופרת, שכן היא שוקעת במהרה ונשרפת במהרה. "במים אדירים" (שמות טו,י) – אלה הם המים הגדולים שלא יכלו לכבות את האש שאכלה אותם. "מי כמכה באלים ה''" (שמות טו,יא) – מי כמוך, עושה הכל? אין דבר הדומה לך. "מי כמכה נאדר בקודש" (שמות טו,יא) – שדן בצדק. קדוש ונקי מכל אשר יאמרו הכופרים. "נורא תהלות עושה פלא" (שמות טו,יא) – לו שמות קדושים ותארים גדולים, ואין לאחר חלק בהם. "עושה פלא" – ארבעים נפלאות במצרים ועל שפת ים סוף. כל מעשיו הם נפלאות עוצמה. "נטית ימינך תבלעמו ארץ" (שמות טו,יב). יש שני פנים לעניין זה: האחד – קרקעית הים נבקעה ובלעה את פרעה ואת מרכבותיו ואת פרשיו. השני – נאמר שכאשר מתו המצרים, השליך אותם הים אל החוף. לפיכך אמר: "וירא ישראל את מצרים מת על שפת הים" (שמות יד,ל). וכשראו אותם מתים, נבקע שפת הים שוב ובלעם. ומשה התפלל למען ישראל, שיוביל אותם אל הר גריזים.');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (99,'II','28','על תהומי מעין עדן',2000281,'הזדבגת מיה ואשתה כחדה לאבדן בישיה וכן אמר נביה רבה משה בכתבה תשגר תקופך יסיפון כקסה הדה מעמי חיול יתיר אשתה ומיה כחדה גבורת מיה אנדנד ] ת [ וגבורת אשת ] ה [ אתגברת ואש ] וו [ תריון ברב ] ו [ רבה למוקר ישראל רבות צורתה דאדם תמן הגלת דמיה ואשתה ] ל [ גוה ] א [ צטמתו ] אדם [ אגבל ] מן עפרה ואשתה ר [ מה ] בה חיל וחכמה …[ מלא עלמה תשבחן למרה ישתבח נהירה דהנאר לבביה בחכמת קשטה וברבין אימנו נהימן באלהותה ונזע מן גאותה ונסיד ונימר לית אלה אלא אחד','The water and the ﬁre coupled together for the destruction of the 
wicked. Thus said the great prophet Moses in his book: You send forth Your fury, 
it consumes them like straw (Exod. 15:7). This is an exceedingly powerful vision: 
the ﬁre and the water together. The power of the water was weakened, and the 
power of the ﬁre gathered strength. Both become equal in great glory, to exalt 
Israel. The greatness of the form of Adam was revealed there, since the water 
and the ﬁre were conjoined in him. Adam was kneaded from the dust [and the 
ﬁre planted in him strength and wisdom.] The world is full of praises to the 
Master. Praised be the Enlightened One who illuminated the hearts with true 
wisdom and with great faith. Let us believe in His divinity and fear His highness, 
and testify saying “There is no god but One.”','המים והאש התחברו יחד לאבדן הרשעים. כך אמר משה הנביא הגדול בספרו: "תשלח חרונך יאכלמו כקש" (שמות טו,ז). זוהי חזון עוצמתי ביותר: האש והמים יחדיו. כוח המים נחלש, וכוח האש התגבר. שניהם נעשו שווים בכבוד גדול, להרים את ישראל. גדולת דמותו של אדם נגלתה שם, שכן המים והאש היו שזורים בו. אדם נלוש מן העפר, והאש שתלה בו עוז וחכמה. העולם מלא שבחים לאדון. ברוך המאיר שהאיר את הלבבות בחכמה אמיתית ובאמונה גדולה. נאמין באלוהותו ונירא את רוממותו, ונעיד לאמור: "אין אלוה אלא אחד."');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (100,'II','49','על תהומי מעין עדן',2000491,'יהוה כוננו ידך ומה הו אתרה אלא משכן לקדשה וכן אמר ושכנתי בתוך בני ישר שמה ידור ומה יריחה יתעבד ואף עזר ממללה ואמר ועבדו לי משכן ואשרי בגוכון משכן בלא קרבן מה הנאה בה קרבן דלא ריחו מה הנאה בה לכן אמר נביה רבה משה יהוה כוננו ידך יד יהוה עליו תתפרס נרבי למרן בכל זבן ונשבח לגדלה בכל אתר ונרומם לשמה בכל זבן ועדן ונהימן בנביה דאנדה לנן סוברה לחייה ואזהרן מן מותה ואלפן שביל קשטה וילן במה › חסכנן ‹ מן איקרה דבה יקרן מרן מן סגאי חובינן דעבדנן כל אהן שרי בנן משכנה חסכנן לא קרבן ולא עלה ולא מנחה ולא חטאת ולא שלמים ולא פתור מערך ולא מנורת מאור ולא קטרת ולא שכינה ולא ברכה ולא סליחות ולא כהן יכפר ולא אנש יאחס עלינן אלו עזרנן ליד מרן ובלשנן לטובה ושמרנן תורת משה ואלפנן מה דאלפן ושבחנן כאדם והטיבנן כהבל וקרינן כאנוש והלכנן כחנוך ואזדכינן כנח ואשתעבדנן כאבר ואנצרנן כיצ והדכינן כיע וערקנן כיו וקעמנן עם משה דהוה אהרן מברך עלינן ואלעזר מסלח בדילן ופינחס מפדי לן ואלהים צפי לן ברחמיו','(With) Your hand establish it (SP Exod. 15:17). What is this place if not an 
abode for His sanctity? For thus He spoke: I will abide among the people of Israel 
(Exod. 29:45). There He will abide, and what pleases Him will be done. Moreover, 
He repeated His words and said: “Make Me a sanctuary that I may dwell among 
you (Exod. 25:8).” Of what beneﬁt is a sanctuary without an oﬀering? Of what 
beneﬁt is an oﬀering without pleasing (odor)? Therefore the great prophet Moses 
said: “O Lord, (with) Your hand establish (Exod. 15:17).” The hand of God will be 
stretched out over it. Let us exalt our Master at all times, and praise His great-
ness everywhere, and magnify His name at every time and epoch, and believe in 
the prophet who brought to us hope of life, and warned us away from death, and 
taught us the path of the truth. Woe to us for we lack the honor with which our 
master honored us. Because of the many sins that we committed all this rests on 
us: we lack the sanctuary; we have no oﬀering, no burnt-oﬀering, no gif-
oﬀering, no sin-oﬀering, no sacriﬁces for well-being, no table set, no lampstand 
for lighting, no incense, no Divine Presence, no blessing, no forgiveness; and 
nobody shows us pity. Had we returned to our Master, and sought His goodness, 
and kept the law of Moses, and learnt what he taught us, and praised like Adam, 
and done good like Abel, and invoked (His name) like Enosh, and walked like 
Enoch, and submitted ourselves like Abraham, and been devoted like Isaac, and 
been innocent like Jacob, and ﬂed like Joseph, and stood with Moses – Aaron 
would bless us, Eleazar would purify us, Phinehas would redeem us, and God 
would look upon us in His mercy.','יְכוֹנְנֶהָ יָדֶיךָ (שמות טו,יז נוסח שומרון). מהו המקום הזה אם לא מושב קדושתו? כי כך אמר: וְשָׁכַנְתִּי בְּתוֹךְ בְּנֵי יִשְׂרָאֵל (שמות כט,מה). שם ישכון, ויֵעשה מה שחפץ בו. ועוד שב ואמר: "וְעָשׂוּ לִי מִקְדָּשׁ וְשָׁכַנְתִּי בְּתוֹכָם (שמות כה,ח)." מה תועלת במקדש בלא קרבן? מה תועלת בקרבן בלא ריח ניחוח? לפיכך אמר הנביא הגדול משה: "ה'', יְכוֹנְנֶהָ יָדֶיךָ (שמות טו,יז)." יד האלוהים תישלח עליו. נרומם את אדוננו בכל עת, ונהלל את גדולתו בכל מקום, ונגדל את שמו בכל זמן ותקופה, ונאמין בנביא שהביא לנו תקווה לחיים, והזהירנו מן המוות, ולימד אותנו את דרך האמת. אוי לנו כי חסר לנו הכבוד שכיבד אותנו בו אדוננו. בשל החטאים הרבים שחטאנו כל זה נופל עלינו: חסר לנו המקדש; אין לנו קרבן, אין עולה, אין תרומה, אין חטאת, אין שלמים, אין שולחן ערוך, אין מנורה להאיר, אין קטורת, אין שכינה, אין ברכה, אין סליחה; ואיש אינו חומל עלינו. לו שבנו אל אדוננו, ובקשנו את טובו, ושמרנו את תורת משה, ולמדנו מה שלימדנו, והללנו כאדם, ועשינו טוב כהבל, וקראנו בשמו כאנוש, והלכנו כחנוך, והכנענו עצמנו כאברהם, והיינו נאמנים כיצחק, ותמימים כיעקב, ובורחים מן החטא כיוסף, ועמדנו עם משה – אהרן היה מברך אותנו, אלעזר היה מטהר אותנו, פינחס היה גואל אותנו, והאלוהים היה מביט עלינו ברחמיו.');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (101,'II','51','על תהומי מעין עדן',2000511,'עמוד הענן יומם ועמוד אשתה לילי ונביה רבה משה וכבוד יהוה נגדו כל ישראל אלה פניהם בים סוף עברו ובתרון כל בני ישראל צאו רחף אלהים על בני עבדיו כנשר יעיר קנו ועל גוזליו ירחף כי על אבירתו ישא את גוזליו ויעלה בהם מעלה מכל עוף ויעברם את ארחות הימים וישים אתם בגבחות ההרים הרמים כן עשה אלה עם בני עבדיו נשא אתם על כנפי נשרים ויעברם בתוך הים ביבשה אחרי כבודו ומשה בן ביתו והכין להם חיים וטובים עד יכלו לשמר חקיו ומצותיו למען ייטב להם ולבניהם לעולם אשרך ישראל הן תשמר ותשמע אבותינו היו במצר אסורים וצעקו ושמע אלה צעקותם ושלח שליחן לפרקנון כן יעשה יהוה עמן ויפרקנן דו עני לכל דרוש ופתח רחמיו לא יסגר נפחד מן גדלה ונהימן בה ובמשה נביה ונסיד ונימר לית אלה אלא אחד','The pillar of cloud by day and the pillar of ﬁre by night (Exod. 13:22) and 
the great prophet Moses and the Glory of the Lord led all of Israel. These crossed 
before them the Sea of Reeds, and afer them all the people of Israel went out. 
God hovered over the children of his servants like an eagle who rouses its nest, 
that ﬂutters over its nestlings (Deut. 32:11). Indeed, on its pinions, he carries his 
nestlings and brings them upwards, higher than any bird, and brings them 
across the ways of the seas, and places them in the heights of the elevated 
mountains. Thus God did with the children of His servants: He carried them on 
eagles’ wings and brought them into the midst of the sea on dry land (Exod. 14:16, 
22) following His Glory, and Moses the Son of His House. He established for them 
life and good (things), that they may be able to keep His Laws and command-
ments that it may go well with them and with their sons forever (Deut. 5:29). 
Happy are you Israel (Deut. 33:29) if you keep and obey. Our ancestors were 
conﬁned in Egypt, and they cried out, and God heard their outcry and sent emis-
saries to deliver them. Thus will God do with us: He will deliver us, for He re-
sponds to every seeker, and the gate of His mercy is never shut. Let us fear His 
greatness and believe in Him and in Moses His servant, and let us testify and 
say: “There is no god but One.”','עַמּוּד הֶעָנָן יוֹמָם וְעַמּוּד הָאֵשׁ לָיְלָה (שמות יג,כב) והנביא הגדול משה וכבוד ה'' הנחו את כל ישראל. אלה עברו לפניהם את ים סוף, ואחריהם יצא כל עם ישראל. האלוהים ריחף על בני עבדיו כְּנֶשֶׁר יָעִיר קִנּוֹ עַל גּוֹזָלָיו יְרַחֵף (דברים לב,יא). אכן, על כנפיו הוא נושא את גוזליו ומעלה אותם מעלה, גבוה מכל עוף, ומעבירם בדרכי הימים, ומניחם בפסגות ההרים הנשגבים. כך עשה האלוהים לבני עבדיו: נשאם עַל כַּנְפֵי נְשָׁרִים (שמות יט,ד) והביאם אל תוך הים בַּיַּבָּשָׁה (שמות יד,טז, כב) אחרי כבודו, ומשה בן ביתו. הציב להם חיים וטוב, כדי שיוכלו לשמור את חוקותיו ומצוותיו לְמַעַן יִיטַב לָהֶם וְלִבְנֵיהֶם לְעֹלָם (דברים ה,כט). אַשְׁרֶיךָ יִשְׂרָאֵל (דברים לג,כט) אם תשמרו ותשמעו. אבותינו היו כלואים במצרים, ויצעקו, ואלוהים שמע את זעקתם ושלח שליחים לגאול אותם. כך יעשה האלוהים עמנו: יגאל אותנו, כי הוא עונה לכל דורש, ושער רחמיו לעולם אינו נסגר. נירא את גדולתו ונאמין בו ובמשה עבדו, ונעיד ונאמר: "אין אלוה מלבד האחד."');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (102,'II','18','על תהומי מעין עדן',2000181,'נפרש בחלק יהוה הלבב השלם מדעה אשר יגיד למחכום חכמתה ונחל בפתרון דברי אז ישר דאשיר משה וב ישראל שיאלה מזמנה בה נשאל זקני עמה למשמע חכמה המופתים אשר עשה אלהים במצרים על יד נאמנו ועבדו היו פני אשר › עשה ‹ יה במצרים בים סוף לעיני ישראל ולמה קדם את מופתי ימה על מופתי מצרים בהדה שירתה על ימה דסוף וירא ישראל › את ‹ מצר מת על שפת הים ביד הגדלה אשר עשה יה במצרים פתרון הדה שילתה דאנון לא שוו מהימנין ביה ובמשה במצרים וכאשר ראו מעשה אלהים ומופתיו בים ומות כל מצראי אימנו ביהוה ובמשה עבדו עמי מלת ישר דשרה בה נביה ועבדה אוצר לתרי חלקים חמש מאון ועשרה תרי מניאנין חד } ו {» מ « ניאן שני גירות אבהתה וענות בניה ומניאן שני משה דאמלאת אדה למיתוביתה אז ישר משה ובני ישראל את השירה הזאת ליה כל ] ם [ זכר מלת יש ] ר [ מכל מלי התשבח ] ה כי [ היא מאספ ] ה [ למלי תשבחת ] ה','Let us retire to the Plot of the Lord, the beloved, the perfect, the sage, 
which teaches the knowledge of His wisdom, and let us begin with the interpre-
tation of the words ,אז ישרwhich sung Moses and the people of Israel (Exod. 15:1). 
A question occurs, about which we ask the elders of the people, in order to hear 
wisdom. The wonders which God performed in Egypt through His devoted one 
and His servant were prior to (those) which the Lord performed upon the 
Egyptians in the Sea of Reeds in the sight of Israel. Why (then) did he place the 
wonders of the sea before the wonders of Egypt in the song (sung) by the Sea of 
Reeds: and Israel saw the Egyptians dead upon the seashore (Exod. 14:30) by the 
great work which the Lord did against the Egyptians (Exod. 14:31)? The explana-
tion to this question is that they were not sound in believing in God and in 
Moses (while) in Egypt, but when they saw the deeds of the Lord and His won-
ders by the Sea of Reeds, and the death of all the Egyptians, they believed in the 
Lord and in Moses His servant (Exod. 14:31). Look at the word ישרby which the 
prophet began. He turned it into the treasure of two parts: ﬁve hundred and ten 
(allows for) a twofold counting: One counting (relates) the years of the sojourn of 
the fathers and the oppression of the children, and the second counting (relates) 
Moses’ years when he was appointed to his rank. Then Moses and the people of 
Israel sang this song to the Lord (Exod. 15:1) – all of them. He mentioned the word 
 ישרout of all the words of praise, because it epitomizes the words of the praises.','נפנה אל חלקת ה'', האהובה, השלמה, החכמה, המלמדת את דעת חכמתו, ונחל בפירוש המילים "אז ישיר", שר משה ועם ישראל (שמות טו,א). עולה שאלה אשר נשאל בה את זקני העם, כדי לשמוע חכמה. הנפלאות שעשה אלהים במצרים על ידי חסידו ועבדו קדמו לאלו שעשה ה'' במצרים בים סוף לעיני ישראל. מדוע אם כן הציב את נפלאות הים לפני נפלאות מצרים בשירה שנשרה על ים סוף: וירא ישראל את מצרים מת על שפת הים (שמות יד,ל), ואת המעשה הגדול אשר עשה ה'' במצרים (שמות יד,לא)? הביאור לשאלה זו הוא שלא היו שלמים באמונה באלהים ובמשה בהיותם במצרים, אך כשראו את מעשי ה'' ונפלאותיו בים סוף ואת מות כל המצרים, האמינו בה'' ובמשה עבדו (שמות יד,לא). הבט במילה "ישיר" שבה פתח הנביא. הפכה לאוצר של שני חלקים: חמש מאות ועשר (מאפשרים) ספירה כפולה: ספירה אחת מונה את שנות מגורי האבות וגלות הבנים, והספירה השנייה מונה את שנות משה בהיותו ממונה על מעמדו. אז ישיר משה ובני ישראל את השירה הזאת לה'' (שמות טו,א) – כולם יחד. הזכיר את המילה "ישיר" מכל מילות השבח, מפני שהיא מסכמת את כל מילות התהילות.');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (103,'II','4','על תהומי מעין עדן',2000041,'ארבעתי אקרי העולם שרתו לקהל יהוה מיום אשר יבא משה עליו השלום לעולם , אל הר האלהים חורבה ושלח אתו במופתים רמים לנקם המצרים ולפדות כל צבאות יהוה שלשה פעמים צעת האש הגדלה מאת יהוה מן השמים לשרת בני עבדיו מן חורבה עד שרת } ו {» מדבר שור רוחה עשרה זבנים ה « שבטי רחותה וצררו דבביון עד מוצאם מים סוף והמים ארבעה עשר פעמים שרתם עד מדבר שור ועפר הארץ שרתם עוד ששה פעמים הך הוו כל אלה ידעים בבינה מבדילים בין אהבים ובין איובים כל עובדי אלהים שמעים לעבדי אלהים הגדלות ליה','The four elements of the world served the congregation of the Lord from 
the day that Moses, upon him be peace forever, came to the Mount of God, 
Horeb, and (God) sent him with elevated wonders to take revenge on the Egyp-
tians and to deliver the hosts of the Lord. Three times went forth the Great Fire 
from the Lord out of heaven to serve the sons of His servants, from Horeb to the 
Desert of Shur. Ten times served the Wind the tribes of the Divine Favor and op-
pressed their enemies, until their exit from the Sea of Reeds. And the Water four-
teen times served them up to the Desert of Shur. The Dust of the Earth served 
them six more times. As though all these (elements) knew with understanding to 
distinguish between friends and foes! All the creatures of God obey the servants 
of God. Greatness to the Lord.','ארבעת יסודות העולם שירתו את עדת ה'' מהיום שבא משה, עליו שלום לעד, אל הר האלהים חורב, ו(הא-ל) שלחו עם נסים נשגבים לנקום בפרעה ולהציל את צבאות ה''. שלוש פעמים יצאה האש הגדולה מאת ה'' מן השמים לשרת את בני עבדיו, מחורב עד מדבר שור. עשר פעמים שירח הרוח את שבטי חן האל ולחץ על אויביהם, עד צאתם מים סוף. והמים שירתו אותם ארבע עשרה פעמים עד מדבר שור. עפר האדמה שירת אותם עוד שש פעמים. כאילו כל אלה (היסודות) ידעו בתבונה להבחין בין ידידים לאויבים! כל ברואי האלהים נשמעים לעבדי האלהים. גדולה לה''.');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (104,'II','37','על תהומי מעין עדן',2000371,'כל שם אלהים שם דשותף אלא שם יהוה אין לו בו שותף לכן אמר משה נביה בשירתה יהוה שמו אין שם כשמו עשרים תהללות בשירה הזאת אמר נביה רבה ליהוה רבה ברוך נשא הכל דנשא המצרים עד ראו ישראל יצאים בשלם מכן אמר משה מרכבת פרעה וחיליו ירא בים והגבורים בעלי היד החזקה מבחר שלישיו טבעו בים סוף ומאחרי ראות ישראל למצרים ירדים במצלות כמו אבן אמר נביה רבה בשירתה ימינך יהוה נדארי בכוח אשר בה השמים והא סבילים ימינך יהוה תרעץ אויב כי ראה כבוד יה ומעשיו הגדלים וברב גאוניך תהרס קמיך הם רמות מי עצי דיניו והך עטף אבד בחילה דתקיף רב חילה דשרף גויתם בתוך הים ולא טפה מיה לאשתה','Every (occurrence of the) name אלהיםhas an associate, unlike the name 
 ,יהוהwhich has no associate. Hence Moses the prophet in the Song said: The 
Lord is His name (Exod. 15:3). There is no name like His name. The great prophet 
said twenty praises in this song to the Lord. Blessed be the Bearer of all, who 
lifed the Egyptians up, so that they saw Israel go forth safely. About this, Moses 
said: Pharaoh’s chariots and his host He cast into the sea, and as for the warriors 
with their strong arms, the pick of his oﬃcers drowned in the Sea of Reeds (Exod. 
15:4). Afer Israel had seen the Egyptians sinking into the depths like a stone 
(Exod. 15:5), the great prophet said in the Song: Your right hand, O Lord, glorious 
in power (Exod. 15:6), by which the heavens and the earth are borne, Your right 
hand, O Lord, shatters the foe (ibid.). Indeed, he saw the Glory of the Lord and 
His great deeds: In Your great triumph You overthrow Your adversaries (Exod. 
15:7). This is the overthrowing of the one who rebels (against) His judgments – in 
a moment he will perish by His immutable power. Great is God who burned their 
bodies in the sea, and the water did not extinguish the ﬁre.','לכל הופעה של שם "אלהים" יש שותף, שלא כשם "יהוה" שאין לו שותף. לפיכך אמר משה הנביא בשירה: "ה'' שמו" (שמות טו,ג). אין שם כשמו. הנביא הגדול אמר עשרים שבחים בשירה זו לה''. ברוך נושא הכל, שהרים את המצרים כדי שיראו את ישראל יוצא לשלום. על כך אמר משה: "מרכבת פרעה וחילו ירה בים ומבחר שלישיו טובעו בים סוף" (שמות טו,ד). לאחר שראה ישראל את המצרים שוקעים במצולות כמו אבן (שמות טו,ה), אמר הנביא הגדול בשירה: "ימינך ה'' נאדרי בכח" (שמות טו,ו), אשר השמים והארץ נישאים בה, "ימינך ה'' תרעץ אויב" (שם). אכן, הוא ראה את כבוד ה'' ואת מעשיו הגדולים: "וברוב גאונך תהרוס קמיך" (שמות טו,ז). זוהי הריסתו של המורד בדיניו – ברגע יאבד בכוחו הבלתי משתנה. גדול אלוהים שהיקד גופותיהם בים, והמים לא כיבו את האש.');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (105,'II','50','על תהומי מעין עדן',2000501,'יהוה ימלך עולם ועוד מלכו תדירה ליתה מתחלפה יהוה ימלך עולם ועוד אנשה קנו לנפשהתכון טבה יהוה ימלך עולם ועוד וילה לאנש דיהי דבב למרה יהוה ימלך עולם ועוד טוב אנשה דמהמן באלהים יהוה ימלך עולם ועוד בני טביה הדבקו באלהכון יהוה ימלך עולם ועוד טוב מן אתקרב בה ווילה למי אתרחק מנה יהוה ימלך עולם ועוד לא נבטל כל עת מן מרבאה למרה דעלמה יהוה ימלך עולם ועוד אסף בין זכרון שם יהוה ובין הרגריזים כי הו המקום המבחר מן יום דבראתה אלהים קדוש ותמיד עד יום נקם קדש כל המקומות שלש עשר שמות לו בתורה וכל שם מהם מודע בכבודו הראש הר הקדם כי יהוה אלהי קדם רבה יתה והסגלה מן ימי קדם בעדים שבעה נאמנים גלים בתורה על יד נביא כל עלמה יה כוננו ידך יה ימ עו וע השני בית אל כי האל הגיבור והנורא מגן ועזר לאשר בו יאמנו ושמו מקלט הפליטה למי ישובו אל האלהים יהוה כונ ידך יהוה ים עו ועוד השל › י ‹ שי בית אלהים כי המלאכים הקדושים לא ימושו תמיד עליו עלים וירדים בו אמרים תשבחן לאלהים יהוה כוננו ידך יהוה ימלך עולם ועוד הרביעי שער השמים כי דרושי אלהים עליו ימצאו רחמים קרוב והוא מקום מכון לנזירים והמעשרים והנדרים והברכות והזבחות והעלות והתרומות והנדבות והמנחות והמתנות יה כו יד יה ימ עו ועוד החמישי שמו לוזה בגלל כבוד יהוה ואורו יהוה כוננו ידך יהוה ימ עו ועוד הששי שם אתו קדש שמו כשם מעון הקדש כי המקום משכן קדש וקהל קדש ודבר , קדש לאלה נאדרי בקדש יהוה כוננו ידך יהוה ימלך עולם ועד השביעי הרגריזים כי הוא מקום הברכה בשם יהוה הגדול דשכן עליו כאשר צוה יה ביד משה עבדו ונתתה את הבר על הרגריזים יה כונ ידך יהוה ימלך עולם ועד השמיני בית יה וכמה אין עם זה השם בעל שני ולא שותף כן אין בכל ההרים מקום דמי לו ולא דמי לקדשו יהוה כוננו ידך יהוה ימלך עולם ועוד התשיעי ההר הטוב כי כל הטובות תבא בהעבדה לאלה עליו יהוה כוננו ידך יהוה ימלך עו וע העשירי המקום המבחר כי בו בחר יהוה אלהים מכל המקומות לשכן את שמו בו יהוה כוננו ידך יהוה ימלך עולם ועד האחד עשר גבעת עולם כי הוא רם על כל ההרים בקדשו ובכבוד יהוה כוננו ידך יה ימלך עולם ועוד השני עשר אחד ההרים הדרש עליו אחד הבנים מן אחד הנבים ואמר אלהים יראה יהוה כוננו ידך יהוה ימלך עולם ועוד השלש עשר שם המקום ההוא יהוה יראה הודע הן כל דרושים לאלה עליו לא ישובו רקים מן חסדיו יהוה כוננו ידך יהוה ימלך ] עולם ו [ עוד','The Lord will reign for ever and beyond (SP Exod. 15:18) – a permanent 
kingdom which shall never be changed. The Lord will reign for ever and beyond – 
O People, take Good into your possession. The Lord will reign for ever and beyond 
– woe to the man who is an enemy to his master. The Lord will reign for ever and 
beyond – happy is the man who believes in God. The Lord will reign for ever and 
beyond – O, children of the good ones, cling to your God. The Lord will reign for 
ever and beyond – happy is the one who draws near to Him; woe to the one who 
moves away from Him. The Lord will reign for ever and beyond – we shall not 
cease at any time from exalting the Master of the world. The Lord will reign for 
ever and beyond – (the passage) joins the mention of the Lord’s name with that 
of Mount Gerizim, (to make known) that it is the Chosen Place. It is holy and 
enduring from the day God created it until the Day of Requital (SP Deut. 32:35) – 
the most holy of all places. It has thirteen names in the Torah, each of them 
proclaims its glory. The ﬁrst: The Mountain of the East (Gen. 10:30), for the 
Ancient God gloriﬁed it and chose it from the most ancient days, with seven 
faithful witnesses, revealed in the Torah by the prophet of the whole world – O 
Lord, (with) Your hands establish it. The Lord will reign for ever and beyond (SP 
Exod. 15:17–18). The second: Beth El (Gen. 28:19, etc.), for the mighty and awe-
some God is a shield and a help to whoever believes in him. He made it a safe 
shelter for all those who return to God – O Lord, (with) Your hands establish it. 
The Lord will reign for ever and beyond. The third: The House of God (Gen. 28:17), 
for the holy angels never stop ascending and descending on it, saying praises to 
God – O Lord, (with) Your hands establish it. The Lord will reign for ever and 
beyond. The fourth: The Gate of Heaven (ibid.), for all who seek God will soon 
ﬁnd mercy on it. It is a place appointed to the Nazirites, the tithes, the vows, the 
blessings, the burnt-oﬀerings, the gif-oﬀerings, the free-will oﬀerings, the gifs – 
O Lord, (with) Your hands establish it. The Lord will reign for ever and beyond. The 
ﬁfh: Its name is Luza (Gen. 28:19) for the sake of God’s glory and light – O Lord, 
(with) Your hands establish it. The Lord will reign for ever and beyond. The sixth: 
“He made it a Sanctuary”; its name is like the name “Holy Abode”, as the place 
is a holy sanctuary, (for) a holy congregation. A holy word by God, majestic in 
holiness (Exod. 15:11) – O Lord, (with) Your hands establish it. The Lord will reign 
for ever and beyond. The seventh: Mount Gerizim (Deut. 11:29), truly the place of 
the blessing, in the great name of the Lord who abides on it. As the Lord com-
manded by His servant Moses, you shall pronounce the blessing at Mount Gerizim 
(Deut. 11:29) – O Lord, (with) Your hands establish it. The Lord will reign for ever 
and beyond. The eighth: The House of the Lord (Deut. 23:19). Just as there is no 
second owner, nor associate to this name, so there is no place like it among all 
the mountains nor similar to it in sanctity – O Lord, (with) Your hands establish 
it. The Lord will reign for ever and beyond. The ninth: The Good Mountain (Deut. 
3:25), for all favors shall come through the worship of God on it – O Lord, (with) 
Your hands establish it. The Lord will reign for ever and beyond. The tenth: The 
Chosen Place, for God has chosen it from all the places, to make his name dwell 
on it – O Lord, (with) Your hands establish it. The Lord will reign for ever and 
beyond. The eleventh: The Everlasting Hill, for it is the highest of the mountains 
in its holiness and glory – O Lord, (with) Your hands establish it. The Lord will 
reign for ever and beyond. The twelfh: One of the Mountains (Gen. 22:2). On it 
one of the sons from one of the prophets was asked for, who said God will see 
(Gen. 22:8) – O Lord, (with) Your hands establish it. The Lord will reign for ever 
and beyond. The thirteenth: The name of that place is God Will See (Gen. 22:14) – 
He made it known that those who seek God on it will not turn back empty from 
His grace – O Lord, (with) Your hands establish it. The Lord will reign for ever and 
beyond.','ה'' יִמְלֹךְ לְעֹלָם וָעֶד (שמות טו,יח נוסח שומרון) – מלכות נצחית שלעולם לא תשתנה. ה'' ימלוך לעולם ועד – עם, קחו לכם את הטוב לאחוזה. ה'' ימלוך לעולם ועד – אוי לאיש השונא את אדונו. ה'' ימלוך לעולם ועד – אשרי האיש המאמין באלוהים. ה'' ימלוך לעולם ועד – בני הטובים, דבקו באלוהיכם. ה'' ימלוך לעולם ועד – אשרי הקרב אליו; אוי למתרחק ממנו. ה'' ימלוך לעולם ועד – לא נחדל לעולם מרומם את אדון העולם. ה'' ימלוך לעולם ועד – הפסוק מצמיד את שם ה'' לשם הר גריזים, להודיע כי הוא המקום הנבחר. קדוש הוא ועומד לעד מיום שבראו האלוהים עד יוֹם נָקָם (דברים לב,לה נוסח שומרון) – קדוש שבכל המקומות. שלושה עשר שמות יש לו בתורה, וכל אחד מהם מכריז על כבודו. הראשון: הַר הַקֶּדֶם (בראשית י,ל), כי האלוהים הקדמון כיבדו ובחר בו מימים קדומים, בשבעה עדים נאמנים, הנגלים בתורה על ידי נביא כל העולם – ה'', יְכוֹנְנֶהָ יָדֶיךָ. ה'' יִמְלֹךְ לְעֹלָם וָעֶד (שמות טו,יז-יח נוסח שומרון). השני: בֵּית אֵל (בראשית כח,יט וכו''), כי האלוהים האדיר והנורא הוא מגן ועזר לכל המאמין בו. עשאו מחסה בטוח לכל השבים אל האלוהים – ה'', יְכוֹנְנֶהָ יָדֶיךָ. ה'' יִמְלֹךְ לְעֹלָם וָעֶד. השלישי: בֵּית אֱלֹהִים (בראשית כח,יז), כי מלאכי הקודש אינם פוסקים מלעלות ולרדת עליו ולשיר שבחים לאלוהים – ה'', יְכוֹנְנֶהָ יָדֶיךָ. ה'' יִמְלֹךְ לְעֹלָם וָעֶד. הרביעי: שַׁעַר הַשָּׁמַיִם (שם), כי כל המבקשים את האלוהים ימצאו עליו רחמים במהרה. הוא מקום המיועד לנזירים, למעשרות, לנדרים, לברכות, לעולות, לתרומות, לנדבות, למתנות – ה'', יְכוֹנְנֶהָ יָדֶיךָ. ה'' יִמְלֹךְ לְעֹלָם וָעֶד. החמישי: שמו לוּזָה (בראשית כח,יט) לשם כבוד האלוהים ואורו – ה'', יְכוֹנְנֶהָ יָדֶיךָ. ה'' יִמְלֹךְ לְעֹלָם וָעֶד. השישי: "עשאו מקדש"; שמו כשם "נְוֵה קֹדֶשׁ", שכן המקום הוא מקדש קדוש לקהל קדוש. דבר קדוש מאת האלוהים, נֶאְדָּר בַּקֹּדֶשׁ (שמות טו,יא) – ה'', יְכוֹנְנֶהָ יָדֶיךָ. ה'' יִמְלֹךְ לְעֹלָם וָעֶד. השביעי: הַר גְּרִזִּים (דברים יא,כט), ממש מקום הברכה, בשמו הגדול של ה'' השוכן עליו. כאשר ציווה ה'' ביד עבדו משה, תִּתְּנוּ אֶת הַבְּרָכָה עַל הַר גְּרִזִּים (דברים יא,כט) – ה'', יְכוֹנְנֶהָ יָדֶיךָ. ה'' יִמְלֹךְ לְעֹלָם וָעֶד. השמיני: בֵּית ה'' (דברים כג,יט). כשם שאין בעלים שני ואין שותף לשם הזה, כך אין מקום כמוהו מבין כל ההרים ואין דומה לו בקדושה – ה'', יְכוֹנְנֶהָ יָדֶיךָ. ה'' יִמְלֹךְ לְעֹלָם וָעֶד. התשיעי: הָהָר הַטּוֹב (דברים ג,כה), כי כל הטובות יבואו דרך עבודת האלוהים עליו – ה'', יְכוֹנְנֶהָ יָדֶיךָ. ה'' יִמְלֹךְ לְעֹלָם וָעֶד. העשירי: המקום הנבחר, כי האלוהים בחר בו מכל המקומות, לשכן את שמו עליו – ה'', יְכוֹנְנֶהָ יָדֶיךָ. ה'' יִמְלֹךְ לְעֹלָם וָעֶד. האחד עשר: גִּבְעַת עוֹלָם, כי הוא נשגב מכל ההרים בקדושתו ובכבודו – ה'', יְכוֹנְנֶהָ יָדֶיךָ. ה'' יִמְלֹךְ לְעֹלָם וָעֶד. השנים עשר: אַחַד הֶהָרִים (בראשית כב,ב). עליו נתבקש אחד הבנים מאחד הנביאים, אשר אמר: אֱלֹהִים יִרְאֶה (בראשית כב,ח) – ה'', יְכוֹנְנֶהָ יָדֶיךָ. ה'' יִמְלֹךְ לְעֹלָם וָעֶד. השלושה עשר: שֵׁם הַמָּקוֹם הַהוּא ה'' יִרְאֶה (בראשית כב,יד) – הודיע כי המבקשים את האלוהים עליו לא ישובו ריקם מחסדו – ה'', יְכוֹנְנֶהָ יָדֶיךָ. ה'' יִמְלֹךְ לְעֹלָם וָעֶד.');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (106,'II','46','על תהומי מעין עדן',2000461,'מן הנה שמע הכדו שילה לקבל מה דאתמר לאברהם מה אנדה במימרה דקשטה כד בלש יצחק למעלותה עלה על אחד ההרים אשר אמר אליך דהוא חכמה מריש זיעקתה אתב מדעך שאולה ושמע האגבו לית צריך הגבו תניאן כד אתא סמיך בזכו ואימנו בלש אתרה דבחרה מרה שעתה דאתחזי צרך להבישה אתחזי לה מלאך וחכמה שבילה אלא כתב מד יוזף לך נאר בחזותה מן רחיק כד תלא עיניה לא תלא עיניה אלא מן סגדה דהוה בצפרה קעום ומצלי ולהן הות צלותה אלא לכבונה כד סגד באנצירו חזה בנהירו ולא יתאמר בדיל אשר אמר אליך די לדאתי אלא לדאזל דקדמתה אשר חכמת בכן וחיצת במחכום אהן ממללה והאנה מקים לך סהד קשט דאשר עבידה תחכם לדאזל כד קרא קשטה עסרתי מליה לא אמר תמן אשר הוצאתיך אלו הות לדאתי לא הוה ישראל נפק ממצרים ולא קעם למשמע','From here hear now a question concerning what was said to Abraham. 
What (was) included in the speech of the True One, when He requested that 
Isaac be oﬀered as a burnt oﬀering upon one of the mountains of which I shall tell 
you (Gen. 22:2), since he (Abraham) knew it from the beginning of His summons? 
Prepare your mind, O inquirer, and listen to the answer, and there is no need for 
a second answer. When he came, accompanied by righteousness and faith, he 
sought the place his Master had chosen. When the need for saddling became 
obvious, an angel appeared to him and showed him the way. But write down 
what will illuminate you (about) seeing from afar oﬀ (Gen. 22:4). When he raised 
his eyes, he raised his eyes only from prostration, since it was the morning (and 
he was) standing and praying. And to where was his prayer (directed), unless 
towards it? When he bowed down in devotion, he saw clearly. Let it not be said 
regarding ( אשר אמר אליךGen. 22:2), that it (refers) to what is to come, but to what 
has past, for (the word) אשרpreceded it; be taught by this and strengthened by 
the knowledge of this word. And behold, I set out for you a true witness that אשר
is designated that you may know what has past. When the True One proclaimed 
the Ten Words, did not He say then ( אשר הוצאתיךExod. 20:2)? If He referred to the 
future, Israel would not have exited from Egypt and would not be present to 
listen.','מִכָּאן שְׁמַע נָא שְׁאֵלָה בְּעִנְיַן מַה שֶּׁנֶּאֱמַר לְאַבְרָהָם. מַה כָּלוּל בְּדִבְרֵי הָאֱמֶת כַּאֲשֶׁר בִּקֵּשׁ לְהַעֲלוֹת אֶת יִצְחָק לְעֹלָה עַל אַחַד הֶהָרִים אֲשֶׁר אֹמַר אֵלֶיךָ (בראשית כב,ב), הֲרֵי הוּא (אַבְרָהָם) כְּבָר יְדָעוֹ מֵרֵאשִׁית קְרִיאָתוֹ? הָכֵן אֶת לִבְּךָ, הַשּׁוֹאֵל, וְהַקְשֵׁב לַתְּשׁוּבָה, שֶׁאֵין צֹרֶךְ בִּתְשׁוּבָה שְׁנִיָּה. כַּאֲשֶׁר בָּא, מְלֻוֶּה בְּצֶדֶק וּבֶאֱמוּנָה, בִּקֵּשׁ אֶת הַמָּקוֹם שֶׁבָּחַר בּוֹ אֲדוֹנָיו. כְּשֶׁהִתְבָּרְרָה הַצֹּרֶךְ לַחֲבֹשׁ, נִגְלָה לוֹ מַלְאָךְ וְהֶרְאָהוּ אֶת הַדֶּרֶךְ. אַךְ רְשֹׁם מַה שֶׁיֵּאִיר אוֹתְךָ בְּעִנְיַן וַיַּרְא אֶת הַמָּקוֹם מֵרָחֹק (בראשית כב,ד). כַּאֲשֶׁר נָשָׂא אֶת עֵינָיו, לֹא נְשָׂאָן אֶלָּא מִתּוֹךְ הִשְׁתַּחֲוָיָה, שֶׁכֵּן הָיָה הַבֹּקֶר וְהוּא עוֹמֵד וּמִתְפַּלֵּל. וּלְאָן הָיְתָה תְּפִלָּתוֹ מֻפְנֵית, אִם לֹא אֵלָיו? כַּאֲשֶׁר כָּרַע בְּדֶבֶקוּת, רָאָה בְּבֵרוּר. וְאַל יֵאָמֵר בְּעִנְיַן אֲשֶׁר אֹמַר אֵלֶיךָ (בראשית כב,ב) שֶׁמַּשְׁמָעוֹ לֶעָתִיד לָבֹא, אֶלָּא לְמַה שֶׁעָבַר, כִּי הַמִּלָּה אֲשֶׁר קָדְמָה לוֹ; לְמַד מִזֶּה וְהִתְחַזֵּק בִּידִיעַת הַמִּלָּה הַזֹּאת. וְהִנֵּה אֲנִי מַצִּיג לְפָנֶיךָ עֵד אֱמֶת שֶׁ"אֲשֶׁר" מְיֻחֶד לְהוֹרוֹת מַה שֶׁעָבַר. כַּאֲשֶׁר הִכְרִיז הָאֱמֶת אֶת עֲשֶׂרֶת הַדִּבְּרוֹת, הֲלֹא אָמַר אָז אֲשֶׁר הוֹצֵאתִיךָ (שמות כ,ב)? אִם הִתְכַּוֵּן לֶעָתִיד, לֹא הָיָה יִשְׂרָאֵל יָצָא מִמִּצְרַיִם וְלֹא הָיָה נוֹכֵחַ לִשְׁמֹעַ.');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (107,'II','36','על תהומי מעין עדן',2000361,'ארבעים מלחמות עבד אלה בגלל ישראל עשרים במצרים ועשרים בים סוף בשירתה רבתה הלוא הוא אביך קנך בארבעים מופת גלה בגללך ואספם הנביא משה בשבעה מלים בקץ כי שאל נא מן מסות עד תמה','God waged forty wars for the sake of Israel, twenty in Egypt and twenty 
in the Sea of Reeds. In the “Great Song” (it is said): Is not He your father, who 
created you (Deut. 32:6) through forty wonders which He wrought for the sake of 
Israel? The prophet Moses included them in seven words in the pericope “For 
ask now” (Deut. 4:32), from “by trials” till its end (Deut. 4:34).','אלוהים ניהל ארבעים מלחמות למען ישראל: עשרים במצרים ועשרים בים סוף. ב"שירה הגדולה" נאמר: "הלוא הוא אביך קנך" (דברים לב,ו) – באמצעות ארבעים נפלאות שעשה למען ישראל. משה הנביא כלל אותן בשבע מילים בפרשת "כי שאל נא" (דברים ד,לב), מ"במסות" עד סופה (דברים ד,לד).');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (108,'II','3','על תהומי מעין עדן',2000031,'שלשה מאומות בנביותו הגלו שם יהוה הגדול והאות והכהן שלשה פעמים אימנו באלה ובמשה ולא שוו באימנותון בר ] אי [ שון עשה שלש אותתים לעיני העם ויאמנו , העם וישמעו ובזה לא שוו כי זרו ואמרו יראה יהוה עליכם וישפט ובשנית ראו עשרה מופתים לעיניהם עשה הנביא במצרים ובזה לא אימנו כי סרו עד מאד ואמרו למות במדבר לקחתנו והשלישית ראו רב מאשר ראו מופתים בים סוף כהם לא ראו רב הוא קהלה קדישה אשר יצא מכור ברזל על יד הנביא הקדוש במופתי האל הקדוש בעד משמר תורות קדש ממעון הק ] דש [ ירדת','Three things were revealed in his prophethood: the great name of the 
Lord, the wonder, and the (role of the) priest. Three times they believed in God 
and in Moses, but were not sound in their belief. In the ﬁrst (case) he performed 
three wonders in the sight of the people, and the people believed and obeyed 
(Exod. 4:31), but they were not sound in this, for they dealt viciously and said: 
May the Lord look upon you and punish (Exod. 5:21). In the second (case) they be-
held ten wonders in their sight that the prophet performed in Egypt, but they did 
not believe in this, and they turned aside excessively and said: You brought us to 
die in the wilderness (Exod. 14:11). In the third (case) they saw wonders in the Sea 
of Reeds, even more than they beheld (in Egypt); they never saw like them. Great 
is the holy congregation, who went forth from the iron furnace (led) by the holy 
prophet with the wonders of the Holy God, for the sake of keeping the Holy Law, 
which descended from the holy abode.','שלושה דברים נגלו בנבואתו: שמו הגדול של ה'', הנס, ו(תפקיד) הכהן. שלוש פעמים האמינו לא-להים ולמשה, אך לא היו יציבים באמונתם. בפעם הראשונה עשה שלושה נסים לעיני העם, והעם האמין ושמע (שמות ד,לא), אך לא היו יציבים בכך, שכן נהגו בנבלה ואמרו: יֵרֶא ה'' עֲלֵיכֶם וְיִשְׁפֹּט (שמות ה,כא). בפעם השנייה ראו עשרה נסים שעשה הנביא לעיניהם במצרים, אך לא האמינו בכך, ונטו הרבה הצידה ואמרו: הֲבִלְתִּי אֵין קְבָרִים בְּמִצְרַיִם לְקַחְתָּנוּ לָמוּת בַּמִּדְבָּר (שמות יד,יא). בפעם השלישית ראו נסים בים סוף, אף יותר ממה שראו (במצרים); מעולם לא ראו כמותם. גדולה היא הקהילה הקדושה, אשר יצאה מכור הברזל בהנהגת הנביא הקדוש, עם נסי הא-ל הקדוש, למען שמירת התורה הקדושה אשר ירדה מן המעון הקדוש.');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (109,'II','34','על תהומי מעין עדן',2000341,'אלהי אבי אדם בראתה אלהים מן חלק החכמה אלהי אבי וארוממנהו דפלט לנח ופלטן בימה אלהי אבי וארו אברהם אשר אקים לן סקפנה יה גיבור במלחמה','The God of my father (Exod. 15:2) – Adam, whom God created from the 
sphere of wisdom. The God of my father, and I will exalt Him (Exod. 15:2) – who 
saved Noah and saved us in the sea. The God of my father, and I will exalt Him – 
Abraham, who established for us the covenant. The Lord is mighty in war (SP 
Exod. 15:3).','"אלהי אבי" (שמות טו,ב) – אדם, שאלוהים בראו מספיר החכמה. "אלהי אבי וארוממנהו" (שמות טו,ב) – שהציל את נוח והצילנו בים. "אלהי אבי וארוממנהו" – אברהם, שכרת לנו את הברית. "ה'' איש מלחמה" (שמות טו,ג לנוסח השומרוני).');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (110,'II','44','על תהומי מעין עדן',2000441,NULL,'Hear now a speech adding great wisdom to your mind: The Lord God 
formed man from the dust of the earth (Gen. 2:7), from the good dust of the Good 
Mountain. The House of Adam is exalted by the True One, for he is the choicest 
of all the creatures, and like each of the choicest things appointed for the holy, 
imperfection has no share in it. Every oﬀering that is oﬀered by men for the sake 
of the holy name is empowered and gloriﬁed. Such is the body of Adam, the 
choicest of all creature(s). Indeed, he was only taken from what preceded him: 
the “Good Mountain”, the choicest of all the mountains. At the beginning of 
 בראשיתthe Creator raised it up. Indeed, Jacob too taught its holiness, as our Mas-
ter taught the holiness of the Sabbath (saying): This is none other than the house 
of God (Gen. 28:17), thus also said our Master: And God blessed (Gen. 2:3).','שְׁמַע נָא דִּבְרֵי מוּסָר הַמּוֹסִיפִים חָכְמָה גְדוֹלָה לְלִבְּךָ: וַיִּיצֶר ה'' אֱלֹהִים אֶת הָאָדָם עָפָר מִן הָאֲדָמָה (בראשית ב,ז), מֵעֲפַר הַטּוֹב שֶׁל הָהָר הַטּוֹב. בֵּית אָדָם מְרוֹמָם עַל יְדֵי הָאֱמֶת, כִּי הוּא הַנִּבְחָר מִכָּל הַבְּרִיּוֹת, וּכְמוֹ כָל הַנִּבְחָרִים שֶׁנִּתְמַנּוּ לַקֹּדֶשׁ, אֵין לַפְּגָם חֵלֶק בּוֹ. כָּל קָרְבָּן שֶׁמַּקְרִיבִים בְּנֵי הָאָדָם לְשֵׁם הַקָּדוֹשׁ – הוּא מְחֻזָּק וּמְכֻבָּד. כֵּן הוּא גּוּפוֹ שֶׁל אָדָם, הַנִּבְחָר מִכָּל הַבְּרִיּוֹת. אָמְנָם, לֹא נִלְקַח אֶלָּא מִמַּה שֶּׁקָּדַם לוֹ: "הָהָר הַטּוֹב", הַנִּבְחָר מִכָּל הֶהָרִים. בְּרֵאשִׁית בְּרִיאָה, הֵרִים אוֹתוֹ הַבּוֹרֵא. אָמְנָם גַּם יַעֲקֹב לִמֵּד אֶת קְדֻשָּׁתוֹ, כְּשֵׁם שֶׁלִּמֵּד אֲדוֹנֵנוּ אֶת קְדֻשַּׁת הַשַּׁבָּת בְּאָמְרוֹ: כִּי אֵין זֶה כִּי אִם בֵּית אֱלֹהִים (בראשית כח,יז), כֵּן אָמַר גַּם אֲדוֹנֵנוּ: וַיְבָרֶךְ אֱלֹהִים (בראשית ב,ג).');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (111,'II','2','על תהומי מעין עדן',2000021,'אדכיר לטב עד לעלם נביה רבה משה אשר פתח לנו גן עדן התורה כי מבגללה פדה שבטי יעקב ואוליך כוכבי אברהם קעומי החלק השלישי ענות מאה וארבעים שנה מן ארבע מאות שנה היה עמון חשבן ארבע מאות שנה כי על כלותה יצאו מלכים וכאשר ראו מלאת השנים וינחו ויצעקו למדרש הרוח ואלהים את בריתו זכר בזכות אברהם ויצ ויעקב כן בן למך כרז על מלאת חמשים ומאת יום צעק ויזכר אתו אלהים בן שמנים שנה אתנבה בן עמרם על מלאת לבבו ומלאת דעתו לו','Blessed be forever the memory of the great prophet Moses who opened 
for us the Garden of Eden of the Torah. Indeed, for its sake (God) redeemed the 
tribes of Jacob, and led the stars of Abraham, the masters of the third part – the 
misery of one hundred and thirty years of four hundred years (Gen. 15:13). For 
they were (tied to) the calculation of four hundred years, at the end of which 
they were to depart (like) kings. When they saw that the years were over, they 
sighed and cried out seeking relief. And God remembered his covenant for the 
sake of Abraham, Isaac, and Jacob. Similarly, the son of Lamech cried out at the 
completion of one hundred and ﬁfy days; he cried out and God remembered 
him. The son of Amram was eighty years old when he prophesied – with a full 
heart and full mind.','יהי זכרו מבורך לעד של הנביא הגדול משה, אשר פתח לנו את גן עדן של התורה. אכן, למענה גאל (הא-ל) את שבטי יעקב, והנהיג את כוכבי אברהם, בעלי החלק השלישי – ייסורי מאה ושלושים שנה מתוך ארבע מאות שנה (בראשית טו,יג). שכן היו קשורים לחשבון ארבע מאות שנה, שבסופן היו עתידים לצאת כמלכים. כשראו כי השנים תמו, נאנחו וזעקו לבקש הקלה. וא-להים זכר את בריתו למען אברהם, יצחק ויעקב. כמו כן, בן למך זעק בהשלים חמישים ומאה יום; זעק ואלוהים זכרו. בן עמרם היה בן שמונים שנה בנבאו – בלב שלם ובדעת מלאה.');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (112,'III','35','וידבר משה והכהנים הלוים',3000351,'ועוד חמשה ברכהן פרטון נביה רבה משה חדה בימה וחדה במפוקה ותלתה בשפול טור סיני ואנון תלתיתה דאתמרת לאברהם חכמון רבינה דאשבו יתה שרה ואמר לה ויהי זרעך בגדל מדמין לכוכבי שומיה אמר נביה רבה משה בטור סיני והנוכון יומה ככוכבי שומיה יוזף עליכון דמותכון אלף זבנין הדה לתהבה כד ייתי ויברך יתכון חכמון מיתוביתה דמלכו אלין תלתי ברכהתה דאתמרת לאברהם אמרין משה למרבהתון וכן חדדון בהרגריז אתר סגדתה','Also: ﬁve blessings the great prophet Moses pronounced, one at the sea, 
one at the departure, and three at the foot of Mount Sinai. These three that were 
said to Abraham – His Greatness taught that they were worthy of him (Moses). 
He opened by saying to him: “Your descendants will resemble in abundance to 
the stars of heaven.” The great prophet Moses said on Mount Sinai: You are this 
day as the stars of heaven […]. May (the Lord) […] increase you a thousand times 
as many as you are (Deut. 1:10–11). This concerns the Taheb, and when he will 
come and bless you. He taught them the status they possessed. These three 
blessings that were said to Abraham, Moses said them to magnify them. Thus He 
renewed them on Mount Gerizim, the place of worship.','גם כן: חמש ברכות נשא הנביא הגדול משה, אחת על הים, אחת ביציאה, ושלוש למרגלות הר סיני. שלוש אלה שנאמרו לאברהם – לימד אותו הגדולה כי היה ראוי להן (למשה). פתח ואמר לו: "צאצאיך יהיו רבים ככוכבי השמים." הנביא הגדול משה אמר בהר סיני: אַתֶּם הַיּוֹם כְּכוֹכְבֵי הַשָּׁמַיִם [...]. יְהוָה [...] יֹסֵף עֲלֵיכֶם כָּכֶם אֶלֶף פְּעָמִים (דברים א,י-יא). דבר זה מתייחס לתאהב, ולכשיבוא ויברך אתכם. לימד אותם את המעמד שהיה בידם. שלוש הברכות הללו שנאמרו לאברהם אמרן משה כדי לגדלם. כך חידש אותן בהר גריזים, מקום הפולחן.');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (113,'III','13','וידבר משה והכהנים הלוים',3000131,'עמו כל אהן איקרה רבה דיקר בה אלה כהניה ואלפה בגדל ושררה באימנו ואתחיד בה בשלמה יתרה והן תימר הן לכהנה רבה מיתובין סגי ממד אדכרת הנו יהי במשכנה הוא בית מרה דאמר בדילה ומן מקדשה לא יפק תשמישתה הי מיתובה חדה וביומי פניה קוממותה בבית מרה קומה דדכרן ישתבח מן גלה לן חכמה כהלה חיים ישתבח ממנה יכולה רבה באריה טבה מיטבה צעורה מתקנה תדירה מורכה מספק מכל , גוני טבהתה יהוב מתנהתה וזאון כל נפשהתה שלטנותה רבה וגיברותה תקיפה קמאי לא מראש וחראה לא עד עקב ממן עד לעלם ליתו מתחלף אתו בנן נזדמן כהלן בלב אחד לבעותה וננצר קדם יכלותה ונסגד לגדלה ונזע מן גבורתה ונאמן ביחידאותה כות אדם כד הבלד וכאנוש כד קרא וחנוך כד אזל בריחות אלהה ונח כד אזדכה ואברהם כד אמן ויצחק כד שלם נפשה ויעקב כד אתפורר מן דמכה ויוסף כד ערק מן עצינה ומשה כד טמר אפיו בשוש מן אלה ואהרן כד תלא אדיו וברך בשם יהוה בארכנו רבה ואלעזר כד אתימן ופינחס כד קנא לאלה וסלח על שת מון דאלף וכלא מגיפתה ונזדכי כות תרי צדיקיה יהושע וכלב עד נהי מן תהבים גלו רחותה וסתרו פנותה ואשתעבדו ואקימו מה דאמר אלה ] וית [ ה מלכו','See all this great glory by which God gloriﬁed the priests, and learn it in 
greatness and strengthen it with faith and cleave to it in exceeding perfection. If 
you say that the high priest performs more functions than mentioned, the an-
swer is that his being in the Sanctuary, the House of his Master, about which He 
said: He shall not go out of the sanctuary (Lev. 21:12), and his service make both 
one function. During the days of Divine Disfavor his staying in his Master’s 
House is a staying of memory. Praised be He who revealed to us wisdom that is 
wholly life. Praised be the Enduring, the Mighty, the Great, the good Creator, the 
Benefactor, the Producer, the Establisher, the Steadfast, the Perseverant, who 
provides all sorts of goodies, who gives gifs and sustains all souls. His dominion 
is great and His might is powerful. Ancient – before the beginning – and last – 
afer the end. Enduring forever, He does not change. Let us assemble with one 
heart to seek Him and (let us) devote ourselves before His might, and bow down 
to His greatness, and fear His power, and believe in His uniqueness, like Adam 
when he was afraid, like Enosh when he proclaimed, like Enoch when he 
walked according to God’s will, like Noah when he was upright, and Abraham 
when he believed, and Isaac when he submitted himself, and Jacob when he 
woke up, and Joseph when he ﬂed from deceit, and Moses when he concealed 
his face, shy of God, and Aaron when he lifed up his hands and blessed in the 
name of the Lord in great humility, and Eleazar when he was appointed, and 
Phinehas when he was zealous for God and atoned for six hundred thousand 
and stopped the plague. Let us become upright like the two righteous, Joshua 
and Caleb, so that we may be among the repentants, who revealed the Divine 
Favor and hid away the Divine Disfavor and submitted themselves and per-
formed what God said, and acquired it.','ראו את כל הכבוד הגדול הזה שבו כיבד האלוהים את הכוהנים, ולמדו אותו בגדולה וחזקו אותו באמונה והיצמדו אליו בשלמות יתרה. אם תאמרו שהכוהן הגדול ממלא תפקידים רבים יותר מן האמור, התשובה היא שהיותו במקדש, בית אדונו, שעליו אמר: לא יצא מן המקדש (ויקרא כא,יב), ועבודתו – שניהם כתפקיד אחד. בימי הסתר הפנים, שהייתו בבית אדונו היא שהייה של זיכרון. ברוך הוא שגילה לנו חכמה שכולה חיים. ברוך הנצחי, האדיר, הגדול, הבורא הטוב, המיטיב, היוצר, המכונן, הנאמן, המתמיד, המספק כל טוב, הנותן מתנות ומפרנס כל הנשמות. גדולה ממשלתו ועצום כוחו. קדמון – לפני הראשית – ואחרון – אחרי הסוף. נצחי לעולם, אינו משתנה. נתכנס בלב אחד לבקשו ונמסור עצמנו לפני גבורתו, ונשתחווה לגדולתו, ונירא את עוזו, ונאמין ביחודו, כאדם כשנתיירא, כאנוש כשקרא, כחנוך בהתהלכו ברצון האלוהים, כנח בהיותו תמים, וכאברהם בהאמינו, ויצחק בהגישו עצמו, ויעקב כשנעור, ויוסף בברוחו מן המרמה, ומשה בהסתירו פניו מפאת יראת האלוהים, ואהרן בהרימו ידיו ובברכו בשם ה'' בענווה גדולה, ואלעזר כשנתמנה, ופינחס בקנאו לאלוהים ובכפרו על שש מאות אלף ובעצרו את המגפה. נהיה ישרים כשני הצדיקים, יהושע וכלב, למען נהיה בין השבים, שגילו את רצון האלוהים והסתירו את הסתר הפנים, ומסרו עצמם וקיימו את אשר אמר האלוהים, וקנו אותו.');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (114,'III','70','וידבר משה והכהנים הלוים',3000701,'נתן אפרשו גדיל דחיל ונמלי לבבן מן נאר חכמת מכתב נביה רבה משה דעקרה מן חיי עולם דאנן כדו קדמין על מלה מדמיה למלתה דקדמה במה דאתמר בדיל אתת אבוה ארור שכב עם כל בהמה אזהר אלה מן אהן עובדה בישה לגברה ולאתתה לגברה אמר ואיש אשר יתן שכבתו בבהמה מות יומת ולאתתה אמר ואשה אשר תקרב אל כל בהמה לארבעה והרגת את האשה ואת הבהמה מות יומתו דמיהם בם ויתוקדו באשתה באתר טמא דמותון כי גדלה בעי מדכאה ארעה מנון כמד דכה יתה מן גברי סדם טב לך תדע דפנאיה בישה ארורה טמיה אזל בביש שביליה לכן הדמה למד בה אזל והתוזף בבישו עם בהמה בעירה לא אכשר בעובדה ולא אצלח אלא אבד ובהמתה עמה','Let us set out a great and fearsome division and let us ﬁll our hearts 
from the light of the knowledge of the writing of the great prophet Moses, whose 
root is everlasting life. We are now advancing toward a word that resembles the 
word preceding what has been said about the father’s wife: Cursed be he who lies 
with any beast (Deut. 27:21). God warned man and woman against this evil deed. 
To the man He said: If a man lies with a beast he shall be put to death (Lev. 20:15), 
and to the woman He said: If a woman approaches any beast and lies with it, you 
shall kill the woman and the beast; they shall be put to death, their blood is upon 
them (Lev. 20:16). They shall be burnt by ﬁre in a place that is unclean like they 
are. For His Greatness sought to purify the earth from them, as He puriﬁed it 
from the people of Sodom. It is good for you to know that the evil pervert, the 
cursed, the deﬁled, walked on the most evil path, therefore he became similar to 
what he walked therein, and was joined in evil with a wild beast. He does not 
succeed in his deed nor does he prosper, but he perishes, and the beast (per-
ishes) with him.','נפתח חלוקה גדולה ואיומה ונמלא את לבנו מאור הדעת של כתבי הנביא הגדול משה, ששורשו חיי עולם. אנו מתקדמים כעת אל דבר הדומה לדבר שקדם לאמור על אשת האב: ארור שוכב עם כל בהמה (דברים כז,כא). אלוהים הזהיר את האיש ואת האישה מפני המעשה הרע הזה. לאיש אמר: ואיש אשר יתן שכבתו בבהמה מות יומת (ויקרא כ,טו), ולאישה אמר: ואישה אשר תקרב אל כל בהמה לרבעה אותה והרגת את האישה ואת הבהמה מות יומתו דמיהם בם (ויקרא כ,טז). יישרפו באש במקום טמא כמותם. כי גדולתו ביקשה לטהר את הארץ מהם, כפי שטיהר אותה מאנשי סדום. טוב לך לדעת כי הנפסד הרע, הארור, הטמא, הלך בדרך הרעה ביותר, לפיכך נעשה דומה לזה שהלך בה, ונשתתף ברשע עם חיה פראית. הוא אינו מצליח במעשהו ואינו משגשג, אלא אובד, והבהמה אובדת עמו.');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (115,'III','71','וידבר משה והכהנים הלוים',3000711,'נעזר אל מליה דהוינן בון ונפרש יתון קדם שמועיה תרע סיאג זכותה במה דעבד עבד עובד לא עבדונה אבהתה לכן כתב מקל אבהתה יתקטל וילבש לבטה רבה דאקים תאוה בישה כותה לא יתעבדו כותה לא יהי אדמה באנשי המבול דגלו חובין לא השמע בכותון שרר גרמה על עמל רע לא עבדנה אנש דרש מזנאה בסתר לא עם אשה יהי מתגלי בה וחשב בנפשה הן לא עליו חוב יתקטל בה ולא יטמא ולא יתחלל מן אזהרותה אתמר בהדה מלתה סגי מכן','Let us go back to the words we have dealt with and explain them before 
the listeners: He shattered the fence of righteousness by what he did. He did an 
act his ancestors never did. To this (God) wrote: He who dishonors his parents 
shall be put to death and be cursed greatly, for he established bad lust, the like 
of which has never been done and the like of which will never be (done again). 
He made himself like the people of the Flood, who revealed sins the like of 
which was never heard of. He hardened himself for a bad action like which no-
body else did. He sought to play harlotry in secret and not with a woman – he 
will be exposed. He thought in his self that there was no guilt on him – he will be 
put to death because of it. Let him not be deﬁled or profaned, in view of the 
warning that has been vehemently said by this word.','נשוב אל הדברים שעסקנו בהם ונבארם לפני השומעים: הוא שבר את גדר הצדק במה שעשה. עשה מעשה שאבותיו מעולם לא עשו. על כך כתב: המחלל את הוריו יומת ויהיה ארור מאוד, כי הקים תאווה רעה שכמוה לא נעשתה וכמוה לא תיעשה עוד. עשה את עצמו כאנשי המבול, שגילו חטאים שכמותם לא נשמע מעולם. הקשיח את עצמו למעשה רע שאיש אחר לא עשה כמוהו. ביקש לזנות בסתר ולא עם אישה – ייחשף. חשב בנפשו שאין עליו אשמה – יומת בגללה. אל יטמא ואל יחולל, לנוכח האזהרה שנאמרה בחריפות בדבר הזה.');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (116,'III','47','וידבר משה והכהנים הלוים',3000471,'נ חכמו רבינה הך הו ובלשו יתה בשלמו דמדע מנה לא נפק ויתה לא נשבק ומן איקרה לא נחדל ולא נמוש כל עת נרבינה דבידה פרקנן מכל דין מכה אוי לן אלית יהי לן מדע נדע בה מה דו טב לן ונקים קנומן במד ארשתן הנית בעי מחכום אתילף ולא תשבק לבך פני מן מחכומה ובעי לנפשך מד מרך בעי לך ולא תרחק גרמך מן מרך ודע דו רחמן ורתאי ליתו מקבל חיבין עד האן יתובון הא אנן מחסלין מלתה קמאה וממללים במלתה תניניתה והנון מבלדין ממן ישמעון ממלל מדחל לכל שמועה כד קרא אלה עסרתי מליה לא הוה יזהר על כל מלה בלבטה ונהי אמרים אמן מה נימר ומרן חכם מד לינן חכמין מן ביש עמלינן אוי לן לית לן מדע נדע בה מד מרן בלש מנן ליתו בעי מנן אלא מהו טב לן לא מהו מכה לן נודי לה על כן ונשתעבד קדם רבותה על כל יתה איקרה ונרכן קדם גבורתה דמה יריח עלינן','Nun – know its greatness and seek it with perfection of mind. Let us not 
leave it, nor forsake it. Let us not cease from honoring it, nor depart from exalt-
ing it at all times, for through it we were redeemed from all aﬄicting judgement. 
Woe to us if we do not have the understanding to know what is good for us and 
to establish ourselves in what it has commanded us. If you seek knowledge, 
learn, and do not leave your mind empty from knowledge. Seek for yourself 
what your Master wants for you, and do not let yourself be far from your Master. 
Know that He is merciful and pitiful. He does not accept wicked ones till they 
repent. Lo, we ﬁnish with the ﬁrst statement, and speak of the second. They are 
disquieted at what they are about to hear, a statement that terriﬁes all who hear 
it. When God proclaimed the Ten Words, He did not warn every statement with a 
curse, so that we should say Amen. What should we say? Our Lord knows what 
we do not know of the evil of our doings. Woe to us! We do not have the wisdom 
to know what our Master seeks of us. He only seeks of us what is for our own 
good, not what is harmful to us. Let us give thanks to him for this and submit be-
fore His greatness for all that glory, and be humble before His potency; perhaps 
He will be pleased with us.','נון – דע את גדולתה ובקש אותה בשלמות המחשבה. אל נניח אותה ואל נעזבה. אל נחדל מלכבדה ואל נסור מלרוממה בכל עת, שכן על ידה נגאלנו מכל דין מציק. אוי לנו אם אין לנו את הבינה לדעת מה טוב לנו ולכונן עצמנו במה שציוותה אותנו. אם אתה מבקש דעת, למד, ואל תניח את דעתך ריקה מידע. בקש לך את מה שאדונך רוצה לך, ואל תניח עצמך להתרחק מאדונך. דע כי הוא רחום וחנון. הוא אינו מקבל רשעים עד שישובו בתשובה. הנה, אנו מסיימים את האמירה הראשונה ועוברים לדבר על השנייה. הם נרעשים ממה שעומדים לשמוע, אמירה שמפחידה את כל שומעיה. כאשר האל הכריז את עשרת הדברות, הוא לא חיזק כל אמירה בקללה כדי שנאמר אמן. מה עלינו לומר? אדוננו יודע את מה שאין אנו יודעים מרוע מעשינו. אוי לנו! אין לנו החכמה לדעת את מה שאדוננו מבקש מאיתנו. הוא אינו מבקש מאיתנו אלא את טובתנו, לא את נזקנו. נודה לו על כך ונכנע לפני גדולתו על כל אותו כבוד, ונהיה ענווים לפני עוצמתו; אולי ירצה בנו.');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (117,'III','6','וידבר משה והכהנים הלוים',3000061,'ושמע ישראל לא אשמעך אלה מלה חדה אלא ובה מרבאה לחייך הפקתך לזימון מלאכיה ואשמעך אלה קלה ואימנת ואמרת כל דמלל יה נשמע ונעבד אה לאויך אתמנת על אהן ממללה אלא עזרת וכחשת כלה דאלו לא אמרת ולא כחשת אידן מדע הוה לך תימר ולא תעבד דאה ערבוב חיול איך תתרחי לנפשך תהי רחיק מן אלה ומן קשטה אלולי אלה לא הוה לך משכח מן רבינך מן אוקרך מן אחס עליך מן עבד עמך כל טוב מן קטל דבביך תבעי קיאם אברהם ולא תעבד עובדיו ותדרש איקר יצחק ולא תנצר כותה ועוד כשרנה דיעקב ולא תקום במליו ומלכות יוסף ולא תברח מן עציאנה דמותה מה אהן סמיונה רבה דאנה עמי מנך קשטה הוקם לך ספר ולא צביך תתילף מנה ואנה אקימת קנומי כאב אחס עליך ורביתך ואת מגדד על מד אתה שבוק לכל הדה יתודי רחמנה סבולך בכל זבן שבק כדו שביל טעותה ואתב גרמך למשמע מה תתרבי בה ותתיטב בכל עת הלא קשטה כתב קמיך וכדו ישראל ודאזל אזל ומכדו ולעל תהי מתרבי במד תתילף','And hear, O Israel (Deut. 27:9) – God did not make you hear (even) one 
word unless by means of it your life might be prolonged. I brought you out to 
meet the angels, and God made you hear His voice. You believed and said: “All 
that the Lord said we shall hear and do” (SP Deut. 5:23). Would that you perse-
vered in this statement! But you turned back and utterly deceived. Better that 
you had not said and not deceived! What (kind of) mind did you have? You said 
but did not accomplish! This is a mighty blemish. How do you delight yourself 
being afar from God and from the truth? Had it not been for God, nobody would 
have found you. Who elevated you? Who honored you? Who had mercy on you? 
Who made to you every good? Who killed your enemies? You seek the covenant 
of Abraham but do not do his deeds. You seek the glory of Isaac but are not de-
voted like him. Moreover, (you seek) the success of Jacob but do not fulﬁll his 
words. And the kingship of Joseph but do not ﬂee from mortal evil-doing like 
him. What is this great blindness that I see in you? The True One set up a good 
teacher for you, but you did not want to learn from him. I have set myself up as a 
merciful father for you, to elevate you, but you rebel against your own status. 
Leave all this. Blessed be the Merciful One, who forgives you always. Abandon 
now the straying path and set yourself to hear the (matter) by which you will be 
elevated and good will be done to you at any time. For the True One has written 
before you: And now, O Israel (Deut. 10:12) – what is past is past, and from now 
on you will be exalted by what you will learn.','וּשְׁמַע יִשְׂרָאֵל (דברים כז,ט) – האלוהים לא השמיעך אף מילה אחת אלא שבאמצעותה תאריך ימים. הוצאתי אותך לקראת המלאכים, והאלוהים השמיע לך את קולו. האמנת ואמרת: "כֹּל אֲשֶׁר דִּבֶּר יְהוָה נִשְׁמַע וְנַעֲשֶׂה" (ספ"ש דברים ה,כג). הלוואי שהתמדת בדברה זו! אך חזרת לאחוריך ורמית לחלוטין. מוטב שלא אמרת ולא רמית! איזו דעת הייתה לך? אמרת ולא קיימת! זו פגם גדול מאוד. כיצד אתה מוצא נחת בהיותך רחוק מאלוהים ומן האמת? לולא האלוהים, לא היה מוצא אותך איש. מי הרים אותך? מי כיבד אותך? מי ריחם עליך? מי עשה לך כל טוב? מי הרג את אויביך? אתה מבקש את ברית אברהם אך אינך עושה את מעשיו. אתה מבקש את כבוד יצחק אך אינך מסור כמוהו. ועוד, את הצלחת יעקב אך אינך מקיים את דבריו. ואת מלכות יוסף אך אינך בורח מן הרשע הקטלני כמוהו. מהי העיוורון הגדול הזה שאני רואה בך? האמת הקים לך מורה טוב, אך לא רצית ללמוד ממנו. העמדתי את עצמי כאב רחום עבורך, להרים אותך, אך אתה מורד בעצמך. עזוב את כל זה. ברוך הרחמן, המוחל לך תמיד. עזוב עתה את דרך התעיה, והכן את עצמך לשמוע את הדבר שבו תתעלה ויֵיטַב לך בכל עת. כי האמת כתב לפניך: וְעַתָּה יִשְׂרָאֵל (דברים י,יב) – מה שעבר עבר, ומעתה תתעלה במה שתלמד.');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (118,'III','39','וידבר משה והכהנים הלוים',3000391,'כד הוה אהרן כהנה פריד אהן ברכתה אלה מסעדה עד ישמענה כל קהלה כן הוה לוי זבנה דפרד ברכתה אלה מסעדה עד ישתמע קלה משרי ואמר מה דארשתה אלה יתרבי אמורה ויתחיל שמועה אה קהלה טבה דמרה חילה ואקים לה מד ימה לאבהתה יומה אדן הכלל רבינך ואתידע איקרה דבה אתפרדת › ו ‹ הוית עם קדש ליהוה אלהיך אבהתן נפקו ממצרים ביד רמה ומתו במדברה ולאהן אתרה לא חזו ואתון מלכתון יתה ‹} ואמטיתון לידה ברבין גדיל וקטלתון דמלך אר › ע ח { כון ולא שירתון לה שיור תתברכון כות נח כד אמטה לאהן אתרה בפצו לגו עלם שלם ותתרבו כות אברהם בסגין יתר ועלמה בוכון יתיטב ותמלכו ארעה בקשט וזכו ועלמה חדי מד אתון מלוכיו עד תעבדון בה כל מד אלה בעי ולא יהי רגז מתחזי בעלמה ותרבו שריר דמות אברהם כד אתא מתנסה לאכה ועקד ית יצחק ושבה יתה על מדבחה ובלש יעבד מד לה אמיר } לה { וכד ידע קשטה אנצירות לבה שגר פרקנה מן גנתה ושמע ברכתה מן לבה דשומיה ורבה יתה סגי מכל דגעזו כי ברוך אברכך ] י [ תה תמלכו ] עד יהכ [ ו כל אמיה ] לי [ ד ] כ [ ון וסגוי אסגי ית זרעכון עורי לא תסור דאה מנוכון לעלם','While Aaron the priest was pronouncing this Blessing, God was assist-
ing him, so that all the congregation could hear him. So it was with Levi when 
he pronounced the Blessing; God was assisting him, so that his voice could be 
heard. He began to say what God commanded him. Gloriﬁed be the speaker and 
strengthened be the hearer. O good congregation, which your Master strength-
ened and fulﬁlled what He had sworn to your ancestors. Today (Deut. 27:9) your 
greatness has been completed and your glory has been made known, by which 
you are made unique and became a holy people to the Lord your God (ibid.). Our 
ancestors went forth from Egypt gloriously and died in the wilderness, and did 
not see this place. But you possessed it and reached it in great might, and slew 
those who owned your land, and did not leave one survivor. You will be blessed 
like Noah, when he reached this place by deliverance in a perfect world, and glo-
riﬁed like Abraham with exceeding multitude, and the world will beneﬁt through 
you. And you will own the land in truth and righteousness, and the world will be 
joyful with you as its owner, so that you may do in it whatever God wants. And 
anger will not be seen in the world. You will multiply exceedingly like Abraham, 
when he came here while being tested: he bound Isaac and put him on the altar 
and sought to do what has been said to him. When the True One knew the devo-
tion of his heart, He sent his redemption from the Garden. He heard the blessing 
from the midst of heaven (which) gloriﬁed him greatly, more than all who had 
gone: for indeed, I will bless you (Gen. 22:17) – you will possess it till all the 
nations come to you. And I will multiply your descendants (ibid.) – this will never 
turn away from you.','בשעה שאהרן הכוהן היה אומר ברכה זו, אלוהים היה מסייע לו כדי שכל הקהל יוכל לשמוע אותו. כן היה עם לוי כשאמר את הברכה; אלוהים סייע לו כדי שקולו יישמע. החל לומר מה שאלוהים ציווה עליו. יהיה מפואר הדובר ויתחזק השומע. הו קהל טוב, שאדונכם חיזק ומילא את אשר נשבע לאבותיכם. הַיּוֹם (דברים כז,ט) הושלמה גדולתכם ונודעה תפארתכם, שבה נבדלתם וַתִּהְיוּ עַם קָדוֹשׁ לַיהוָה אֱלֹהֶיכֶם (שם). אבותינו יצאו ממצרים בכבוד ומתו במדבר ולא ראו את המקום הזה. אתם ירשתם אותו והגעתם אליו בגבורה רבה, והרגתם את מחזיקי ארצכם ולא השארתם שריד. תהיו ברוכים כנח, שהגיע למקום זה בגאולה בעולם תמים, ומפוארים כאברהם ברבוי עצום, והעולם יופק ממכם תועלת. ותירשו את הארץ באמת ובצדק, ויגל העולם בכם כבעליה, למען תעשו בה כל אשר אלוהים חפץ. ולא ייראה כעס בעולם. תרבו מאוד כאברהם, כשבא הנה בשעת ניסיונו: עקד את יצחק ושם אותו על המזבח וביקש לעשות כאשר נאמר לו. כשידע האמיתי את מסירות לבו, שלח את גאולתו מן הגן. שמע את הברכה מתוך השמים, שגידלה אותו מאוד יותר מכל אשר קדמו: כִּי בָרֵךְ אֲבָרֶכְךָ (בראשית כב,יז) – תירשנה עד שכל הגויים יבואו אליך. וְהַרְבָּה אַרְבֶּה אֶת זַרְעֲךָ (שם) – זאת לא תסור ממך לעולם.');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (119,'III','56','וידבר משה והכהנים הלוים',3000561,'נבלד כדו מן › מימר ‹ יתמר בפממי מלאכיה ועוד כבודה מן מלאכיה אוכחו לכל דריה ומן כבודה חרב שליף לשטנה מלאכיה אמרים אה קהלה אתחיד ויטם נפשך באימנו כי באדינן איטבו ובאדינן פרקנה ובאדינן פוגגה ובאדינן אנשמה ובאדינן אבדנה ובאדינן צדוה ובאדינן קטלה ובאדינן שיוצה וכל אהן עבדנן יתה בדילך למרבה יתך › ו ‹ אף למשרראתך ולמלף יתך לית לך צורכה למבקר על מד לה עבדנן מן אדם עד נח עד אברהם עד לוט אי מן סדם עד יצחק עד יעקב עד יוסף עד נביה רבה משה מגלי אמנותה מן אדם קעמנן ורבינן מקדומה ומן נח אתחזינן והסהרנן בתיבותה › ו ‹ כן אברהם הגלינן לה לבסרנה וכן ליצחק בדיל פרקנה לא הגלינן אלא לאלין טביה שלמיה וליתך צריך תבקר על עובד לוט וסדם כי דברון גלי קמיך והן בעית ת } ע { ד › ע ‹ רז עובדן עם יצחק כד אתעקד על מדבחה עמי הך כרזנן בקל רם אל תשלח ידך ואל תעבד מאדם וכן עם יעקב כד קעם ועבר בנהר ירדנה בקענן יתה לה ועברה בשלם כמד אתמר ויקם ויעבר את הנהר רבינן מקדומה וחילנן דרגה והגדל בברכה לה ולזרעה בתרה אן התהלכתון על יתה מיתוביתה כיינן נפניכון מן עובדי סדם ] ו [ הן עזרתון ] מ [ ן שביל קשטה ] מ [ ה דאתעבד באנשי סדם בוכון ישרי וכן קשטה כתב כמהפכת סדם ועמרה ניתי ונגלי ולינן מתחזין עדהן יתעבד דין רב ויתר לית בה רחמים יתודי יכולה דעבד יתן › סהדים ‹ מודעים בכל טוב ובכל ביש ואנן קעמין מרבים עובד לית בה חסרן וכלה פוגגו','Let us now be frightened by the speech spoken by the mouths of the 
angels and also (of) the Glory. From the angels, an admonishment to all genera-
tions, and from the Glory – a sword drawn in adversity. The angels said: “O con-
gregation, cling (to God) and strengthen yourself in faith, for in our hands is 
beneﬁt, and in our hands is redemption, and in our hands is delight, and in our 
hands is relief, and in our hands is destruction, and in our hands is aﬄiction, 
and in our hands is death, and in our hands is extermination. All this we have 
done for your sake, to magnify you and also to strengthen you and to teach you. 
You do not need to ask what we have done from Adam to Noah, to Abraham, to 
Lot, or from Sodom to Isaac, to Jacob, to Joseph, to the great Prophet Moses, the 
revealer of the faith. With regard to Adam: we stood and we magniﬁed him 
greatly. With regard to Noah: we appeared and sat in his ark. And also (to) Abra-
ham, we appeared to him to announce him. And also to Isaac, in order to redeem 
him. We did not appear except to these good and perfect ones, and you need not 
inquire about the deed of Lot and Sodom, for their matter is revealed to you. If 
you want to know the secret of our deed with Isaac, when he was tied on the 
altar, see how we proclaimed aloud: Do not lay your hand […] or do anything 
(Gen. 22:12). And also with Jacob when he arose and crossed the river Jordan, we 
split it and he passed in peace, as it is said: and he arose and crossed the river 
(Gen. 31:21), and we magniﬁed him greatly and we empowered his rank. And he 
was elevated with a blessing for him and his descendants afer him. If you act 
according to that rank, indeed we turn you away from the deeds of Sodom. But if 
you turn back from the path of the True One, what has been done to the people 
of Sodom will fall on you. Thus wrote the True One: an overthrow like that of 
Sodom and Gomorrah (Deut. 29:23). We shall come and accomplish it and we 
shall not appear until an exceedingly great judgement is done, with no mercy. 
Praised be the Potent who made us witnesses, who announce about every good 
and every evil. And we stand and magnify any deed that has no blemish and is 
wholly delight.”','נחרד נא מן הדברים שיצאו מפי המלאכים וגם מפי הכבוד. מן המלאכים – תוכחה לכל הדורות, ומן הכבוד – חרב שלופה בעת צרה. אמרו המלאכים: "הו עדה, דבקי (באל) והתחזקי באמונה, כי בידינו הטובה, ובידינו הגאולה, ובידינו העונג, ובידינו הרווחה, ובידינו ההשמדה, ובידינו הייסורים, ובידינו המוות, ובידינו הכיליון. את כל זה עשינו למענך, להגדילך ולחזקך וללמדך. אין לך לשאול מה עשינו מאדם ועד נוח, ועד אברהם, ועד לוט, ומסדום ועד יצחק, ועד יעקב, ועד יוסף, ועד הנביא הגדול משה, גלה האמונה. באשר לאדם – עמדנו והגדלנוהו מאוד. באשר לנוח – נגלינו וישבנו בתיבתו. וכן לאברהם נגלינו לבשר אותו. וכן ליצחק, כדי לגאול אותו. לא נגלינו אלא לאותם טובים ותמימים, ואין לך לדרוש במעשה לוט וסדום, כי עניינם גלוי לך. אם תרצה לדעת את סוד מעשינו עם יצחק בשעה שנעקד על המזבח, ראה כיצד קראנו בקול: אל תשלח ידך [...] ואל תעש לו מאומה (בראשית כב,יב). וכן עם יעקב כשקם ועבר את נהר הירדן – קרענוהו ועבר בשלום, כפי שנאמר: ויקם ויעבור את הנהר (בראשית לא,כא), והגדלנוהו מאוד וחיזקנו את מעמדו. והוא נתעלה בברכה לו ולצאצאיו אחריו. אם תנהגו לפי אותו מעמד, הרי נסיר אתכם ממעשי סדום. אך אם תסורו מדרך האמת, יפול עליכם מה שנעשה לאנשי סדום. כן כתב האמת: מהפכה כסדום ועמורה (דברים כט,כב). נבוא ונבצע זאת ולא נגלה עד אשר ייעשה משפט גדול ביותר, ללא רחמים. ברוך הגיבור שעשה אותנו עדים, המבשרים על כל טוב וכל רע. ואנו עומדים ומגדילים כל מעשה שאין בו פגם והוא עונג כולו."');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (120,'III','72a','וידבר משה והכהנים הלוים',3000722,'ארור שכב עם אחותו מקדם אזהר מן הדה בישתה ואכהן קלל מן יעבדנה נתן אפרשו גדילה רבה ונמלי לבן מן נהרה דחכמתה דמה דני מכללין מכל איקר דאנן כדו קדמין על מלה תדמי למלה דאתקדמת','Cursed be he who lies with his sister (Deut. 27:22). Previously, He warned 
against this evil, and here He cursed those who do it. Let us set out a great divi-
sion and ﬁll our heart with the light of wisdom, and hopefully we may be 
crowned with all honor. We approach now a matter that resembles the previous 
matter.','ארור שוכב עם אחותו (דברים כז,כב). לפני כן הזהיר מפני הרע הזה, וכאן קילל את עושיו. נפתח חלוקה גדולה ונמלא את לבנו באור החכמה, ואולי נזכה להיות מוכתרים בכל כבוד. אנו ניגשים כעת לעניין הדומה לעניין הקודם.');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (121,'III','75','וידבר משה והכהנים הלוים',3000751,'אי נפש תהי צריכה אי עתירה לא יעבד במדלה מה יאבד נפשה בעלמה ובאחרה בישה דגזוה דו סכה באהן עובדה עסרה סכוהן חדין ללבה וגלית קמיך עסרה גזוהן עבדת יתון חדה קבל חדה בלש יקים בניו בידה דסכה יעבד בחברה אנה עביד בה ומסב חלקה דיהבת לה נסב אנה דלה ויהבנה לה ומקים תאותה במקטל חברה קטול אנה לה ] ב [ מיני ] מ [ עואן והן הוה ביניו › ן ‹ דבבו ואנסב קשטה באדה דבב הוא לי וילה בכן והן בלש מיתובה רמה מפל אנה לה מן מיתובתה דלה והן בלש יגזי יתה לקבל עמל ולא אתרחי בי אנה אעמי יתה יכלותי והן בלש יגלי אד דיכלו אנה מעמינה קצירות אדה ואן בלש יודיע באדה גברו אני מגלי לה גבורתי והן סכה הן עתירותה הי דאמטתה אל תאות נפשה מחסכה אנה מן הדה ומן הדה והן אתחכם דהדה טמירה בישה מגלי יתה אנה קמי 22* אנשה עד לא יסכי דו עבוד בכסי עובד מכעס לי אלא אגלינה וידע כלה הן לית יפלה מני כלום מכל עובד דיתעבד אוי לאנש דיהי מסכי דגדלי רבה יתכסי ממו כלום','Whether a person is poor or wealthy he should not do with his posses-
sions what may destroy himself in this world and in the world to come. The evil 
he was punished with (was) because he sought in this matter ten requests that 
gladden his heart. But I revealed before you ten punishments that I did – one 
punishment against one action. (If) he seeks to place his (the victim’s) sons in 
his hand – what he seeks to do to his fellow I shall do to him. I shall take his 
share that I had given to him, and give it to him (the victim). (If) he fulﬁlls his 
lust to kill his fellow, I shall kill him with various plagues. And if hatred was be-
tween them and he takes justice into his own hands, he is My enemy. Woe to him 
because of this. If he seeks a high rank, I shall throw him down from his rank. If 
he expects that (God) rewards him according to his deed, but did not go through 
Me, I shall show him My might. If he seeks to show a powerful hand, I shall show 
him the weakness of his hand. And if he seeks to make known his strength, I 
shall reveal to him My strength. If he thinks that it is his wealth that brought him 
to implement the desire of his soul, I shall withhold him from this and from this. 
If it becomes evident that his is an evil intention, I shall reveal it before people, 
so that he may not think that he does in secret a deed that enrages me. I shall 
reveal it, and everyone will know that nothing is remote from Me, of any deed 
that is done. Woe to the one who expects that anything would be hidden from 
My majesty.','בין אם אדם עני ובין אם עשיר, אל יעשה בנכסיו מה שעלול לאבדו בעולם הזה ובעולם הבא. הרעה שנענש בה הייתה מפני שביקש בעניין זה עשרה דברים המשמחים את לבו. אך אני גיליתי לפניכם עשר עונשים שעשיתי – עונש אחד כנגד מעשה אחד. אם ביקש לשים את בניו של הקורבן בידו – מה שביקש לעשות לחברו אעשה לו. אקח את חלקו שנתתי לו ואתנו לו לחברו. אם מילא תאוותו להרוג את חברו – אהרגנו במכות שונות. ואם הייתה שנאה ביניהם ונוקם בידו – הוא אויבי; אוי לו מפני כך. אם ביקש מעמד רם – אשליכנו ממעמדו. אם ציפה כי יגמול לו האל כמעשהו, אך לא בא דרכי – אראה לו את עוצמתי. אם ביקש להראות יד חזקה – אראה לו את חולשת ידו. ואם ביקש להודיע את גבורתו – אגלה לו את גבורתי. אם חשב כי עושרו הביאו להשלים את תאוות נפשו – אמנעו מזה ומזה. ואם יתברר כי כוונתו רעה – אגלה אותה לפני הבריות, כדי שלא יחשוב כי עושה בסתר מעשה המרגיז אותי. אגלה אותו, ויידעו הכול כי אין דבר נסתר ממני, מכל מעשה הנעשה. אוי למי שמצפה כי ייסתר ממני דבר כלשהו.');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (122,'III','76','וידבר משה והכהנים הלוים',3000761,'נרכן לחילה ונשתעבד לגדלה ונתפני מן אנשים דאה עובדון ודן מדעה בישה מדעון וילון במה חשבו לינן ככן ולא לה אתילפנן ולינן פנין לה לעלם אלא נדע הן מרן 22* רחמן ורתאה ידע רזי כל לבביה וטמיראת כל עניניה ולא יפלא ממנו כלום והוא מגלינה אם טב אם ביש והן בלש יתה בלוש בלב אדכי הוא מיטב לידה ועני מבלשה והן הוה לבה מתפני מנה לא ישמע לה ויעזר עליו קלל רב עמי פרעה כד בלש יתה והוה טמירה ביש מה כתב קמיך והתקף לב פרעה צפי הדה תקיפותה הך הות ורבי מדעך במד תחכם לא תקף ית לבה אלאן בדיל תלתה עובדין עבדו קדמיו סימניה דמזעין דאקימונה בבלוד רב תקף לבה עד קעם ביתה רגשה דו מבלד לכל חזוי ותליתה בדיל מימרה דאתמר לאברהם הלא לא שלם חוב אמראה סעד אכה רבותה ליכלותה הממן לחודה עם דריה וחליפותם נודי לגדלה ונרכן קדם גבורתה ונסיד ונימר לית אלה אלא אחד','Let us bow down before His might and submit to His greatness and turn 
away from people whose deeds are such and whose mind is this evil mind. Woe 
to them because of what they thought. We are not like this and we did not learn 
this, and we never approach this, but let us know that our master is merciful and 
graceful. He knows the secrets of all hearts and the inner thoughts of all minds, 
and nothing is remote from Him, and He reveals them whether good or evil. If a 
seeker seeks Him with a pure heart, He beneﬁts him and responds to his request. 
But if his heart turns away from Him, He will not listen to him and returns a 
great curse on him. See Pharaoh, when he sought Him with a bad intention, as 
He wrote before you: Pharaoh’s heart stiﬀened (Exod. 8:15). Observe this stiﬀen-
ing [and what it was and elevate your mind with what you are going to learn. He 
did not stiﬀen his heart except because of three deeds which they (Moses and 
Aaron) did before him – the disturbing wonders that set him in great fear. He 
stiﬀened his heart until he stood in the excitement that frightens anyone who be-
holds. And the three – because of the saying that has been told to Abraham: for 
the iniquity of the Amorites is not yet complete (Gen. 15:16). Greatness to His might 
which alone endures throughout the generations and their successions. Let us 
thank His greatness and bow down before His power and testify and say: “There 
is no god but One.”]','נכרע לפני עוצמתו ונשתחווה לגדולתו ונסור מאנשים שמעשיהם כך ושדעתם היא הדעת הרעה הזאת. אוי להם בשל מה שחשבו. אנחנו אינם כך ולא למדנו זאת, ולא נתקרב לזה לעולם, אלא נדע כי אדוננו רחום וחנון. הוא יודע את סתרי כל הלבבות ואת מחשבות כל המוחות, ואין דבר נסתר ממנו, והוא מגלה אותם – בין טוב ובין רע. אם מבקש מבקש אותו בלב טהור, הוא מיטיב לו ועונה לבקשתו. אך אם לבו סר ממנו, לא ישמע לו, וישיב עליו קללה גדולה. ראה את פרעה, כאשר ביקש אותו בכוונה רעה, כפי שכתב לפניכם: וַיֶּחֱזַק לֵב פַּרְעֹה (שמות ח,טו). התבונן בחיזוק הזה [ומהו, ורומם את דעתך במה שאתה עומד ללמוד. לא חיזק את לבו אלא בשל שלושה מעשים שעשו לפניו – הנפלאות המבהילות שהכניסו אותו לפחד גדול. חיזק את לבו עד שעמד בסערה שמבהילה כל רואה. והשלושה – בשל הדבר שנאמר לאברהם: כִּי לֹא שָׁלֵם עֲוֹן הָאֱמֹרִי (בראשית טו,טז). גדולה לעוצמתו שלו בלבד קיימת בכל הדורות ותחלופותיהם. נודה לגדולתו ונכרע לפני כוחו ונעיד ונאמר: "אין אלוהים אלא אחד."]');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (123,'III','40','וידבר משה והכהנים הלוים',3000401,'ודמה יתכון לכוכבי שומיה בדיל תהונו קדש כל אמיה ויהב לזרעך ית כל ארעיה אלין אודו לאלה דאמלה יתכון בכן והתברכו בזרעך כל גוי הארץ אתקוממו על טובה יקום לוכון כל דאה לא תמרי אלין מליה דאנון לקבל עובד מרחי ואתון מלכתון מד אמר קשטה עבדו עובד ימן מד מלכתון ותהונו כות יצחק מתרבי כמד ברכה אלה ומלתה מכל איקר ואזל לביר שבע ותירתון אף ברכת יעקב דאתרבה בה בחלמה והיא תרי עסר מלה אתמרת כהלון לוכון לאיטבו','He made you similar to the stars of the heaven, so that you may be the 
holiest of all nations and He might give to your heirs all these lands (Gen. 26:4). 
Give thanks to God who has appointed you by this, so that all the nations of the 
earth shall bless themselves by your heirs (Gen. 22:18). Persevere in (doing) good 
– all this will last for you. Do not act rebelliously (against) these words, for they 
regard a pleasing deed, and (then) you possess what the True One said. Act in 
such a way that your possession may last, and you may be like Isaac, gloriﬁed as 
God blessed him, and appointed him to every honor, (as) he went to Beer Sheba. 
You also will inherit the blessing of Jacob, who was gloriﬁed with it in his dream 
– it (consists of) twelve words, all of them said for your beneﬁt.','הוא עשה אותך דומה לכוכבי השמים, כדי שתהיה קדוש שבכל העמים ויתן לצאצאיך את כל הארצות הללו (בראשית כו,ד). הודה לאל שייעד אותך לכך, כך שכל עמי הארץ יתברכו בצאצאיך (בראשית כב,יח). התמד בטוב – כל זה יתקיים בך. אל תמרוד בדברים אלה, שכן הם עוסקים במעשה נאה, וכך תירש את אשר אמר הנאמן. נהג כך שירושתך תתקיים, ותהיה כיצחק, שנתכבד בכך שאלוהים ברכו ומינהו לכל כבוד, כאשר הלך לבאר שבע. גם אתה תירש את ברכת יעקב, שנתכבד בה בחלומו – היא כוללת שתים עשרה מילים, וכולן נאמרו לטובתך.');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (124,'III','45','וידבר משה והכהנים הלוים',3000451,'הוא משרי ואמר מלה אתחזי אלה ומלל בה כל קהלה ברבו ארור גבר דיעבד פסל וכל דמו דר ] ש [ גדלה יל ] בט [ מן יעבד ] אהן [ עובדה ב ] גלי [ ובסתר ד ] אנה [ אמר לא תע ] בד [ לך פסל וכ ] ל [ תמונה עמי כדו אהן רזה וחכם מד לה חכמתך ולא תשבקנה','He begins and says a word that God Himself revealed and said it (to) all 
the congregation in greatness. Cursed be anyone who makes a sculptured or 
molten image (Deut. 27:15) – His greatness sought to curse the one who does this 
deed openly or secretly. For I said: You shall not make for yourself a sculptured 
image, or any likeness (Exod. 20:3). See now this mystery and know what I have 
taught you and do not abandon it.','הוא פותח ואומר דבר שהאל בעצמו גילה ואמר אותו לכל הקהל בגדולה. אָרוּר עֹשֵׂה פֶסֶל וּמַסֵּכָה (דברים כז,טו) – גדולתו ביקשה לקלל את מי שעושה מעשה זה בגלוי או בסתר. כי אמרתי: לֹא תַעֲשֶׂה לְךָ פֶסֶל וְכָל תְּמוּנָה (שמות כ,ג). ראה נא את הסוד הזה ודע את מה שלימדתיך ואל תעזבהו.');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (125,'III','59','וידבר משה והכהנים הלוים',3000591,'דאה החתמה בממללה אכה אב בלך לא תחלף אלין מליה תקום בקלל רב מותר לא תרבי לבך על תלימיך במדלך תקום באשדה ואנה מזדכי מנך לא תרבי מלכותך על עסרה גנואן אמסכן יתך ואנון נע ונד ושכיר ואביון ועני ויתום ואלמנה וגר ותושב ודל אלין לא תאמץ לבך עליון השפנך לא תפשט אדך אל לוי אקרך ותסב מד לה אנה דאן לה לא תתלי מליך על כהן במשכנך אנה חלקה ואתה תהי נפיל לא תשוי יכלותך על האלין אנשש חילך ואמחי דכרנך ולא תבלש מד לית לך בה חלק אקימך במסכינו ולא תסב מד ליתו לך עד תוזף בה מהו בידך תתנצל מכלה ותעזר פני מכל איקר ותרבי עול ומבטל קשטה ותתלי אדך ותקים מליך ותרחם › ל ‹ נפשך מד לא רחמו לך מרך ולא אתרחיה לך הן נסבת באדך מד ליתו לך דאדה נתחיה למעבד בך כל דין והן תבלש אוזפו על מהו בידך אנה } ו { מקימך במסכינו רבה והן תרבי עול אנה דיאן קשט אעבד בך כל דין והן תקים מליך כי מלי רמה כעטף אגלי › א ‹ בדותך והן תרחם נפשך בבישהתה אנה סני לה ומזרז אבדנה לית חילי רבה מתלי אפים אלא מקים קשטה עם רבה וזעורה ולא תעבר על הדה מלתה תשתיר בלבט רב וקשי ומן סכה אן יעבד בכסי לית מסתר מני כלום כי לי כסיהתה כות גליהתה לא יפלא מעלי עובד דיתעבד נדע כהלן דן רזה רבה ולא נשבק קנומן פני מנה לעלם ישתבח אמורה דאמר ועבד לית יתהפך עליו מלה מן המלים דאמרה נודי לחילה ונרכן לגדלה ונסיד ונימר לית אלה אלא אחד','This is the conclusion of the matter here. Pay attention and do not alter 
these words, (lest) you will be under an exceedingly great curse. Do not lif up 
your heart over your brother with your possessions, (lest) you will be in distress, 
and I am exempt from you. Do not increase your possessions over ten sorts (of 
people), (lest) I will impoverish you. These are they: the wanderer, the drifer, 
the hired laborer, the pauper, the poor, the orphan, the widow, the sojourner, the 
resident, the needy – against these you should not harden your heart, (lest) I 
will weaken you. Do not stretch your hand to the Levite who (lives) with you to 
take what is his – I will be judging (for) him. Do not raise your voice against the 
priest in your sanctuary – I am his portion and you will fail. Do not use your 
force against these – I will weaken your power and blot out your memory. Do not 
seek what does not pertain to you, (lest) I will set you in poverty. Do not take 
(possession of) what is not yours in order to add to your property, (lest) you will 
be stripped of everything and you will turn back empty of all possession. You in-
crease injustice and abolishment of truth, and you raise your hand and lif your 
words and love your soul – while your Master did not love it and was not favor-
able to it concerning you. If you take in your hand what is not yours, My hand is 
stretched out to do to you every judgement. If you seek addition on what you 
already have, I will place you in great poverty. If you increase injustice, I am a 
just judge, I will apply to you every punishment. If you lif your words, indeed 
my word is elevated, in a moment I will bring about your destruction. If you love 
your soul in evil, I hate it and urge its destruction. My great might does not show 
favor, but implements the truth with great and small (alike). If you transgress 
this matter, you will remain in great and hard aﬄiction. He who sought to do 
(evil) in secret, nothing is hidden from Me, for the Concealed are mine, as are the 
Overt. No deed that is done is too remote from me. Let us all know this great mys-
tery and never abandon ourselves deviating from it. Praised be the Sayer who 
says and does, and none of the words He says is overturned. Let us give thanks 
to the Mighty One and bow down to his greatness and testify and say: “There is 
no god but One.”','זו היא מסקנת הדברים כאן. הקשב ואל תשנה דברים אלה, (פן) תהיה תחת קללה גדולה ביותר. אל תגביה לבך על אחיך בגלל רכושך, (פן) תהיה בצרה ואני פטור ממך. אל תרבה את רכושך על חשבון עשרה סוגים (של אנשים), (פן) אעניך. ואלה הם: הנע, הנד, שכיר היום, האביון, העני, היתום, האלמנה, הגר, התושב, הנצרך – כנגד אלה אל תקשה את לבך, (פן) אחלישך. אל תשלח ידך אל הלוי השוכן אצלך לקחת את שלו – אני שופט עבורו. אל תרים קולך נגד הכוהן במקדשך – אני חלקו ואתה תיכשל. אל תנצל את כוחך כנגד אלה – אחליש את עוזך ואמחה את זכרך. אל תבקש מה שאינו שייך לך, (פן) אשים אותך בעוני. אל תיקח את שאינו שלך כדי להוסיף על רכושך, (פן) תישלל מכל ותשוב ריקם מכל קניין. אתה מרבה עוול ומבטל אמת, ואתה מרים ידך ומגביה דבריך ואוהב את נפשך – בעוד שאדונך לא אהבה ולא נתרצה אליה בעניינך. אם תיקח בידך את שאינו שלך, ידי שלוחה לעשות בך כל משפט. אם תבקש תוספת על מה שכבר יש לך, אשים אותך בעוני גדול. אם תרבה עוול, אני שופט צדק, אחיל עליך כל עונש. אם תגביה את דבריך, הרי דברי מרומם, ברגע אחד אביא את כילויך. אם תאהב את נפשך ברע, אני שונאה ומחיש את אבדנה. עוזי הגדול אינו נושא פנים, אלא מיישם את האמת עם גדול וקטן כאחד. אם תעבור על דבר זה, תישאר בייסורים גדולים וקשים. מי שביקש לעשות (רע) בסתר, אין דבר נסתר ממני, כי הנסתרות שלי הן, וכן הנגלות. אין מעשה הנעשה שהוא רחוק ממני. נדע נא כולנו את הסוד הגדול הזה ולא נרשה לעצמנו לסור ממנו לעולם. ברוך האומר האומר ועושה, ואין אחד מן הדברים שהוא אומר נהפך. נודה לגיבור ונשתחווה לגדולתו ונעיד ונאמר: "אין אלוה אלא אחד."');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (126,'III','53','וידבר משה והכהנים הלוים',3000531,'חסל זרע אברהם יהי נזיף בעלמה ומטרד מכל אתר ומבתר קדשה יתחלל ובתר ברכתה יהי מקלל ובתר הטהרה יטמא דן מללה לא יהי וליתו לאוי לוכון ולא לאבהתכון עמו מה לוכון עביד ואדכרוה ולא תנשונה דבבכון הטרד מן שרואה בסימנים ובתניאנה אביד קמיכון ובתליתה הקטל באדיכון מה דה שהותה רבתה חסלכון תהונו ככן ויתחלף איקרה בקלל לא תשבקו דן איקרה ולא תהי שרה מציקה ויצחק מכעס ויעקב שמם ומחלפי קשטה חדים ורחומי בישתה מצתדים ואתון בכל דין יתר מסכים עמל טב ולית תמן אנחה ותימרו דאתון טבין ואתון במכאוב חיול ואלה מזדכי מנוכון נודי למרן הממן לחודה ולית ימטי בה חלוף לעלם','Far be it from the descendants of Abraham to be rebuked in the world, 
expelled from every place; afer the holiness, to be profaned, afer the blessing, 
to be cursed, afer the purity, to be polluted. Let this matter not be; it is not ap-
propriate to you and not to your fathers. See what is proper for you and remem-
ber it and do not forget it. Your enemy was banished from the beginning by won-
ders. The second time he perished before you and the third time he was killed by 
you. What is this great corruption? Far be it from you to be like this, and for the 
glory to be changed by curse. Do not abandon this glory, lest Sarah be distressed 
and Isaac angered and Jacob desolated, and those who substitute for the True 
One be joyful, and the devotees of evil be mocking, and you ﬁnd yourself in ex-
cessively great punishment, seeking for good reward – but with no beneﬁt there. 
And you say that you are good, but you are in mighty pain, while God exempts 
Himself with regard to you. Let us give thanks to our Master who endures by 
Himself and no substitute reaches Him forever.','חלילה לצאצאי אברהם שייגערו בעולם, ויגורשו מכל מקום; אחר הקדושה, להיות מחוללים; אחר הברכה, להיות מקוללים; אחר הטהרה, להיות מטומאים. אל יהיה הדבר הזה; אין הוא הולם אתכם ולא את אבותיכם. ראו מה ראוי לכם, זכרו אותו ואל תשכחוהו. אויבכם הוגלה מן הראשית בניסים. בפעם השנייה אבד לפניכם ובפעם השלישית הומת בידיכם. מהו השחתה הגדולה הזאת? חלילה לכם להיות כך, ולכבוד שייהפך לקללה. אל תזנחו את הכבוד הזה, פן תעצב שרה ויכעס יצחק ויישאר יעקב שומם, ויישמחו המחליפים את האמת, וישחקו עובדי הרע, ותמצאו עצמכם בעונש גדול ביותר, מחפשים שכר טוב – אך ללא תועלת שם. ותאמרו שאתם טובים, אך אתם בכאב עצום, ואילו האל פוטר עצמו מכם. נודה לאדוננו המתקיים מאליו ואין שום תחליף מגיע לו לעולם.');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (127,'III','68','וידבר משה והכהנים הלוים',3000681,'נתן אפרשו גדילה וניעל ליד אמדינה כהלה פוגגו מדינה רישה ועקבה אוכחו כי גדלה אמר מלין שררו איטבו ורבו רחמו אזהר מן עובד ביש צמת עשרה גנואן חיולין ארור שכב עם אשת אביו הדה גנוה רבה וילה לאנש דיעבדנה עמי גנואתה דצמתת כל חדה מנון גזוה קטלה טמא מדמך אבוה ושבקה מחלל והן הולד בר אזדעק בר זנו אזדנה באבוה ועוד באמה דהוה רכב בסר תריון דאבוה ואמה תריון כחדה גלה ערות אבוה ואמה שילה כדו שמענה מנהן › לה הן ‹ ערות אנש מדמכה עמה איזל ליד קצת ערותה וק › ר ‹ ינה וכיתך מדע אהן רזה גבר גבר לכל חמיר בסרה לא תקרבון למגלה ערוה דאה היא ערות אנשה לקנומה לא יקרב קנומה למפשט אל בישה ואף אלה אמר ממלל חורן גנות אתת אחוך לא תגלה עמי מה שרר גדלה ואמר ערות אחוך היא ליתה צריך מבקר על כן','Let us set out a great division and enter a domain wholly of delight. A 
domain whose beginning and end are reproof. Indeed, the Great One said words 
that strengthened beneﬁt and increased mercy. He warned about a bad deed 
comprised of ten mighty disgraces: Cursed be he who lies with his father’s wife 
(Deut. 27:20) – this is a great disgrace, woe to the man who does it. See the dis-
graces that it includes; for each of them, its penalty is death. He deﬁled his 
father’s bed and lef it profaned. And if a son was born, he was called a child of 
adultery. He acted promiscuously towards his father and also towards his 
mother by joining the ﬂesh of both: of his father and of his mother, both togeth-
er. He uncovered the nakedness of his father and his mother. A question, listen 
to it now: whence do we (know) that the disgrace of a man is his lying with her? 
Go to the section of the “copulation” and read it, and indeed you will know this 
mystery: None of you shall approach any one near of kin to him to uncover 
nakedness (Lev. 18:6). This is the copulation of a man with himself. Let him not 
draw himself near to evil, for God has said another statement: Do not uncover the 
nakedness of your brother’s wife (Lev. 18:16). See how His Greatness emphasized 
it and said: it is the nakedness of your brother (ibid.). There is no need to (further) 
inquire about this.','נציג חלוקה גדולה ונכנס לתחום של תענוג שלם. תחום שתחילתו וסופו הם תוכחה. אכן, הגדול אמר דברים שחיזקו את הטובה והגדילו את הרחמים. הזהיר על מעשה רע הכולל עשרה בושות גדולות: ארור שוכב עם אשת אביו (דברים כז,כ) – זוהי בושה גדולה, אוי לאדם שעושה אותה. ראו את הבושות הכלולות בה; כל אחת מהן עונשה מוות. חילל את משכב אביו והניחו מחולל. ואם נולד בן, קראוהו ילד ממזר. התנהג בזנות כלפי אביו וגם כלפי אמו בהצטרפו לבשר שניהם: בשר אביו ובשר אמו, שניהם יחד. גילה את ערוות אביו ואמו. שאלה, שמעו אותה עתה: מנין לנו שבושת האדם היא שכיבתו עמה? לכו אל פרשת "הגילוי" וקראו בה, ואכן תדעו את הסוד הזה: איש איש אל כל שאר בשרו לא תקרבו לגלות ערוה (ויקרא יח,ו). זוהי שכיבת האדם עם עצמו. לא יקרב את עצמו לרעה, שכן האלוהים אמר דבר נוסף: ערוות אשת אחיך לא תגלה (ויקרא יח,טז). ראו כיצד גדולתו הדגישה זאת ואמרה: ערוות אחיך הוא (שם). אין צורך (עוד) לחקור בכך.');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (128,'III','9','וידבר משה והכהנים הלוים',3000091,'שיאלה כדו אתפרס מן לב מכלל בנהרה רבה למה הדה כהנה ליתו מקבל ויעזר ליד מיתוביתה דהות לה אתמל שמע האגבו על שילתך עד תתוזף בנהר האגבו כי כהנה קדיש וכל קדש בעלמה כד יסתיב איך יהי קדש אנש ינדי ליד משכנה בהמה נדר והיא באדה שלמה עד האן אנדתה וליתו זבנה דקרבנה ובא עליה מום תיעל ליד משכנה דמע יתפרש עד יתיהב לכהנה יסתיב ביד דינדינה לאוי לכהנה ייכלנה אי יעבד בה מה אמר אלה ביד כהנה מתמסר לאשתה עד יחכם כהנה דו לה מדמי וביד בראי יוסף חמושה ודמעה לא יתיהב לכהנה לעלם הלא אדכיותה אסתלקת מנה להדה ליתו מתרחי ולא מתאכל וכנו כהנה מדמי לדמעה דאסתיב בחוב חסילה היא מנה רב הוא מרן הממן לחודה דגלה לנן חכמה כהלה חיים','A question fans out now from a mind crowned with great light: Why is 
this priest not accepted and (does not) return to his rank that he had yesterday? 
Hear the answer to your question, so that you may be magniﬁed with the insight 
of the answer: Because the priest is holy and any holy thing in the world, once it 
becomes deﬁled – how would it be holy (again)? If someone brings to the sanc-
tuary a beast as a votive oﬀering and it is perfect in his hand when he brings it, 
but it is not the (proper) time to perform the oﬀering and a blemish reaches it, 
will it enter the sanctuary? An oﬀering that is separated (in order) to be given to 
the priest, if it becomes deﬁled in the donor’s hand, is it appropriate for the 
priest to consume it, or to do with it what God commanded him? (If it is deﬁled) 
in the priest’s hand, it should be handed down to the ﬁre so that the priest may 
know that it is deﬁled, like he is. But if (it became deﬁled) while in the hand of 
an alien, (the donor) will add a ﬁfh and his oﬀering will never be given to the 
priest, for its purity has been removed from it. Therefore, it is not desirable and 
will not be consumed. Similarly, the priest resembles to the oﬀering: (if) he is de-
ﬁled by a sin, (the priesthood) is removed from him. Great is our Master, who en-
dures alone, who revealed to us wisdom that is wholly life.','שאלה מתפרשת עתה מן השכל המעוטר באור גדול: מדוע אין הכוהן הזה מתקבל ואינו חוזר למעמדו שהיה לו אתמול? שמע תשובה לשאלתך, כדי שתתגדל בתובנת התשובה: מפני שהכוהן קדוש, וכל דבר קדוש בעולם, כשנטמא – כיצד יהיה קדוש שוב? אם מישהו מביא למקדש בהמה כנדר והיא תמימה בידו כשהוא מביאה, אך עדיין לא הגיע זמן ההקרבה ופגם מגיע אליה – האם תיכנס למקדש? קרבן המופרש כדי להינתן לכוהן, אם נטמא בידי הנותן, האם ראוי שהכוהן יאכלנו, או לעשות בו כפי שציווה האלוהים? אם נטמא בידי הכוהן, יש למסרו לאש כדי שהכוהן יידע שהוא טמא, כמותו. אך אם נטמא בידי זר, הנותן יוסיף חומש ונסכו לא יינתן לכוהן לעולם, כי טהרתו נלקחה ממנו. לכן אינו רצוי ולא ייאכל. כך הכוהן דומה לקרבן: אם נטמא בחטא, הכהונה נלקחת ממנו. גדול הוא אדוננו המתקיים לבדו, שגילה לנו חכמה שהיא כולה חיים.');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (129,'III','26','וידבר משה והכהנים הלוים',3000261,'ואנשים אמרו ממלל עורן בדיל יוסף דו דפרט ברכתה וכד השתאלו על יתה ממללה אמרו בדיל יוסף דו חברה דאתרה אמיר לון על מד מללו ממלל ידועיה יתה ישמעו יוסף בריך וארעה בריכה דילה ממלכה לית לידה כהנה והן הוה יוסף חברה דביתה וכל אחיו לידה יזדמנו לא אתמר עליו לשרת ולברך ודן הוא לשבט לוי מיסתה','People have said another word regarding Joseph, that he was the one 
who pronounced the Blessing. When they were asked about that matter, they 
spoke concerning Joseph, that he is the owner of the place. It was said to them, 
about what they said, a statement which those who know will understand: 
“Joseph is blessed and his land is blessed. He owns kingship, not priesthood. If 
Joseph is the owner of the house and all his brethren are gathered together 
(around) him, it is still not said concerning him: To minister and to bless (Deut. 
21:5). This is the prerogative of the tribe of Levi alone.”','אנשים אמרו דבר אחר בעניין יוסף, שהוא היה זה שאמר את הברכה. כאשר נשאלו על הדבר הזה, דיברו על יוסף, שהוא בעל המקום. נאמר להם, על מה שאמרו, דבר שיבינו אותו היודעים: "יוסף מבורך ואדמתו מבורכת. הוא בעל מלכות, לא כהונה. ואף אם יוסף הוא בעל הבית וכל אחיו נקבצים סביבו, עדיין לא נאמר עליו: לשרת ולברך (דברים כא,ה). זו זכות שבט לוי בלבד."');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (130,'III','19','וידבר משה והכהנים הלוים',3000191,'אנדי מדעך למלי ודע הן בן נכראה לא יסק אל הרגריזים ואנן עמין דאנון ארבעה לא אתפרד אחד מן חברה אלו סלק אחד והשתירו תלתה הוינן אמרים דו לסוד עביד אתבחר מנון אחד ואתפסלו השיורין לוד אתעבד לכהלון עובד אחד לכן חכמתך הן בר נכראה לא יכל יסק להרגריזים ולא יהי מנה דיאן ולא יקום באתר כהנה והיא אזהרו לקהל ישראל בדיל בר נכראה לא יהי בון','Pay attention to my words and know that the son of a foreigner should 
not ascend to Mount Gerizim. We see that they are four and none is separated 
from his fellow. Had one of them ascended and three remained, we would have 
said that a mystery is there: one was chosen and the rest were rejected. However, 
the same deed has been done for all, therefore, (by this) I taught you that the son 
of an alien is not allowed to ascend to Mount Gerizim, and no judge will be (ap-
pointed) from among them, and he will not function as priest. This is a warning 
to the congregation of Israel concerning the son of a foreigner: he will not be 
among them.','הקשיבו לדבריי ודעו כי בן נכר לא יעלה אל הר גריזים. אנו רואים שהם ארבעה ואין אחד נפרד מחברו. אילו עלה אחד מהם ושלושה נשארו, היינו אומרים שיש שם סוד: אחד נבחר והשאר נדחו. אולם אותו מעשה נעשה לכולם, לפיכך למדתי אתכם שבן נכר אינו רשאי לעלות אל הר גריזים, ולא יהא שופט מבינותם, ולא ישמש ככוהן. זוהי אזהרה לעדת ישראל בנוגע לבן הנכר: לא יהיה בתוכם.');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (131,'III','43','וידבר משה והכהנים הלוים',3000431,'יאי לך תשוב בלבך כדו ותתב קנומך למשמע מלי קללתה ותזהר גרמך מנך ובך ותעבד עובד כשיר ירחקך מן קללתה ויקרבך ליד ברכתה וינשמך בעלמה ובאחראה אה ברכתה פרידה קמיך ועורי לוטה לא תשבק ברכתה ואתה ברה והיא לך מן העקר ותתפני אל קללתה דליתה לך ולא תקרבנך לעלם כי אבהתך מלכו זכותה ואתרבו בברכתה ולא לאוי לך תהי בר מנון עד יתמר דאת ברון בקשט בר לא יהי דמי לאבוה במן ידמי בר ארדי ומעזי קטיל בפמה דאלה ודאה עובדה הוא דקטלה לא תשבקו לקשטה ותהכו עם אלילה תתפנו מכל איקר ותקומו בקלל רב עד מותר רק התהלכו בדרך הקשט והתקלצו בה תתוחון בתרי עלמיה כי אלהכון בחרכון לכן נודי לחילה ונשבח לגדלה ונסגד קדם גבורתה רב ] ת [ ה ונזרז למ ] יל [ ף מה דאל ] פן [ אלה ונב ] רך [ ונסיד ונ ] ימר [ לית אל ] ה [ אלא אחד','It is appropriate that you should return to your heart now and set your-
self to hear the words of the Curse and warn yourself, by yourself, and do an ap-
propriate deed, which will remove you from the Curse and will bring you near 
the Blessing, and will relieve you in this world and in the world to come. Behold, 
the Blessing is pronounced before you and so is the Curse. Do not abandon the 
Blessing, to which you belong and which is essence for you, and (do not) turn to-
wards the Curse, which is not for you, and let it never approach you. Indeed, 
your ancestors possessed righteousness, and were elevated through the Bless-
ing, and it is not appropriate for you to be diﬀerent from them. That way it may 
be said that indeed, you are their son. A son who does not resemble his father, 
whom will he resemble? A stubborn and rebellious son is killed by God’s com-
mand, and it is this fact that killed him. Do not forsake the True One and (do not) 
walk with the idol, for fear you will be emptied from all honor and will be cursed 
excessively. But walk on the path of truth, and cleave to it – you will live in both 
worlds, for your God has chosen you. Therefore let us give thanks to the Mighty 
and praise His greatness and bow before his great potency. And let us hurry to 
learn what God taught us, and bless and testify and say: “There is no god but 
One.”','ראוי שתשוב עתה אל לבך ותכין את עצמך לשמוע את דברי הקללה ותזהיר את עצמך בעצמך, ותעשה מעשה הולם, שיסיר אותך מן הקללה ויקרב אותך אל הברכה, וייטיב לך בעולם הזה ובעולם הבא. הנה, הברכה נאמרת לפניך וכן הקללה. אל תעזוב את הברכה, שאליה אתה שייך והיא עצמותך, ואל תפנה אל הקללה, שאינה מיועדת לך, ואל תקרב אליך לעולם. אכן, אבותיך החזיקו בצדק ונישאו על ידי הברכה, ואין זה ראוי לך שתהיה שונה מהם. כך ייאמר שאכן אתה בנם. בן שאינו דומה לאביו – למי ידמה? בן סורר ומורה נהרג בצו האל, ועצם הדבר הזה הוא שהמיתו. אל תעזוב את הנאמן ואל תלך עם האליל, שמא תרוקן מכל כבוד ותיקלל מאוד. אלא לך בדרך האמת ודבק בה – תחיה בשני העולמות, שכן אלוהיך בחר בך. לכן נודה לגיבור ונהלל את גדולתו ונשתחווה לפני עוצמתו הגדולה. ונמהר ללמוד מה שאלוהים לימדנו, ונברך ונעיד ונאמר: "אין אלוהים כי אם אחד."');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (132,'III','22','וידבר משה והכהנים הלוים',3000221,'ואן תימר בזבן דיקרי כהנה ארהותה קדישתה בבית אל צפי ית ממללה איך הו ושבח למרך ושמע אלפנה בה תגדל כד אמר לכהנ › י ‹ ה במיתי כל ישראל למחזי ית פני יהוה עמי דן רזה ושבח לאלה דאמר במיעל כל ישראל אלולי דו בעי חורן ישראל לא אמר במיעל כל ישראל ולא תימר הן מלת כל צמתת כהלון והפך פרדון כל ישראל עמי הך היא ולא תיפך מדעך לחורן כן כל ישראל אנון ונשיון ובניון לית עמון ערברוב לכן אמר במיעל כל ישראל למחזי פני יה אלהך והפך ואמר כנש ית עמה וכלולה אמר כנש הו על גיורה ועל כל מן סלק למחזי ית פני יה אלהך וסהד חורן מקים לך רישיכון שבטיכון ומן אנון רישיהון אלא ראשי שבטיה סהביכון סרפיכון וכל גבר ישראל וטפליכון ונשיכון וגיורך דבגו משרוך','If you say that when the priest reads the Holy Torah in Bet El (the so-
journer may join you), see the matter how it is, praise your Master and hear His 
teaching – by which you will be elevated. When He said to the priests: when all 
Israel come to see the Lord (Deut. 31:11), see this secret and praise God who said: 
when all Israel come. If it had not been that He meant other than Israel, He 
would not have said when all Israel come. Do not say that the word all includes 
all of them. And He speciﬁed again: all Israel – see how it is and do not turn your 
mind to anything else too. All Israel (are): they and their wives, and their chil-
dren; there is no “mixed multitude” with them. Therefore, He said when all Israel 
come to see the Lord your God. He said again: Gather the people (Deut. 31:12), and 
the whole of it. (What He) said, namely gather, regards the sojourner, and all 
who ascended to see the face of the Lord your God. Another testimony that He 
establishes to you: [your tribal heads, your tribes (Deut. 29:9) – and who are their 
heads? the heads of the tribes your elders, your oﬃcers, all the men of Israel, your 
children, your wives, and the sojourner within your camp (Deut. 29:9–10).','אם תאמר שכאשר הכוהן קורא את תורת הקודש בבית אל יצטרף אליך הגר, ראה את הדבר כפי שהוא, שבח את אדונך ושמע את תורתו – שבה תתעלה. כשאמר לכוהנים: בְּבוֹא כָל יִשְׂרָאֵל לֵרָאוֹת אֶת פְּנֵי ה'' (דברים לא,יא), ראה סוד זה ושבח את האל שאמר: בבוא כל ישראל. אילו לא התכוון לאחרים שאינם מישראל, לא היה אומר בבוא כל ישראל. אל תאמר שהמילה "כל" כוללת את כולם. והוסיף ופירט: כל ישראל – ראה כפי שהוא ואל תפנה את דעתך לדבר אחר. כל ישראל הם: הם ונשיהם וילדיהם; אין "ערב רב" עמהם. לפיכך אמר בבוא כל ישראל לראות את פני ה'' אלוהיך. ושוב אמר: הַקְהֵל אֶת הָעָם (דברים לא,יב), וכולו. מה שאמר, דהיינו הקהל, מתייחס לגר, ולכל מי שעלה לראות את פני ה'' אלוהיך. עדות נוספת שהוא מציב לך: רָאשֵׁיכֶם שִׁבְטֵיכֶם (דברים כט,ט) – ומי הם ראשיהם? רָאשֵׁיכֶם שִׁבְטֵיכֶם זִקְנֵיכֶם וְשֹׁטְרֵיכֶם כֹּל אִישׁ יִשְׂרָאֵל טַפְּכֶם נְשֵׁיכֶם וְגֵרְךָ אֲשֶׁר בְּקֶרֶב מַחֲנֶיךָ (דברים כט,ט-י).');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (133,'III','69','וידבר משה והכהנים הלוים',3000691,'כלול עסרתיתה דקמיך אתדכרו עמי יתון ושבח למרך דאזהרך מן מקרוב בישתה עד לא תטמי ותחלל אבהתך ותגלי עובד לא אתעבד בעלמה ותקטל נפשך ותיפר פרותה ותעבד אבוך מקללך עם אורכות זמנה ומרך מרגז עליך ותפל מן דרגך ותפל אבוך עמך וכן אמר יעקב לראובן בכורי אתה עלית משכבי אביך חללת יצועי עלה וכן אמר קשטה בדילה דו ריש הכעסו ורב פנו עמי רז הדה מלתה וחכמה וברר קנומך מנה לעלם דמללה מלאכה וחכמה › ב ‹ הדה גנותה דלית כותה אתא לידה ובלדה בלוד רב וליתו אתי לידה בכל זבן אלא דו מש ] ד [ ך לבה ואחס עליו ומרבינה בכל עובד גדיל ובכן חכמן דו מוכחנה מוכח חיול ואמרו אנשים מלים חורנים ליתו אלא על מפוק רחמה לית שרי לה מקים זרע לעלם כי כל זרע מרבי אבהתה ומחיל עורי מיתובית דיקום מנה ויירת אתר דיחלף יתה ואמרו אנשים מלים חורנים ליתו אלא ודיו ראובן תפך ענינה וחלל מיתוביתה וקם עליו גנו רבה מותר לאוי עלינן נזהר קנומן מדן עובדה ונשבע הן לא נקרבנה לעלם אה אפלה בישה אה עובד משף אה גנו ביש טב נזע מנה ומן מקרובה דחלה על נפשהתן אדלא נסתפי במה נעבדנה הלא קטול גרמה באדה מתבעי הנה וגם שמה ואנשי סדם סנאים לה ואנשי המבול לא עבדונה ומצראי לא גלותה ואף מובאי לא אתקרבו לידה וילה למן עבדה ותעי במדעה בתר כן והזל בתר תאות נפשה למנדי עליו לבטה רבה אסני אהן עובדה ולא תקרבה תנשם מן לבטה מן אלהך › ו ‹ מן אבהתך הלא לא ברר אלה מנה אלא › לא ‹ יתעבד לעלם וילן דאנן בעשדה במה עבדנן נדחל לאלא נסתפי ברב חובינן נגען קמי מרן וננצר לגדלה ונרכן קדם יכלותה ונרבי לגבורתה ונשאל רחמיו וחסדיו לא יטרף בעותן כי הוא רחום וחנון קרוב למי יביעינה באנצירו יתודי יכולה דגלה לן מחכום גדול נודינה על כן ונשתעבד לה על כן ונשאל חסדה ימלי יתן נטר גזריו ופקודיו כל הימים','All the ten that have been mentioned before you, see them and praise 
your Master who warned you against drawing near to evil, that you may not be-
come deﬁled and profane your parents and reveal a deed that was not done in 
the world and kill yourself and abolish fertility and make your father curse you 
constantly. Your Master would be angry with you and you would fall from your 
rank and cause your father to fall with you. This is what Jacob said to Reuben: 
You are my ﬁrst-born […] you mounted your father’s bed, you deﬁled the one who 
mounted my couch (Gen. 49:3–4). And thus said the True One about him; he is 
the beginning of anger and excelling in disfavor. See the meaning of this word, 
and know it and distance yourself from it forever. For the angel said it and in-
formed him about this disgrace; there is none like it. He came to him and 
frightened him with a great fright. (Commonly the angel) does not come to (a 
person) at any time but to comfort his heart, (as) he has pity on him, and he 
supports him in every great deed. And in this (case) he taught us that he reproofs 
him with a mighty reproof. People have said other words. (The matter) only 
concerns the progeny of the womb: he is not permitted to procreate forever, for 
every oﬀshoot exalts the fathers and also strengthens the position of the oﬀ-
shoot, and he will inherit a place which he will worsen. People have said other 
words only concerning the confession of Reuben. He altered his reasoning and 
profaned his rank, and an exceedingly great shame befell him. It is proper for us 
to warn ourselves away from such a deed and swear that we will never draw near 
to it. Behold a bad fall, behold a despicable deed, behold an evil disgrace – it is 
good that we should move away from it and from approaching it. Let fear be on 
our souls, lest we be consumed by what we do. For he who kills himself with his 
own hand (by doing it) will be prosecuted in this world and in the world to 
come. And (even) the people of Sodom hate it, and the people of the Flood did 
not do it, and the Egyptians did not reveal it, and the Moabites did not approach 
it. Woe to him who does it and whose mind strays afer this, and he walks afer 
the lust of his soul, to bring on himself a great curse. Hate this deed and do not 
approach it; (then) you will be released from the curse of your God and of your 
fathers. For God has singled out in it only that which should not be done ever. 
Woe to us, for we are in great distress because of what we have done. Let us fear, 
lest we be consumed. Let us fall down before our Master and devote (ourselves) 
to His greatness and bow before His potency and magnify his majesty and ask 
for His mercy and grace, that He may not reject our prayer. For He is merciful 
and gracious, and He is near to the one who prays to Him in devotion. Let thanks 
be given to the Potent who revealed to us a great teaching. Let us give Him thanks 
for this and submit to Him for this and ask that His grace will ﬁll us. Let us 
observe His rules and decrees always.','כל העשרה שהוזכרו לפניך – ראה אותם ושבח את אדונך שהזהירך מלהתקרב אל הרע, כדי שלא תיטמא ותחלל את הוריך ותגלה מעשה שלא נעשה בעולם ותהרוג את עצמך ותבטל את הפוריות ותגרום לאביך לקללך תמיד. אדונך יכעס עליך ותיפול ממעמדך ותגרום לאביך ליפול עמך. כך אמר יעקב לראובן: בכורי אתה [...] עלית משכבי אביך, אז חיללת יצועי עלה (בראשית מט,ג-ד). וכך אמר האמת עליו: הוא ראשית האף ויתר בחוסר חן. הבן את משמעות הדבר הזה, ודע אותו והתרחק ממנו לעולם. כי המלאך אמר זאת והודיע לו על הבושה הזאת – אין כמוה. בא אליו והפחיד אותו פחד גדול. בדרך כלל המלאך אינו בא אל האדם בכל עת אלא כדי לנחם את לבו, שכן הוא חס עליו ותומך בו בכל מעשה גדול. ובמקרה הזה לימד אותנו שהוא מוכיח אותו תוכחה עזה. אנשים אמרו דברים אחרים. העניין נוגע אך ורק לצאצאי הרחם: אסור לו לפרות לעולם, שכן כל ענף מרומם את האבות וגם מחזק את מעמד הענף, והוא יירש מקום שיקלקלנו. אנשים אמרו דברים אחרים אך ורק בנוגע לוידויו של ראובן. הוא שינה את טעמו וחילל את מעמדו, ובושה גדולה מאוד נפלה עליו. ראוי לנו להזהיר את עצמנו מפני מעשה כזה ולהישבע שלעולם לא נתקרב אליו. הנה נפילה רעה, הנה מעשה נבזה, הנה חרפה רעה – טוב לנו שנתרחק ממנה ומהתקרבות אליה. תהא יראה על נפשותינו, פן נאכל בגלל מה שנעשה. כי מי שממית את עצמו בידיו יישפט בעולם הזה ובעולם הבא. ואפילו אנשי סדום שונאים זאת, ואנשי המבול לא עשו זאת, והמצרים לא גילו זאת, והמואבים לא התקרבו אליה. אוי לו שעושה זאת ושדעתו תועה אחר כך, והולך אחר תאוות נפשו, להביא על עצמו קללה גדולה. שנא את המעשה הזה ואל תתקרב אליו, ותינצל מקללת אלוהיך ואבותיך. כי אלוהים ייחד בו אך ורק את אשר לא ייעשה לעולם. אוי לנו, כי אנו בצרה גדולה בגלל מה שעשינו. נירא פן נאכל. ניפול לפני אדוננו ונתמסר לגדולתו ונשתחווה לפני עוזו ונגדל את הדרו ונבקש את רחמיו וחסדו, שלא ידחה את תפילתנו. כי הוא רחום וחנון, וקרוב הוא למי שמתפלל אליו בהתמסרות. תינתן הודיה לגיבור שגילה לנו תורה גדולה. נודה לו על כך ונכנע לו על כך ונבקש שחסדו ימלאנו. נשמור את חוקיו ומשפטיו תמיד.');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (134,'III','21','וידבר משה והכהנים הלוים',3000211,'שמע האגבו על כל חדה מן אלין בקרבן הפסח יזדמן עמך גיורה דיתי בליש לקשטה הלא דן עובדה כעס לאלהי נכר והות הדה אמנותה ותרביתה אמר לה יקרב לעובד פסחה מקטעה ערלתה מלך אימנותה ולבש גזרה אתפרק מן בישה ואכל פסחה בריחות אלה אקרץ בצפרה קעום האן דו לא יכל יסק אל בית אל אתב קנומך האנה מגלי לך רז דן מחכומה דלה חכמתך מד את עביד אמטלתה בכל אתר ובבית מרך יכל עבד אי גיור יהי עללה אי ידור בה לבר מנך','Hear the answer to each of these. At the Passover oﬀering let the so-
journer join you, he who comes seeking the True One, for this act is exasperation 
to foreign gods. This would be his habit, and his routine. (God) said about him: 
let him approach to the deed of Passover. He whose foreskin is cut possesses the 
faith. He who is circumcised is saved from evil and eats the Passover-oﬀering 
with God’s consent. He rises early in the morning, standing where he cannot 
ascend, to Beth El. Pay attention, behold, I reveal to you the secret of this knowl-
edge, which I taught you. When you make the booths, in every place and (even) 
in the House of your Master, either a servant or a sojourner may enter or dwell 
there, apart from you.','שמע את התשובה לכל אחד מאלה. בקרבן הפסח יצטרף אליכם הגר, הבא לבקש את האמיתי, שכן מעשה זה הוא כעס לאלים נכרים. זאת תהיה דרכו ורגילותו. נאמר עליו: יגש אל מעשה הפסח. מי שערלתו נימולה מחזיק באמונה. הנימול ניצל מהרע ואוכל את קרבן הפסח ברצון אלוהים. הוא משכים בבוקר ועומד במקום שאינו יכול לעלות ממנו, לבית אל. הקשב, הנה אני מגלה לך את סוד הידע הזה אשר לימדתיך. כשאתה עושה את הסוכות, בכל מקום ואפילו בבית אדונך, עבד או גר רשאים להיכנס ולשבת שם, לצדך.');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (135,'III','72b','וידבר משה והכהנים הלוים',3000723,'ארור שכב עם חתנתו מלה בישה עד מותר אזמנת עסרה גנואן אקים קנומך לבר מן תפוכה אנש הן יקדם על הדה בישתה וילה במה דעבד ואיך יאי לאנש יקדם קנומה על עסרה גנואן כהלין בישין יטמי פגרה ויגלי פרג חתנתה ויחלל משכבה ויזני › ב ‹ קנומה דו רכב תלתה בסרהן כל אחד מנון זונה רבה ויקים פריה בישה ויוליד בנים דזנו ויתפתי בישה בעלמה ויהי מחלל תרי זרעין וילבש קללה חיולה שריר ליתך בעי מבקר על מלה מן אלין כי גזוי כל חדה מנון לוטה וילה לאנש דיהי לון עביד ויפני במדעה ליתה בישתה רבתה כי לא שררה קשטה במלת לבט אלא לא תתעבד בעלמה הטמא ועבד חובה רבה אתקטל בדילה וקללתה עליו יתודי חילה ממנה הממן לחודה ליתו מתחלף ולא מתהר חי לקלומה נודי לה בצפרה וברמשה כמה דארשתן דו מרן ועבודן וקניאנן לא נבטל כל עת מן תשבחתה דו מלך לכלה וכלה לידה מעזר כמד צבה עבד וכמ › ה ‹ בעה תקן ברבין גדיל ושלטנו יתרה לגרמה יכבד ויתקדש','Cursed be he who lies with his mother-in-law (Deut. 27:23) – an exceed-
ingly evil matter, that includes ten shameful acts – place yourself outside its per-
version. If one approaches this evil, woe to him for what he did. How is it appro-
priate for a man to approach ten disgraces, all of them evil? He deﬁles the body 
and uncovers the pudendum of his mother-in-law, and profanes her bed and 
plays harlotry with himself. He combines three close related – each of them is a 
great harlotry, and establishes a bad fruit, and begets sons of adultery, and evil 
is disseminated in the world, and he profanes two seeds, and wears a very great 
curse. You need not inquire further about any of these matters, for the repay-
ment for each of them is a curse. Woe to him to whom it applies, and turns his 
mind towards that great evil. Indeed, the True One reinforced it with the word 
“cursed” only in order that it may not be done in the world. If he deﬁled himself 
and committed a great sin, he will be put to death because of it, and the curse 
lies on him. Let thanks be given to the everlasting Potent that endures alone. He 
does not change nor is He estimable. He lives by Himself. Let us give Him thanks 
in the morning as well as in the evening, as He commanded us, for He is our 
Master and our doer, and our creator. We shall not cease at any time from prais-
ing Him, for He is the King of all, and all turns toward Him. He did as He wanted 
and as He wanted He set up in great majesty and tremendous dominion. By Him-
self He is gloriﬁed and sanctiﬁed.','ארור שוכב עם חותנתו (דברים כז,כג) – עניין רע ביותר, הכולל עשר מעשים מביישים – הצב את עצמך מחוץ לסטייתו. אם מישהו מתקרב אל הרע הזה, אוי לו על מה שעשה. כיצד ראוי לאיש להתקרב אל עשר חרפות, כולן רעות? הוא מטמא את הגוף ומגלה את ערוות חותנתו, ומחלל את מיטתה וזונה עם עצמו. הוא משלב שלוש קרובות – כל אחת מהן זנות גדולה, ומקים פרי רע, ומוליד בני ניאוף, והרע מופץ בעולם, ומחלל שני זרעים, ולובש קללה גדולה מאוד. אינך צריך לחקור עוד על אף אחד מהעניינים הללו, כי הגמול על כל אחד מהם הוא קללה. אוי למי שהדבר נוגע לו, ומפנה את דעתו אל הרע הגדול ההוא. אכן, האמת חיזק זאת במילה "ארור" אך ורק כדי שלא ייעשה בעולם. אם טימא את עצמו ועשה חטא גדול, יומת בגללו, והקללה רובצת עליו. תינתן הודיה לגיבור הנצחי המתקיים לבדו. הוא אינו משתנה ואינו ניתן לאמידה. הוא חי מעצמו. נודה לו בבוקר וגם בערב, כפי שציווה אותנו, כי הוא אדוננו ועושנו ובוראנו. לא נחדל לעולם מלשבחו, כי הוא מלך הכל, והכל פונה אליו. עשה כרצונו, וכרצונו כונן בגדולה עצומה וממשלה נוראה. מעצמו הוא מפואר ומקודש.');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (136,'III','18','וידבר משה והכהנים הלוים',3000181,'שיאלה עתד גרמך ושמע לה בדיל אשר דו מן סולה אבוה אמר ממלל טבן גלה עליו איקר יתר אשר משחה לחמה דו מחפש על טובה ומקים יתה בשרוה לא רצי במד חזה מן גוני תפוכה ונבי רבה משה אמר בדילה חורי לגו ברכתה מימר לא אתמר אלא לה בדיל ארעה דו בה מטמר דרומה ומכה מרעין יתה אמר בריך בניה אשר ויהי מרחי תלימיו מדו קמיון ייתי בגדל ויבלש דבביו ויהי פדי לון עדהאן יתגלי מה דאמר קשטה למה לא קעם על הרגריזים עם מסחני ברכתה ויהי תמן עם אחיו סעד יתחכם מד לה טמיר','A question; be prepared and listen to it. Concerning Asher, who is from a 
maidservant, his father said a good word, which revealed exceeding glory about 
him: Asher’s bread is (like) oil (ST Gen. 49:20), for he seeks goodness and will 
attain it by his might. He will not accept the various corrupted acts which he 
saw. And the great prophet Moses said about him in addition, in his blessing, a 
saying which has not been said except about him, about the land in which he 
will be interred – that heaven and earth accept him. He said: Blessed above sons 
be Asher; let him be the favorite of his brothers (Deut. 33:24). He will come before 
them in greatness, and will look for their enemies, and he will salvage them, so 
that what the True One said may be revealed: why (Asher) did not stand on 
Mount Gerizim (together) with the owners of the blessings, and stay there with 
his brothers, until it became known what was reserved for him?','שאלה; היכונו ושמעו אותה. לגבי אשר, שהוא בן שפחה, אמר עליו אביו דבר טוב שגילה עליו כבוד יתר: לֶחֶם אָשֵׁר שְׁמֵן (נוסח שומרוני בראשית מט,כ), כי הוא מחפש טוב וישיגנו בכוחו. הוא לא יקבל את מעשי השחיתות השונים שראה. והנביא הגדול משה אמר עליו עוד בברכתו דבר שלא נאמר כמוהו אלא עליו, על הארץ שבה יהא קבור – שהשמים והארץ מקבלים אותו. אמר: בָּרוּךְ מִבָּנִים אָשֵׁר יְהִי רְצוּי אֶחָיו (דברים לג,כד). הוא יקדים אותם בגדולה ויחפש את אויביהם ויצילם, כדי שיתגלה מה שאמר האמת: מדוע לא עמד אשר על הר גריזים עם בעלי הברכות, ולא נשאר שם עם אחיו, עד שנודע מה שנצור לו?');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (137,'III','27','וידבר משה והכהנים הלוים',3000271,'ואנשים אמרו הך יהי גבר אחד ממלל וקלה משתמע לגו משריתה הו מדמי למשה הך דהוה בטור סיני ממלל וכל קהלה שמעים ישר אמורה במה דאמר ברטה בחכמה חיולה שמע אגבו יחיל מדעך וירבי לבך מנה דיתעבד כל עת מריח לאלה סימניה יהונו לה מרבים עד האן יתעבד כלה לסעדו וירבינה בכל מד יתעבד ודן עובדה מריח לאלה יגדל מדעה דמנה אזדאן והמלא רוחה כלה חכמה אניתה בעי מדע רזי ממלליה אקים מדעך האן דו קשטה ושבק רוחה דנפשה דלית בה חנאה','People have said: “How can one man speak and his voice be heard 
throughout the camp? Does he resemble Moses when he was speaking on Mount 
Sinai, while all the congregation could hear?” Strengthened be the speaker in 
what he said – he objected with mighty wisdom. Hear an answer that will 
strengthen your mind and magnify your heart, so that it may be always pleasing 
to God. The signs magniﬁed him, so that everything was done to help him and 
make him great in all that takes place. This deed is pleasing to God. Magniﬁed 
be the mind which is nourished from Him, so that the spirit may be wholly ﬁlled 
with wisdom. If you seek to know the secrets of things, set your mind where the 
truth is, and forsake the desire of the soul, in which there is no advantage.','אנשים אמרו: "כיצד יכול אדם אחד לדבר וקולו ישמע בכל המחנה? האם הוא דומה למשה בעת שדיבר בהר סיני, כשכל הקהל יכול לשמוע?" יתחזק הדובר במה שאמר – שכן השיג תשובה בחכמה עצומה. שמע תשובה שתחזק את דעתך ותגדיל את לבבך, למען יהיה תמיד לרצון לפני האלוהים. האותות גידלו אותו, עד שהכל נעשה לעזרתו ולהגדלתו בכל אשר יקרה. המעשה הזה רצוי לפני האלוהים. יתגדל השכל הניזון ממנו, למען תתמלא הרוח כולה חכמה. אם תבקש לדעת את סתרי הדברים, שים את דעתך במקום שבו האמת נמצאת, ועזוב את תאוות הנפש שאין בה כל יתרון.');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (138,'III','4','וידבר משה והכהנים הלוים',3000041,'עמי איקרה דאתיקר בה אהרן ואתחיד בה ולא תסטי מנה ואניר לבך במטר כל גזריה ולא תפסח מן מלי ברכתה כד הגדל אהרן ביתה איקרה והוה שותף למשה אישה זבן בתר זבן אתרחי אלה יוקר ישראל אלפון דינין וגזירהן ופקודין ותרוהן והוכח יתון ואזהרון וגלה לון בריתה ואזהר יתון מן קללתה וידבר משה והכהנים } ו { הלוים עמי דן רבינה ושבח לאלה למה אמר אכה אלין מליה אלא למזקף דרגה דכהניה ויחכם קהלה דישראל הן לית עובד מתעבד אלא בידון וידעו הן לון נגישתה בכל עובד כמה דאמר ונגשו הכהנ בני לוי כי בם בחר יה לשרת ולברך ותלא אתרון על כל שבטיה ולא אמר אכה ומלל משה ואהרן כמה דהוה בשרוה דאנן עמין אהרן שותפה במה דהוה עבד לקדם פרעה ובאתרין סגי אזדמן עמה ולא אתדכרו כהניה לויאיה בעה משה יקדמון אכהן סעד תתגלי איטבותון וירומו וידע ישראל הן מיתוביתון רמתה גדילה בכל דר ודור מכן אמר כדו בהדה הקצה ומלל משה וכהניה לויאיה עמי מה אתמר לכל ישראל למימר מימר טב כהלה אצלחו','Consider the honor by which Aaron was honored; cling to it and do not 
stray from it and enlighten your heart in keeping the precepts, and (then) you 
will not turn away from the “words of the blessings”. When Aaron was elevated 
with that honor, and he was partner to Moses the Man time afer time, it was the 
will of God to honor Israel. (At that time) He taught them judgments, precepts 
and commandments, He admonished them and warned them and revealed to 
them the covenant, and He warned them away with the curse: And Moses and 
the Levitical priests said (Deut. 27:9). See this greatness and praise God. Why did 
he say these words here unless to elevate the rank of the priests and to teach the 
congregation of Israel that no deed should be done but by them, so that they 
may know that the approach to every service is theirs? As He said: And the 
priests the sons of Levi shall come forward, for the Lord […] has chosen them 
(Deut. 21:5) to serve and to bless, and He raised their rank over all the tribes. He 
did not say here: And Moses and Aaron said (Exod. 16:6), as it was at the begin-
ning, for we see (that) Aaron was his partner in the things he did before Pha-
raoh. Since in many places the Levite priests were not mentioned, Moses wanted 
to advance them here, so that their favor might be revealed and they might be 
elevated, and that Israel might know that their high status will grow in every 
generation. Therefore, he said now in this section: And Moses and the Levitical 
priests said. See what has been said to all Israel, saying a good statement, 
wholly prosperity.','הבט בכבוד שנתכבד בו אהרן; דבק בו ואל תסטה ממנו, והאר את לבך בשמירת המצוות, ואז לא תסור מ"דברי הברכות". כשנתרומם אהרן בכבוד ההוא והיה שותף למשה האיש פעם אחר פעם, היה רצון האל לכבד את ישראל. אז לימדם משפטים, חוקים ומצוות, הוכיחם והזהירם וגילה להם את הברית, והרחיקם באזהרת הקללה: וַיְדַבֵּר מֹשֶׁה וְהַכֹּהֲנִים הַלְוִיִּם (דברים כז,ט). ראה גדולה זו ושבח את האל. מדוע אמר דברים אלה כאן אלא כדי לרומם את מעמד הכוהנים וללמד את קהל ישראל שאין מעשה נעשה אלא על ידיהם, למען ידעו שהגישה לכל עבודה שייכת להם? כפי שנאמר: וְנִגְּשׁוּ הַכֹּהֲנִים בְּנֵי לֵוִי כִּי בָם בָּחַר יְהוָה [...] (דברים כא,ה) לשרת ולברך, ורומם את מעמדם על כל השבטים. לא נאמר כאן: וַיֹּאמֶר מֹשֶׁה וְאַהֲרֹן (שמות טז,ו), כפי שהיה בתחילה, שהרי אנו רואים שאהרן היה שותפו בדברים שעשה לפני פרעה. הואיל ובמקומות רבים לא הוזכרו כוהני הלויים, רצה משה לקדמם כאן, כדי שיתגלה חנם וייתרוממו, וכדי שידע ישראל שמעמדם הרם יגדל בכל דור ודור. לפיכך אמר עתה בפרשה זו: וַיְדַבֵּר מֹשֶׁה וְהַכֹּהֲנִים הַלְוִיִּם. ראה מה שנאמר לכל ישראל, דברים טובים, טובה שלמה לחלוטין.');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (139,'III','37','וידבר משה והכהנים הלוים',3000371,'קטלו דבביון בחיל אלה וגעזו ירדנה דמות יעקב כד געז והוא ריקן ממדל עלמה וארום הוה עתיר מן זכותה עמי במה אתוקר ושבח לאלה וכד פגעה מלאכה בתר מגוזה יקרה באיקר יתר בשרוי מגוזה הוה באדה אטר ובתניאתה געז עתיר וכן אמר הלא באטרי געזת ית ירדנה ואודי לאלה דעתרה מבתר ענותה וכן אלה בעי מן זרעה ירבון אודהו על מד יהב לון על כן חיב עלינן נחכם רז דן עובדה עד נהי ממן חכמו איקר אלה והודו בעה באהן עובדה ביומה דבה יגוזו ית ירדנה יעבדו אלין תרי עובדיה סהדו עליכון משתמעה מן פממיכון הן תעבדו עובד מריח ברכתה דפרדתון מן פממיכון תהי עליכון והן עבדתון בישה מן הדה דאמרתון בפממיכון לבטתה תהי עליכון ומן ברכתה תתפנו לא תנשו אהן קעימה ולא תשבקו קשטה עד תנשמו אנה וגם שם','They slew their enemies by the power of God and crossed the Jordan like 
Jacob when he crossed, empty of the worlds goods. But he was rich in righteous-
ness. See how he was honored, and praise God. When the angel met him afer 
his crossing, he honored him greatly. At his ﬁrst crossing his staﬀ was in his 
hand; at the second he crossed as a rich man. Thus He said: For with only my 
staﬀ I crossed (this) Jordan (Gen. 32:10), and he gave thanks to God who had 
enriched him afer his poverty (ibid., v. 11). And so God wanted his descendants 
to multiply thanksgiving for what He had given them. Therefore it is our duty to 
know the inner meaning of this action, that we should be among those who 
know the glory of God and give him thanks. By this action He sought (that) the 
day when they should cross the Jordan, they do these two deeds – your testi-
mony heard from your (own) mouths. If you do something that is pleasing, the 
Blessing which you uttered from your own mouths will come to pass for you. If 
you do something evil relating to that which you said with your own mouths, 
then the Curse will befall on you, and from the Blessing you will be turned away. 
Do not forget this covenant and do not forsake the True One, that you may be at 
rest both here and there.','הרגו את אויביהם בגבורת אלוהים ועברו את הירדן כיעקב שעבר, ריק מטובת העולם, אך עשיר בצדקה. ראה כמה נכבד היה, ושבח את אלוהים. כשפגש בו המלאך לאחר עברו, כיבדו מאוד. בעברו הראשון היה מטהו בידו; בשני עבר כאיש עשיר. כך אמר: כִּי בְמַקְלִי עָבַרְתִּי אֶת הַיַּרְדֵּן הַזֶּה (בראשית לב,י), והודה לאלוהים שהעשירו לאחר עוניו (שם, פסוק יא). וכך רצה אלוהים שיכפלו צאצאיו את תודתם על מה שנתן להם. לפיכך חובתנו לדעת את הפנימיות של מעשה זה, כדי שנהיה בין יודעי כבוד אלוהים ומודים לו. במעשה זה ביקש שביום עברם את הירדן יעשו שני מעשים אלה – עדותכם הנשמעת מפיכם. אם תעשו דבר רצוי, תתקיים עליכם הברכה שהוצאתם מפיכם. אם תעשו דבר רע בנוגע לאשר אמרתם בפיכם, תבוא עליכם הקללה ומן הברכה תיסוגו. אל תשכחו ברית זו ואל תעזבו את האמיתי, למען תנוחו הן כאן והן שם.');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (140,'III','17','וידבר משה והכהנים הלוים',3000171,'שילה אצית ושמע למה יתאמר מן אלין מליה דאתדכרו כי אבהתון לא הוו יכלין למסוק ליד הרגריזים וקעמים על ברכתה בניון כד ייתו לידה יסקו אליו אי לא יסקו האגבו ישר שאולה במד שאלת ועל מה דרש יבקר מן מחכום הבינה צבה רבה יחידאה יעמי איקרה על כהניה מיתוביתון כדו איך היא ארבעתיתה דמן תרתי שמשהתה אקימון על טור עיבל לצביה והיא למודע ישראל הן לית בני שמשהתה כות יצוביה וקטע מתמן הן לא יהי מן עבד בר בכור יסק אל מקדשה עד יהי אלפן לדעבר ולדאתי יסגרו קנומון מן מקרוב בר עבד ישמעאל כד הוה בר לאברהם מן סולה עמו מד בעה יעבד ביצחק אלולי מד בה חכמת שרה דהוה עובד קין מתגלי תמן בלא פג','A question. Listen and hear what is said regarding these words which 
have been mentioned. Since their fathers were unable to ascend to Mount 
Gerizim and to stand for the blessing, will their sons climb on it when they get 
there, or will they not? The answer: Strengthened be, O questioner, in what you 
asked and about what He sought to be inquired about with the insight of the 
mind. The Great One, the Unique, desired to show His glory on the priests, and 
what their rank is. The four, who descend from the two maidservants – He 
placed them on Mount Ebal according to His will, to inform Israel that the sons 
of the maidservants are not like (the sons of) the natives. And He derived from 
there that no ﬁrstling of a servant should enter into the sanctuary, so that (this) 
will be a teaching for the past and for the future: they (the priests) should refrain 
from approaching a maidservant. Ishmael, as he was a son of Abraham from a 
maidservant – see what he sought to do to Isaac. If it had not been for that which 
was made known to Sarah, the deed of Cain would have emerged there, un-
doubtedly.','שאלה. הקשיבו ושמעו מה נאמר בנוגע לדברים שהוזכרו. הואיל ואבותיהם לא יכלו לעלות אל הר גריזים ולעמוד לברכה, האם יעלו עליו בניהם כשיגיעו לשם, אם לאו? התשובה: חזק, שואל, על מה ששאלת ועל מה שביקשת לחקור בהשכל הדעת. הגדול, היחיד, חפץ להראות את כבודו על הכוהנים ואת מעלתם. את הארבעה היורדים משתי השפחות – הציב על הר עיבל כרצונו, להודיע לישראל שבני השפחות אינם כבני הבית. ומכאן למד שבכור עבד לא יכנס אל המקדש, כדי שיהא זה הוראה לדורות עבר ולדורות הבאים: שיימנעו הכוהנים מלהתקרב לשפחה. ישמעאל, שהיה בן אברהם משפחה – ראו מה ביקש לעשות ליצחק. אלמלא מה שנודע לשרה, היה מעשה קין מתרחש שם, בלא ספק.');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (141,'III','55','וידבר משה והכהנים הלוים',3000551,'עמו אפרים מגיב אבוה אגבו טבה מחיבה איטבו אנית בעי אנשים טבים אקימו אתרה ולה יקימו ואנון משעבדים ואף מרבים שעבודה ומתמנים בגדל הך דהוו מן שרואה וליתון מתפנין מן דרכי קשטה אלא מדמין במי אתקדמו } ו { מן יהונו מתרחצין על עובד אבהתון ולא יחלפון מד לון אמיר אלא אנה דחל מן עובד ביש יהי מכלל בכל דין יתר מאבד ומשנק ומלבט ומזהר לעלמה מצדי מבתר עלם כהלה אצלחו ייתי עלם כהלה אבדו','See Ephraim answering his father with a good answer involving beneﬁt: 
“Indeed, you seek good men (like these who) established the place and would 
(re)establish it, and they are submissive, and even increase submission, and are 
enduring in greatness, as they were at the beginning, and do not turn away from 
the way of the True One, but resemble those who came before, (men) who will 
lean on the deed of their ancestors and do not change what is commanded to 
them. But I fear an evil deed which will end in every excessive punishment, 
which destroys and aﬄicts and oppresses. (I) warn about a desolate world. Afer 
a period wholly of prosperity, a period wholly of destruction will come.”','ראה את אפרים משיב לאביו תשובה טובה הכוללת תועלת:
"אכן, אתה מבקש אנשים טובים (כגון אלה) שהקימו את המקום ויקימוהו (מחדש), והם נכנעים ואף מוסיפים נכנעות, ועומדים בגדולתם כפי שהיו בתחילה, ואינם סרים מדרך האמת, אלא דומים לאלה שקדמו להם, אנשים שישענו על מעשי אבותיהם ואינם משנים את המצווה עליהם. אולם אני יירא מפני מעשה רע שיסתיים בכל עונש מופרז, המשחית והמייסר והמדכא. (אני) מזהיר מפני עולם שומם. אחרי תקופה שכולה שגשוג, תבוא תקופה שכולה חורבן."');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (142,'III','50','וידבר משה והכהנים הלוים',3000501,'כד הכללו שומיה וארעה מן ממללה עם קהלה שרי לבה ומלל עם מדעה ממללה דרבו מוכח דן לדן וגויתה קעמה ביניון ברתעה ובבלוד ממד יימרון מדעה אמר ללבה אתעיד וקטר כנפיך במד לה תשמע הב בלך לא תסור יתערברב כלה ויקומון באשדה רבה ולא לאוי לך דאה וליתך יכל עליו דלא יעזר אבדנה יתחזי כי לא בחילך תיחדיף יתה מנך והן הקמת גרמך ביתה תשניקה הדרש מנך אדמך הך דאמר ואת דמכם מן נפשהתכון אביע ותהונו תמן בלחץ רב וחיול לוד דלאוי עליך עובדה תפני קנומך מן בישהתה ותטר גזירהתה ולא תהי מרח מן עובד בישהתה ותהי ניוש וליתך יכל תאסי גרמך ברן לאוי עליך תטר שלמות נפשך הך דאמר לך ושמור נפשך בעובד טובה תהי מתפדי ותפדי עורנך וכן אמר כד בלש מנך הן תרחם ית יהוה אלהך לטב לך','[When the Heaven and the Earth had ﬁnished speaking to the congrega-
tion, the Heart began, and spoke with the Mind in greatness of speech, admon-
ishing one to the other, and the Body stood between them trembling and afraid 
because of what they were saying. The Mind said to the Heart: “Grasp yourself 
and concentrate (towards) what you are going to hear! Pay attention, do not de-
viate, (lest) everything becomes confused and (the congregation) be in great dis-
tress. This would not be right for you and you will not be able (to prevent) the de-
struction from appearing again. For it is not in your power to repel it from you. If 
you set yourself in that aﬄiction, I shall demand your blood from you, as it is 
said: your blood from your selves I shall require (Gen. 8:5). You would then be 
under great and strong oppression. But it is (this) that is proper for you to do: turn 
yourself away from evil and keep the commandments, lest you be smitten be-
cause of doing evil, and become weak, and unable to heal yourself. But it is ﬁt-
ting for you to preserve your own perfection, as He said to you: Guard your soul 
(Deut. 4:9) by doing good, that you may be delivered and deliver others. As He 
said when He requested you: Love the Lord your God (Deut. 6:5) for your own 
good (Deut. 10:13).”','כאשר השמים והארץ סיימו לדבר אל הקהל, החל הלב, ודיבר עם השכל בגדולת דברים, מוכיח האחד את השני, והגוף עמד ביניהם רועד וירא מפני דבריהם. אמר השכל ללב: "אחוז בעצמך והתרכז במה שאתה עומד לשמוע! הקשב, אל תסטה, פן הכל יתבלבל והקהל יהיה בצרה גדולה. זה לא יהיה ראוי לך ולא תוכל למנוע את האבדון מלהופיע שוב. שכן אין בכוחך לדוחפו מעליך. אם תשקע עצמך בייסור הזה, אדרוש את דמך ממך, כמו שנאמר: את דמכם מנפשותיכם אדרוש (בראשית ט,ה). אזי תהיה תחת עול גדול וכבד. אך זה הראוי לך לעשות: הסר עצמך מן הרע ושמור את המצוות, פן תוכה בעוון הרע, ותחלש, ולא תוכל לרפא עצמך. אלא ראוי לך לשמור על שלמותך שלך, כפי שאמר לך: שמור נפשך (דברים ד,ט) בעשיית הטוב, למען תינצל ותציל אחרים. כפי שאמר כאשר ביקש ממך: ואהבת את ה'' אלהיך (דברים ו,ה) לטובתך (דברים י,יג)."');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (143,'III','73','וידבר משה והכהנים הלוים',3000731,'אנשיה אתו ועתדו ית מדעיכון למה יתפרס קמיכון מן חכמתה במלתה דאמרה אלה וגלתה בפם נביותה ארור מכה רעהו בסתר בלש אבדנה ומחרב גויתה אני בגבורתי מנד גויתה ומקים יתה בלבטה רבה דו הוה מתכסי מן עיניה ולא שפט עליו דיאן במותה אנה מגזי יתה בלבטה לא יתפרק מנה לעלם עסרה גנואן אסחנת הדה מלתה כל חדה מהם יתרה על חברתה אנד נפשה ואקימה בעשדה ואסרה במסכינו ואשלמה ל ] ח [ סרנה ו ›› ש ‹ שפפה במסכינותה ו › א ‹ שבק מדלה הזל בשבי והפך ענינה מן איטבותה ונפל מן דרגה וקעם בצדותה ואתרחק מכל איקר ושרא עליו כל קלל וקטע גרמה ודכרה מן עמה כי דסכה דיעבד בחברה אנה מעבדנה בה דו דרש יסב ח ] לק [ ה דיהבת ] ה [ לה נסבה אנה ויהבה לחברה כי שדלתה נפשה בקטלה קטולה אנה בגוני מעואן והן הות ביניון דבבה וגוה פריתה באדה דבב הוא לי ואני אגזינה בכן ואקטע דכרה מן עלמה נזהר קנומן ] מן [ אהן עובדה ונהי מתפנין מן מקרובה לעלם דאנן בני טבים לא נהי בני זנו ולא יקום מנן פריה בישה נקום האן דאנן דאנחן בני זכאים לא נשבק זכות אבהתן לעלם עלמים נרבי לחילה דאמלתן בכן ו › נ ‹ שבח לשמה הגדול הגיבור והנורא','O people, come and prepare your minds towards what is set out before 
you of wisdom, through the word said by God and revealed by the mouth of 
prophecy: Cursed be he who strikes down his fellow in secret (Deut. 27:24). He 
seeks his (fellow’s) destruction and the ruin of his body. I, in my majesty, will 
shake his body and set him in a great curse. For he was hiding from sight and no 
judge sentenced him to death, I will punish him with a curse from which he will 
never depart. This matter comprises ten shameful acts, each of them prevails 
upon the other. I shall shake the soul and set him in aﬄiction and chain him to 
poverty and hand him over to need. I shall humiliate him with poverty and 
abandon his possessions going into captivity, and I shall turn away his mind 
from the good, and he will fall down from his rank and he will stand in 
desolation and depart from all honor, and every curse will lay upon him, and he 
will cut himself and his memory oﬀ from his people. What he sought to do to his 
fellow, I shall do to him. Indeed, he sought to take the share that I had given to 
him, I shall take it from him and give it to his fellow. Indeed, his soul enticed 
him to kill, I shall kill him with various plagues. And if hatred was between them 
and he took revenge with his hand, he acts in enmity towards me, and I shall 
punish him by this and cut oﬀ his memory from the world. Let us warn ourselves 
against this deed and turn away from approaching it forever. For we are sons of 
good men – let us not be sons of harlotry. Let not arise from us a bad oﬀshoot. 
Let us stay where we are, for we are sons of righteous men. We should not for-
sake the justice of our fathers forever and ever. Let us magnify His Potency who 
ﬁlled us with it and praise His great name, the Mighty and the Awesome (Deut. 
10:17).','הו עם, בואו והכינו את מוחותיכם למה שמוצג לפניכם מן החכמה, דרך הדבר שנאמר בפי האל ונגלה מפי הנבואה: אָרוּר מַכֵּה רֵעֵהוּ בַּסָּתֶר (דברים כז,כד). הוא מבקש את אבדן חברו והחרבת גופו. אני, בגדולתי, אזעזע את גופו ואשים אותו בקללה גדולה. שכן הסתתר מן העין ולא גזר עליו שום שופט מיתה – אענישנו בקללה שממנה לא יצא לעולם. עניין זה כולל עשרה מעשי בושה, שכל אחד מהם גובר על חברו. אזעזע את נפשו ואשים אותו בסבל, ואכבלנו לעוני ואמסרנו לחסר. אביישנו בעוני ואעזוב את נכסיו לשבי, ואסיט את דעתו מן הטוב, והוא יפול ממעמדו ויעמוד בשממה ויסור מכל כבוד, וכל קללה תנחת עליו, ויכרית את עצמו ואת זכרו מקרב עמו. מה שביקש לעשות לחברו – אעשה לו. הן ביקש לקחת את החלק שנתתי לחברו – אקחנו ממנו ואתנו לחברו. הן נפשו פיתתה אותו להרוג – אהרגנו במכות שונות. ואם הייתה שנאה ביניהם ונקם בידו, הוא נוהג כלפיי בעוינות, ואענישנו על כך ואכרית את זכרו מן העולם. נזהיר את עצמנו מן המעשה הזה ונסור מלקרוב אליו לעולם. שכן בני אנשים טובים אנחנו – אל נהיה בני זנות. אל ייצא מאתנו צאצא רע. נעמוד במקומנו, שכן בני צדיקים אנחנו. אל נעזוב את משפט אבותינו לעולם ועד. נגדיל את עוצמתו אשר מילאנו בה ונהלל את שמו הגדול, הגיבור והנורא (דברים י,יז).');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (144,'III','25','וידבר משה והכהנים הלוים',3000251,'נטעיל מן אהן אתרה דאנן בה ונגלי רביאן איקרה דיקרן בה מרן דאנון אשתה ומליה תרין עסר חכמה איך הוה אהן ממללה והך אזדמן אמרו כהלון פם אחד אי מכל גבר וגבר נלך במדע שלם ליד גברי ברכתה כי מנון נדע הך אתיתב דברה דאלין כות אלין עבדין אנשים אמרו ממלל סגי וממללון כדו יתפרס קדמיך לוי הוא מסחנה דברכתה הוא יפרדה וכלם שמעים וכן אמר משה אישה הלא בה אתרחי יה למשראה ולמברך בשם יה וחתם מד אמר בעובדיו דכהלה מרחי למרה דעלמה פעל אדה תרחי רבותה בכל עובד ומשה ואהרן מנה שלמו יתרה נביה וכהנה עמי ריש הקצה הך נביה רבה משה משרי וממלל בגדל לקדם קהלה ומלל משה וכהניה לויאיה חכם אכהן רב מיתוביתון מדן אמרו לא פרט ברכתה אלאן לוי וכהלון סעודה','Let us move on from this place in which we are, and discover the great-
ness of the glory with which our Master gloriﬁed us. They are six (men) and the 
words are twelve. Learn it: what this matter was like and how it happened. Did 
they all speak in unison or from every man apart (were they said)? Let us go with 
a perfect mind to the men of the blessing, for from them we will know how the 
matter was settled, since these and these (others) operate alike. People have said 
a great thing, and their speech is now spread out before you: Levi is the owner of 
the blessing, and he pronounces it, and all of them listen. And thus Moses the 
Man said: for the Lord […] has chosen to minister and to bless in the name of the 
Lord (Deut. 21:5) and he concluded what he said about his deeds, [all of which 
pleased the Master of the world: favor the work of his hands (Deut. 33:11). His 
greatness is in every (of his) deed and Moses and Aaron (stem) from him – abun-
dant perfection: the prophet and the priest. See the beginning of the section, 
how the great prophet Moses begun to speak in greatness in front of the congre-
gation: Moses and the Levitical priests said (Deut. 27:9) – he taught thus the 
greatness of their rank. Hence (people) said: “Only Levi pronounced the Bless-
ing, and all of them accompanied him.”','הבה נעבור מן המקום שבו אנו עומדים, ונגלה את גדולת הכבוד שבו כיבדנו אדוננו. הם שישה אנשים והדברים שנים עשר. למד זאת: כיצד היה הדבר הזה וכיצד אירע. האם כולם דיברו כאחד, או שמא נאמרו הדברים מפי כל אחד לחוד? הבה נלך בדעה שלמה אל אנשי הברכה, כי מהם נדע כיצד נסתיים הדבר, שכן אלו ואלו פועלים באותה דרך. אנשים אמרו דבר גדול, ודבריהם פרושים עתה לפניך: לוי הוא בעל הברכה, והוא הוא שאומר אותה, וכולם מקשיבים. וכך אמר משה האיש: כי ה'' [...] בחר לשרת ולברך בשם ה'' (דברים כא,ה), וסיים את שאמר על מעשיו, שכולם היו לרצון לאדון העולם: רצה פעל ידיו (דברים לג,יא). גדולתו בכל מעשיו, ומשה ואהרן יוצאים ממנו – שלמות נפלאה: הנביא והכוהן. ראה את ראשית הפרשה, כיצד פתח הנביא הגדול משה לדבר בגדולה לפני הקהל: וידבר משה והכוהנים הלויים (דברים כז,ט) – כך למד את גדולת מעמדם. לפיכך אמרו: "לוי בלבד אמר את הברכה, וכולם נלוו אחריו."');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (145,'III','15','וידבר משה והכהנים הלוים',3000151,'וחכם נביה רבה משה מנו דיתקומם ואמר מד בה גדל ישראל ויצו משה את העם ביום ההוא ולא אתדכרו אכה כהניה דו אמר מימר חכמה קבלה מן מרה דעלמה ולא הוה תמן איש מהימן אלא נביה רבה משה לבדיל אמר ופקד משה ית עמה ביתה יומה בדיל מד הו פרס ממד גלה לה קשטה ופקדון במד בה יתוקרו כד שרה משה בממללה פלג שבטיה בנביו רבה חלקין תרין מן לאוי לה המוכח ומן ליתו מתוכח וכן אמר אלה למשה אישה זבן דגלה לה מד גלה ליעקב ופלג יתון ואקים מד לון מן עובד ומן מוכח ובסר יתון במגוז ירדנה ומן יקום בברכתה ומן יקום בקללתה וגלה רבות מד תמן יתפרס','The great prophet Moses knew what would come to pass and said that 
which magniﬁed Israel: Moses charged the people the same day (Deut. 27:11) – 
the priests were not mentioned here. For he said a saying of wisdom which he re-
ceived from the Master of the world, and no faithful man was there except the 
great prophet Moses. Therefore, it is said: Moses charged the people the same day 
(ibid. – ST), regarding that which he disclosed out of that which the True One re-
vealed to him, and he commanded them with that which they will be gloriﬁed. 
When Moses begun speaking, he divided the tribes with great prophetic insight 
(into) two parts: those ﬁt for reproof and those not to be reproved. Thus said God 
to Moses the Man at the time when He revealed to him what He revealed to Ja-
cob. He divided them into those to whom reproof is appropriate, and those who 
are not to be reproved. And he announced to them the crossing of the Jordan, 
and about those who will stand for the blessing and those who will stand for the 
curse. And he revealed the greatness of that which was disclosed there.','הנביא הגדול משה ידע את אשר עתיד לבוא, ואמר דברים שהרוממו את ישראל: וַיְצַו מֹשֶׁה אֶת הָעָם בַּיּוֹם הַהוּא (דברים כז,יא) – הכוהנים לא נזכרו כאן. שכן אמר דבר חכמה שקיבל מאדון העולם, ולא היה שם איש נאמן מלבד הנביא הגדול משה. לפיכך נאמר: וַיְצַו מֹשֶׁה אֶת הָעָם בַּיּוֹם הַהוּא (שם – נוסח שומרוני), בנוגע למה שגילה מתוך אשר הראה לו האמת, וציווה אותם בדברים שבהם יתכבדו. כאשר החל משה לדבר, חילק את השבטים בתובנה נבואית עמוקה לשני חלקים: אלה הראויים לתוכחה ואלה שאין לתוכחם. כך אמר האל למשה איש האלוהים בעת שגילה לו את אשר גילה ליעקב. חילק אותם לאלה שהתוכחה הולמת אותם ולאלה שאין לתוכחם. והודיע להם על העברת הירדן, ועל אלה שיעמדו לברכה ואלה שיעמדו לקללה. וגילה את גדולת מה שנתגלה שם.');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (146,'III','63','וידבר משה והכהנים הלוים',3000631,'וגבר דיהי פני מן הדעה ובלש מנך ולא ] ת [ לפה מה אמרת יתך אנה גבינך והן ליתו בלש ושבק מילף דעתה כיי הפך מגביה עליו באפרי וגבר דיזרז למעבד ערבוב באנש הן עבדנה במדע שלם אנה בה אעבד מה זמם יעבד באחוה והפך אעבד בה דין למכלהתה עד לא יהי לה תקומה בעלמה וגבי פריתה וגבר דילבש מלים בישים על אנש מחיבין עליו דין מותה אזהרת דיאנה מן משמע מליו לא יקום עד אחד באיש ואניתו לא שמע אלפנה יקום בלבט ואת זכי מנה עמי למליה דהי מתלבשה ואבקר עליה ולא תשחי','(If) a man is empty of knowledge and seeks (it) from you, and you do not 
teach him (as) I commanded you, I will punish you. If he does not seek and 
abandons the learning of knowledge, indeed I will turn the punishment on him 
in haste. A man who hastens to inﬂict a blemish on another, if he did it with a 
whole mind, I will do (to him) what he schemed to do to his fellow (Deut. 19:19). 
And I will return and judge him to destroy him, so that he will have no existence 
in the world, and I will take vengeance from him. A man who utters bad words 
about another, death punishment will be coerced upon him. I have warned the 
judge not to listen to his words: A single witness shall not prevail against a man 
(Deut. 19:15). And if he does not obey the teaching, he will be placed under a 
curse, and you are exempt. See the words that they are uttered and examine 
them and do not tarry.','אם אדם ריק מידע ומבקשו ממך ואינך מלמדו כפי שציוויתיך, אענישך. אם אינו מבקש ועוזב את לימוד הדעת, אהפוך את העונש עליו במהרה. אדם הממהר להטיל פגם באחר, אם עשה זאת בדעת שלמה, אעשה לו כאשר זמם לעשות לרעהו (דברים יט,יט). ואשוב ואדונהו לאבדו, כך שלא יהיה לו קיום בעולם, ואקח נקמה ממנו. אדם המוציא דברים רעים על אחר, עונש מוות ייכפה עליו. הזהרתי את השופט שלא לשמוע לדבריו: לא יקום עד אחד באיש (דברים יט,טו). ואם לא יציית לתורה, יושם תחת קללה, ואתה פטור. ראה את הדברים שנאמרו ובחן אותם ואל תתמהמה.');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (147,'III','33','וידבר משה והכהנים הלוים',3000331,'שיאלה שמע יתה מן האן לן אהן מחכומה רבה דנח לא דבח אלא לכונה ולא דבח באתר רחיק מנה האגיבו כי לא הוה טור שמם מן מי מבולה אלא הו וכל טוריה מתכסין הך דאמר וטמרו כל טוריה שחיקה ומנה אנדת יונתה טרפי זיתה דו טב ומנה אתת ביסרה טבה מכן אתעקב ההר הטוב דמי מבולה לא אמטה בה ולא אביד בה נפש למטמהתה דו בית אלהים ומשרוי מלאכיה ואתר מעונות צבעתה ואתר שכינותה ואתר סליחותה ואתר ברכתה ואתר חגיה ואתר איקר יהוה בכל עת מתחזי ועלמה באיקר מודאה לאלה דבחר יתה ועבדה אתר קדש מנגד לידה כל קדש','Hear a question: From where do we get this great knowledge, that Noah 
sacriﬁced only before Mount Gerizim and did not sacriﬁce in a place distant from 
it? The answer: Indeed, there was not a mountain empty of the water of the 
Flood except it, and all the mountains were submerged, as He said: (The waters) 
covered all the mountains under heaven (Gen. 7:19). From it the dove brought 
olive leaves, for it was good, and from it came good tidings. Therefore it was 
named The Good Mountain (Deut. 3:25), for the water of the Flood did not reach 
it and no one perished on it deﬁling it, for it is the House of God and the abode 
of the angels, the place where supplications are answered, the place of the Pres-
ence, the place of forgiveness, the place of blessings, the place of the pilgrim-
ages, the place of the Glory of the Lord – which is bound to appear at any time, 
while the world is in glory. Thanks be to God who chose it and made it a holy 
place, to which every holy thing is directed.','שמע שאלה: מנין לנו הידע הגדול הזה, שנח הקריב רק לפני הר גריזים ולא הקריב במקום הרחוק ממנו? התשובה: אכן, לא היה הר שלא כוסה במי המבול מלבדו, שכן כל ההרים שקעו, כפי שאמר: כסו כל ההרים הגבהים אשר תחת כל השמים (בראשית ז,יט). ממנו הביאה היונה עלי זית, כי טוב הוא, וממנו באה הבשורה הטובה. לפיכך נקרא ההר הטוב (דברים ג,כה), שכן מי המבול לא הגיעו אליו ולא אבד עליו אדם שיטמאהו, כי הוא בית האל ומושב המלאכים, המקום שבו נענות התפילות, מקום השכינה, מקום הסליחה, מקום הברכות, מקום העליות לרגל, מקום כבוד ה'' — אשר עתיד להתגלות בכל עת, בעוד העולם בתפארתו. תהילה לאל אשר בחר בו ועשהו מקום קדוש, אשר כל דבר קדוש מכוון אליו.');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (148,'III','1b','וידבר משה והכהנים הלוים',3000013,'נתן אפרשו גדול ודחיל מקדם ניעל לתחומה דקדשה נביה רבה משה הגדל בנביותה ואהרן הגדל בכהנתה מן יום דאתמר למשה ואהרן אחיך יהיה נביאך תריון אזדמנו לגו שלמותה ובמקומין אכללת אדיון הלא בשלחית פרעה לא הוה לאהרן כהנה אלאן כד אתפרק ישראל ממצר ואתו להר האלהים ברבו רבה בירחה תליתה אמר אלה על ישראל ואתם תהיו לי ממלכת כהנ וגוי קדש תמן אתמסרת דרג כהנתה לאהרן ואתפרד בה הוא וזרעה וחכם משה דשבט לוי כהלה יגדל בכהנתה הלא אבוה אקימה בגלל מן מנה קעם אמסיר ליה בקנאה יתרה שריר אתה ואהרן עמך ועורי כהניה לא אתמרת אלא בדיל זרעה מיסתה וכן אמר אלה מפם גבורתה למשה אישה וגם הכהנים הנגישים אל יה יתקדשו פן יפרץ בם יהוה אתידע מן אכה דאהרן ובניו לבשו הכהנה ובה אתפרשו','Let us now set out a great and fearful division before we enter the realm 
of holiness. The great prophet Moses was gloriﬁed in prophethood and Aaron 
was gloriﬁed in priesthood from the day that it was said to Moses: And Aaron 
your brother shall be your prophet (Exod. 7:1). Both were joined in perfection, and 
in (various) passages they were ordained. For at the (time of the) mission to 
Pharaoh Aaron had no priesthood, but afer Israel was delivered from Egypt, 
and they came to the Mountain of God in great glory in the third month, God 
said to Israel: You shall be to me a kingdom of priests and a holy nation (Exod. 
19:6). Then the rank of priesthood was handed down to Aaron, and he was dis-
tinguished by it; he and his oﬀspring. Moses taught that the whole tribe of Levi is 
elevated by priesthood, for his ancestor established it for the sake of the one 
who stemmed from him, and was devoted to the Lord with most exceeding zeal. 
You and Aaron with you (Exod. 19:24), moreover, the priests (ibid.) was not said 
about anyone other than their oﬀspring. And thus said God through His Might to 
Moses the (divine) Man: The priests also, who come near the Lord, must conse-
crate themselves, lest the Lord break out against them (Exod. 19:22). From here on 
it was made known that Aaron and his sons wore the priesthood, and by it they 
were distinguished.','נציג עתה חלוקה גדולה ונוראה לפני שנכנס לתחום הקדושה. הנביא הגדול משה נתכבד בנבואה ואהרן נתכבד בכהונה מן היום שנאמר למשה: וְאַהֲרֹן אָחִיךָ יִהְיֶה נְבִיאֶךָ (שמות ז,א). שניהם נצטרפו יחד בשלמות, ובפסוקים שונים נתמנו. שכן בשעת השליחות אל פרעה לא הייתה לאהרן כהונה כלל, אך לאחר שישראל נגאלו ממצרים ובאו להר האלוהים בכבוד גדול בחודש השלישי, אמר האל לישראל: וְאַתֶּם תִּהְיוּ לִי מַמְלֶכֶת כֹּהֲנִים וְגוֹי קָדוֹשׁ (שמות יט,ו). אז נמסר מעמד הכהונה לאהרן והוא נתייחד בה, הוא וצאצאיו. משה לימד שכל שבט לוי מתרומם בכהונה, שכן אבי השבט כונן אותה למען זה שיצא ממנו ומסר עצמו לה'' בקנאה גדולה ביותר. וְגַם אַתָּה וְאַהֲרֹן עִמָּךְ (שמות יט,כד), ועוד, הַכֹּהֲנִים (שם) לא נאמר על אף אחד אחר זולת צאצאיהם. וכן אמר האל בגבורתו למשה איש האלוהים: וְגַם הַכֹּהֲנִים הַנִּגָּשִׁים אֶל יְהוָה יִתְקַדָּשׁוּ פֶּן יִפְרֹץ בָּהֶם יְהוָה (שמות יט,כב). מכאן ואילך נודע שאהרן ובניו לבשו את הכהונה ובה נתייחדו.');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (149,'III','20','וידבר משה והכהנים הלוים',3000201,'מה דן נימר בדיל גיורה אי בר נכראה דיולד על שביו כי אלה אמר כגר כאזרח עד מימרו יחדי עמך בחגך ואמר בדילה יזדמן עמך וישמע כהנה קרי ארהותה ולא יקרנה כהנה אלאן באתרה דבחר יה ועבדה לה מסגד יזדמן תמן בר נכראה ואף גיורה דיגור עמוכון פרט','What should we say about the sojourner or the son of a foreigner who is 
born in captivity? Indeed God said: like sojourner like native (Lev. 24:22) even as 
much as His word: he shall rejoice with you in your feast (paraphrase of Deut. 
16:14). (Moreover), He said about him that he should join you and hear the priest 
reading the Law. Now, the priest should not read it except in the place that the 
Lord had chosen and made it a sanctuary. Will the son of the foreigner join, and 
also the sojourner who sojourns with you (Lev. 19:34)?','מה נאמר על הגר או בן הנכר הנולד בשבי? הן אלוהים אמר: כגר כאזרח (ויקרא כד,כב), וכמו כן דברו: וְשָׂמַחְתָּ בְּחַגֶּךָ (פרפרזה על דברים טז,יד). ועוד אמר עליו שיצטרף אליכם וישמע את הכוהן קורא בתורה. והכוהן אינו רשאי לקרוא אלא במקום אשר בחר בו ה'' ועשאו מקדש. האם יצטרף בן הנכר, וכן הגר הגר אתך (ויקרא יט,לד)?');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (150,'III','65','וידבר משה והכהנים הלוים',3000651,'וגבר יחכמנך מד חכמה מנו דישמע גדף ממלל באתר אזהרה מנה לא יקום עמה ואזהר גרמך מן משמע מליו והוא גברה דאהזרתך מנה דו מצמת שבעה בישהן דמה נפשה לזכאים דגעזו אתחזית לון בחלמה וגלית לון מד יקרון ואמר אני דמי למשה אעבד קדמיך סימן ופלי יהי כל אהן עד הן תסור מן שבילה דקשטה ותשבק אימנות אבהתך אברהם ליתו שאל בדילך אקמת דמותה בחלמה ואף בממללה יצחק ליתו אחס עליך שבקת אתרה ובחרת לך אתר יעקב ליתו בלש לך אכשרו שבקת מד שרר יתה ובלשת חלופה וגבר לא חכם רז עובדה דעבדה חסכה מנה עד תתפני מן לבטה והוא עובדה דיקרבנה אל קשטה הן במעשר הן בדבח בררה לא יעלנה אל ביתה יסתפי וחובה עליו אנש יהי לה קניאן מרחי ליתו צמתה אלא […]','(If) a man makes known to you what he had learned from one who let 
him hear blasphemy uttered in a place, warn him from him (the blasphemer), 
that he will not stand with him (in that place). Warn yourself away from hearing 
his words. He is the man that I warned you away from, since he joins seven evils: 
he likens himself to the righteous who passed away, to whom I appeared in the 
dream and revealed to them what gloriﬁed them. And he says: “I am like Moses; 
I will perform before you a sign and a wonder, and all this will come into being”, 
so that you might turn away from the path of the truth and abandon the way of 
your ancestors. Abraham will not pray for you – did you act like him in dream or 
in speech? Isaac will not have pity on you – you lef his place and chose (an-
other) place. Jacob will not seek prosperity for you – you have forsaken what 
strengthened him and you sought its substitute. If a man does not understand 
the meaning of the deed he did, prevent him from doing it, so that you may be 
exempt from the curse. This is the deed that may draw him near to the True One, 
whether in tithe or in oﬀering. Prevent him from bringing it to his house, lest he 
is swept away and he is responsible for the guilt. If a man has a pleasing posses-
sion which he does not keep but […]','אם אדם מגלה לך את מה שלמד ממי שהשמיעו גידוף שנאמר במקום מסוים, הזהר אותו ממנו (מן המחרף), שלא יעמוד עמו (באותו מקום). הזהר את עצמך מלשמוע את דבריו. הוא האדם שממנו הזהרתיך, שכן הוא מצרף בתוכו שבע רעות: הוא משווה את עצמו לצדיקים שעברו מן העולם, אשר נגליתי אליהם בחלום וגיליתי להם מה שכיבד אותם. והוא אומר: "אני כמשה; אעשה לפניכם אות ומופת, וכל זה יתקיים" – כדי שתסורו מדרך האמת ותעזבו את דרך אבותיכם. אברהם לא יתפלל בעדכם – האם נהגתם כמוהו בחלום או בדיבור? יצחק לא ירחם עליכם – עזבתם את מקומו ובחרתם (במקום) אחר. יעקב לא יבקש טובתכם – נטשתם את מה שחיזק אותו ובקשתם את תחליפו. אם אדם אינו מבין את משמעות המעשה שעשה, מנע אותו מלעשותו, כדי שתינקה מן הקללה. זהו המעשה שעשוי לקרבו אל האמיתי, בין במעשר ובין בקרבן. מנע אותו מלהביאו לביתו, שמא יִסָּחֵף והוא יישא באשמה. אם לאדם יש קניין חמוד שאינו שומרו אך [...]');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (151,'III','41','וידבר משה והכהנים הלוים',3000411,'ותנגדו במלתה דאמרה משה כד קעם על ימה ואשיר נחית בחסדך עם זה גהלת נחלת בעזך אל נוה קדשך בה אתיכון לאכה בשלם ובמימרה עוד תביאמו ותטעמו בהר נחלתך מכון לשבתך אכה אתקוממת ומלתה דבה רבה יתכון כד אמטתון לטור סיני ואתון יומה ככוכבי שומיה לסגוי מלכו ליתה איקרה יאי עליכון תרומו על כל אמיה דאנון טמאים ואתון קדישים אנון צריכין לכוכבי שומיה ואתון לא כן רק רבותכון יתרה עליון יהוה אלהי אבותיכם יסף עליכון ככם אלף פעמים לגדל הדה מלתה ליומה ובתר יומה ליטבו ובתר לכלול ויברך אתכם כאשר דבר לכם אמנו על קשטה יקום לוכון כל אהן','You will be led by the word which Moses said when he stood by the sea: 
In Your grace You led the people You redeemed; in Your strength You guided them 
to Your holy abode (Exod. 15:13). By it you came here in safety. Moreover, by his 
word: You will bring them and plant them in Your own mountain, the place (You 
made) to dwell in (Exod. 15:17) – (it) was fulﬁlled here. And the word by which He 
elevated you when you reached Mount Sinai (is): You are this day as the stars of 
heaven for multitude (Deut. 1:10) – take possession of that glory. It is appropriate 
for you to be elevated above all nations, for they are unclean and you are holy; 
they are submitted to the stars of heaven and you are not so. Contrastingly, your 
greatness prevails over them. May the Lord, the God of your fathers, make you a 
thousand times as many as you are (Deut. 1:11) according to the greatness of this 
statement, today and tomorrow (Exod. 19:10) – today for prosperity and tomor-
row for perfection. May (He) bless you, as He has told you (ibid.) – persevere in 
truth, and this will materialize for you.','תינחה על ידי הדבר שאמר משה כאשר עמד על הים: בחסדך נחית עם זו גאלת, בעזך נהלת אל נוה קדשך (שמות טו,יג). בכך הגעת לכאן בשלום. יתרה מזו, דברו: תביאמו ותטעמו בהר נחלתך, מכון לשבתך (שמות טו,יז) – התקיים כאן. והדבר שבו הרימך כאשר הגעת להר סיני הוא: והנכם היום ככוכבי השמים לרוב (דברים א,י) – קח לך את אותו כבוד. ראוי לך להינשא מעל כל העמים, שכן הם טמאים ואתה קדוש; הם כפופים לכוכבי השמים ואתה אינך כן. להיפך, גדולתך עולה עליהם. יוסף ה'' אלוהי אבותיכם עליכם ככם אלף פעמים (דברים א,יא) בהתאם לגדולת האמירה הזאת, היום ומחר (שמות יט,י) – היום לשגשוג ומחר לשלמות. יברך אתכם כאשר דיבר לכם (שם) – התמד באמת, ודבר זה יתגשם עבורך.');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (152,'III','8','וידבר משה והכהנים הלוים',3000081,'ושמע ישראל לית תמן בהתה לאנש בעלמה כד יזרז למשמע זעק » ת « זיעקה חורנה ואמרת לך שמע ישראל וחכמתך רז מד לה שמעת באיטבו רבה ושלמו יתרה אלפתך אלפן תתרבי בה עד לעלם וכלה לך איטבו דקרית קמיך יה אלהינו יה אחד בדאה תגדל בעלמה ובאחרית אנית בעי טובך בעלמה מד אתה שמע אטרה בזכו ורבינה באימנו ושררה בשעבוד ואמלכנה באשמחה ושמע ישראל מד אזל אזל ומכדו ולעל אמלך לזכותה כי בה תתרבי היום הזה נשרי לאלפנך וכהניה ממללים עמך עורי כד אוכח ישראל אפך ואוכח כהניה בדיל מיתוביתון דחלה עליון לא יסטון ויאבדו מה אוקרון בה מרון עד ידע כל אנש מהיא דרגה ויהי עמלה לפם חנותה רבין כהנתה רבין חיול עד מותר ואיקרה יתר על כל מאום וליתו יתר אלאן בעמל מרבי עמולה הך מה לאוי אנש דיהי עובדה מרחי למרה עובדה מרבינה בכלה מן אברהם חזינן יתה עובדה ולינן צבין בר מנה אה כהניה חכמו דן איקרה ולא תשבקו ית אדיכון ריקה כל קהל ישראל כד יסטי ויעזר יתקבל וכן קשטה אמר כי תשוב אל יה אלהיך אלאן כהניה לא יתקבלון כד יסטון דאנון הטמו וטמא לא יתקדש לוד אשתה תלחט יתה גזוי טמהתה לפם עמלה יהי גמלה יתרבי יכולה הממן לחודה עם כל דריה ולית לה סוף ולא עקב','And hear, O Israel (Deut. 27:9) – there is no shame for a man in the world 
when he hastens to hear. I summoned you with another summon and said to 
you: Hear, O Israel (Deut. 6:4). And I caused you to know a teaching, which you 
heard in great favor and tremendous perfection. I taught you a lesson by which 
you will be exalted in this world and in the next one, and is wholly grace for you, 
for I stated before you: The Lord our God is one Lord (ibid.) – in this you will be 
exalted in this world and in the world to come. If you seek your own good in this 
world, keep what you hear with uprightness and exalt it with faith, and strength-
en it with humility, and possess it with obedience. And hear, O Israel, what is 
past is past, and from now on take possession of uprightness, for by it you will 
be exalted. This day (Deut. 27:9) I shall begin to teach you, and also the priests 
will speak to you. When he reproved Israel he turned back and reproved the 
priests because of their rank. Let fear rest upon them, that they may not stray 
and lose that with which their Master honored them, and that every man may 
know what is his rank, and his deed will be according to his position. The great-
ness of the priesthood is an excessively powerful greatness, and its honor pre-
vails upon everything. It is appreciable only by the deed that exalts its doer, as is 
appropriate. Anyone’s deed that pleases his Master, his deed exalts him in every 
respect. We saw that fact from Abraham and we do not want something else. O 
priests, know this honor and do not leave your hands empty. All the congrega-
tion of Israel, when they err and repent, will be accepted. For thus said the True 
One: if you turn to the Lord your God (Deut. 30:10). But the priests will not be ac-
cepted, if they stray, for they deﬁled themselves, and no-one deﬁled is then sanc-
tiﬁed. Rather, the ﬁre will consume him because of his deﬁlement. According to 
his deed is his reward. Exalted be the Powerful who endures alone forever, and 
He has no end nor expiry.','וּשְׁמַע יִשְׂרָאֵל (דברים כז,ט) – אין בושה לאדם בעולם כאשר הוא ממהר לשמוע. קראתי לך בקריאה אחרת ואמרתי לך: שְׁמַע יִשְׂרָאֵל (דברים ו,ד). והודעתי לך תורה שקיבלת ברצון גדול ובשלמות עצומה. לימדתי אותך שיעור שבו תתעלה בעולם הזה ובעולם הבא, והוא חסד כולו עבורך, כי הצהרתי לפניך: יְהוָה אֱלֹהֵינוּ יְהוָה אֶחָד (שם) – בזה תתעלה בעולם הזה ובעולם הבא. אם אתה מבקש את טובתך בעולם הזה, שמור את מה שתשמע ביושר, ורומם אותו באמונה, וחזק אותו בענווה, וזכה בו בציות. וּשְׁמַע יִשְׂרָאֵל, מה שעבר עבר, ומעתה תפוש את היושר, כי בו תתעלה. הַיּוֹם הַזֶּה (דברים כז,ט) אתחיל ללמדך, וגם הכוהנים ידברו אליך. כאשר הוכיח את ישראל פנה חזרה והוכיח את הכוהנים בגלל מעמדם. תשרה עליהם יראה, שלא יתעו ויאבדו את אשר כיבד אותם בו אדונם, ושיידע כל איש מה מעמדו, ומעשהו יהיה לפי מצבו. גדולת הכהונה היא גדולה עצומה מאוד, וכבודה עולה על הכל. ניתן להעריכה רק במעשה המרומם את עושהו, כראוי. מעשה כל אחד שמרצה את אדונו מרומם אותו בכל דבר. ראינו זאת מאברהם ואיננו רוצים דבר אחר. כוהנים, דעו את הכבוד הזה ואל תניחו את ידיכם ריקות. כל עדת ישראל, כשתחטא ותשוב בתשובה, תתקבל. כי כך אמר האמת: כִּי תָשׁוּב אֶל יְהוָה אֱלֹהֶיךָ (דברים ל,י). אך הכוהנים לא יתקבלו אם יחטאו, כי טימאו את עצמם, ואין טמא מתקדש. אלא האש תאכל אותו בגלל טומאתו. לפי מעשהו שכרו. תתעלה הגבורה המתקיימת לבדה לעולם, ואין לה סוף ולא תכלה.');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (153,'III','14','וידבר משה והכהנים הלוים',3000141,'ישתבח רחמנה דרחמיו יתרים עם חדוד שעי זבנה ונעזר עורי ליד ממללה דהוינן בה ועשית את מצותיו אשר אנכי מצוך היום עמי הך דרש נביה רבה משה צמות קהל ישראל עד ילפנה ולגו לבה מה דחכמה אלה במה יהי מנון והוא ממללה דקנא לבה בדיל שיורה דסכה דו בון חדי דאנון בתר מותה יעבדו בישה בחזות יהוה ויקימו פנותה צמתון ואמר לון כל אילן ממלליה והוא ידע דאנון לא יתקוממו על כן אלאן פרות יוסף אנון דימלכו אתרה טבה הרגריזים ירום יוסף וירום זרעה שמורי קשטה בכל שרוון וכד הוה דן רזה בדיל בית יוסף בעה נביה רבה משה ירבי יתון הלא לא נטר גזיראתה ונטרון אברהם לבר מן יוסף אנש בעלמה סגי דגעז עליו ולא צבה ישמע ויקרב בישה מכן אתרבה יוסף ביד אבוה ומשה במה דחכמו מן מלכה רבה','Praised be the Merciful One, whose mercy increases with the renewal of 
the hours of the time. Let us return to the matter that we were dealing with: And 
you shall do His commandments […] which I command you this day (Deut. 27:10). 
See how the great prophet Moses sought to gather the congregation of Israel, so 
that he might teach them, (although) within his heart (he knew) what God 
taught him, (namely) about what would became of them. About this matter his 
heart was zealous: for the sake of the remnants. For he foresaw that, even 
though he was happy with them, afer his death they would do evil in the sight 
of God and (thus) they would incur the Divine Disfavor. He assembled them and 
told them all these words, even though he knew that they would not be accom-
plished as they were (said), except for the descendants of Joseph. They are the 
ones who will possess the Good Place, Mount Gerizim. Exalted be Joseph and ex-
alted be his oﬀshoot, the keepers of the truth, with all their might. And when 
this secret about the house of Joseph was (revealed), the great prophet Moses 
sought to magnify them, for nobody in the world observed the commandments, 
(as) Abraham observed them, except Joseph: he underwent much. Nevertheless 
he would not listen and approach evil. Therefore Joseph was exalted by his 
father, and by Moses, due to what they knew from the Great King.','ברוך הרחמן שרחמיו מתחדשים עם חידוש שעות הזמן. נשוב לעניין שעסקנו בו: ועשית את מצוותיו [...] אשר אנכי מצווך היום (דברים כז,י). ראו כיצד ביקש הנביא הגדול משה לכנס את קהל ישראל כדי ללמדם, אף שבלבו ידע מה לימדו האלוהים, דהיינו מה עתיד לקרות להם. על עניין זה היה לבו קנאי: למען שארית. כי ראה מראש שאף שהיה שמח בהם, לאחר מותו יעשו רעה בעיני האלוהים ויגיעו לכך שהסתר הפנים יירד עליהם. כינסם ואמר להם את כל הדברים האלה, אף שידע שלא יתקיימו כאמורם, אלא על ידי בני יוסף. הם יהיו אלה שיזכו במקום הטוב, הר גריזים. ירום יוסף וירום צאצאיו, שומרי האמת, בכל עוזם. וכאשר נתגלה סוד זה על בית יוסף, ביקש הנביא הגדול משה לגדלם, כי איש בעולם לא שמר את המצוות כפי ששמרן אברהם, אלא יוסף: הוא סבל הרבה. ועם זאת לא הסכים לשמוע ולגשת אל הרע. לפיכך רוממו יוסף אביו ומשה, מתוך מה שידעו מן המלך הגדול.');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (154,'III','1a','וידבר משה והכהנים הלוים',3000012,'מן אוצרה רבה דכלה חיים נזדהן עד נתוחי לגו עלמה רב הו אהן אוצרה דכל מלאה חיים ורב הוא ברנשה דמטי לידה ואנסב וסבע וזאן לכל דריה קניאן דלא בלי קניאן זכותה והוא פתח פתחי ליתו צניק לעלם אה רבו רבה ישתבח חילה דרבה משה מלבין כל בני אדם ירום דן נביה רבה דאתחיל ברומה ובמכה וחזה אורה גלי לה ולבש כליל לא לבשה אנש מכל בית אדם כליל עתיד מימי הבריה כתיב עליו אהיה אשר אהיה מן ארבעתי פאתיה ועל רישה מלעל עבד ליהוה מחוי עליו דו שוי לכן ועורי ארבעה מלים רמין יהוה אלהינו יהוה אחד ועל תרי כתפיה כתיב איש האלהים לא כותה לעלם נשבח למרן צעורן ומלוכן ונודינה בכל זבן ונסגד לגדלה דו אחד לגרמה פרד במלכותה לית עמה אל חורן מלך על כלה ואדה אחדה על כל בוראיה סהדות קמאותה חדוד בוראיו וסדרון בטב יתוב אהלו הוה לה תניאן עזרה בעובד הות יכלתה קעצה מרישה דכל יכול בעלמה תהי יכלתה לית בה חסירו ולא קעצה יהי עובדה תמים בכלה לית יתשקח בה חסרן ולא פגול והן הוה בה חלוף מן יתה חורנה כל עובד דיתעבד לית בה שלמו דלפם עבודה יהי עובדה הן ביכלו אי בקצירו והן הזדמנת יכלת תריון כחדה צביתה חדה והן אתחלפת וכל דמנון יבעי יגלי יכלתה ויעבד עובד עד הן יתחכם דו יכול יהי תפוך ותתחבל עבדתה ולא תתקומם יתרבי יכולה הממן לגרמה ולית עמה אל חורן כמד בעה ברא וכמד בעה יתב וכל מד עבד ממן על מהו נודי לחילה ונסגד קדם גדלה ונימר בדחלה רבה וסהדו קשיטה לית אלה אלא אחד','Of the Great Treasure, all of which is life, let us be supplied, so that we 
may live in the world. Great is this treasure, whose entirety is life, and great is 
the man who approaches it and takes (of it) and is satisﬁed and supplies (of it) to 
all generations. A possession that is never worn out is the possession of righ-
teousness, and it is an open gate that will never be closed. Behold a great glory. 
Praised be God who gloriﬁed Moses amongst all the sons of men. Exalted be this 
great prophet, who was strengthened in heaven and on earth, and saw the light 
revealed to him, and wore a crown, as nobody of all the House of Adam ever 
wore. A crown ready from the times of the Creation, on which is written I am who 
I am (Exod. 3:14) on its four corners, and on its top, above: God’s servant (Deut. 
34:5), which makes known about him that he is worthy of this. Likewise, four 
elevated words: The Lord our God is one Lord (Deut. 6:4). On his two shoulders it 
is written: The Man of God (Deut. 33:1). Nobody will ever be like him. Let us 
praise our Master, our Creator and Owner, and let us thank Him and worship His 
greatness, for He is one, alone, peerless in His kingdom. There is no other god 
beside Him, king over all; His hand supports all the creatures. The witness of His 
primacy (is) the creation of the creatures and their arrangement in good order. If 
He had any partner, a helper in deed, His might would have ceased right from its 
beginning. For with respect to any mighty (one) in the world, his power has nei-
ther deﬁciency nor ceasing. (On the contrary), his deed is perfect in every re-
spect, no deﬁciency would be found in it nor deﬁlement. But if the opposite of 
that might occur, (having a) partner, any accomplished deed would be void of 
perfection. For the deed is according to its doer, whether in might or in deﬁ-
ciency. If the might of both is joined together – there is one (common) will. But if 
(the partnership) changes, and each of them wants to manifest his power doing 
a deed that would make known that he is the powerful, an overthrow would 
result, and the deed would be spoiled and would not endure. Exalted be the 
Mighty One who endures alone – and there is no alien god besides Him. As He 
wanted He created, and as He wanted He established, and everything He did is 
steadfast, as it is. Let us thank His might, and bow down before His greatness, 
and say with great fear and true testimony: “There is no god but One.”','מהאוצר הגדול, שכולו חיים, ייתן לנו, למען נחיה בעולם. גדול האוצר הזה שכולו חיים, וגדול האיש הניגש אליו ולוקח ממנו ושובע ומחלק ממנו לכל הדורות. קניין שאינו נבלה לעולם הוא קניין הצדק, והוא שער פתוח שלא ייסגר לעולם. הנה כבוד גדול. ברוך האל שכיבד את משה מכל בני האדם. יתרומם הנביא הגדול הזה, שנתחזק בשמים ובארץ, וראה את האור הנגלה לו, ועטה כתר שלא עטה כמוהו אף אחד מכל בית אדם. כתר מוכן מימי הבריאה, שכתוב עליו אֶהְיֶה אֲשֶׁר אֶהְיֶה (שמות ג,יד) על ארבע פינותיו, ועל ראשו מלמעלה: עֶבֶד הָאֱלֹהִים (דברים לד,ה), המעיד עליו שהוא ראוי לכך. וכן ארבע מילים נשגבות: יְהוָה אֱלֹהֵינוּ יְהוָה אֶחָד (דברים ו,ד). על שתי כתפיו כתוב: אִישׁ הָאֱלֹהִים (דברים לג,א). לא יהיה דומה לו לעולם. נהלל את אדוננו, בוראנו ובעלינו, ונודה לו ונשתחווה לגדולתו, כי הוא אחד, יחיד, אין כמוהו במלכותו. אין אלוהים אחר מלבדו, מלך על הכול; ידו סומכת את כל הנבראים. עדות לקדמותו היא בריאת הנבראים וסידורם בסדר נאה. אילו היה לו שותף, עוזר במעשה, הייתה גבורתו פוסקת מתחילתה. שכן לגבי כל גיבור בעולם, כוחו אין בו לא חסרון ולא פסיקה. אדרבה, מעשהו שלם מכל בחינה, לא ימצא בו חסרון ולא פגם. אך אם יקרה ההפך, שיהיה שותף, כל מעשה שנעשה יהיה חסר שלמות. שכן המעשה כעושהו, בין בגבורה בין בחולשה. אם גבורת שניהם מאוחדת – יש רצון אחד משותף. אך אם יתפרד הדבר, וכל אחד מהם רוצה להראות את כוחו ולעשות מעשה שיוכיח שהוא החזק – יגרם הפיכה, והמעשה יישחת ולא יתקיים. יתרומם הגיבור המתקיים לבדו – ואין אל נכר מלבדו. כרצונו ברא, וכרצונו כונן, וכל מה שעשה מתקיים כשהוא. נודה לגבורתו, ונשתחווה לגדולתו, ונאמר ביראה גדולה ועדות אמת: "אין אלוהים כי אם אחד."');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (155,'III','23','וידבר משה והכהנים הלוים',3000231,'דכר עובדיון עמך מחטב עץ אי זלי מים הוה מקעמון מבתר כל אלין וגיורה והן שבט } ו {» סגה לית לה שבט ולא חלק וברי ישראל כהלון י « ן ולכל שבט פלגה והן מימרה והן יגור עמוכון גר בארעכון לא תונונו כיצובה מנוכון יהי עמוכון בעה חילה רבה ילף לישראל אלפן מרכן ללבה כיצובה מנוכון הך דאמר ותרחם לחברך כותך אנה יהוה בהדה ממללה תלמוד חיוס רב ועורי במימרו לא תונון יתה לא במה דו מכעס לה ולא במה דליתו יכל עליו וכל תשמיש ישראל עליון עבדה בארכנו וכן גדלה אמר יתודי יכולה דאלפן אלפן מרבי למן ילפנה ומקימה על דרגה מסקפה נשבח לחילה דמלתן בכן ונשתעבד קדמיו באימנו','He mentioned their dealing with you: from woodchopper or waterdrawer 
(ibid., v. 10) – their status (comes) afer all these. And the sojourner, even if he is 
numerous; he has no tribe and no share, while the Children of Israel are all 
tribes and every tribe has a share, and (therefore) this is His enunciation: When 
a stranger sojourns with you in your land, you shall not do him wrong […]. He shall 
be to you as the native among you (Lev. 19:33–34) – the Mighty one sought to 
teach Israel a lesson that subdues their heart. As the native among you – as it is 
said: Love your fellow as yourself; I am the Lord (Lev. 19:18). In this saying there is 
a teaching of great clemency, and so is in His saying you shall not do him wrong 
(Deut. 23:17), not in what enrages him and not in what he cannot overcome. He 
shall perform all the tasks of Israel with humility. This is what His Greatness 
said. Thanks to the Mighty One who taught us a teaching that exalts the one who 
learns it, and sets him on a high rank. Praised be the Mighty One who entrusted 
us with this. Let us submit before Him in faith.]','הזכיר את עיסוקם אתכם: מֵחֹטֵב עֵצֶיךָ עַד שֹׁאֵב מֵימֶיךָ (שם, פסוק י) – מעמדם בא אחר כל אלה. והגר, אפילו אם הוא רב; אין לו שבט ואין לו חלק, ואילו בני ישראל כולם שבטים וכל שבט יש לו חלק, ולפיכך זוהי אמירתו: וְכִי יָגוּר אִתְּךָ גֵּר בְּאַרְצְכֶם לֹא תוֹנוּ אֹתוֹ [...] וְהָיָה לָכֶם כָּאֶזְרָח מִכֶּם (ויקרא יט,לג-לד) – הגיבור ביקש ללמד את ישראל לקח המכניע את לבם. כאזרח מכם – כמו שנאמר: וְאָהַבְתָּ לְרֵעֲךָ כָּמוֹךָ אֲנִי ה'' (ויקרא יט,יח). באמירה זו יש תורה של חמלה גדולה, וכן באמרו לֹא תוֹנֶנּוּ (דברים כג,יז), לא בדבר שמרגיזו ולא בדבר שאינו יכול לעמוד בו. הוא יקיים את כל תפקידי ישראל בענווה. זהו מה שאמרה גדולתו. תודה לגיבור שלימדנו תורה המרוממת את הלומד אותה ומעמידה אותו במדרגה גבוהה. יהולל הגיבור שהפקיד זאת בידינו. נשתחווה לפניו באמונה.');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (156,'III','67a','וידבר משה והכהנים הלוים',3000672,'ושבעתיתה דליתמה הב בלך לא תעלם על חדה מנון שרוון עמינה ורבי מדעך במד לה תתילף לא ימללך לבך דו מכיך לא תשבקנה כבי דחכמתך דו מזדמן עמך בביתך ועורי בביתי ובגו קדשי ובגו מועדי ובגו איקרי דבה יקרתך וכל דלאבוה יהי לה מן זעור סעד רב ומה דאתלפ ] ת ת [ הי מלפנה ] ע [ דהן לא יתרבי סוכיל רק מן דעתה דאני הקימת קלומי ונביי ספרים בדיל מלפהתך מן שומיה אלפתך במשמע קלי ועל ארעה חזיתך ית גבורתי ואף ארשית למשה מביר ארהותה דאקימתה על רזיתה ואשקחת יתה מלוא באהן איקרה דאימנת יתה עליו כמשה לא אשתלח שלחי וכן אלה כתב בדילה ולא קם עוד נביא בישראל כמשה','The seven concerning the orphan – pay attention, do not ignore even 
one of them. See their beginning and increase your attention to what you learn. 
Let not your heart tell you that he is humble. You shall not abandon him in pain, 
for I taught you that he will join you in your house and also in My House and in 
My Sanctuary and in My festivals and in My glory by which I gloriﬁed you. All 
that is his father’s (inheritance) will be his, small and great alike. And what you 
have been taught, you shall teach him, so that he may not grow up a fool, empty 
of knowledge. For I set Myself up and also My prophet as teachers in order to 
teach you. From heaven I taught you by making you hear my voice. And on the 
earth I showed you My majesty, and commanded Moses to write the Law, and I 
appointed him to its teaching, and I found him qualiﬁed for the honor to which I 
appointed him. There was never (again) sent a messenger like Moses. Thus God 
wrote about him: Never again did there arise in Israel a prophet like Moses (Deut. 
34:10).','השבע הנוגעות ליתום – שימו לב, אל תתעלמו אפילו מאחת מהן. ראו את תחילתן והגבירו את תשומת לבכם למה שאתם לומדים. אל ייאמר לבבכם שהוא דל. לא תעזבוהו בצער, שכן לימדתי אתכם שהוא יצטרף אליכם בביתכם, ואף בביתי ובמקדשי ובמועדיי ובכבודי שבו כיבדתי אתכם. כל שהוא ירושת אביו יהיה שלו, קטן וגדול כאחד. ומה שלמדתם, תלמדוהו אותו, כדי שלא יגדל שוטה, ריק מידע. שכן אני הצבתי את עצמי ואת נביאי כמורים כדי ללמד אתכם. מן השמים לימדתי אתכם בהשמיעי את קולי. ובארץ הראיתי לכם את גדולתי, וציוויתי את משה לכתוב את התורה, ומיניתי אותו לתורתה, ומצאתיו ראוי לכבוד שלשמו מיניתיו. לא נשלח עוד שליח כמשה. כך כתב האלוהים עליו: ולא קם עוד נביא בישראל כמשה (דברים לד,י).');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (157,'III','31','וידבר משה והכהנים הלוים',3000311,'יהי לן נחכם מה דהות ברכתה במדע שלם וחכמה יתרה על ריש ממללה נשרי למודאה למלכה רבה דאמליכנן בכל איקר ועבדן שוין נירת דלאבהתן ואקים לן במה דעגה דלון דו בגדלה פסק לון ועל כלול אודאותה אמרו מלי ברכתה והיא ברכתה דאתיהבת לאברהם ואף ליצחק על כלול עובדה ומד בה יקרון בזבן דשמעו גדלה ארשה יתון אמרים בשעבוד חיול ואימנו סגי וכל עמה קעמין למשמע','It is appropriate that we should know what the blessing was, with per-
fect insight and exceeding wisdom. At ﬁrst, let us begin by giving thanks to the 
great King who has made us owners of all honor and made us worthy to inherit 
what belonged to our fathers, and fulﬁlled for us what He promised them, for He 
in His greatness allocated (it) to them. At the completion of the thanksgiving (the 
priests) said the words of the blessing, the blessing that was given to Abraham 
and Isaac too at the completion of the deed, and with which He honored them, 
at the time when they obeyed the Great One. He commanded them to speak with 
great submissiveness and abundant faith while all the people stands to listen.','ראוי שנדע מה הייתה הברכה, בתבונה שלמה ובחכמה יתרה. תחילה, נפתח בהודאה למלך הגדול אשר עשה אותנו בעלי כל הכבוד והכשיר אותנו לרשת את אשר היה של אבותינו, וקיים לנו את אשר הבטיח להם, כי הוא בגדולתו הקצה להם. בתום ההודאה אמרו הכוהנים את דברי הברכה — הברכה שניתנה לאברהם ולאיסחק גם הוא בתום המעשה, ובה כיבד אותם בעת שציתו לגדול. ציווה אותם לדבר בענווה רבה ובאמונה שופעת בעוד כל העם עומד ומאזין.');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (158,'III','7','וידבר משה והכהנים הלוים',3000071,'האן נביא כמשה דהוה אחס על ישראל חיוס רב עד מותר כד אמר לה אלה אשתבק ממני לא צבה אלא צלה בדילון אמר ואשיצנון ארתק לבה ותנא טבהתה החל מן רישה ושמעו מצר ושמעו דאתה יה אשר עין בעין נראה ועננך עמד עליהם וכדו ירום חיל רבי כמד מללת יהוה רחיק רגזה וסגי חסדה וקשטה וסלח לכל עובדיהון האן נביא כמשה דהוה אחס על ישראל כות אבוה על בריה ולא עלל על לבה צערה אלא בדילון וכן אתגלה לנן בכתבה ולא אתחסך מן מעילה ליד ארעה אלא בדיל מד לון אמר מרון אה קהלה אשתעבד והיא מלת אסכת ושמע לקשטה ומד אלפך לא תעלם עליו ושרי ואמר מכדו אנה ממלל עם לבי סעד אמת אעבד עובד מכה לי ומרחקי מן עבודי ומטרד מן רחותה בכל אתר כות קין קטול אחוה והוה כאלי וטמא ומד לאבהתי אתיהב לדבבי ואנה מנה מתרוקן בכל עת אוכח גרמך מנך ובך בזכו עבידה בך מן אבהן טבין אלו הויך מד הויך אנה ידע דאתה מעזר ליד קשטה דארשה טבה כלה בלש יתה והן הכעס יומה בתר יעזר ומרה מקבלה וכן אמר ושבת ושב יהוה אלהיך מתי ייתון אלין טביה ויאבדו כל בישיה דשבקו שביל רבית אלוכה והלכו שביל קטלת הנוסע בגוה אוי לאנש הדה עבידתה אלית קין קמיכון דהך בתר ריחות נפשה ואתלעט עד לעלם וככן נמרודה וכן גברי סדם ועוד פרעה דנצעתון תחמדותון ואזלו בתרה ועבודי עגלה דאנשתון תחמדותון לקשטה ולא אתמר לגוי מה אתמר לון ולא אתנשי גוי מד לה נשו אלולי הוה בינכון ובין קשטה דבבה לא עבדתון הדה לית דבבתכון לאלה מכיה אלא בוכון מן עמיכון לגו עלמה אכעס לאלה ואצלח במה דעבד ואני ידע דאתון מעזרין › מבתר ‹ יגבי קשטה פריתה מנוכון כמה דאמר והם ירצו את עונם ייתי בשלם מן ירחם לקשטה ויחדי בה עלמה וכל דיאריו','Where is a prophet like Moses who showed to Israel exceedingly great 
compassion? When God said to him: Let me alone (Deut. 9:14), he did not con-
sent, but he prayed for them. (God) said: I may destroy them (ibid.) – his heart 
beat and he detailed the good things starting from the beginning: Then the Egyp-
tians will hear of it (Num. 14:13), they have heard that You, O Lord […] are seen 
face to face, and Your cloud stands over them (Num. 14:14). And now, let my Lord’s 
forbearance be great, as You have declared […] a God […] slow to anger, and 
abounding in grace and faithfulness (Num. 14:17–18). And (Moses) atoned all their 
(sinful) deeds. Where is there a prophet like Moses who showed mercy on Israel 
like a father with his sons, and no distress entered his heart but for them? This 
was revealed to us in the Book. His entering into the land was only prevented 
because of what their Master said to them: “O congregation, be submissive” – 
this is (the meaning of) the word(s) Listen and hear – to the True One. Do not 
ignore what He taught you, and begin saying: “from now on I talk to my heart: 
till when do I do deeds that strike me and make me distanced from my Creator 
and banished from the Divine Favor in any place, like Cain, who killed his broth-
er and became rejected and impure (Gen. 4:12). And what belongs to my ances-
tors was given to my foes, while I was emptied of it?” At any time reprove 
yourself, by yourself, with the uprightness implanted in you from good ances-
tors. Were you what you used to be, I know that you would return to the True 
One, whom the whole “good foundation” sought. And if he exasperates today, 
tomorrow he will repent, and his Master will receive him. And thus He said: and 
you return […] and the Lord your God will return (Deut. 30:2–3). When will these 
good ones come, and all the wicked ones will perish, (those) who abandoned the 
path which elevates the one who walks in it, and walked on a path that kills the 
one who strolls in it? Woe to the person whose deed is thus. Don’t you have Cain 
in mind, who walked afer the desire of his soul, and was cursed for eternity? 
Likewise Nimrod, and also the people of Sodom, and also Pharaoh, whom their 
lust subdued, and they followed it, and the makers of the calf who forgot their 
desire for the True One. Never has been said about a nation what has been said 
about them, and no nation forgot as they have forgotten. Had there not been 
enmity between you and the True One, you would not have done this. Your 
hatred to God does no harm except to you alone. Who have you seen in the 
world vexing God and succeeding in whatever he does? I know that you repent 
afer God takes revenge on you, as He said: They will atone for their iniquity (Lev. 
26:43). Let he who loves the True One come in peace, and (let) the world and all 
its inhabitants rejoice in him.','היש נביא כמשה שהראה לישראל חמלה גדולה ועצומה מאוד? כאשר אמר לו האלוהים: הֶרֶף מִמֶּנִּי (דברים ט,יד), לא הסכים, אלא התפלל עליהם. אמר: וַאֲשַׁמִּידֵם (שם) – ליבו פעם והוא פירט את הדברים הטובים מן הראשית: וְשָׁמְעוּ מִצְרַיִם (במדבר יד,יג), שמעו כִּי אַתָּה יְהוָה [...] נִרְאָה עַיִן בְּעַיִן, וַעֲנָנְךָ עֹמֵד עֲלֵיהֶם (במדבר יד,יד). וְעַתָּה יִגְדַּל נָא כֹּחַ אֲדֹנָי כַּאֲשֶׁר דִּבַּרְתָּ [...] אֵל [...] אֶרֶךְ אַפַּיִם וְרַב חֶסֶד וֶאֱמֶת (במדבר יד,יז-יח). ומשה כיפר על כל מעשיהם. היש נביא כמשה שרחם על ישראל כאב על בניו, ולא נכנסה צרה ללבו אלא בגללם? הדבר נתגלה לנו בספר. כניסתו לארץ נמנעה ממנו רק בגלל מה שאמר אדונם להם: "עדה, היכנעו" – זוהי משמעות המילים הַקְשֵׁב וּשְׁמַע – לאמת. אל תתעלמו ממה שלימד אתכם, ופתחו ואמרו: "מעתה אני מדבר אל לבי: עד מתי אני עושה מעשים הפוגעים בי ומרחיקים אותי מבוראי ומגרשים אותי מן החן האלוהי בכל מקום, כקין שהרג את אחיו ונעשה נדחה וטמא (בראשית ד,יב). ומה שייך לאבותיי ניתן לאויביי, ואני ריק ממנו?" בכל עת הוכח את עצמך, בעצמך, ביושר הנטוע בך מאבות טובים. לו היית כפי שהיית, יודע אני שהיית שב אל האמת, אשר כל "היסוד הטוב" ביקש. ואם הוא מתרגז היום, מחר ישוב בתשובה, ואדונו יקבלו. וכך אמר: וְשַׁבְתָּ [...] וְשָׁב יְהוָה אֱלֹהֶיךָ (דברים ל,ב-ג). מתי יבואו הטובים הללו ויאבדו כל הרשעים, אשר עזבו את הדרך המרוממת את ההולך בה, והלכו בדרך ההורגת את המטייל בה? אוי לאדם שמעשהו כך. הלא קין לנגד עיניך, שהלך אחר תאוות נפשו ונתקלל לעולם? כן נמרוד, וכן אנשי סדום, וכן פרעה, שתאוותם שלטה בהם והלכו אחריה, ועושי העגל ששכחו את שאיפתם לאמת. לא נאמר על עם כמה שנאמר עליהם, ולא שכח עם כמו שהם שכחו. לולא הייתה איבה בינך לבין האמת, לא היית עושה זאת. שנאתך לאלוהים אינה מזיקה אלא לך בלבד. מי ראית בעולם מכעיס את האלוהים ומצליח בכל מעשיו? יודע אני כי תשוב בתשובה אחרי שהאמת ייקום בך, כפי שאמר: וְנָשְׂאוּ אֶת עֲוֹנָם (ויקרא כו,מג). יבוא אוהב האמת בשלום, וישמח בו העולם וכל יושביו.');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (159,'III','48','וידבר משה והכהנים הלוים',3000481,'ארור מקל אבוה ואמה צמתת הדה מלתה עסרה מצואן חדה מן שומיה וחדה מן ארעה וחדה מן לבה וחדה מן מדעה תריה מרבין גויתה למקעמה וחדה מן סהבך וחדה מן סהבתך הקעומין בתרבותך ואף במילפך וחדה מן יוסף וחדה מן אפרים תרים רמים חיולין וחדה מן מלאכיה וחדה מן כבודה כללו מה דאתעבד לישראל עמי כל חדה מן אלין מללת ממלל חכמה מרביה אלופה שומיה אמרת אנה לך מניקה חלב טב ובאוצרי טבהתה דתזדהן מנה לא תשימני מרגזה עליך ומגריה עליך תשניק חיול ובתר כן אנה אחסה 51, עליך ואזהרך מן מרדה על אלה ] ה [ לא שמעת קין ] כד [ שאל למרה האן ייזל ] תה [ י לה אסתרו ] כיי טר [ יד מן ] ארע [ לארע ] וליתו [ מסתר ] מני [ בכלום ] האן ב [ רנשה ] אזל [ אנה ] מטלל [ ה עליו ] אן [ בביתה ] א [ י במדינה לא תעבדני משתבקה מנך תקום בדין רב מותר','Cursed be he who dishonors his father or his mother (Deut. 27:16). This 
statement comprises ten teachings, one from heaven and one from earth, one 
from the heart and one from the mind – both magnify the body for existence –, 
one from your grandfather and one from your grandmother – the establishers of 
your fostering and your teaching –, one from Joseph and one from Ephraim – 
two great and mighty ones –, one from the angels and one from the Glory – they 
completed what was done to Israel. See: each of these spoke a statement of 
wisdom that elevated its learner. The Heaven said: “I suckle you with good milk, 
and in my storehouse there are good things from which you are nourished. Do 
not make me angry with you] and urge on you a mighty aﬄiction, afer I had 
mercy on you and had warned you from rebellion against God. Did you not hear 
about Cain when he asked his Master where he should go so as to get a hide-out, 
and indeed, he was expelled from land to land, and had no hide-out from me at 
all? Wherever a man goes, I shade him, whether in his house or in the city. Do 
not forsake me, (lest) you will stand in exceedingly great punishment.”','אָרוּר מַקְלֶה אָבִיו וְאִמּוֹ (דברים כז,טז). אמירה זו כוללת עשרה לימודים: אחד מן השמים ואחד מן הארץ, אחד מן הלב ואחד מן המחשבה – שניהם מרוממים את הגוף לקיום –, אחד מסבך ואחד מסבתך – מכוני גידולך ולימודך –, אחד מיוסף ואחד מאפרים – שניים גדולים ועצומים –, אחד מן המלאכים ואחד מן הכבוד – הם השלימו את מה שנעשה לישראל. ראה: כל אחד מאלה אמר אמירת חכמה שרוממה את לומדה. השמים אמרו: "אני מיניקה אותך בחלב טוב, ובאוצרי יש טוב שממנו אתה ניזון. אל תכעיסני עליך ואל תביא עליך מכה עצומה, אחרי שריחמתי עליך והזהרתיך ממרידה באל. האם לא שמעת על קין כאשר שאל את אדונו לאן ילך כדי למצוא מחבוא, ואכן, גורש מארץ לארץ, ולא היה לו ממני מחבוא כלל? בכל מקום שאדם הולך, אני מצילה עליו, בין בביתו ובין בעיר. אל תעזבני, פן תעמוד בעונש גדול מאוד."');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (160,'III','5','וידבר משה והכהנים הלוים',3000051,'הסכת אלפה המוסר ובתר כן אמר ושמע אלפן תתחיל בה הסכת דאה מלתה לא אתמרת אלאן אכהן כדו יתגלי קדמיך מד הוא מלפנך ומהו מוכח לך ומזהרך אסכת חכם דאת שטי בכל עת ואלה מקבל מנך וסבלך כד תעזר לידה כד צבעת לידה במצר וקבל מנך ושגר יתי ועבדת פליאן לקדמיך וקטלת פרעה וכל חילו וכל עמו ואגיזתך בימה ואת לביש כליל מתכלל ברבו רבה יתיר עד מאד והבלדו כל דיארי ארעה ממה דהוה כל אהן אתעבד בדיל מרבהתך ובתר תלתה יומין רננת על קשטה ולא גזיתך בכן וזזע קיאמי אבהתך ופרק יתך ואתחזי קשטה ופרקך וארשה יתי למלפך כמה דאמר אם שמע תש לקול יהוה אל והכשיר בחזותה תעבד תלבש בכן כליל תגדל בה על כל אמיה ואשמעך קלה ואקים גרמה ספר טב לאלפנך והישר בעיניו תעשה סעד תרום ותהי כשיר בפעליך מטט שמעת אהן שבעתי מליה ורננת איך לא שמעת ובגו כל עת אתה עביד אהן וקשטה זעוקך ואתה לא עני לה עד האן לא תבהת ממד אתה עביד וכדו ישראל אתיתבו וקבעו בליכון ואתילפו ולא יהי אכה רנון דו אתר רב לא כותה','Listen (Deut. 27:9) – He taught him the discipline. Aferwards he said and 
hear (ibid.) – a teaching by which you will be strengthened. – הסכתthis word has 
never been said except here. Now what He teaches you will be revealed before 
you and by what He admonishes you and warns you. – הסכתknow that you may 
stray at any time, but God listens to you and forgives you whenever you return to 
Him. When you cried out in Egypt, He heard you and sent me. I performed won-
ders in front of you, and I killed Pharaoh and all his army and his people. I took 
you across the sea, while you wear a crown adorned with exceedingly great glo-
ry, and all the inhabitants of the earth were dismayed by what happened. All 
this was carried out in order to glorify you. Afer three days you murmured 
against the True One, but He did not punish you for this. (On the contrary,) He 
awoke the covenants of your ancestors and redeemed you. The True One ap-
peared and redeemed you and commanded me to teach you, as He said: If you 
will hearken to the voice of the Lord your God, and do that which is upright in his 
sight (Exod. 15:26), you will wear thereby a crown, by which you will prevail over 
all the nations. He made you hear His voice and made Himself a good teacher to 
teach you, and do that which is upright in his sight so that you may be exalted 
and be upright in your deeds. Since the time that you heard these seven words, 
you murmured, as though you never heard. And every time you do so, the True 
One calls you and you do not answer him. When will you not be afraid of what 
you do? And now Israel, settle down and pay attention and learn, so that no 
murmur may be here. For this is a great place; there is none like it.','הַקְשֵׁב (דברים כז,ט) – לימד אותו את המוסר. לאחר מכן אמר וּשְׁמַע (שם) – תורה שבה תתחזק. – הַקְשֵׁב – מילה זו לא נאמרה מעולם אלא כאן. עתה, מה שהוא מלמדך יתגלה לפניך, ובמה שהוא מוכיחך ומזהירך. – הַקְשֵׁב – דע כי תוכל לתעות בכל עת, אך האלוהים שומע לך ומוחל לך בכל פעם שתשוב אליו. כאשר זעקת במצרים שמע אותך ושלח אותי. עשיתי נפלאות לפניך, והרגתי את פרעה ואת כל חילו ועמו. העברתי אותך בים, ואתה עוטה כתר מעוטר בכבוד גדול ועצום מאוד, וכל יושבי הארץ נבהלו ממה שאירע. כל זאת נעשה כדי לפארך. לאחר שלושה ימים רטנת על האמת, אך הוא לא עָנַשְׁך על כך. אדרבא, הוא העיר את בריתות אבותיך וגאל אותך. האמת נגלה וגאל אותך וציווה עליי ללמדך, כפי שאמר: אִם שָׁמוֹעַ תִּשְׁמַע לְקוֹל יְהוָה אֱלֹהֶיךָ וְהַיָּשָׁר בְּעֵינָיו תַּעֲשֶׂה (שמות טו,כו), תעטה בזה כתר שבו תגבר על כל הגויים. הוא השמיע לך את קולו, ועשה את עצמו למורה טוב ללמדך, וְהַיָּשָׁר בְּעֵינָיו תַּעֲשֶׂה, כדי שתתעלה ותהיה ישר במעשיך. מאז ששמעת שבע מילים אלה, רטנת, כאילו לא שמעת מעולם. ובכל פעם שאתה עושה כן, האמת קורא לך ואתה אינך עונה לו. מתי לא תירא ממה שאתה עושה? ועתה ישראל, שקוט והקשב ולמד, ולא יהיה כאן עוד ריטון. כי זה מקום גדול; אין כמוהו.');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (161,'III','24','וידבר משה והכהנים הלוים',3000241,'ונעזר אל ממללה דבה הוינן דאנן עמין איך ראובן וזבולן קעמין ביני ארבעתיתה , אתב מדעך ושמע מד בה תתוזף אלפן דו צריך יפרט גנותה בפמה ומזהר מנה הן לא יתעבד לעלם בדיל נדע דמרן זכי ליתו נסב אפים לרב ולא לזעור וזבולן מודע בפמה כל מה יתעבד ב › פ ‹ נאיה דמבדר אבוה גלה מדורה ומשה גלה מפוקה','Let us return to the matter we were dealing with. We see how Reuben 
and Zebulon stood among the four. Set your mind and hear something which 
will add to you a teaching. For he needs to specify his blame with his mouth and 
warn about it so that it may not be done ever, and so that we may know that our 
Master is righteous, that He shows no favor whether to great or to small. And 
Zebulon declares too what will be done to the scattered one who strays. His 
father revealed his dwelling and Moses revealed his departure.','נשוב לעניין שעסקנו בו. אנו רואים כיצד עמדו ראובן וזבולון בין הארבעה. שים לבך ושמע דבר שיוסיף לך תורה. שכן עליו לפרש את אשמתו בפיו ולהזהיר ממנה כדי שלא תיעשה לעולם, ולמען נדע שאדוננו צדיק, שאינו נושא פנים לגדול ולקטן. וגם זבולון מכריז מה ייעשה למפוזר הנתעה. אביו גילה את מושבו ומשה גילה את יציאתו.');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (162,'III','74','וידבר משה והכהנים הלוים',3000741,'נתן אפרשו רבה ודחילה עד האן נתילף כל מה דאלפן נביה רבה משה אהן אלפן יתר חזה מרן גלת ] לבטתה ארור לקח שחד להכות נפש לית אנה שבק לה [ ומקים יתה בתשניק יתר ומחסכה תרי עלמין ומפרי יתה בגוני מעואן ומשלם יתה בגוני צרען ועבד שומיה קבלין עליו › וארעה ‹ צניקה עליו וכל הדה לעבוד אלין גנוהתה ואשרי עליו קללה לעולם לא תשרי כי גזואה להדה ולהדה באדי כחדה סיובה מוזף לה תשניקה ודסכה דו סתרה במד יהב לה ועבד תאות לבה אני מכללה עד יתשלם חובה כמד כתבת בשרוה כי לא שלם עון האמרי ] ע [ ד הנה ובתר כל הדה ליתי מעלם על דם זכי מה כתבת קמיך קצת קין והבל כד קעם לידה וקטלה מבזע ומבזק תהי בארעה הלא על מלואה יגבי קין וברה דברה יזיף ומוזף ובדן אלפן לכל דריה דלא ידמי אנש בקין ולא יעבד כעובדה כי חסל גדלי יהי מעלם על דמות דאה עובדה בישה דו מחיב רגזי כי גדלי יהוב לאנשה עותר וקניאן יקטל בה דם זכי לוד יקני בה נפשהן ירבי יתון באימנותה','Let us set out a great and frightful division, so that we may learn what 
the great prophet Moses taught us. This is a great teaching our Master showed, 
(and) revealed was the curse: Cursed be he who takes a bribe to slay an innocent 
person (Deut. 27:25). I shall not leave him be, and shall place him in great aﬄic-
tion and withhold him from both worlds and hasten him to various plagues, and 
hand him over to a variety of leprosies, and make the heaven dark over him and 
the earth blocked to him – and all this to the doer of these shameful acts. I shall 
set up a curse over him which will never be loosened. Indeed, the punishment 
for both, this and this, is in My hand altogether. His deﬁlement increases his af-
ﬂiction. The one who sought that he cover him up by what he gave him, so that 
he fulﬁlls the lust of his heart, I shall bring to an end when the sin is carried out, 
as I wrote in “The Beginning”: for the iniquity of the Amorites is not yet complete 
(Gen. 15:16). Afer all this, I do not disregard innocent blood (Deut. 27:25). Did I 
not write before you the qiṣṣa of Cain and Abel, when he approached him and 
killed him: You shall be a fugitive and a wanderer on the earth (Gen. 4:12)? For 
Cain is punished in entirety and his son’s son much more so. In this there is a 
lesson for all the generations, that nobody should resemble Cain and do the like 
of his deed. Indeed, far be it from My greatness to ignore (something) like this 
evil deed, which involves My anger. For My greatness (does not) give to men 
wealth and possession in order to kill with it innocent blood, but in order to 
gather souls with it and make them grow in faith.','נציג חלוקה גדולה ונוראה, כדי שנלמד מה שלימד אותנו משה הנביא הגדול. זוהי תורה גדולה שהראה אדוננו, ונגלתה הקללה: אָרוּר לֹקֵחַ שֹׁחַד לְהַכּוֹת נֶפֶשׁ דָּם נָקִי (דברים כז,כה). לא אניחנו, ואשים אותו בסבל גדול ואמנע ממנו את שני העולמות ואמהרנו למכות שונות, ואמסרנו למיני צרעת, ואחשיך עליו את השמים ואסגור לפניו את הארץ – וכל זאת לעושה מעשי הבושה הללו. אקים עליו קללה שלא תישמט לעולם. הן העונש על שניהם – זה וזה – בידי כולו. טומאתו מגדילה את סבלו. מי שביקש כי יכסה עליו בנתינתו, כדי שימלא את תאוות לבו – אביאנו לסופו כאשר יושלם החטא, כפי שכתבתי ב"בראשית": כִּי לֹא שָׁלֵם עֲוֹן הָאֱמֹרִי (בראשית טו,טז). לאחר כל זאת, איני מתעלם מדם נקי (דברים כז,כה). האם לא כתבתי לפניכם את הסיפור של קין והבל, כאשר ניגש אליו והרגו: נָע וָנָד תִּהְיֶה בָּאָרֶץ (בראשית ד,יב)? שכן קין נענש כולו, ובן בנו אף יותר ממנו. יש בזה לקח לכל הדורות, שלא ידמה איש לקין ולא יעשה כמעשהו. הן רחוק מגדולתי להתעלם ממעשה רע כזה, המעורר את כעסי. שכן גדולתי אינה נותנת לבני אדם עושר וקניין כדי להרוג בהם דם נקי, אלא כדי לקרב בהם נפשות ולגדלן באמונה.');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (163,'III','32','וידבר משה והכהנים הלוים',3000321,'ואנון עסרה ברכהן רברבהן תלתה לאברהם בפמה דאלה אתמרת ואברכך והרבה שמך ונברכו בה כל אמי ארעה כי ברוך אברכך וסגוי אסגי ית זרעך ותלתה ליצחק וברך אלהה ית יצחק ברה ויתברכו בזרעך כל גוי ארעה ויברכהו יהוה וליעקב חדה ויתברכון בך כל גוי אדמתה אה שבעה לזכאי עלמה ותלתה מן פמה דנביה רבה משה ולמהב עליכם יומה ברכתה ועל כלול עבידת משכנה וברך יתון משה ובטור סיני ויברך יתכון כמד מלל לוכון ועורי ברכתה דנח מד דבח לכבון הרגריזים ואתבסר באנחמו','And they are ten great blessings. Three were said to Abraham by the 
mouth of God: And I will bless you, and make your name great (Gen. 12:2), and all 
the families of the earth shall bless themselves by you (Gen. 12:3), I will bless you, 
and I will multiply your descendants (Gen. 22:17). Three to Isaac: God blessed 
Isaac his son (Gen. 25:11), and by your descendants all the nations of the earth will 
bless themselves (Gen. 26:4), the Lord blessed him (Gen. 26:12). One to Jacob: By 
you […] shall all the families of the earth bless themselves (Gen. 28:14) – behold, 
seven to the Righteous of the world. And three from the mouth of the great 
prophet Moses: That He may bestow a blessing upon you this day (Exod. 32:29), 
and at the completion of the making of the Sanctuary: And Moses blessed them 
(Ex. 39:43), and on Mount Sinai: And bless you, as He has promised you (Deut. 
1:11). In addition: the blessing of Noah (Gen. 9:1) when he sacriﬁced before 
Mount Gerizim, and was announced about comfort (ibid., v. 11).','ועשר ברכות גדולות הן. שלוש נאמרו לאברהם מפי האל: ואברכך ואגדלה שמך (בראשית יב,ב), ונברכו בך כל משפחות האדמה (בראשית יב,ג), ברך אברכך והרבה ארבה את זרעך (בראשית כב,יז). שלוש ליצחק: ויברך אלהים את יצחק בנו (בראשית כה,יא), והתברכו בזרעך כל גויי הארץ (בראשית כו,ד), ויברכהו ה'' (בראשית כו,יב). אחת ליעקב: ונברכו בך [...] כל משפחות האדמה (בראשית כח,יד) — הרי שבע לצדיק העולם. ושלוש מפי משה הנביא הגדול: לתת עליכם היום ברכה (שמות לב,כט), ובתום הקמת המשכן: ויברך אתם משה (שמות לט,מג), ובהר סיני: וברכך כאשר דבר לך (דברים א,יא). ויש להוסיף: ברכת נח (בראשית ט,א) כאשר הקריב לפני הר גריזים, והובשר לו על הנחמה (שם, פסוק יא).');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (164,'III','12','וידבר משה והכהנים הלוים',3000121,'עם קדש ליהוה אתון בחורין בעלמה וכל בחור מתגלג וכל אנש דאתוקר הוא מתיטב בכלה וכל מתיטב מתחיל לעלם מד את חכם דאתה בחור אמיה ועם קדש ליהוה אלהך לאוי עליך הן תטר דאה מיתוביתה ותשמע מן פקוד יהוה אלהך הלא מן שמע בקלה דמרה יתגלג ויהי מגדל בכל דרי עלמה שמע אגזריה דאנה מפקדך על פם קשטה ולא תחלף מד אנה מפקדך הלא לית לאוי לך תהי מחליף לא מללת עמך אלא בסהדים עד לא יהי ממללה מגן שרוי מה עבדתי רבית לכהניה דרגה ממנה עד לעלם ואתון כהלכון סדירין וכל אחד סהד על חברה כהניה סהדים ומהימנים קדשיה ואתון סהדים לבושי קדש מן מרה דכל קדשיה כהניה לון שבעה דרגים כל חדה מנון יתרה על חברתה לון מקדמהתה ומיכל קדש › י ‹ ה ואימנותה עליה ועל כל מד הו לאלה וסהדות קשטה ולמקח מה דו לון חלק ולמשמש אתרי סגדתה לעלם ולכהנה רבה עסרה מיתובין לית לה בון שותף ואנון אוזפו על מיתוביתה מטהר ומדכי וממשח ולבש ומברך ומשרי ומסלח לגו פרכתה ודאר בביתה דמרה ולא יסתיב במית ולא יפק מן מקדשה מנון ארבעה בינה ובין בניה ואשתה לה לחודה לית לחורן בה נמי עמי מיתובהתה אלין ושבח למלכה רבה דיקר בון לכהנה רבה ישתבח יכולה תדירה לגרמה מלכותה רבתה ושלטנותה יתרה ליתו מתחלף ולא משתאם מנה נדחל ולה נודי וקמיו נסגד ונסיד ונימר לית אלה אלא אחד','A holy people of the Lord (SP Deut. 27:9) – you are chosen in the world, 
and everyone chosen is gloriﬁed. And every man who was honored is promoted 
in everything. And everyone promoted is strengthened forever. Since you know 
that you are chosen among the nations and a holy people of the Lord your God, it 
is appropriate for you that you preserve this rank and obey the command of the 
Lord your God. For he who obeys his Master will be gloriﬁed and will be elevated 
through all the generations of the world. Hear the precepts which I command 
you according to the True One, and do not change what I command you, for it is 
not appropriate for you to change (anything). I spoke to you only (in the pres-
ence of) witnesses, so that the speech may not be in vain. The beginning of what 
I did: I magniﬁed the priests (by a) rank that endures forever. And all of you are 
arranged, and each of you testiﬁes for his companion. The priests are witnesses 
and appointed to the holy things, and you are witnesses, wearing holiness from 
the Master of all holiness. The priests possess seven prerogatives; every one of 
them exceeds the other. They perform the approach, the consuming of what is 
sanctiﬁed, the appointment upon it and upon everything that pertains to God, 
and the testimony to the truth, and the receipt of their share, and the service of 
the place of worship forever. The high priest possesses ten prerogatives, having 
no associate in them, and they are a supplement to his prerogatives. He puriﬁes 
himself and puriﬁes (others), is anointed, and wears, and blesses, releases and 
atones within the veil, and abides in his Master’s House, he is not deﬁled by a 
corpse, does not depart from the temple. Four of them are for him and his sons 
and six for him alone, no other has a share in them. See these tasks and praise 
the Great King, who honored the high priest by them. Praised be the Mighty One, 
enduring by Himself, great is His kingdom, His dominion is supreme. He does 
not change nor can He be evaluated. Let us fear Him and thank Him, and bow 
down before Him, and testify and say: “There is no god but One.”','עם קדוש לה'' (ספר שומרוני דברים כז,ט) – אתם נבחרים בעולם, וכל הנבחר מפואר. וכל איש שנכבד מתעלה בכל. וכל המתעלה מתחזק לעולם. מאחר שאתם יודעים שאתם נבחרים מבין האומות ועם קדוש לה'' אלוהיכם, ראוי לכם לשמור על מדרגה זו ולציית למצות ה'' אלוהיכם. כי המציית לאדונו יכובד ויתרומם בכל דורות העולם. שמעו את החוקים שאני מצווה אתכם על פי האמת, ואל תשנו את אשר אני מצווה אתכם, כי אין זה הולם לשנות דבר. לא דיברתי אליכם אלא בפני עדים, כדי שהדברים לא יהיו לריק. ראשית מה שעשיתי: גידלתי את הכוהנים במעלה הנצחת לעולם. וכולכם ערוכים, וכל אחד מכם מעיד על חברו. הכוהנים הם עדים ומינויים על הקדשים, ואתם עדים, לבושים קדושה מאדון כל הקדושה. לכוהנים שבע זכויות; כל אחת עולה על חברתה. הם מקיימים את הגישה, אכילת הקדשים, המינוי עליהם ועל כל הנוגע לאלוהים, העדות לאמת, קבלת חלקם, ועבודת מקום הפולחן לעולם. לכוהן הגדול עשר זכויות שאין לו שותף בהן, והן תוספת על זכויותיו. הוא מטהר את עצמו ומטהר אחרים, נמשח ולובש, מברך ומשחרר ומכפר מבפנים לפרוכת, ושוכן בבית אדונו, אינו מטמא למת ואינו יוצא מן המקדש. ארבע מהן לו ולבניו ושש לו לבדו, ואין לאיש אחר חלק בהן. ראו את המשימות הללו ושבחו את המלך הגדול שכיבד בהן את הכוהן הגדול. ברוך האדיר, הנצחי בכוחו, גדולה מלכותו ועצומה ממשלתו. לא ישתנה ואין לשערכו. נירא אותו ונודה לו, ונשתחווה לפניו, ונעיד ונאמר: "אין אלוה מלבד האחד."');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (165,'III','58','וידבר משה והכהנים הלוים',3000581,'נתן אפרשו גדילה ודחילה ונקים קנומן במקום אלפנה ונשמע אזהרותה תלתיתה ארור מסיג גבול רעהו ואמרו כל העם אמן עמי הדה אזהרותה וחכם רזה ולא תסטי מנה לא ימין ולא שמאל די אסחנת עשרה חלקים חמשה לכהניה ולנשיאיה ותרין לדיאניה ותרין לקהלה וחדה לשוטרה ] י [ שתבח אשר ] א [ לפן כל הדה עמי מה אמיר לכהניה וגדל מדעך במה דתיל › פ ‹ נה לא תהי מגדד במד תעבד בתשמישתה דחיבה אלה עליכון ומד לוכון הפלג בכל ארח וארח דמות חלקון מן טוב ישראל ומה אתיהב לוכון מן חלקיה עמי הך הוא כל חלק לקבל עובד ולא תהונו עבדים עובד יכליכון מן מיכל קרבן אלהכון ולא תעבדו שקר בדין יתהפך עליכון בגנו ודאתמר לנסיאה עמי הך הו ואלפה בגדל תתרבי לא יקום עד › אחד ‹ במימר גדף למאבד נפש עד יהי אתר חברך שמם ויסב באדך מד ליתו לאוי לה ודאתמר לדיאנה עמינה הך הו ואלפה ולא תפק מנה לא תשא פני דל ולא תהדר פני גדול ודאתמר לקהלה עמי יתה הך הו ועבדה קמיך תורס תקיף והיא מלתה דאמרה אלה וכתבה קמיך ואהבת לרעך כמוך אקימה ינשם לבך','Let us set out a great and frightful division, set ourselves in the place of 
learning and hear the third warning: Cursed be he who moves his fellow’s land-
mark, and all the people shall say Amen (Deut. 27:17). See this warning and know 
its meaning and do not turn from it right nor lef, for it contains ten sections – 
ﬁve referring to the priests and the princes, two to the judges, two to the congre-
gation, and one to the oﬃcials. Praised be He who taught us all this. See what 
was said concerning the priests and elevate your mind with what you will learn 
of it. Do not be a rebel in what you do within the service that God assigned to 
you. And what has been allocated to you in every way, like that which He allo-
cated from the good of Israel, and that which has been given to you from the al-
locations, see how it is: every allocation according to action. (Thus), you shall 
not do a deed which may prevent you from eating the oﬀerings of God. You shall 
not do wrong in judgement – it will turn against you in blame. And what was 
said concerning the princes, see how it is and learn it well – you will be elevated: 
A single witness with a statement of aﬀront intended in order to destroy a per-
son, so that your neighbor’s place will be desolate, shall not be valid, as (the wit-
ness) takes through you what he does not deserve. And what was said concern-
ing the judge, see how it is and learn it and do not depart from it: Do not favor 
the poor or show deference to the rich (Lev. 19:15). And what was said concerning 
the congregation, see how is it and make it a strong shield before you – it is the 
word that God said and wrote before you: Love your neighbor as yourself (Lev. 
19:18) – He established it to relieve your heart.','נשים לפנינו חלוקה גדולה ונוראה, נעמוד במקום הלימוד ונשמע את האזהרה השלישית: ארור מסיג גבול רעהו ואמר כל העם אמן (דברים כז,יז). ראה אזהרה זו ודע את משמעותה ואל תסור ממנה ימין ושמאל, כי יש בה עשרה חלקים – חמישה מתייחסים לכוהנים ולנשיאים, שניים לשופטים, שניים לעדה, ואחד לפקידים. ברוך אשר לימד אותנו את כל זה. ראה מה שנאמר על הכוהנים ורומם את שכלך במה שתלמד ממנו. אל תהי מורד במה שאתה עושה בתוך העבודה שהאל הטיל עליך. ומה שנחלק לך בכל דרך, כגון מה שחלק מטוב ישראל ומה שניתן לך מן החלוקות, ראה כיצד הוא: כל חלוקה לפי מעשה. לפיכך, אל תעשה מעשה שעלול למנוע ממך לאכול את קרבנות האל. אל תעוות את הדין – יחזור עליך לגנאי. ומה שנאמר על הנשיאים, ראה כיצד הוא ולמדהו היטב – תתעלה: עד אחד בהצהרת עלבון שנועדה להשמיד אדם, כדי שמקום רעך ישומם, לא יהיה תקף, שכן (העד) לוקח באמצעותך מה שאינו מגיע לו. ומה שנאמר על השופט, ראה כיצד הוא ולמדהו ואל תסור ממנו: לא תישא פני דל ולא תהדר פני גדול (ויקרא יט,טו). ומה שנאמר על העדה, ראה כיצד הוא ושים אותו כמגן חזק לפניך – הוא הדבר שאמר האל וכתב לפניך: ואהבת לרעך כמוך (ויקרא יט,יח) – הוא קבעו להקל על לבך.');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (166,'III','60','וידבר משה והכהנים הלוים',3000601,'נתן אפרשו דמי לבוצין מניר קמינן וקפל כל חשך דגדלה חזה וחילין במחכום רב טובה לאשר ימלכנה חזו רז הדה מלתה רבתה ואתעידו בה ומנה לא תסטו לעלם ארור משגה עור בדרך ואמרו כל העם אמן בקל תליל הדה מלתה אזמנת תרין עסר מצואן עמי יתון ובון אתבונן לית הדה מלי לסמי עינה ליתון אלא לאנש עמי ושמע גבר ישאל על קשט לא תעזר שיאלה מטרף גבר יבלש יבקר על דעה לא תשבקנה בלא אלפן גבר טעי בשביל בישו לא תשבקנה תקבל חובה גבר ימלל ממלל גדף לא תחדי בה תקבל חובה גבר יטען ממלל גנו למשמע בישה לא תקבלנה וליני מעלם על אבדנה גבר יקעם לקדם חובה לא חכם רזה הפכה מן שבילה גבר ישבק קנומה מן חכמה לא תימר לה חדי במלכונך 51, , גבר מזרז למקים ערבוב עזרה מן שבילה והגזר עליו דין גבר דילבש מלים לא יחכם יתה ותהי מחיבה בישו עזר יתה בקשטה גבר דיקום במקום צדו לא ידע האנו אזהרה מן יתה אתרה גבר דיחכמנך מד לא חכמה אודעה קשטה ולא תהך בתרה גבר לא ידע רז מה יעבד אקימה על קשטה ולא תשבקנה טעי והן לית אחד מן אלין שמע ולא עני אנה דיאן בקשט תתפני מן לבטה ואני מקים לה אהן לבטה הכתוב קמיך ובעלמה אנה מגזינה לפם עובדה דעבד','[Let us set out a division like a lamp which shines before us and re-
moves all darkness, for His Greatness decided to strengthen us with great knowl-
edge. Happy is the one who possesses it. See the meaning of this great statement 
and cling to it, and do not ever deviate from it. Cursed be he who misleads a blind 
man on the road, and all the people shall say Amen (Deut. 27:18) – with a loud 
voice. This statement comprises twelve teachings. See them and consider them. 
This statement does not refer to him who is blind in sight, but to the man who 
sees and hears. When a man asks about truth, his question shall not return 
rejected. When a man seeks to inquire about knowledge, do not leave him with-
out teaching. When a man goes astray in the way of evil, do not desert him, lest 
you would bear his sin. When a man speaks a word of disgrace, do not rejoice at 
him, lest you would bear his sin. When a man carries a statement of shame, to 
utter a rumor, do not listen to him. I will not refrain from his destruction. When a 
man is about to commit a sin and he does not realize its signiﬁcance, turn him 
from his way. When a man leaves himself devoid] of knowledge, do not say to 
him: “Be happy with your mind.” When a man rushes to establish confusion, 
turn him from his way and sentence him to punishment. When a man adopts 
things he does not know, and they involve evil, turn him back with the truth. 
When a man stands in a place of desolation, and he does not know where he is, 
warn him about that place. When a man teaches you what he does not know, in-
form him about the truth and don’t follow him. When a man does not know the 
meaning of what he does, let him know the truth and do not leave him straying. 
If none of these listens or answers, I am a just judge: you will be released from 
the Curse, and I will apply to him this Curse written before you. In this world I 
will repay him according to the deed that he did.','הבה נציב חלוקה כנר המאיר לפנינו ומסיר כל חשכה, שכן גדולתו החליטה לחזקנו בידע רב. אשרי מי שזוכה בו. ראה את משמעות האמירה הגדולה הזו והידבק בה, ואל תסטה ממנה לעולם. ארור מטה עיוור בדרך, ואמר כל העם אמן (דברים כז,יח) – בקול רם. אמירה זו כוללת שתים עשרה תורות. ראה אותן ושקול אותן. אמירה זו אינה מדברת במי שעיוור בראייתו, אלא באדם הרואה והשומע. כשאדם שואל על האמת, שאלתו לא תשוב דחויה. כשאדם מבקש לדרוש בדעת, אל תניחהו ללא תורה. כשאדם תועה בדרך הרע, אל תעזבהו, פן תשא את חטאו. כשאדם מדבר דבר גנאי, אל תשמח עליו, פן תשא את חטאו. כשאדם נושא דבר בושה להוציא שמועה, אל תקשיב לו. לא אמנע את אבדנו. כשאדם עומד לחטוא ואינו מכיר בחומרת הדבר, הסב אותו מדרכו. כשאדם מותיר את עצמו ריק מידע, אל תאמר לו: "שמח בדעתך." כשאדם ממהר להקים מבוכה, הסב אותו מדרכו וגזור עליו עונש. כשאדם אומץ דברים שאינו יודע ויש בהם רע, השיבהו אל האמת. כשאדם עומד במקום שממה ואינו יודע היכן הוא, הזהירהו על אותו המקום. כשאדם מלמד אותך מה שאינו יודע, הודיעהו את האמת ואל תלך אחריו. כשאדם אינו יודע את משמעות מעשיו, הודיעהו את האמת ואל תניחהו לתעות. אם אין אחד מאלה שומע או עונה, אני שופט צדק: אתה תשתחרר מן הקללה, ואני אחיל עליו את הקללה הכתובה לפניך. בעולם הזה אשלם לו כפי המעשה שעשה.');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (167,'III','28','וידבר משה והכהנים הלוים',3000281,'דאנן בעין כדו נפרש ממלל נדע בה סודי בוננותה מן דהוה משרי במליה חברי ברכתה אי חברי קללתה ואנן עמין דלא הכתב קמינן אלאן מללה דלבטה ולא אתמר לן מללה דברכתה עד נדע מה הו יהי לן נבקר על כן עד נמלך שלמו לית בה חסרן מה את קרי מד קמיך כתוב האלין יקומו למברך עמה אלין מליה מה חנאה בון ומלי אלהנו כהלון כן כי גדלה אמר אלין יקומו לברך ית עמה ולית תמן ברכה תתמר על קהלה מן לויאיה מה חנאה במקעמון על הרגריזים ומהיא ברכתה דתמרת על עמה','For we now intend to spread out a statement by which we shall know 
the secrets of understanding. Who was to open the speech: the owners of the 
Blessing or the owners of the Curse? We see that there is written before us only a 
statement of cursing, and there is no statement of blessing addressed to us so 
that we may know what is it. We must inquire about that, so that we may possess 
perfection in which there is no ﬂaw. Don’t you read what is written before you: 
These shall stand to bless the people (Deut. 27:12)? What is the purpose of these 
words? The words of our God are all true. Indeed, His greatness has said: These 
shall stand to bless the people. If there is no blessing said there for the people by 
the Levites, what would be the purpose in their standing on Mount Gerizim and 
what would be the blessing that would be said for the people?','שכן אנו מתכוונים עתה לפרוש דבר שממנו נדע את סתרי ההבנה. מי היה ראוי לפתוח בדברים: בעלי הברכה או בעלי הקללה? אנו רואים שלפנינו כתובה אך ורק לשון של קללה, ואין לפנינו לשון של ברכה שממנה נדע מה היא. עלינו לחקור בכך, כדי שנזכה בשלמות שאין בה פגם. האין אתה קורא את הכתוב לפניך: אלה יעמדו לברך את העם (דברים כז,יב)? מה תכלית דברים אלה? דברי אלוהינו כולם אמת. אכן, גדולתו אמרה: אלה יעמדו לברך את העם. ואם לא נאמרה שם ברכה לעם על ידי הלויים, מה היה הטעם בעמידתם על הר גריזים, ומה הייתה הברכה שהייתה נאמרת לעם?');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (168,'III','38','וידבר משה והכהנים הלוים',3000381,'ואנן בעים נחכם אך יפרדון ברכתה ושת מואן דאלף שמעין לוי חברה דברכתה הוה משרי הך מד לאוי עליו כי לית לאנש עליו מקדמה אנית בעי מחכמה הך פרט ברכתה הסכת ושמע לוי משרי ואמר בקול רם והאלהים יעננו בקול עד ישמעון כל קהלה וכן הוה לאהרן כד עלל לגו משכנה עם נביה רבה משה ונפק קלה מבין כרוביה למשה מלל אל אהרן ולבניו כדן תברכו ית בני ישראל וקבל שמה רבה מפם הגבורה ונפק לתרח אגן זימונה ותלא ית קלה בדחלה רבה וברך לקהלה וכהלון שמעים יברכך יהוה ולבשם דחלה והפך אמר לון וישמרך כד לבשו דחלתה השבו מטרתה יאיר יהוה פניו אליך מן נטר אתנטר ורצונה ישרי עליו ויחנך חזי יתה רבינה והתפש בה מדאת מגדל ברתות מרך , אתה כל עת מתרבי בידה יתלי יהוה רגזה מנך מלכו רבה לא משתאמה וישוי לך שלם מיתובה רבה טובי אנש יהי בה מתחיל ונתתי שלום בארץ ושכבתם ואין מחריד','We want to know how they pronounce the Blessing while six hundred 
thousand people hear. Levi, the possessor of the Blessing, was beginning, as 
was proper for him for no man has precedence over him. If you seek knowledge 
of how he pronounced the Blessing, be silent and hear. Levi begun to speak 
aloud, and God was answering him aloud (Exod. 19:19) so that all the congrega-
tion might hear. Thus it was with Aaron when he entered the Sanctuary with the 
great prophet Moses. The voice came forth from among the Cherubim to Moses: 
Say to Aaron and his sons […]. Thus you shall bless the people of Israel (Num. 
6:23). He received the great name from the mouth of the Divine Power and went 
forth to the gate of the Tent of Meeting; he raised his voice with much reverence 
and blessed the congregation, while they were all listening: Let the Lord bless 
you (Num. 6:24) – they were wearing reverence. He further said to them: And 
protect you (ibid.) – when they were wearing reverence they became worthy of 
protection. Let the Lord make His face to shine upon you (Num. 6:25). He who 
keeps is kept, and the Divine Favor abides over him. And be gracious to you 
(ibid.) – observe that greatness and seize it.] When you are magniﬁed with the 
mercy of your Master, you are at all time gloriﬁed by Him: Let the Lord lif up His 
countenance upon you (Num. 6:26) – an inestimably great possession! And give 
you peace (ibid.) – a great rank – happy is the man who is strengthened by it. 
And I will give peace in the land, and you shall lie down, and none shall make you 
afraid (Lev. 26:6).','רצוננו לדעת כיצד הם אומרים את הברכה בשמוע שש מאות אלף איש. לוי, בעל הברכה, החל לפתוח, כראוי לו, שאין אדם קודם לו. אם תבקש לדעת כיצד השמיע את הברכה, שתוק ושמע. לוי החל לדבר בקול רם, וַיַּעֲנֶנּוּ אֱלֹהִים בְּקוֹל (שמות יט,יט), למען ישמע כל הקהל. כן היה עם אהרן כשנכנס אל המקדש עם הנביא הגדול משה. יצאה קול מבין הכרובים אל משה: אֱמֹר אֶל אַהֲרֹן וְאֶל בָּנָיו [...] כֹּה תְבָרְכוּ אֶת בְּנֵי יִשְׂרָאֵל (במדבר ו,כג). קיבל את השם הגדול מפי הכוח האלוהי ויצא אל פתח אוהל מועד; נשא קולו ביראה רבה ובירך את הקהל בכולם מאזינים: יְבָרֶכְךָ יְהוָה (במדבר ו,כד) – עטויי יראה היו. עוד אמר להם: וְיִשְׁמְרֶךָ (שם) – כשהיו עטויי יראה נמצאו ראויים לשמירה. יָאֵר יְהוָה פָּנָיו אֵלֶיךָ (במדבר ו,כה). השומר נשמר, וחסד האל שורה עליו. וִיחֻנֶּךָּ (שם) – הסתכל בגדולה ההיא ואחוז בה. כשתתגדל ברחמי אדונך, תיהיה מכובד על ידו בכל עת: יִשָּׂא יְהוָה פָּנָיו אֵלֶיךָ (במדבר ו,כו) – אחוזה גדולה שאין לשערה! וְיָשֵׂם לְךָ שָׁלוֹם (שם) – מעמד נשגב – אשרי האיש המתחזק בו. וְנָתַתִּי שָׁלוֹם בָּאָרֶץ וּשְׁכַבְתֶּם וְאֵין מַחֲרִיד (ויקרא כו,ו).');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (169,'III','64','וידבר משה והכהנים הלוים',3000641,'וגבר דיקום במקום › מ ‹ צדי ולא ידע מהו פני מן לבטה עמי אתר צדותה ודע הך הוא ולא תהי פני מן מחכומה תצדי מנה אתר צדותה אתר סגדתה לאל נכר לא תקום בה תצדי לבך ולא תקום אלאן באתרה דבחרה יהוה אלהך אן שמעת בגבר בלשה וקם בה ושבקתנה לגו טעותה אתה מתבעי בכן וחכמה דלה בה עסרה גנואן כל חדה מנין יתרה על חברתה פסל וכל דמו לא לאוי לך תחזינה כיינך תקלל במחזינה מדבח ביש מעמר קמיך עיניך מליאן מן מדבח יה אלהך וקטרה בישה על שם בישתה לית לאוי עליך תקום לגוה הלא טמאתה ורגוסה תמן צמידים טמאת אנשיה ורגוס נשיה לית לאוי עליך תגע באחד מן אלין ולא תתקרב בכלום מנון וגלות גנוה על מדבח שקר הלא מרך ארחקך מדן וכ › ל ‹ ול כל אלין כל מד יתעבד מן ממללים לא ארשה בה אלה הן שמע מליך ולא יקום באלין אתריה חסל טובי יגלי לבט ומן לא שמע למלי וחלף מימרי גדלי ידע הך יסב קשטה כי אזהרתה ולא ברר גרמה','(If) a man stands in a place of desolation and does not know, he is free 
of curse. See the place of fear and know how it is, and be not empty of knowl-
edge. Fear it, (it is) a place of fear, a place of worship to an alien god, do not 
stand there. Frighten your heart and do not stand (there), but in the place that 
the Lord your God had chosen. If you hear about a man who sought it and stood 
there, and you abandoned him in the error, you will be prosecuted for this. 
Know it, for it includes ten blames, each one of them greater than the other: A 
sculpture or any image (Exod. 20:3) – it is not appropriate for you to see it, lest 
you be cursed by seeing it. (If) a bad altar is erected before you, (let) your eyes 
(be) full with the altar of the Lord your God. Bad company in the name of evil – it 
is not appropriate for you to be therein, for impurity and deﬁlement are coupled 
there – the impurity of the men and the deﬁlement of the women. It is not 
appropriate for you to touch one of them and to draw near to any of them (or) to 
the shameful exposure of a false altar. For your Master distanced you from this 
and (from) all these: doing any of the things that God did not permit. If he listens 
to your words and will not stand in these places, far be it that My goodness re-
veals curse! And he who does not listen to My words but alters My statement, My 
greatness knows how he will take the truth, for I warned him and he did not 
distance himself (from evil).','אם אדם עומד במקום שממה ואינו יודע, הוא פטור מקללה. ראה את מקום הפחד ודע כיצד הוא, ואל תהיה ריק מידע. ירא ממנו, הוא מקום פחד, מקום עבודה לאל זר, אל תעמוד שם. הפחד את לבך ואל תעמוד שם, אלא במקום אשר בחר ה'' אלוהיך. אם שמעת על אדם שביקשו ועמד שם, ועזבתו בטעותו, תיענש על כך. דעהו, שכן הוא כולל עשרה אשמות, כל אחת גדולה מחברתה: פסל או כל תמונה (שמות כ,ג) – אין ראוי לך לראותו, שמא תתקלל בראייתו. אם מזבח רע הוקם לפניך, מלא עיניך במזבח ה'' אלוהיך. חברה רעה בשם הרע – אין ראוי לך להיות בתוכה, שכן טומאה ורשע קשורים שם – טומאת האנשים ורשע הנשים. אין ראוי לך לגעת באחד מהם ולקרב לאחד מהם או לערוות מזבח שקר. שכן אדונך הרחיקך מזה ומכל אלה: מעשות כל דבר שאלוהים לא התיר. אם שמע לדבריך ולא יעמוד במקומות אלה, חלילה שתגלה גדולתי קללה! ומי שאינו שומע לדברי אלא משנה את אמירתי, גדולתי יודעת כיצד יקח את האמת, שכן הזהרתיו ולא התרחק מן הרע.');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (170,'III','42','וידבר משה והכהנים הלוים',3000421,'אה קהלה אשתעבד ואמלך קשטה תתיקר אודי למרך כל עת על אהן איקרה 23* דנחילך לגו בית מרך את קעום משתרר במלכו רבה לדבבך קטלת לברכתה שמעת אב בלך לא תסור מן קשטה קללתה קמיך הב בלך מנה תתעקר מכלה ותקום בקלל רב ותתערטל ביני בוראיה תתגני ותנזף וכלה מנך מתכלי רחותה מנך אכסית וקשטה מנך אתדבר וזכותה לך שבקת ובישתה בך שרת ואתה חדי וזהי בכן ומרבי תאות נפשך שבקת שרה ובקושה והזלת עם נעמה ותפוכה שבקת הרגריזים ואזלת עם דרי המבול שבקת 23* נביות משה אישה והלכת עם קרח שבקת פינחס והלכת עם זמרי מה הדה שהותה תשבק אבהתך טביה › ב ‹ מן את מדבק חסלך הן תהי כדן תשבק לקדושך ותהי מחלל לעלם תשבק אתרך שמם ואתה יכל לא יהיה כן חסלך אה בחורה תהי פסול ואה קדוש תהי מתחלל ואה יקיר תהי נזיף ואה סגולה תהי בראי ואה כהנה תהי מטמי מה הדה שהותה רבתה דסתמת מדעך וגלת תפוכך ועבדת יתך כאנש סמי ממשש בקבלה לא ידע להאן ייזל','O congregation, be submissive and take possession of the truth – then 
you will be honored. Give thanks to your Master at any time for this honor which 
He bequeathed you with. Within the house of your Master you will stand, 
strengthened with great kingship. You have slain your enemies, you have heard 
the Blessing; take care not to turn aside from the True One. The Curse is in front 
of you – beware of it, lest you will be uprooted from everything and confront a 
great curse and be bare among the creatures. You will be blamed and rebuked, 
and everything will be held from you. The Divine Favor will be concealed from 
you, and the True One will withdraw from you, and virtue will abandon you, and 
evil will dwell in you. But you are joyful and cheerful with this, and you increase 
your soul’s lust. You abandoned Sarah and her request and followed Naama and 
her perversion. You abandoned Mount Gerizim and followed the dwellers of the 
Flood. You abandoned the prophethood of Moses the Man and followed Korah. 
You lef Phinehas and followed Zimri. What is this corruption? You leave your 
good ancestors – to whom you cling? Far be it from you to be like this, to aban-
don your sanctity and to be deﬁled forever, lest you will leave your place deso-
late. (But) you can (behave in such a way) that it won’t be like that. Far be it from 
you, O selected one, from being rejected, and, O sanctiﬁed one, from being de-
ﬁled, and, O notable one, from being rebuked, and, O chosen one, from being 
alien, and, O priest, from being deﬁled. What is this great corruption that 
blocked your mind and revealed your perversion, and made you like a blind man 
who gropes in darkness and does not know where to go?','הו עדה, היכנעי וקחי לך את האמת – אז תתכבדי. הודי לאדונך בכל עת על הכבוד שהנחיל לך. בבית אדונך תעמדי, מחוזקת במלכות גדולה. הרגת את אויביך, שמעת את הברכה; היזהרי שלא תסורי מן הנאמן. הקללה לפניך – הישמרי ממנה, פן תיעקרי מכל ותעמדי נוכח קללה גדולה ותהיי ערומה בין הנבראים. תיגנה ותיוכחי, וכל דבר ייעצר ממך. רצון השמים יוסתר ממך, והנאמן יסוג ממך, והמעלה תעזוב אותך, והרע ישכון בך. אך אתה שמח ועליז בכך, ומרבה את תאוות נפשך. עזבת את שרה ובקשתה והלכת אחרי נעמה וסטייתה. עזבת את הר גריזים והלכת אחרי יושבי המבול. עזבת את נבואתו של משה האיש והלכת אחרי קורח. עזבת את פינחס והלכת אחרי זמרי. מה הוא השחתה הזאת? אתה עוזב את אבותיך הטובים – למי אתה נדבק? חלילה לך להיות כך, לעזוב את קדושתך ולהיטמא לעולמי עד, פן תשאיר את מקומך שמם. אך ביכולתך לנהוג כך שלא יהיה כן. חלילה לך, הנבחר, מלהידחות, וחלילה לך, המקודש, מלהיטמא, וחלילה לך, הנכבד, מלהיגנות, וחלילה לך, הבחיר, מלהיות זר, וחלילה לך, הכהן, מלהיטמא. מה היא השחתה הגדולה הזאת שסתמה את דעתך וגילתה את סטייתך, ועשתה אותך כאדם עיוור הממשש בחשכה ואינו יודע לאן ילך?');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (171,'III','67b','וידבר משה והכהנים הלוים',3000673,'ודבדיל ארמלתה פנתה מן הדה כי לית לה נמי לגו מלי חכמתה דהי › פניה ‹ מכל הדה לוד אזהרך מן לבוטה בדיל קבול צבעתה כמה דאמר כל אלמנה ויתום לא תענו כי אם צעק יצעק אלי ושמע אשמע צעקתו וכן בנדרה דיקום ודלא יקום ובררך מן משכון תכסיה ואשתפת עמך בתלתה במיכל מעשרה ואף בקצירה ובפט זיתה כמה דאמר מקץ שלש שנים כי תקצר קצירך כי תהבט זיתיך יתרבי יכולה הממן לחודה החי לקלומה דלא יתחלף נודי ] ל [ גדלה בלב אדכי כני ] ד [ מד יקום ] ל [ נן קיאם ] ז [ כאי עלמה ולא נסטי מן שביל קשטה לא ימינה ולא שמאלה','And concerning the widow, uncouple her from this, for she has no 
share in the words of wisdom, and she is exempt of all this. Only I warn you 
away from aﬄicting her because of (My) receiving her outcry, as it is said: You 
shall not aﬄict any widow or orphan […]. If they cry out to me, I will surely hear 
their cry (Exod. 22:22–23). And also regarding her vow, whether it stands or not, 
and your distancing from taking her cloak in pledge. She shares with you in 
three (matters): in eating the tithe and also in harvesting and in beating the olive 
trees, as it is said: When you reap your harvest […] when you beat your olive tree 
(Deut. 24:19–20). Gloriﬁed be the Potent One, who endures alone, who lives by 
Himself, who is unchangeable. Let us give thanks to His greatness with a pure 
and humble heart, and hopefully the covenant with the righteous of the world 
will subsist for us. Let us not deviate from the path of the True One neither right 
nor lef.','ובנוגע לאלמנה, הפרד אותה מזה, שכן אין לה חלק בדברי החכמה, והיא פטורה מכל זאת. אלא שאני מזהיר אתכם מלהציק לה מפני שאני שומע את זעקתה, כפי שנאמר: כל אלמנה ויתום לא תענון [...] אם צעוק יצעק אלי שמוע אשמע צעקתו (שמות כב,כב–כג). וכן בנוגע לנדרה, בין שיעמוד ובין שלא יעמוד, ובנוגע להתרחקותכם מלקחת את בגדה בעבוט. יש לה חלק אתכם בשלושה דברים: באכילת המעשר, וכן בקציר ובחביטת עצי הזית, כפי שנאמר: כי תקצור קצירך [...] כי תחבוט זיתך (דברים כד,יט–כ). מְפֹאָר יהיה הגיבור, הנצחי יחיד, החי בפני עצמו, שאין בו שינוי. נודה לגדולתו בלב טהור ושפל, ויהי רצון שיתקיים לנו הברית עם צדיקי עולם. לא נסור מדרך האמיתי לא ימינה ולא שמאלה.');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (172,'III','11','וידבר משה והכהנים הלוים',3000111,NULL,'A holy people of the Lord your God (SP Deut. 27:9) – this is a great honor, 
no other has been honored in this way. Therefore, He said of the Lord your God 
(ibid.) – He taught us that this statement is for those who enter the land. For He 
said this statement to their fathers – and He does not say a word, and then turns 
back and cancels it – “You will not enter the land, but your children will enter”, 
in order to teach you that they will be exalted by ten mighty and elevated deeds. 
They will learn it and accomplish it with uprightness. When they come to the 
good place they will hear what their fathers did not hear, and learn what they 
did not learn, and know what they did not know, and see what they did not see, 
and read what they did not read, and stand in a place where they did not stand. 
And there they will be elevated greatly. And they will destroy every enemy of 
theirs and possess every glory and will procreate in the world.','עם קדוש לה'' אלוהיך (ספר שומרוני דברים כז,ט) – זהו כבוד גדול, ואיש לא כובד כך. לפיכך אמר לה'' אלוהיך (שם) – לימדנו שדברים אלה אמורים לנכנסים אל הארץ. שכן אמר את הדברים האלה לאבותיהם – ואינו אומר דבר ואחר חוזר ומבטלו – "לא תבואו אל הארץ, אבל בניכם יבואו", כדי ללמד שיתרוממו בעשרה מעשים עצומים ונשגבים. ילמדום ויקיימום ביושר. כשיבואו אל המקום הטוב ישמעו מה שאבותיהם לא שמעו, וילמדו מה שלא למדו, וידעו מה שלא ידעו, ויראו מה שלא ראו, ויקראו מה שלא קראו, ויעמדו במקום שבו לא עמדו. ושם יתרוממו עד מאוד. ויכניעו כל אויביהם ויזכו בכל כבוד ויפרו בעולם.');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (173,'III','30','וידבר משה והכהנים הלוים',3000301,'ומד את בעי אהן מחכומה שרי במקרת קציה והיה אם שמע תשמע ודבתרה ברכה ואיקר ושלמו והיה אם לא תשמע ודבתרה מדן תחכם הן אלה בכל עת מקדם ברכה מקמי לבטתה וכן עבד לגו אהן מקומה קדם ברכתה ושחי קללתה מכן אמר אלה יעמדו לברך ית עמה ושרואה מאז מגוזה וכן אמר במגוזכון עד יעבדו מד יריח לאלה ויודו לגדלה דמלא אתרון ואקים דימה לאבהתון וגעזו ית ירדנה בשלם ותברו דבביון ואנון בעין ביומה דבה ייעלון לאתרה דלון אתמסר יהי לון בה חדו רבה משררה חילון ומרביה יתון ויהונו על כן פריטין ברכתה ומרבים מן אודאותה על מה דאמלתון מכן אתמר דאנון משרין בברכה קמי קללתה חכם אהן ומנה לא תסור ואתילף מד בה תתוחי בעלמה באיקר','When you seek this knowledge, begin by reading the Qiṣṣot, if you obey 
(Deut. 28:1), and what follows: blessing, honor, and perfection. But if you will not 
obey (Deut. 28:15), and what follows. From this you will know that God always 
puts blessing ﬁrst, before the curse. Thus He did in this instance: He put bless-
ing ﬁrst and deferred cursing. Thus He said: These shall stand to bless the people 
(Deut. 27:12). The beginning is from the entry (in the land), as He said: When you 
pass over (Deut. 27:2), that they may do what pleases God and praise His great-
ness, which appointed them and fulﬁlled what He swore to their fathers. They 
crossed the Jordan safely and smashed their enemies. They were seeking the day 
when they should enter the place which had been appointed for them, they 
should have great joy therein, (which) strengthens their force and magniﬁes 
them, so that they would pronounce the Blessing and multiply thanksgiving for 
what (God) appointed them. Therefore it is said that they begin with the Blessing 
before the Curse. Know this and do not turn aside from it, and learn what will 
give you life in the world with glory.','כאשר אתה מבקש את הידע הזה, התחל בקריאת הקיסות: אם שמוע תשמע (דברים כח,א), ומה שבא אחריו — ברכה, כבוד ושלמות. אך אם לא תשמע (דברים כח,טו), ומה שבא אחריו. מכאן תדע שהאל תמיד מקדים את הברכה לפני הקללה. כך עשה במקרה זה: הקדים את הברכה ודחה את הקללה. כך אמר: אלה יעמדו לברך את העם (דברים כז,יב). הפתיחה היא מן הכניסה לארץ, כפי שאמר: והיה בעברכם (דברים כז,ב), כדי שיעשו את הרצוי לפני האל וישבחו את גדולתו, אשר ייעדם ואשר קיים את מה שנשבע לאבותיהם. הם עברו את הירדן בשלום וניפצו את אויביהם. הם ציפו ליום שבו ייכנסו למקום שנועד להם, וישמחו בו שמחה גדולה המחזקת את כוחם ומרוממת אותם, עד שיאמרו את הברכה וירבו בהודאה על מה שהאל ייעד להם. לפיכך נאמר שהם פותחים בברכה לפני הקללה. דע זאת ואל תסור ממנה, ולמד מה שייתן לך חיים בעולם בכבוד.');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (174,'III','57','וידבר משה והכהנים הלוים',3000571,'כבודה הך אמר בידי יכלו ליתי יכל אסבל חוב אנש ובכן חכמתך בכל אתר ולית קדמי עובד תקיף קטלת ושנקת ואבדת וחוית ועמך עבדת כל אהן עובדה לא קעמת על › ימה ‹ וחזיתך כל תמח והגיזית יתך בה בחיל מלכה רבה קבע בלך מני וקמי לא תגדד דאני סגי מכן אמן על קשטה בזכו ולבישה לא תקרב ולרחותה בכל עת רבי עדהן ביד מרך תתרבי ובידי תתחיל ואלא כליתך מן עלמה ורבית בך דיניה וגוני לבטיה ואקימתך בתשניק רב אזהר גרמך מנך ובך והוכחנה בפמך תהי בעלמה זכי ובחראה שלום ותזדעק עם קדש וסגולה ומה אתמר לאבהתך יתקומם לך דמרן רחמן וכני אמנותה נודי לחילה › ו ‹ נשבח לגדלה › ו ‹ נסגד לרבינה › ו ‹ נכפת לגבורתה ונשתעבד לה בכל עת דו › מרן ‹ וקניאן ועבודן וצעורן ותקנן וגדלן בחכמה שלמה ימן מדעה על אהן מחכומה וימלכנה באימנו רבה ויזרז וישבח למלכה חיולה דלית לא יקום לעלם אלא חילה דמע דימן איקרה עלינן ונהי פריקים מן פנותה דו חכם יתן דו מרוח לבני רחמיו נודי לחילה ונסיד ונימר לית אלה אלא אחד','It was as though the Glory was saying: “I have might; I cannot stand 
men’s guilt – this is what I taught you in every place. There is no deed (too) 
mighty for me. I killed and aﬄicted and destroyed and gave life, and all this I did 
with you. Did I not stand by the sea and show you every wonder, and made you 
cross it with the power of the Great King? Pay attention to me, and do not rebel 
against me, for I am (even) greater than that. Persevere in truth with righteous-
ness, and do not draw near evil, and magnify (God’s) will at any time, so that 
you may be magniﬁed by your Master, and by me you may be empowered. And if 
not, I will withhold you from the world and intensify in you punishments and 
various aﬄictions, and I will set you in great torment. Warn yourself, by your-
self, and reprove yourself with your own mouth, so that you may be righteous in 
this world and in peace in the world to come. You will be called a holy and 
chosen people. And what has been said to your ancestors will be fulﬁlled for 
you.” For our Master is merciful – thus is His manner. Let us give thanks to God 
and praise His greatness and bow down to His majesty and submit to His might 
and subdue to Him at any time, for He is our Master and our Creator and our 
Maker and our Shaper and our Arranger and our Breeder with perfect wisdom. 
Let the mind persist in this teaching and possess it with great faith, and hasten 
to praise the powerful King, for there is not, nor will be, but (by) His might. Per-
chance His glory may stay with us, and we may be redeemed from Disfavor, for 
He knows us, for he relieves the sons of His devotees. Let us give thanks to His 
might and testify and say: “There is no god but One.”','כאילו אמר הכבוד: "עוז בי; אין אני יכול לשאת את אשמת בני האדם – זה מה שלימדתי אתכם בכל מקום. אין מעשה עצום ממני. הרגתי וייסרתי והשמדתי והחייתי, וכל זה עשיתי אתכם. הלא עמדתי על הים והראיתי לכם כל פלא, והעברתי אתכם בכוח המלך הגדול? הקשיבו לי ואל תמרדו בי, כי גדול אני מזה אף יותר. התמידו באמת עם צדק, ואל תתקרבו לרע, והגדילו את (רצון האל) בכל עת, למען תוגדלו בידי אדוניכם ותתחזקו בי. ואם לאו, אמנעכם מן העולם ואכבד עליכם עונשים וייסורים שונים ואשים אתכם בצרה גדולה. הזהרו בעצמכם, מעצמכם, והוכיחו את עצמכם בפיכם, למען תהיו צדיקים בעולם הזה ובשלום בעולם הבא. תיקראו עם קדוש ובחיר. ומה שנאמר לאבותיכם יתקיים בכם." כי אדוננו רחום – כן דרכו. נודה לאל ונהלל את גדולתו ונשתחווה להדרו ונכנע לעוזו ונכנע לו בכל עת, כי הוא אדוננו ובוראנו ועושנו ויוצרנו ומסדרנו ומגדלנו בחכמה שלמה. יתמיד השכל בלימוד הזה ויחזיק בו באמונה גדולה, וימהר לשבח את המלך הגיבור, כי אין ולא יהיה אלא בכוחו. אולי יישאר כבודו עמנו ונגאל מן החרון, כי הוא יודע אותנו, כי הוא מרים עול מבני חסידיו. נודה לכוחו ונעיד ונאמר: "אין אלוה אלא אחד."');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (175,'III','49','וידבר משה והכהנים הלוים',3000491,'וארעה אמרה אנה דסבלתך ובכל עת מקימה לך איקרי ומשימה לך מהו מרבי לך בכל זבן ועדן לא תשימני הוי חסירה לך מה הו מקים לך צורכה דנפשה ואגלי באפיך דבבו רבה עדהן תתכלי מן עלמה ותקום באשדה ולית רתי ותהיה בצרר ולית מפצי וייתי עליך קלל ולית רחמה ארחק גרמך מן מקרוב בישתה אדלא תפל עליך קללתה כי מן הקלל ליתו מתקבל אקר קשטה לעלם כי במקום סלחיותה ואתר ברכתה אתקוממת סהדים על פניה דפנו ואקימו עליון סהדים רבים חכמת יתך הך אנון ויודו בפממיהון סהדה חיולה עד לא יפסחו ממה','The Earth said: “It is I who bore you and at all times convey to you my 
abundance and extend to you (all) what elevates you at all time. Do not make me 
lack what supplies you for personal needs. (Then) I will manifest great hostility 
against you till you will cease from the world. And you will be in distress, and 
there is no mercy, and you will be in aﬄiction, and there is no deliverer. And a 
curse will befall you and there is no compassion. Distance yourself from ap-
proaching evil, lest the curse falls upon you. Indeed, he who is cursed is never 
accepted near the True One. For in the place of forgiveness and in the place of 
blessing witnesses have been set up (to testify) against the apostates who erred. 
They set up against them many witnesses – I taught you how they are – and they 
will testify with their mouths a mighty testimony, till they will not (be able to) 
turn away from it.”','הארץ אמרה: "אני היא שילדתי אותך, ובכל עת מעבירה לך את שפעי ומושיטה לך את כל המרומם אותך בכל עת. אל תגרום לי לחסר את מה שמספק לך את צרכיך האישיים. (שאם לא כן) אגלה נגדך איבה גדולה עד שתחדל מן העולם. ותהיה בצרה ואין רחמים, ותהיה בייסורים ואין מציל. וקללה תבוא עליך ואין חמלה. התרחק מלגשת לרוע, פן תפול עליך הקללה. שכן מי שמקולל אינו מתקבל לעולם בקרבת האמת. כי במקום הסליחה ובמקום הברכה הועמדו עדים כנגד הסוטים שתעו. הועמדו כנגדם עדים רבים – לימדתי אותך מהם הם – והם יעידו בפיהם עדות עצומה, עד שלא יוכלו להתחמק ממנה."');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (176,'III','51','וידבר משה והכהנים הלוים',3000511,'אמר מדעה ללבה שמעת אלין מליה ענתה לבה אה מדעה זלין אנן מנך ואת מבועה דמנך נשתי לית נהרה דמנך מתחזי אלא מתחיל בזית דזכו כי נארך מכלי לכל , חשך וקפל כל עשש דיתחזי ולא יהי ערווב מן אכה ומן אכה יתעמי בינינן לעלם בידך תעתיד מן אלהותה רבתה מנו דיכל ידמי להדה יתברך יכולה דאמלתך באהן ועבדך מלוא באהן רביאנה לא תוכח יתי עד תודי ממלל יוכח קנומך כי ממך ובך קעמי דאנה וקעמי בך מסתמכין מה דת מחזי אנן בה הלכים נשמע כדו מלי תרין','The Mind said to the Heart: “Have you heard those words?” The Heart 
answered him: “O Mind, we draw from you, and you are the fountain from which 
we drink.] Your light is invisible, but it is strengthened with oil of righteousness. 
Indeed, your light annihilates all darkness and obscurity, all murkiness that is 
seen. And no blemish on either sides will be seen among us forever. (But) in your 
hands there is nourishment from the great Divinity. Who can resemble this? 
Blessed be the Mighty One who designated you for this and made you appointed 
with this greatness. Do not chasten me until you confess by a word that chastens 
yourself, for my existence lies in yourself. Since I and my existence depend on 
you, we follow the way you direct us in.” We heard now the words of (those) two.','אמר השכל ללב: "האם שמעת את הדברים האלה?" ענה אותו הלב: "הו שכל, ממך אנו שואבים, ואתה המעין ממנו אנו שותים. אורך אינו נראה לעין, אך הוא מתחזק בשמן הצדק. ואכן, אורך מכלה את כל החושך והאפלה, את כל הערפל הנראה לעין. ולא ייראה בנו שום פגם בשום צד לעולם. אך בידיך מזון מן האלוהות הגדולה. מי יכול לדמות לזאת? ברוך הגיבור שייעד אותך לכך ומינה אותך בגדולה הזאת. אל תוכיחני עד שתודה בדבר המוכיח אותך עצמך, שהרי קיומי נמצא בך עצמך. מכיוון שאני וקיומי תלויים בך, אנו הולכים בדרך שאתה מוליך אותנו בה." שמענו עתה את דברי השניים האלה.');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (177,'III','10','וידבר משה והכהנים הלוים',3000101,'היום הזה יהב לישראל כל מה דאזל ליתו משתאל בדילה נהית חכמה דאתה שיור טב עלל ית ארעה טבתה דאשבע אלה לאנשים אזלו בדיל מד הוו לה מכעסים כלם אזלו ואתון אנון שיורה דאתבחרו לטובה מכל אמי עלמה עסרה עובדים אתמסרת לכון לא אתמסרת ללבר מנכון סעד תחכמו מד תעבדו במגוזכון ית ירדנה ותיתון ליד אתרה דבחר יתה אלהה אתר ברכהתה משרוי מלאכיה בית אלהים משכן כבודה אתר סליחתה וענות צבעתה דקדש יתה מר אלהותה במד בחרה דיניה לידה תנשא ולידה יעזר כל דבר רגז לית יקרבנה אש נכראה לא תגוז לידה טוב מן אתא לידה ובלש מרה לגוה דו לה עני וממטינה ית מבלשה כלה ומשגר לה כל איקר וילה למן פנה מנה ואתרחק מן טובה ועבד מהו מכעס כי רגזה בה שרי ומרבי לה אבדנה כיון מנה פנו ובה לא אתקרבו אה ישר בקשטה אתלבבו ובה הדבקו עד ירחם יתכון ויתלי רגזה מנוכון ויקבל עובדיכון כמה דעבד לאברהם וכלל ליצחק ורבה ליעקב ומלך ליוסף ולוכון שיאר ובוכון עשק מכל גויה 11] [ לעם קדש ליהוה אלהיך אה איקר רב לא אתוקר בה בר מכם לכן אמר ליה אלהיך הודענן הן דאה מימרה לעלולי ארעה דו אמר לאבהתון אהן מימרה וליתו אמר מלה והפך מבטל לה אף אתון לא תיעלו ליד ארעה ובניכון אנון ייעלון לבדיל חכמתך דאנון מתרבים בעשרה עובדים חיולין ורמין יילפו יתה ויעבדו יתה בזכו כד יהונו אתים ליד אתרה טבה ישמעו מד לא שמעו אבהתון ויילפו מד לא אתלפו ויחכמו מד לא חכמו ויחזון מד לא חזו ויקרו מד לא קרו ויקומו באתר לא קעמו אנון בה ויתרבו תמן ברבין גדול שריר ויאבדו כל דבב דלון וימלכו כל איקר ויפרו לגו עלמה','This day (Deut. 27:9) is given to Israel; all that had passed is not asked 
about. You have become (ibid.) – He taught that you are a good remnant which 
enters the good land that God had sworn to the men who passed away, because 
they all were irritating Him. They all passed away, while you are the remnant 
chosen for the better from all the nations of the world. Ten deeds were handed 
down to you, which have not been handed down to anyone other than you, so 
that you may know what to do when crossing the Jordan and coming to the place 
that God had chosen; the place of the blessings, the dwelling of the angels, the 
House of God, the abode of the Glory, the place of forgiving and of the answer to 
outcries, which the Master of Divinity sanctiﬁed by choosing it. The judgments 
will be carried there, and there will return anything. Ire will not get near to it. 
Alien ﬁre (Lev. 10:1) will not pass near it. Happy is the one who comes to it and 
seeks there his Master, for He answers him and stretches out to him with all his 
requests and dispatches to him every glory. Woe to the one who turned away 
from Him and distanced himself from the Good One, and committed irritating 
acts. Indeed, anger stays with him and increases his devastation. Indeed, they 
turned away from Him and did not get near to Him. O Israel, cleave to the True 
One and cling to Him, so that He may have mercy upon you and suspend his 
anger from you and accept your deeds, as He did to Abraham and crowned Isaac 
and exalted Jacob and made Joseph a king, and made you survive, and set His 
love upon you out of all the nations.','יום זה (דברים כז,ט) ניתן לישראל; כל מה שעבר אינו נשאל עליו. הייתם (שם) – לימד שאתם שארית טובה הנכנסת אל הארץ הטובה שנשבע האלוהים לאנשים שעברו, כי כולם הכעיסוהו. כולם עברו, ואתם השארית הנבחרת לטובה מכל אומות העולם. עשרה מעשים נמסרו לכם, שלא נמסרו לאיש זולתכם, כדי שתדעו מה לעשות בעוברכם את הירדן ובבואכם אל המקום שבחר בו האלוהים; מקום הברכות, משכן המלאכים, בית האלוהים, מעון הכבוד, מקום הסליחה ועניית הזעקות, אשר קידשו אדון האלוהות בבחרו בו. המשפטים יינתנו שם, ושם ישוב כל דבר. חרון לא יתקרב אליו. אש זרה (ויקרא י,א) לא תעבור בקרבתו. אשרי הבא אליו ומבקש שם את אדונו, כי הוא עונה לו ופושט אליו יד בכל בקשותיו ומשגר לו כל כבוד. אוי למי שפנה ממנו והתרחק מן הטוב, ועשה מעשים מכעיסים. הכעס שורה עליו ומגדיל את חורבנו. אכן פנו ממנו ולא קרבו אליו. הוי ישראל, דבק באמת והיצמד אליו, למען ירחם עליך ויסיר ממך את חרונו ויקבל את מעשיך, כפי שעשה לאברהם, וכתר את יצחק, ורומם את יעקב, ומינה את יוסף למלך, והחיה אתכם, ושם אהבתו עליכם מכל האומות.');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (178,'III','52','וידבר משה והכהנים הלוים',3000521,'קעמו למ » שמע « דאה ] קע [ ים ברבו ] אבר [ הם הך אמר לבניו בדילכון רבתי קשטה במד בלשת וקעמת וצלית ואורֿ כֿ ת בשדל והגל ] ה [ לי כל איקר מן מרי ורבה יתכון וחכמי ר ] זין [ כהלין אי ] טב [ ו כי כלה מנה וכלה ל ] יד [ ה יעזר ] ד [ ו במלתה מתעבד וביכלתה מ ] תית [ ב לית אסגהותה כדו מתפכה מן קשטה ליד בטולה חסל צלותי תעזר מס › ג ‹ יאנה למניאן זעור ופשטות יצחק צברה לריחות מרה ופרקנה דהוה לה וברכתה דשמעת ובריתה ד › א ‹ קטר ושבועתה דאשבע יהי בידכון מתחלף ומנוכון יתדבר','Stand to hear this. Abraham stands in greatness; as if he says to his 
sons: “For your sake the True One elevated me by what I requested. I stood and 
prayed and entreated lengthily. And every glory was revealed to me from my 
Master (who) increased you and taught me secrets, all of which are beneﬁting. 
For everything is from Him and everything to Him returns, for it is done by His 
command and by His power it is established. Let the abundance not be reversed 
now from its existence to its abolition. Far be it from my prayer to reverse from 
abundance to scarcity. And Isaac’s stretching out of his neck for his Master’s 
pleasing, and the redemption that he got, and the blessing that was heard, and 
the covenant that was tied, and the oath that was sworn – (all) will be changed 
by you, and it will be taken away from you.”','עמוד ושמע זאת. אברהם עומד בגדולה; כאילו הוא אומר לבניו: "למענכם הרוממני האמת על ידי מה שביקשתי. עמדתי והתפללתי והתחננתי בארוכה. וכל כבוד נגלה לי מאת אדוני, שהרבה אתכם ולימד אותי סודות, שכולם מועילים. שכן הכל ממנו והכל אליו שב, כי בציוויו הוא נעשה ובכוחו הוא מתקיים. אל ישתנה עתה השפע מקיומו לביטולו. חלילה לתפילתי להיהפך מן השפע אל המחסור. ועקידת יצחק את צווארו לרצון אדונו, והפדיון שקיבל, והברכה שנשמעה, והברית שנכרתה, והשבועה שנשבעה – כל אלה יישנו בידיכם, ויילקחו מכם."');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (179,'III','62','וידבר משה והכהנים הלוים',3000621,'כל גדף בעלמה לית לה תקומה גדף באנשים גדף במרה דגד › פ ‹ ה מדגל במהו ממלל לית לה קמי תקומה בעלמה מחי אנה דכרה מכתי שומיה בדיל דתרע מלי מתרע אנה חייו וגבר דיטען ממלל דגנו הן חכם רזה דילי גבינה ומקים יתה בעשדה ומעבדה אלפן עד לא ילך אנש בשבילה והן ליתו חכם ואתילף מנך טובך וטוביו והן אלפתנה ולא אתלף זידן הו מתקטל בדינה וגברה דיקעם לקדם חובה הן הות מנה בלא כ › מ ‹ ינה לית תמן חוב מתידע בדילה חכמה אדלא ייפך לקלל רב כל חובה רבה אקימת כל צדו ורבת שיאלה כד הוה כן צפי חובה דעבדת דינה בריה בעמה בכל דרי עלמה מן צפה לזנו ידאן על כן הגלה על בישה לא יכל יכסינה וכל אנש חכם לבישותה די חובה חיולה והן צפה גנב לא יעלם עליו והן עלם ידאן על כן לית חוב אלא מד גלית לך והוא מטמי לבה ומרגס מדעה ומתפך לאנשה מן גון איטבו לגון דבישו ומקים אנשה בסמיון דלבה יעמי אורה ולא ילך בה הן הוה כדן עובדה יהי ביד רמה משלה עליו דאדי מכליאה יתה ומקימנה בצדו רבה בביש עובדה דעבד יתה','No reviler in the world shall have existence. He who reviles men blas-
phemes his Master, for the reviler defames in what he says. He has no existence 
before Me in the world. I will erase his memory from under heaven. Since he 
broke My words, I will shatter his life. When a man carries a statement of shame, 
if he knows My secret, (I) will punish him and place him in distress. And I will 
set him as an example, so that no man will walk in his path. (But) if he does not 
know, and learned it from you, good for you and good for him. If you taught him, 
and he did not learn, he is presumptuous, he will be slain in judgement. When a 
man commits a crime, if it is with no presumption, there is no crime. A teaching 
is made known from it, so that it would not turn into a great curse. Any great sin 
produced distress and brought about a question when it occurred. See the sin 
that Dinah committed, who whored within her people (and was blamed) in all 
the generations of the world. He who sees harlotry (and does not warn) will be 
judged for this. He who is discovered in (his) evil will not be able to hide it, and 
everyone will be aware of his evil, which is a mighty sin. And if one sees a thief, 
he is not to shun him, and if he shuns, he will be punished for this. There is no 
sin, except what I revealed to you, that it pollutes the heart and deﬁles the mind, 
and turns the man from comfort to destitution, and places the man in blindness 
of mind. He sees the light, but does not walk in it. If this deed is done deﬁantly, 
it dominates him. My hand will destroy him and place him in great desolation, 
because of the bad deed that he did.','לשום מחרף בעולם לא תהיה קיום. המחרף בני אדם מגדף את אדונו, שכן המחרף מוציא שם רע בדבריו. אין לו קיום לפני בעולם. אמחה את זכרו מתחת השמים. מאחר ששבר את דברי, אשבור את חייו. כשאדם נושא דבר בושה, אם יודע הוא את סודי, אענישהו ואשימהו בצרה. ואשימהו לאות, למען לא ילך אדם בדרכו. אך אם אינו יודע ולמד זאת ממך, טוב לך וטוב לו. אם לימדתו ולא למד, הוא זדוני, ייהרג בדין. כשאדם עובר עבירה, אם שלא במזיד, אין עבירה. תורה נודעת ממנה, כדי שלא תהפוך לקללה גדולה. כל חטא גדול הוליד צרה ועורר שאלה בהתרחשו. ראה את החטא שדינה חטאה, שזנתה בתוך עמה ונאשמה בכל דורות העולם. מי שרואה זנות ואינו מזהיר ייידון על כך. מי שנתפס ברשעתו לא יוכל להסתירה, והכול יידעו את רשעתו, שהיא חטא עצום. ומי שרואה גנב, אין לו להתרחק ממנו, ואם יתרחק ייענש על כך. אין חטא, אלא מה שגיליתי לך, שהוא מטמא את הלב ומגאל את הדעת, ומסב את האדם מנחת לדלות, ומשים את האדם בעיוורון הלב. הוא רואה את האור אך אינו הולך בו. אם מעשה זה נעשה בזדון, הוא שולט עליו. ידי תאבדהו ותשימהו בשממה גדולה, בעבור המעשה הרע שעשה.');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (180,'III','29','וידבר משה והכהנים הלוים',3000291,'טב לך תחכם דשרוי מה דאתעבד מברכה עמה למשדך לבביה ועד יחכמון רבין דרגתה דגדל בה קהלה ומן רב מרן כתב קמינן מד בה חיינן ואורכות ימינן ומד בה ננשם ביומה עקבאה כתב קמינן בראשית וכל איטבותה דבה מתמן אמרנן דמלי ברכתה ליתו מקדם עליה עובד דאמנותה משרי במלי אנחמותה לא במלי אפלותה מן ריש בראשית ברכה וטוב וכן אמר ויברך ואה טב שריר','It is good for you to know that at the beginning of what happened was 
the blessing of the people to soothe the hearts, so that they may know the great-
ness of the rank through which the congregation was made great. How great is 
our Lord! He wrote before us that which contains life for us and length for our 
days, and that which gives us relief in the last day. He wrote before us בראשיתand 
all the goodness that it contains. Hence we say that the words of the Blessing are 
not preceded by a deed. For His habit is to begin with words of consolation, not 
with words of calamity. From the beginning of בראשיתthere is blessing and good. 
Thus He said: And he blessed (Gen.1:22), and behold it was very good (Gen. 1:31).','טוב לך לדעת כי בראשית מה שאירע הייתה ברכת העם, כדי לרגע את הלבבות, למען ידעו את גדולת המעמד שבו הוגדל הקהל. כמה גדול אדוננו! הוא כתב לפנינו את אשר בו חיים לנו ואורך ימים, ואת אשר ישיב לנו נחת ביום האחרון. הוא כתב לפנינו בראשית, וכל הטוב הגנוז בה. לפיכך אנו אומרים שדברי הברכה אינם קדומים למעשה. שכן דרכו להתחיל בדברי נחמה ולא בדברי פורענות. מראשית בראשית יש ברכה וטוב. כך אמר: ויברך (בראשית א,כב), והנה טוב מאד (בראשית א,לא).');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (181,'III','16','וידבר משה והכהנים הלוים',3000161,'אנשה אתעידו במד שמעתון מן אהן ממללה רבה דכהלה אלפן וחיים וברכה 12296 . עמו אשתיתה דקעמו על ברכתה ואף אשתיתה דקעמו על קללתה דקעמו על ברכתה על ריש הרגריז שמעון ולוי יהודה ויש ותרין אתרבו בכליל ממלכתה יוסף ובנימ מסחני טובה ואשתיתה דקעמו על קללתה על טור עיבל ראובן גד ואשר זבולן ואתכללו עורי בדן ונפתלי אתבו אה שמועיה מדעיכון ואזינו אל מלי דכדו יתפרסי אקים אלה על הרגריזים אשתה כהלון בני איטבו ארבעה מן לאה ותרין מן רחל לית עמון לבר מנון אנש ואקים תרין מבני איטבותה עם בני סולהתיה והאנחן גלין למה דן אתעבד אהן עובדה ניזל בתר אברהם ארש נטורי פקודי אלה דאמר בדילה וישמר משמר מצ חקותי ותר ומדן לא נפק ולא נסטי שרוי מד אתת בסרתה לידה עמר פתור לזימון מלאכי אלהה לא יכל ישמעאל דבח ולא סבל כלום ממד עבד למוקרון','O people, cleave to what you have heard from this great speech, for it is 
wholly teaching and life and blessing. See the six who stood for the blessing and 
also the six who stood for the curse. Those who stood for the blessing on the top 
of Mount Gerizim: Simeon and Levi, Judah and Issachar, and two (who) were 
magniﬁed with the royal crown: Joseph and Benjamin, the favored ones. And the 
six who stood for the curse on Mount Ebal: Reuben, Gad and Asher, Zebulon, 
and included therein: Dan and Naphtali. You who hear, set your minds and 
listen to the words that are now disclosed. God placed on Mount Gerizim six, all 
of them highborn; four from Leah and two from Rachel. There was no other with 
them. And He placed two of the favored with the sons of the maidservants. And 
behold, we reveal why this was done. Let us turn to Abraham, the fundament of 
the keepers of God’s commandments, about whom He said: He kept My charge: 
My commandments, My laws, and My teachings (Gen. 26:5). Let us not leave this 
and not turn away. First, when the announcement came to him, he arranged a 
table towards the angels of God. Ishmael could not slaughter, nor did he carry 
anything of what (Abraham) did to honor them.','עם, דבקו במה ששמעתם מן הדברים הגדולים האלה, שכן כולם תורה וחיים וברכה. ראו את ששת העומדים לברכה וגם את ששת העומדים לקללה. העומדים לברכה על ראש הר גריזים: שמעון ולוי, יהודה ויששכר, ושניים שנתעטרו בכתר המלכות: יוסף ובנימין, האהובים. וששת העומדים לקללה על הר עיבל: ראובן, גד ואשר, זבולון, ועמהם: דן ונפתלי. אתם השומעים, שיתו לבבכם והקשיבו לדברים הנגלים עתה. האל הציב על הר גריזים ששה, כולם ממוצא רם: ארבעה מלאה ושניים מרחל. לא היה עמהם אחר. והציב שניים מן האהובים עם בני השפחות. והנה, אנו מגלים מדוע כך נעשה. נפנה אל אברהם, יסוד שומרי מצוות האל, אשר עליו נאמר: אֲשֶׁר שָׁמַע בְּקֹלִי וַיִּשְׁמֹר מִשְׁמַרְתִּי מִצְוֹתַי חֻקּוֹתַי וְתוֹרֹתָי (בראשית כו,ה). לא נסטה מכך ולא נסור ממנו. בראשית, כאשר הגיעה אליו הבשורה, ערך שולחן לכבוד מלאכי האל. ישמעאל לא יכול היה לשחוט, ולא נשא דבר ממה שעשה אברהם לכבדם.');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (182,'III','46','וידבר משה והכהנים הלוים',3000461,'אלאף חכם די הודעת יתך רביאן דאלה מלכה דעלמה ולית בר מנה בלשה מן בראשית תשקח יתה בשתתי קציה על מניאן א ; אמן והאן אתחזית לית תמן בלם וקשטה קעם ומרבי בריאתה מכן דאלאף מרביה מדעיה דיתון ממנים על קשטה וידעו רביאן אלהותה רבתה ] ו [ לא יקצו מן ] מ [ רבה לגדלה ] י [ תודי יכולה ] ד [ ממן לחודה ] ל [ עלם עלמים ולית עמה אל חורן מים מחכמה רבין ] ר [ ב מד › לית ‹ בחיל אנש שאם ] י [ תרה אקימת לנן שלמה גלי לן בגו דר ודר ממן לעלם הך דהות לן סהד כן תהי עלינן וילן הן נפקנן מן אהן פרדיסה כיינן נקום במקום מצדי אוי לאנש ד › י ‹ ק } י { ום › בה ‹ נעמי קנומן מן חברי בישתה ונשבע הן לא נקרבנה לעלם דאנן דחלין לא נסתפי בחוביה דאתיטמת עלינן כמה › אמרו ‹ מלאכיה דפרקו ללוט המלט ] על נפשך פן תספה [ ותקפו בה עד אתפרק ולא שבקותה עד אמטה אל אתרה דבעה מן הנון אנן עד יהי לן פרקן אלית נזזע רוחה דקנתה','Aleph – know that it taught you the greatness of God, the King of the 
world; there is no other except Him. Seek Him in Genesis and you will ﬁnd Him 
in the six sections concerning the value of .אAmen, wherever it appears, there is 
no foolishness. The True One stands and promotes the Creation. Therefore Aleph 
elevates the minds of those who persevere in truth and know the glory of the 
great Divinity, and never stop from glorifying His greatness. Praised be the 
Potent who endures alone forever and ever, and there is no other god with Him. 
Mem teaches a very great glory, which none has the power to estimate its great-
ness. It has established for us peace, manifest in every generation, enduring for-
ever. As it was to us a witness so shall it be to us (in the future). Woe to us if we 
depart from this garden, for we would stand in a desolate place, woe to the man 
who would stand in it. Let us remove ourselves from the companions of the evil 
and swear that we shall never draw near to it. For we fear, lest we perish because 
of the sins, which became burdensome on us. As said the angels who redeemed 
Lot: Flee for your life […] lest you be consumed (Gen. 19:17) [and they insisted 
until he was redeemed, and they did not leave him until he arrived to the place 
which he requested from them. Who are we, that we may have redemption, if we 
do not move the spirit of zeal?','אלף – דע כי לימדה אותך את גדולת האל, מלך העולם; אין אחר מלבדו. בקש אותו בבראשית ותמצאהו בשישה חלקים הנוגעים לערכה של א''. אמן, בכל מקום שהוא מופיע, אין בו שטות. האמת עומדת ומקדמת את הבריאה. לכן האלף מרומם את מחשבותיהם של המתמידים באמת ויודעים את כבוד האלוהות הגדולה, ולעולם אינם פוסקים מלפאר את גדולתו. ברוך החסין השורד לבדו לעולם ועד, ואין אל אחר עמו. מם מלמדת כבוד גדול מאוד, שאין לאל ידו של איש לשער את גדולתו. היא כוננה לנו שלום, הנגלה בכל דור, הנמשך לעולם. כפי שהייתה לנו לעד, כן תהיה לנו (גם בעתיד). אוי לנו אם נסטה מגן זה, שכן נעמוד במקום שממה, אוי לאיש שיעמוד בו. נרחיק עצמנו מחברת הרשעים ונישבע שלעולם לא נתקרב אליהם. כי אנו יראים פן נאבד בשל החטאים שהכבידו עלינו. כפי שאמרו המלאכים שגאלו את לוט: מַלֵּט עַל נַפְשְׁךָ [...] פֶּן תִּסָּפֶה (בראשית יט,יז) – [והפצירו בו עד שנגאל, ולא עזבוהו עד שהגיע למקום שביקש מהם]. מי אנחנו שתהיה לנו גאולה, אם לא נעורר את רוח הקנאה?');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (183,'III','36','וידבר משה והכהנים הלוים',3000361,'שיאלה אתכון למשמע יתה מן אהן לון מפרדנה תמן הביא ענינך ושמע האגבו שיאלתך כל ברכה דאמרה אלה מן נח עד יעקב עמי הך היא אסתכל ברכת נח וקבע בלך ואתילף אמר ויברך אלהים את נח ואת בניו ואמר לון הפרו ואסגו וכן אמר לאברהם ואף ליצחק ועורי ליעקב לא נפקת ברכה לאחד מנון אלא לון ולזרעון בתרון ואנית בעי בדיל דארעה צפי מה אתמר לון בדילה לא דהו יהבה לון מסתה אלא לון ולזרעון בתרון וכן אמר לון נביה רבה משה בשרוי שליחותה כד אתא לידון למפרקון חכמון דאנון יירתו ית ארעה דאשבע לאבהתון יתננה לון ובכל שיאלה דמשה שאלה הות שיאלה למלכון ארעה ודכפרו בה לא יחזונה ובניון אנון דייעלו לתמן מכן חכמתך דשוי מה יתעבד ברכתה תתמר קדם קללתה בדיל ידעו אתרה דכלל אלה בו מלכותון ואודעון דאנון מלו באהן איקרה רבה דליתו משתאם','A question – prepare yourself to hear it. From where do we know that 
they (the descendants) are speciﬁed there? Set your mind to hear the answer to 
your question: Every blessing which God pronounced from Noah up to Jacob, 
see how it is. Consider the blessing of Noah, and set your mind and learn. He 
said: And God blessed Noah and his sons, and said to them: Be fruitful and 
multiply (Gen. 9:1). Likewise He said to Abraham and also to Isaac and Jacob. No 
blessing went forth to any one of them unless (it applied) both to them and to 
their descendants afer them. If you enquire about the land, see what was said to 
them about it. It was not that He gave it to them alone, but to them and to their 
descendants afer them. So the great prophet Moses said to them at the begin-
ning of his mission, when he came to them to deliver them. He taught them that 
they will inherit the land which He swore to their fathers that He would give 
them. In every question that Moses asked, his question pertained to their posses-
sion of the land. Those who did not believe in him would not see it, but it was 
their sons who would go up there. Therefore I taught you that ﬁrst of all the 
Blessing will be pronounced before the Curse, that they may know the place 
with which God has crowned their possession. He informed them that they 
became worthy of this great honor – which is inestimable.','שאלה – הכן עצמך לשמוע אותה. מנין לנו שהצאצאים נכללים שם? שים לבך לשמוע את תשובת שאלתך: כל ברכה שאלוהים השמיע מנח ועד יעקב, ראה כיצד היא. התבונן בברכת נח, שים לבך ולמד. אמר: וַיְבָרֶךְ אֱלֹהִים אֶת נֹחַ וְאֶת בָּנָיו וַיֹּאמֶר לָהֶם פְּרוּ וּרְבוּ (בראשית ט,א). כן אמר לאברהם, וכן גם ליצחק וליעקב. לא יצאה ברכה לאחד מהם אלא שנגעה גם להם וגם לצאצאיהם אחריהם. אם תשאל על הארץ, ראה מה נאמר להם עליה. לא שנתנה להם לבדם, אלא להם ולצאצאיהם אחריהם. כך אמר להם הנביא הגדול משה בראשית שליחותו, כשבא אליהם לגאלם. לימד אותם שיירשו את הארץ אשר נשבע לאבותיהם לתת להם. בכל שאלה ששאל משה, נגעה שאלתו לירושת הארץ שלהם. אלה שלא האמינו בו לא יראוה, אלא בניהם הם שיעלו לשם. לפיכך לימדתי אתכם שהברכה תיאמר לפני הקללה בראש ובראשונה, כדי שידעו את המקום שבו כיתר אלוהים את אחוזתם. הודיעם שנמצאו ראויים לכבוד גדול זה – שאין לשערו.');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (184,'III','61','וידבר משה והכהנים הלוים',3000611,'גבר דישאל על קשטה וישמע האגבו ולא יתאלף גבי אנה מנה וליתו זכי ולא מפרנס בנהרה קעום הוא בחשכה בחייו ובמותה וליתי מקבל מנה צבעה לעלם דו כפרעה כד שאל למשה ואמר מנו יה הפך לבה אל בישה וכן עבדת עמה בכל עבידה הפך לבה הך מה דהוה מן שרואה וגבר מבקש על מחכום אלפן הן אתלף כשיר עובדה והן הוה מליו שקר מלי לוטה עליו ואתה מזדכי מנה עמי גזואה ומה אנה לה עביד אכנו בסמיון עין ולב עד יעמי גרמה בקלל רב ובאח ] ר [ ית בתשניק חיול עד מותר וגבר הן ילך בשבילה בישה והוא לא ידע ושבקת יתה תהי מקבל מלי לבטה והוא מתפני מנה כד לא הפכתנה והן ליתו הפך ולא שמע מן מליך דאמרת לה עמי מה גדלי מגזינה אקים יתה בקלל רב ביני בוראיה וגבר דימלל ממלל גדף הן חכם יתה דיאן אנה בה לא תהי מוכח לה בין עלמה אנה מוכחנה בסגי מעואן והן הוה ליתו ידע מהו ממלל ואתלף למליך טובך וטובה והן הוה חכם מהו ממללה ולא שמע למליה דאתמרת פלי קשטה מנה וקללתה עליו על טור סיני אזהרת מן אהן עובדה לא יתעבד לעלם ואכהן קטרתה בלבטה עד לא יתעבד','When a man asks about the truth and hears the answer but does not 
learn, I will exact (revenge) on him. He will never be cleared and will not be con-
ducted in light, but will stand within darkness in both his life and death. I will 
never listen to his outcry, for he is like Pharaoh when he asked Moses saying 
Who is the Lord (Exod. 5:2). His mind turned towards evil – and I dealt with him 
accordingly. In every deed his mind turned, as it was in the beginning. If a man 
seeks to know the teaching, if he learns it, his deed is right; but if his words were 
lies, words of curse will befall him, while you are exempted from him. See his re-
quital and what I will do to him. I will strike him with blindness of the eye and 
mind, until he sees himself as under a great curse, and at his end in an exceed-
ingly mighty aﬄiction. If a man walks in an evil path, and he does not realize it, 
and you abandon him, you will receive the words of the curse, and he will be ex-
empt of it, since you did not turn him back. If he does not turn back, and does 
not listen to the words you said to him, see how my greatness requites him: I will 
set him under a great curse amongst the creatures. If a man utters an utterance 
of defamation, and he knows it, I will judge him. Do not reprove him among 
people, for I will reprove him with many plagues. If he does not know what he 
says, and he learned from your words, good for you and good for him. But if he 
knew what his utterance (means), and did not listen to the words that were said 
to him, the truth will be removed from him and the curse will be on him. On 
Mount Sinai I warned about this deed, that it should never be done, and here I 
have bound it with a curse, that it should not be done.','כשאדם שואל על האמת ושומע את התשובה אך אינו לומד, אתבע ממנו. לא יינקה לעולם ולא יידרך באור, אלא יעמוד בתוך חשכה בחייו ובמותו. לא אשמע לזעקתו לעולם, שכן הוא כפרעה בשאלו את משה לאמור מי ה'' (שמות ה,ב). לבו פנה אל הרע – ועשיתי לו בהתאם. בכל מעשה שפנה לבו, כאשר היה בתחילה. אם אדם מבקש לדעת את התורה, אם למד אותה, מעשהו ישר; אך אם דבריו היו שקר, דברי קללה יפלו עליו, ואתה פטור ממנו. ראה את גמולו ומה אעשה לו. אכהו בעיוורון עיניים ולב, עד שיראה את עצמו תחת קללה גדולה, ובסופו בייסורים עצומים מאוד. אם אדם הולך בדרך רעה ואינו יודע זאת, ואתה עוזבו, תקבל את דברי הקללה והוא יהיה פטור ממנה, מפני שלא השיבותו. אם לא שב ולא שמע לדברים שאמרת לו, ראה כיצד גדולתי גומלת לו: אשימהו תחת קללה גדולה בין הברואים. אם אדם מוציא אמירת דיבה ויודע זאת, אדונהו. אל תוכיחהו בפני אנשים, שכן אוכיחהו במכות רבות. אם אינו יודע מה אומר ולמד מדבריך, טוב לך וטוב לו. אך אם ידע את משמעות אמירתו ולא שמע לדברים שנאמרו לו, תוסר ממנו האמת והקללה תהיה עליו. על הר סיני הזהרתי על מעשה זה, שלא ייעשה לעולם, והנה קשרתי אותו בקללה שלא ייעשה.');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (185,'III','3','וידבר משה והכהנים הלוים',3000031,'עסרתי תשמישהתה כהלה עבידה לגו משכנה תשמיש כיורה דמנה יסחי בדיל עובד מיני קדשיה ותשמיש מזבח עלתה ותשמיש פתורה ותשמיש מנהרתה ואף תשמיש אשתה כמד אתרשי אש תדירה תוקד על מדבחי לא תטפי ותשמיש מזבח הועדותה ברמשה ובצפרה ותשמישה דלה מלגו פרכתה למעלי קטרתה כמה דאתרשי ולה תשמישהן לקנומה קדם דיקרב עובד ועסרתי קרבניה דהוה לון מקרב כל קרבן עביד בזבנה בדברה רישי ירחיה ונדרה ורחבתה ועלת תדירה וקרבן פסחה וקרבן יום הבכורים וריש ירחה שביעיה ויום סלוחה וחג כנושה וקרבן יומה תמינה שביעי מועדי › ה ‹ וחתמת קדשיה יתרומם מרה דכל קדשה ועשרים חלקין לקבל כל אלין לית צורכה למבקר על יתון חלקיה','The ten “services” – all of them are performed in the Sanctuary: the ser-
vice of the laver in which (the priest) washes for the performance of the various 
holy (works), the service of the altar for the burnt oﬀerings, the service of the 
table, the service of the lampstand, and also the service of the ﬁre, as he was 
commanded: The ﬁre on the altar shall be kept burning, not to go out (Lev. 6:12), 
and the service of the altar of incense in the evening and morning, and its 
service within the veil to oﬀer the incense, as he was commanded, and to it (ap-
pended) separate services before he may approach to (his) duty. The ten oﬀer-
ings which they ought to oﬀer, each oﬀering made at its proper time according to 
its practice: the beginning of the months, the vow, the free-will oﬀering, the reg-
ular burnt oﬀering, the Passover oﬀering, the oﬀering on the Day of the First 
Fruit, and the (oﬀering of the) beginning of the seventh month, and (that of) the 
Day of Atonement, and (that of) the Feast of Ingathering, the oﬀering on the 
eighth day – the seven feasts and the conclusion of the sacred donations. 
Exalted be the Master of all holiness. The twenty (other) assignments as opposed 
to these – there is no need to inquire about those assignments.','עשרת ה"שירותים" – כולם נעשים במשכן: שירות הכיור שבו רוחץ הכוהן לצורך עבודות הקודש השונות, שירות המזבח לעולות, שירות השולחן, שירות המנורה, וכן שירות האש, שכן נצטווה: אֵשׁ תָּמִיד תּוּקַד עַל הַמִּזְבֵּחַ לֹא תִכְבֶּה (ויקרא ו,יב), ושירות מזבח הקטורת בערב ובבוקר, ושירותו לפנים מן הפרוכת להקטיר הקטורת כאשר נצטווה, ולו שירותים נפרדים לפני שיוכל לגשת אל חובתו. עשרת הקרבנות שחייבים להקריב, כל קרבן בזמנו הנכון לפי מנהגו: ראש החודש, הנדר, הנדבה, העולה התמידית, קרבן הפסח, הקרבן ביום הביכורים, וקרבן ראש החודש השביעי, וקרבן יום הכיפורים, וקרבן חג האסיף, הקרבן ביום השמיני – שבעת המועדים וסיום המתנות הקדושות. יתרומם אדון כל הקדושה. העשרים תפקידים האחרים כנגד אלה – אין צורך לחקור אחר תפקידים אלה.');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (186,'III','34','וידבר משה והכהנים הלוים',3000341,'וכד הוה דן אתרה מכלל בכל הדה אתא נח ובלש קדושה ועבד עובד כהלה קדיש לית בה מום ונסב מכל בהמאתה דכיאתה כי לא יכל יעבד דכי באתר טמא דהוא חכם דכל אתריה המלת טמא מן אבדן כל היקום והך דאמר גדלה כן הו עבד דאמנותה כן מקים מה דו אמר מכן אתעבד שרוי מן דאתברך עליו אהן דבח תמן אתברך מכן חכמנן דמרן וקניאן לית יעבד עובד אלא באתרה כד זעק לאברהם והלך ברחיותה חזי מה אתמר לה ואברכך וקטר ברכתה עד אתא לאתרה וברכה וברכת אברהם ועוד יצחק ועוד יעקב וברכת יוסף תמן גליה וכן אמר מברכת יהוה ארעה','When this place was crowned with all this, Noah came and sought to 
sanctify it, and he did a deed wholly holy, with no blemish. He took of all the 
clean animals – indeed, for he could not do (anything) pure in an unclean place, 
as he knew that every place was ﬁlled with uncleanness from the destruction of 
all living beings. And as the Great One said, so He did, for this is His habit: He 
brings about what He says. So (Noah) became the ﬁrst of those who were blessed 
on it. Where he sacriﬁced, there he was blessed. Therefore, we know that our 
Master and Creator does not do a deed except in its (proper) place. When He 
called to Abraham and (Abraham) walked according to His will, see what was 
said to him: And I will bless you (Gen. 12:2). He retained His blessing until 
(Abraham) came to the place, and (then) He blessed him. The blessing of 
Abraham and the blessing of Isaac and the blessing of Jacob too, and the bless-
ing of Joseph, were revealed there. And thus he said: From the Lord’s blessing his 
land […] (Deut. 33:13).','כאשר הוכתר המקום הזה בכל אלה, בא נח וביקש לקדשו, ועשה מעשה שהוא כולו קדוש וללא מום. לקח מכל הבהמות הטהורות — אכן, שכן לא יכול היה לעשות דבר טהור במקום טמא, שידע שכל מקום מלא טומאה מחורבן כל היצורים. וכאשר אמר הגדול כך עשה, כי זאת דרכו: הוא מממש את דברו. וכך נעשה נח הראשון מבין המבורכים עליו. במקום שהקריב, שם נתברך. לפיכך אנו יודעים שאדוננו ובוראנו אינו עושה מעשה אלא במקומו הראוי. כאשר קרא לאברהם והוא הלך לפי רצונו, ראה מה נאמר לו: ואברכך (בראשית יב,ב). שמר את ברכתו עד שאברהם בא אל המקום, ואז ברכו. ברכת אברהם וברכת יצחק וברכת יעקב גם הוא, וברכת יוסף — כולן נגלו שם. וכך אמר: ממגד ה'' ארצו [...] (דברים לג,יג).');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (187,'III','54','וידבר משה והכהנים הלוים',3000541,'נתן אפרשו גדילה ונמלי קנומן במד קשטה אמלתן עמו יוסף ואפרים ממללים עמון ממלל כהלה חכמה מרביה שמורה יוסף איך אמר תנשם רוחיכון במיתיכון אל ביתי ותעבדו עובדי לית ידור בביתי מנהו מחליף מה עבדת מן עובדה טבה מן נטר עובדה דעבדה אברהם יסק לאתרה דהוה בה מצלי ויהי נטר מד נטרה ולא יפק מנה מן אתילף מן יצחק שעבודה יקום באתר דפשט צברה מן נטר מד נטר יעקב ינשם האן דנשם אלין אנון חברי קשטה דרחמו מרון ויתון רחם אתון כדו מסחני אתרה לא יהי עובדכון מכעס לאלה ישתבח רחמנה דרחמיו יתרים וחסדה וטובה לא משתאמים','Let us set out a great division and ﬁll ourselves with what the True One 
has appointed us to. See Joseph and Ephraim speaking to them a speech wholly 
of wisdom that elevates its keeper. It was as though Joseph was saying: “Quieten 
your mind when you enter my house and do my deed. Let there not enter my 
house whoever deviates from the good deeds that I did. He who keeps the deed 
that Abraham did, let him ascend to the place where he used to pray. Let him 
observe what he observed and not depart from it. He who learned submissive-
ness from Isaac will stay in the place where he stretched out his neck. He who 
observed what Jacob observed will rest where he rested. These are the compan-
ions of the True One who loved their Master, and whom He loved. You are now 
the owners of the place – let not your deeds vex God. Praised be the Merciful One 
whose mercies are abundant and whose grace and goodness are inestimable.”','נצא לחלוקה גדולה ונמלא את עצמנו במה שהאמת הקצה לנו. ראו את יוסף ואפרים מדברים אליהם דברים מלאי חכמה לחלוטין, המרוממים את שומרם. היה כאילו יוסף אומר: "הרגיע את שכלך כאשר תיכנס לביתי ועשה את מעשי. אל ייכנס לביתי מי שסוטה מן המעשים הטובים שעשיתי. מי ששומר את המעשה שעשה אברהם, יעלה למקום שבו נהג להתפלל. יקיים מה שהוא קיים ולא יסטה ממנו. מי שלמד ענווה מיצחק ישהה במקום שבו הושיט את צווארו. מי ששמר מה שיעקב שמר ינוח במקום שבו הוא נח. אלה הם חברי האמת שאהבו את אדונם, ואשר הוא אהבם. אתם עתה בעלי המקום – אל יכעיסו מעשיכם את האל. ברוך הרחמן שרחמיו מרובים וחסדו וטובו אין להם שיעור."');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (188,'III','66','וידבר משה והכהנים הלוים',3000661,'נתן אפרשו מוזף לן נור ונעיל מנה לתחום כהלה אימנו אלפנה חיים ובטולה מות טוב למי יילפנה ווילה למי ישבקנה ארור מטה משפט גר יתום ואלמנה אקדם על עשרים עובד ביש עמי הך קדם ית גיורה ועזר מזכר יתמה וארמלתה אסתכל מה צמתת הדה מלתה מן רזין רמין בדיל גיורה שבעה פקודין ובדיל יתמה שבעה ובדיל ארמלתה ששה והאנה גלי לך יתון דלגיורה עמי הך ה » נ « ון ודע דעובד אלהנו כהלה איטבו לא תוננו במלל ולא בעובד עד לא ינחם על מה שבק ולא יתעב מד לידה אתא כיצובה מנוכון לא יעבד עובד ממה דהוה עבד בזבנה קדמאה תורה חדתה אסחנת תלתה מצוהן רמין 51, יהי קרי מקרתה דקשטה עד יתילף אלפן מוחי ותניאנה יעבד ] מ [ הו מרחי ] לא [ לה והן סטי ידאן כותך ולא תחס עליו תליתה יעבד ] ש [ למו בכלה לא יפק מן פקוד ולא יעלם על מצוה ומשפט אחד מהו לישראל יהי לה מן טבה אל בישה לא תתאני בחדו ותשבקה לוד יזדמן עמך בכל חדואתך וינשם עמך האן דאנשמך מרך שבי כל הדה קבלך דאלה אוקרה באלין שבעתיתה לית לאוי על דיאנה יהי מעבר עליו אלא מקים קשטה הך מד אתרשי לא יהי מעלם עליו ולא יאי לאחד מבני ישראל יושט לידה יד ולא › ב ‹ מלה דאנה פקדת בדילה בסגי אתרין','[Let us set out a division that will increase light for us and let us enter 
from it into a domain wholly of faith. Its teaching is life, its abandonment is 
death. Happy is he who learns it, woe to him who forsakes it: Cursed be he who 
perverts the justice due to the sojourner, the orphan, and the widow (Deut. 27:19). 
He brings forward twenty evil deeds. See how He puts the sojourner ﬁrst and 
then he mentions the orphan and the widow. Consider what this statement col-
lates from exalted mysteries: concerning the sojourner seven precepts, concern-
ing the orphan seven, and concerning the widow six. Behold, I reveal them to 
you. Concerning the sojourner, see what they are, and know that the deed of our 
God is wholly beneﬁcial. You must not ill-treat him (Deut. 23:17) neither in speech 
nor in action, lest he regrets what he lef behind and abhor what he comes to. As 
the native among you (Lev. 19:34), he shall not do the deeds which he used to do 
in former times.] One law (Num. 15:16) consists of three exalted commands. (The 
ﬁrst:) Let him read the reading of the truth, that he may learn a life-giving teach-
ing. The second: Let him do what is desirable to God, and if he deviates, he shall 
be judged as you are – do not have pity on him. The third: Let him do everything 
in perfection. Let him not depart from a decree nor ignore a commandment. And 
one ordinance (ibid.) – what is intended for Israel should apply for him too, 
either good or bad. Do not enjoy pleasure while deserting him, but let him join 
you in all your happy occasions and have rest with you where your Master gives 
you rest. Put all this in front of you, for God honored him with these seven. It is 
not appropriated to a judge to transgress it, but to implement justice as he was 
commanded. He should not ignore it. It is not appropriate for one of the people 
of Israel to raise his hand towards him unless in connection with the statement 
that I commanded about him in many places.','[נציג חלוקה שתרבה לנו אור, ונכנס ממנה לתחום של אמונה שלמה. תורתה היא חיים, ועזיבתה היא מוות. אשרי מי שלומדה, אוי למי שעוזבה: ארור מטה משפט גר יתום ואלמנה (דברים כז,יט). הוא מביא לפנינו עשרים מעשים רעים. ראו כיצד הוא מקדים את הגר ואחר כך מזכיר את היתום ואת האלמנה. התבוננו מה שאלה המילים כוללות מתוך סודות נשגבים: בנוגע לגר – שבע מצוות, בנוגע ליתום – שבע, ובנוגע לאלמנה – שש. הרי אני מגלה אותן לכם. בנוגע לגר, ראו מה הן, ודעו כי מעשה אלוהינו טוב לחלוטין. לא תונה אותו (דברים כג,יז) לא בדיבור ולא במעשה, שמא יתחרט על מה שעזב וימאס במה שבא אליו. כאזרח מכם (ויקרא יט,לד), לא יעשה את המעשים שנהג לעשות בעבר.] חוקה אחת (במדבר טו,טז) כוללת שלוש מצוות נשגבות. (הראשונה:) שיקרא את קריאת האמת, למען ילמד תורה המחייה. השנייה: שיעשה את הרצוי לאלוהים, ואם יסטה, יישפט כמוכם – אל תחמלו עליו. השלישית: שיעשה הכל בשלמות. שלא יסור מגזירה ולא יתעלם ממצווה. ומשפט אחד (שם) – מה שנקבע לישראל יחול עליו גם כן, בין לטובה ובין לרעה. אל תיהנו בהנאה תוך עזיבתו, אלא שייצטרף אליכם בכל שמחותיכם וינוח עמכם במקום שרבונכם מניח אתכם לנוח. שימו כל זאת לנגד עיניכם, שכן האלוהים כיבד אותו בשבעה אלה. אין זה ראוי לשופט לעבור עליהם, אלא לקיים את הדין כפי שנצטווה. לא יתעלם מהם. אין זה ראוי לאחד מבני ישראל להרים את ידו כנגדו, אלא בהקשר לדבר שציוויתי עליו בנוגע אליו במקומות רבים.');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (189,'III','44','וידבר משה והכהנים הלוים',3000441,'יקום ראובן ויפתח פמה ויפרד תרתסרי מלי לוטיה דאני שמע אנש מרבי מלים ואמר לין בדיל דישמע אגבו למה ראובן הוא משרי בממללה ולא יהי חורנה אמר יתון ליתה בעי מבקר על אלין מליה שמע מה דאתמר לה ולית בעי אגבו מנו דאתמר לה מה אתמר אי שמע מד לה שמע אי עבד מה דעבד כל אנש עבד מהי אמנותה לעלם עדהן ידע כל אנש במהו מתגזי ולא יבלש אנש מד ליתו לאוי לה דמות קרח כד בלש מיתובה ליתה יהי לה עמי גזואה ולא תבקר על סגי מכן כד קעם לוי ושרי ברכתה דאה מיתוביתה דלה אמסרת וכן אכהן יקום ראובן וימלל ממלל יוכח בה כל קהלה וגרמה','Reuben arises and opens his mouth and pronounces the twelve words 
of the curses – I hear a man multiplying words and speaking out in order to hear 
an answer: Why is it that Reuben starts the words, and not another says them? It 
is not desirable to inquire about these matters. Hear what was said to him and 
no (other) answer is required. Who else was told what he was told, or heard what 
he heard, or did what he did? Everyone always acts according to his habit, until 
he knows with what he is recompensed. Let nobody seek what is not appropriate 
for him, like Korah, when he sought a rank not ﬁtted for him. See his recompense, 
and do not inquire further. When Levi stood up and begun the Blessing – this 
(was according to) his rank, which was appointed to him. Likewise here, Reuben 
stands up and utters a statement, with which he rebukes the congregation as 
well as himself.','ראובן קם ופותח את פיו ואומר את שתים עשרה דברי הקללות – אני שומע אדם המרבה דברים ומדבר כדי לשמוע תשובה: מדוע ראובן פותח את הדברים, ולא אחר אומרם? אין זה ראוי לחקור בענינים אלה. שמע מה שנאמר לו ואין צורך בתשובה אחרת. מי עוד נאמר לו מה שנאמר לו, או שמע מה ששמע, או עשה מה שעשה? כל אחד תמיד נוהג לפי הרגלו, עד שידע במה הוא נגמל. אל ידרוש איש את מה שאינו הולם לו, כקורח, כאשר בקש מעמד שלא התאים לו. ראה את גמולו, ואל תחקור יותר. כאשר לוי קם והחל בברכה – זה היה לפי מעמדו, שנקבע לו. כך גם כאן, ראובן קם ואומר דבר, שבו הוא מוכיח את העדה ואת עצמו כאחד.');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (190,'III','2','וידבר משה והכהנים הלוים',3000021,'נעתד קנומן לממלא מן חכמתה ונמלך איטבו בעלמה ובאחרית לא אתמר לן ואתון תהונו ריקנים דכל אתר מרוקן לית בה אנחה לא אמיר על בור } קר { » רק « מן מיה אלא בדיל יוסף ודאה אוקרו לה ואמר באתר חורן ממלל כל אילן דלית בה פרי יתה תחבל ברן יהי לנן הן נהי אילן טב מכלל בפרים טבים תחמד לנפש נזרז למילף מיני החכמה ונרבי קנומן במה דאלפן קשטה לית לאוי עלינן נשבק קנומן איך ארעה באירה לית בה איטבו ולא נהי כות אילן לית בה פרים יתה יקטע כמה דאמר כי לא עץ מאכל הוא אתו תשחית לא אתברינן אלא למטר ולמעבד כל דמלל יהוה ישתבח אמורה כד הגדל אהרן בכהנה ואנהרה קשטה וגלה לה מד יקרה ארשה למשה ידור בעננה וחזה דמית משכנה וארשה יתה בעובדה כמה דאמר דמית משכנה וית דמית כל מניו וכדן תעבד ויהב לאהרן הכהנה חמשין חלקים לגו משכנה קדישה ארבעים ולבר מנה עסרה עסרה לתשמיש ועסרה קרבנים ועשרים עובד צפי בכל אחד מנון ושבח למלך הממן לחודה לעלם','Let us prepare ourselves to absorb wisdom, so that we may possess favor 
in this world and in the world to come. We will not be told “You shall be empty”, 
for every emptied place has no beneﬁt. (However), it is not said about a pit 
“empty of water”, except about Joseph – and this is in his honor. And He said in 
another passage an utterance: “Any tree that does not yield fruit, you may de-
stroy.” It is appropriate for us, however, to be a good tree, crowned with good 
fruits, a delight to the soul. Let us hasten to learn (various) kinds of wisdom and 
(thus) elevate ourselves in what the True One taught us. It is not appropriate for 
us to abandon ourselves like a barren land, in which there is no beneﬁt, lest we 
are like a tree without fruits, whom (one) cuts down. As (the Law) says: that they 
are not trees for food you may destroy (Deut. 20:29). We were not created except 
to keep and to accomplish all that the Lord said, praised be the Sayer. When 
Aaron was elevated in priesthood the True One mentioned him and revealed to 
him what comprises his glory. He commanded Moses to dwell in the cloud and 
showed (him) the likeness of the Sanctuary, and commanded him to do the 
work, as He said: the pattern of the Sanctuary and the pattern of all its furnish-
ings, so shall you make it (Exod. 25:9). And He gave to Aaron the priesthood – 
ﬁfy assignments; within the holy Sanctuary forty, and on its outer side ten. 
(Within the forty) ten for service, ten for oﬀerings, and twenty for duty. See every 
one of them and praise the King that endures alone forever.','נכין עצמנו לקלוט חכמה, למען נזכה לחן בעולם הזה ובעולם הבא. לא ייאמר עלינו "תהיו ריקים", שכן כל מקום שהתרוקן אין בו תועלת. ואולם לא נאמר על בור "ריק ממים" כי אם על יוסף – וזה לכבודו. ואמר בפסוק אחר דברים כאלה: "כל עץ שאינו עושה פרי, מותר לכרות." ראוי לנו להיות עץ טוב, עטור פירות טובים, תענוג לנפש. נמהר ללמוד מיני חכמה ולהתרומם במה שלימדנו האמת. אין ראוי לנו לנטוש עצמנו כאדמה בורה שאין בה תועלת, פן נהיה כעץ ללא פירות שכורתים אותו. כפי שנאמר: כִּי לֹא עֵץ מַאֲכָל הוּא כִּי אֹתוֹ תִכְרֹת (דברים כ,כ). לא נבראנו אלא לשמור ולקיים את כל אשר אמר ה'', ברוך האומר. כשנתרומם אהרן בכהונה הזכירו האמת וגילה לו את מה שמכיל את כבודו. ציווה את משה לשבת בענן, והראה לו את דמות המשכן, וציווה אותו לעשות את המלאכה, כפי שאמר: כְּכֹל אֲשֶׁר אֲנִי מַרְאֶה אוֹתְךָ אֵת תַּבְנִית הַמִּשְׁכָּן וְאֵת תַּבְנִית כָּל כֵּלָיו וְכֵן תַּעֲשׂוּ (שמות כה,ט). ונתן לאהרן את הכהונה – חמישים תפקידים; ארבעים בתוך המשכן הקדוש, ועשרה מחוצה לו. מתוך הארבעים: עשרה לשרת, עשרה לקרבנות, ועשרים לחובה. ראה כל אחד מהם ושבח את המלך המתקיים לבדו לעולמי עד.');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (191,'IV','84','מימר על שירתה רבתה',4000841,NULL,'The third statement which he said: His allotted heritage Israel (SP Deut. 
32:9) – he emphasized their sanctity with a kingdom of priests (Exod. 19:6) who 
will minister to their Master with curds from the herd (Deut. 32:14). Joseph is the 
Son of Abundance (Gen. 49:22) about whom the great prophet Moses said: the 
ﬁrstling bull has majesty (Deut. 33:17) on account of what will be done in his 
estate (which is) of two sorts – (1) A holy oﬀering; (2) Observe the month of Aviv 
(Deut. 16:1), for in it is the beginning of the oﬀerings. He taught him that he will 
reach the place of the ancestors – and you shall oﬀer […] from your ﬂock or your 
herd, at the place which the Lord your God chose, to make his name dwell there 
(Deut. 16:2). Behold, a merciful God, and there is none except Him. Happy is the 
heart that abides in Him. He lowered His Goodness to speak with weak dust, in 
order to increase His mercy to him. Behold, a merciful God and there is none 
except Him. For two worlds are bound together in His might. He called Moses 
(Exod. 19:20) and sent him to the sons of His servants. Behold, a merciful God 
and there is none except Him, who created a beautiful world and perfected it 
without assistant. He made Moses hear His voice in great majesty and gave him 
life, by which Israel may live.','האמירה השלישית שאמר: חֶבֶל נַחֲלָתוֹ יִשְׂרָאֵל (נוסח שומרון דברים לב,ט) – הדגיש את קדושתם במַמְלֶכֶת כֹּהֲנִים (שמות יט,ו) המשרתים את אדונם בחמאה מבקר (דברים לב,יד). יוסף הוא בֶּן הַשִּׂפְעָה (בראשית מט,כב) שעליו אמר הנביא הגדול משה: בְּכוֹר שׁוֹרוֹ הָדָר לוֹ (דברים לג,יז) על שם מה שייעשה בנחלתו, שהיא מן שני המינים – (א) קרבן קודש; (ב) שָׁמוֹר אֶת חֹדֶשׁ הָאָבִיב (דברים טז,א), כי בו ראשית הקרבנות. לימד אותו שיגיע למקום האבות – וְזָבַחְתָּ [...] מִצֹּאנְךָ וּמִבְּקָרְךָ, בַּמָּקוֹם אֲשֶׁר יִבְחַר יְהוָה אֱלֹהֶיךָ לְשַׁכֵּן שְׁמוֹ שָׁם (דברים טז,ב). הנה אֵל רַחוּם, ואין בלתו. אשרי הלב השוכן בו. הוריד את טובו לדבר עם עפר חלש, כדי להרבות את רחמיו עליו. הנה אל רחום ואין בלתו. כי שני עולמות קשורים יחד בגבורתו. קרא למשה (שמות יט,כ) ושלחו אל בני עבדיו. הנה אל רחום ואין בלתו, שברא עולם יפה והשלימו בלא עוזר. השמיע למשה את קולו בהוד גדול ונתן לו חיים, שבהם תחיה ישראל.');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (192,'IV','71','מימר על שירתה רבתה',4000711,'ירום נביה רבה משה דפרט גוני טבהתה דמרן עלינן מלתה אשתהיתה ירכיבהו , אזד } מ {› על במתי הארץ מד מלאכיה הלכים עמה מן יכל קעם לקבלה כד יא ‹ נו על מדין ולגוה חמשה » מלכים « מה קטלונון ובזזו דלון מן קעם תמן קבלון וכד אזלו למגוז לירדנה אדהן מלך יקום לקבלון וכד אתו לארע כנען ומרון עמון מן קעם קבלון הדה מלתה הודעת דאנון ימלכון רמבאת ארעה בתרין זבנים עזר אל מדעך ושבק רוחה דנפשך ומה דאלפך אלה תתילף דמה דתמלך מה מלכו אבהתך ולך יתקומם מה לון אמיר ויכחשו או לך ואתה על במתם תדרך עתה נשמר חקיך יה אלהינו ונדאל מנך כל ימי חיינו','Exalted be the great prophet Moses who detailed various good things 
which our Master (did) for us. The sixth statement: He set him atop the highlands 
(Deut. 32:13) – since the angels walk with him, who can stand against him? 
When they gathered against Midian, among which were ﬁve kings, did they not 
kill them and plunder their possessions? Who stood there against them? When 
they went to pass the Jordan, what king stood against them? And when they 
came to the land of Canaan, while their Master was with them, who stood 
against them? This word proclaimed that they will govern the highlands in two 
periods. Go back to your senses and leave the caprices of your desire, and learn 
what (God) taught you. Perchance you will possess what your ancestors pos-
sessed, and what was said about them may apply to you: Your enemies shall be 
rebuked because of you, and you shall tread upon their high places (Deut. 33:29). 
Now we will keep Your precepts, O Lord our God and we will fear You all the days 
of our lives.','יתרומם הנביא הגדול משה שפירט טובות שונות שאדוננו עשה לנו. האמירה השישית: "יַרְכִּיבֵהוּ עַל בָּמֳתֵי אָרֶץ" (דברים לב,יג) – כיוון שהמלאכים הולכים עמו, מי יכול לעמוד נגדו? כשנאספו על מדיין, שבה היו חמישה מלכים, הלא הרגום ובזזו את רכושם? מי עמד שם נגדם? כשהלכו לעבור את הירדן, איזה מלך עמד נגדם? וכשבאו לארץ כנען, בעוד אדונם עמם, מי עמד נגדם? דבר זה הכריז שישלטו בגבהות בשתי תקופות. שובו לדעתכם ועזבו את שרירות ליבכם, ולמדו מה שלימד אתכם (האלוהים). אולי תירשו את אשר ירשו אבותיכם, ויחול עליכם מה שנאמר עליהם: "וְאֹיְבֶיךָ יִכָּחֲשׁוּ לָךְ וְאַתָּה עַל בָּמוֹתֵימוֹ תִדְרֹךְ" (דברים לג,כט). מעתה נשמור את מצוותיך, ה'' אלוהינו, וניראך כל ימי חיינו.');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (193,'IV','80','מימר על שירתה רבתה',4000801,'יצב גבולות עמים למספר בני ישראל כמה דאמר לאברהם ארבה ית זרעך ככוכבי השמים כי חלק יהוה עמו יעקב קדישים תהיו כי קדוש אני והתקדשתם והייתם קדישים ועד תטרו קדשי מלתה תליתה דאמר יתה הוזף בה ית קדושון חבל נחלתו ישראל ואתון תהונו לי ממלכת כהנים וגוי קדש ובתהללות ישימנה » ו « ובמנו » ח « ה יאמר שובה יהוה למרבי בכל זבן רבבות ישראל יסובבנהו ויבננהו ויוציא משה את העם לקראת האלהים מן המחנה בדיל ישמע עמה בממללי עמך יאכל יעקב וישבע ואכלת ושבעת וברכת את יהוה אלהך על מה חננך וכל אשר תתן לי עשר אעשירנו לך ישמן משבחה וברכך יהוה אלהיך בכל אשר תעשה והיה אם שמע תשמע בקול יהוה אלהיך וראו כל עמי הארץ כי שם יהוה נקרא עליך ותהי ברכה','He ﬁxed the boundaries of peoples according to the number of the 
Children of Israel (Deut. 32:8), as He said to Abraham: I will multiply your descen-
dants as the stars of heaven (Gen. 22:17); for the Lord’s portion is his people, Jacob 
(Deut. 32:9); you shall be holy, for I […] am holy (Lev. 19:2). Consecrate yourselves 
and be holy (Lev. 11:44), that you may keep my holiness. (At) the third word that 
He said He added their holiness: His allotted heritage Israel (SP Deut. 32:9); you 
shall be to Me a kingdom of priests and a holy nation (Exod. 19:6). And in praises 
He placed him (SP Deut. 32:10). At the halt he would say: Return, O Lord (Num. 
10:36), to exalt at all times the ten thousand thousands of Israel (ibid.). He engird-
ed him, watched over him (Deut. 32:10). Then Moses brought the people out of the 
camp to meet God (Exod. 19:17), in order that the people might hear when I speak 
with you. (Exod. 19:9). Jacob shall eat and be satisﬁed (Deut. 32:15); and you shall 
eat and be full, and you shall bless the Lord your God (Deut. 8:10) on account of 
His gracious dealing with you. And of all that You give me I will give the tenth to 
You (Gen. 28:22). The praising one grew fat (Deut. 32:15) – so the Lord your God 
will bless you in all that you do (Deut. 15:18); and if you listen to the voice of the 
Lord Your God (Deut. 28:1); and all the peoples of the earth shall see that you are 
called by the name of the Lord (Deut. 28:10); and you shall be a blessing (Gen. 
12:2).','הוּא הִצִּיב גְּבֻלֹת עַמִּים לְמִסְפַּר בְּנֵי יִשְׂרָאֵל (דברים לב,ח), כמו שאמר לאברהם: הַרְבָּה אַרְבֶּה אֶת זַרְעֲךָ כְּכוֹכְבֵי הַשָּׁמַיִם (בראשית כב,יז); כִּי חֵלֶק יְהוָה עַמּוֹ יַעֲקֹב (דברים לב,ט); קְדֹשִׁים תִּהְיוּ כִּי [...] קָדוֹשׁ אָנִי (ויקרא יט,ב). הִתְקַדִּשְׁתֶּם וִהְיִיתֶם קְדֹשִׁים (ויקרא יא,מד), לשמור את קדושתי. בדבר השלישי שאמר הוסיף על קדושתם: חֶבֶל נַחֲלָתוֹ יִשְׂרָאֵל (דברים לב,ט, נוסח שומרוני); וְאַתֶּם תִּהְיוּ לִי מַמְלֶכֶת כֹּהֲנִים וְגוֹי קָדוֹשׁ (שמות יט,ו). וּבִתְהִלּוֹת הֱנִיחוֹ (דברים לב,י, נוסח שומרוני). בנסיעה היה אומר: שׁוּבָה יְהוָה (במדבר י,לו), להרים בכל עת את רִבְבוֹת אַלְפֵי יִשְׂרָאֵל (שם). יְסֹבְבֶנְהוּ יְבוֹנֲנֵהוּ (דברים לב,י). אז הוֹצִיא מֹשֶׁה אֶת הָעָם לִקְרַאת הָאֱלֹהִים (שמות יט,יז), לְמַעַן יִשְׁמַע הָעָם בְּדַבְּרִי עִמָּךְ (שמות יט,ט). וְאָכַל יַעֲקֹב וְשָׂבָע (דברים לב,טו); וְאָכַלְתָּ וְשָׂבָעְתָּ וּבֵרַכְתָּ אֶת יְהוָה אֱלֹהֶיךָ (דברים ח,י) על חסדיו עמך. וְכֹל אֲשֶׁר תִּתֶּן לִי עַשֵּׂר אֲעַשְּׂרֶנּוּ לָךְ (בראשית כח,כב). וַיִּשְׁמַן הַמְהֻלָּל (דברים לב,טו) – כֵּן יְבָרֶכְךָ יְהוָה אֱלֹהֶיךָ בְּכֹל אֲשֶׁר תַּעֲשֶׂה (דברים טו,יח); וְהָיָה אִם שָׁמוֹעַ תִּשְׁמַע בְּקוֹל יְהוָה אֱלֹהֶיךָ (דברים כח,א); וְרָאוּ כָּל עַמֵּי הָאָרֶץ כִּי שֵׁם יְהוָה נִקְרָא עָלֶיךָ (דברים כח,י); וְהָיִיתָ בְּרָכָה (בראשית יב,ב).');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (194,'IV','6','מימר על שירתה רבתה',4000061,'רב הוא נביה רבה משה ומה הוא אמר מן יתה ממללה דכהלה חייה כל מלה דהוה לשנה מגלגל בה מרביאה בחכמה מדילה דאלה שרה ואמר בפמה דנביותה השירה הזאת ולא אמר התורה הזאת בעו מחכם לון דהי אסחנת כל כלום ממד חזה קשטה וכלל בה ארהותה אמר השירה והוזף נהר בזאת עמי רבותון והשלם מדעך נהירו לא אתפרק בה לבר מן עבודה ואנהרה עד ביאר בקשט חמשה ספרים ביאר משה על פי מרה ועבודה יהוה ומשה והתורה צמתת הדה מלתה והשיגה במלת הזאת שמה דלבשה וקדשה דגלתה והן העבוד אחד לקלומה וחתמת אותת מכתבה דקדשה ירום מדעה דמשה דכל ממללה חכמה ודעה אהן הך משה ומן מדמי למשה נביא לא קם כותה ולא יקום לעלם','Great is the prophet Moses and (great is) what he said in that speech, 
wholly of life.] Every word that his tongue was uttering was exalted with wisdom 
from God. He began and spoke by the mouth of prophethood: This song (Deut. 
31:30). He did not say: This Law (Deut. 31:24) – he sought to teach them that it 
contains everything that the True One contemplated, and he adorned it with the 
Torah. He said השירהand added insight by means of .הזאתSee their greatness 
and perfect your mind with enlightenment, for in it nothing was separated from 
its Maker. And He enlightened him, so that he may write in truth. Five books 
Moses wrote at the command of his Master and Maker. The Lord, and Moses, and 
the Torah are encompassed in the word :הזאתthe name that (Moses) wore, and 
the holiness which he revealed, and that the Creator is the One, alone. And it 
concluded the letters of the Holy Writ. Exalted be the mind of Moses, for all his 
speech is wisdom and knowledge. Where is anyone like Moses and who resem-
bles Moses, a prophet like whom nobody has arisen and will never arise?','גדול הנביא משה וגדול מה שאמר בנאום ההוא, שכולו חיים.] כל מילה שנשאה לשונו היתה נישאת בחכמה מאת האלוהים. פתח ודיבר מפי הנבואה: השירה הזאת (דברים לא,ל). לא אמר: התורה הזאת (דברים לא,כד) – ביקש ללמדם שהיא כוללת את כל מה שהאמת זמם, וקישט אותה בתורה. אמר השירה והוסיף תובנה באמצעות הזאת. ראו את גדולתן ושכללו את דעתכם בהארה, שכן בה לא נפרד דבר מבוראו. והאיר לו, למען יכתוב באמת. חמישה ספרים כתב משה בצו אדונו ובוראו. ה'', ומשה, והתורה כלולים במילה הזאת: השם שמשה לבש, והקדושה שגילה, ושהבורא הוא האחד, לבדו. והיא חתמה את אותיות הכתב הקדוש. תרומם דעתו של משה, שכל דיבורו חכמה ודעת. היכן מישהו כמשה ומי דומה למשה, נביא שכמותו לא קם ולא יקום לעולם?');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (195,'IV','39','מימר על שירתה רבתה',4000391,'יזבחו לשידים לא אלה בדיל פאניה ארורה כדו יקום ויסתיר משכנה ויבטל כל עובד דיתעבד בה ויהי עלמה בלא משכן ולא מזבח ולא קרבן ולא עלה ולא שלמים ולא מנחה ולא חטאת ולא אועד ולא צלו ולא כהן כל הדה בדיל פניה אה רחמנה דכר אבהתן ולא תשתבק מן שיורה דן דאסרו בה דבביה בעים מכלינה כי נפושה מנך קריב אמן לבן על אימנותה בך הנגד יתן בריחותך דאתה אסידת על גרמך הן לית תנשי קיאם טביה נשים קנומן קעמין ביספר קשטה ולא נפק מנה ונילף מן ספרה דלגוה קעם ונרבי למקרתה דבה כתיבה נביה רבה משה ספרה ואנן טליה דבחרן מרן לכן הן הוינן טלים טבים אתילפנן מן אהן ואתפנינן מכל מרדה נחיל קנומן במטר פקודין דפקדן מרן ונשמע ממללה דאוקרן בה מרן וילה ברנשה דשטת בה פנותה עד אזל מדעה לאלהי נכר','They sacriﬁced to demons which were no gods (Deut. 32:17) – this 
concerns the cursed apostate. When he will arise, he will destroy the Sanctuary 
and suspend all that is done in it, and the world will be without a sanctuary, no 
altar, no oblation, no burnt-oﬀering, no peace-oﬀerings, no cereal-oﬀering, no 
sin-oﬀering, no incense, no prayer, and no priest. All this because of the apos-
tate. O Merciful One, remember our fathers and let not this remnant be forsaken, 
which the foes have conﬁned seeking to destroy it. Indeed, relief by you is near. 
Set our heart upon faith in You, lead us in Your grace, for You have testiﬁed 
about Yourself that You will not forget the covenant (with) the good ones. Let us 
make ourselves stand in the schoolhouse of the True One and not depart from it, 
but learn from the teacher who stands in it, and magnify the reading which is 
written in it. The great prophet Moses is the teacher, and we are the pupils whom 
our Lord chose. Therefore, if we are good children, we shall learn from this and 
turn away from all rebellion. Let us strengthen ourselves by keeping the 
commandments which our Master has commanded, and obey the commands by 
which our Master honors us. Woe to the man whom Fanuta led astray, so that his 
mind turned to alien gods.','יִזְבְּחוּ לַשֵּׁדִים לֹא אֱלֹהַּ (דברים לב,יז) – זה עניינו של המומר הארור. כשיקום, יחריב את המקדש ויבטל את כל הנעשה בו, והעולם יהיה בלא מקדש, בלא מזבח, בלא מנחה, בלא עולה, בלא שלמים, בלא מנחת סולת, בלא חטאת, בלא קטורת, בלא תפילה ובלא כוהן. כל זאת בגלל המומר. הו רחמן, זכור את אבותינו ואל תעזוב את השארית הזאת, אשר הצרים הקיפוה ומבקשים להשמידה. הן ישועתך קרובה. כוון את לבנו לאמונה בך, הנחנו בחסדך, שהרי העדת על עצמך שלא תשכח את הברית עם הטובים. נחזק את עצמנו לעמוד בבית המדרש של האמת ולא נסור ממנו, אלא נלמד מן המורה העומד בו ונרומם את הקריאה הכתובה בו. הנביא הגדול משה הוא המורה, ואנחנו התלמידים אשר בחר בנו אדוננו. לפיכך, אם נהיה ילדים טובים, נלמד מזה ונסור מכל מרי. נחזק את עצמנו לשמור את המצוות שציווה עלינו אדוננו, ונציית לחוקים שבהם מכבד אותנו אדוננו. אוי לאיש אשר פנותא הטעה אותו עד שפנה לבו לאלים זרים.');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (196,'IV','56','מימר על שירתה רבתה',4000561,'עסרה מלים אמרה אוכחו מן נהירות קשט במדע שלם עמי יתון ושבח למרך ורבי לנביך דאל » פ « ך בה אוקר שאל אבוך ויחוי לך במד בדילך עביד עד תהי ממלך ומצלח בכל עובדיך דעבדת סהביך ויימרו לך קשיטות מלי גזרי ארהותה עד לא תהי מסתרבך וירום מדעך ויתוזף דעה שמנת עבית ועיצה במלת כשית מיכל דלא בצבצוב ‹} ומשתה דלא בלעיו וירא יהוה ואקפה במלת וינ › א ח { ץ הגלה בסימנים וינאץ בדינים ואתחזי לגו סימני » ם « בדיל פרקנך והנאץ בדינים בדיל משרראתך מכעוס בניו ובנותה מלת אוכחו ארכן כל קהלה מד שמע מן משה אישה אדה מלתה וזוג בנאתה עם בניה ואזדמנו במלתה דאה בנים לא אמן בם אה אוכחו רבה וילה אנש דלא יתפורר אנון פנסוני עשדה רבה עד מותר עסרה זבנים ולא שמעו אמרת אבדון עזרת לדברי ובצלות משה אחסת עליון אנון כעסוני באחמדוהן בישהן בישה לון במה דעבדו אבטל מן אנשה דכרנון } דכרנון { בקשט ב » ק « יאם אבהתון גלג › ל ‹ ת עמון','Ten words, he said them – a reproof by true wisdom, with a perfect 
mind. See them and praise your Master and exalt your prophet; honor the one 
who taught it to you. Ask your father and he will tell you (Deut. 32:7) – about what 
has been done for your sake, that you may be guided and succeed in all the 
deeds that you do. Your elders, and they will tell you (ibid.) – the truthfulness of 
the words of the precepts of the Torah, so that you might not be confused, and 
your mind might be exalted, and wisdom might be added to it. (He said) You 
waxed fat, you grew thick (v. 15) and strengthened it with the word(s) you became 
beautiful (ibid.) – (by) food without restriction and drink without toil. The Lord 
appeared (v. 19) and he adjoined to it the word and spurned (ibid.) – (God) 
appeared with wonders and spurned with punishments. He revealed Himself 
with wonders in order to deliver you, and spurned you with punishments in 
order to strengthen you. Because of the provocation of his sons and his daughters 
(ibid.) – a word of reproof. The entire congregation bowed down, when they 
heard from Moses the Man this word. He joined the daughters and the sons, 
(who) were gathered in this word: Children in whom is no faithfulness (v. 20) – 
behold, a great reproof. Woe to the man who is not awakened. They incensed Me 
(v. 21) – exceedingly great distress. Ten times they disobeyed. I said: I will destroy 
them (v. 26), but I reverted to my way, and through the prayer of Moses I had pity 
for them. They stirred My anger (v. 21) with their evil desires – evil to them for 
what they have done. I shall abolish their memory among people (ibid.) – 
(because of) the truth of the covenant of their fathers I had mercy for them.','עֶשֶׂר דְּבָרִים אָמַר – תּוֹכָחָה בְּחָכְמָה אֲמִתִּית, בְּשֵׂכֶל שָׁלֵם. רְאֵם וְשַׁבֵּחַ אֶת אֲדוֹנֶיךָ וְרוֹמֵם אֶת נְבִיאֶךָ; כַּבֵּד אֶת מִי שֶׁלִּמֵּד אוֹתְךָ. שְׁאַל אָבִיךָ וְיַגֵּדְךָ (דברים לב,ז) – עַל מַה שֶּׁנַּעֲשָׂה לְמַעַנְךָ, כְּדֵי שֶׁתִּנָּחֶה וְתַצְלִיחַ בְּכָל הַמַּעֲשִׂים שֶׁתַּעֲשֶׂה. זְקֵנֶיךָ וְיֹאמְרוּ לָךְ (שם) – אֶת אֲמִתּוּת דִּבְרֵי חֻקֵּי הַתּוֹרָה, כְּדֵי שֶׁלֹּא תִּתְבַּלְבֵּל, וְשֵׂכְלְךָ יִתְרוֹמֵם וְחָכְמָה תִּתּוֹסַף בּוֹ. (אָמַר) וַיִּשְׁמַן יְשֻׁרוּן וַיִּבְעַט (פסוק טו) וְחִזֵּק זֹאת בַּמִּלָּה וַתִּיטַב (שם) – (בְּ)אֹכֶל בְּלֹא הַגְבָּלָה וּמַשְׁקֶה בְּלֹא עָמָל. וַיַּרְא יְהוָה (פסוק יט) וְצֵרֵף אֵלָיו אֶת הַמִּלָּה וַיִּנְאָץ (שם) – (הָאֱלֹהִים) נִגְלָה בְּנִפְלָאוֹת וְנָאַץ בְּעֳנָשִׁים. נִגְלָה בְּנִפְלָאוֹת כְּדֵי לְהַצִּילְכֶם, וְנָאַץ בְּעֳנָשִׁים כְּדֵי לְחַזְּקְכֶם. מִכַּעַס בָּנָיו וּבְנֹתָיו (שם) – דָּבָר שֶׁל תּוֹכָחָה. כָּל הַקָּהָל כָּרַע, כְּשֶׁשָּׁמַע מִמֹּשֶׁה הָאִישׁ דָּבָר זֶה. צֵרֵף אֶת הַבָּנוֹת וְאֶת הַבָּנִים, שֶׁ(שְׁנֵיהֶם) נִכְלְלוּ בְּדָבָר זֶה: בָּנִים לֹא אֵמֻן בָּם (פסוק כ) – הִנֵּה תּוֹכָחָה גְּדוֹלָה. אוֹי לָאִישׁ שֶׁאֵינוֹ מִתְעוֹרֵר. קִנְאוּנִי (פסוק כא) – צָרָה גְּדוֹלָה בִּמְאֹד. עֶשֶׂר פְּעָמִים מָרָדוּ. אָמַרְתִּי אַשְׁבִּיתָה (פסוק כו) אֲבָל שַׁבְתִּי לְדַרְכִּי, וּבִתְפִלָּתוֹ שֶׁל מֹשֶׁה חָמַלְתִּי עֲלֵיהֶם. יַכְעִיסוּנִי (פסוק כא) בְּתַאֲווֹתֵיהֶם הָרָעוֹת – רַע לָהֶם עַל מַה שֶּׁעָשׂוּ. וְאַשְׁבִּיתָה מֵאֱנוֹשׁ זִכְרָם (שם) – (בִּ)גְלַל אֱמֶת בְּרִית אֲבוֹתֵיהֶם רִחַמְתִּי עֲלֵיהֶם.');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (197,'IV','75','מימר על שירתה רבתה',4000751,'יתודי אלה רחמנה דגלה לן נאר מן מחכומה רבה נרכן קנומן ונשתעבד קמי עבודן ונשמע מלי אזהרותה דצמת יתון בנהירות נביותה בהדה שירתה רבתה והי עסרה מלים פרטון קמי קהלה ברבו רבה כי אש קדחה באפי סדם ועמרה אתר ביש טמא כהן הטמא אשתה תדכינה וכן אמר והתקדשתם אזהר מן אשתה תאכל ארעה ועללאתה לא תזריע ולא תצמיח תיבד ארעה וכל דיריה בבישהתון תלחט מוסדי ההרים תמן יתחכם קדוש הרגריזים ואמר עוד אספה עליהם רעות בעלמה יתוקדו ולגו יום נקם יתגזו בקשט וחצי אכלה בם אצית עלמה למחזי מה יתעבד בון מן מדונה מזה רעב לחמ › ה ‹} ו { אמר , ואכלתם ולא תשבעו גמלון רשף קטף מררים נביא ] שקרה [ ראש ] ולע [ נה ושן ] בהמות [ אשלח ] בם ו [ תבלענון ] וילו [ ן בכן ] עם [ חמת זהלי ] עפר [ ייתון ] מן כל [ ארע ] רח [ יקה ולא ידחלו מנון מחוץ תשכל חרב ומחדרים ] אימ [ ה לא ] נש [ אר בהם עד ] א [ חד','Thanks be to the Merciful God who revealed light to us from His great 
knowledge. Let us lower ourselves and submit before our Maker. Let us hear the 
words of warning which Moses gathered in this Great Song by means of the 
insight of his prophethood, ten words he detailed before the congregation with 
great majesty. For a ﬁre is kindled by my anger (Deut. 32:22). Sodom and Gomorrah 
are an evil, unclean place. When a priest deﬁles himself, (only) the ﬁre puriﬁes 
him. And thus He said: Consecrate yourselves (Lev. 11:44). He warned of the ﬁre: 
it devours the land and its crops (Deut. 32:22) – unsown and growing nothing 
(Deut. 29:22). The land would be destroyed and all its inhabitants in their 
evildoing. Sets on ﬁre the foundations of the mountains (Deut. 32:22) – then the 
sanctity of Mount Gerizim would be made known. He further said: And I will 
gather evils upon them (v. 23) – in (this) world they will be burnt and in the Day 
of Vengeance they will be justly repaid – I will use up my arrows upon them 
(ibid.). Listen, O world, to behold what would be done to him] by way of 
punishment: Out of hunger (is) his bread (v. 24); He said: And you shall eat, and 
not be satisﬁed (SP Lev. 26:26) – (this is) their reward. Bitter venom of snakes 
(Deut. 32:24) (is) a false prophet. Flame of bitter fruit (Deut. 29:18), and I will send 
the teeth of beasts against them (Deut. 32:24) and they will swallow them up. Woe 
to them in this! With venomous creepers in dust (ibid.), will come from every 
distant land, and they will not fear them. In the open the sword shall bereave, and 
in the chambers shall be terror (v. 25), not one of them will remain.','תודה לאל הרחמן שגילה לנו אור מידיעתו הגדולה. נשפיל עצמנו ונכנע לפני יוצרנו. נשמע את דברי האזהרה שכינס משה בשירה הגדולה הזאת בכוח תובנת נבואתו, עשרה דברים פירט לפני הקהל בגדולה רבה. כִּי אֵשׁ קָדְחָה בְאַפִּי (דברים לב,כב). סדום ועמורה הם מקום רע וטמא. כשכוהן מטמא את עצמו, רק האש מטהרת אותו. וכך אמר: וְהִתְקַדִּשְׁתֶּם (ויקרא יא,מד). הזהיר מפני האש: וַתֹּאכַל אֶרֶץ וִיבֻלָהּ (דברים לב,כב) – לֹא זֶרַע וְלֹא צֹמֵחַ (דברים כט,כב). הארץ תֵּחָרֵב וכל יושביה ברשעתם. וַתְּלַהֵט מוֹסְדֵי הָרִים (דברים לב,כב) – אז תיוודע קדושת הר גריזים. עוד אמר: וְאַסְפֶּה רָעוֹת עֲלֵיהֶם (שם כג) – בעולם הזה יישרפו וביום הנקמה ייפרע מהם כדין – אֲכַלֶּה בָּם חִצָּי (שם). שמע, עולם, ראה מה ייעשה לו בדרך עונש: מְזֵי רָעָב לַחְמוֹ (שם כד); אמר: וַאֲכַלְתֶּם וְלֹא תִשְׂבָּעוּ (ספ ויקרא כו,כו) – זהו שכרם. וְלֶחֶם רֶשֶׁף (דברים לב,כד) הוא נביא שקר. מְרֹרִי פַּרְעֹנֹת (דברים כט,יח), וְשֶׁן בְּהֵמוֹת אֲשַׁלַּח בָּם (דברים לב,כד) ויבלעו אותם. אוי להם בזאת! עִם חֲמַת זֹחֲלֵי עָפָר (שם), יבואו מכל ארץ רחוקה ולא ייראו מהם. מִחוּץ תְּשַׁכֶּל חֶרֶב וּמֵחֲדָרִים אֵימָה (שם כה), לא ייוותר מהם אחד.');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (198,'IV','53','מימר על שירתה רבתה',4000531,'יתיקר נביה רבה משה דאנהר מדעה למד מריח לאלה ואמר יהוה בדד לית לה אתר בה יתחכם ולא פאת בה מתידע ולא שרי באתר וריק מן אתר לכל אתריה חדד ביכלותה רבתה גלה בהדה מלתה דלית לה אתר יבלש מנה לבדיל כן אמר יהוה בדד הן דו מבלש הוא מתשקח ושרר אדה מלתה במלה רבה והיא אין עמו אל נכר כל דלבר מנה אכסנאי ובטול לית לה חלק באלהותה ברא בלא סעוד עבד בלא שותף תקן דלא על דמו אחד באלהותה פרד בקמאותה לית לה שותף תקן דלא על דמו בכל מה דעבד נחכם בכל הדה באימנו רבה ונסיד ונימר לית אלה אלא אחד','Gloriﬁed be the great prophet Moses who enlightened the mind with 
what pleases God and said: The Lord alone (Deut. 32:12). He has no place in 
which He is known, and no corner in which He is perceived; He does not reside 
in a place and He is devoid of any place. By His great power He created all 
places. By this statement (Moses) made known that He has no place where He 
can be sought. Therefore he said: The Lord alone – wherever He is sought He is 
found. He reinforced this statement with a great word which is: There is no alien 
god with Him (ibid). Anyone who is distinct from Him is alien and abolished, and 
has no part in divinity. (God) created without helper, He made without associate, 
He shaped without design. He is unique in His divinity, peerless in His prim-
ordiality. He has no associate. He shaped without design in everything He made. 
Let us understand all this in great faith and testify and say: “There is no god but 
One.”','מְהוּלָּל הנביא הגדול משה, שהֵאיר את הדעת בַּמַּה שֶׁנִּרְצֶה לִפְנֵי הָאֱלֹהִים, וְאָמַר: יְהוָה בָּדָד (דברים לב,יב). אֵין לוֹ מָקוֹם שֶׁבּוֹ הוּא נוֹדָע, וְאֵין פִּנָּה שֶׁבָּהּ הוּא מוּרְגָּשׁ; אֵינוֹ שׁוֹכֵן בְּמָקוֹם וְהוּא נֶעְדַּר מִכָּל מָקוֹם. בְּגָדְלוֹ הָעָצוּם בָּרָא אֶת כָּל הַמְּקוֹמוֹת. בְּמַאֲמָר זֶה הוֹדִיעַ (משה) שֶׁאֵין לוֹ מָקוֹם שֶׁבּוֹ יְבַקֵּשׁ אוֹתוֹ. לְפִיכָךְ אָמַר: יְהוָה בָּדָד – בְּכָל מָקוֹם שֶׁיְּבַקְּשׁוּהוּ יִמָּצֵא. וְחִזֵּק מַאֲמָר זֶה בְּדָבָר גָּדוֹל, שֶׁהוּא: וְאֵין עִמּוֹ אֵל נֵכָר (שם). כָּל מִי שֶׁנִּבְדָּל מִמֶּנּוּ הוּא זָר וּבָטֵל, וְאֵין לוֹ חֵלֶק בָּאֱלֹהוּת. (הָאֱלֹהִים) בָּרָא בְּלֹא עֵזֶר, עָשָׂה בְּלֹא שֻׁתָּף, יָצַר בְּלֹא תַּכְנִית. הוּא יָחִיד בֶּאֱלֹהוּתוֹ, אֵין כְּמוֹתוֹ בְּקַדְמוּתוֹ. אֵין לוֹ שֻׁתָּף. יָצַר בְּלֹא תַּכְנִית בְּכָל אֲשֶׁר עָשָׂה. נָבִין כָּל זֹאת בֶּאֱמוּנָה גְּדוֹלָה וְנָעִיד וְנֹאמַר: "אֵין אֱלֹהִים כִּי אִם אֶחָד."');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (199,'IV','68','מימר על שירתה רבתה',4000681,'יאמיצהו בארץ המדבר מן אזל והוא מתרחץ בה לית לערויה עליו יכלו יצירנהו כאישן עינו עיני יהוה אלהך בה מן רישה ועד עקבאה כנשר יעיר קנו ושכבתם ואין מחריד וישכב במקום ההוא ויחלם ועל גוזליו ירחף לאיטבו ראה ראיתי את עני עמי יפרש כנפיו ויקחהו בגדל ויסע משה את ישר מים סוף ירכיבהו על במתי הארץ הנה אנ שלח מלאכי לפניך יאכלהו תנופת שדה והיה כי יב יה אלה אל הארץ אשר נשבע לאבותיך יינקהו דבש מסלע ואכלת ושבעת וברכת את יה אלה ושמן מחלמיש צור הנני ממטיר והיה טעמו כטעם לשד השמן חמת בקר וחלב צאן וזבחת מבקרך ומצאנך ננהר לנביה רבה משה › והו ‹ מעזר לאלין מליה דבון אוקר לישראל בהדה שירתה רבתה יאמיצהו בארץ המדבר אלית יהי לה נגד הוה טעי פן תסגי עליך חית בראה הן תהי טב תרכן לקדמיך והנדה ליד האדם למחזי כד לא הוה תמן מרד כלה לקדמה ארכן והוי וכלי טמא בארעה ויהי כל מן ישכחני יקטלני אהן ] ה [ וה לקבל עובד ביש מן עבד חטא אתגזי בדין וכד הוה ישראל מתהלך בפני אלה ישכן לבטח ולבה מלי חדו אדה מלה רבה יתגלג ] נבי [ ה דלנן א [ וקר ] בהדה מל [ תה ] תניאנ [ תה ] ויצרנה [ ו כאי ] ] עי [ נו ] ע [ יני ] יה [ וה אלהיך ] בה [ משרואה ] עד [ עקבה ] עינ [ יכון ] חזי [ ן ית כל דעבד יהוה מן עובדים רברבים וכן עבד ליהושע תבר מלכים קבלה ביכלתה ודזדמנו לבעל פעור קטל סגודיה ומן סגד לון אה אלה רחמן ולית חורי לבר מנה אה נביא צדיק לא קם ולא יקום כותה לעלם מכל בניו דאדם','(1) He strengthened him in the desert land (Deut. 32:10) – he who walks 
trusting Him, mishap has no power over him. (2) He guarded him as the pupil of 
His eye (ibid.). The eyes of the Lord your God are always upon it, from the 
beginning […] to the end […] (Deut. 11:12). (3) Like an eagle which rouses his 
nestlings (Deut. 32:11). And you shall lie down, and none shall make you afraid 
(Lev. 26:6). He lay down in that place and he dreamed (Gen. 28:11–12). (4) Gliding 
down to his young (Deut. 32:11) – for prosperity. I have seen the plight of My 
people (Exod. 3:7). (5) He spread His wings and took him (Deut. 32:11) – in great-
ness. Then Moses caused Israel to set out from the Sea of Reeds (Exod. 15:22). 
(6) He set him atop the highlands (Deut. 32:13). Behold, I send My angel before you 
(SP Exod. 23:20). (7) He fed him with the yield of the ﬁeld (Deut. 32:13). When the 
Lord your God brings you into the land that He swore to your fathers (Deut. 6:10). 
(8) He fed him honey from the crag (Deut: 32:13). And you shall eat and be full, and 
you shall bless the Lord your God (Deut. 8:10). (9) And oil out of the ﬂinty rock 
(Deut. 32:13) I will rain down (Exod. 16:4). The taste of it was like the taste of 
marrow of oil (Num. 11:8). (10) Curds from the herd, and milk from the ﬂock (Deut. 
32:14). You may slaughter any of the cattle or sheep (Deut. 12:21). Let us remember 
the great prophet Moses as he repeats those words by which he gloriﬁed Israel in 
this Great Song: He strengthened him in the desert land (Deut. 32:10) – unless 
they had a leader, they would have strayed. Lest the wild beast multiply too 
numerous for you (Deut. 7:22) – if you are good, they will submit to you. He 
brought them to Adam to see (Gen. 2:19) – when there was no rebellion there, 
they all submitted to him. You will be withheld and isolated whoever ﬁnds me will 
slay me (Gen. 4:13–14) – this corresponded to the evil deed. He who committed a 
sin was repaid by punishment. When Israel was walking before God, they dwelt 
in safety (Deut. 33:28) and their hearts were full of joy. This is a great word; 
praised be God who honored us with it. The second statement: He guarded him 
as the pupil of His eye (Deut. 32:10). The eyes of the Lord your God are always 
upon it, from the beginning […] to the end […] (Deut. 11:12). Your eyes have seen all 
the great deeds of the Lord which he did (paraphrase of Deut. 11:7 etc.). Thus He 
did to Joshua: He broke kings before him with his might. And those who gath-
ered at Baʿal Peʿor: He slew the idols and those who worshipped them. Behold a 
merciful God, and there is no other except Him. Behold a righteous prophet, like 
whom none has arisen and will never arise from out of all the sons of Adam.','(א) "יְסֹבְבֶנְהוּ בְּאֶרֶץ מִדְבָּר" (דברים לב,י) – מי שהולך בוטח בו, אין לאסון שום שליטה עליו. (ב) "יִצְּרֶנְהוּ כְּאִישׁוֹן עֵינוֹ" (שם). "עֵינֵי ה'' אֱלֹהֶיךָ בָּהּ תָּמִיד מֵרֵשִׁית [...] עַד אַחֲרִית [...]" (דברים יא,יב). (ג) "כְּנֶשֶׁר יָעִיר קִנּוֹ" (דברים לב,יא). "וְשָׁכַבְתָּ וְאֵין מַחֲרִיד" (ויקרא כו,ו). "וַיִּשְׁכַּב בַּמָּקוֹם הַהוּא וַיַּחֲלֹם" (בראשית כח,יא–יב). (ד) "יְרַחֵף עַל גּוֹזָלָיו" (דברים לב,יא) – לשגשוג. "רָאֹה רָאִיתִי אֶת עֳנִי עַמִּי" (שמות ג,ז). (ה) "יִפְרֹשׂ כְּנָפָיו יִקָּחֵהוּ" (דברים לב,יא) – בגדולה. "וַיַּסַּע מֹשֶׁה אֶת יִשְׂרָאֵל מִיַּם סוּף" (שמות טו,כב). (ו) "יַרְכִּיבֵהוּ עַל בָּמֳתֵי אָרֶץ" (דברים לב,יג). "הִנֵּה אָנֹכִי שֹׁלֵחַ מַלְאָךְ לְפָנֶיךָ" (שמות כג,כ נוסח שומרוני). (ז) "וַיֹּאכַל תְּנוּבֹת שָׂדָי" (דברים לב,יג). "כִּי יְבִיאֲךָ ה'' אֱלֹהֶיךָ אֶל הָאָרֶץ אֲשֶׁר נִשְׁבַּע לַאֲבֹתֶיךָ" (דברים ו,י). (ח) "וַיֵּינִקֵהוּ דְבַשׁ מִסֶּלַע" (דברים לב,יג). "וְאָכַלְתָּ וְשָׂבָעְתָּ וּבֵרַכְתָּ אֶת ה'' אֱלֹהֶיךָ" (דברים ח,י). (ט) "וְשֶׁמֶן מֵחַלְמִישׁ צוּר" (דברים לב,יג) – "הִנְנִי מַמְטִיר" (שמות טז,ד). "וְטַעְמוֹ כְּטַעַם לְשַׁד הַשָּׁמֶן" (במדבר יא,ח). (י) "חֶמְאַת בָּקָר וַחֲלֵב צֹאן" (דברים לב,יד). "וְזָבַחְתָּ מִבְּקָרְךָ וּמִצֹּאנְךָ" (דברים יב,כא). נזכיר את הנביא הגדול משה כשהוא חוזר על הדברים שבהם פאר את ישראל בשירה הגדולה הזו: "יְסֹבְבֶנְהוּ בְּאֶרֶץ מִדְבָּר" (דברים לב,י) – לולא היה להם מנהיג, היו תועים. "פֶּן יִרְבֶּה עָלֶיךָ הַחַיָּה" (דברים ז,כב) – אם תהיו טובים, יכנעו לכם. "וַיָּבֵא אֶל הָאָדָם לִרְאוֹת" (בראשית ב,יט) – כאשר לא הייתה שם מרי, כולם נכנעו לו. "גָּרַשְׁתָּ אֹתִי [...] כָּל מֹצְאִי יַהַרְגֵנִי" (בראשית ד,יג–יד) – זה תאם את המעשה הרע. מי שחטא, שילם בעונש. כשישראל הלך לפני האלוהים, ישב לבטח (דברים לג,כח) ולבם היה מלא שמחה. זהו דבר גדול; ברוך האל שכבדנו בו. האמירה השנייה: "יִצְּרֶנְהוּ כְּאִישׁוֹן עֵינוֹ" (דברים לב,י). "עֵינֵי ה'' אֱלֹהֶיךָ בָּהּ תָּמִיד מֵרֵשִׁית [...] עַד אַחֲרִית [...]" (דברים יא,יב). "עֵינֵיכֶם הָרֹאֹת אֵת כָּל מַעֲשֵׂה ה'' הַגָּדֹל אֲשֶׁר עָשָׂה" (פרפרזה על דברים יא,ז ועוד). כך עשה ליהושע: שבר מלכים לפניו בכוחו. ואלה שנאספו בבעל פעור: הרג את האלילים ואת עובדיהם. הנה אל רחום, ואין אחר מלבדו. הנה נביא צדיק, שכמוהו לא קם ולא יקום לעולם מבין כל בני האדם.');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (200,'IV','85','מימר על שירתה רבתה',4000851,'עמו נביה רבה משה איך פרט עסרה דינים עתידים לחיביה בדיל יתוכחון ברי יעקב ולא יפקון מן תחומי אלה ולא ילקון גרמון בתשניק יום נקם עפל וקרא קמי כל קהלה וכהלון שמעין ודחלין מן יתה מקרתה ואני אקניהם ואוזפון צער במלתה בלא עם יתלי יהוה עליך גוי מרחיק נקמה בעלמה מזזעה לכל מדעיה וכן והפיצך יה בכל העמים אם לא תשמר לעשות וכל ונשארתם מתי מספר בגו ונוגפתם לפני איביכם וילה בישה במה דעבד כד יקום לקדם מרה וישאלה מה יהי אגבה ובתר כל הדא גזוה עתיד הן לטב והן לביש','See the great prophet Moses, how he outlined ten judgements prepared 
for the guilty, so that the sons of Jacob may be reproved, and they may not 
depart from the domain of God and may not smite themselves with the aﬄiction 
of the Day of Requital. He began and read before the whole congregation, while 
all of them listen and fear from that reading: I will stir them to jealousy (Deut. 
32:21). He added to them distress with the word no folk (ibid.). The Lord will bring 
a nation against you from afar (Deut. 28:49) – a vengeance on the world, shatter-
ing all minds. And also: The Lord will scatter you among all the peoples (Deut. 
28:64) if you do not observe to do (Deut. 28:58), and so on. Only a scant few of you 
shall be lef among the peoples (Deut. 4:27); and you shall be smitten before your 
enemies (Lev. 26:17). Woe to the evil one for what he has done, when he will 
stand before his Master and He will ask him. What will be his reply, and afer all 
this, (while) his punishment is prepared, will it be for good or for ill?','ראו את הנביא הגדול משה, כיצד תיאר עשרה משפטים מוכנים לחוטאים, כדי שבני יעקב יוכחו ולא יסורו ממשמעת האלוהים ולא יכו את עצמם בנגע יום הגמול. פתח וקרא לפני כל הקהל, וכולם שומעים ויֵראים מאותו מקרא: אֲנִי אַקְנִיאֵם (דברים לב,כא). הוסיף להם צרה בדברו לֹא עָם (שם). יִשָּׂא יְהוָה עָלֶיךָ גּוֹי מֵרָחוֹק (דברים כח,מט) – נקמה על העולם, משברת את כל הדעות. וכן: וֶהֱפִיצְךָ יְהוָה בְּכָל הָעַמִּים (דברים כח,סד) אם לא תִשְׁמֹר לַעֲשׂוֹת (דברים כח,נח), וכן הלאה. וְנִשְׁאַרְתֶּם בִּמְתֵי מְעָט בַּגּוֹיִם (דברים ד,כז); וְנִגַּפְתֶּם לִפְנֵי אֹיְבֵיכֶם (ויקרא כו,יז). אוי לרשע על מה שעשה, כאשר יעמוד לפני אדונו ויישאל. מה תהיה תשובתו, ולאחר כל זאת, כשעונשו מוכן, האם יהיה לטוב או לרע?');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (201,'IV','43','מימר על שירתה רבתה',4000431,'האן הך משה ומן מדמי למשה עבדה דאלה ומהימנה דביתה דדער ביני קעימיה לגו משכן כסיאתה ויקרוה כהלון במדורה עמון המאר מן מארון והוה מלוא בכן והקרב ביניון והוה כהן קדיש תרתי כנשהן בדילה אזדמנו כוארתת עלמה מנה כד קרא כד שמע קל מרה וקל נביה רבה משה עמה תמחו כסיאתה והבלדו כל גליאתה נביה רבה משה צעם חדו בה קעימים ודחלו מנה מאתים וכד קבל לוחיה קדמאיה רבו מלאכיה והוא סבלין על אדיו וכד חדדון מבתר עובד חובה רבה הנהרת לה ברקיה ולבש קרן אורה ובהדה צומה הכלל בשבעה חדה לבה בון אקבל שדלה ואשתיר קהלה ואקבלת תתובתה ואתחזי לה קשטה וקרא עסרתי רחמיה והבסר באהרן הן מיתוביתה ממנה מכן צעם יומה תנינה ואצים כל ישראל בה כל דרי עלמה','Where is there the like of Moses and who resembles Moses the servant of 
God, the faithful of His House, who dwelt among the immortals in the Sanctuary 
of the Concealed? They all honored him when he stayed with them. He was 
supplied from their provisions, and was qualiﬁed to that. He drew near to them. 
He was a holy priest. Two assemblies were gathered because of him, and the 
world trembled when he proclaimed, when (the world) heard the voice of his 
Master and the voice of the great prophet Moses too. The Concealed were asto-
nished, and all the Overt were dismayed. The great prophet Moses fasted; the 
immortals rejoiced for him; the mortals were afraid of him. When he received the 
ﬁrst tablets the angels praised, while he carried them in his hands. When he got 
the new ones afer the deed of the great guilt, the lightning ﬂashed at him, and 
he wore the “ray of light”. In that fast he was crowned sevenfold: (1) His heart 
rejoiced in them. (2) He received what he desired. (3) The congregation survived. 
(4) Their repentance was accepted. (5) The True One appeared to him. (6) He pro-
claimed the ten mercies. (7) He informed Aaron that his status was perpetual. 
Therefore he fasted a second day and made all Israel fast in it throughout all the 
generations of the world.','היכן ימצא דוגמתו של משה, ומי דומה למשה עבד האלוהים, הנאמן לביתו, אשר שכן בין האלמותיים במקדש הנסתר? כולם כיבדוהו בשבתו עמהם. הוא ניזון מהספקתם והיה ראוי לכך. הוא נגש אליהם. הוא היה כהן קדוש. שתי קהילות נתכנסו בגללו, והעולם רעד כאשר הכריז, כאשר שמע את קול אדונו ואת קולו של הנביא הגדול משה אף הוא. הנסתרים נדהמו, וכל הגלויים נבהלו. הנביא הגדול משה צם; האלמותיים שמחו בשבילו; בני התמותה יראו ממנו. כאשר קיבל את הלוחות הראשונים שיבחו המלאכים, בעוד שנשאם בידיו. כאשר קיבל את החדשים לאחר מעשה האשמה הגדולה, הבקיע בו הברק ולבש את "קרן האור". בצום ההוא הוכתר שבע פעמים: (1) ליבו שמח בהם. (2) קיבל את אשר ביקש. (3) הקהל ניצל. (4) תשובתם התקבלה. (5) האמת נגלתה אליו. (6) הכריז את עשרת הרחמים. (7) הודיע לאהרן כי מעמדו קבוע לעולם. לפיכך צם יום שני ועשה את כל ישראל לצום בו לכל דורות העולם.');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (202,'IV','22','מימר על שירתה רבתה',4000221,'כי כל דרכיו משפט יתרבי אמורה דחכם דריה שבילה דאלה עמו מלת משפט ואתחידו בה עשה משפט יתום ואלמנה והיה כי יצעק אלי ושמעתי כי חנון אנכי וגר לא תונו עשה גדלה משפט לא תכיר פנים עשה גדלה משפט לא תעמד על דם רעך עשה גדלה משפט לא תסני ית אחוך עשה גדלה משפט לא תשתבע בשמי לשקר עשה גדלה משפט לא תהך רכיל בעמך עשה גדלה משפט לא תטמי גזרתה עשה גדלה משפט לא תרבי בר זנו עשה גדלה משפט לא תתחמד מד לית לך עשה גדלה מש לא תחלל יום שבתה עשה גדלה משפט לא תגנב לב אחוך עשה גדלה משפט קין כד גנב לב אחוה ונסבה וקטלה עבד גדלה משפט הן יקום בגוך נביא יהי גנב לבך לא תשמע לה אל גדול עשה משפט כי יסיתך אח לא תקבל מנה אל גדול עשה משפט והן אזל לבך ואצטמד עמה כי אל גדול עשה המשפט כי כל דרכיו משפט יתגלג נביה רבה משה דחכמן חכמה כהלה חיים וברכאן ירום מדעה דמשה } א { דגלה במקרתה רזה דבראשית ויום נקם וחכם דריה במד לה קרא כי בשרוה וכי בממציעה ואתעבדת ריש בכל שיראתה ובכל מקרתה ובכל צלותה בראשית שרוי ויום נקם חסול אה תריה לא יבטלון לעלם מד אלין לא יכל למקדמה עליהון כן אלין מליה לית מקדמה עליהון דו חכמן במדע שלם מן שרוי כי חסול משפט הודע עורי דמרן ממן מבתר אלין תריה לחודה דו מקמי בראשית ובתר יום נקם בהכדה לגרמה לא יתר ולא פעת','For all His ways are justice (Deut. 32:4). Exalted be the one who taught 
the generations the way of God. See the word “justice” and cling to it. He exe-
cutes justice for the fatherless and the widow (Deut. 10:18); and if he cries to me, I 
will hear, for I am compassionate (Exod. 22:26); you shall not wrong a stranger 
(Exod. 22:20). His Greatness executes justice: you shall show no partiality (Deut. 
16:19). His Greatness executes justice: you shall not stand forth against the blood 
of your fellow (Lev. 19:16). His Greatness executes justice: you shall not hate your 
kinsfolk (Lev. 19:17). His Greatness executes justice: you shall not swear by my 
name falsely (Lev. 19:12). His Greatness executes justice: you shall not slander 
among your people (Lev. 19:16). His Greatness executes justice: do not deﬁle the 
circumcision. His Greatness executes justice: do not bring up a son of harlotry. 
His Greatness executes justice: do not lust afer what is not yours. His Greatness 
executes justice: do not profane the day of Sabbath. His Greatness executes 
justice: do not deceive your fellow. His Greatness executes justice: when Cain 
deceived his brother and took him (to the ﬁeld – SP Gen. 4:8), he slew him. His 
Greatness executes justice: if there appears among you a prophet who dissuades 
you, do not listen to him (Deut. 13:2–4). A great God executes justice: if your 
brother […] entices you (Deut. 13:7), do not listen to him. A great God executes 
justice: if your heart deviates and joined him, indeed, a great God will judge you, 
for all His ways are justice (Deut. 32:4). Praised be the great prophet Moses, who 
taught us a teaching wholly of life and blessings. Exalted be the mind of Moses 
who revealed in his reading the mystery of בראשיתand יום נקםand taught the 
generations what he read: כיat the beginning and כיin the middle. It was made a 
foundation of all songs and all prayer and all reading. בראשיתis the beginning 
and יום נקםis the end. The two will never be abolished. Just as for these, nothing 
can precede them, likewise, these words have no precedent. For he taught (them) 
to us with a perfect mind. At the beginning ,כיthe end is .משפטHe also taught us 
that our Master endures afer these two by Himself: He was before בראשיתand 
will be afer ,יום נקםstill by Himself, no more and no less.','כי כל דרכיו משפט (דברים לב,ד). ברוך מי שלימד את הדורות את דרך האלוהים. ראו את המילה "משפט" ודבקו בה. עושה משפט יתום ואלמנה (דברים י,יח); וכי יצעק אלי ושמעתי כי חנון אני (שמות כב,כו); ולא תונה גר (שמות כב,כ). גדולתו עושה משפט: לא תכיר פנים (דברים טז,יט). גדולתו עושה משפט: לא תעמוד על דם רעך (ויקרא יט,טז). גדולתו עושה משפט: לא תשנא את אחיך (ויקרא יט,יז). גדולתו עושה משפט: לא תישבעו בשמי לשקר (ויקרא יט,יב). גדולתו עושה משפט: לא תלך רכיל בעמך (ויקרא יט,טז). גדולתו עושה משפט: אל תחלל את המילה. גדולתו עושה משפט: אל תגדל בן זנות. גדולתו עושה משפט: אל תחמוד מה שאינו שלך. גדולתו עושה משפט: אל תחלל את יום השבת. גדולתו עושה משפט: אל תרמה את רעך. גדולתו עושה משפט: כשרימה קין את אחיו ולקחו (אל השדה – שמות ד,ח של הנוסח השומרוני), הרגו. גדולתו עושה משפט: אם יקום בקרבך נביא המסיתך, אל תשמע לו (דברים יג,ב–ד). אל גדול עושה משפט: אם אחיך [...] יסיתך (דברים יג,ז), אל תשמע לו. אל גדול עושה משפט: אם לבך יסור ויצטרף אליו, אכן אל גדול ידין אותך, כי כל דרכיו משפט (דברים לב,ד). הלל לנביא הגדול משה, שלימד אותנו תורה שכולה חיים וברכות. ברוך תבונת משה שגילה בקריאתו את סוד בראשית ויום נקם ולימד את הדורות את שקרא: כי בראשית וכי באמצע. נעשה יסוד לכל שירות ולכל תפילה ולכל קריאה. בראשית הוא הראשית ויום נקם הוא הסוף. שניהם לא יבוטלו לעולם. כשם שלאלה אין דבר שקודם להם, כך לדברים אלה אין קדימה. שכן לימד אותנו בתבונה שלמה. בתחילה כי, הסוף הוא משפט. לימד אותנו גם שאדוננו קיים אחרי שניהם בפני עצמו: הוא היה לפני בראשית ויהיה אחרי יום נקם, עדיין בפני עצמו, לא יותר ולא פחות.');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (203,'IV','69','מימר על שירתה רבתה',4000691,'מלתה ] ת [ לתיתה כנשר יעיר קנו ושכבתם ואין מחריד מן אדכר שם אלה מקדם דידמך לית אנש מבלד לה כד אתא יעקב עריק מן אחו לא אבלד כד פגע אתר קדש , דמלאכיה בה שרין ודכר שם מרה דמך ולא בלדנה אנש חכם הן אהן אתרה מפלט למן לידה ימלט בנשפה דמך תמן יעקב בלב אדכי וחזה חלם כלה פוגגו ועבדו לי משכן ואדור בגוכון אחס עליכון ואברך יתכון ושכנתי בתוך בני ישראל ולא יכל דבב ידור עמון ולא ישלט בון ויחכמון דאנה יהוה אלהיון אה אלה רחמן ולית חורי לבר מנה נעיר ומעיני לרחמיו אה נביא צדיק שמע קל מרה וקבל חיים מוחים לכל ישראל','The third statement: Like an eagle who rouses his nestlings (Deut. 32:11). 
And you shall lie down, and none shall make you afraid (Lev. 26:6). He who men-
tions the name of God before he lies down, nobody frightens him. When Jacob 
came, ﬂeeing from his brother, he was not frightened. When he arrived at a holy 
place, where the angels abide, and mentioned the name of his Master, and no-
body frightened him, He knew that this place is a refuge to the one who ﬂees to it 
alone. Jacob lay down there with a pure heart and saw a dream, wholly of relief. 
Make Me a sanctuary that I may dwell among you (SP Exod. 25:8) – I will show 
mercy to you and I will bless you. I will abide among the Israelites (Exod. 29:45), 
and no enemy will be able to dwell among them and prevail over them. And they 
will know that I am the Lord their God (Exod. 29:46). Behold, a merciful God, and 
there is no other except Him, remembers and protects His devotees. Behold, a 
righteous prophet obeyed his Master and received a life which gives life to all 
Israel.','האמירה השלישית: "כְּנֶשֶׁר יָעִיר קִנּוֹ" (דברים לב,יא). "וְשָׁכַבְתָּ וְאֵין מַחֲרִיד" (ויקרא כו,ו). מי שמזכיר את שם האלוהים לפני שהוא שוכב, אין מי שיבהיל אותו. כשבא יעקב, נס מפני אחיו, לא נבהל. כשהגיע למקום קדוש, שבו שוהים המלאכים, והזכיר את שם אדונו, ואיש לא הבהיל אותו, ידע כי מקום זה הוא מפלט למי שנס אליו לבדו. יעקב שכב שם בלב טהור וראה חלום, שכולו הקלה. "וְעָשׂוּ לִי מִקְדָּשׁ וְשָׁכַנְתִּי בְּתוֹכָם" (שמות כה,ח נוסח שומרוני) – ארחם עליכם ואברך אתכם. "וְשָׁכַנְתִּי בְּתוֹךְ בְּנֵי יִשְׂרָאֵל" (שמות כט,מה), ולא יוכל שום אויב לשכון בתוכם ולגבור עליהם. "וְיָדְעוּ כִּי אֲנִי ה'' אֱלֹהֵיהֶם" (שמות כט,מו). הנה אל רחום, ואין אחר מלבדו, זוכר ושומר את חסידיו. הנה נביא צדיק, שמע בקול אדונו וקיבל חיים המחיים את כל ישראל.');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (204,'IV','103','מימר על שירתה רבתה',4001031,'אזין ושמע ואקים בקשטה וזכי עניניך וכייון לך כי ידין יהוה עמה עם יהוה יעקב נוף וארש ריש ונוף מן אבהן ובנים מן נח ארשה ועד תהבה נופה הדה מלתה מפוררה בדיל שלמותה דארבת על כל אמתה מכן אמר ועל עבדיו יתנחם לא יקומו בחסרן ולא יסטערו בדין כי הלכו בשביל זכותה אנשמו ביום דינה מכל מגוי ואתרוחת נפשהתון בפני מלכותה ייתי בשלם פתוח דרוחה ואפס עצור ועזוב תמן תתחיל מלת קשטה ויניר עלמה למה בה ידור מה רבה שעתה דבה ישתמע קלה דאלה מתהלך לגו עלמה וכל בוראיה סדירין ורישיון מככין ולבביון מרקפין ועיניון צליבין ואבריון מזזעין מן פחד יומה דדינה ופם אלהותה ממלל ראו עתה כי אני אני הוא','Give ear and hear and maintain the truth, purify your mind, and 
indeed, (they will exist) for you: For the Lord will judge his people (Deut. 32:36) – 
the people of the Lord (Num. 11:29). Jacob is both treetop and root, origin and 
descent from fathers to sons. From Noah, the origin, to the Taheb, his descen-
dant. This statement brings to attention the perfection which was superior to all 
peoples. Therefore He said: And had compassion on His servants (Deut. 32:36). 
They will not be in poverty, nor will they be aﬄicted in judgement, for they 
walked in the way of righteousness. They will have relief in the Day of Judgement 
from all punishment; their souls will have comfort before the kingdom. Let him 
come in peace who opens up relief. And there is none remaining, bond or free 
(ibid.). Then the word of the truth will be enforced and will illumine the world 
(with) those who dwell in it. How great is the hour when God’s voice will be 
heard going forth in the world! All creatures will be arrayed with their heads 
lowered, their hearts trembling, their eyes burning, their limbs shaking from fear 
of the Day of Judgement. The mouth of the Divinity speaks: See now that I, I am 
He (v. 39).','הַאֲזִינוּ וְשִׁמְעוּ וְהַחֲזִיקוּ בָּאֱמֶת, טַהֲרוּ אֶת לְבַבְכֶם, וְאָכֵן יִהְיוּ לָכֶם: כִּי יָדִין יְהוָה עַמּוֹ (דברים לב,לו) – עַם יְהוָה (במדבר יא,כט). יַעֲקֹב הוּא גַּם צַמֶּרֶת וְגַם שֹׁרֶשׁ, מָקוֹר וְיֶרֶד מֵאָבוֹת לְבָנִים. מִנֹּחַ הַמָּקוֹר עַד הַתָּאֵב צֶאֱצָאוֹ. אִמְרָה זוֹ מַפְנָה אֶת הַדַּעַת אֶל הַשְּׁלֵמוּת אֲשֶׁר הָיְתָה עֶלְיוֹנָה עַל כָּל הָעַמִּים. לְפִיכָךְ אָמַר: וְעַל עֲבָדָיו יִתְנֶחָם (דברים לב,לו). לֹא יִהְיוּ בְּעֹנִי וְלֹא יִסְבְּלוּ בַּמִּשְׁפָּט, כִּי הָלְכוּ בְּדֶרֶךְ הַצֶּדֶק. יִהְיֶה לָהֶם רֶוַח בְּיוֹם הַדִּין מִכָּל עֹנֶשׁ; נַפְשׁוֹתֵיהֶם תִּמְצֶאנָה נַחַת לִפְנֵי הַמַּלְכוּת. יָבֹא בְּשָׁלוֹם הַפּוֹתֵחַ רֶוַח. וְאֵין עָצוּר וְאֵין עָזוּב (שם). אָז תִּתְבַּצֵּר מִלַּת הָאֱמֶת וְתָאִיר אֶת הָעוֹלָם עִם יוֹשְׁבֵיו. כַּמָּה גָּדוֹלָה הַשָּׁעָה שֶׁבָּהּ יֵישָׁמַע קוֹל אֱלֹהִים יוֹצֵא בָּעוֹלָם! כָּל הַבְּרִיּוֹת תַּעֲמֹדְנָה עֲרוּכוֹת כְּשֶׁרָאשֵׁיהֶן כְּפוּפִים, לְבָבוֹתֵיהֶן חֲרֵדִים, עֵינֵיהֶן בּוֹעֲרוֹת, אֵיבְרֵיהֶן רוֹעֲדִים מִפַּחַד יוֹם הַדִּין. פִּי הָאֱלֹהוּת אוֹמֵר: רְאוּ עַתָּה כִּי אֲנִי אֲנִי הוּא (פסוק לט).');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (205,'IV','108','מימר על שירתה רבתה',4001081,'אברהם כד אזדעק אמר הנני ונביה רבה משה אמר הנני רבותה למרן דאמר אני אני אוקר אברהם ומשה בעלמה ובעקבה וילה אנש דלית בה נעירו יחכם רבין תריה , הך הוא אברהם הוה ארש במה דעבד ומשה ארש במד לה הגלה איך אברהם לית ואיך משה לית יתודי אלה ממנה המורך לקלומה המחליף ולא מתחלף דיאמר וכל בוראיה מבלדין לגו זבן ולית שקחי אלא הוא אני אנ הוא אברהם ומשה אברהם ריש זכותה ומשה הו } ה {› ריש אנשמותה אני אני הוא הדה והדה אברהם קטל מלכים ו ‹ סנאים לקשטה ותבר צלמיהון בנצחן דזכו ונביה רבה משה אפל אלהין וקטל כל סגודיון מכן אמר אלה ואין אלהים עמדי וכלל כלה במימרה אני אמית ואחיי אני אמית כל אלהי נכר וכל נבי שקר וכל כתב פגול דאמר דו על שמי וליתו מדלי ואחיי כל טביה וכן ית כתבה דבידון דו מדלי ויעזר לדלי מפם גבורתי השתמע ובאצבעי הכתב מד אנה קעים ככן כתבי קעים עד לעלם','When Abraham was called, he said: Here am I (Gen. 22:11), and the 
great prophet Moses said: Here am I (Exod. 3:4). Greatness to our Lord, who said: 
I, I am He (Deut. 32:39). He honored Abraham and Moses in this world and in the 
world to come.] Woe to a man in whom there is no insight to know the majesty of 
both, how it is. Abraham was a fundament in what he did; Moses was a funda-
ment in what was revealed to him. There is none like Abraham and there is none 
like Moses. Thanks to the everlasting God who endures alone, who changes but 
is not changed, who commands and all the creatures are frightened. In the time 
(when) there is no existence except He – I, I am He. Abraham and Moses: Abra-
ham is the head of righteousness and Moses is the head of relief. I, I am He 
(refers) to this and this. Abraham slew kings who hated God and smashed their 
idols in a righteous ﬁght, and the great prophet Moses threw down gods and 
slew all their worshippers. Therefore God said: There are no gods beside me 
(ibid.), and included all in the statement: I kill and I make alive (ibid.). I shall kill 
every alien god and every false prophet and every impure writing by him who 
says, that it is in My name, while it is not Mine. And I shall give life to all the 
good ones, and also the scripture in their possession, and turns it back to My 
possession – from the mouth of My Divine Power it was heard and with My ﬁnger 
it was written. As I exist, so My Scripture will exist forever.','כַּאֲשֶׁר נִקְרָא אַבְרָהָם, אָמַר: הִנֵּנִי (בראשית כב,יא), וְהַנָּבִיא הַגָּדוֹל מֹשֶׁה אָמַר: הִנֵּנִי (שמות ג,ד). גְּדֻלָּה לַאדוֹנֵנוּ, שֶׁאָמַר: אֲנִי אֲנִי הוּא (דברים לב,לט). הוּא כִּבֵּד אֶת אַבְרָהָם וְאֶת מֹשֶׁה בָּעוֹלָם הַזֶּה וּבָעוֹלָם הַבָּא. אוֹי לָאָדָם שֶׁאֵין בּוֹ תְּבוּנָה לָדַעַת אֶת גְּדֻלַּת שְׁנֵיהֶם, כֵּיצַד הִיא. אַבְרָהָם הָיָה יְסוֹד בְּמַעֲשָׂיו; מֹשֶׁה הָיָה יְסוֹד בַּנִּגְלָה אֵלָיו. אֵין כְּאַבְרָהָם וְאֵין כְּמֹשֶׁה. הוֹדָיָה לָאֵל הָעוֹלָמִי הַמִּתְקַיֵּם לְבַדּוֹ, הַמִּשְׁתַּנֶּה אַךְ אֵינוֹ מִשְׁתַּנֶּה, הַמְצַוֶּה וְכָל הַבְּרוּאִים חֲרֵדִים. בָּעֵת שֶׁלֹּא הָיָה שׁוּם מָצוּי זוּלָתוֹ — אֲנִי אֲנִי הוּא. אַבְרָהָם וּמֹשֶׁה: אַבְרָהָם הוּא רֹאשׁ הַצֶּדֶק וּמֹשֶׁה הוּא רֹאשׁ הַיְשׁוּעָה. אֲנִי אֲנִי הוּא — מִתְיַחֵס לָזֶה וְלָזֶה. אַבְרָהָם הָרַג מְלָכִים שֶׁשָּׂנְאוּ אֶת הָאֱלֹהִים וְשִׁבֵּר אֶת פְּסִילֵיהֶם בְּמִלְחָמָה שֶׁל צֶדֶק, וְהַנָּבִיא הַגָּדוֹל מֹשֶׁה הִפִּיל אֱלִילִים וְהָרַג אֶת כָּל עוֹבְדֵיהֶם. לְפִיכָךְ אָמַר הָאֱלֹהִים: אֵין אֱלֹהִים עִמָּדִי (שם), וְכָלַל הַכֹּל בְּאוֹתוֹ הַדִּבּוּר: אָמִית וַאֲחַיֶּה (שם). אָמִית כָּל אֵל נֵכָר וְכָל נָבִיא שֶׁקֶר וְכָל כְּתָב טָמֵא שֶׁל מִי שֶׁאוֹמֵר כִּי הוּא בִּשְׁמִי, בְּעוֹד שֶׁאֵינוֹ שֶׁלִּי. וַאֲחַיֶּה אֶת כָּל הַטּוֹבִים, וְגַם אֶת הַכָּתוּב שֶׁבְּיָדָם, וְאָשִׁיב אוֹתוֹ לִרְשׁוּתִי — מִפִּי גְּבוּרָתִי נִשְׁמַע וּבְאֶצְבָּעִי נִכְתַּב. כְּשֵׁם שֶׁאֲנִי קַיָּם, כָּךְ כִּתְבִי יִתְקַיֵּם לְעוֹלָמִים.');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (206,'IV','27','מימר על שירתה רבתה',4000271,'יתחיל מדעה דמשה וירום כד שרי קרי ועזר דרש אמר אל ושרר אמונה וכלל תרתיה במלת ואין עול כן עזר ואמר צדיק אה מלה שלמה פניה מן בלם אדם אמרה כד הקטל הבל ואנחמה מרה ועזר ליד אתתה וכד לה אמר ואתחיל לבה בה והוה זכי קעם מנה שת וכד הזדכי נח הגדל ואתפצה ואתעבד אדם תניאן אה מלה רבה כהלה אצלחו בה ישראל מתברך עדן דיקימנה קשטה ארשינך בתרה תהך עמי שרואה ועמי חסולה כד אתעקב בה נח אתמלית ביות וכד נפקת מפם קשטה לא הוה בה יות וכד } וכד { חדדה משה וחיל מלכותה בה הפך יות לגוה התודע דהיא מרחיה כי עקרה צדק ובה אדין לישראל דקשטה בה הוקם ובה הכבד ישראל','Let Moses’ mind be eulogized and exalted. When he began proclaiming, 
he sought further to say God and strengthened (it with) of faithfulness and com-
pleted the two with the word(s) without injustice. Likewise he said further just – 
behold a perfect word, entirely without restriction. Adam said it when Abel was 
killed, and his Master comforted him, and he turned back to his wife, and when 
he said it, his heart was strengthened by it, and he was exempt. From him arose 
Seth. And when Noah was proclaimed just (Gen. 6:9; 7:1), he was elevated and 
relieved and became the second Adam. Behold a great word, wholly beneﬁcial. 
By it Israel is blessed, when they fulﬁll it. The True One commanded you, and 
you (must) follow it. See its beginning and see its end. When Noah was named 
by it (Gen. 6:9), it was (written) with a yod but when it issued from the mouth of 
the True One (Gen. 7:1), there was no yod in it. And when Moses renewed it (Deut. 
32:4) and emphasized the Kingdom with it, he put yod in it again. (Thus) it was 
made known that it is welcome, for its foundation is ,צדקand by it (God) judges 
Israel, for the truth is established in it and by it Israel was honored.','יהולל ויתרומם שכלו של משה. כאשר החל לקרוא, ביקש להוסיף ולומר אֵל וחיזק זאת ב אֱמוּנָה והשלים את השניים במילים בְּלִי עָוֶל. כמו כן אמר עוד צַדִּיק – הנה מילה שלמה, כולה ללא מגבלה. אדם אמר אותה כאשר נהרג הבל, ואדונו נחמו, ושב אל אשתו, וכאשר אמרה התחזק לבו בה, ונפטר. ממנו יצא שת. וכאשר הוכרז נח צַדִּיק (בראשית ו,ט; ז,א), הוא הוּרם ונוחם והפך לאדם השני. הנה מילה גדולה, כולה לטובה. על ידה ישראל מתברכים כאשר הם מקיימים אותה. האמיתי ציווה אותך ואתה חייב ללכת בה. ראה תחילתה וראה סופה. כאשר נקרא נח בשמה (בראשית ו,ט), היה בה יוד, אך כאשר יצאה מפי האמיתי (בראשית ז,א), לא היה בה יוד. וכאשר חידשה משה (דברים לב,ד) והדגיש עמה את המלכות, שב ושם בה יוד. ובכך הודע שהיא מקובלת, כי יסודה הוא צֶדֶק, ועל ידה הוא שופט את ישראל, כי האמת קבועה בה ועל ידה נתכבד ישראל.');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (207,'IV','4','מימר על שירתה רבתה',4000041,'ואמר בעקבה באזני למחכום אן ליתו מדין אלאן מימניה דמן ריש כריזתה אמר אלה למשה אספה לי שבעים חכמים שילה אכהן אתחילת בדיל דאתמר דממללה לכל קהלה עמי ממללה בשרואה הך הוא מדו קרי עסרתי מליה הות בזומנות אלה ומשה ושת מון דאלפים וכן אמר בדיל ישמע עמה בממללי עמך למודע רבינה בין כל קהל ישראל וכד חסל מן מקרת עסרתי מליה עזר וכל עמה שמע מהימניה אנון גבריה דאתבחרו ואנון שבעים גבר מסהבי עמה וכן אמר ואשוזב מן רוחה דעליך ואשוי עליון בדיל דאתמר לה ויתצבו שם עמך באגן זימונה לית אנש ממלל אלאן דמותה וכד רמת דרגיון אשוו ממלל עמון הוה ממללה לון ואנון ילפו וימללון לכל קהלה דישמעון ירום מדעה דנביה רבה משה במה דחכם וגלה לכל קהל ישראל','And he said at the end: in the ears (Deut. 31:30), to indicate that he warns 
only the faithful ones, for from the beginning of the proclamation God had said 
to Moses: Gather for me seventy […] elders (Num. 11:16). A question draws atten-
tion here, for it was said that the statement (was uttered) to the whole congre-
gation. See the previous statement of how is it. When He read the Ten Words, it 
was in the presence of God and Moses and six hundred thousand. And thus He 
said: that the people may hear when I speak with you (Exod. 19:9), to make known 
his greatness among all the congregation of Israel. And when He ﬁnished 
reading the Ten Words, He further (said): and all the people heard (SP Exod. 
20:18). Faithful are [the men who have been chosen – they are seventy men of the 
elders of the people (Num. 11:24). And thus He said: I will take some of the spirit 
which is upon you and put it upon them (Num. 11:17), for it was said to him: and 
let them take their stand there with you (Num. 11:16) in the Tent of Assembly. No 
man speaks except with his equal. And when their rank was elevated, (and) they 
become worthy to speak to them, the speech was (directed) to them, and they 
learned and spoke to the whole congregation, so that they hear. Exalted be the 
mind of the great prophet Moses for what he taught and revealed to the whole 
congregation of Israel.','ובסוף אמר: באוזני (דברים לא,ל), להורות שאינו מזהיר אלא את הנאמנים, שכן מראשית ההכרזה אמר האלוהים למשה: אספה לי שבעים [...] מזקני ישראל (במדבר יא,טז). שאלה מושכת כאן את תשומת הלב, שהרי נאמר שהדברים נאמרו אל כל הקהל. ראו את הדברים הקודמים כיצד הם. כאשר קרא את עשרת הדברים, היה זה בנוכחות האלוהים ומשה ושש מאות אלף. וכך אמר: למען ישמע העם בדברי עמך (שמות יט,ט), להודיע את גדולתו לכל קהל ישראל. וכאשר סיים לקרוא את עשרת הדברים, נוסף: וכל העם שמעו (שמות כ,יח בנוסח השומרוני). נאמנים הם [האנשים שנבחרו – הם שבעים איש מזקני העם (במדבר יא,כד). וכך אמר: ואצלתי מן הרוח אשר עליך ושמתי עליהם (במדבר יא,יז), שכן נאמר לו: והתיצבו שם עמך (במדבר יא,טז) באוהל מועד. אין איש מדבר אלא עם שווה לו. וכאשר נתעלתה מדרגתם, ונעשו ראויים לדבר אליהם, הופנתה אליהם הדיבור, והם למדו ודיברו אל כל הקהל כולו, למען ישמעו. תרומם דעתו של הנביא הגדול משה על מה שלימד וגילה לכל קהל ישראל.');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (208,'IV','17','מימר על שירתה רבתה',4000171,NULL,'And the two (other) elements, he began to call them and emphasized 
them, for they are treasures: the wind – a good oﬀshoot that carries a deed, like a 
good servant who carries on the service; and the ﬁre that takes part in all the ac-
tions, since it is a fundament of everything of the Creation. All of them are made 
from four elements, each one exists in its own kind. Water of four (kinds), dust 
of four (kinds), wind of four (kinds), ﬁre of four (kinds). See the foundations of 
the water and set your mind in the knowledge of the Book: it was divided into 
four branches. Purify your mind and see how they are: a sweet liquid and also its 
opposite, and a bitter liquid and also its opposite. And likewise the ﬁre, in a 
similar way. In the Sanctuary thus its foundations were set: Aaron was kindling 
it on the lampstand, and it was permanently on the altar. And the ﬁre made for 
incense on which it is said: coals of ﬁre […] before the Lord (Lev. 16:12). Therefore 
no alien ﬁre (Lev. 10:1) shall enter the Sanctuary. And when it was oﬀered, it pro-
duced an overthrow and in a moment it was extinguished. And the dust and the 
wind too were seen in the worship of the Sanctuary, and from there established.','ואת שני היסודות האחרים החל לקרוא אותם והדגישם, שכן הם אוצרות: הרוח – ענף טוב הנושא מעשה, כעבד טוב הנושא בשירות; והאש המשתתפת בכל הפעולות, שכן היא יסוד של כל הבריאה. כולם עשויים מארבעה יסודות, וכל אחד קיים במינו. מים בארבעה סוגים, עפר בארבעה סוגים, רוח בארבעה סוגים, אש בארבעה סוגים. ראה את יסודות המים ושים לבך בידיעת הספר: נחלק לארבעה ענפים. טהר דעתך וראה מהם: נוזל מתוק וכן הפכו, ונוזל מר וכן הפכו. וכן האש, באותו אופן. במקדש כך הוקמו יסודותיה: אהרן הדליקה על המנורה, ועל המזבח הייתה תמיד. ואש הקטורת שעליה נאמר: "גחלי אש [...] לפני ה''" (ויקרא טז,יב). לפיכך לא תיכנס "אש זרה" (ויקרא י,א) למקדש. וכאשר הוקרבה, גרמה לחורבן ורגע היא כבתה. וגם העפר והרוח נראו בעבודת המקדש, ומשם נוסדו.');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (209,'IV','50','מימר על שירתה רבתה',4000501,'יתרבי לעלם נביה רבה משה דגלה לן בתשבחתה מלתה דאמרה ברבו אלית הוא אבוך ומלוכך שרה במלת הלוא מלה גדילה כהלה בכל זבן ועדן שרה בה וחתם בא הודע ישראל בסוד רב ה לבראשית א ליום נקם ה ברת א חתמת וכן אמר כי ידין יהוה דרבה צורה ידין לה מכן אמר נביה רבה משה הדה מלתה תמן ארכנו כל שמוע » י « ה קדמיו ואמר תרתי מליה אבוך ומלוכך עבדה דכרן לישר בני בכורי ישראל דרש רתו מן מרון עליון כבד את אביך ואת אמך עורי פוררו } א { ן לקשטה וקנך אמרה בדיל ירום ישראל ויסב טוב מן מרה כל אנש דלה קניאן ירפרף עליו ויביע הן יגדל בכל זבן וכל דעמי לה יתאוי כן אלה מעיני ישראל כדו קעניה וישראל יגדל הן יטר מליו','Exalted forever be the great prophet Moses who revealed to us in his 
praise the word which he said in majesty: Is not He your Father and your owner? 
(Deut. 32:6) He started with the word – הלואa great word, all of it, at all times 
and periods. He began with הand ended with .אHe made known to Israel a great 
secret: הfor the Creation, אfor the Day of Vengeance; הcreated and אconcluded. 
So He said: For the Lord will judge (v. 36) – He who promoted the Form will judge 
it. Therefore, the great prophet Moses said this word. Then all who heard it 
prostrated themselves before him. And he said two words: Your father and your 
owner – he made (them) a remembrance for Israel. Israel is my ﬁrstborn son 
(Exod. 4:22) – he sought pity from their Master for them. Honor your father and 
your mother (Exod. 20:12) – he also awakened them to the True One. And your 
owner, he said it, that Israel might be exalted and receive good from their Master. 
Every man who has a possession protects it and seeks to increase it at any time, 
while everyone who sees it lusts for it – so God protects Israel, for He is the 
Owner, and Israel will grow, if they keep His commands.','יתעלה לעד הנביא הגדול משה אשר גילה לנו בשבחו את הדבר שאמר בהדרה: הלוא הוא אביך קנך (דברים לב,ו). פתח במילה – הלוא, מילה גדולה היא, כולה, בכל עת ובכל זמן. פתח בה'' וסיים באל"ף. הודיע לישראל סוד גדול: ה'' לבריאה, אל"ף ליום הנקמה; ה'' ברא ואל"ף סיים. לכן אמר: כי ידין ה'' (פסוק לו) – הוא אשר הרים את הצורה ידין אותה. לפיכך אמר הנביא הגדול משה את הדבר הזה. אז כרעו כל שומעיו לפניו. ואמר שתי מילות: אביך וקנך – עשה אותן זיכרון לישראל. בני בכורי ישראל (שמות ד,כב) – ביקש רחמים מאדונם עליהם. כבד את אביך ואת אמך (שמות כ,יב) – גם העיר אותם אל האמיתי. וקנך, אמרה, למען יתעלה ישראל ויקבל טוב מאדונו. כל איש שיש לו קניין משמרו ומבקש להרבות אותו בכל עת, ואילו כל הרואה אותו חומד אותו – כך שומר אלוהים את ישראל, כי הוא הקונה, וישראל יגדל אם ישמור את מצוותיו.');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (210,'IV','102','מימר על שירתה רבתה',4001021,'קדיש הוא נביה דאקדש בידה דאלה ואתגלה על אדה גונין יקירין עד מותר הך משה לא קעם ולא יקום לעלם נביא הסתקף על כל מינה דאדם ואמטה עד אזדמן במלאכיה הך דאמיר לה ואזדמן לך אהן כמשה דדרס אשתה אהן כמשה דקרע שגביה אהן כמשה דנגש לערפלה אהן כמשה דאמר לה מרה ואת אכה קום עמי אהן נביא כמשה מללה אלה פה אל פה האן נביא כמשה צעם ארבעים יום וארבע לילה לא אכל ולא שתה ונחת סביל תרי לוחי אבנים כתיבין באצבע אלהים ואמר עורי מלים עורנין כהלון בסרנה לעבודי טבהתה ייתי בשלם תהבה דימלך אתרי שלמיה ויגלי קשטה','Holy is the prophet who was sanctiﬁed by God, and through him 
exceedingly glorious things were revealed. No prophet like Moses has arisen and 
will never arise. He was exalted above the whole human race and he advanced 
until he was gathered with the angels, as was said to him: I will meet with you 
(Exod. 25:22). Where is there anyone like Moses who trod the ﬁre? Where is there 
anyone like Moses who ripped the veils? Where is there anyone like Moses who 
approached the thickness? Where is there anyone like Moses to whom his Lord 
said: Stand by me now (Deut. 5:28). Where is there anyone like Moses whom God 
addressed mouth to mouth? (Num. 12:8) Where is there anyone like Moses who 
fasted forty days and forty nights; he neither ate nor drank? (Exod. 34:28) He 
descended carrying two stone tablets inscribed by the ﬁnger of God. He also said 
other words, all of them comprising tidings for the doers of good. Let the Taheb 
come in peace to possess the places of the perfect ones and to reveal the truth.','קָדוֹשׁ הוּא הַנָּבִיא אֲשֶׁר קִדְּשׁוֹ אֱלֹהִים, וְעַל יָדוֹ נִגְלוּ דְּבָרִים נִשְׂגָּבִים עַד מְאֹד. לֹא קָם נָבִיא כְּמֹשֶׁה וְלֹא יָקוּם לְעוֹלָם. הוּא נִתְעַלָּה עַל כָּל הַמִּין הָאֱנוֹשִׁי וְהִתְקַדֵּם עַד אֲשֶׁר נֶאֱסַף אֶל הַמַּלְאָכִים, כַּאֲשֶׁר נֶאֱמַר לוֹ: וְנוֹעַדְתִּי לְךָ שָׁם (שמות כה,כב). אַיֵּה כָּמֹשֶׁה אֲשֶׁר דָּרַךְ בָּאֵשׁ? אַיֵּה כָּמֹשֶׁה אֲשֶׁר קָרַע אֶת הַפְּרָגוֹד? אַיֵּה כָּמֹשֶׁה אֲשֶׁר נִגַּשׁ אֶל הָעֲרָפֶל? אַיֵּה כָּמֹשֶׁה אֲשֶׁר אָמַר לוֹ אֲדֹנָיו: עֲמֹד עִמָּדִי עַתָּה (דברים ה,כח)? אַיֵּה כָּמֹשֶׁה אֲשֶׁר דִּבֶּר אִתּוֹ אֱלֹהִים פֶּה אֶל פֶּה (במדבר יב,ח)? אַיֵּה כָּמֹשֶׁה אֲשֶׁר צָם אַרְבָּעִים יוֹם וְאַרְבָּעִים לַיְלָה, לֹא אָכַל וְלֹא שָׁתָה (שמות לד,כח)? יָרַד וְנָשָׂא שְׁנֵי לֻחוֹת אֲבָנִים כְּתוּבִים בְּאֶצְבַּע אֱלֹהִים. וְעוֹד אָמַר דְּבָרִים אֲחֵרִים, כֻּלָּם בְּשׂוֹרוֹת לְעוֹשֵׂי הַטּוֹב. יָבֹא הַתָּאֵב בְּשָׁלוֹם לְרָשֶׁת אֶת מְקוֹמוֹת הַתְּמִימִים וּלְגַלּוֹת אֶת הָאֱמֶת.');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (211,'IV','73','מימר על שירתה רבתה',4000731,'מלתה תמניאיתה דאמרה בזכו הך אתרבו בשלמותה יינקהו דבש מסלע שרי בתנוי טבהתה עליך ועל אבהתך מטט הוו במצרים מתלבטים והעק עליון בפ ] קו [ ד תרתי מ ] ילד [ התה ] כל בר [ עבראי ] תקטלון [ וכל ] בר [ ת תחון ] ולא [ עבדו ] דאה כ [ ד דחלו מן אלהה והתוחין ית ילידיה אזדעק בון כפורה וגער יתון ענותה עבריאתה חיאן אנון לית לון צורכה בנן כד תכשב אבטנתה בזבן מילד › ה ‹ תפק אל מדברה ותרחק וכד תילד תצפי ילידה הן הות ברתה תסבל יתה בעבה ותגוז והן הוה בר תפקינה לאלה לגו מדברה ותעזר אמרה לא אחזי מות ילידה ייתו מלאכים מדילה דאלה יסובון בה כמה דאמר יסובבנהו ויבננהו ויניקונה עד הן יגדל ויגמל ישכילנה בטובה וייתי לבית אבהתה וכן עבד עמון במדברה המטיר לון מזון מן שומיה טעמו כמעפים בסולך ובזבן כלשדה שמינה וכד הוה מינקה מתקפה ומיכלנה מן צנמה אזהרון נביה רבה משה באתרין סגי מן קשותה וקדלכון לא תקשון לא תאמץ ית לבך ורם לבבך ותתנשי ית יהוה אלהך','The eighth statement, which he said in righteousness, as (Israel) was 
exalted in perfection: He made him suck honey out of the rock (Deut. 32:13) – he 
started telling of the good deeds (made) to you and your ancestors since they 
were oppressed in Egypt, and (Pharaoh) aﬄicted them by commanding the two 
midwives: “Every Hebrew son you shall kill and every daughter you shall let 
live”, but they did not accomplish this for they feared God, and they let live the 
children. The unbeliever summoned them and rebuked them. They answered 
him: “They deliver (by themselves), they do not need us. When the pregnant is 
about to lie down at the time of her delivery, she goes out to the desert, farther 
away. And when she delivers, she looks at the child: if it is a daughter, she 
carries in her bosom and passes. If it was a boy, she takes him out to God in the 
desert, and goes back, saying: Let me not look on as the child dies (Gen. 21:16). 
(Then) angels of God come, surround him, as it is said: He engirded him, watched 
over him (Deut. 32:10), they made him suck (v. 13) [until he grows and is weaned. 
(God) teaches him the good and he comes to the house of his father.” Likewise 
He dealt with them (Israel) in the desert; He rained down food for them from 
heaven, whose taste is like (a cake) coated with honey (Exod. 16:31), and at the 
same time like fat marrow. And when He was making them suck from the rock 
and feed them from the stone, the great prophet Moses warned them in many 
places against obstinacy: Be not stubborn (Deut. 10:16), do not harden your heart 
(Deut. 15:7), lest your heart grow haughty and you forget the Lord your God (Deut. 
8:14).','האמירה השמינית, שאמרהּ בצדק, כשנתעלה ישראל בשלמות: וַיַּנִּקֵהוּ דְבַשׁ מִסֶּלַע (דברים לב,יג) – החל לספר את המעשים הטובים שנעשו לך ולאבותיך מאז שנגפו במצרים, כשהצר להם פרעה בציוותו לשתי המיילדות: "כל בן עברי תמיתו וכל בת תחיו", אך לא עשו כן כי יראו את האלהים, והחיו את הילדים. הכופר קרא להן ונזף בהן. ענו אותו: "הן יולדות מעצמן, ואינן צריכות לנו. כשהמעוברת עומדת ללדת בעת לידתה, יוצאת היא אל המדבר, הרחק. וכשיולדת, מביטה בילד: אם בת היא, נושאת אותה בחיקה ועוברת. ואם בן הוא, מוציאה אותו אל האל במדבר, וחוזרת ואומרת: אַל אֶרְאֶה בְּמוֹת הַיָּלֶד (בראשית כא,טז). ואז מלאכי אלהים באים ומקיפים אותו, כמו שנאמר: יְסֹבְבֶנְהוּ יְבוֹנְנֵהוּ (דברים לב,י), וַיַּנִּקֵהוּ (שם יג) עד שיגדל ויִגָּמַל. מלמדו הטוב ובא לבית אביו." כך עשה להם גם במדבר: המטיר להם מזון מן השמיים, שטעמו כִּצְפִיחִת בִּדְבָשׁ (שמות טז,לא), ובעת ובעונה אחת כמוח שמנים. וכשהניקם מן הסלע והאכילם מן האבן, הזהיר אותם הנביא הגדול משה בכמה מקומות מפני קשיות הלב: וּמַלְתֶּם אֵת עָרְלַת לְבַבְכֶם (דברים י,טז), לֹא תְאַמֵּץ אֶת לְבָבְךָ (דברים טו,ז), פֶּן יִרְבַּב לְבָבְךָ וְשָׁכַחְתָּ אֶת יְהוָה אֱלֹהֶיךָ (דברים ח,יד).');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (212,'IV','86','מימר על שירתה רבתה',4000861,'ומלתה תניאנתה בגוי נבל אכעיסם גוי עז פנים לא יחכם מנו באריה מעיל בכפרה למי יכפרו במרון דאה גזוי עתיד לקבל עובד מכעס מן אפל לגרמה יתלקי בכן קין וכוש ונמרוד ולמך לכן עבדו ואתגזו לפם עובדון קין כד קטל הוה כלי וטמי כוש אתלעט ולבשה קבלה והנמרוד כד אתגבר נש גברה ואשתנק במה דעבד והמחק דכרנה ולמך יזיף ומוזף אוי לאנש דיפל גרמה זמרי זנאה כדן עבד ואתקטל ולא › השתיר ‹ והמחק שמה נדחל מן אימת מרן ולא נבטל לשנינן מן דכרן שמה רבה אולי יאס עלינן וירחקן מן רגזה','The second statement: I will vex them with a nation of fools (Deut. 32:21), 
a ruthless nation (Deut. 28:50) which does not know its creator, which brings to 
darkness those who deny their Master. This is a repayment prepared for a pro-
voking act. He who debases himself will be struck by this. Cain and Cush and 
Nimrod and Lamech acted this way and were repaid according to their deed. 
Cain, when he killed, was withheld and isolated (Gen. 4:12). Cush was accursed 
and blackness covered him. And Nimrod, when he strengthened himself, his 
might weakened and he was aﬄicted because of what he did, and his remem-
brance was blotted out. And Lamech, much more so. Woe to the man who debas-
es himself. Zimri the fornicator acted in this way and was killed and did not 
survive and his name was blotted out. Let us fear the awe of our Master and not 
stop our tongues from mentioning His great name, perchance He will pity us and 
distance us from His anger.','האמירה השנייה: אֲכַעִיסֵם בְּגוֹי נָבָל (דברים לב,כא), גּוֹי עַז פָּנִים (דברים כח,נ) שאינו יודע את בוראו, המביא לחושך את כופרי אדונם. זוהי תגמול המוכן למעשה הגרוי. מי שמבזה את עצמו יוכה בזה. קין וכוש ונמרוד ולמך נהגו כך ונגמלו לפי מעשיהם. קין, כאשר הרג, נעצר וניתק (בראשית ד,יב). כוש נתקלל וחושך כיסהו. ונמרוד, כאשר התחזק, חלשה גבורתו ונענש בשל מה שעשה, וזכרו נמחה. ולמך, על אחת כמה וכמה. אוי לאיש המבזה את עצמו. זמרי הזונה נהג כך ונהרג ולא שרד ושמו נמחה. נירא את אימת אדוננו ולא נחדל לשונותינו מלהזכיר את שמו הגדול, שמא ירחם עלינו ויניסנו מחרונו.');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (213,'IV','15','מימר על שירתה רבתה',4000151,NULL,'Give glory to our God (SP Deut. 32:3) – a word proclaimed at the gather-
ings. What is said by ו ?והבוis made a gathering wholly of glory; therefore, the 
great prophet Moses made it an opening for the praises and the assemblies, and 
(of) בראשיתand (of) all that is like it. – וthe six days, and also the number of (the 
letters of) בראשיתand all that it includes. – הthe name of Him who stood and 
performed the covenant. – בthe two worlds; the ﬁrst world and the second 
world. And וbecame the corollary of all. It revealed that Here resembles There, 
and illuminated by the speech of wisdom in the word greatness ( )גדלthat magni-
ﬁes the words with holiness. Therefore, he said the word גדלwhen the founda-
tions of the Sabbath gathered before him. He magniﬁed its sanctity with גand ד
and added .לGlory to all of them – a perfection of holiness strengthened there. 
He added speech saying, “For the sake of perfection, .”לאלהינו#קצירן# Behold, a 
domain wholly of greatness is the area whose name is Praise. Happy is he who 
dwells in it; he will possess life in it. Happy is he who increases glory in it; it 
strengthens him with everything. See Moses: he dwelt in it and possessed glory. 
He was fed from it, and was magniﬁed by it alone, and by it he was elevated. 
Nobody will dwell in it the way he did, and no one will be supplied from it. O 
People, learn from him and observe the Book and from its wisdom grow and to 
its word(s) cling, for all its words are life and its teaching is wholly blessing. Woe 
to him who lacks it and deviates from its light and forgets its teaching and does 
not draw near to it. He destroys himself, and departs from the mercy of his 
Master and possesses His anger. He receives destruction, and God is clean of 
him, for He taught him but he did not learn, and called him, but he did not 
listen. Glory to our God, who forgives to sinners and shows (mercy) to them, so 
that they may repent. Exalted be the mind of Moses who revealed wisdom that 
elevates us. When he ﬁnished proclaiming כיand what it includes, he said בשם
 ,יהוהand what he made known by it. He proclaimed further: ,והבוas he turned 
back to בראשיתand all that it includes, and the holiness of the Sabbath, and 
what is gathered in it.','"הבו גדל לאלהינו" (דברים לב,ג לפי נוסח השומרונים) – דבר הנקרא בקהילות. מה נאמר ב"ו"? "והבו" עשוי לקהל שכולו כבוד; לפיכך עשה אותו הנביא הגדול משה פתיחה לתהילות ולקהילות, ול"בראשית" ולכל הדומה לה. "ו" – ששת הימים, וכן מספר אותיות "בראשית" וכל שהיא כוללת. "ה" – שמו של מי שעמד וכרת את הברית. "ב" – שני העולמות: העולם הראשון והעולם השני. וה"ו" נעשה המסקנה של הכל. גילה שכאן דומה לשם, והאיר בדבר החכמה במילת "גדל" שמגדילה את הדברים בקדושה. לפיכך אמר את המילה "גדל" כאשר נתכנסו לפניו יסודות השבת. גידל את קדושתה ב"ג" וב"ד" והוסיף "ל". כבוד לכולם – שלמות קדושה התחזקה שם. הוסיף דבריו ואמר: "לשם שלמות, לאלהינו". הנה, תחום שכולו גדולה הוא מרחב ששמו תהילה. אשרי מי שדר בו, יזכה בו לחיים. אשרי מי שמרבה בו כבוד, יתחזק בו בכל. ראה את משה: דר בו וזכה לכבוד. נזון ממנו ונתגדל בו לבדו, ובו נתעלה. איש לא ידור בו כמוהו, ואיש לא יינזון ממנו. עם, למד ממנו ושמור את הספר, ומחכמתו גדל ובדבריו דבק, כי כל דבריו חיים וכל תורתו ברכה. אוי למי שחסר אותה וסר מאורה ושוכח את תורתה ואינו קרב אליה. הוא מאבד את עצמו, ומתרחק מרחמי אדונו וזוכה בחרונו. מקבל הוא חורבן, והאלהים נקי ממנו, שהרי לימד אותו ולא למד, וקראו ולא שמע. כבוד לאלהינו, שסולח לחוטאים ומראה להם חסד, כדי שישובו. יתרומם שכלו של משה שגילה חכמה המרוממת אותנו. כאשר סיים לקרוא את "כי" ואת כל שהיא כוללת, אמר "בשם ה''" ומה שהודיע בה. המשיך וקרא: "והבו", כשחזר ל"בראשית" וכל שהיא כוללת, ולקדושת השבת ולמה שנאסף בה.');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (214,'IV','78','מימר על שירתה רבתה',4000781,'יתרבי נביה מהימנה משה איש האלהים דאלפן מה דאלפה אלה כותה לא קם ולא יקום לעלם נביה דאתימן בכסיהתה ובגליהתה ומרה אמר בדילה ולא קם עורי בישראל כותה מן יכל יחלפנה אלפן חייה ואזהר יתן מן מותה נשמע בקלה אולי נתוחי אקימן על קשטה וקיאמן עליו וחכמן שקרה והזהרן מנה נגד יתן בשביל פצותה והרחקן מן שביל אבדנה נשמע למליו דחייה לגון ונטרנון כי קוממותה בון מליו כסמן מאסי לכל מטאנין מן קבל מנה לא יקרבנ } ך {» ה « באש כי } כי { אני יהוה רפאך דאתה יומן פני מן תועבת מצראי לא תעבד כעובדיון ולא תגזר לון קיאם כי חיבין אנון ולא תסגד לאלהי » ו « ן ת } ע {» א « בד בפנותה דפנית בתרון יהוה הוא האלהים ואין עוד מלבדו ברוך שמו לעולם','Exalted be the faithful prophet Moses, the Man of God, who taught us 
what God taught him. Like him none has arisen and will never arise. The prophet 
who was entrusted with the Concealed and the Overt, and his Master said of 
him: There has not arisen (a prophet) since in Israel like him (Deut. 34:10). Who 
can succeed him? He taught us life and warned us of death. Let us listen to his 
voice, perchance we may have life. He taught us about the truth and covenanted 
us on it. He taught us about the lie and warned us against it. He led us in the way 
of salvation and removed us far from the way of destruction. Let us listen to his 
words, for there is life in them; let us keep them, for there is endurance in them. 
His words are like medicine which cures all the sick. The one who obeys him, 
sickness will not come near to him, for I am the Lord, your healer (Exod. 15:26). 
Indeed, today you are free of the abomination of the Egyptians, you shall not do 
their deeds, nor make covenant with them, for they are guilty men and you shall 
not worship their gods. You would perish in the Disfavor for turning aside to 
follow them. The Lord is God; there is no other besides him (Deut. 4:35). Blessed is 
His name for ever.','מרומם יהיה משה הנביא הנאמן, איש האלוהים, אשר לימד אותנו את מה שלימד אותו האל. כמוהו לא קם ולא יקום לעולם. הנביא שנאמן עליו הנסתר והנגלה, ואדונו אמר עליו: וְלֹא קָם נָבִיא עוֹד בְּיִשְׂרָאֵל כְּמֹשֶׁה (דברים לד,י). מי יכול לבוא אחריו? הוא לימד אותנו חיים והזהיר אותנו מפני המוות. נשמע לקולו, שמא יהיו לנו חיים. הוא לימד אותנו את האמת וכרת עמנו ברית עליה. הוא לימד אותנו את השקר והזהיר אותנו ממנו. הוא הדריך אותנו בדרך הישועה והרחיק אותנו מדרך האבדון. נשמע לדבריו, כי יש בהם חיים; נשמרם, כי יש בהם קיום. דבריו כתרופה המרפאת את כל החולים. מי שישמע לו, לא תקרב אליו מחלה, כי אֲנִי יְהוָה רֹפְאֶךָ (שמות טו,כו). אכן, היום אתם חופשיים מתועבת המצרים; לא תעשו את מעשיהם ולא תכרתו עמם ברית, כי הם אנשי אשמה ולא תעבדו את אלוהיהם. תאבדו בחרון על פנותכם ללכת אחריהם. יְהוָה הוּא הָאֱלֹהִים אֵין עוֹד מִלְבַדּוֹ (דברים ד,לה). ברוך שמו לעולם.');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (215,'IV','63','מימר על שירתה רבתה',4000631,'כעסוני דבר ביש סהדה בישה מימר אלה וצרפו יתי עסר זבנין עד הן ממעין עד הן יבתרני עד אמת לכנשתה בישתה דאה תלתה קבל תלתה אתמרת וכל חדה מנון יתרה על חברתה עד הן ממעין לנפוקי מצרים ישמעאל תמן ילפנון קשותה עד אמת יבתרני עמה אדן בניה דבתרו ואתילפו מן עשו עד אמת לכנשתה בישתה דאה צמות מכעס אתא לאכה נתן ראש ונעזר ליד מצרם כי על ימה אתפלגו אל תלתה פלגים וכל פלג אמר מימר ואגיבה נביה רבה משה קבל מימרה פרקנה קדמאה אמר נעזר אל מצרים ונשמש יתון הרי טב לן מן מותן במדברה אמר לון נביה רבה משה לא תעזרון למחזנון עד לעלם פרקנה תניאנה אמר נערק מן מצראי לגו מדברה אמר לון נביה רבה משה אתקוממו וחזו ית פצות יהוה דיעבד לוכון יומה פרקנה תליתה אמר נקום ונגיח עם מצראי אמר לון נביה רבה משה יה ילחם לכם ואתם תחרישון בכל זבן אלה מכך ברב טובה וחסדה וישראל מכעס ואלה אמר ואשיצנון ומשה אישה מצלי ואמר עזר מן תקוף רגזך ובדיל צלותה אתנחם על כל בישתה דמללת למעבדנה ישתבח רחמנה דרחמיו כסיהן על עבדיו ויטר יתון האן דאנון ש } ב {» ר « ין ויטר בדילון לבניון עד יחכמון ית חסדה וילכון בריחותה נהימן בה ובמשה נביה ונרכן קדמיו ונסיד ונימר לית אלה אלא אחד','They have provoked me (Deut. 32:21) – an evil conduct. A testimony of 
evil is God’s statement: They have tried me ten times (Num. 14:22); how long do 
you refuse? (Exod. 16:28) How long will this people spurn Me? (Num. 14:11) How 
long shall this wicked congregation […]? (Num. 14:27) Three (trials) against three 
have been said, and each one of them prevails upon the other. How long do you 
refuse?, (refers) to those coming out of Egypt. Ishmael was then teaching them 
stubbornness. How long will this people spurn me? – the children who spurned 
and learned from Esau. How long shall this wicked congregation […]? – an irritat-
ing gathering came in here. Let us choose a captain, and go back to Egypt (Num. 
14:4). Indeed, they divided at the sea into three divisions, and each division 
made a statement, and the great prophet replied to each statement. The ﬁrst 
division said: Let us head back to Egypt (Num. 14:4) and we will serve the 
Egyptians, for it is better for us to serve the Egyptians than to die in the wilderness 
(Exod. 14:12). The great prophet Moses said: You shall never see again (Exod. 
14:13). The second division said: Let us ﬂee from the Egyptians into the desert. 
The great prophet Moses said to them: Stand ﬁrm, and see the salvation of the 
Lord, which He will work for you today (ibid.). The third division said: Let us arise 
and ﬁght against the Egyptians. The great prophet Moses said to them: The Lord 
will ﬁght for you, and you have only to be still (Exod. 14:14). At any time God 
lowers His abundant goodness and grace, but Israel irritates. God says: That I 
may consume (Exod. 32:10), but Moses the Man prays and says: Turn from your 
ﬁerce wrath (Exod. 32:12). By reason of the prayer: renounce all the evil which 
you threatened to do. Praised be the Merciful One whose mercies protect His 
servants, and He guards them wherever they dwell and for their sake preserves 
their children, that they may know His grace, and walk to His will. Let us believe 
in Him and in Moses His prophet, and let us bow down before Him and testify, 
saying: “There is no god but One.”','הִכְעִיסוּנִי (דברים לב,כא) – הִתְנַהֲגוּת רָעָה. עֵדוּת לָרָעָה הִיא אֲמִירַת הָאֵל: וַיְנַסּוּ אֹתִי זֶה עֶשֶׂר פְּעָמִים (במדבר יד,כב); עַד אָנָה מֵאַנְתֶּם? (שמות טז,כח) עַד אָנָה יְנַאֲצֻנִי הָעָם הַזֶּה? (במדבר יד,יא) עַד מָתַי לָעֵדָה הָרָעָה הַזֹּאת? (במדבר יד,כז) שְׁלוֹשָׁה כְּנֶגֶד שְׁלוֹשָׁה נֶאֶמְרוּ, וְכָל אֶחָד מֵהֶם גּוֹבֵר עַל הַשֵּׁנִי. עַד אָנָה מֵאַנְתֶּם? – אֵלּוּ הַיּוֹצְאִים מִמִּצְרַיִם. יִשְׁמָעֵאל לִמֵּד אוֹתָם אָז עַקְשָׁנוּת. עַד אָנָה יְנַאֲצֻנִי הָעָם הַזֶּה? – הַבָּנִים שֶׁנִּאֲצוּ וְלָמְדוּ מֵעֵשָׂו. עַד מָתַי לָעֵדָה הָרָעָה הַזֹּאת? – קְהִלָּה מַרְגִּיזָה בָּאָה לְכָאן. נִתְּנָה רֹאשׁ וְנָשׁוּבָה מִצְרָיְמָה (במדבר יד,ד). אָמְנָם, נֶחְלְקוּ בַּיָּם לִשְׁלוֹשָׁה חֲלָקִים, וְכָל חֵלֶק אָמַר דָּבָר, וְהַנָּבִיא הַגָּדוֹל הֵשִׁיב לְכָל דָּבָר. הַחֵלֶק הָרִאשׁוֹן אָמַר: נִתְּנָה רֹאשׁ וְנָשׁוּבָה מִצְרָיְמָה (במדבר יד,ד) וְנַעֲבֹד אֶת הַמִּצְרִים, כִּי טוֹב לָנוּ עֲבֹד אֶת מִצְרַיִם מִמֻּתֵנוּ בַּמִּדְבָּר (שמות יד,יב). אָמַר לָהֶם משֶׁה הַנָּבִיא הַגָּדוֹל: לֹא תֹסִפוּ לִרְאֹתָם עוֹד (שמות יד,יג). הַחֵלֶק הַשֵּׁנִי אָמַר: נִבְרַח מִפְּנֵי הַמִּצְרִים אֶל הַמִּדְבָּר. אָמַר לָהֶם משֶׁה הַנָּבִיא הַגָּדוֹל: הִתְיַצְּבוּ וּרְאוּ אֶת יְשׁוּעַת ה'' אֲשֶׁר יַעֲשֶׂה לָכֶם הַיּוֹם (שם). הַחֵלֶק הַשְּׁלִישִׁי אָמַר: נָקוּמָה וְנִלָּחֲמָה בַּמִּצְרִים. אָמַר לָהֶם משֶׁה הַנָּבִיא הַגָּדוֹל: ה'' יִלָּחֵם לָכֶם וְאַתֶּם תַּחֲרִישׁוּן (שמות יד,יד). בְּכָל עֵת מַשְׁפִּיל הָאֵל אֶת טוּבוֹ הָרָב וְחַסְדּוֹ, אַךְ יִשְׂרָאֵל מַרְגִּיז. אוֹמֵר הָאֵל: וַאֲכַלֶּה אֹתָם (שמות לב,י), אַךְ משֶׁה הָאִישׁ מִתְפַּלֵּל וְאוֹמֵר: שׁוּב מֵחֲרוֹן אַפֶּךָ (שמות לב,יב). בִּזְכוּת הַתְּפִלָּה: הִנָּחֵם עַל הָרָעָה אֲשֶׁר דִּבַּרְתָּ לַעֲשׂוֹת לְעַמֶּךָ. בָּרוּךְ הָרַחֲמָן שֶׁרַחֲמָיו שׁוֹמְרִים עַל עֲבָדָיו, וְנוֹצְרָם בְּכָל מְקוֹם מוֹשָׁבָם, וּלְמַעֲנָם שׁוֹמֵר אֶת בְּנֵיהֶם, כְּדֵי שֶׁיֵּדְעוּ אֶת חַסְדּוֹ וְיֵלְכוּ בִּרְצוֹנוֹ. נַאֲמִין בּוֹ וּבְמשֶׁה נְבִיאוֹ, וְנִשְׁתַּחֲוֶה לְפָנָיו וְנָעִיד לֵאמֹר: "אֵין אֱלֹהִים כִּי אִם אֶחָד."');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (216,'IV','67','מימר על שירתה רבתה',4000671,'צפי תרין הזדוגו כחדה אחד עמר אתר ואחד עמר אתר יוסף עמר אתר אבוה ונסב ית דלה ודבנה לקנומה הוה לה נמי ומשה עבד משכן קדש משרוי לכבוד יהוה וכד חסלה שרה כבודה לגוה כמה דאמר וכבוד יה מלא ית משכנה והוה אתר מתרחי לקשטה עמי אלין טביה דגעזו והך יהב אלה אגרון והגדלון ומד בחרה אלה לא סטו מנה אהרן הכהן ואלעזר אתימן ופינחס קנא לאלהה עמי רבות אלין דשמשו למרון ולא הרפו מן עובד מרחי יהושע וכלב הסתמכו על קשטה וקנו קניאן כהלה אצלחו וכשרן מודאה לאלה המיטב למי היטבו ומרעי לרחמיו לאלף דור נקד פניו ארצה בכל עת ונשתעבד קדם גדלה ונהימן בה ובמשה נביה ובכתבה ונטר גזריו ופקודיו הא אלה רחמן אה } ן { נביא מהימן טב נעבד כל מד מרחי לון הא אלה רחמן אה נביא מהימן נטר למליון כיינן מתנטרים הא אלה רחמן אה נביא נאמן מן דהך בתרון ליתו טעי הא אלה רחמן אה נביא נאמן נ › ד ‹ בק בון ולא נביע לבר מנון אסתכלו עסרתי פנודתה דפנד אלה לישראל בון ורבהתון בכלה','See two who were coupled together. The one built a place and the other 
built a place. Joseph built the place of his father, and took what was his 
(father’s), and what he built for himself was his share. Moses made a holy Sanc-
tuary, abode to the Glory of the Lord, and when he ﬁnished it Glory dwelt in it, as 
it is said: and the glory of the Lord ﬁlled the Sanctuary (Exod. 40:34). It was a 
place pleasing to the True One. See these good ones who passed away, and how 
God gave them their reward and elevated them. From what God had chosen, they 
did not deviate. Aaron became a priest and Eleazar was appointed and Phinehas 
was zealous for God. See the greatness of these who served their Master, and did 
not cease from (doing) pleasing deeds. Joshua and Caleb associated themselves 
to the True One and acquired a possession fully of prosperity and success. 
Thanks to God who does good to these who acted properly and pleases his 
devotees for thousand generations. Let us bow down before Him at all times and 
submit ourselves before his greatness and believe in Him and in Moses His 
prophet and in his Book. Let us keep its precepts and commandments. Behold a 
merciful God, behold a faithful prophet; it is good (for) us to do all what is 
pleasing to them. Behold a merciful God, behold a faithful prophet; let us keep 
their words, indeed we will be guarded. Behold a merciful God, behold a faithful 
prophet; he who walks afer them does not stray. Behold a merciful God, behold 
a faithful prophet; let us cling to them and seek none beside them. Examine the 
ten statements that God stated to Israel and elevated them in every respect.','רְאוּ שְׁנַיִם שֶׁנִּזְדַּוְּגוּ יַחְדָּו. הָאֶחָד בָּנָה מָקוֹם וְהָאַחֵר בָּנָה מָקוֹם. יוֹסֵף בָּנָה אֶת בֵּית אָבִיו וְנָטַל אֶת אֲשֶׁר הָיָה לְאָבִיו, וּמַה שֶּׁבָּנָה לְעַצְמוֹ הָיָה חֶלְקוֹ. משֶׁה עָשָׂה מִקְדָּשׁ קָדוֹשׁ, מָעוֹן לִכְבוֹד ה'', וּכְשֶׁגָּמַר אוֹתוֹ שָׁרָה בוֹ הַשְּׁכִינָה, כַּאֲמוּר: וּכְבוֹד ה'' מָלֵא אֶת הַמִּשְׁכָּן (שמות מ,לד). הָיָה מָקוֹם רָצוּי לִפְנֵי הָאֱמֶת. רְאוּ אֶת הַטּוֹבִים הָאֵלֶּה שֶׁעָבְרוּ מִן הָעוֹלָם, וּכֵיצַד שִׁלֵּם לָהֶם הָאֵל אֶת שְׂכָרָם וְרוֹמְמָם. מִמַּה שֶּׁבָּחַר בּוֹ הָאֵל לֹא סָטוּ. אַהֲרֹן נַעֲשָׂה כֹּהֵן, וְאֶלְעָזָר נִתְמַנָּה, וּפִינְחָס קִנֵּא לֵאלֹהִים. רְאוּ גְּדֻלַּת אֵלּוּ שֶׁשֵּׁרְתוּ אֶת אֲדוֹנָם וְלֹא פָסְקוּ מִמַּעֲשִׂים רְצוּיִים. יְהוֹשֻׁעַ וְכָלֵב נִלְווּ אֶל הָאֱמֶת וְקָנוּ נַחֲלָה מְלֵאָה שׁוֹפַע וְהַצְלָחָה. תּוֹדָה לָאֵל הַמֵּטִיב לְאֵלֶּה שֶׁנָּהֲגוּ כָּרָאוּי וּמֵיטִיב לַחֲסִידָיו לְאֶלֶף דּוֹרוֹת. נִשְׁתַּחֲוֶה לְפָנָיו בְּכָל עֵת וְנִכָּנַע לִפְנֵי גְּדֻלָּתוֹ, וְנַאֲמִין בּוֹ וּבְמשֶׁה נְבִיאוֹ וּבְסִפְרוֹ. נִשְׁמֹר אֶת מִצְווֹתָיו וְחֻקּוֹתָיו. הִנֵּה אֵל רַחֲמָן, הִנֵּה נָבִיא נֶאֱמָן; טוֹב לָנוּ לַעֲשׂוֹת כָּל מַה שֶּׁרָצוּי לִפְנֵיהֶם. הִנֵּה אֵל רַחֲמָן, הִנֵּה נָבִיא נֶאֱמָן; נִשְׁמֹר אֶת דִּבְרֵיהֶם, אָכֵן נִשָּׁמֵר. הִנֵּה אֵל רַחֲמָן, הִנֵּה נָבִיא נֶאֱמָן; מִי שֶׁהוֹלֵךְ אַחֲרֵיהֶם לֹא יִתְעֶה. הִנֵּה אֵל רַחֲמָן, הִנֵּה נָבִיא נֶאֱמָן; נִדְבַּק בָּהֶם וְלֹא נְבַקֵּשׁ אַחֵר מִלְּבַדָּם. בְּחֹנוּ אֶת עֶשֶׂרֶת הַדְּבָרִים שֶׁאָמַר הָאֵל לְיִשְׂרָאֵל וְרוֹמְמָם בְּכָל דָּבָר.');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (217,'IV','20','מימר על שירתה רבתה',4000201,'אנשיו דדרה בכן אימנו וליתה מחכומה אתילפו מה רב אהן ממללה ופמה דמללה חנוך התהלך בריחות אלהה מבתר עובד קין וברה דברה ואזל כל עובדיון ביום נקם יקום קשטה וירבי חבריו במה דעבדו אברהם עמר פרדיס בה כל טביה ישענון דעליון אמיר ושמרו דרך יה משה נטע אהל הוו כל מבקשי יהוה לידה יזדמנו קעם ביום אדהנותה מפצי רחמים ומאבד דבבים יצחק רחט לגו הדה שבילה מרבי בנים יהונו מנה אלפים משה צעם ורבה צלותה בדיל אנשים דמה ד ] י [ תקבלון קשטה קעם מדין אנשים ישבקו כל חוביון וליד קשטה יעזרון','O people of the generation, believe in this and learn that knowledge. 
How great is this statement, and the mouth that stated it! Enoch walked at the 
will of God (Gen. 5:22) afer the deed of Cain and (of) the son of his son, and 
further on. On the Day of Requital the True One will stand and exalt His friends 
for what they had done. Abraham planted a garden wherein all the good ones 
recline, about whom it is said: they will keep the way of the Lord (Gen. 18:19). 
Moses erected a tent, in which all the seekers of God (SP Exod. 33:7) gather. He 
will stand on the Day of Judgement and redeem devotees and destroy foes. Isaac 
rushed on this path bringing up sons who learn from him (devotion). Moses 
fasted and increased his prayer for the sake of people, in hope they will be 
received. The True One (will) stand and judge people who will abandon all their 
sins and turn back to the True One.','הו אנשי הדור, האמינו בזאת ולמדו את הדעת הזאת. כמה גדול המאמר הזה, והפה שאמרו! חנוך הלך ברצון האלוהים (בראשית ה,כב) אחר מעשה קין ובן בנו, וכן הלאה. ביום הגמול יעמוד האמת וירומם את ידידיו על מה שעשו. אברהם נטע גן שבו נשענים כל הטובים, עליהם נאמר: ישמרו דרך ה'' (בראשית יח,יט). משה הקים אוהל שבו מתאספים כל מבקשי האלוהים (שמות לג,ז של הנוסח השומרוני). הוא יעמוד ביום הדין ויגאל את החסידים וישמיד את האויבים. יצחק מיהר בדרך זו ומסר בנים הלומדים ממנו (מסירות). משה צם והרבה תפילתו למען העם, בתקווה שיתקבלו. האמת יעמוד וידין את האנשים שיעזבו את כל חטאיהם ויחזרו אל האמת.');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (218,'IV','65','מימר על שירתה רבתה',4000651,'ועוד תלתה מלכים אתגברו קמי בטלת שמון נמרודה כד אתגבר בחילה דכוש גלית דיני וקטלת יתה פרעה כד הדמי לה ואתגבר וכפר גלית סימני וקטלת יתה עמלק אתגבר וסגת גבורתה מחקת דכרנה תלתה מבני זכו בטלו מצוהתי פוררת יתון בדינה ולא בטלת שמון יהודה כד גלה זנותה לגו עלמה פוררתה בבטול אוכחו לכל דריה שמעון אף הו העק על יוסף פוררתה בבטול אוכחו לכל דריה ראובן כד הדמי לון פוררתה בבטול אוכחו לכל דריה ותלתה שמעו קלי ועלמו עליו אתחזית בדינה ובטלת שמון עבודי עגלה כד גלו בישתה אתחזית בדינה ובטלת שמון ודאצטמתו ליד בעל פעור אתחזית בדיני ובטלת שמון קרח וסיעתה כד קעמו לקדמי ובעו מד לית לון קטית לדכרנון הב בלך תילף מן אלין ותתקרב בון תיבד כותון הצנק אהן ביספרה ולא תפתחנה כי נחשה ובלעל מזדמנים לגוה הפתח פתח טובה ועבר לגוה בשלם','Also three kings acted arrogantly before Me – I abolished their name. 
Nimrod, when he acted arrogantly with the army of Cush: I revealed My judge-
ment and killed him. Pharaoh, when he resembled him and acted arrogantly and 
disbelieved: I revealed My wonders and killed him. Amaleq acted arrogantly and 
his arrogance was great: I blotted out his remembrance. Three from the sons of 
righteousness abolished My precepts – I warned them with judgement [but did 
not abolish their name. Judah when he revealed fornication in the world: I 
warned him with abolishment – admonishment to all generations. Simeon, too, 
oppressed Joseph: I warned him with abolishment – admonishment to all gener-
ations. Reuben, when he resembled them: I warned him with abolishment – 
admonishment to all generations. Three heard my voice and ignored it – I ap-
peared in judgement and I abolished their name. The makers of the calf, when 
they revealed evil: I appeared in judgement and I abolished their name. Those 
who gathered in Baʿal Peʿor: I appeared in judgement and I abolished their name. 
Korah and his party, when they stood before me and demanded what was not for 
them: I cut oﬀ their remembrance. Pay attention lest you learn from these, and 
draw near to them – you will perish like them. Lock up this school and do not 
open it, for the Serpent and Belial are gathered in it. Open the gate of the good-
ness and pass through it in peace.','וְגַם שְׁלוֹשָׁה מְלָכִים הִתְגָּאוּ לְפָנַי – מָחִיתִי אֶת שְׁמָם. נִמְרוֹד, כַּאֲשֶׁר הִתְגָּאָה בְּחֵיל כּוּשׁ: גִּלֵּיתִי אֶת מִשְׁפָּטִי וַהֲרַגְתִּיו. פַּרְעֹה, כַּאֲשֶׁר דָּמָה לוֹ וְהִתְגָּאָה וְכָפַר: גִּלֵּיתִי אֶת נִפְלְאוֹתַי וַהֲרַגְתִּיו. עֲמָלֵק הִתְגָּאָה וּגְאוֹנוֹ הָיָה רַב: מָחִיתִי אֶת זִכְרוֹ. שְׁלוֹשָׁה מִבְּנֵי הַצַּדִּיקִים בִּטְּלוּ אֶת מִצְווֹתַי – הִזְהַרְתִּים בְּמִשְׁפָּט אַךְ לֹא מָחִיתִי אֶת שְׁמָם. יְהוּדָה, כַּאֲשֶׁר גִּלָּה זְנוּת בָּעוֹלָם: הִזְהַרְתִּיו בִּמְחִיָּה – אַזְהָרָה לְכָל הַדּוֹרוֹת. גַּם שִׁמְעוֹן שֶׁעִנָּה אֶת יוֹסֵף: הִזְהַרְתִּיו בִּמְחִיָּה – אַזְהָרָה לְכָל הַדּוֹרוֹת. רְאוּבֵן, כַּאֲשֶׁר דָּמָה לָהֶם: הִזְהַרְתִּיו בִּמְחִיָּה – אַזְהָרָה לְכָל הַדּוֹרוֹת. שְׁלוֹשָׁה שָׁמְעוּ אֶת קוֹלִי וְהִתְעַלְּמוּ מִמֶּנּוּ – נִגְלֵּיתִי בְּמִשְׁפָּט וּמָחִיתִי אֶת שְׁמָם. עוֹשֵׂי הָעֵגֶל, כַּאֲשֶׁר גִּלּוּ רָעָה: נִגְלֵּיתִי בְּמִשְׁפָּט וּמָחִיתִי אֶת שְׁמָם. הַנֶּאֱסָפִים בְּבַעַל פְּעוֹר: נִגְלֵּיתִי בְּמִשְׁפָּט וּמָחִיתִי אֶת שְׁמָם. קֹרַח וַעֲדָתוֹ, כַּאֲשֶׁר עָמְדוּ לְפָנַי וְתָבְעוּ מַה שֶּׁלֹּא הָיָה לָהֶם: כָּרַתִּי אֶת זִכְרָם. הִשָּׁמְרוּ פֶּן תִּלְמְדוּ מֵאֵלּוּ וְתִתְקָרְבוּ אֲלֵיהֶם – תֹּאבְדוּ כָּמוֹהֶם. נְעֲלוּ אֶת בֵּית הַמִּדְרָשׁ הַזֶּה וְאַל תִּפְתְּחוּהוּ, כִּי הַנָּחָשׁ וּבְלִיַּעַל נֶאֱסָפוּ בוֹ. פִּתְחוּ אֶת שַׁעַר הַטּוֹבָה וְעִבְרוּ בוֹ בְּשָׁלוֹם.');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (219,'IV','41','מימר על שירתה רבתה',4000411,'ותוקד עד שיאול ועיצה במלת תחתית גלה רבות יומה דנקם ומה בה יתחדד מן מדון רב לית בה נשום הך הוא טוב מן הוא תמן מתפלט בעמל טב עתדה לה לית תמן לאשתה עליו יכלה פרק קנומה בעמלה מן תחמדות בישהתה אתרחק ולא קעם בשקרה ולא מלל דגל מכן מרה אוקרה וילה מן לא יהיה כן בעלמה אדן מתלעי ולגו יום נקם משתנק ואלה מזדכי מנה אלפה ולא אתלף זעקה ולא ענה אזל לקשטה ועבד עובד אכעס בה על כן ישתנק כי מגזי לכל עמול לפם עמלה נעזר ליד קשטה וכן לן אמיר ותעזר לצעד יה דו רחמן ורתאי מקבל לכל תאב','And burns to Sheol (Deut. 32:22). He strengthens it with the word 
beneath. He revealed the greatness of the Day of Vengeance and the great 
punishment that will be wrought in it. There is no way to estimate how it will be. 
It is good for him who will be delivered on that day by a well-doing that he has 
prepared for himself. Fire will have no power over him, then. He delivered 
himself by his own deeds. He kept away from evil desire and has not been in-
volved in lies nor spoke falsehood, therefore his Lord has honored him. Woe to 
the one who is not so. In this world he is weary and on the Day of Vengeance he 
will be aﬄicted, and God is exempt from him. He taught him but he did not 
learn. He called him, but he did not answer. He went to the True One and did a 
deed by which he vexed Him. Accordingly, he will be aﬄicted. Indeed, He recom-
penses every doer according to his deed. Let us return to the True One, for so we 
have been told: And you will return to the Lord (Deut. 30:2) for He is merciful and 
full of pity and receives every penitent.','וַתִּיקַד עַד שְׁאוֹל תַּחְתִּית (דברים לב,כב). הוא מחזק זאת במילה "תחתית". הוא גילה את גדולת יום הנקמה ואת העונש הגדול שייעשה בו. אין דרך לאמוד כיצד יהיה. טוב לו למי שיינצל באותו יום על ידי מעשה טוב שהכין לעצמו. לאש לא תהיה שליטה עליו אז. הציל את עצמו במעשיו הוא. התרחק מתאוות הרע ולא נגע בשקר ולא דיבר כזב, לפיכך כיבדו אדונו. אוי למי שאינו כן. בעולם הזה הוא עייף וביום הנקמה יסבול, והאל פטור ממנו. לימד אותו ולא למד. קרא לו ולא ענה. בא לפני האמת ועשה מעשה שהכעיסו. לפיכך יסבול. הן הוא משלם לכל עושה לפי מעשהו. נשוב אל האמת, שכן כך נאמר לנו: וְשַׁבְתָּ עַד יְהוָה אֱלֹהֶיךָ (דברים ל,ב), שהרי הוא רחום ומלא חמלה ומקבל כל שב בתשובה.');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (220,'IV','14','מימר על שירתה רבתה',4000141,NULL,'– בראשיתyou have known it and comprehended its secrets, how they are: 
the Great Name, whose glory we know, and the greatness of כיwhich was heard 
from the mouth of Moses, and the name with which he was strengthened and ex-
alted. Both (names) were coupled with each other from the mouth of the Divinity 
and from the mouth of the prophethood. Let us watch the word which the True 
One wrote. It is the word בראwhich He said; what is its nature? He wrote: In the 
beginning created (Gen. 1:1), and Moses said: For in the name of the Lord I pro-
claim (Deut. 32:3). In the beginning בראwas said, for there (is) the deed of the 
Potent One. He saw and created by His will. And Moses said in prophethood: I 
will proclaim, like the word בראfrom the Divinity. בראשיתcomprises two parts: 
the six days and all the commandments that were comprised in the Torah. And 
because of a great reason it is said ,בראfor Moses was bound to reveal the 
decrees. Praised be the Merciful One, who shows compassion, and He endures 
forever.','"בראשית" – ידעת אותה והבנת את סודותיה, כמה הם: השם הגדול שאת כבודו אנו יודעים, וגדולת "כי" שנשמעה מפי משה, והשם שבו התחזק ונתעלה. שניהם נקשרו זה בזה מפי האלוהות ומפי הנבואה. נתבונן במילה שכתב האמת. היא המילה "ברא" שאמר; מה טבעה? כתב: "בראשית ברא" (בראשית א,א), ומשה אמר: "כי שם ה'' אקרא" (דברים לב,ג). בראשית נאמר "ברא", כי שם מעשה הכול יכול. ראה וברא ברצונו. ומשה אמר בנבואה: "אקרא", כמילה "ברא" מן האלוהות. "בראשית" כוללת שני חלקים: ששת הימים וכל המצוות שנכללו בתורה. ומטעם גדול נאמר "ברא", שכן משה היה חייב לגלות את הגזרות. ברוך הרחמן שמרחם ועומד לעד.');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (221,'IV','100','מימר על שירתה רבתה',4001001,'מלתה עסיראה ויהיו עליכם סתרה באדן יום דינה אנכי מגן לך מגזי לכל עמול לפם עמלה לית אלין מליה לאנשים בראים אלא לנן אוי לן אם לא נילפנון כיינן נתגזי במד שמענן דאנן בני טבים שבועת יהוה תהי בינינן הן לא נעבד בישה ולא נקרב גנואה ולא נעלם על קשטה ולא נתפני מן ארחה דאלה ומה דאלפן לא נתנשי ומה דחכמן לא נשבקנה טכח רחותה תגלי בעלמה ושדכה ושלמה יעזר לדברה כמה דאמר ותדמכון ולית מרתת ונשכן בטחים › כי ‹ לית נביה רבה משה שקיח קעום מצלי בדילן כמה דאמר וכדו אסק ליד יהוה מאן אסלח בדיל חוביכון ולא אהרן כהנה משמש לגו משכנה מסלח עלינן ל } ה {› כמה דאמר ועל כל עם הקהל יכפר לית ן ‹ חוגה כד ישאלנן מרן ארהותה באדינן וכל פקודיה קמינן ליתה פליה מננה כמה דאמר הלא קריב לידך ממללה בפיך ולבך למעבבדנה קטרה באדה ו ] שר [ רה באדה בפמך ולבבך עובדה תדירה באדה שנונה באדה כמה דאמר ושננתם לבניך ] נ [ שבח לאלה באימנו רבה ונודי גדלה בדחלה ונסגד קדם יחידאותה בשעבוד רב ונסיד ונימר לית אלה אלא אחד','The tenth statement: and let them be your protection (Deut. 32:38). On 
this Day of Judgement I am your shield (Gen. 15:1). [I repay to every doer accord-
ing to his deed. These words do not concern alien men, only us. Woe to us if we 
do not] learn them; indeed, we will be repaid with what we have heard. We are 
children of the good ones, the Lord’s oath shall be between us, that we will not 
do evil, or draw near to blame, or ignore the truth, or deviate from the way of 
God, and what we learned we shall not forget, and what He taught us we shall 
not forsake. Perchance the Divine Favor will appear in the world, and tranquility 
and peace will come back to their course, as He said: you shall lie down, and 
none shall trouble you (Lev. 26:6), and we will dwell safe. If the great prophet 
Moses does not stand in prayer for our sake, as he said: Now I will go up to the 
Lord; perhaps I can make atonement for your sin (Exod. 32:30), and (if) Aaron the 
priest does not worship in the sanctuary making expiation for us, as He said: 
and he shall make expiation for all the people of the congregation (Lev. 16:33), we 
shall have no justiﬁcation when our master will question us. The Torah is in our 
hands and all its commandments are before us, it is not remote from us, as He 
said: the word is very close to you; it is in your mouth and in your heart, so that you 
can do it (Deut. 30:14). He tied it by His hand and fastened by His hand. Its 
accomplishing is in your mouth and in your heart (ibid.) (but) its perpetuity is by 
His hand, and its teaching is His hand, as He said: you shall teach them to your 
children (Deut. 6:7). Let us praise God in great faith and give thanks with fear and 
let us bow down before His uniqueness with great submission, and let us testify 
and say: “There is no god but One.”','האמירה העשירית: ויהי עליכם סתרה (דברים לב,לח). ביום הדין הזה אני מגן לכם (בראשית טו,א). [אני משלם לכל עושה לפי מעשהו. הדברים האלה אינם מכוונים לאנשים זרים, אלא אלינו בלבד. אוי לנו אם לא] נלמד אותם; אכן, נשולם לפי מה ששמענו. אנו בני הטובים, שבועת ה'' תהיה בינינו, שלא נעשה רע, ולא נתקרב לגנאי, ולא נתעלם מן האמת, ולא נסור מדרך ה'', ומה שלמדנו לא נשכח, ומה שלימד אותנו לא נעזוב. אולי יתגלה הרצון האלוהי בעולם, ותחזור השלווה והשלום למסלולם, כאשר אמר: ושכבתם ואין מחריד (ויקרא כו,ו), ונשב בבטחה. אם הנביא הגדול משה לא יעמוד בתפילה למעננו, כאשר אמר: ועתה אעלה אל ה'' אולי אכפרה בעד חטאתכם (שמות לב,ל), ואם אהרן הכוהן לא יעבוד במקדש לכפר עלינו, כאשר אמר: וכיפר על כל קהל עדת ישראל (ויקרא טז,לג), לא תהיה לנו כל הצדקה כאשר אדוננו יישאל ממנו. התורה בידינו וכל מצוותיה לנגד עינינו, היא אינה רחוקה מאיתנו, כאשר אמר: כי קרוב אליך הדבר מאוד, בפיך ובלבבך לעשותו (דברים ל,יד). קשר אותה בידו ואסר בידו. עשייתה בפיך ובלבבך (שם), אך קיומה בידו, ולימודה בידו, כאשר אמר: ושיננתם לבניך (דברים ו,ז). נהלל את ה'' באמונה גדולה ונודה ביראה ונשתחווה ליחודו בהכנעה גדולה, ונעיד ונאמר: "אין אלוה אלא האחד."');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (222,'IV','93','מימר על שירתה רבתה',4000931,'מלתה שביעתה וחש עתידות למו מן קדם קדמה עובדים בישים אשכח מדון , ביש לקבל מה דעבד מן עבד מרדה חלקה יזמן גרמה ליום נקם יהי עלינן נחדד תתובה עד ‹} ננשם בה ממה עבדנן יום נקם עתיד למי יעבד חוב וילה לחיביה במה עבדו בג › ר ב { מון מן יפרקנון מן אש גדלה מוקדה ולא תכבי כי מן קדם בישהן יזמן מגויהן ומן קדם טבהן ישכח כותה כמה דאמר ועבד טב לאלפין לרחומי ונטורי פקודי דכור אוב אבהן עם בנים על תליתאים ועל רב › י ‹ עי } ה { ם לסנאי לאוי עלינן נהי רחומים בכל מאדנו למרן כמה דאמר ‹} ותרחם ית יה אלהיך עד ינשם ג › ר ב { מך מן יומה עקבאה יום נקם מכל חיביה יום שלם לכל טביה יום עמידותה לכל ברנשיה ויום תאותה לכל בישיה יום חשבנה לכל עמליה יום גזוה למרודיה יום שיאלה על כל עמליה מן זעוריה ] ועד רברביה [ יום תחרד כל אבריה , יום בו כל נפש גזוה לקחיה יום דינה יום בכוה יום פשרונה יום כנושה יום קשטה יום דחלה יום מפוקה מן שיאולה יום חדותה לכל שמועיה יום יגונה למקצפיה יום יגלי בה ברוי כל בוראיה ויכרז אנה אנה הוא ] מ [ לכה קעימה ] מ [ ורכה ולא עורן עמי','The seventh statement: And destiny rushes upon them (Deut. 32:35). He 
who brought before Him evil deeds ﬁnds a bad punishment, according to what 
he had done. He who committed rebellion, his Creator will summon him to the 
Day of Vengeance. It is appropriate for us to renew repentance, that we may be 
relieved by it from what we have done. The Day of Vengeance is prepared for he 
who commits sin. Woe to the sinners because of what they have done to them-
selves. Who will redeem them from a great ﬁre that burns and is not extin-
guished. For he who brought forth evil deeds will be appointed to punishments, 
and he who brought forth good deeds will ﬁnd like them, as He said: showing 
kindness to the thousandth (generation of) those who love Me and keep My 
commandments (Exod. 20:6), visiting the guilt of the parents upon the children, 
upon the third and upon the fourth generations for those who hate Me (Exod. 20:5). 
Would that we be devoted with all our might to our Master, as He said: You shall 
love the Lord your God (Deut. 6:5), that He may relieve you from the Last Day: the 
Day of Vengeance for all the guilty ones, the Day of Requital for all the good 
ones. The Day of “standing” for all humans and the Day of remorse for evildoers, 
the Day of reckoning of all deeds, the Day of punishment for all rebels, the Day 
of inquiry into all actions, from the small ones [to the great ones], the Day when 
all limbs will tremble, the Day when each soul will take its reward, the Day of 
judgement, the Day of lament, the Day of trial, the Day of assembly, the Day of 
the True One, the Day of fear, the Day of exit from Sheol, the Day of joy for all the 
obedient, the Day of mourning for the irritating ones, the Day in which the 
Creator of all creatures will appear and proclaim: I, I am He (Deut. 32:39), the 
everlasting King, enduring, and there is no other with me.','האמירה השביעית: "וְחָשׁ עֲתִדֹת לָמוֹ" (דברים לב,לה). מי שהביא לפניו מעשים רעים מוצא עונש קשה, כפי שעשה. מי שמרד – בוראו יזמנו ליום הנקמה. ראוי לנו לחדש את התשובה, כדי שתציל אותנו ממה שעשינו. יום הנקמה מוכן למי שחוטא. אוי לחוטאים על מה שעשו לעצמם. מי יגאל אותם מאש גדולה הבוערת ואינה כבה. שכן מי שהביא מעשים רעים ייועד לעונשים, ומי שהביא מעשים טובים ימצא כמותם, כפי שאמר: "וְעֹשֶׂה חֶסֶד לַאֲלָפִים לְאֹהֲבַי וּלְשֹׁמְרֵי מִצְוֹתָי" (שמות כ,ו), "פֹּקֵד עֲוֹן אָבֹת עַל בָּנִים עַל שִׁלֵּשִׁים וְעַל רִבֵּעִים לְשֹׂנְאָי" (שמות כ,ה). הלוואי שנהיה מסורים בכל מאודנו לאדוננו, כפי שאמר: "וְאָהַבְתָּ אֵת ה'' אֱלֹהֶיךָ" (דברים ו,ה), כדי שיצילך מהיום האחרון: יום הנקמה לכל החייבים, יום הגמול לכל הטובים. יום ה"עמידה" לכל בני האדם, ויום החרטה לעושי הרע, יום חשבון כל המעשים, יום העונש לכל המורדים, יום החקירה בכל המעשים, מן הקטנים ועד הגדולים, היום שבו ירעדו כל האיברים, היום שבו תיקח כל נפש את שכרה, יום הדין, יום הבכי, יום המשפט, יום הקהל, יום האמת, יום הפחד, יום היציאה משאול, יום השמחה לכל הציתנים, יום האבל לבני העוררין, היום שבו יופיע בורא כל הברואים ויכריז: "אֲנִי אֲנִי הוּא" (דברים לב,לט), המלך הנצחי, הקיים, ואין אחר עמי.');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (223,'IV','77','מימר על שירתה רבתה',4000771,'אה איקר רב ] אה [ רבין יתר ] א [ ה ברכה רבה אה מלכו ממנה אה שלטנו חיולה אה אימנו שלמה אה ] טו [ ב ] כפל אה זבן מרי [ ח ] אה עדן נפוש אה אוצר בריך [ אה כרי דלא פעת אה פתור מיקר קדשה בה משתוי אלהים כללה ברכתה בה קטירה שלמותה בה דעארה כהנה דלה כבודה רבה קעומיה עליה מלאכיה יתוביה מהימניה שמשיה קדישיה לחמה דבה דמעה אוכליה מדכים שמה רבה תשבחתה נביה רבה משה סדרה אדם אקים דמסה ונח מלא בניאנה ואברהם יתב עליה ויצחק יקרה ויעקב שררה ויוסף מלכה לה נטר באימנו כי נביה רבה משה ארשהתן בכן לבר מנה לא נשמע דמותה בחלופה ואף דינה בבטולה נשתעבד למרן וננצר קדמיו ונימר באימנו לית אלה אלא אחד','Behold, a great glory! Behold, an exceeding majesty! Behold, a great 
blessing! Behold, an eternal kingdom! Behold, a mighty sovereignty! Behold, a 
perfect faith! Behold, a double good! Behold, a pleasing epoch! Behold, a blessed 
treasure! Behold, a fundament that is not diminished! Behold, an honored table 
on which the holy is placed. God crowned it, the blessings are bound with it, 
perfection abides in it. Its priest is Great Glory. Those who stand by it are the 
angels. Those who sit at it are the faithful ones. The servants are the Holy ones. 
The bread which is on it is the most select, those who eat it are the pure ones. 
The Great Name is its praise. The great prophet Moses arranged it, Adam laid its 
foundations, and Noah completed its building, Abraham sat there, Isaac hon-
ored it, and Jacob strengthened it, and Joseph the king guarded it with faith. 
Indeed, the great prophet Moses [commanded us with this. Let us not listen to 
anyone but him, for death resides in its substitute, and also punishment in its 
abrogation. Let us be submissive to our Lord and devoted to Him, saying with 
faith: “There is no god but One.”','הנה כבוד גדול! הנה הוד נשגב! הנה ברכה גדולה! הנה מלכות עולם! הנה שלטון אדיר! הנה אמונה שלמה! הנה טובה כפולה! הנה עת רצון! הנה אוצר מבורך! הנה יסוד שאינו מתמעט! הנה שולחן נכבד שעליו מונח הקודש. האל עיטרו, הברכות קשורות בו, השלמות שוכנת בו. כוהנו הוא הכבוד הגדול. העומדים לצדו הם המלאכים. היושבים בו הם הנאמנים. המשרתים הם הקדושים. הלחם שעליו הוא המובחר שבמובחר, ואוכליו הם הטהורים. השם הגדול הוא תהילתו. משה הנביא הגדול סידרו, אדם הניח את יסודותיו, ונח השלים את בנייתו, אברהם ישב בו, יצחק כיבדו, ויעקב חיזקו, ויוסף המלך שמר עליו באמונה. אכן, משה הנביא הגדול ציווה אותנו בזאת. אל נשמע לאיש זולתו, כי המוות שוכן בתחליפו, וגם עונש בביטולו. נשפיל את עצמנו לפני אדוננו ונהיה נתונים לו, ונאמר באמונה: "אין אלוהים כי אם אחד."');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (224,'IV','7','מימר על שירתה רבתה',4000071,'דאמר עורי עד תמם בעה מרבאה דרגי מיאמניה וכן חורי תרי כהניה צמת כהלון במלת עד יהושע אמר לה בטורה אלדד ומודד מתנבאים במחנה וכן אמר אלה בדיל אלעזר ונשיא נשיאי הלוים אלעזר וכלל רביאן פינחס בבריה ממנה צמת כהניה ומיאמניה תמן כהניה אנון שמורי קדשה ומימניה על מלי קשטה ואלין ואלין במטרה חדה ברבין מלכו ושלטנו יתרה נשבח למרן במד לן חכם ונחיל למשה במד בן אדיר איך משה לא קעם ולא יקום לעלם וכן אלה אמר בגללה מן יכל מגלג במשה אי ימטי ידע רבינה דמדעה האן הך משה ומן מדמי למשה דאתיקר בכסיאתה סגי מגליאתה בר ביתה דאלהים ומהימן אלהים ועבדה דאלהים ואיש האלהים ואתחזי לה אלהים ומלל עמה אלהים קרא ואמר תמם לשלמו כנו תמים כן מליו תמימים','He spoke further: to their very end (Deut. 31:30) – he sought to elevate the 
rank of the faithful, and also the two priests. He included all of them in the word 
 .עדJoshua said to him on the mountain: Eldad and Modad are acting the prophet 
in the camp (Num. 12:27), and God spoke thus regarding Eleazar: The head 
chiefain of the Levites was Eleazar (Num. 3:32), and included the greatness of 
Phinehas in a steadfast covenant (Num. 25:11) – he joined the priests and the 
faithful ones there. The priests are the keepers of holiness, and the faithful ones 
are (the keepers) of the words of the True One. Both (teams) are (appointed to) 
the same custody with authority of kingship and great sovereignty. Let us praise 
our Master for what he has taught us and let us strengthen Moses for what he set-
tled in us. None has arisen like Moses, and never will arise. Thus God said of 
him. Who is able to praise Moses or successfully knows the greatness of his 
mind? Where is there anyone like Moses and who resembles Moses, who was glo-
riﬁed in the Concealed more than in the Overt, the Son of the house of God, and 
the faithful of God, the servant of God, the Man of God? God has revealed Him-
self to him, and God spoke with him. He proclaimed and said תמםfor perfection. 
As he is perfect, so are his words perfect.','עוד אמר: עד תומם (דברים לא,ל) – ביקש להעלות את מדרגת הנאמנים, וכן את שני הכוהנים. כלל את כולם במילה עד. יהושע אמר לו בהר: אלדד ומידד מתנבאים במחנה (במדבר יא,כז), והאלוהים אמר כך על אלעזר: נשיא נשיאי הלוי אלעזר (במדבר ג,לב), וכלל את גדולת פינחס בברית שלום (במדבר כה,יב) – חיבר שם את הכוהנים ואת הנאמנים. הכוהנים הם שומרי הקדושה, והנאמנים הם שומרי דברי האמת. שתי הכתות שומרות על אותה משמרת, בסמכות מלכות ושלטון גדול. נהלל את אדוננו על מה שלימדנו ונאמץ את משה על מה שנטע בנו. לא קם כמשה ולא יקום. כך אמר עליו האלוהים. מי יכול לשבח את משה או לדעת באמת את גדולת דעתו? היכן מישהו כמשה ומי דומה למשה, שנתכבד בנסתר יותר מבנגלה, בן בית האלוהים ונאמן האלוהים, עבד האלוהים, איש האלוהים? האלוהים נגלה לו, ואלוהים דיבר אתו. הכריז ואמר תמם לשלמות. כשם שהוא שלם, כך דבריו שלמים.');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (225,'IV','32','מימר על שירתה רבתה',4000321,'בני מום וילה קין דאולד בזבן כהלה אכעס תרין עובדים בישים עבד אבד בכירתה וחיב מותה אבד בכירתה לא אנדה בכורים וחיב מותה כד קטל הבל אחוה טבה שנת אדם אלא לא כללה וטבה שנת קין אלא לא כללה שנת אדם פתור מברך אקים קנומה עני כד חלף פקודה ויצמיח יהוה אלהים } ית { » מן « האדמה ית כל עץ מכלל שבקה ואכל למותה קין בשנתה חלל דמעה ושבק פתורה ועזר כלי וטמי ודמעה על מה דו מתותר והוא } מתרחם { » מתחרם « וכן ישראל בשתה קדמאה שבק חייה ואזל למותה בשתה קדמאה שמק מן מרה דעלמה אנכי יהוה לא יהי לך אלה חורן שבקה ועבד עגל מסכה בשנת השנית הנצב משכנה טמרו כניזתה עד אתו אל בעל פעור ועבדו מה דעבדו מכן אמר נביה רבה משה שחתו } לאלו { » לא לו « וסמך עליה בני מום','Children of blemish (SP Deut. 32:5). Woe to Cain who begot at a time, 
wholly anger. He did two evil deeds: he lost his birthright and was liable to 
death. He lost his birthright by not bringing ﬁrst fruits, and was liable to death 
when he slew Abel his brother. The year of Adam would have been good, but he 
did not complete it. The year of Cain would have been good, but he did not 
complete it. The year of Adam was a blessed table, but he made himself poor 
when he altered the command. And from the ground the Lord God caused to grow 
every perfect tree (Gen. 2:9) – he abandoned it and ate death. Cain in his year 
profaned the oﬀering and abandoned the table and returned withheld and isolat-
ed (Gen. 4:14). The oﬀering from what is lef over is proscribed. Likewise, Israel 
in the ﬁrst year abandoned life and went forth to death. In the ﬁrst year they 
heard from the God of the world: I am the Lord […] You shall have no other god 
(Exod. 20:2–3). They abandoned Him and made a molten calf (Exod. 32:4). In the 
second year the Sanctuary was erected – they concealed (bad) conscience until 
they came to Baʿal Peʿor and did what they did. Therefore the great prophet said: 
 שחתו ]…[ לא לוand joined to it .בני מום','בני מום (דברים לב,ה בנוסח השומרוני). אוי לקין שהוליד בעת שהיתה כולה זעם. עשה שני מעשים רעים: איבד את בכורתו ונתחייב במוות. איבד את בכורתו בכך שלא הביא ביכורים, ונתחייב במוות כשהרג את אחיו הבל. שנתו של אדם היתה יכולה להיות טובה, אך לא השלימה. שנתו של קין היתה יכולה להיות טובה, אך לא השלימה. שנתו של אדם היתה שולחן ברוך, אך עשה את עצמו עני כאשר שינה את הציווי. ומן האדמה הצמיח ה'' אלוהים כל עץ שלם (בראשית ב,ט) – עזב אותו ואכל את המוות. קין בשנתו חילל את הקרבן ועזב את השולחן וחזר עצור ובודד (בראשית ד,יד). הקרבן מן הנשאר הוא אסור. כמו כן, ישראל בשנה הראשונה עזב את החיים ויצא אל המוות. בשנה הראשונה שמעו מאלוהי העולם: אנכי ה'' [...] לא יהיה לך אלוהים אחרים (שמות כ,ב–ג). עזבוהו ועשו עגל מסכה (שמות לב,ד). בשנה השנייה הוקם המשכן – הסתירו מצפון רע עד שבאו לבעל פעור ועשו מה שעשו. לפיכך אמר הנביא הגדול: שחתו [...] לא לו, וצירף לו בני מום.');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (226,'IV','58','מימר על שירתה רבתה',4000581,'שאל אבוך ויחוי לך ויהי לבך שמחי בכל איקרה דיהבה מרך ויקרך בה מן הכדך סעד כדו מה פרקך מן אדי כפוריה בסימנים רמין וקטל בניון על דדיך מה מלאך מכל טוב מה פלג קמיך ימה מה טבע דבביך בה מה אמתק לך מימי מרתה מא אמטר לך לחם מן השמים מה אפק לך מים מן תקפה מה שבר עמלק ועמה קמיך מה אטלך בעננה ואשרה יתך בגוה מה אשמעך קלה מלגו אשתה מה יהב לך כיר אדה מה אנשמך ביום שבתה מה אפרש לך מועדים קדישים מה הפך קללתה לברכתה עמי אלין מתנהתה ואודי למרך ודע הן לא אתוקר גוי כותך וכן אמר כי מי גוי גדול אשר לו אלהים קרובים אליו כיהוה אלהינו כי מי כל בשר אשר שמע קול אלהים חיים כל אלין טבהתה לא אתעבדת לחרונך בעלמה אן תשאל אבוך תהי בר טב תקום באימנו אתה ובריך נביה רבה משה אמר זכור לעבדיך לאברהם וליצחק וליעקב שלמיה אב טב שאלה בר טב ואתעבד ברון דמי לון בקשטה ויהי כד ישאלך בנך אלהים אמר ומשה אמר שאל אביך ויחוי לך אמסר אוב אבהן עם בנים ועם ברי בנים אלה אמרה ומשה אישה שררה אכה אמר שאל אבוך ויחוי לך אתאלף לקשטה ואלפה לברך עד ירחמך מרך נודי ונשבח לאלה ונקד ארצה באימנו ונרומם יתה הך מד לאוי לה אהיה אשר אהיה ואני הנני אזל ואתי מודע דו אחד לקלומה לא מתחלף על מד הוה בקדם הו ממן עד לעלם ניאמן בה ונסיד בקשטה ונימר לית אלה אלא אחד','Ask your father, he will tell you (Deut. 32:7) and your heart will be joyful 
with all the honor that your Master gave and honored you with, from your ﬁrst 
coming into being to this day: Did He not deliver you from the hands of the 
unbelievers with great wonders and slain their children for your sake? Did He 
not ﬁll you with every good? Did He not divide the sea before you? Did He not 
sink your enemies in it? Did He not sweeten for you the water of Mara? Did He 
not make bread from heaven rain on you? Did He not take out water from the 
rock? Did He not smite Amaleq and his people before you? Did He not shadow 
you with His cloud and place you within? Did He not make you hear His voice 
from the ﬁre? Did He not give you the writing of His hand? Did He not make you 
rest on the day of Sabbath? Did He not select for you holy festivals? Did He not 
turn the curse into blessing? See these gifs and praise your Master and know 
that no people has been ever honored like you. And thus has He said: For what 
great nation is there that has a god so near to it as the Lord our God (is to us)? 
(Deut. 4:7) For what mortal ever heard the voice of the living God? (Deut. 5:26) All 
these good things have not been made to other than you in the world. If you ask 
your father [you will be a good son, you will be in faith, you and your sons. The 
great prophet Moses] said: Remember Your servants, Abraham, and Isaac, and 
Jacob (Deut. 9:27), the perfect ones. With a good father, a good son asked him 
and the son became like him in the truth. When your son asks you (Deut. 6:20) – 
God said; and Moses said: Ask your father and he will tell you (Deut. 32:7). He 
visits the iniquity of fathers upon children and children’s children (Exod. 37:4) – 
God said it; and Moses the Man emphasized it here, saying: Ask your father and 
he will tell you. Learn the truth and teach it to your son, that your Master may 
love you. Let us give thanks and praise God and prostrate ourselves to the 
ground in faith, and exalt Him as is appropriate, I am who I am. And I, behold, I 
go and come, recognizing that He is one, by Himself, unchangeable. Over what-
ever existed He is steadfast forever. Let us believe in Him and testify in truth and 
say: “There is no god but One.”','שאל את אביך ויגד לך (דברים לב,ז) וייטב לבך בכל הכבוד שנתן לך ריבונך וכיבד אותך בו, מיום היוולדך הראשון ועד היום הזה: האם לא הצילך מידי הכופרים באותות ומופתים גדולים והכה את בכוריהם למענך? האם לא מילאך בכל טוב? האם לא בקע את הים לפניך? האם לא טבע את אויביך בתוכו? האם לא המתיק לך את מי מרה? האם לא המטיר עליך לחם מן השמים? האם לא הוציא לך מים מן הסלע? האם לא הכה את עמלק ואת עמו לפניך? האם לא הצל עליך בעננו ושמך בתוכו? האם לא השמיעך את קולו מתוך האש? האם לא נתן לך את כתב ידו? האם לא הניחך ביום השבת? האם לא בחר לך מועדים קדושים? האם לא הפך את הקללה לברכה? ראה את המתנות הללו ושבח את ריבונך ודע כי לא כובד עם כמוך מעולם. וכך אמר: כי מי גוי גדול אשר לו אלהים קרובים אליו כה'' אלהינו (דברים ד,ז). כי מי מכל בשר שמע קול אלהים חיים (דברים ה,כו). כל הדברים הטובים הללו לא נעשו לאף אחד זולתך בעולם. אם תשאל את אביך [תהיה בן טוב, תהיה באמונה, אתה ובניך. הנביא הגדול משה] אמר: זכור לעבדיך לאברהם ליצחק וליעקב (דברים ט,כז), התמימים. עם אב טוב, בן טוב שאלו ונעשה הבן כמוהו באמת. כי ישאלך בנך מחר (דברים ו,כ) – אמר האל; ומשה אמר: שאל אביך ויגדך (דברים לב,ז). פקד עון אבות על בנים ועל בני בנים (שמות לד,ז) – אמרו האל; ומשה איש האלהים הדגיש זאת כאן באמרו: שאל אביך ויגדך. למד את האמת ולמד אותה לבנך, למען יאהבך ריבונך. נודה ונשבח לאל ונשתחווה ארצה באמונה, ונרוממהו כראוי לו, אני אשר אני. ואני, הנני הולך ובא, מכיר כי הוא אחד, לבדו, בלתי משתנה. על כל אשר היה הוא עומד לעולמי עד. נאמין בו ונעיד באמת ונאמר: "אין אלהים כי אם אחד."');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (227,'IV','38','מימר על שירתה רבתה',4000381,'ובתועבות יכיעסהו עלם חסרן לית לגוה אכשרו עלם דיתחזי בה תועבהתה לא בנים טבים ולא אבהן שלמין ולא חכמה ולא בינה אלא עלם כהלה בישהן לא קשט ולא זכו אלא עלם כהלה תועבהן וילון מרגזיה ומה עבדו בגרמון עתדו לון זבדה כהלה תשניק ביומה חראה טוב לנן הן נעבד לקנומן זבד לעלמה עורנה דמה דנהי זכים מן מגביה ביום נקם ונטר מה דאלפן נביה רבה משה דכל מליו חיים ורתו','With abominations they provoked Him to anger (Deut. 32:16) – a deﬁcient 
world with no equity, a world in which abominations will appear, with no good 
children, no perfect fathers, no wisdom nor understanding. But a world wholly 
of evildoing, with no truth nor justice, a world wholly of abominations. Woe to 
those who stir up anger, by what they did in themselves. They have prepared for 
themselves a provision wholly of aﬄiction in the last day. Happy will we be, if we 
make for ourselves a provision for the other world; perchance we may be exempt 
of punishment in the Day of Vengeance. And we will observe what the great 
prophet Moses has taught us, all of whose words mean life and grace.','בְּתוֹעֵבֹת יַכְעִיסֻהוּ (דברים לב,טז) – עולם חסר בלא יושר, עולם שבו תופענה תועבות, בלא ילדים טובים, בלא אבות תמימים, בלא חכמה ובלא בינה. אלא עולם של רשע בלבד, בלא אמת ובלא צדק, עולם של תועבות כולו. אוי לאלה המעוררים כעס, במעשיהם שעשו בעצמם. הכינו להם צידה של ייסורים בלבד ליום האחרון. אשרינו אם נכין לעצמנו צידה לעולם האחר; שמא ניפטר מן העונש ביום הנקמה. ונשמור את אשר לימד אותנו הנביא הגדול משה, שכל דבריו חיים וחסד הם.');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (228,'IV','64','מימר על שירתה רבתה',4000641,'נאזין ונשמע מימרה אבטל מן אנוש דכרנון מן בטל פקודי אבטל אנה ית דכרנה מן אנדינתה בדעתי ולא צבה ילף אתחזי אנה בדיני ואבטל ית דכרה מן קרית קדמיו ולא שמע ית מקרתי אתחזי אנה בדיני ואבטל ית דכרנה מן מר לקשטה ואקים שקרה אתחזי בדיני אנה ואבטל ית דכרנה תלתה ראשים הגדדו קדמי גלית דיני ובטלת שמון מבולאי , כד השלמת חוביהון גלית דיני ובטלת שמון סדמאי עורי כד השלמת בישהתון בטלת שמון ומצראי כד השלם עונון גלית דינין ובטלת שמון ותלתה עורי כד השלמת בישהתון פוררת יתון ולא בטלת לשמון דכור עוב אבהן עם ברים עם תליתאים עם רביעים הן הוו סנאים גזית יתון בקשטה מן חנוך עד למך שלשלה בישה שרוה קין וחסולה מבולאיה וכן אנשי בבל בנאי מגדלה הוו ככן שרון כנען וחסולון עד סדם ועוד ברה דאזל אבוה אוזפת לבטה ולא בטלת שמה','Let us listen and hear His word: I will abolish their remembrance from 
among men (Deut. 32:26). He who abolished My precepts, I will abolish his 
remembrance. He to whom I conveyed My knowledge, but he did not want to 
learn, I shall emerge with My judgement and I will abolish his remembrance. He 
before whom I called and he did not hearken to My summon, I shall emerge with 
My judgement and I will abolish his remembrance. He who swapped the truth 
and brought about falsehood, I emerge with My judgement and I will abolish his 
remembrance. Three parties rebelled against Me,] and I revealed My judgement 
and I abolished their name. The People of the Flood, when their transgressions 
were completed: I revealed My judgement and I abolished their name. The 
People of Sodom too, when their evildoing was completed: I abolished their 
name. The Egyptians, when their guilt was completed: I revealed judgement and 
I abolished their name. Three more, when their evildoing was completed: I 
warned them, but I did not abolish their name. I visit the iniquity of the fathers 
upon the children to the third and the fourth generation (Exod. 20:5). If they were 
enemies, I repaid them in truth. From Enoch to Lamech, an evil chain beginning 
with Cain and ending with the People of the Flood. Likewise, the people of 
Babylon, the builders of the tower were like this; their beginning was with 
Canaan and their end up to Sodom. Also the son who debased his father. I added 
to his curse, but did not abolish his name.','נִשְׁמַע וְנַאֲזִין לִדְבָרוֹ: אֲפָאֵיהֶם מֵאֱנוֹשׁ (דברים לב,כו). מִי שֶׁבִּטֵּל אֶת מִצְווֹתַי, אֲמַחֶה אֶת זִכְרוֹ. מִי שֶׁהַעֲבַרְתִּי לוֹ אֶת דַּעְתִּי וְלֹא רָצָה לִלְמֹד, אֵצֵא בְּמִשְׁפָּטִי וְאֶמְחֶה אֶת זִכְרוֹ. מִי שֶׁקָּרָאתִי לְפָנָיו וְלֹא שָׁמַע לְקוֹלִי, אֵצֵא בְּמִשְׁפָּטִי וְאֶמְחֶה אֶת זִכְרוֹ. מִי שֶׁהֶחֱלִיף אֶת הָאֱמֶת וְהֵבִיא שֶׁקֶר, אֵצֵא בְּמִשְׁפָּטִי וְאֶמְחֶה אֶת זִכְרוֹ. שְׁלוֹשָׁה כִּתּוֹת מָרְדוּ בִּי, וְגִלֵּיתִי אֶת מִשְׁפָּטִי וּמָחִיתִי אֶת שְׁמָם. אַנְשֵׁי הַמַּבּוּל, כַּאֲשֶׁר נִשְׁלְמוּ פִּשְׁעֵיהֶם: גִּלֵּיתִי אֶת מִשְׁפָּטִי וּמָחִיתִי אֶת שְׁמָם. אַנְשֵׁי סְדוֹם גַּם הֵם, כַּאֲשֶׁר נִשְׁלְמָה רִשְׁעָתָם: מָחִיתִי אֶת שְׁמָם. הַמִּצְרִים, כַּאֲשֶׁר נִשְׁלְמָה עֲווֹנָם: גִּלֵּיתִי אֶת מִשְׁפָּטִי וּמָחִיתִי אֶת שְׁמָם. וְעוֹד שְׁלוֹשָׁה, כַּאֲשֶׁר נִשְׁלְמָה רִשְׁעָתָם: הִזְהַרְתִּים, אַךְ לֹא מָחִיתִי אֶת שְׁמָם. פֹּקֵד עֲוֹן אָבוֹת עַל בָּנִים עַל שִׁלֵּשִׁים וְעַל רִבֵּעִים (שמות כ,ה). אִם הָיוּ אוֹיְבִים, שִׁלַּמְתִּי לָהֶם בֶּאֱמֶת. מֵחֲנוֹךְ עַד לֶמֶךְ – שַׁלְשֶׁלֶת רָעָה שֶׁתְּחִלָּתָהּ בְּקַיִן וְסוֹפָהּ בְּאַנְשֵׁי הַמַּבּוּל. כֵּן אַנְשֵׁי בָּבֶל, בּוֹנֵי הַמִּגְדָּל, כָּאֵלּוּ הָיוּ; תְּחִלָּתָם בִּכְנַעַן וְסוֹפָם עַד סְדוֹם. וְגַם הַבֵּן שֶׁבִּזָּה אֶת אָבִיו – הוֹסַפְתִּי עַל קְלָלָתוֹ, אַךְ לֹא מָחִיתִי אֶת שְׁמוֹ.');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (229,'IV','42','מימר על שירתה רבתה',4000421,'אנשה אתפוררו מן שנתכון ועבדו מה דאלפכון נביה רבה משה עד תנשמון ביום נקם כד יכרז אלה ואין מידי מציל וילה חיבה כד ישאלה קשטה על עובדה וילה חיבה כד יימר לה קשטה במד פנית עולמך במה אבדת מדהלך לא משמע ולא עשה ולא מקרא ולא צלו ולא תחנון ולא עמל מרחי כי ידין יהוה לכל עמול דעמל אי טב אי ביש מן עבד לה אלה עד יסעדנה ייתי יומה מן עבד בידה אלה וסגד לה ייתי יפשרנה ואין מידי מציל מן אקים לה אלה בתחמדות לבה ואין מידי מציל מן עבד צלם על דמות צורה וילה תמן לית לה מידי מציל מן שוה רחצונה על בלעדי וילה תמן אין לה מידי מציל','O people, awake from your sleep and do what the great prophet Moses 
has taught you, that you may be relieved in the Day of Vengeance, when God 
calls: And there is none that can deliver out of my hand (Deut. 32:39). Woe to the 
sinner when the True One asks him about his deed. Woe to the sinner when the 
True One says to him, “How is it that you have emptied your life? How is it that 
you have destroyed your belongings? You have no hearing, no obedience, no 
reading, no prayer, no supplication, no pleasing action.” For the Lord will judge 
(Deut. 32:36) every doer of deed(s), whether good or bad. He who has made for 
himself a god to help him, his day will come. He who has made a god with his 
own hands and worshiped it, let it come and deliver him – And there is none that 
can deliver out of my hand (Deut. 32:36). He who has set up a god for himself in 
the desire of his heart – And there is none that can deliver out of my hand. He who 
makes a ﬁgure according to an image, woe to him then, he has none to deliver 
(him) out of my hand. He who has set his trust on any one besides me, woe to 
him then – he has none to deliver (him) out of my hand.','עַם, הקיצו משנתכם ועשו את אשר לימד אתכם הנביא הגדול משה, למען תינצלו ביום הנקמה, כאשר יקרא האל: וְאֵין מִיָּדִי מַצִּיל (דברים לב,לט). אוי לחוטא כאשר האמת שואל אותו על מעשהו. אוי לחוטא כאשר האמת אומר לו: "כיצד ריקנת את חייך? כיצד השחתת את נכסיך? אין לך שמיעה, אין ציות, אין קריאה, אין תפילה, אין תחנה, אין מעשה רצוי." כִּי יָדִין יְהוָה (דברים לב,לו) כל עושה מעשה, בין טוב בין רע. מי שעשה לו אל לעזרתו, יומו יבוא. מי שעשה אל בידיו וסגד לו, יבוא וייצילנו – וְאֵין מִיָּדִי מַצִּיל (דברים לב,לו). מי שהעמיד לו אל בתאוות לבו – וְאֵין מִיָּדִי מַצִּיל. מי שעשה פסל כדמות צלם, אוי לו אז, אין לו מי שיצילנו מִיָּדִי. מי שנתן את בטחונו בכל אחר מלבדי, אוי לו אז – אין לו מי שיצילנו מִיָּדִי.');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (230,'IV','11','מימר על שירתה רבתה',4000111,'דגוני סימניה דגלתון בעלמה אזדמנו תמן למיקרה ואורה פסח לה מדעי אנשה דייעל ממללה לידון בכשרן וחשכה קבל על לבבי דבביו דעבדו קנומון דבבים לקשטה ] ו [ רוחה אתחיל ] ל [ מתלי קלה ] ב [ דיל דיעבר על כל שמועיה ואשתה הגדלת ולבלבת ברבו למדיר חכמתה בלבבי חכימיה ומיה ארכנת קדמיו ושמעת למליו ועורי יסדיה קמת תמן לאוקרותה ותרי מאוריה וכוכביה אדמו לון במה עבדו ולית אתפרד אחד מן חברה הב בלך לא תהי דבב לאלין בתר מלך תהי עבד הב בלך לא תהי דבב לאלין כלה מקים לך באשדה חיולה הב בלך לא תהי דבב לאלין תתעבד מטה ] ו [ דבבך לעל ] מ [ נך הב בלך לא תהי דבב לאלין תקום במסכינו וכלה קבל עליך ולית לך בון יכלו','The various wonders that he revealed in the world gathered there to 
honor him: the light broke forth for him into the minds of men, so that his words 
should penetrate them with righteousness. The darkness darkened the hearts of 
his enemies who made themselves enemies of the True One. The wind strength-
ened itself to lif up his voice, so that it might pass towards all the audience. The 
ﬁre increased and ﬂamed in majesty to implant wisdom in the hearts of the wise. 
The water bowed down before him and listened to his words, and also the foun-
dations stood there in order to honor him. The two luminaries and the stars 
(were) like them in what they did, and none was diﬀerent from the other. Pay at-
tention, do not be an enemy to these, (for) afer being a king (you will be) a slave. 
Pay attention, do not be an enemy to these, all (of them) will leave you in mighty 
distress. Pay attention, do not be an enemy to these, lest you be down and your 
enemy up. Pay attention, do not be an enemy to these, lest you be in poverty, 
and all (of them) complain about you, and you have no power over them.','הנפלאות השונות שגילה בעולם נקבצו שם לכבדו: האור פרץ לתוך מחשבות בני האדם, כדי שדבריו יחדרו אליהם בצדק. החושך החשיך את לבות אויביו, אלה שעשו עצמם אויבים לאמת. הרוח התחזקה כדי להרים את קולו, ולהעבירו אל כל השומעים. האש גברה ובערה בהדר כדי לשתול חכמה בלבות החכמים. המים כרעו לפניו והקשיבו לדבריו, וגם היסודות עמדו שם כדי לכבדו. שני המאורות והכוכבים היו כמותם במה שעשו, ואף אחד לא נבדל מרעהו. שים לב, אל תהי אויב לאלה, כי לאחר שהיית מלך תהיה עבד. שים לב, אל תהי אויב לאלה, כולם יניחוך בצרה גדולה. שים לב, אל תהי אויב לאלה, פן תהא למטה ואויבך למעלה. שים לב, אל תהי אויב לאלה, פן תהא בעוני וכולם יתלוננו עליך, ולא תהא לך שליטה בהם.');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (231,'IV','30','מימר על שירתה רבתה',4000301,'ונצפי איך קרא משה מלת וישר ושררה במימרה הוא אמלך לשמה דחדד בריתה בשתתי יומיה וכד חכם משה מן מרה רבין דן שמה אמר הוא הודע דהוא מקדם עלמה ועמה ובתרה והוא אחד לקלומה לית עמה אל עורן נרכן לקדמיו ונסיד ונימר לית אלה אלא אחד אישה משה משרי ומוכח לעלמה וכל ישראל קעם ושמע לא אוכח אלא מבתר ממלל מריח לאלה יגדלו טביה בה צמת חילי שומיה וארעה ועבדון שרוי הך מה דעבד אלה ותעתידה דלחייה מרבי מה הו מן שרואה עתיד לסעד לבה דברנשה וכן אמר אלה חיים ומות תעתיד אדם ותעתיד משה אדם אכל למותה עתד משה צעם לחייה עתד','Let us observe how Moses recited the word וישרand reinforced it saying 
( הואDeut. 32:4) – he indicated the Name that performed the Creation during the 
Six Days. When Moses learned from his Master the majesty of this name (Exod. 
3:14), he said – הואhe made known that (God) exists from before the world and is 
with it and (will exist) afer it. And He is One to Himself, there is no other god 
with Him. Let us bow down before Him and testify and say: “There is no god but 
One.” The man Moses began to reprove the world, while Israel stands and lis-
tens. He did not reprove except [afer a statement pleasing God, by which the 
good ones are elevated. He assembled the hosts of heaven and earth and made 
them a beginning, as did God. The Nourishment elevates life (according to) what 
it is. From the beginning it is designated to nourish the mind of man, and thus 
said God: Life and death (Deut. 30:19). The nourishment of Adam and the nour-
ishment of Moses: Adam ate (the forbidden fruit) – he prepared death; Moses 
fasted (when receiving the Law) – he prepared life.','נתבונן כיצד אמר משה את המילה וישר וחיזקה באומרו הוא (דברים לב,ד) – הצביע על השם שפעל את הבריאה בששת הימים. כאשר למד משה מאדונו את גדולת השם הזה (שמות ג,יד), אמר – הוא הודיע כי אלוהים קיים מלפני העולם ועמו ואחריו. והוא אחד לעצמו, אין אל אחר עמו. נשתחווה לפניו ונעיד ונאמר: "אין אלוה כי אם אחד". האיש משה החל להוכיח את העולם, כשישראל עומד ושומע. לא הוכיח אלא לאחר דבר הנוח לאלוהים, שבו מתרוממים הטובים. כינס את צבאות השמים והארץ ועשה מהם ראשית, כפי שעשה אלוהים. המזון מרומם את החיים לפי מהותו. מראשיתו הוא מיועד להזין את שכל האדם, וכך אמר אלוהים: החיים והמוות (דברים ל,יט). מזון אדם ומזון משה: אדם אכל (מן הפרי האסור) – הכין מוות; משה צם (בקבלת התורה) – הכין חיים.');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (232,'IV','82','מימר על שירתה רבתה',4000821,'עמו נביה רבה משה הך הו מחדד ממללה דארש יתה לגו עסרתי מליה דפרטון יצב גבולות וקטרה במימרה למספר בני ישראל ויהי זרעך ככוכבי שומיה תרין עסר לעל ותרין עסר לרע וכד אמר ככוכבי שומיה ליתון צרכים לפרנוסון לעלם כל אמי עלמה לא תורה ולא מצוה מכן מדברין בכוכביה והתורה והמצוה היא בידך אה ישראל צפי לבלעם ומה בעה יעבד כד לא הוה על קשטה אתפך בקשט קלץ גרמך בקשטה לא יכל עליך דבב אלא הן הקימת גרמך בתחמדה בישה קטר קנומך על קשטה וטר מצוהתה עד תפרה ותרבה ותסתחן ית ארעה וכל דאלין תחומיה פרישין מן ימי פלג כי בימיו נפלגה הארץ','See the great prophet Moses, how he renews the word on which he 
founded the ten words that he detailed. (The ﬁrst statement): He ﬁxed the bound-
aries (Deut. 32:8) – which he connected with his word: according to the number 
of the Israelites (ibid.). And your descendants shall be as the stars of heaven 
(Gen. 28:14; 22:17), twelve (stars) above and twelve (tribes) below. When He said: 
As the stars of heaven, (he meant that) they did not need their government ever. 
All the nations of the world are without law or commandment, therefore they are 
led by the stars, while the Law and the precepts are in your hand. O Israel, con-
sider Balaam and what he sought to do. When he was not (behaving) according 
to the True One, he was reversed by the truth. Join yourself to the True One, and 
no enemy will have power over you, unless you establish yourself in evil desire. 
Bind yourself to the True One and keep the precepts, that you may increase and 
multiply and possess the land and so on (Exod. 23:30). For these boundaries are 
appointed from the days of Peleg, for in his days the earth was divided (Gen. 
10:25).','ראו את הנביא הגדול משה, כיצד הוא מחדש את הדבר שעליו ביסס את עשרת הדברים שפירט. (האמירה הראשונה): הוא קבע גבולות (דברים לב,ח) – שחיבר עם דברו: לְמִסְפַּר בְּנֵי יִשְׂרָאֵל (שם). וְזַרְעֲךָ יִהְיֶה כְּכוֹכְבֵי הַשָּׁמַיִם (בראשית כח,יד; כב,יז), שנים עשר (כוכבים) למעלה ושנים עשר (שבטים) למטה. כשאמר: כְּכוֹכְבֵי הַשָּׁמַיִם, (התכוון ש)הם לא נזקקו לממשלתם לעולם. כל עמי הדונים עולם חסרי חוק ומצווה, לפיכך הם מונהגים על ידי הכוכבים, ואילו התורה והמצוות נתונות בידכם. הֵן ישראל, בחנו את בלעם ואת אשר ביקש לעשות. כשלא נהג לפי האמת, הופך על ידי האמת. הידבק אל האמת, ולא יהיה לשום אויב שלטון עליך, אלא אם כן תתמקם ביצר הרע. קשור את עצמך אל האמת ושמור את המצוות, למען תרבה ותפרה ותירש את הארץ וכן הלאה (שמות כג,ל). כי גבולות אלה נקבעו מימי פלג, שכן בימיו נחלקה הארץ (בראשית י,כה).');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (233,'IV','49','מימר על שירתה רבתה',4000491,'וכדו אפתח פמי ואשרי בתשבחתך לגו הדה שירתה בארשו מדילך הליהוה רביאן ליתו משתאם חכמה נביה רבה משה לזרע יעקב עמי מדעה שמינה אך אמר הדה מלתה ועבדה ארש בתשבחתה שרה בה בעה בדן זבוג תרי שמהתה כחדה אלהים ויהוה בראשית ואדם בריתה וצורתה כללו תשבחתה שבח אדם אתוקרת בריתה שבח משה חדו מלאכיה ואמרו למימר שבחו ליהוה כבודה וכל מלאכיה תמן שבחו והבו גדל לאלהינו דדאמר תמן חדדה אכה הליהוה כלה בה הגדל מן בראשית הוא וכן הוא ביום נקם קשטה אמר וידבר אלהים יסדי בריתה ארתתו וכד אמר אני יהוה כל ישראל דחלו וכד אמר הליהוה ארכנו בוראיה וכל ישראל לתשבחתה לבדיל אמר וידבר משה באזני כל קהל ישראל והפך ואמר האזינו השמים ותשמע הארץ צמת כלה ואמר הליהוה בתשבחתה צמת עלאי וארעי בדיל תשבחתה למר עלמה בדיל כן נברך למרן וטובינן בכן דו רחמן ורתאי מיטב לרחמיו ומרוח למן לה משבח','And now I shall open my mouth and begin to praise You in this Song 
with Your permission: To the Lord (Deut. 32:6) – inestimable magniﬁcence. The 
great prophet taught it to the descendants of Jacob. Contemplate his fertile mind, 
how he said this word and made it a foundation of the praise. He started with it, 
seeking to join the two names אלהיםand .יהוהGenesis and Adam, the Creation 
and the Form, completed in praising. Adam praised – Creation was made glori-
ous. Moses praised – the angels rejoiced: and they said, Praise the Lord (Exod. 
15:1). The Glory and all the angels then praised: ascribe greatness to our God 
(Deut. 32:3). What he said there he renewed here: to the Lord (v. 6) – all is 
magniﬁed by Him. It is from the Beginning and likewise it will be on the Day of 
Vengeance. The True One said: And God spoke (Exod. 20:1), and the foundations 
of Creation trembled. When He said: I am the Lord (Exod. 20:2), all Israel was 
afraid. When he said: the Lord, the people and all Israel prostrated to praise Him, 
because He said: Then Moses spoke in the ears of all the assembly of Israel (Deut. 
31:30), and further he said: Give ear, O heavens (Deut. 32:1), and let the earth hear 
(ibid.), he included them all when he said: to the Lord (v. 6). In his praises he 
included heaven and earth, because he was praising the Master of the world. 
Therefore, let us bless our Master. Happy are we in this, for He is merciful and 
full of pity, doing good to His beloved and giving relief to those who praise Him.','ועתה אפתח את פי ואחל לשבחך בשירה זו ברשותך: לה'' (דברים לב,ו) – גדולה שאין לה שיעור. הנביא הגדול לימד אותה לצאצאי יעקב. התבונן בפוריות מחשבתו, כיצד אמר את המילה הזו ועשה אותה יסוד השבח. פתח בה, שביקש לחבר את שני השמות אלהים ויהוה. בראשית ואדם, הבריאה והצורה, הושלמו בשבח. אדם שיבח – הבריאה נתעטרה. משה שיבח – המלאכים שמחו: ויאמרו שירו לה'' (שמות טו,א). הכבוד וכל המלאכים אז שיבחו: הבו גודל לאלוהינו (דברים לב,ג). מה שאמר שם חידש כאן: לה'' (פסוק ו) – הכל מתעלה על ידו. כן היה מהתחילה וכן יהיה ביום הנקמה. האמיתי אמר: וידבר אלהים (שמות כ,א), ויחרדו יסודות הבריאה. כאשר אמר: אנכי ה'' (שמות כ,ב), פחד כל ישראל. כאשר אמר: ה'', כרעו העם וכל ישראל לשבחו, כי אמר: וידבר משה באזני כל קהל ישראל (דברים לא,ל), ועוד אמר: האזינו השמים (דברים לב,א), ותשמע הארץ (שם), וכללם כולם כאשר אמר: לה'' (פסוק ו). בשבחיו כלל את השמים ואת הארץ, כי שיבח את אדון העולם. לפיכך נברך את אדוננו. אשרינו בזאת, כי הוא רחום ומלא רחמים, עושה טוב לאהוביו ומביא הקלה למשבחיו.');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (234,'IV','72','מימר על שירתה רבתה',4000721,'מלתה שביעיתה יאכלהו תנופת שדה ויהי כד יעלנך יהוה אלהיך ליד ארעה דאשתבע לאבהתך לאברהם ליצ וליעקב ותשקח תמן כל טוב יתר הרגריזים בה כל בר } י { כה כד תמטי אל תמן תשקח איקר ותיזף גוים ותמלך מדה לון דאה ממלכה שלמה , ליתה מתחלפה נודי לאלה דכל רבינה דילה ונרבי למשה רבה הך מד לאוי לגדלה','The seventh statement: He will feed him with the produce of the ﬁeld (SP 
Deut. 32:13), when the Lord your God brings you into the land that He swore to 
your fathers, Abraham, Isaac, and Jacob (Deut. 6:10) and you will ﬁnd there every 
exceeding good: Mount Gerizim, in which there is every blessing. When you 
arrive there, you will ﬁnd glory and you shall lend to nations (Deut. 15:6) and 
possess their possession. This is a perfect kingdom that will not change. Let us 
give thanks to God to whom majesty belongs, and exalt Moses the great, as is 
appropriate to his greatness.','האמירה השביעית: וַיַּאֲכִלֵהוּ תְּנוּבֹת שָׂדַי (ספ דברים לב,יג), כַּאֲשֶׁר יְבִיאֲךָ יְהוָה אֱלֹהֶיךָ אֶל הָאָרֶץ אֲשֶׁר נִשְׁבַּע לַאֲבֹתֶיךָ לְאַבְרָהָם לְיִצְחָק וּלְיַעֲקֹב (דברים ו,י), ותמצא שם כל טוב נעלה: הר גריזים, שבו כל ברכה. כשתגיע לשם תמצא כבוד, וְהִלְוִיתָ גּוֹיִם רַבִּים (דברים טו,ו), ותירש את אחוזתם. זוהי ממלכה שלמה שלא תשתנה. נודה לאל אשר לו הגדולה, ונרומם את משה הגדול, כראוי לגדולתו.');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (235,'IV','62','מימר על שירתה רבתה',4000621,'בנים לא האמן בם זמרי זנאה נסיא בית אב הא נסיא ביש מן שבט רשי עמי ממלל יעקב דאמר בדילה בשותפו הלא ברגזון קטלו מלך מכן עזר קשטה ממללה בנביו מן גנב לב אבוה לית לה אימנו ולא אחס על אחיו מן דאה יהי מנה מן סכה במדעה דו מתרע סיג קשטה מה דאה תהי עקבהיתה אלולי רתות אלה על זכות יוסף ומד לה ולאביו דהוה שמעון כקין מכן אתמר בנים לא האמן בם אוכח לכהלון בגנות שמעון ועוד ראובן ומה דעבד לאבוה גנב זכותה וטמא משכבה מכן אמר בנים לא אמן בם דאנון תרים הזדוגו באוכחותה זכותה לדיאנה דליתו נסב אפים ולא מנשי עמל מגלג בטביה ומגני בבישהתה טביה ירומו ובישיה יפלו איך משה לא קם לעלם דחכמנן אורח קשטה','Children in whom is no faithfulness (Deut. 32:20) – Zimri the fornicator, 
chiefain of a father’s house (Num. 25:14). Behold an evil chiefain from an evil 
tribe. See the word of Jacob who said concerning him, “in association”: For in 
their anger they slay (Gen. 49:6) a king. Therefore the True One repeated the 
speech in the “prophecy”: “He who defrauds his father has no faith and has no 
compassion for his brother.” What will become of him? He who thinks in his 
mind that he will break the fence of the True One, what will his end be? If it had 
not been for God’s mercy, on account of Joseph’s merit, his and that of his father, 
Simeon would be like Cain. Therefore it was said: Children in whom is no faithful-
ness (Deut. 32:20). He reproved them all for the blame of Simeon, and of Reuben 
too, for what he did to his father: he stole away his rights and polluted his bed. 
Therefore He said: Children in whom is no faithfulness, for they are two coupled 
together in the reproof. Righteousness belongs to the Judge who shows no par-
tiality and who does not overlook any act, he praises the good and condemns the 
evil. The good are exalted and the evil debased. There has never arisen anyone 
like Moses, who has taught us the way of the True One.','בנים לא אמון בם (דברים לב,כ) – זמרי המנאף, נשיא בית אב (במדבר כה,יד). הנה נשיא רע משבט רע. ראה את דברי יעקב שאמר עליו, ב"שיתוף": כי באפם הרגו (בראשית מט,ו) מלך. לכן שנה האמיתי את הדברים ב"נבואה": "המרמה את אביו אין בו אמונה ואין לו רחמים על אחיו." מה יהיה עליו? מי שחושב בדעתו לפרוץ את גדרו של האמיתי, מה תהיה אחריתו? לולא רחמי האל, בזכות יוסף, הן שלו הן של אביו, היה שמעון כקין. לכן נאמר: בנים לא אמון בם (דברים לב,כ). תוכח את כולם בגלל חטאו של שמעון, ושל ראובן גם הוא, על מה שעשה לאביו: גנב את בכורתו וטימא את מיטתו. לכן אמר: בנים לא אמון בם, כי שניהם צמודים יחד בתוכחה. הצדק שייך לשופט שלא ישא פנים ואינו מתעלם מאף מעשה, המשבח את הטוב ומגנה את הרע. הטובים מתעלים והרעים משפלים. לא קם כמשה, שלימד אותנו את דרך האמיתי.');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (236,'IV','89','מימר על שירתה רבתה',4000891,'איך ירדף אחד אלף אנן אנון לא חיל ולא מלך ולא נסיא ולא יכלה ולא מן יסלח לנן ולא כהנה רבה מקרב על מדבחה ריח רחוה ליהוה למשכנה חסכנן כיין בטלנן קשטה ועלמנן על זכותה וית פגרינן לא דכינן לכנינן קללנן אלולי עזרנן ליד מרן בתתובתה אדכיה עזר כל איקרה דחסכנן לה ולא שלט בנן דבב וקיאם יהוה דקיאמה לאבהתינן יקום לנן ונפלו איביכם לפניכם לחרב והפך ואמר ושנים יינסו רבבה וכשלו איש באחיו כמפני חרב מלה מרירה ורודיף אין ולא יהיה לכם תקומה לפני איביכם אהן צדוה רבה להאן ייזל חיבה במן יתרחץ במן יתחיד הן הוה מרה רגז עליו מן מרד מרה מן יאחס עליו מן כפר בעבודה מן יפרקנה מן אדה מן שבקה מרה מנו דרתי לה לית אמי עלמה משתאלים על עובד כי יתון לא אזדעקו גוי קדש ובן בכור ולא שמעו קול אלה חיים מדבר וילה מרודה דעבד בישתה בכל שרוה ייתי תהבה בשלם לעלמה ויסטי כל ערבוב דבה איך משה לא קם ולא יקום לעלם מהימן אלהים ובר ביתה','How should one chase a thousand (Deut. 32:30) – this refers to us: no 
army, no king, no prince, no power. (We have) no one to atone for us and no high 
priest to oﬀer pleasing odor to the Lord on the altar. We lack the Sanctuary. 
Indeed, we abrogated the truth and ignored the righteousness and did not purify 
our bodies, we degraded our status. Had we returned to our Master in pure re-
pentance, all the honor that we lack would have returned, and no enemy would 
prevail against us, and the covenant of the Lord that He swore to our ancestors 
would have been valid for us: Your enemies shall fall before you by the sword (Lev. 
26:8). And he said again: Two will put ten thousand to ﬂight (Deut. 32:30), they 
shall stumble over one another as before the sword (Lev. 26:37) – a bitter word. 
Though none pursues and you shall have no power to stand before your enemies 
(Lev. 26:37) – this is a great dread. Where should the sinner go, whom should he 
trust, whom should he cling to, when his Master is in anger with him? He who 
rebels (against) his Master, who has pity on him? He who denies his Maker, who 
will deliver him from His hand? He whom his Master abandoned, who will pity 
him? The nations of the world are not quizzed about any deed, for they have not 
been called “a holy nation” and “ﬁrstborn”, and they have not heard the voice of 
the Living God speaking. Woe to the rebel who has done evil with all his might. 
Let the Taheb come in peace to the world and remove every blemish in it. Like 
Moses, none has arisen and will never arise, the faithful of God and Son of His 
house.','כיצד יִרדֹּף אחד אלף (דברים לב,ל) – זה מכוון אלינו: אין צבא, אין מלך, אין שׂר, אין עוצמה. אין מי שיכפר עלינו ואין כוהן גדול שיקריב ריח ניחוח לה'' על המזבח. חסר לנו המקדש. אכן, ביטלנו את האמת והתעלמנו מן הצדק ולא טיהרנו את גופינו, השפלנו את מעמדנו. אילו שבנו אל אדוננו בתשובה טהורה, היה כל הכבוד שחסר לנו חוזר, ולא היה שום אויב גובר עלינו, והברית שנשבע ה'' לאבותינו הייתה קיימת עבורנו: ונפלו אויביכם לפניכם לחרב (ויקרא כו,ח). ועוד אמר: שניים יַנִּיסוּ רבבה (דברים לב,ל), ונפלו איש על אחיו כלפני חרב (ויקרא כו,לז) – דבר מר. ורדפתם אויביכם ולא יהיה לכם כוח לעמוד לפני אויביכם (ויקרא כו,לז) – זוהי אימה גדולה. לאן ילך החוטא, בְּמִי יבטח, בְּמִי יִתְדַּבֵּק, כאשר אדונו כועס עליו? מי יחמול על מי שמורד באדונו? מי יַציל ממידו את מי שכופר ביוצרו? מי יחמול על מי שאדונו עזבהו? אומות העולם אינן נחקרות על שום מעשֶׂה, שהרי לא נקראו "גוי קדוש" ו"בכור", ולא שמעו את קול האל החי מדבר. אוי למורד שהרע בכל מאודו. יבוא הַתָּאֵב בשלום לעולם ויסיר ממנו כל מום. כמשה לא קם ולא יקום לעולם, נאמן האל ובן ביתו.');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (237,'IV','95','מימר על שירתה רבתה',4000951,'ובישיה דלקבל כד תסק ריחון בישה מן עפר חסרה וגפרי ואש מחרברב בה לא מתקבל ותכסיהתון מקדדין ואפיון זעיפין יתמר לון למה אפיכון בישהן יומה וקין ולמך ואנשי המבול ואנשי בבל ואנשי סדם ומצראי ועמלקאי וקרח וכל סיעתה ומגמריון , באדיהון מועדין עליהון ומלאכי רגזה שרין בון ועבקה ועפרה נחת מן שומיה אליון וקבל אפיל בעיניון ונביה רבה משתבק מנון ואהרן ובניו מזדכי ] ן מ [ נון וזכאי ] על [ מה לא פנין אליון ואשתה רבתה מוקדה פגריון כמה דאמר ותבער בם אש יהוה ואלה לא יאחס עליון ואנון נביכים ועלמה סגיר עליון וקשטה אמר אשכיר חצי מדם וחרבי תאכל בשר אדה הי עקובאת חיביה ביום דינה','And the evildoers, on the other hand, when their bad odor issues from 
the stinking dust, with which brimstone and ﬁre are mingled, will not be accept-
ed. And their garments torn, and their faces distressed. It will be said to them: 
Why are your faces downcast today? (Gen. 40:7) And Cain and Lamech and the 
people of the Flood, and the people of the Tower and the people of Sodom and 
the Egyptians and the Amaleqites and Korah and all his party,] with their censers 
in their hands, assembled (around) them. And the angels of wrath dwell among 
them, and powder and dust descend from heaven over them, and obscure 
darkness in their eyes. And the great prophet is distanced from them, and Aaron 
and his sons are clear of them, and the Righteous of the world do not turn 
towards them, and the great Fire burns their bodies, as He said: a ﬁre of the Lord 
broke out against them (Num. 11:1). And God will not show mercy for them, and 
they will be confused, as the world shut them in. The True One said: I will make 
My arrows drunk with blood and My sword will devour ﬂesh (Deut. 32:42). This is 
the end for the sinners on the Day of Judgement.','ואילו הרשעים, לעומת זאת, כאשר ייצא ריחם הרע מן העפר המסריח, שגפרית ואש מעורבות בו, לא יהיו מקובלים. ובגדיהם קרועים ופניהם עצובות. ייאמר להם: "מַדּוּעַ פְּנֵיכֶם רָעִים הַיּוֹם" (בראשית מ,ז)? וקין ולמך ואנשי המבול, ואנשי המגדל ואנשי סדום והמצרים והעמלקים וקורח וכל עדתו, עם מחתותיהם בידיהם, נאספים סביבם. ומלאכי החרון שוכנים בתוכם, ואפר ועפר יורדים מן השמים עליהם, וחשכה אפלה בעיניהם. והנביא הגדול מתרחק מהם, ואהרן ובניו נקיים מהם, וצדיקי עולם אינם פונים אליהם, והאש הגדולה שורפת את גופם, כפי שאמר: "וַתִּבְעַר בָּם אֵשׁ ה''" (במדבר יא,א). והאלוהים לא ירחם עליהם, ויהיו נבוכים, כאשר העולם יסגר עליהם. האמת אמרה: "אַשְׁכִּיר חִצַּי מִדָּם וְחַרְבִּי תֹּאכַל בָּשָׂר" (דברים לב,מב). זהו הסוף לחוטאים ביום הדין.');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (238,'IV','29','מימר על שירתה רבתה',4000291,'אמר מלת וישר מלה פרידה לית ל ] ה [ תניאן › מן ‹ שרואה ועקבה לאלה ומשה לית לעורן לגוה נמי שרואה בריה מחכמה יכלו ] ו [ חס ] ו [ לה נביו ] מתרביה בק [ שטה ] לית צ [ ריך ] תבקר על מ [ ליה דקמיך מלים מליה בוננו לבך בך ינהר וישכיל למדעך וירבי חכמתך ספר טב אתה טר ספרותך עד תרום ותתנשא חכים לא דרש מה הנאה בה לביתה יעזר לא יקום במשכנה כהן בה מום לא יקרב למשכנה מומה בברנשה אי בעין אי באבר לקנומה הוא לית באנש לה חלק ליתו מסעד קהלה לא בחיל ולא בנצחן אלה מסעדון מד אנון מצלחין יהוה יגיע לכון לא צריך לחכמים במעמון נצח ] ן [ ] מ [ סעדין לון כן משה לא זעק לחכימיה ורישי שבטיה וסרפיה אלא למלפה ולאזהרו מן מחלפה ממה פקד יהוה ויתב משה למדין בעמה אלף חכימיה וחכימיה ילפו לקהלה וכד ארשה משה למשקי ית עמה כנש ית קהלה קדם › ת ‹ קפה ואפק מנה מימים תמן אמיר לה סב עמך מן חכימי ישראל בריך מרן מרבי רחמיו ומעיני יתון בכל הלכתון מד אנן צריכים למרבאה חיינן נקום על קשטה ומנה לא נפק','He said the word ,וישרand right, (Deut. 32:4) – a unique word that has no 
peer. The beginning and the end (refer) to God and Moses; no other shares in it. 
The beginning is Creation manifesting might, and the end prophecy exalted with 
truth. There is no need to inquire about the words, for before you there are words 
full of insight, (that) will enlighten your heart inside you and teach your mind 
and increase your wisdom. If you are a good teacher, guard your teaching, that 
you may be exalted and elevated. A wise man who does not inquire, what is his 
beneﬁt? He returns to his home and has no position within the Sanctuary. A 
priest who has a blemish is not to approach the Sanctuary. The blemish in a 
man, whether in an eye or in (another) organ; it is in himself, nobody has a part 
in it. He does not assist the congregation, neither in host nor in battle. God 
assists them when they succeed: The Lord will battle for you (Exod. 14:14); there 
is no need for the wise men, when they see battle (Exod. 13:17), to assist them. 
Thus Moses did not summon the wise men and the chiefains of the tribes, and 
the teachers, except to teach and to warn against altering what the Lord com-
manded. Moses sat to judge the people (Exod. 18:13) – he taught the wise men, so 
that the wise men in turn will teach the congregation. And when Moses was 
commanded to give the people to drink, he assembled the congregation before 
the rock and brought forth waters from it. Then it was said to him: Take with you 
some of the elders of Israel (Exod. 17:5), blessed be our Master, who increases his 
mercy and guards them in all their walking. As we need to increase our life, let 
us stand with the True One and not depart from Him.','אמר את המילה וישר, ונכון (דברים לב,ד) – מילה ייחודית שאין לה אח ורע. הראשית והאחרית מתייחסות לאלוהים ולמשה; אין אחר שותף בהן. הראשית היא הבריאה המגלה עוז, והאחרית נבואה המרוממת באמת. אין צורך לחקור את המילים, שכן לפניך מילים מלאות תובנה, שיאירו את לבך מבפנים וילמדו את שכלך וירבו את חכמתך. אם אתה מורה טוב, שמור על לימודך, למען תינשא ותתרומם. חכם שאינו חוקר, מה תועלתו? שב הוא לביתו ואין לו מעמד בקודש. כהן שיש בו מום אינו רשאי לגשת אל הקודש. המום שבאיש, בין בעין בין בשאר אבר – הוא בו עצמו, ואין לאחר חלק בו. הוא אינו עוזר לעדה, לא בצבא ולא בקרב. אלוהים עוזר להם כאשר הם מצליחים: ה'' ילחם לכם (שמות יד,יד); אין צורך לחכמים, כשהם רואים מלחמה (שמות יג,יז), לסייע להם. כך לא זימן משה את החכמים וראשי השבטים והמורים, אלא ללמד ולהזהיר מלשנות את אשר ציווה ה''. וישב משה לשפוט את העם (שמות יח,יג) – לימד את החכמים, כדי שהחכמים ילמדו בתורם את העדה. וכשנצטווה משה להשקות את העם, כינס את העדה לפני הסלע והוציא ממנו מים. אז נאמר לו: קח אתך מזקני ישראל (שמות יז,ה) – ברוך אדוננו המרבה חסדו ושומר עליהם בכל מהלכם. כשם שעלינו להרבות חיינו, נעמוד עם האמת ולא נסור ממנה.');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (239,'IV','46','מימר על שירתה רבתה',4000461,'ואולם אנחן בני נח מבתר טובה לא אתילדנן בעדן מבולה אנן בני אברהם בתר דאתגזר לא אתילדנן ותמן ערלה לא נדמי בעובד לבני ישמעאל לית מרן רצי בכן ויהב אברהם ית כל דלה ליצחק בנו נגדד קמי קשטה ונקים לישמעאל מן אבוה חלק במה נעבד כן גנו עלינן הן עבדנן חדה אנן בני יצחק מבתר ברכתה נשבק אתרה שמם למה כן לית לעשו נמי בבכורתה דלן נקים } לן { » לה « נמי לא יהי כן מן זבן בכירתה בתאות נפשה נעזר לה נמי למה יהי כן אנן בני יעקב דאתמר עליו תם ישיב האהלים ומה היא האהלים אהל יצחק ואהל אברהם נשבק חכמתה לא יהי כן אנן בני יוסף מבתר נסיון נשבק מלכותה לא יהי כן','Yet we are the descendants of Noah, following the good. We were not 
born at the time of the Flood. We are the sons of Abraham following his circum-
cision, we were not born while foreskin still was there – let us not resemble in 
this respect the sons of Ishmael. Our Master would not be pleased with that – 
Abraham gave all he had to Isaac his son (ST Gen. 25:5). Should we rebel against 
the True One, and give Ishmael a share from his father? Why should we do that? 
Shame on us if we do so. We are the descendants of Isaac following the Blessing. 
Shall we leave his place desolate? Why so? Esau has no part in the birthright that 
is ours. Shall we establish a portion for him? It is not appropriate. He who sold 
his birthright for his own lust – shall we return a portion to him? Why should 
this be so? We are the descendants of Jacob of whom it was said: A quiet man, 
dwelling in tents (Gen. 25:27). And what is tents? The tent of Isaac and the tent of 
Abraham. Shall we abandon his knowledge? It would not be appropriate. We are 
the descendants of Joseph following trial. Shall we leave his kingdom? That 
would not be appropriate.','אולם אנו צאצאי נח ההולכים בדרך הטוב. לא נולדנו בזמן המבול. אנו בני אברהם ההולכים אחר מילתו, לא נולדנו בעוד הערלה שם — לא נדמה בזה לבני ישמעאל. אדוננו לא ישמח בכך — אברהם נתן את כל אשר לו ליצחק בנו (תרגום שומרוני בראשית כה,ה). האם נמרוד באמת ונתן לישמעאל חלק מאביו? מדוע נעשה כן? בושה לנו אם נעשה כך. אנו צאצאי יצחק ההולכים אחר הברכה. האם נעזוב את מקומו שממה? מדוע? לעשו אין חלק בבכורה שהיא שלנו. האם נחצה לו נחלה? אין זה הולם. מי שמכר את בכורתו בעד תאוותו — האם נשיב לו חלק? מדוע יהיה כן? אנו צאצאי יעקב אשר נאמר עליו: אִישׁ תָּם יֹשֵׁב אֹהָלִים (בראשית כה,כז). ומהם האוהלים? אוהלו של יצחק ואוהלו של אברהם. האם נעזוב את ידיעתו? לא יהיה זה הולם. אנו צאצאי יוסף ההולכים אחר הניסיון. האם נעזוב את מלכותו? לא יהיה זה הולם.');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (240,'IV','61','מימר על שירתה רבתה',4000611,'נסגד ארצה קמי עבודן וקניאן ונדמי לנביה רבה משה כד עקד וסגד ונזין לה והו ממלל מכעוס בניו ובנותיו בבישו ויתפרקו כל העם את נזמי הזהב מן בניה ומן בנהתה כחדה מכן אתקטלו בפרי וכן אתעבד במדין כל אתה דהות בעילת בעל די שרוי בישתה פרקו את נזמי הזהב אשר באזני נשיכם ברתה דלא לה גבר לא עלת לגון מכן אמר בניה ובנהתה נשיה וגבריה דאצטמתו על בישתה יתודי ממנה הממן בחיי עולם עם כל דר וחלופה נודינה על רב טובה וחסדה דשלח נביא צדיק גלה לן כל איקר','Let us bow to the ground before our Maker and Creator and let us 
resemble the great prophet Moses when he bowed and worshipped. Let us listen 
to him as he says: Because of the vexation of His sons and His daughters (Deut. 
32:19) – through evildoing. So all the people took oﬀ the rings of gold (Exod. 32:3) 
– from sons and daughters together. Thus they were instantly slain. And thus it 
happened in Midian. Every woman who was married – for she is the beginning 
of the evildoing: Take oﬀ the rings of gold which are in the ears of your wives 
(Exod. 32:2). The daughter with no husband was not included among them. 
Therefore He said: Sons and daughters (Deut. 32:19) – the women and the men 
who gathered for the evildoing. Thanks be given to the Eternal One, who endures 
in everlasting life with all generation and its successions. Let us give thanks to 
Him for His abundant goodness and grace, who sent a righteous prophet who 
revealed to us all glory.','נשתחווה ארצה לפני יוצרנו ובוראנו ונדמה לנביא הגדול משה בשעה שהשתחווה ויקד. נשמע אליו כאומרו: מכעס בניו ובנותיו (דברים לב,יט) – מתוך הרשעה. ויתפרקו כל העם את נזמי הזהב (שמות לב,ג) – מבנים ומבנות יחדיו. כך נהרגו מיד. וכן היה במדין. כל אישה נשואה – שהיא ראשית הרשעה: התפרקו נזמי הזהב אשר באזני נשיכם (שמות לב,ב). הבת שאין לה איש לא נמנתה בתוכם. לכן אמר: בנים ובנות (דברים לב,יט) – הנשים והאנשים שנקהלו לרשעה. תודה תינתן לאחד העולמים, שקיים בחיי עולם עם כל דור ותמורותיו. נודה לו על טובו הרב וחסדו, שלח נביא צדיק שגילה לנו את כל הכבוד.');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (241,'IV','34','מימר על שירתה רבתה',4000341,'עמו הך נביה רבה משה משרי במלי נביותה וכל ישראל מזדמן לידה אמר זכרו יומת עולם אודע הן כל מתחדד הוא שאב לעקרה בריתה במלה אתחדדת ובמלה תעזר בראשית השתרית בב לא בא אלו הות בא לא הות חדתה כי אלה עבד א שרוי כירה וב אכהן גלת למדעיה דקדמה אקר מתרכס עליו עורנה מכן חכמנן נביה מהימנה הן חדת מבני על אקר והוא כריה דמשתוקה ולידה הוא מעזר מכן עבד אלה כל בוראיה באשתה יומים ושבת ביומה שביעיה יהי לך אן תחכם יומה חראה ותעבד עובד ינשמך תמן וילה לאנש דלא מקדם קמיו עובד יהי טמיר לה תמן הך משה לא קם ולא יקום חכם בראשית ויום נקם והוא מלוא באהן ובאהן','See how the great prophet Moses begins with words of prophecy, when 
all Israel gathered to him. He said: Remember the days of old (Deut. 32:7) – he 
made known that everything created returns to its original state (of rest). 
Creation was innovated by the word and by the word will return. בראשיתbegan 
with the letter ,בnot with .אIf it had been with ,אit would not have been 
innovation, for God made אthe beginning of writing, and בhere reveals to the 
mind that a radical precedes it, joined to it. Therefore, the faithful prophet 
taught us that innovation is founded on an origin (which) was the base of the 
silence, to which it returns. For this reason God made all creatures in six days 
and rested on the seventh day. It is proper to you to know about the last day and 
do action that will give you rest on it. Woe to any man who does not advance an 
action that will be stored for him then. Like Moses none has arisen nor will arise. 
He knew the Beginning and the Day of Requital, and he is appointed on both.','ראה כיצד פותח הנביא הגדול משה בדברי נבואה, כאשר נאסף אליו כל ישראל. אמר: זְכֹר יְמוֹת עוֹלָם (דברים לב,ז) – הודיע שכל הנברא שב למצבו המקורי של מנוחה. הבריאה חודשה בדיבור ובדיבור תשוב. בְּרֵאשִׁית פתחה באות ב ולא ב-א. אם הייתה פותחת ב-א, לא הייתה זו חידוש, שכן האל עשה את ה-א ראשית הכתב, ואילו ה-ב כאן מגלה לשכל שקדמה לה שורש הצמוד אליה. לפיכך לימד אותנו הנביא הנאמן שהחידוש מיוסד על מקור שהיה בסיס הדממה, אליה הוא שב. משום כך ברא האל את כל הברואים בששה ימים ונח ביום השביעי. ראוי לך לדעת על היום האחרון ולעשות מעשה שיניח לך בו. אוי לכל אדם שאינו מקדים מעשה שיהיה שמור לו אז. כמשה לא קם ולא יקום. הוא ידע את הראשית ואת יום הגמול, והוא ממונה על שניהם.');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (242,'IV','66','מימר על שירתה רבתה',4000661,'ועמי תלתה כנשו אוצרי טובה נח צמת מן שביל זכותה מה אזדאנו בה נפשהתה דבחרון מרון וחנוך עורי פתח אוצר זכותה וזאן נפשה מן מזון חיי עולם ואנוש פתח אוצר תשבחתה וכרז בשם יהוה מכן הוה זרעה כהלה שלמיה עמי אלין תלתיתה ומה עבדו והדמי לון והזדאן ממה אזדהנו ותלתה בתרון ועבדו כות עובדיון וקעמו לקבל קשטה ועבדו בנצירו אברהם ויצחק ויעקב שלמיה פרנסו ארעה דזכותה ] וב [ ה זרעו סלק ואדגן , בר ] כ [ ן ועלת מ ] נו [ ן ] או [ צרין ] ט [ ב ] הוא [ זרעה דאברהם דסלק מנה קרבן מרחי ולא השפך לה אדם יצחק הגדל והגמל באלפן אבוה אתיהב לה תלתה ברכהן רברבהן יעקב התהלך בדאה שבילתה הוה גבר שלם אלין תלתיתה הכללו בכל איקר והוו פריקין לכל דריה ודכרנון לא מתנשי','And see three who gathered the treasures of good: Noah gathered from 
the path of righteousness that which nourished the souls whom their Master had 
chosen. Enoch too opened the treasury of righteousness and fed himself from the 
nourishment of everlasting life. Enosh opened the treasury of praises and 
invoked the name of the Lord. Therefore, all his seed was perfect. See these three 
and what they did and become like them, be nourished from what they were 
nourished. And three afer them did like their deeds, and stood before the True 
One and acted with devotion.] Abraham and Isaac and Jacob, the perfect ones, 
cultivated the land of righteousness, and sowed in it. Blessings grew and were 
reaped, and storehouses were ﬁlled from them. Good is the seed of Abraham, for 
a pleasing oﬀering grew up from it, while no blood was shed. Isaac was grown 
up and weaned in his father’s teaching – three great blessings were given to him. 
Jacob walked in this path – he was a perfect man. These three were crowned 
with every glory, and were delivered for all generations and their remembrance 
will not be forgotten.','וּרְאוּ שְׁלוֹשָׁה שֶׁאָגְרוּ אוֹצְרוֹת טוֹבִים: נֹחַ אָגַר מִדֶּרֶךְ הַצֶּדֶק אֶת אֲשֶׁר זִין אֶת הַנְּשָׁמוֹת שֶׁבָּחַר בָּהֶן אֲדוֹנָם. חֲנוֹךְ גַּם הוּא פָּתַח אֶת אוֹצַר הַצֶּדֶק וְנִזּוֹן מִמְּזוֹן חַיֵּי הָעוֹלָם. אֱנוֹשׁ פָּתַח אֶת אוֹצַר הַתְּהִלּוֹת וְקָרָא בְּשֵׁם ה''. לְפִיכָךְ כָּל זַרְעוֹ הָיָה תָּמִים. רְאוּ אֶת הַשְּׁלוֹשָׁה הָאֵלֶּה וּמַה שֶּׁעָשׂוּ, וִהְיוּ כָּמוֹהֶם, הִזָּנוּ מִמַּה שֶּׁנִּזּוֹנוּ הֵם. וְשְׁלוֹשָׁה אַחֲרֵיהֶם עָשׂוּ כְּמַעֲשֵׂיהֶם, וְעָמְדוּ לִפְנֵי הָאֱמֶת וְנָהֲגוּ בְּדֶרֶךְ חֶסֶד. אַבְרָהָם וְיִצְחָק וְיַעֲקֹב, הַתְּמִימִים, עִבְּדוּ אֶת אַדְמַת הַצֶּדֶק וְזָרְעוּ בָּהּ. בְּרָכוֹת צָמְחוּ וְנִקְצְרוּ, וְאוֹצָרוֹת נִמְלְאוּ מֵהֶן. טוֹב זֶרַע אַבְרָהָם, כִּי קָרְבַּן רָצוֹן צָמַח מִמֶּנּוּ, וְלֹא נִשְׁפַּךְ דָּם. יִצְחָק גָּדַל וְנִגְמַל בְּתוֹרַת אָבִיו – שָׁלוֹשׁ בְּרָכוֹת גְּדוֹלוֹת נִתְּנוּ לוֹ. יַעֲקֹב הָלַךְ בַּדֶּרֶךְ הַזֹּאת – אִישׁ תָּמִים הָיָה. הַשְּׁלוֹשָׁה הָאֵלֶּה עוּטְּרוּ בְּכָל כָּבוֹד, וְנִמְסְרוּ לְכָל הַדּוֹרוֹת וְזִכְרָם לֹא יִשָּׁכַח.');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (243,'IV','44','מימר על שירתה רבתה',4000441,'נעמי נביה רבה משה נחת מן טור סיני ביומה דצומה ואורה שרי על צלמה ותרי לוחיה על אדיו יתב על כרסי גדול כתב מה אלפה מרה ביספר מן אקרה דקעימים אלף מן מירון המאר על פתורון יתב ומן לחמון סבע ובכיורון צבע ובמשכנון הקבע מכן צעם לאודאו ואצים קהלה עמה ועבדה דכרן עד לעלם לא יבטל טוב מן יטרנה ומנה לא יפק ווילה למן דפנה מנה לקנומה אבד ולפרותה עקר ובכן מרן לן חכם בכתבה על יד נביה אהן הך משה ומן מדמי למשה נביה דלא קעם כותה ולא יקום נגפף כהלן על קשטה כחדה ולא נסטי מנה דאנן בני טבים ולנן מרן בחר ועבדנן אסגלה מכל העמים','Let us contemplate the great prophet Moses descending from Mount 
Sinai on the day of the fast, the light dwelling on his face, and the two tablets in 
his hands. He had been sitting on a great throne and writing what his Lord had 
taught him. Torah from the immortals he learned, from their provisions he had 
been supplied, at their table he sat and with their bread he was satisﬁed. He had 
washed in their laver and he had been established in their abode. Therefore, he 
fasted in thanksgiving and made the congregation to fast with him, and he made 
this a matter of commemoration, never to be abolished. Happy are they who ob-
serve it and do not abandon it. Woe to him who turns away from it; he destroys 
himself and cuts oﬀ his own oﬀshoot. This our Lord has taught us in His Scrip-
ture through His prophet. Where is there anyone like Moses and who resembles 
Moses the prophet like whom none has arisen nor will arise? Let us all together 
cling to the True One and not stray from Him, for we are the children of the good 
ones and our Master has chosen us and made us His own possession out of all 
nations (Exod. 19:5).','נתבונן בנביא הגדול משה כשהוא יורד מהר סיני ביום הצום, כאשר האור שוכן על פניו ושני הלוחות בידיו. הוא ישב על כס גדול וכתב את אשר למדהו אדונו. תורה מן האלמותיים למד, מהספקתם ניזון, ליד שולחנם ישב ומלחמם שבע. הוא טבל בכיורם והתבסס בדירתם. לפיכך צם להודיה, ועשה את הקהל לצום עמו, ועשה זאת לזיכרון שלא יבוטל לעולם. אשרי השומרים עליו ואינם עוזבים אותו. אוי לו לפונה ממנו; הוא מאבד את עצמו וכורת את ענפו. זאת לימדנו אדוננו בכתבו על ידי נביאו. היכן ימצא מי שדומה למשה ומי דומה למשה הנביא אשר לא קם ולא יקום כמוהו? נדבקו כולנו יחד באמת ולא נתעה ממנו, כי אנו בני הטובים ואדוננו בחר בנו ועשאנו סגולתו מכל העמים (שמות יט,ה).');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (244,'IV','35','מימר על שירתה רבתה',4000351,'ויטש אלה עשהו מלה דרבו מודעה דאלה ממן בעודנו לא יתר ולא פעת ולא יתחלף מורך בקמאו אהיה באלהו תמיד בנוראו לית לגדלה אתר וכל אתר חדדה בחילה יתודי אלהן מלכה רבה דנבא משה אישה וגלה לה שביל קשטה לית חיים טבים אלא חיי אנשים חכמו קשטה והלכו בה למלי משה בזכו אציתו וכי חייכון מתרבים כל עת באיטבו','He forsook God who made him (Deut. 32:15) – a powerful statement 
which declares that God is eternal in His standing. He does not increase or 
decrease; He is eternal in His primordiality, I am (Exod. 3:14) in divinity, stead-
fast in awe. His greatness has no (deﬁned) place – He created every place by His 
might. Gloriﬁed be our God, the great King, who gave prophecy to the Man 
Moses to whom He revealed the way of truth. There is no good life except that of 
men who know the truth and walk in it. To the words of Moses listen in righ-
teousness, and indeed, your life may be magniﬁed, always in prosperity.','עָזַב אֱלוֹהַּ עָשָׂהוּ (דברים לב,טו) – אמירה חזקה המכריזה שהאל נצחי בעמידתו. הוא אינו גדל ואינו קטן; הוא נצחי בקדמוּתו, אֶהְיֶה (שמות ג,יד) באלוהותו, איתן ביראה. גדולתו אין לה מקום מוגדר – הוא ברא כל מקום בכוחו. יתברך אלוהינו, המלך הגדול, אשר נתן נבואה לאיש משה אשר גילה לו את דרך האמת. אין חיים טובים אלא אלה של בני אדם היודעים את האמת והולכים בה. לדברי משה שמעו בצדק, ואכן חייכם יתרבו, תמיד בשלווה.');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (245,'IV','79','מימר על שירתה רבתה',4000791,'ישראל זעקה מרה בר בכור מן לא ישמע מן אבוה כנען טב מנה ישראל זעקה מרה בר בכור מן לא ידע איקרה הנמרוד טב מנה ישראל זעקה מרה אסגלה מן לא יחכם טבה ישמעאל טב מנה ישראל זעקה מרה קדיש מן חלל קדושה עשו טב מנה ישראל זעקה מרה מלך מן לא יטר ממלכתה יהודה טב מנה שמע למלי מרך וקומם פקודיו ללא יתגלי דינה לאבדנך עמי נביה רבה משה הך אוקרך והאן אקימך עסרה אוקרואן אוקרך בדיל תטהר נפשך ולא תחללנה','Israel – his Lord called him ﬁrstborn son (Exod. 4:22) – he who does not 
listen to his father, Canaan is better than that one. Israel – his Lord called him 
ﬁrstborn son – he who does not know the glory, Nimrod is better than that one. 
Israel – his Lord called him His possession (Exod. 19:5) – he who does not 
understand the good, Ishmael is better than that one. Israel – his Lord called 
him holy (Exod. 19:6) – he who profanes holiness, Esau is better than that one! 
Israel – his Lord called him king (ibid.) – he who does not preserve his kingship, 
Judah is better than that one. Hear the words of your Lord and implement His 
precepts, lest judgement be revealed, to your destruction. See how the great 
prophet Moses honored you and where he established you. With ten honors he 
honored you, in order that you may purify your soul and not profane it.','ישראל – אדונו קרא לו בן בכור (שמות ד,כב) – מי שאינו שומע לאביו, כנען טוב ממנו. ישראל – אדונו קרא לו בן בכור – מי שאינו יודע את הכבוד, נמרוד טוב ממנו. ישראל – אדונו קרא לו סגולתו (שמות יט,ה) – מי שאינו מבין את הטוב, ישמעאל טוב ממנו. ישראל – אדונו קרא לו קדוש (שמות יט,ו) – מי שמחלל את הקדושה, עשו טוב ממנו! ישראל – אדונו קרא לו מלך (שם) – מי שאינו שומר את מלכותו, יהודה טוב ממנו. שמעו את דברי אדונכם וקיימו את מצוותיו, פן יתגלה המשפט לאבדנכם. ראו כיצד כיבד אתכם משה הנביא הגדול והיכן העמיד אתכם. בעשרה כבודות כיבד אתכם, כדי שתטהרו את נפשכם ולא תחללוה.');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (246,'IV','13','מימר על שירתה רבתה',4000131,'ועסרתי עקריה דאתרבו בבראשית קעמו תמן למרבאה שלמותה רב הוא דן נביה רבה משה דלא קם כותה ולא יקום לעלם בראשית חכמה וכתבה הך היא ורבה מדעך בה דחכמתה חיולה אשתתי כתביה לאשתתי יומיה וכל אחד מנון מדמי לחברה ושמה דקעם תמן גלה קדשה מכן אמר ויכלה אלהים בראשית החלת ואלהים כללת אשתתי יומיה ושבתה מכן קרא משה כי מד אלין אתו בשם דאתחיל בה נביה רבה משה בראשית שרוי וכן כי שרוי אלהים למרבה בשם למרבה דו שמה דלבשה ואסקף מיתוביתה מכן שראה ואמר כי בשם עמי רבין מדעה דעבד בשם רז אקים עקרה דלבשה מרה אסתכל ממללה איך הו ורבי למדעך ואנער בה בשלמו ו ] כ [ יתך מתחיל יהוה אמרה אקר צעורתה דאדם דבה הוקמת ובמכתבה אתקוממת לכן אמר אכה כי בשם יהוה אקרא חדד בראשית ושמה דלבשה ושמה רבה דברא אדם וכלל כל מצוהתה אה כדו הגדלת בבוננו כהלה אימנו 14] [ בראש חכמתנה ורזיתה איך היא ושמה רבה ידענן איקרה ורבין כי דמן פמה דמשה השתמעת ושמה דבה אתחיל והגדל תריון הזדבגו זה עם זה מן פם אלהותה ופמה דנביותה נצפי מלתה דכתבה קשטה והיא מלת ברא דאמרה מה חנאה בה והך כתב בראשית ברא והך משה אמר כי בשם יהוה אקרא בשרואה ברא אתאמרת כי תמן עובד חילה חזה וחדד בדחנתה ומשה אמר אקרא בנביו הך מלת ברא מן אלהותה בראשית צמתת חלקין תרין אשתתי יומיה וכל מצוהתה דבארהותה הכללו ולגלל גדיל אמר ברא כי משה הוה עתיד למגלי פקודיה ישתבח רחמנה דרחמיו כמרים והוא ממן עד לעלם 15] [ והבו גדל לאלהינו מלה הודעת בזומנואתה מנו דאמר והבו ו עבידה צמות כלה איקר מכן עבדה נביה רבה משה מפתח תשבחתה וזומנאותה ובראשית ומה על דמותה ו אשתתי יומיה ואף מניאן בראשית ומה דאסחנת ה שמה דקעם וכלל בריתה ושמה דלבשה ב גלת תרי עלמיה עלמה קמאה ועלמה תניאנה וו אתעבדת חתמה לכהלון גלה הן אכה מדמי לתמן ואוזף נאר מן ממלל חכמתה במימרה גדל מרבי מליה בקדישו מכן אמר מלת גדל כד אזדמנו לה עקרי שבתה רבה קדשה בג וד ועזר ל אוקרו לכהלון כלול דקדש דאתחיל תמן ועזר בממללה ואמר לשלמו לאלהינו # קצירן # אה אמדינה כהלה רבו מדינתה דשמה תשבחתה טוב מן דבה ידור לחייה בה ימלך טובי המרבי לה איקרה מחילה בכלה עמו משה בה דאר ולאיקרה מלך אזדאן מנה לקנומה ואתרבי בה לחודה בה יקר לקנומה ובה הגדל כותה לית בה ידור ולא מנה ימאר אנשה מנה אלפו ולכתבה אטרו ומן חכמתה אתרבו ובממללה אתחידו כי כל ממללה חיים ואלפנה כהלה ברכה וילה לה מן לה חסך ומן נהרה סטי וללפנה מתנשי ובה לא יתקרב מאבד הוא לקלומה וכן מרחק מן רתות מרה ולרגזה ימלך לאבדנה יסב ואלה זכי מנה דאלפה ולא אלף וזעקה ולא שמע רבותה לאלהנו דסבל חיביה ומגלגל עמון עד הן דיתובון ירום מדעה דמשה דגלה חכמה מרביה יתן כד חסל מן מקרתה כי ומד בה קוה אמר בשם יה ומה בה אודע ואוזף במקרתה והבו במיפכה בראשית ומד אסחנת וקדשה דשבתה ומד בה הזדרם','The ten fundaments that were gloriﬁed in בראשיתstood there to increase 
the perfection. Great is this great prophet Moses like whom none has arisen and 
will never arise. – בראשיתknow it and its writing as it is, and increase your know-
ledge in it, for its wisdom is mighty. Its six letters (correspond) to the six days 
and each of them resembles the other, and the name which is there revealed the 
holiness. Therefore, it says: ,ויכלה אלהיםGod ﬁnished (Gen. 2:2) – בראשיתbegun 
and אלהיםcompleted: the six days and the Sabbath. Therefore, Moses read כי
(ﬁrst). Since these came “in the name”, by which the great prophet Moses was 
strengthened. בראשיתis a beginning and also כיis a beginning. – אלהיםto glorify, 
 – בשםto glorify, for this is the name that (Moses) wore and his rank was elevated. 
Therefore, he begun it and said: for in the name (Deut. 32:3). See the greatness of 
his mind, that made “in the name” a mystery, which established the fundament 
with which his Master dressed him. See the matter as it is and increase your 
knowledge and be enlightened by it in perfection, and you will be strengthened. 
The Lord said it at the creation of Adam, by which it was set up, and by its 
writing it was established. Therefore, it is said here: For in the name of the Lord I 
proclaim (Deut. 32:3). (By this) he renewed בראשיתand the name that he wore 
and the Great Name who created Adam in which He included all the command-
ments. Behold, now you have been gloriﬁed with insight, all of it is faith.','עשרת היסודות שהתפארו ב"בראשית" עמדו שם להגדיל את השלמות. גדול הוא הנביא הגדול משה, שכמוהו לא קם ולא יקום לעולם. "בראשית" – דע אותה וכתיבתה כמות שהיא, והוסף דעתך בה, כי חכמתה עצומה. שש אותיותיה כנגד ששת הימים, וכל אחת דומה לאחרת, והשם הנגלה שם הוא הקדושה. לכן נאמר: "ויכל אלהים" (בראשית ב,ב) – "בראשית" פתחה ו"אלהים" השלים: ששת הימים והשבת. לפיכך פתח משה ב"כי". שכן אלה באו "בשם", שבו התחזק הנביא הגדול משה. "בראשית" היא פתיחה, וגם "כי" היא פתיחה. "אלהים" – לפאר; "בשם" – לפאר, כי זה השם שאותו לבש ועלתה מעלתו. לפיכך פתח ואמר: "כי בשם" (דברים לב,ג). ראה את גדולת שכלו, שעשה "בשם" לסוד, שביסס את היסוד שבו לבשו אדונו. ראה את הדבר כמות שהוא, הוסף דעתך והאר בו לתמים, ותתחזק. ה'' אמרו בבריאת אדם, שבה הוקם, ובכתיבתו נכון. לפיכך נאמר כאן: "כי שם ה'' אקרא" (דברים לב,ג). בכך חידש את "בראשית" ואת השם שלבש ואת השם הגדול שברא את אדם, שבו כלל את כל המצוות. הנה עתה נתפארת בתבונה – כולה אמונה.');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (247,'IV','47','מימר על שירתה רבתה',4000471,'אלין אנון אבהתן טביה לית לאוי נתלמד אלא מנון ולא נעבד ביש לא לאוי כן אנן בני טבים כהלון קדישים הן שבקנן אבהתן נהי כבר ערדאי ומעזי ואבהתן על אבדנן יסעדו ולא יאסו עלינן ולא יפשרו יתן מן לא רתי לגרמה מנו דרתי לה מן לא ישמע לקשטה איך ישתמע קלה מן אזל זכותה מן יאס עליו בר שלומית כד נקב לשם אתרגם מן אחס עליו זמרי זנאה כד טמא גזרתה דקרה פינחס מן אחס עליו עמלק כד קטלה יהושע והמחק על אדה מן אחס עליו קרח כד קעם לנביה רבה משה ובלעתה ארעה מן אחס עליו ואנה חכם דאנן מדמין לון מד אנן כל עת מחדדין בישה כל אלין בעובד אחד אתנסבו ולא אתורכו בבישה אלא גרם יומה מסתה עד אמת עד אמת קשטה מרף יתן ואנן לא נחכם איקרה עד אמת קשטה מגלגל עמן ולינן מעזרי » ן « מן טעותה עד אמת קשטה מגלגל עמן ולינן טרין מה דאלפנן וילן אלית נהי מרגלים לקשטה ונשמע מצוהתה דבה נתוחי ועתה ישראל שמע מן גזריה עד תדמי לאבהתך ותזדעק בר טב וישמר משמרתי מצותי חקותי ותורותי אה עובד מרחי גלג בה קשטה ואסגי זרעך בדיל אברהם עבדי מן שמע קל מרה אתחיל בכהלה למען הביא יה על אברהם יהב לה אגר לקבל עובדה ית דמלל לה אה בריה שלמה מרביה לה ולזרעה','These are our good forefathers. It would not be proper that we learn 
from any but them, so that we do no evil – that would not be appropriate. We are 
the descendants of good men, all of them holy. If we forsake our fathers, we 
would be like a stubborn and rebellious son, and our fathers would assist in our 
destruction and not have pity for us and would not save us. He who has no 
compassion for himself, who has compassion for him? He who does not listen to 
the True One, how will his voice be heard? He who disdains his piety, who will 
pity him? When the son of Shelomith blasphemed the name (and) was stoned, 
who had pity for him? When Zimri the fornicator deﬁled the circumcision (and) 
Phinehas speared him, who had pity for him? Amaleq, when Joshua slew him 
and was blotted out by him, who had pity for him? When Korah opposed the 
great prophet Moses and the earth swallowed him up, who had pity for him? I 
know that we resemble them, since we are always renewing sin. All these people 
were put to death by one deed, and they did not persist in evil, except for that 
very day alone. How long, how long will the True One be lenient with us, while 
we do not acknowledge His glory? How long will the True One show us mercy, 
while we do not turn back from the error? How long will the True One show us 
mercy, while we do not observe what He has taught us? Woe to us if we do not 
rush to the True One to listen to His commandments, for in Him we shall live. 
Now, O Israel, listen to the laws, that you may resemble your fathers and be 
called “good son”. And he kept my charge, my commandments, my statutes, and 
my laws (Gen. 26:5) – this is a desirable deed. The True One praised by it: I will 
bless you and multiply your descendants for my servant Abraham’s sake (Gen. 
26:24). He who hears the voice of his Master was strengthened in everything. So 
that the Lord may bring to Abraham (Gen. 18:19) – He gave him rewards according 
to his action. What He has promised him (ibid.) – this is a perfect covenant, that 
magniﬁes him and his descendants.','אלה הם אבותינו הטובים. לא יהיה נאות שנלמד מאחרים זולתם, כדי שלא נעשה רע — לא יהיה זה הולם. אנו צאצאי אנשים טובים, כולם קדושים. אם נעזוב את אבותינו נהיה כבן סורר ומורה, ואבותינו יסייעו לאבדוננו ולא יחמלו עלינו ולא יצילונו. מי שאין לו רחמים על עצמו, מי ירחם עליו? מי שאינו שומע בקול האמת, כיצד ישמע קולו? מי שמזלזל בחסידותו, מי יחמול עליו? כאשר בן שלומית גידף את השם ונסקל, מי חמל עליו? כאשר זמרי המנאף טימא את הברית וחנית פינחס קדחה בו, מי חמל עליו? עמלק, כאשר יהושע הכהו ומחהו, מי חמל עליו? כאשר קרח התנגד לנביא הגדול משה ובלעה אותו הארץ, מי חמל עליו? ידוע לי שאנו דומים להם, שכן אנו מחדשים את החטא תמיד. כל האנשים האלה הומתו על מעשה אחד, ולא התמידו ברע אלא אותו יום לבדו. עד מתי, עד מתי יסבול לנו האמת, בעוד אנו אינם מכירים בכבודו? עד מתי ירחם עלינו האמת, בעוד אנו אינם שבים מן השגיאה? עד מתי ירחם עלינו האמת, בעוד אנו אינם שומרים את אשר לימדנו? אוי לנו אם לא נמהר אל האמת לשמוע את מצוותיו, כי בו נחיה. עתה, ישראל, שמעו אל החוקים, למען תדמו לאבותיכם ותיקראו "בן טוב". וַיִּשְׁמֹר מִשְׁמַרְתִּי מִצְוֹתַי חֻקּוֹתַי וְתוֹרֹתָי (בראשית כו,ה) — זהו מעשה נחמד. האמת שיבח בו: וְהִרְבֵּיתִי אֶת זַרְעֲךָ בַּעֲבוּר אַבְרָהָם עַבְדִּי (בראשית כו,כד). מי ששמע בקול אדונו התחזק בכל דבר. לְמַעַן אֲשֶׁר יְבִיא יְהוָה עַל אַבְרָהָם (בראשית יח,יט) — נתן לו שכר לפי מעשהו. אֲשֶׁר דִּבֶּר עָלָיו (שם) — זוהי ברית שלמה המגדילה אותו ואת צאצאיו.');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (248,'IV','99','מימר על שירתה רבתה',4000991,'מלתה תשעיתה יקומו ויסעדוכון אלהיכון קשטה יימר מן דלה אלהין ינדינון מן דפסל כיף באדה ועבדה אלה וסגד לה מה דן בחיל אהן כיפה יעבד מן אקים צלם מכל אלין בוראיה דברא יתון אלהה מן כוכביה עד חורנה מד בחילון יעבדון כהלון קפעין לקדם עבודון לית יכלה ולא עובד דכלה מדלה ומעזר לדלה ישתבח עבוד גוני תמחיה נהימן בה ובמשה נביה ובכתבה ונתרחץ ביחידאותה','The ninth statement: Let them rise up and help you (Deut. 32:38). Your 
God, the True One, will say: He who has gods, let him produce them; he who 
sculpted with his hands and made it a god and worshipped it, what is in the 
power of this stone to do? He who placed an image of any of these creatures that 
God created, from the stars to any others, what is it in their power to do? All of 
them freeze before their Maker, void of power and deed. For all is His possession 
and turns back to Him. Praised be the Maker of various wonders. Let us believe 
in Him and in Moses His prophet and in His Book, and trust His Uniqueness.','האמירה התשיעית: יקומו ויעזרו לכם (דברים לב,לח). אלוהיכם האמיתי יאמר: מי שיש לו אלוהים, שיביא אותם; מי שחצב בידיו ועשה ממנו אל והשתחווה לו, מה ביכולת האבן הזאת לעשות? מי שעשה צלם מאחד הברואים שאלוהים ברא, מן הכוכבים ועד כל אחר, מה ביכולתם לעשות? כולם קפאים לפני יוצרם, ריקים מכוח ומעשה. כי הכל הוא קניינו וחוזר אליו. ברוך עושה הנפלאות השונות. נאמין בו ובמשה נביאו ובספרו, ונבטח ביחודו.');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (249,'IV','76','מימר על שירתה רבתה',4000761,'לאלין ] מ [ ליה שמעו ] ו [ הזהרו דמה ] תא [ מנו בכל ] א [ יקר מד אתה ] נטר פקודי [ ה ] אתה מתנט [ ר ] וכד תרבנון אתה מתרבי ומרך זאון לך בכל זבן [ וזעוקך אתי לידי וטר מצוהתי עד אטרך ודע הן אלהך רחמן ורתאי מיטב לכל מן יבלשה ועתה ישראל מה יהוה אלהיך שאל מעמך אלאן דחלתה מנה הן דחלת מנה דחלך כל בורא כמה דאמר וראו כל עמי הארץ כי שם יהוה נקרא עליך וייראו ממך וללכת בכל דרכיו הן הלכת בדרכיו תרבי בכל מהלכך כמה דאמר פחדכם ומראכם יתן יה אלהיכם על פני כל הא אשר תדרכו בה ולאהבה אתו ] ו [ הן רחמתנה רחמך כמה ] ד [ אמר ורחמך והרבך ולשמר א [ ת מצות יה ] אלה הן ] ש [ מרת מליו ] יש [ מרך ואקים ] לך כ [ ל ברכתה ] הן [ רבית ית פקודיו תהי ] ל [ על לעל ודבבך לרע לרע והן תפתח אספרה ותקרי לגוה יפתח באפיך אוצרי טובה','Listen to these words and be warned, perchance you may endure in all 
glory. As long as you keep the precepts, you will be kept, and when you exalt 
them you will be exalted, and your Master feeds you at any time. “Your cry has 
come to me.” Keep My precepts, that I may keep you. Know that your God is 
merciful and gracious, who does good to all who seek Him. And now, Israel, what 
does the Lord your God require of you but (Deut. 10:12) the fear of Him. If you fear 
Him, all creatures will fear you, as He said: And all the peoples of the earth shall 
see that you are called by the name of the Lord; and they shall be afraid of you 
(Deut. 28:10). And to walk in all his ways (Deut. 10:12) – if you walk in His ways, 
you will be exalted in all your movements, as He said: the Lord your God will put 
the dread and the fear of you over the whole land in which you set foot (Deut. 
11:25). And to love Him (Deut. 10:12) – if you love Him, he will love you, as He 
said: and show you mercy and multiply you (Deut. 13:18). And to keep the com-
mandments of the Lord your God (Deut. 4:2) – if you keep His words, He will 
guard you and will apply all the blessings to you. If you exalt His command-
ments, you will be higher and higher (Deut. 28:43) and your foe lower and lower 
(ibid.). If you open His Scripture and read therein, He will open the treasures of 
good before you.','שמע את הדברים האלה והיזהר, שמא תעמוד בכל הכבוד. כל עוד תשמור את המצוות תישמר, וכשתרוממן תתרומם, ואדונך מזין אותך בכל עת. "צעקתך באה אלי." שמור את מצוותי ואשמרך. דע כי אלהיך רחמן וחנון, הטיב לכל מבקשיו. וְעַתָּה יִשְׂרָאֵל מָה יְהוָה אֱלֹהֶיךָ שֹׁאֵל מֵעִמְּךָ כִּי אִם (דברים י,יב) יראתו. אם תירא אותו, כל הברואים ייראו ממך, כמו שאמר: וְרָאוּ כָּל עַמֵּי הָאָרֶץ כִּי שֵׁם יְהוָה נִקְרָא עָלֶיךָ וְיָרְאוּ מִמֶּךָּ (דברים כח,י). וְלָלֶכֶת בְּכָל דְּרָכָיו (דברים י,יב) – אם תלך בדרכיו תתעלה בכל תנועותיך, כמו שאמר: יִתֵּן יְהוָה אֱלֹהֶיךָ אֶת אֵימָתְךָ וּפַחְדְּךָ עַל פְּנֵי כָל הָאָרֶץ אֲשֶׁר תִּדְרְכוּ בָהּ (דברים יא,כה). וּלְאַהֲבָה אֹתוֹ (דברים י,יב) – אם תאהב אותו יאהב אותך, כמו שאמר: וְרִחַמְךָ וְהִרְבֶּךָ (דברים יג,יח). וְלִשְׁמֹר אֶת מִצְוֹת יְהוָה אֱלֹהֶיךָ (דברים ד,ב) – אם תשמור את דבריו ישמרך ויחיל עליך את כל הברכות. אם תרומם את מצוותיו, תהיה מַעְלָה מָּעְלָה (דברים כח,מג) ואויבך מַטָּה מָּטָּה (שם). אם תפתח את כתבו ותקרא בו, יפתח לפניך את אוצרות הטוב.');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (250,'IV','98','מימר על שירתה רבתה',4000981,'מלתה תמניהיתה מבלדה לכל שמועיה איה אלהימו מן סגד לעובד אד ביש מה דעבד מן עבד צלם וסגד לה תשתני צורתה מן סגד לבורא ושם יתה רחצונה כד יתחזי ברואה מנו דיכל יפרקנה מן רבה לבר מן צעורה כד יקום לחשבנה מן יפשרנה נעזר מן שביל טעותה ונלך בשביל אימנותה דהיא מנשמה ומפציה לכל מן אתנגד בה טבה יתה שבילה טובי ההלכים בה כי לה נגוד כל יום הוא מזעק אתו דאנה עמוכון לית עליכון דחלה לאוי נשמע למלי קשטה דמד נהי מנשמין אנה ותמן דו אלה רחמן מקבל לכל שהב','The eighth statement frightens all who hear it: Where are their gods 
(Deut. 32:37) – he who worshipped an idol, what he did is evil. He who made an 
image and worshipped it, his countenance will be changed. He who worshipped 
an artifact and made it his haven, when his Creator appears, who can redeem 
him? He who exalted other than his Creator, when he stands for the reckoning, 
who will rescue him? Let us turn back from the path of error and walk in the 
path of the faith, for it gives rest and redeems all who are led in it. That path is 
good. Happy are those who walk in it, for it has a Leader who calls every day: 
“Come, for I am with you, you should not fear.” It is appropriate for us to listen to 
the words of the True One, perchance we may rest here and there, for He is a 
merciful God, who receives every repentant.','האמירה השמינית מבעיתה את כל השומעים אותה: איה אלוהיהם (דברים לב,לז) – מי שעבד עבודה זרה, מה שעשה הוא רע. מי שפסל צלם והשתחווה לו, פניו ישתנו. מי שעבד מעשה ידי אדם ועשה ממנו מחסה, כשיופיע בוראו, מי יגאלנו? מי שרומם זולת בוראו, כשיעמוד לחשבון, מי יצילנו? נשוב מדרך התועה ונלך בדרך האמונה, כי היא מניחה את הדעת וגואלת את כל הנוהלים בה. אותה הדרך טובה היא. אשרי ההולכים בה, כי יש לה מנהיג הקורא בכל יום: "בואו, כי אני עמכם, אל תיראו." ראוי לנו להאזין לדברי האמיתי, אולי נמצא מנוחה כאן וכאן, כי הוא אל רחום המקבל כל שב בתשובה.');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (251,'IV','40','מימר על שירתה רבתה',4000401,'אלהין דלא חכמון אשדה לון לתמן ימטו ומתמן יעזרו דאה עובד ביש עבדו בקנומון לא דבוק ולא פרוק ולא סעוד ארשי פאניה דיתמר עליון ככן מן לא יחכם לה מר לאהן ייפך אפיו לא דבוק לה לגו לחצה ולא מי תלי מנה מגיפה מן אלין נתרחק ומנון נערק עובד קין ופריתה אכהן קין על מלואה יגבי ולמך יזיף ומוזף מן לא ידע קשטה במה יתקלץ וילה למן ישוי קנומה בקבל בישהתה נבך ישתבח רחמנה דרחמיו כפלין דאמלתן בטובה וכלל יתן ברתותה נלך בתר נביה רבה משה ונטר מצוהתה דלנן חכם ואוקרן בון ולא ננשון כל יומינן','Gods they had never known (Deut. 32:17) – distress on them! Thither they 
arrive and thence they return. For behold, an evil deed they have done to them-
selves: no savior and no deliverer and no assistant. (They are) the origins of their 
apostasy, of whom it is said thus: “He who is not known to a master, to where is 
he to turn his face? He has no savior in aﬄiction, and he has no one to remove 
plague from him.” From these (men) let us be distant and ﬂee from them. (This 
is) the deed of Cain and its requital. Thus Cain was punished fully, and Lamech 
much more so. He who does not know the True One – to what does he cling? Woe 
to him who places himself, confused, in the darkness of evildoing. Praised be the 
Merciful One whose mercies are manifold, who has ﬁlled us with His goodness 
and crowned us with His grace. Let us walk afer the great prophet Moses and 
keep his commandments, which he has taught us and by which he has gloriﬁed 
us. And let us not forget them all our days.','אֱלֹהִים לֹא יְדָעוּם (דברים לב,יז) – צרה עליהם! לשם הם מגיעים ומשם הם חוזרים. שהרי מעשה רע עשו לעצמם: אין מושיע ואין מציל ואין עוזר. הם שורשי כפירתם, ועליהם נאמר כך: "מי שאינו ידוע לאדון, לאן יפנה פניו? אין לו מושיע בצרה, ואין מי שיסיר ממנו מגיפה." מאנשים אלה נתרחק ונברח מהם. זהו מעשה קין וגמולו. כך נענש קין עונש שלם, ולמך על אחת כמה וכמה. מי שאינו מכיר את האמת – במה יאחז? אוי למי שמעמיד את עצמו, מבולבל, בחשכת הרשע. ברוך הרחמן שרחמיו רבים, שמילאנו בטובו ועיטרנו בחסדו. נלך אחר הנביא הגדול משה ונשמור את מצוותיו, שלימד אותנו ובהן כיבד אותנו. ולא נשכחם כל ימינו.');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (252,'IV','45','מימר על שירתה רבתה',4000451,'לית אבונן קין עד נהי חרימים ולא בני חנוך עד נהי מתפלטים ולא בני כוש עד נהי לעיטים ולא בני הנמרוד עד נהי מנדנדים ולא בני מגדלאי עד נהי מבדרים ולא בני אנשי סדם עד נהי משתרפים ולא בני מצראי עד נהי משתנקים ולא בני עמלקאי עד נהי ממחין ולא בני קרח עד תבלענן ארעה באידן מדע נקרב לבישהתה יהודה כד קרב בישתה אולד ער ואונן מתו פנים מן טבהתה ראובן כד קרב למרדה אבד פרותה ואזלת דרגה ואלה מזדכי מנה ואלולי יוסף לא אקבל מנון תתובתה וארום אתמר מן פמה דנביותה יחי ראובן ולא ימות ושמע יהוה קול יהודה','Cain is not our father, that we should be proscribed, nor are we the sons 
of Enoch that we should be fugitives, nor of Cush that we should be accursed, 
nor of Nimrod that we should be thwarted, nor of the Tower Builders that we 
should be scattered, nor of the people of Sodom that we should be burnt, nor of 
the Egyptians that we should be aﬄicted, nor of the Amaleqites that we should 
be blotted out, nor of Korah that the earth should swallow us up. For what 
reason could we draw near to evil? When Judah drew near to evil, he begot Er 
and Onan, who died turning away from the good. When Reuben drew near to 
rebellion, he destroyed his fruit and his status passed away and God is exempt 
from him. If it had not been for Joseph, their repentance would not have been 
accepted, but it was said from the mouth of the prophethood: Let Reuben live, 
and not die (Deut. 33:6), and: Hear, O Lord, the voice of Judah (ibid., v. 7).','קין אינו אבינו שנהיה מוחרמים, ואין אנו בני חנוך שנהיה נעים ונדים, ולא של כוש שנהיה ארורים, ולא של נמרוד שנהיה כשלים, ולא מבוני המגדל שנהיה מפוזרים, ולא מאנשי סדום שנהיה שרופים, ולא ממצרים שנהיה מעונים, ולא מעמלקים שנהיה נמחים, ולא של קורח שתבלענו הארץ. מה סיבה שנתקרב לרע? כאשר קרב יהודה לרע הוליד את ער ואת אונן, שמתו בפנותם מן הטוב. כאשר קרב ראובן למרד, השחית את פריו ומעמדו עבר ממנו, והאלוהים פטור ממנו. אלמלא יוסף לא הייתה תשובתם מתקבלת, אך נאמר מפי הנבואה: יְחִי רְאוּבֵן וְאַל יָמֹת (דברים לג,ו), ו: שְׁמַע יְהוָה קוֹל יְהוּדָה (שם, פסוק ז).');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (253,'IV','59','מימר על שירתה רבתה',4000591,'אוכחותה תניאנאתה מחכמה עקרי רחמיה סהביך ויאמרו לך דאלפון אלה ונביה אנון ילפונך אברהם איכו קמיך קעם וממלל עמך שמה דנגדי לא תחללנה גזרתה קדש לא תטמינה בזנו אלהים ברכני לא תנדי עלי קללה ותוקר אפי סהב הן הוה חכום דו מתיל ] ף קשטה [ ולך יל ] ף יתה איך [ דאמר נביה רבה משה דאמר שמנת עבית כלל הדה מלתה במימר כשית כל מן דעמה מאדם טב הוה משבח טלי משעבד לספרה משה למרה וכן בעה ישראל יעבדון נפקת ממצרים טעין ברכהן מלך שלם במדלה קבלת ככן תיתי ליד ארע כנען ותמלך כל איקרה בתים מלאים כל טוב מעתדים לך אנצר לאלה באודאו ואימר בלב מלי דחלה לית אלה אלא אחד','The second reproof teaches the descendants of the devotees. Your elders, 
and they will tell you (Deut. 32:7) – what God and the prophet taught them, they 
will teach you. Abraham, as if he is standing before you and speaks with you: 
“The name that led me – you shall not profane it. The circumcision is holy, you 
shall not deﬁle it with harlotry. God has blessed me, you shall not bring curse 
over me.” Show deference to the old (Lev. 19:32), if he is wise, he learns the truth 
and teaches you, as [the great prophet Moses said: You waxed fat, you grew thick 
(Deut. 32:15), and concluded this statement with the saying: you became beautiful 
(ibid.) – everyone who saw something good was praising. As a child submissive 
to his teacher was Moses to his Lord, and so he looked for Israel to become: “You 
went forth from Egypt laden with blessings, a full possession of His wealth you 
received. Likewise, you will come to the land of Canaan and possess all its glory; 
houses full of all good things (Deut. 6:11) are prepared for you. Be devoted toward 
God in thanksgiving and say with a heart full of reverence: ‘There is no god but 
One.’”','התוכחה השנייה מלמדת את צאצאי הנאמנים. וזקניך ויאמרו לך (דברים לב,ז) – את אשר לימדום האל והנביא, הם ילמדו אותך. אברהם, כאילו הוא עומד לפניך ומדבר עמך: "השם שהנחה אותי – לא תחלל אותו. הברית קודש היא, לא תטמא אותה בזנות. האל ברכני, לא תביא קללה עלי." מפני שיבה תקום והדרת פני זקן (ויקרא יט,לב), אם הוא חכם, הוא לומד את האמת ומלמד אותך, כאשר [אמר הנביא הגדול משה: וישמן ישורון (דברים לב,טו), וסיים את הדברים באמרו: ויפת (שם)] – כל מי שראה דבר טוב היה משבחו. כשלמיד כנוע לרבו היה משה לריבונו, וכך קיווה שיהיה ישראל: "יצאת ממצרים עמוס ברכות, ירושה מלאה מעושרו קיבלת. כך תבוא לארץ כנען ותרש את כל כבודה; בתים מלאים כל טוב (דברים ו,יא) מוכנים לך. היה מסור לאל בהודיה ואמור בלב מלא יראה: ''אין אלהים כי אם אחד.''"');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (254,'IV','9','מימר על שירתה רבתה',4000091,'האן הך משה ומן מדמי למשה עבדה דאלה ובן בית אלהים האן הך משה ומן מד למשה דמללה מרה כרחם עם רחמה האן הך משה ומן מדמי למשה בעה מחכמה דרזי בראשית דילה','Where is there anyone like Moses and who resembles Moses, the servant 
of God, and Son of God’s House? Where is there anyone like Moses and who re-
sembles Moses, with whom his Master spoke like any friend with his friend? 
Where is there anyone like Moses and who resembles Moses, who sought to 
make known that the mysteries of the Creation are his?','היכן ימצא מי שדומה למשה ומי שנמשל למשה, עבד האלוהים ובן בית האלוהים? היכן ימצא מי שדומה למשה ומי שנמשל למשה, שאדונו דיבר עמו כאיש אל רעהו? היכן ימצא מי שדומה למשה ומי שנמשל למשה, שביקש להודיע כי סודות הבריאה הם שלו?');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (255,'IV','26','מימר על שירתה רבתה',4000261,'אדם חלף פקודה אתגזי בקשט למך יקר ית בישתה אתגזי בקשט מגדלאי אכעסו לאלה אתגזו בקשט סדמאי מצראי עבודי עגלה כל אלין הכלאו בעובד בישהתה אתגזו בקשט ישתבח מלכה הממן במדו והוא מחליף ולא מתחלף ממיר עבודי בישהתה ומגזי יתון בקשט ומדיר עבודי טבהתה ומגזי יתון בקשט הך דאמר בר ברה דעדן לפם די עבי › ד ‹ תה הו אגרה אברהם כד אזדעק ואתא בכשירו אתגזי בקשט ויצחק כד שמע מן אבוה אתיקר ואתברך יעקב כד הדבק במה דאלף מנון אתברך והגדל יוסף כד נטר גרמה אתצלח ואתגזי בקשט אהן הך משה ומן מדמי למשה דגלה לה מרה מד לא לחורנה › גלתה ‹ עד לעלם יתודי רחמנה דרחמיו יתרים ומן אתקרב בה לא מנזף לעלם ומן הלך עמה ליתו טעי לא נבטל מן } מן { תשבחתה ולא נבצר מן › עצמהתה ‹ נדחל מנה ונרתת ונזע מן גבורתה ונסיד ונימר לית אלה אלא אחד','Adam transgressed the command – he was repaid justly. Lamech hon-
ored evil – he was repaid justly. The people of the tower (of Babel) irritated God – 
they were repaid justly. The people of Sodom, the Egyptians, the makers of the 
calf, all these were conﬁned within evildoing – they were repaid justly. Praised 
be the King who endures as he is, and He changes (others but) is not changed. 
He frightens the doers of evil and repays them justly and settles the doers of 
good and repays them justly, as the son of the son of Eden said: “According to 
the deed is the repayment.” When Abraham was summoned, and walked in 
righteousness, he was repaid justly. Isaac, when he obeyed his father, was hon-
ored and blessed. Jacob, when he clung to what he learned from them, was 
blessed and magniﬁed. Joseph, when he guarded himself, was successful and 
repaid justly. Where is there anyone like Moses and who resembles Moses, to 
whom his Master revealed what He did not reveal to another. Forever be praised 
the Merciful One, for His mercy is enormous, and the one who draws near to Him 
is never rejected. The one who walks with Him does not stray. We will not stop 
His eulogy nor will we lessen His veneration. Let us fear Him and tremble and 
shiver from his might and testify and say: “There is no god but One.”','אדם עבר על הציווי – שולם לו כראוי. למך כיבד את הרשע – שולם לו כראוי. אנשי המגדל (של בבל) הכעיסו את האל – שולם להם כראוי. אנשי סדום, המצרים, עושי העגל, כולם היו שקועים ברשעה – שולם להם כראוי. ברוך המלך הקיים כפי שהוא, והוא משנה אחרים אך אינו משתנה. הוא מפחיד את עושי הרע ומשלם להם כראוי, ומיטיב עם עושי הטוב ומשלם להם כראוי, כפי שאמר בן בנו של עדן: "לפי המעשה כן התשלום." כאשר נקרא אברהם, והלך בצדק, שולם לו כראוי. יצחק, כאשר שמע לאביו, נכבד ונתברך. יעקב, כאשר דבק במה שלמד מהם, נתברך והתגדל. יוסף, כאשר שמר על עצמו, הצליח ושולם לו כראוי. היכן יש מישהו כמשה ומי דומה למשה, אשר גילה לו אדונו מה שלא גילה לאחר. לעולם יהולל הרחום, כי רחמיו עצומים, ומי שמתקרב אליו לא יידחה לעולם. המהלך עמו לא יתעה. לא נחדל מהלל אותו ולא נמעיט בכבודו. נירא ממנו ונרעד ונחרד מגבורתו ונעיד ונאמר: "אין אלוה אלא אחד."');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (256,'IV','19','מימר על שירתה רבתה',4000191,'כד חסל משה מן אלין מליה עזר ואמר כי כי קדמאיתה שרוי לעלם וכי כדו שביל לאחרותה לכן אמר כי כל דרכיו דכרן מעתיד ליום נקום אנשיו דדרה אתפררו ולמלי משה אלפו לא אתבחרנן אלא לאלפנה ולא אתפרקנן אלא למחכומה חיים וברכה למי ימלך איקר וטוב למי יילף עלמה לה ארכן ולמליו אצית עמו נביה רבה משה מוכח ביום נקם דבה גזוי לכל עמל אמר כי כל כי שרוי וכל חסול ומשה חכם שרואה ועקבה רב הוא נביה רבה משה במד גלה מן שביל קשטה האן הך משה ומן מדמי למשה נביה דלא קעם כותה ולא יקום לעלם נביא } דלעל { » דעלה « לכסיאתה ודער ביני קעימיה רישה נגש לערפלה באדיו אנצע ישראל צלותה פרקן ואבדן ממללה אסו ואמטאנו שילתה יתוב וטלטול האן הך משה ומן מדמי למשה בעלמה תריח גנתה לה הפתחו ובה דער עננה כסה לה ומלאכיה רבונה וכבודה רבה יקרנה אורה קמיו אניר חשכה מקמיו הטרד רוחה סבלה , מעונה לה נפש על עקרי בראשית קעם ולרזיתה חכם וגלתון לכל דריה ביום נקם הודע ואזהר ממה דבה עתיד עשדאה לאנשים חלפו וביום נקם ילקו אוי לן אוי לן כל אהן עביד לן וילן אלית נהי אלפים ומן השמע מתילפין כי כלה קבל עלינן ומרה דעלמה מנן מזדכי עמו נב רבה משה איך אמר כי כל דרכיו משפט חדד דכרן זכאיה שבילה דחנוך שבילה דקשטה בה התהלך אברהם והתברך בכלה ולגוה אנגד יצחק לריחותה דמרה וכן יעקב בה אתיקר על כן אמר נב רבה משה במחכום דקשט כי כל דרכיו משפט','When Moses had ﬁnished these words, he said again ( כיDeut. 32:4). The 
ﬁrst ( כיv. 3) is the beginning of the world and the present כיis the road to the 
end. Therefore he said: for all His ways (v. 4), a reminder prepared for the day 
when we shall stand. O people of the generation, be awake [and learn the words 
of Moses. We were not chosen but for learning, and we were not delivered but for 
knowledge. Life and blessing for him who possesses (it), glory and good for him 
who learns. The world bows down before him and listens to his words. See the 
great prophet Moses preaches about the “day of vengeance”, on which there is 
remuneration for every deed. He said כי – כי כלis beginning and כלis end, and 
Moses knew the beginning and the end. Great is the great prophet Moses for 
what he revealed from the way of the True One. Where is there anyone like Moses 
and who resembles Moses, the prophet like whom none has arisen and will 
never arise – a prophet who ascended to the Concealed and dwelt among immor-
tals? His head approached the thick cloud (Exod. 20:21), through him Israel was 
victorious, his prayer brought deliverance and destruction, his word is healing 
and disease, his request is encampment and journey. Where is there anyone like 
Moses and who resembles Moses in the world – the gates of the garden were 
opened for him and he abode therein, the cloud wrapped him, the angels exalted 
him, and the Great Glory honored him. The light lit up before him, the darkness 
before him was scattered, the wind bore him,] the Divine Abode made him rest. 
He understood the foundations of ,בראשיתand perceived its mysteries, and 
disclosed them to all the Generations. He made known “the Day of Vengeance” 
(Deut. 32:35) and warned against what is prepared in it. Distress to the men who 
altered (the Law); on the “Day of Vengeance” they will be struck. Woe to us, woe 
to us, all this is made for us. Woe to us, if we do not learn and we (do not) master 
the teaching, for all will complain about us, and the Master of the world will 
clear Himself from us. See the great prophet Moses as he said: for all his ways are 
justice (v. 4) – he renewed the memory of the righteous. The path of Enoch is the 
path of the True One. Abraham walked on it and was blessed with everything. 
Isaac was led in it to the pleasing of his Master, and also Jacob was honored in it. 
Therefore the great prophet Moses said through the knowledge of truth: for all 
his ways are justice.','כאשר סיים משה את הדברים האלה, חזר ואמר כי (דברים לב,ד). הכי הראשון (פסוק ג) הוא ראשית העולם, והכי הנוכחי הוא הדרך אל הסוף. לכן אמר: כי כל דרכיו משפט (פסוק ד), זכרון המוכן ליום שבו נעמוד. הו אנשי הדור, היו ערים [ולמדו את דברי משה. לא נבחרנו אלא ללמוד, ולא נגאלנו אלא לדעת. חיים וברכה למי שיש לו (ידיעה זו), כבוד וטוב למי שלומד. העולם משתחווה לפניו ומקשיב לדבריו. ראו את הנביא הגדול משה מטיף על "יום הנקם", שבו יש שכר לכל מעשה. אמר כי – כי כל הוא ראשית, וכל הוא סוף, ומשה ידע את הראשית ואת הסוף. גדול הנביא הגדול משה על מה שגילה מדרך האמת. היכן יש מי כמשה ומי דומה למשה, הנביא שכמותו לא קם ולא יקום לעולם – נביא שעלה אל הנסתר ושכן בין אלמותיים? ראשו הגיע אל הערפל הכבד (שמות כ,כא), על ידו נצח ישראל, תפילתו הביאה ישועה וכליון, דברו הוא רפואה ומחלה, בקשתו היא חניה ומסע. היכן יש מי כמשה ומי דומה למשה בעולם – שערי הגן נפתחו לפניו וישב בהם, הענן עטפו, המלאכים רוממוהו, והכבוד הגדול כיבדו. האור האיר לפניו, החושך לפניו נתפזר, הרוח נשאתו,] המשכן האלוהי הניח לו מנוחה. הבין את יסודות בראשית ותפס את מסתוריה, וגילה אותם לכל הדורות. הודיע את "יום הנקם" (דברים לב,לה) והזהיר מפני המוכן בו. צרה לאנשים שסילפו (את התורה); ב"יום הנקם" יינגפו. אוי לנו, אוי לנו, כל זאת נעשה לנו. אוי לנו, אם לא נלמד ולא נשלוט בתורה, כי הכל יתלוננו עלינו, ואדון העולם יתנכר לנו. ראו את הנביא הגדול משה כשאמר: כי כל דרכיו משפט (פסוק ד) – חידש את זכרון הצדיקים. דרך חנוך היא דרך האמת. אברהם הלך בה ונתברך בכל. יצחק הונהג בה לרצון אדונו, וגם יעקב כובד בה. לכן אמר הנביא הגדול משה מתוך דעת אמת: כי כל דרכיו משפט.');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (257,'IV','91','מימר על שירתה רבתה',4000911,'מלתה חמישה לעת תמוט רגלם האיש הרך בך והענג מאד לבט גרמה בגנואן סגי הרכה בך והענגה דלא נסתה כף רגלה הלכת בבישה ימוט כף רגלה מן לה מקדמהן בישהן יתגזי במעוהן בישהן מכף רגלה וסעד רומה ישתבח רחמנה דרחמיו יתרים עם כל דר ודור ועם חלוף כל זבן ועדן','The ﬁfh statement: At the time that their foot falters (Deut. 32:35) the 
man who is most tender and fastidious among you (Deut. 28:54) aﬄicted himself 
with many blames. She who is most tender and dainty among you […] that she 
would never venture (to set) the sole of her foot (Deut. 28:56) walked in evil – her 
foot will falter. He who has committed evildoing, will be punished with evil 
plagues from the sole of his foot to the crown of his head. Praised be the Merciful 
One, whose mercy increases with every generation and succession of all time 
and period.','האמירה החמישית: לעת תמוט רגלם (דברים לב,לה) – הרך והעָנֹג שבך (דברים כח,נד) הִסב על עצמו גינויים רבים. הרַכָּה והעֲנֻגָּה שבך [...] אשר לא ניסתה כף רגלה (דברים כח,נו) הלכה ברשע – רגלה תמוט. מי שחטא ועשׂה רשע ייענש בנגעים רעים מכף רגלו ועד קדקדו. ברוך הרחמן, שרחמיו גדֵלים עם כל דור ודור לאורך כל הזמנים והתקופות.');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (258,'IV','70a','מימר על שירתה רבתה',4000702,'מלתה ] ר [ ביעיתה ועל גוזליו ] יר [ חף כד הויתון ] במ [ צרים לגו לבט ] חי [ ול מתלחצים ] באד [ י דבביה אתחזה ופרק יתכון ] מתמן וג [ לה סי ] מנ [ ים רמים לא שבקכון מן טובה במצרים ולגו ימה ובמדברה מן רחמותה לכון } לכון { עבד גוני תמחיה ומן מטרתה ית שבועתה דאשבע לאבהתיכון פרקכון בחילה רבה מכורה דברזלה יתודי אהן מלכה , רחמנה הממן לקלומה עם חלוף כל דריה ולא יתחלף ויתגלג נביה רבה משה ] מ [ הימנה לגו ] כס [ יהתה ] וגל [ יהתה','The fourth statement: Gliding down to his young (Deut. 32:11). When 
you were in Egypt in mighty distress, oppressed by enemies, (God) appeared and 
delivered you from there and revealed great wonders. He did not forsake you in 
His goodness in Egypt and at the sea and in the wilderness. Out of His mercy for 
you He performed various wonders, and out of His keeping His oath which He 
swore to your ancestors He delivered you with great Might from the iron furnace. 
Praised be this merciful King, who endures alone during the succession of all the 
generations – and He does not change. Praised be the great prophet Moses, the 
appointed over the Concealed and the Overt.','האמירה הרביעית: "יְרַחֵף עַל גּוֹזָלָיו" (דברים לב,יא). כשהייתם במצרים בצרה עצומה, לחוצים בידי אויבים, נגלה (האלוהים) והצילכם משם וגילה נפלאות גדולות. לא עזב אתכם בטובו במצרים ובים ובמדבר. מרחמיו עליכם עשה נפלאות שונות, ומשמירת שבועתו שנשבע לאבותיכם הצילכם בגבורה גדולה מכור הברזל. ברוך המלך הרחמן הזה, העומד לבדו לאורך כל הדורות הבאים זה אחר זה – והוא אינו משתנה. ברוך הנביא הגדול משה, הממונה על הנסתר והנגלה.');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (259,'IV','21','מימר על שירתה רבתה',4000211,'יעקב זרז להדה שבילה ואתחזי לה סלם לא אגלה כותה לעלם משה נביה סלק וקבל לוחיה דאסחנו חיים יעקב חזה בחלמה מלאכי רומה עלים וירדים ומשה עמה גוני תמחיה אזדמנו קמיו למוקר יתה בדיל יעקב אתמר והנה יה נציב עליו ובדיל משה אמיר ויעב } י { ר יהו על פניו בדיל יעקב אמר ויאמר אליו אני יה ובדיל משה אמר ויקרא יהוה עסרה מלים סוברו לכל דריה אהן הך משה ומן מדמי למשה נביא לא קם כותה ולא יקום','Jacob hurried to this path, and a ladder appeared to him, the like of 
which was never revealed. Moses the prophet ascended and received the tablets 
that contained life. Jacob saw in his dream the angels of heaven ascending and 
descending (Gen. 28:12), and Moses saw various wonders that gathered before 
him to honor him. Concerning Jacob it was said: And behold, the Lord stood 
above it (Gen. 28:13) and concerning Moses it is said: The Lord passed before him 
(Exod. 34:6). Concerning Jacob it is said: I am the Lord (Gen. 28:13) and concer-
ning Moses it is said: The Lord proclaimed (Exod. 34:6) – Ten Words, support to 
all generations. Where is there anyone like Moses, and who resembles Moses, the 
prophet like whom none has arisen nor will arise?','יעקב מיהר בדרך הזאת, וסולם נגלה לו, שכמותו לא נגלה מעולם. משה הנביא עלה וקיבל את הלוחות שהכילו חיים. יעקב ראה בחלומו את מלאכי השמים עולים ויורדים (בראשית כח,יב), ומשה ראה פלאות שונות שנקבצו לפניו לכבדו. על יעקב נאמר: והנה ה'' נצב עליו (בראשית כח,יג) ועל משה נאמר: ה'' עבר על פניו (שמות לד,ו). על יעקב נאמר: אני ה'' (בראשית כח,יג) ועל משה נאמר: ה'' קרא (שמות לד,ו) – עשרת הדברות, משענת לכל הדורות. היכן יש מי כמשה ומי דומה למשה, הנביא שכמותו לא קם ולא יקום?');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (260,'IV','18','מימר על שירתה רבתה',4000181,'נרבי למרן ונרכן קדמיו ונאמן בה ובמשה עבדה דחסל מלת הצור ואמר תמים צורה ומדעה מכן אתעבדת ת אכהן ריש ת רבת כל תמימו לכן עבדה שרוי ואקים י בממציע מ מ קדמאיתה מניאן צומה ומ תנינתה מניאן נביותה מכן כתב י בין תרתיה ומלך בקמאיתה רבין דן שמה ורבה מקרתה ואמר פעלו מספר שניה מקדם דתנבא ודתנבאו מנה ובריתה ועסרתי מליה ורחמיה ומקעמה בעננה מכן ברך על רישה בתמים ובעקבה פעלו הודע במלתה דפרסה דמרן בחילה עבד לכלה צער וברא ועבד ותקן בוראים רמים בחילה דתקיף # קצירן # כלה בה עביד כלה מנה מצל כלה מנה אתא כלה בה אמדבר כלה בה מתרבי טוב מן בה אתקרב ומנה לא ירחק קריב הוא לכל בלושיו ומרעי לכל רחומיו תורס תקיף ועזר לכל מן בה יימן ולמן עליו יתרחץ דו רחמן ורתאי וכן אסיד על גרמה אנשיו דדרה אתבו קנומיכון ואתוזפו נעירה מן מדעה דנביותה','Let us exalt our Master and bow down before Him and believe in Him 
and in Moses His servant, who ﬁnished (with) the word הצורand (then) said 
 ,תמיםthat is to say, the form and the mind. Therefore תwas made here a begin-
ning. תelevated all perfection, therefore he made it a beginning. And he set יin 
the middle, between (the two) .מThe ﬁrst מcorresponds to the number of the 
(days of Moses’) fasting. The second corresponds to the number of (the years of 
Moses’) prophethood. Therefore he inserted יbetween the two, and acquired at 
the beginning the glory of this name. He increased the reading and said (in ad-
dition): ( פעלוDeut. 32:4) – the number of years before the prophethood, and (the 
number of) those who were inspired by his prophethood, and the Creation, and 
the Ten Words, and the Mercy, and His residence within the cloud. Therefore he 
blessed at the beginning with תמיםand at the end with .פעלוHe made known 
through the word which he manifested, that our Master with His might made 
everything. He shaped and created and made and arranged elevated creatures 
with His mighty power. #קצירן# Everything is made by Him, everything is grant-
ed from Him, everything comes from Him, everything is led by Him, everything is 
exalted by Him. Happy is he who draws near to Him and does not move away 
from Him. He is near to all who seek Him and protects all his devotees. A strong 
shield and an aid to all who believe in Him and who trust Him, for He is merciful 
and gracious, and so He testiﬁed about Himself (Exod. 34:6). O people of the 
generation, set yourselves and increase insight from the mind of the prophet-
hood.','נרומם את אדוננו ונשתחווה לפניו ונאמין בו ובמשה עבדו, אשר סיים את המילה הצור ואמר תמים, כלומר הצורה והתבונה. לכן נעשתה כאן ת'' ראשית. ת'' הרימה את כל השלמות, ולכן עשאה ראשית. ויסד את י'' באמצע, בין שני המ"מין. המ"מ הראשון מקביל למניין (ימי הצום של משה). המ"מ השני מקביל למניין (שנות נבואתו של משה). לכן שם את י'' בין שניהם, וקנה בראשיתו את כבוד השם הזה. הרבה בקריאה ואמר (בנוסף): פעלו (דברים לב,ד) – מניין השנים שלפני הנבואה, ו(מניין) אלה שהונעו על ידי נבואתו, והבריאה, ועשרת הדברות, והרחמים, ושכינתו בתוך הענן. לכן בירך בתחילה ב תמים ובסוף ב פעלו. הודיע על ידי המילה שגילה, שאדוננו בכוחו עשה הכל. עיצב וברא ועשה וסידר יצורים נשגבים בכוחו הגדול. הכל נעשה על ידו, הכל ניתן ממנו, הכל בא ממנו, הכל מונהג על ידו, הכל מתרומם על ידו. אשרי מי שמתקרב אליו ואינו מתרחק ממנו. הוא קרוב לכל מבקשיו ושומר על כל חסידיו. מגן עז ועזרה לכל המאמינים בו ובוטחים בו, כי הוא רחום וחנון, וכך העיד על עצמו (שמות לד,ו). הו אנשי הדור, כוננו עצמכם והרבו בהבנה מתוך תבונת הנבואה.');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (261,'IV','92','מימר על שירתה רבתה',4000921,'מלתה אשתיתה כי קרוב יום אידם ארף ממני ואשמידם ואמח את שמם הנ › ך ‹ שכב עם אבותיך וקם עמה הדן וזנה בתר אלהי נכר מן עבד בישה ייבד בקשטה שיורה בישה שיורה דשגות › ה ‹ גזוי קשי › י ‹ גזי ביום דינה טובי שיורה דלה אתמר והם תכו לרגליך ושאו מדבר אה רבו רבה אה שלטנו יתרה מרביה למי ימלכה יתודי מלכה רחמנה הממן לקלמה לא עד סוף עלם מניר עלם זכותה סדר גדיל כהלה אצלחו זבנה דהוה בה נב רבה משה נהרה מופע על כל עלמה','The sixth statement: For the day of their calamity is at hand (Deut. 32:35) 
– let me alone, that I may destroy them and blot out their name (Deut. 9:14), you 
are soon to lie with your fathers then this people will rise and play the harlot afer 
the alien gods (Deut. 31:16) – he who does evil will perish by truth. A bad rem-
nant is the remnant of the error. A severe repayment will be repaid to him on the 
Day of Judgement. Happy is the remnant about whom it was said: They submit-
ted to Your steps, receiving Your commands (Deut. 33:3). Behold great majesty, 
behold an immense sovereignty that exalts its owner. Thanks to the merciful King 
who endures alone to eternity. An enlightening time (was) the time of righteous-
ness. A great order, fully of prosperity (was) the time in which the great prophet 
Moses was. Its light shone over the whole world.','האמירה השישית: "כִּי קָרוֹב יוֹם אֵידָם" (דברים לב,לה) – "הֶרֶף מִמֶּנִּי וְאַשְׁמִידֵם וְאֶמְחֶה אֶת שְׁמָם" (דברים ט,יד), "הִנְּךָ שֹׁכֵב עִם אֲבֹתֶיךָ וְקָם הָעָם הַזֶּה וְזָנָה אַחֲרֵי אֱלֹהֵי נֵכַר הָאָרֶץ" (דברים לא,טז) – מי שעושה רע ייאבד על ידי האמת. שארית רעה היא שארית הטעות. תשלום חמור יושלם לו ביום הדין. אשרי השארית שעליה נאמר: "תַּכּוּ לְרַגְלֶךָ יִשָּׂא מִדַּבְּרֹתֶיךָ" (דברים לג,ג). הנה גדולה עצומה, הנה ממשלה אדירה המרוממת את בעליה. תודה למלך הרחום הנצחי העומד לבדו לעולמי עד. עת מאירה הייתה עת הצדקה. סדר גדול ומלא שגשוג הייתה העת שבה היה משה הנביא הגדול. אורו הבהיק על פני כל העולם.');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (262,'IV','37','מימר על שירתה רבתה',4000371,'יקניאהו בזרים גלה בנאירו מן מדעה דקשטה דפאניה בישה ייתי ויעבד תועבהן ויקנא לאלה ייתי לאתר קשטה ויעלם עליו ויקים אתר עורן ובה יקנא אה עלמה כליתה ולא תרבה לה תקומה ולא תחיל לה חיל ולא תסגי לה פריה כמבולאי אבדה כות סדמאי אוקדה כות מגדלאי בדרה כות מצראי שיאצה כות פרעה שנקה כות עמלק קטלה וכקרח אבדה דמרך רצי בכן והן תרף ולא תצבי תלעט כארע קין ותהפך כות סדם ואלה מנך מזדכי דו לא יהב בישה ולא יחס עליון ברן ירחם לטביה דשמעו ית קלה ונטרו גזיראתה דו רחמנה ורתאה מקבל כל דבעי לה בנצירו','They stirred him to jealousy with alien (gods) (Deut. 32:16). He revealed 
with insight from the mind of the True One that the evil apostate will come and 
do abhorrent things and stir God to jealousy. He will come to the place of the 
True One, but will shun it and establish another place and stir up jealousy there. 
O world, make an end of him, lest his presence increase. Do not strengthen his 
power, nor increase his fruit. Destroy him like the people of the Flood, burn him 
like the people of Sodom. Scatter him like the people of the Tower, uproot him 
like the Egyptians. Aﬄict him like Pharaoh, slay him like Amaleq, destroy him 
like Korah, for your Lord desires this. If you leave him alone and do not want 
(likewise), you will be cursed like the land of Cain, and be overthrown like 
Sodom, and God is exempt from you. For He does not like the evildoers and has 
no pity for them. But He loves the good ones, who hear His voice and keep His 
decrees, for He is merciful and full of pity, and receives all who seek Him in 
devotion.','יַקְנִאֻהוּ בְּזָרִים (דברים לב,טז). הוא גילה בתבונה מדעתו של האמת שהמשומד הרשע יבוא ויעשה דברים מתועבים ויקנא את האל. הוא יבוא למקומו של האמת אך יתחמק ממנו, יכונן מקום אחר ויעורר שם קנאה. עולם, עשה בו כלה, פן יגדל נוכחותו. אל תחזק את כוחו ואל תרבה את פריו. השמידהו כאנשי המבול, שרפהו כאנשי סדום. פזרהו כאנשי המגדל, עקרהו כמצרים. ענהו כפרעה, הרגהו כעמלק, השמידהו כקורח, כי אדונך חפץ בכך. אם תניח לו ולא תרצה לעשות כן, תהיה ארור כארץ קין, ותהפך כסדום, והאל יהיה פטור ממך. שכן הוא אינו אוהב את הרשעים ואין לו עליהם חמלה. אולם הוא אוהב את הטובים, השומעים בקולו ושומרים את חוקיו, כי הוא רחמן ומלא חמלה, ומקבל את כל המבקשים אותו בכוונה.');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (263,'IV','55','מימר על שירתה רבתה',4000551,'אני אני הוא יתרבי אמורה מזזע עלמה אהיה אשר אהיה פתח מדינת רוח אני אני הוא פתח מדינת שאול אהיה אשר אהיה פצה ושנק אני אני הוא קטל וחוי אהיה אשר אהיה אנשמת ואלעת אני אני הוא פלטת ואבדת אהיה אשר אהיה לישראל פרק וכדו , אזהרון מן חלו › פ ‹ ה . וילה פרעה וכל סיעתה כד מלל משה באהן שמה תבר שרוון ולא } ק {» פרקה עד אבדה כן כ « ד קשטה מתחזי וקלה מתאזל לגו עלמה אני אני הו ירתאתו כל } עלמה אני { בוראיה וידחלו מן משמע אהן קלה רבה תמן יתפרקו כל טביה ויאבדו כל בישיה אה אלה רחמן ולית חורי לבר מנה נרכן לקדמיו ונשתעבד קדם גדלה ונאמן בנביות נביה רבה משה דשגרה טוב מן בה יימנו } ו { ולפקודיה יטרו כי מרון לון מעיני ברחמיו ומפצי יתון מכל תשניק בעלמה ובחרית עמו הך מלל נביה רבה משה הדה שירתה ואמר הרנינו גוים עמו תמן כהלון עקדו וסגדו ובלשו פרקנה אנן בניה דאלין דבמשה אישה אזדמנו ושמעו מנה הדה שירתה רבתה ואתוקרו בה טב לן נהי כותון מזדמנים על קשטה ולא נפק מנה כד מלל משה מימרי ת } ח { שבחתה וכל חילה דבוראיה עמה מזדמנים וכל קהל ישראל נציב למשמע בדיל יילף וילף ונביה רבה משה מוכח לון בדיל יתוזפו ולא יתנשו לאהן ממללה רבה','I, I am He (Deut. 32:39) – exalted be the Sayer who shakes the world. I 
am who I am (Exod. 3:14) – opened the domain of relief; I, I am He – opened the 
domain of Sheol. I am who I am – delivered and chastised; I, I am He – slew and 
made alive. I am who I am – gave relief and troubled; I, I am He – saved and 
destroyed. I am who I am – Israel] He deliver(ed), and now warned them against 
the alternative. Woe to Pharaoh and all his company when Moses spoke in this 
name; He broke their strength and did not relieve him till He destroyed him. 
Thus, when the True One appears and His voice walks all over the world: I, I am 
He, all the creatures tremble and fear hearing this great voice. Then all the good 
ones will be relieved and all the evil ones will perish. Behold, a merciful God and 
there is none besides Him. Let us bow down before Him, and submit before His 
greatness, and believe in the prophethood of the great prophet Moses, whom He 
sent. It is good for those who believe in Him and keep His commandments, for 
their Master will watch them in His mercy and relieve them from any aﬄiction in 
this world and in the world to come. See how the great prophet Moses uttered 
this song and said: O nations, acclaim His people (Deut. 32:43). Then all of them 
bowed and worshipped and sought the deliverance. “We are the sons of these 
who were gathered with Moses the Man and heard from him this Great Song and 
were gloriﬁed by it. It is good for us to be gathered with the True One like them, 
and not depart from Him.” When Moses uttered the words of praise, and all the 
host of creatures gathered with him, and all the congregation of Israel were 
standing to hear in order to learn, (then) the great prophet Moses taught, 
reproving them so that they might be increased and forget not this great word.','אֲנִי אֲנִי הוּא (דברים לב,לט) – יִתְרוֹמֵם הָאוֹמֵר שֶׁמַּרְעִישׁ אֶת הָעוֹלָם. אֶהְיֶה אֲשֶׁר אֶהְיֶה (שמות ג,יד) – פָּתַח אֶת תְּחוּם הַהַצָּלָה; אֲנִי אֲנִי הוּא – פָּתַח אֶת תְּחוּם שְׁאוֹל. אֶהְיֶה אֲשֶׁר אֶהְיֶה – הוֹשִׁיעַ וְיִסֵּר; אֲנִי אֲנִי הוּא – הֵמִית וְהֶחֱיָה. אֶהְיֶה אֲשֶׁר אֶהְיֶה – הֵנִיחַ וְהֵצִיק; אֲנִי אֲנִי הוּא – הֵצִיל וְהִשְׁמִיד. אֶהְיֶה אֲשֶׁר אֶהְיֶה – אֶת [יִשְׂרָאֵל] הֵצִיל, וְעַתָּה הִזְהִירָם מִפְּנֵי הַחֲלוּפָה. אוֹי לְפַרְעֹה וְכָל חֵילוֹ כְּשֶׁדִּבֶּר מֹשֶׁה בַּשֵּׁם הַזֶּה; שָׁבַר אֶת כֹּחָם וְלֹא הֵנִיחַ לוֹ עַד שֶׁהִשְׁמִידוֹ. כָּךְ, כְּשֶׁיִּגָּלֶה הָאֱמִתִּי וְקוֹלוֹ יַהֲלֹךְ בְּכָל הָעוֹלָם: אֲנִי אֲנִי הוּא, כָּל הַבְּרִיּוֹת רוֹעֲדוֹת וּפוֹחֲדוֹת לִשְׁמֹעַ קוֹל גָּדוֹל זֶה. אָז יָנוּחוּ כָּל הַטּוֹבִים וְכָל הָרָעִים יֹאבֵדוּ. הִנֵּה אֵל רַחוּם וְאֵין בִּלְתּוֹ. נִשְׁתַּחֲוֶה לְפָנָיו וְנִכָּנַע לִפְנֵי גְּדֻלָּתוֹ, וְנַאֲמִין בִּנְבוּאָתוֹ שֶׁל הַנָּבִיא הַגָּדוֹל מֹשֶׁה שֶׁשְּׁלָחוֹ. טוֹב לְאוֹתָם הַמַּאֲמִינִים בּוֹ וְשׁוֹמְרִים אֶת מִצְווֹתָיו, כִּי אֲדוֹנָם יִשְׁמְרֵם בְּרַחֲמָיו וְיַצִּילֵם מִכָּל צָרָה בָּעוֹלָם הַזֶּה וּבָעוֹלָם הַבָּא. רְאוּ כֵּיצַד אָמַר הַנָּבִיא הַגָּדוֹל מֹשֶׁה אֶת הַשִּׁירָה הַזֹּאת וְאָמַר: הַרְנִינוּ גוֹיִם עַמּוֹ (דברים לב,מג). אָז כֻּלָּם כָּרְעוּ וְהִשְׁתַּחֲווּ וּבִקְּשׁוּ אֶת הַיְּשׁוּעָה. "אֲנַחְנוּ בְּנֵי אוֹתָם שֶׁנֶּאֶסְפוּ עִם מֹשֶׁה הָאִישׁ וְשָׁמְעוּ מִמֶּנּוּ אֶת הַשִּׁירָה הַגְּדוֹלָה הַזֹּאת וְהִתְכַּבְּדוּ בָּהּ. טוֹב לָנוּ לְהֵאָסֵף אֶל הָאֱמִתִּי כְּמוֹתָם, וְלֹא לָסוּר מִמֶּנּוּ." כְּשֶׁאָמַר מֹשֶׁה אֶת דִּבְרֵי הַשֶּׁבַח, וְכָל צְבָא הַבְּרִיּוֹת נֶאֱסַף עִמּוֹ, וְכָל עֲדַת יִשְׂרָאֵל עָמְדָה לִשְׁמֹעַ כְּדֵי לִלְמֹד, (אָז) לִמֵּד הַנָּבִיא הַגָּדוֹל מֹשֶׁה, מוֹכִיחָם כְּדֵי שֶׁיִּרְבּוּ וְלֹא יִשְׁכְּחוּ אֶת הַדָּבָר הַגָּדוֹל הַזֶּה.');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (264,'IV','88','מימר על שירתה רבתה',4000881,'עד אמת דינין עד אמת ערואין שרין בנן ולינן דחלים אהן בלבה ואהן בבניה ואהן בגויתה ואהן בחילה ואהן במדלה אלמנהן שגיהן יתמין מקצפין רבקין מרודין ילידם משתיצאים אה מן בישתה האן דהגלת אנדת אבדן האן תסגי תמחק אנשי אתרה עמי עובדה בגו גן עדן טרדת חייה והנדת מותה אדירת ית קבלה בלבה הקשת לבה דקין ושותה נע ונד הרמת בניו במעוהן רברבהן קמת › עם ‹ בנאי מגדלה ובדרת יתון על אפי כל ארעה לגברי סדם אוקדת לפרעה אבדת למצר חרבת לעמלק קטלת שלמת על בר שלומית אתרגם מללת עם קרח בלעת יתה ארעה לזמרי בזעת לעבודי › עגלה ‹ קטלת לאוי הרחוק מנה וחסרן חזוה ולא תמללן ולא נשמע לקולה ולא נהי לה חברים מן האן היא › ו ‹ מן האן אנן אנן בני טבים אנן בני זכאים לית נהי מטרדים בכל ארעה ובין בוראיה מנזפין ולן תקום מלי } מלי { דינה חסלן מדן לא נביע אלא מלי ברכתה','How long the punishments, how long will mishaps reside among us, 
and we do not fear? The one (aﬄiction) in the heart, the one in the sons, the one 
in the body, and the one in power, and the one in the possessions. Widows are 
straying, orphans irritating, youths rebellious, children extinct. Behold, the evil 
is the cause; wherever it appeared it brought destruction. Wherever it grows it 
blots out the people of that place. See the deed that was in the Garden of Eden: It 
expelled life and installed death, settled darkness in the heart. It hardened 
Cain’s heart and made him a fugitive and a wanderer (Gen. 4:12), it cast his sons 
into great plagues. It stood against the builders of the tower and scattered them 
over the face of the whole earth. It burnt the people of Sodom, destroyed Pha-
raoh, desolated Egypt, slew Amaleq. It repaid the son of Shelomith – he was 
stoned. It incited Korah – the earth engulfed him. It ripped up Zimri. It slew the 
worshippers of the calf. Would it be that we should distance ourselves from it, 
and that we lack its image, and let it not talk to us, so that we do not listen to its 
voice and not be its friends. Where is it from – and where are we from?! We are 
the sons of the good ones, we are the sons of the righteous. We shall not be 
driven away all over the earth, and (not) rebuked amongst the creatures, and the 
words of judgement (will not) refer to us. Far be it from us. We shall not seek 
anything but the words of the blessings.','כמה ארוכים הייסורים, כמה זמן ישכנו תקלות בינינו ואין אנו יֵרָאים? האחת בלב, האחת בבנים, האחת בגוף, והאחת בכוח, והאחת ברכוש. אלמנות תועות, יתומים מרגיזים, נוער מורד, ילדים כלים. הנה, הרוע הוא הגורם; בכל מקום שהופיע הביא חורבן. בכל מקום שצמח הוא מוחה את בני אותו מקום. ראה את המעשֶׂה שהיה בגן עדן: הוא גירש את החיים והכניס את המוות, הִשְׁכִּין חושך בלב. הוא הִקשה את לב קין ועשׂהו נָע וָנָד (בראשית ד,יב), הִטיל את בניו לתוך מכות גדולות. הוא עמד נגד בוני המגדל ופיזרם על פני כל הארץ. הוא שרף את אנשי סדום, הָרַס את פרעה, השמים את מצרים, הִכָּה את עמלק. הוא שִׁלֵּם לבן שלומית – נִסקל. הוא הסית את קורח – הארץ בלעתו. הוא קָרַע את זִמְרִי. הוא הרג את עובדי העֵגֶל. הלוואי שנתרחק ממנו, ושלא תהיה בנו דמותו, ושלא ידבר אלינו כדי שלא נשמע בקולו ולא נהיה ידידיו. מאין הוא – ומאין אנחנו?! אנו בני הטובים, אנו בני הצדיקים. לא נידח לכל קצות הארץ, ולא נוּכַח בין הברואים, ודברי הדין לא יתייחסו אלינו. חלילה לנו. לא נבקש דבר זולת דברי הברכות.');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (265,'IV','105','מימר על שירתה רבתה',4001051,'נעזר כדו במדע שלם אל מימרה כי ידין יהוה עמו תדע כל נפש גזוה אכה עמי דחכמו יתי איך יתוחו בטובי ויתפוגגו באיקרי עמי איך אתמרת לפרעה מלך מצרים שלח עמי כי בדיל פרקנה אנה מתחזי כי שחת עמך חובה רבה ביומה דנקם יתפרק דן מן דן מכן אמר נביה רבה משה ועל עבדיו יתנחם מן פנה יגבי ומן שמע ינשם טובי שמועיה ווילון כל חיביה ועורי ועל עבדיו יתנחם מלה כהלה איקר תהבה יקום ויהוה יתנחם מקום יום נקם מקום עגלה בישה אתקף רגזה למכלי עמה צלא נביה רבה משה אתעזר רגזה ואתנחם על שיור לא עבדו עגלה מכן יום נקם תתוקד אשתה רבתה מן הוה על קשטה לית לה עליו יכלה נטר מליה דפקדן מרן כי היא חייה וארך יומיה למי יטרון','Let us return now with perfect mind to His saying: For the Lord will 
judge his people (Deut. 32:36). Let every soul know his recompense here. See 
how those who know Me will live through My goodness and be joyful through My 
glory. See how it was said to Pharaoh, king of Egypt: Let my people go (Exod. 5:1) 
– for I appear for the sake of his deliverance. For your people have acted corruptly 
(Deut. 9:12) – a great sin. On the Day of Vengeance one will be separated from the 
other. Therefore the great prophet Moses said: And have compassion on his 
servants (Deut. 32:36). The one who is apostate will be punished, but the one 
who obeys will ﬁnd rest. Happy are those who listen, woe to all guilty ones. 
Furthermore: And have compassion on his servants – a word wholly of glory. The 
Taheb will arise and the Lord will have compassion. The place of the Day of 
Vengeance will be the place of the evil calf. (When) His anger was kindled to 
exterminate the people, the great prophet Moses prayed – anger was averted and 
He had compassion for the remainder who did not worship the calf. Therefore on 
the Day of Vengeance the great ﬁre will be kindled. He who clung to the truth 
will not be overcome by it (the ﬁre). Let us keep the words which our Lord 
commanded us, for they are life and lengthening of days for those who keep 
them.','נָשׁוּבָה עַתָּה בְּדַעַת שְׁלֵמָה אֶל דְּבָרָיו: כִּי יָדִין יְהוָה עַמּוֹ (דברים לב,לו). תֵּדַע כָּל נֶפֶשׁ אֶת גְּמוּלָהּ כָּאן. רְאֵה כֵּיצַד יוֹדְעַי יִחְיוּ בְּטוּבִי וְיִשְׂמְחוּ בִּכְבוֹדִי. רְאֵה כֵּיצַד נֶאֱמַר לְפַרְעֹה מֶלֶךְ מִצְרַיִם: שַׁלַּח אֶת עַמִּי (שמות ה,א) – כִּי אֲנִי נִגְלָה לְמַעַן הַצָּלָתוֹ. כִּי שִׁחֵת עַמְּךָ (דברים ט,יב) – חֵטְא גָּדוֹל. בְּיוֹם הַנְּקָמָה יִבָּדֵל זֶה מִזֶּה. לְפִיכָךְ אָמַר מֹשֶׁה הַנָּבִיא הַגָּדוֹל: וְעַל עֲבָדָיו יִתְנֶחָם (דברים לב,לו). הַמּוֹרֵד יֵעָנֵשׁ, אַךְ הַשּׁוֹמֵעַ יִמְצָא מְנוּחָה. אַשְׁרֵי הַמַּאֲזִינִים, אוֹי לְכָל הָאֲשֵׁמִים. וְעוֹד: וְעַל עֲבָדָיו יִתְנֶחָם – מִלָּה שֶׁכֻּלָּהּ כָּבוֹד. הַתָּאֵב יָקוּם וַיהוָה יְרַחֵם. מְקוֹם יוֹם הַנְּקָמָה יִהְיֶה מְקוֹם עֵגֶל הָרָעָה. כַּאֲשֶׁר חָרָה אַפּוֹ לְהַשְׁמִיד אֶת הָעָם, הִתְפַּלֵּל מֹשֶׁה הַנָּבִיא הַגָּדוֹל – הֻסַּר הָאַף וְרִחֵם עַל הַשְּׁאָר שֶׁלֹּא עָבְדוּ אֶת הָעֵגֶל. לְפִיכָךְ בְּיוֹם הַנְּקָמָה תִּדְלַק הָאֵשׁ הַגְּדוֹלָה. מִי שֶׁנִּדְבַּק בָּאֱמֶת לֹא יִגָּבַר עָלָיו הָאֵשׁ. נִשְׁמְרָה אֶת הַדְּבָרִים אֲשֶׁר צִוָּנוּ אֲדֹנֵנוּ, כִּי חַיִּים הֵם וְאֹרֶךְ יָמִים לְשֹׁמְרֵיהֶם.');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (266,'IV','1','מימר על שירתה רבתה',4000011,'עמו הך משה הוה משבח וכלה עמה אזדמן הך זומנוהתה דהות על רישה דטור סיני קעם קדמון ודרש מקרתה ושרי מקרינה וכהלין שמעין ודחלין השתקו יתה הך שרי ואמר וידבר הך הות מקרתה דאלה מרישה וידבר עמו רז וידבר ומהי מצמתה מן גוני איקרה דכהלה אצלחו הות מתאמרה ברישה לנח בסור אנחמו וקוממות סקפנה ובסור במפוקה מן תיבותה ומשחיתה עביד אלפנה דאתא בה אמרה בשרוי זיעקתה הך דעבדת שרוי ספרה תליתה ויקרא אל משה וידבר יה אל שרוה בסור וחסולה אנחמו וחתמת מצוהתה במעכום ברכה מכן עובד נח אתחדד אכה ועוד במניאנה אתעבד כתבה דאתעתד לאיטבו וכן עוד בשרוי ספרה רביעיה כד אמר תמן וידבר חדדה אכה וכל מצוהתה בה משררה כד פקד אהרן בברכה על ישראל הות מצוה ועוד ברכה מצוה לה ולבניו וברכה לה ולישראל מכן כתב בשרוה וידבר וכן בזבן עובד חציצרהתה הות מצוה וברכה וכן במצות קרבניה מדמי לכל מה דאתדכר עמי רבינה ולא תבקר סגי מכן','See how Moses was praising with everyone assembled before him, like 
the assembly that was on the top of Mount Sinai. He stood before them and di-
rected himself to the Law and began to read it, and all of them listened and 
feared. They gazed at him in silence, as he began and said: ( וידברDeut. 31:30), as 
was the call of God at its beginning: ( וידברGen. 8:15). See the meaning of וידבר
and what the various honors that it comprises are, all of which (involve) prosper-
ity. It was ﬁrst said to Noah (as) a message of relief, and of the establishment of 
the covenant, and the announcement of his exit from the ark. In its (the Ark’s) 
dimensions, into which he entered, the teaching was conceived. He said it at the 
beginning of His call (to Moses), as it was (also) made the beginning of the Third 
Book: And He called to Moses and the Lord spoke to him (Lev. 1:1). Its beginning is 
a summons and its end is relief, and at the end of the commandments there is 
the teaching of the blessing. Therefore the work of Noah was renewed here. 
Moreover, in its number the Law was conceived, which was set up for the best. 
Furthermore, at the beginning of the Fourth Book, that which He said there, 
 ,וידברHe renewed here, and all the commandments He emphasized with it. 
When He commanded Aaron to bless Israel, there was a commandment and a 
blessing: a commandment for him and his sons and a blessing for him and 
Israel. Therefore He wrote at its beginning, .וידברAnd also at the time of the 
making of the trumpets, there was a commandment and a blessing. And also in 
the commandment regarding the oﬀerings there is a resemblance to all that was 
mentioned (above). See its greatness and do not inquire further.','ראה כיצד משה היה מהלל כאשר כולם אסופים לפניו, כמו הקהל שהיה על ראש הר סיני. עמד לפניהם ופנה לתורה והחל לקרוא אותה, וכולם שמעו ויראו. הביטו בו בדומייה, כשהחל ואמר: וַיְדַבֵּר (דברים לא,ל), כפי שהייתה קריאת האל בתחילתה: וַיְדַבֵּר (בראשית ח,טו). ראה את משמעות וַיְדַבֵּר ומהם הכבודים השונים שהוא כולל, שכולם עניין של שגשוג. בתחילה נאמר לנח כמסר של הקלה, ועל כינון הברית, ועל בשורת יציאתו מן התיבה. במידותיה של התיבה, שבה נכנס, נולדה התורה. נאמר בתחילת קריאתו לו, כפי שגם נעשה ראשית הספר השלישי: וַיִּקְרָא אֶל מֹשֶׁה וַיְדַבֵּר ה'' אֵלָיו (ויקרא א,א). תחילתו זימון וסופו הקלה, ובסוף המצוות יש תורת הברכה. לפיכך התחדש כאן מפעל נח. יתר על כן, במספרו נולדה התורה, שהוקמה לטובה. ועוד, בתחילת הספר הרביעי, מה שנאמר שם וַיְדַבֵּר – חידש כאן, ואת כל המצוות הדגיש בו. כאשר ציווה על אהרן לברך את ישראל, הייתה מצווה וברכה: מצווה לו ולבניו וברכה לו ולישראל. לכן כתב בתחילתו וַיְדַבֵּר. וגם בעת עשיית החצוצרות הייתה מצווה וברכה. וגם במצוות הקורבנות יש דמיון לכל שנזכר לעיל. ראה את גדולתו ואל תדרוש יותר.');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (267,'IV','25','מימר על שירתה רבתה',4000251,'עמו ממללה אהן דמללה משה בתר מה אמר מלת ואין אפך ואמר עול הך מה דהוה ברישה כן הו בעקבה לא תכיר פנים לית בה עול במות תמות לית בה עול כד זעק גדלה לאדם לא הוה תמן עול מנו מגזי לקין לא הוה תמן עול כד שוה לחוה צערה לא הוה תמן עול כד לעט ארעה לא הוה תמן עול כד גזי למך במה דעבד לא הוה תמן עול כד ברך לנח ולעט ית ברה לא הוה תמן עול כד הפך סדם לא הוה תמן עול כד אבד פרעה לא הוה תמן עול כד שנק מצראי לא הוה עול כד קטל עבודי עגלה לא הוה עול דכל אחד מן אלין אתגזי במד עבד','See this statement that Moses said afer he had said the word and 
without (Deut. 32:4). He said further injustice (ibid.). As it was at the beginning, 
so it is at the end. You shall show no partiality (Deut. 16:19) – there is no injustice 
in it. Regarding you shall die (Gen. 2:17) – there is no injustice. When His Great-
ness called Adam, there was no injustice. When He punished Cain, there was no 
injustice. When He put the pain on Eve, there was no injustice. When He cursed 
the land, there was no injustice. When He punished Lamech for what he had 
done, there was no injustice. When He blessed Noah and cursed his son, there 
was no injustice. When He overthrew Sodom, there was no injustice. When He 
destroyed Pharaoh, there was no injustice. When He aﬄicted the Egyptians, 
there was no injustice. When He slew the makers of the calf, there was no injus-
tice. For every one of these was repaid according to what he had done.','ראה את האמירה הזאת שאמר משה לאחר שאמר את המילה ובְּלִי (דברים לב,ד). אמר עוד עָוֶל (שם). כאשר בהתחלה, כך בסוף. לֹא תַכִּיר פָּנִים (דברים טז,יט) – אין בו עוול. לגבי מוֹת תָּמוּת (בראשית ב,יז) – אין עוול. כשגדולתו קרא לאדם, לא היה עוול. כשהעניש את קין, לא היה עוול. כשנתן את הכאב לחוה, לא היה עוול. כשקילל את האדמה, לא היה עוול. כשהעניש את למך על מה שעשה, לא היה עוול. כשברך את נח וקילל את בנו, לא היה עוול. כשהפך את סדום, לא היה עוול. כשהשמיד את פרעה, לא היה עוול. כשהכה את המצרים, לא היה עוול. כשהרג את עושי העגל, לא היה עוול. כי כל אחד מאלה שולם לו כפי מעשיו.');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (268,'IV','106','מימר על שירתה רבתה',4001061,'מלה רבה דאמרה נביה רבה משה ואפס עצור ועזוב עצוריה עבודי חוביה ועזוביה שבקי חוביה אהן כמשה ומן מדמי למשה דאתרבה על כל מינה דאדם אמר במדעה דאלהו בפם נביותה ראו עתה כי אני אני הוא שמע ישראל יהוה אלהינו יהוה אחד כי קרא יתה עבדה ארש השלם מדעיה בה ושמה אקר לסגדה אני יהוה ושמי יהוה אהיה אשר אהיה יהוה אלהינו יהוה אחד שרוה ועקבה אני אני הוא ביום נקם כד תשתמע ייאסף העצור והעזוב','This is a great word which the great prophet Moses said: And there is 
none remaining, bond or free (Deut. 32:36). The “bond” are the doers of sins and 
the “free” are those forsaking sins. Where is there anyone like Moses and who 
can resemble Moses, who was magniﬁed above the whole human race? He said 
with the knowledge of Divinity, by the mouth of prophecy: See now that I, I am 
He (v. 39). Hear, O Israel, the Lord our God is one Lord (Deut. 6:4). When he 
proclaimed that, he made it a fundament by which He perfected minds, and He 
established it as a foundation for worship. I am the Lord (Exod. 20:2), and my 
name YHWH (Exod. 6:3), I am who I am (Exod. 3:14), the Lord our God is one Lord 
(Deut. 6:4) – these are the beginning and the end. I, I am He – on the Day of 
Vengeance when it is heard, the bond and the free will be assembled.','זוֹ מִלָּה גְּדוֹלָה שֶׁאָמַר מֹשֶׁה הַנָּבִיא הַגָּדוֹל: וְאֵין עָצוּר וְאֵין עָזוּב (דברים לב,לו). הָ"עָצוּר" הֵם עוֹשֵׂי הַחֲטָאִים וְהָ"עָזוּב" הֵם עוֹזְבֵי הַחֲטָאִים. אַיֵּה כָּמֹשֶׁה וּמִי יִדְמֶה לְמֹשֶׁה, אֲשֶׁר נִגְדַּל מֵעַל כָּל הַמִּין הָאֱנוֹשִׁי? אָמַר בְּדַעַת הָאֱלֹהוּת, בְּפִי הַנְּבוּאָה: רְאוּ עַתָּה כִּי אֲנִי אֲנִי הוּא (פסוק לט). שְׁמַע יִשְׂרָאֵל יְהוָה אֱלֹהֵינוּ יְהוָה אֶחָד (דברים ו,ד). כַּאֲשֶׁר הִכְרִיז זֹאת, שָׂמָהּ לְיְסוֹד שֶׁבּוֹ שִׁכְלֵל אֶת הַמּוּחוֹת, וְהֶעֱמִידָהּ כְּתַשְׁתִּית לָעֲבוֹדָה. אָנֹכִי יְהוָה (שמות כ,ב), וּשְׁמִי יְהוָה (שמות ו,ג), אֶהְיֶה אֲשֶׁר אֶהְיֶה (שמות ג,יד), יְהוָה אֱלֹהֵינוּ יְהוָה אֶחָד (דברים ו,ד) – אֵלֶּה הֵם הָרֵאשִׁית וְהָאַחֲרִית. אֲנִי אֲנִי הוּא – בְּיוֹם הַנְּקָמָה כַּאֲשֶׁר יִישָּׁמַע, יֵאָסְפוּ הָעָצוּר וְהָעָזוּב.');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (269,'IV','33','מימר על שירתה רבתה',4000331,'דור עקש הוא פניה טמיה דאתי בבישו מחלל קדשה ויבן בית ביש על שם אלהי נכר דלית לה נמי בעלמה כי תעזר דבבות פניה לאלה על קנומה ויגלי רבות נביה רבה משה דצמת אכהן עשר נביות וגלה יתון בהדה שירתה ואנון כהלון בסגדת אלהי נכר דייתי פניה ויעמר יתה בכל חיל אדה במרוד חיול מותר ועסרה אוכח בון לישר אוכח ועסרה } אתפוררו הן { » אתפוררוהן « הוה מפורר לכל קהלה ועשרה אזהרואן אזהרון ועסרה דינין גלה קמיון ועסרה אנחמוהן חכמון ועסרה יקירואן אוקר יתון עסרתי נביותה דבון אתנבה וחילה בם קשטה שרון מימרו זכרו יומת עולם חי אנכי לעולם יהוה ימלך עולם ועוד ואין עמו אל נכר ויטש אלה עשהו כשעירים עלי דשא ממלל אנכי יהוה ומד לה חתמת וינבלו צור ישועתו עשו עגל מסכה ואמרו אלה אלהיך ישראל יקניהו בזרים זימנון ליד בעל פעור והולדו תמן בנים דזנו ובתועב יכיעסהו זמרי זנוה דסכה דהוא מעמר פרדיס לזנותה יזבחו לשי » דים « לא אלה ביש לון וישתחוו לו ויזבחו לו בבישו יתרה אלהים לא ידעום כי תולידו בנים וירא יה וינחץ מד בה חסל ותוקיד עד שיאול תחתית וילה פאנה עובד אנשי סדם אכה אתחדד ואין מידי מציל יאבד עבודי אלהי נכר ולית לון פרקן מן גפרית ואש וכפר אדמת עמו טובי טביה דהודע לגו עלמה מה לון טמיר אקים מדעך שמועה למה דלה שמעת וטמרה בלבך עד תילף ותלף עמי רבות נביה רבה משה ושבח לאלה דחילה בתרי עלמיה איך משה לא קעם ולא יקום וכן אלה כתב בדילה ולא קם עוד נביא בישראל כמשה','A perverse generation (Deut. 32:5) – the unclean apostate who brings evil 
profanes holiness, building an evil house in the name of alien gods who have no 
share in the world. Indeed the enmity of the apostate toward God will turn back 
on himself, and the majesty of the great prophet Moses will be revealed. For he 
included here ten prophecies and revealed them in this song. They are all related 
to the worship of alien gods, whom the apostate will come and set up with all the 
might of his hand in an exceedingly mighty rebellion. With ten he reproved 
Israel, and (with) ten awakenings he was arousing the congregation, and ten 
warnings he warned them, and ten judgments he revealed before them, and ten 
comforts he announced to them, and with ten honors he honored them. The ten 
prophecies which he prophesied, and by which the True One strengthened him, 
began with his saying: Remember the days of eternity (v. 7), as I live forever 
(v. 40), the Lord will reign for ever and ever (Exod. 15:18), there is no foreign god 
with Him (Deut. 32:12). Then he forsook God who made him (v. 15), like iniquity on 
the grass (v. 2), the saying I am the Lord (Exod. 20:2) and what followed it. (He) 
spurned the Rock of his salvation (Deut. 32:15), they have made […] a molten calf 
[…] saying: This is your god, O Israel (Exod. 32:8). They stirred Him to jealousy 
with alien (gods) (v. 16) – they gathered at Baʿal Peʿor and there begot sons of 
harlotry. With abominable practices they provoked Him to anger (v. 16) – Zimri the 
fornicator who sought to plant a garden of fornication. They sacriﬁced to demons 
which were no gods (v. 17) – evil for them. (They) have worshiped it and sacriﬁced 
to it (Exod. 32:8). To gods they had never known (Deut. 32:17), when you beget 
children (Deut. 4:25). The Lord saw it and was vexed and so forth (Deut. 32:19). 
And it burns to the depths of Sheol (v. 22) – woe to the apostate, the deed of the 
people of Sodom is renewed here. And there is none that can deliver out of my 
hand (v. 39) – He will destroy the worshippers of alien gods, and they will have 
no deliverance from brimstone and ﬁre (Gen. 19:24). And makes expiation for the 
land of his people (SP Deut. 32:43). Happy are the good ones, for He has made 
known to the world what is foreseen for them. Set your mind, O hearer, to what 
you have heard and treasure it in your heart, that you may learn and teach. See 
the majesty of the great prophet Moses and praise God who strengthened him in 
both worlds. Like Moses nobody has arisen nor will arise. Thus wrote God of 
him: Never again did there arise in Israel a prophet like Moses (Deut. 34:10).','דּוֹר עִקֵּשׁ (דברים לב,ה) – המשומד הטמא המביא רעה מחלל את הקדושה, בונה בית רע בשם אלים זרים שאין להם חלק בעולם. אכן, איבת המשומד כלפי האל תשוב עליו עצמו, וגדולתו של הנביא הגדול משה תתגלה. שכן הוא כלל כאן עשר נבואות וגילה אותן בשירה זו. כולן קשורות לעבודת אלים זרים, שהמשומד יבוא ויקים אותם בכל עוז ידו במרד עצום ביותר. בעשרה הוכיח את ישראל, ובעשרה עוררים עורר את הקהל, ועשרה אזהרות הזהירם, ועשרה משפטים גילה לפניהם, ועשרה נחמות בישר להם, ובעשרה כבודים כיבדם. עשר הנבואות שנבא, ושבהן חיזקו האמת, פתחו באמרו: זְכֹר יְמוֹת עוֹלָם (פסוק ז), חַי אָנֹכִי לְעֹלָם (פסוק מ), יְהוָה יִמְלֹךְ לְעֹלָם וָעֶד (שמות טו,יח), וְאֵין אֵל נֵכָר אִתּוֹ (דברים לב,יב). אָז עָזַב אֱלוֹהַּ עָשָׂהוּ (פסוק טו), כַּטַּל עַל עֵשֶׂב (פסוק ב), מאמר אָנֹכִי יְהוָה (שמות כ,ב) ומה שבא אחריו. נָבַל צוּר יְשֻׁעָתוֹ (דברים לב,טו), עָשׂוּ [...] עֵגֶל מַסֵּכָה [...] לֵאמֹר אֵלֶּה אֱלֹהֶיךָ יִשְׂרָאֵל (שמות לב,ח). יַקְנִאֻהוּ בְּזָרִים (פסוק טז) – נאספו בבעל פעור ושם הולידו בני זנונים. בְּתוֹעֵבֹת יַכְעִיסֻהוּ (פסוק טז) – זמרי הזנאי שביקש לנטוע גן של זנות. יִזְבְּחוּ לַשֵּׁדִים לֹא אֱלֹהַּ (פסוק יז) – רעה להם. וַיִּשְׁתַּחֲווּ לוֹ וַיִּזְבְּחוּ לוֹ (שמות לב,ח). לֵאלֹהִים לֹא יְדָעוּם (דברים לב,יז), כִּי תוֹלִיד בָּנִים (דברים ד,כה). וַיַּרְא יְהוָה וַיִּנְאָץ וְגוֹמֶר (דברים לב,יט). וְתִיקַד עַד שְׁאוֹל תַּחְתִּית (פסוק כב) – אוי למשומד, מעשה אנשי סדום מתחדש כאן. וְאֵין מִיָּדִי מַצִּיל (פסוק לט) – הוא ישמיד את עובדי האלים הזרים, ולא תהיה להם ישועה מגָּפְרִית וָאֵשׁ (בראשית יט,כד). וְכִפֶּר אַדְמָתוֹ עַמּוֹ (ספר שומרוני, דברים לב,מג). אשרי הטובים, שהוא הודיע לעולם מה צפוי להם. שים את לבך, שומע, למה ששמעת ואצור אותו בלבבך, למען תלמד ותלמד. ראה את גדולתו של הנביא הגדול משה ושבח את האל אשר חיזקו בשני העולמות. כמשה לא קם ולא יקום. כך כתב עליו האל: וְלֹא קָם נָבִיא עוֹד בְּיִשְׂרָאֵל כְּמֹשֶׁה (דברים לד,י).');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (270,'IV','94','מימר על שירתה רבתה',4000941,'יזעק לכל ] ב [ וראיו הך ] ד [ ו בעי תת ] פלג ארעה מ [ ן ] אימ [ תה ] ויק [ ומו כעטף ] עינ [ ה פעם אחת ויתפרסו כהלון לקדמיו ארעה חדה ופלוגה מתחלף כד תתפלג מעל טביה יסק מנה ריח מיר מנקב יעלה ריח ניחח אל מעונה עלאה ובישיה יסק ריח עפרון כמה אמיר ואסרת ארעה › יעזר ‹ ועמה גפרי ואש וכד יזדמנו אלין ואלין צפי מפרשה בין תריון טביה ריחון מקבל ותכסיהתון מתחדדים הך דאמר שמלתך לא בלתה מן עלויך ואדם ונח וזכאי עלמה קמיון ומלאכי רצונה סהרין בון וטללי רחמיה רססים עליון ואורה מניר לון ונביה רבה משה מתגלג בון ואהרן כהנה חדי בדילון וברה אלעזר ששי בון ופינחס מקלס לון ויהושע וכלב והשבעים הזקנים מרבים לון ורצון יהוה שרי עליון וקרי דדיון וישכן ישראל בטח בדד אלין עקובאת טביה מסחני זכותה דנטרו גזירהתה דגזרה אלה ולא עלמו עליה','He will summon all His creatures as He wants. The earth will be split 
because of His awe, and they will rise in a wink of the eye, at once, and all will 
spread out before Him. (Then) the earth will reunite and its division will change. 
When it splits from above the good ones a smell of perfume of garments will 
issue. Pleasing odor will ascend to the Upper Abode. And the evildoers, the smell 
of their dust will arise, as it is said: the land stank (Exod. 8:10). It will return, and 
with it brimstone and ﬁre. When they meet these with these, see the diﬀerence 
between them. The good ones, their smell will be accepted and their garments 
[renewed as He said: Your clothing did not wear out upon you (Deut. 8:4). Adam 
and Noah and the Righteous of the world before them, and the angels of the 
Divine Favor surround them, and the dew of mercy showers upon them, and the 
Light shines on them, and the great prophet Moses is praised by them, and 
Aaron the priest rejoices because of them, and his son Eleazar is joyful with 
them, and Phinehas praises them, and Joshua and Caleb and the seventy elders 
exalt them, and the Lord’s Favor abides over them and proclaims about them: 
Israel dwelt in safety […] alone (Deut. 33:28). These are the attributes of the good 
ones, the owners of righteousness, who kept the precepts which God decreed, 
and they did not ignore them.','הוא יזמן את כל ברואיו כרצונו. הארץ תיבקע מיראתו, והם יקומו כהרף עין, כאחד, וכולם יתפרשו לפניו. ואז תתאחד הארץ מחדש ותתחלף חלוקתה. כאשר תיבקע מעל הצדיקים, ייצא ריח בושם של בגדים. ריח ניחוח יעלה אל המעון העליון. ואילו הרשעים – ריח עפרם יעלה, כפי שנאמר: "וַתִּבְאַשׁ הָאָרֶץ" (שמות ח,י). הוא ישוב, ועמו גפרית ואש. כשייפגשו אלה באלה, ראה את ההבדל ביניהם. הטובים – ריחם יהיה מקובל ובגדיהם יתחדשו, כפי שאמר: "שִׂמְלָתְךָ לֹא בָלְתָה מֵעָלֶיךָ" (דברים ח,ד). אדם ונוח וצדיקי עולם לפניהם, ומלאכי החסד האלוהי מקיפים אותם, וטל הרחמים יורד עליהם, והאור זורח עליהם, ומשה הנביא הגדול מהולל על ידם, ואהרן הכוהן שמח בשבילם, ואלעזר בנו גיל עמם, ופינחס משבח אותם, ויהושע וכלב ושבעים הזקנים מרוממים אותם, ורצון ה'' שוכן עליהם ומכריז עליהם: "וַיִּשְׁכֹּן יִשְׂרָאֵל בֶּטַח [...] בָּדָד" (דברים לג,כח). אלה הם תכונות הטובים, בעלי הצדקה, ששמרו את המצוות שגזר האלוהים ולא התעלמו מהן.');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (271,'IV','104','מימר על שירתה רבתה',4001041,'יתפצו עתה דשרו וחכמו ראו למדתי אתכם חקים ומשפטים רק השמר לך אני אני הוא הקעום על בראשית ועל טור סיני אני אני הוא דהוית ולא הוה לבר מני אני אני הוא דהוית ולא עדן ולא אתר אני אני הוא דחיי עולם דילי אני אני הוא דתלית ופרסת דא } ש {» ביכילתי אני אני הוא דנצבת גנתה ואשלית סדם אני אני הוא מ « לית וחסכת אני אני הוא דכלה דילי ומעזרה לידי אני אני הוא הממית לכל חי ומחיי לכל מאת אני אני הוא המעזר הנקם לצרי וכדו טב לנן ננשם על קשטה ונזע מן גבורתה מאן נמטי אל שביל אצלחותה ולא נבטל מן תשבחתה דמרן בכל זבן ועדן בדיל נרום ונתחיל מכל איקר וניעל לגו מדינה כהלה רחמים ורתו ולגוה ינשמו כל דיאריה אה אלה רחמן ולית עורי לבר מנה אה נביא קשיט מרבי טביה','Those who began to know will now be delivered. Behold, I have taught 
you statutes and precepts (Deut. 4:5), only take heed (Deut. 4: 9). I, I am He (Deut. 
32:39), the Master of בראשיתand Mount Sinai. I, I am He, who was, and there was 
no other beside Me. I, I am He, who was without time or place. I, I am He, to 
whom everlasting life belongs. I, I am He, who raised and spread out by My 
power. I, I am He, who planted the Garden and uprooted Sodom. I, I am He, who 
ﬁlled and withheld. I, I am He, to whom all belongs and to whom it will return. I, 
I am He, who put living beings to death and resuscitates all the dead. I, I am He, 
who wreaks vengeance on My foes. And now, it is good for us to rely on the True 
One and fear His might, perchance we may reach the way of prosperity. Let us 
not cease to praise our Master at all time and period, that we may be exalted and 
strengthened in all glory, and enter into a domain which is full of mercy and 
grace, in which all the inhabitants will rest. Behold, a Merciful God and there is 
no other besides Him. Behold, a true prophet who magniﬁes the good ones.','אֵלֶּה שֶׁהֵחֵלּוּ לָדַעַת יִנָּצְלוּ עַתָּה. הִנֵּה לִמַּדְתִּי אֶתְכֶם חֻקִּים וּמִשְׁפָּטִים (דברים ד,ה), רַק הִשָּׁמֶר לְךָ (דברים ד,ט). אֲנִי אֲנִי הוּא (דברים לב,לט), אֲדוֹן הַבְּרֵאשִׁית וְהַר סִינַי. אֲנִי אֲנִי הוּא, אֲשֶׁר הָיִיתִי וְלֹא הָיָה אַחֵר זוּלָתִי. אֲנִי אֲנִי הוּא, אֲשֶׁר הָיִיתִי בְּלֹא זְמַן וּמָקוֹם. אֲנִי אֲנִי הוּא, אֲשֶׁר לוֹ שַׁיֶּכֶת הַחַיִּים הַנִּצְחִיִּים. אֲנִי אֲנִי הוּא, אֲשֶׁר הֵרִים וּפָרַשׂ בְּכֹחִי. אֲנִי אֲנִי הוּא, אֲשֶׁר נָטַע אֶת הַגָּן וְעָקַר אֶת סְדוֹם. אֲנִי אֲנִי הוּא, אֲשֶׁר מִלֵּא וּמָנַע. אֲנִי אֲנִי הוּא, אֲשֶׁר לוֹ הַכֹּל וְאֵלָיו יָשׁוּב. אֲנִי אֲנִי הוּא, אֲשֶׁר הֵמִית חַיִּים וּמְחַיֶּה אֶת כָּל הַמֵּתִים. אֲנִי אֲנִי הוּא, אֲשֶׁר נוֹקֵם מֵאוֹיְבָי. וְעַתָּה, טוֹב לָנוּ לְהִשָּׁעֵן עַל הָאֱמִתִּי וְלִירֹא אֶת גְּבוּרָתוֹ, אוּלַי נַגִּיעַ אֶל דֶּרֶךְ הַשַּׁגְשׁוּג. אַל נֶחְדַּל מִלְּשַׁבֵּחַ אֶת אֲדוֹנֵנוּ בְּכָל עֵת וְתָקוּפָה, לְמַעַן נִתְעַלֶּה וְנִתְחַזֵּק בְּכָל כָּבוֹד, וְנִכָּנֵס אֶל תְּחוּם הַמָּלֵא חֶסֶד וְחֵן, אֲשֶׁר בּוֹ יָנוּחוּ כָּל יוֹשְׁבָיו. הִנֵּה אֵל רַחוּם וְאֵין אַחֵר זוּלָתוֹ. הִנֵּה נָבִיא אֱמֶת הַמְּגַדֵּל אֶת הַטּוֹבִים.');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (272,'IV','8','מימר על שירתה רבתה',4000081,'צמת בהדה מלתה עובדי טביה דלית דמותון במד בידון עביד נח אתפרד במה עבד כתב אלה עליו נח איש צדיק ותמים אברהם הגדל בזאת המלה כד אתמר לה בשלמו תיעל ולא אתמר לה בתמימו תיעל בדיל מדורה קמאה מקדם זעיקתה יצחק לא אתמרת לה ואתרבה בתלתה ברכהן יקירין עד מותר עקב עובדה רבתה קשטה ואקים לה דכרן לא מתנשי לעלם יעקב אתרבי ממנה בתרין ולא אתיהב לה כהלה על מדי אלא אתמר יעקב איש תם גלת לה מיתובה יתרה משה אמרה בלא י לודיע הן לנח אתמרת בי בפמה דאלה והך דהות הדה שירתה מן פמה דמשה במדעה דקשט וממלל דחכמה אמר תמם ולא אמר תמימה גלה בה תרין עובדין רמים רבין עד ומה אחזת ורבין ממלליה ומה אסחנו ירום נב רבה משה ומה לנן גלה מן ממלל קשט כלה חיים כד הכלל באלין רבוהתה דמן פמה פרדון ומקדמאתה הקימון פתח פמה בברכהן ורבה באודהו ואנהר עלמה וכל קהלה בכן ירום מדעה דמשה במה תמן גלה מן מלי שירתה דכהלה איקר','He joined in this word the deeds of the good ones, to whom none is like 
with respect to what they did. Noah was distinguished by what he did. God 
wrote of him: Noah was a righteous man and perfect (Gen. 6:9). Abraham was 
magniﬁed with this word, when it was said of him: You shall go […] in perfection 
( .)בשלמוBut it was not said of him ,בתמימוbecause of his ﬁrst dwelling, which 
was before the call. It was not said to Isaac either, (though) he was exalted with 
three exceedingly glorious blessings as a result of his deed. The True One estab-
lished for him a memorial which will never be forgotten. Jacob was exalted with 
two (letters) of it; and not all of what it consists was given to him, but it was said: 
Jacob was a perfect man ( – תםGen. 25:27). (The word) revealed his elevated rank. 
Moses said it without yod, to make known that to Noah it was said with yod, from 
the mouth of God. And since this song was said from the mouth of Moses, with a 
true mind and a speech of wisdom, he said ( תמםDeut. 31:30), and did not say 
 .תמימהHe made known two lofy facts: the greatness of עדand what it comprises 
and the greatness of its words, and what they consisted of. Exalted be the great 
prophet Moses and what he has revealed to us from the speech of truth, wholly 
of life. When he was crowned with the great things that he pronounced with his 
mouth, and established them as a preamble, he opened his mouth with bless-
ings and uttered thanks abundantly and enlightened the world and all the con-
gregation by this. Exalted be the mind of Moses for what he revealed there of the 
words of the song, which is wholly glory.','הוא צירף במילה זו את מעשי הטובים, שאין דומה להם ביחס למה שעשו. נח נבדל במעשיו, וכך כתב עליו האלוהים: נֹחַ אִישׁ צַדִּיק תָּמִים (בראשית ו,ט). אברהם הוגדל במילה זו, כשנאמר עליו: לֵךְ [...] בְּשָׁלֵם (בשלמו). אך לא נאמר עליו "בתמימו", בשל מגוריו הראשונים שהיו לפני הקריאה. גם ליצחק לא נאמר כן, אף שנתעלה בשלוש ברכות מפוארות ביותר כתוצאה ממעשיו. האמת כונן לו זיכרון שלא יישכח לעולם. יעקב נתעלה בשתי אותיות ממנה, ולא ניתן לו כל מה שהיא כוללת, אלא נאמר: וְיַעֲקֹב אִישׁ תָּם (תם – בראשית כה,כז). המילה גילתה את מעלתו הרמה. משה אמרה בלא יוד, להודיע שלנח נאמרה ביוד מפי האלוהים. ומאחר שהשירה נאמרה מפי משה, במחשבה נכונה ובדברי חכמה, אמר (תמם – דברים לא,ל) ולא אמר "תמימה". הוא הודיע שני עניינים נשגבים: גדולת "עד" ומה שהיא כוללת, וגדולת דבריה ומה שהם מורכבים ממנו. ברוך הנביא הגדול משה ומה שגילה לנו מדברי האמת, שכולם חיים. כשנעטר בדברים הגדולים שהוציא מפיו ויסד אותם כמבוא, פתח פיו בברכות והרבה להודות, והאיר את העולם ואת כל הקהל בכך. ברוך שכלו של משה על מה שגילה שם מדברי השירה, שהיא כולה תפארת.');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (273,'IV','23','מימר על שירתה רבתה',4000231,'אל אמונה מלת מלכו ממנה לעלם לא מתחלפה ואתמרת עורי עסרה זבנים ולא שרה בון אלא נביה רבה משה בקדמאה זעק לזימון ובעסולה למרבאה אנחמו בזבן מרים עבדה שיאלה וקעמת עמה ואמטתה למד בלש ובהדה זומנותה עבדה שיאלה הודעת רביאן מד תמן אתקומם דו קדם עלמה ועמה ובתרה יכלו ממנה ושלטנו תדירה עזר ואמר מלת אל ועבדה שרוי למחכום דכל מה עתיד אזל אמונה הודע בה דאימונתה שלמה כי קשטה אמר עבדי משה נאמן הוא אימנה על מד לה גלה ועל מה דכסי עוד וכן אמר אלה בכל ביתי נאמן הוא הודע בדילה דאתימן על תרתיה בראשית חכמה ויום נקם חכמה אה אימנו שלמה אה שלטנו תדירה היא מלת אל אמונה # קצירן # אה מקראה כהלה רבו אה חכמה כהלה חיים אה אימנו כהלה שלמו אה שלטנו לא נאדה אה יכלו לא משתאמה אה רבו דלא בטלה אה תדירו לא מתחלפה אל מאבד כל אל אל מרבי כל טביה אל מסחן חיי עולם אל מקמי בראשית אל בתר יום נקם אל כלה מנה ובה אל כלה מכפית לה','A God of faithfulness (Deut. 32:4). The word “Kingship” endures forever, 
it is never altered. It was said ten more times, and none began with it, except the 
great prophet Moses. The ﬁrst (time) he called at the gathering and the last (time) 
to increase relief. At the time of Miriam he made it a request, and it helped him 
and led him to what he requested. And in this gathering he made it a request 
that made known the greatness of what was brought about there. For He was 
before the world and is with it and will be afer it – enduring might, everlasting 
sovereignty. He said again the word אלand made it a beginning of the knowledge 
of all that is about to pass. Faithfulness – he made known that his faithfulness is 
perfect. Indeed, the True One said: My servant Moses […] is entrusted (Num. 12:7) 
– He entrusted him over what he revealed to him and over what is still 
concealed. Thus God said: he is entrusted with all my house (ibid.) – He made 
known that (Moses) was entrusted with both ,בראשיתknow it, and ,יום נקםknow 
it. Behold a perfect faithfulness, behold an everlasting sovereignty, is the word 
 .אמונהBehold a Torah – wholly of greatness, Behold wisdom – wholly of life. 
Behold faith – wholly of perfection. Behold sovereignty – never unstable. Behold 
might – inestimable. Behold majesty – never abolished. Behold steadfastness – 
inalterable. A God who destroys all gods. A God who elevates all good ones. A 
God – possessor of everlasting life. A God who preceded .בראשיתA God who 
endures afer .יום נקםA God – everything is from Him and by Him. A God – 
everything is submitted to Him.','אֵל אֱמוּנָה (דברים לב,ד). המילה "מלכות" קיימת לעולם, לא תשתנה לעולם. נאמרה עשר פעמים נוספות, ולא פתח בה אחד אלא הנביא הגדול משה. בפעם הראשונה קרא בה בקהל ובפעם האחרונה כדי להגדיל את הנחמה. בעת מרים עשה אותה בקשה, והיא עזרה לו והובילה אותו אל מה שביקש. ובקהל זה עשה אותה בקשה שהודיעה את גדולת מה שהתחולל שם. כי הוא היה לפני העולם ועמו ויהיה אחריו – עוז נצחי, מלכות עולמית. אמר שוב את המילה אל ועשאה פתיחה לידיעת כל העתיד לבוא. אמונה – הודיע שאמונתו שלמה. אכן, האמיתי אמר: עבדי משה [...] נאמן הוא (במדבר יב,ז) – האמינו על מה שגילה לו ועל מה שעוד סמוי. כך אמר האל: בְּכָל בֵּיתִי נֶאֱמָן הוּא (שם) – הודיע שהוא נאמן גם על בראשית, דע זאת, וגם על יום נקם, דע זאת. הנה אמונה שלמה, הנה מלכות נצחית, הוא עניינה של המילה אמונה. הנה תורה – כולה גדולה. הנה חכמה – כולה חיים. הנה אמונה – כולה שלמות. הנה מלכות – לעולם לא תתמוטט. הנה עוז – אין לשערו. הנה הוד – לעולם לא יבוטל. הנה יציבות – לא תשתנה. אל המשמיד את כל האלים. אל המרומם את כל הטובים. אל – בעל החיים הנצחיים. אל שקדם לבראשית. אל הקיים אחרי יום נקם. אל – הכל ממנו ועל ידו. אל – הכל כפוף לו.');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (274,'IV','83','מימר על שירתה רבתה',4000831,'ומלתה תניאנתה כי חלק יהוה עמו יעקב מן הימים הראישונים וגלה רבותה אכה ורבה יתה בקדשיה קדש שבתה ואנשמותה דלגוה וקדוש מועדיה ואתרבה עורי בגזיראן ופקודאן וכיר אדה דאלה לא אתשקח באד גוי בר מנך טר מה דחילך בה מרך ולא תסטי מנה ומה דאלפך נביה רבה משה ולא תסור לא ימין ולא שמאל , 84] מלתה תלתיתה דאמר יתה וחבל נחלתו ישר [ שרר קדושון בממלכת כהנ ישמשו למרון חמת בקר יוסף בר פרת דא ] מ [ ר עליו נביה רבה משה בכור שור הדר לו במה יתעבד בחלקה מן תרי גוניה דבח קדש טר ית ירח אביבה דבה שרוי דבחיה עכמה דהוא מטי אל אתר אבהתה ותנכס מן תוריך ומן עאניך לגו אתרה דאתרחי יה אלהך למשרי ית שמה תמן אה אלה רחמן ואין עוד מלבדו טובי לבה דשרא לגוה ארכן טובה > ו < ממלל עם עפר נשיש עד ירבה לה רחמין אה אלה רחמן ולית עורי בר מנה דתרי עלמיה צעידין ביכלתה זעק למשה ו » ש « גר } ה { יתה לבני עבדיו אה אלה רחמן ולית עורי בר מנה דברא עלם יהי ושכלל יתה בלא עזר והשמע קלה למשה ברבו רבה ויהב לה חיים מוחים לישראל','The second statement: For the Lord’s portion is his people Jacob (Deut. 
32:9) since the ﬁrst days. He has revealed His greatness here and exalted him in 
holy things: the holiness of the Sabbath and the rest during it, and the holiness 
of the Festivals. He was also elevated in commandments and precepts, and the 
handwriting of God is found in the possession of no people but you. Keep what 
your Lord has empowered you with and do not deviate from it, and (from) what 
he has taught you through] the great prophet Moses. And do not turn on the right 
or on the lef.','האמירה השנייה: כִּי חֵלֶק יְהוָה עַמּוֹ יַעֲקֹב (דברים לב,ט) מימים ראשונים. הוא גילה כאן את גדולתו והרימו בקדושות: קדושת השבת והמנוחה בה, וקדושת המועדים. כמו כן הוגבה במצוות ובפקודות, וכתב אלוהים אינו מצוי ברשות שום עם זולתכם. שמרו מה שאדוניכם העצים בכם ואל תסורו ממנו, ו(מ)מה שלימד אתכם על ידי הנביא הגדול משה. ולא תפנו ימין ושמאל.');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (275,'IV','31','מימר על שירתה רבתה',4000311,'שחתו אדם וחוה במלתה דנחש דאתא בערימו ומלל גדף ותהונו כמלאכיה היא מלת שחתו הודעת דלית הוה ממלל קשט מכן אמר לא לו בחכמה למוכח רב שחתו קות ממלל נחשה דמלל בערי } ו { מו ובזידנו פלג מדעיון עד אנדה מותה וצערה מה דן תפוכה רבה דהוה לגו עלמה אבדנה במותה לאדם וזרעה וצערה לחוה הך מה דאמר בצער תילדי בנים שחתו בתחמידותו » ן « ומיכלון מן הכלי שחתו הדה היא דאתמרת על עובד אדם דאתעבד שרוי ביש דקדמה לא אתעבד עובד מכעס לקשטה במה אזהר מנה','They have dealt corruptly (SP Deut. 32:5) – (meaning) Adam and Eve 
through the word of the serpent which came with guile and spoke blasphemy: 
and you will be like angels (ST Gen. 3:5). The word שחתוmade known that it was 
not a true speech. Therefore he said ,לא לוthey are not His, (Deut. 32:5) with 
wisdom, as a great reproof. שחתוincludes the speech of the serpent which spoke 
with guile and presumption. He divided their minds till he brought death and 
toil. What is this great overthrow that fell upon the world? Expiration through 
death for Adam and his descendants, pain for Eve, as He said: in pain you shall 
bring forth children (Gen. 3:16). – שחתוin their lust and in their eating from what 
was withheld. – שחתוthis is what was said about the deed of Adam, which 
became the beginning of evil. For before it no deed had been done regarding 
what He had warned against, irritating the True One.','שִׁחֵתוּ (דברים לב,ה בנוסח השומרוני) – כוונתו לאדם וחוה בדבר הנחש שבא בערמה ודיבר גדופים: והייתם כמלאכים (תרגום שומרוני בראשית ג,ה). המילה שחתו הודיעה שלא דבר אמת הוא. לפיכך אמר לא לו (דברים לב,ה) בחכמה, כתוכחה גדולה. שחתו כולל את דבר הנחש שדיבר בערמה ובחוצפה. פילג את דעתם עד שהביא מוות ועמל. מה הוא הכישלון הגדול הזה שנפל על העולם? מיתה לאדם ולצאצאיו, וצער לחוה, כפי שנאמר: בעצב תלדי בנים (בראשית ג,טז). שחתו – בתאוותם ובאכלם ממה שנאסר עליהם. שחתו – זה שנאמר על מעשה אדם, שהיה לראשית הרע. כי לפניו לא נעשה מעשה כנגד מה שהוזהר עליו, המכעיס את האמת.');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (276,'IV','107','מימר על שירתה רבתה',4001071,'ראו עתה ועתה ישראל מן אתילף הדה יתנשם באדה ראו עתה ראו למדתי אני אני הוא השמר לך ושמור נפשך מן יום דינה ואין אלהים עמדי עורי ושמור נפשך מאד טובי לאנשה דיתרחץ על מרה ויתהלך בריחותה ראו עתה ראו ראיתי וארדה להצילו אני אני הוא בשרוה ובעקבה אני דאמרת אברהם אברהם ואמרת משה משה אני אני הוא רביאני לא משתאם','See now (Deut. 32:39), and now, O Israel (Deut. 10:12) he who learned 
this will have rest in this. See now (Deut. 32:39), behold I have taught (Deut. 4:5) I, 
I am He. Only take heed, and keep your soul (Deut. 4:9) from the Day of Judge-
ment. There is no god besides Me (Deut. 32:39). Also: And keep your soul diligently 
(Deut. 4:9) – happy is the man who trusts his Master and walks according to His 
will. See now (Deut. 32:39). I have seen […] and I have come down to deliver them 
(Exod. 3:7–8). I, I am He – the beginning and the end. It was I who said: 
Abraham, Abraham (Gen. 22:11) and said: Moses, Moses (Exod. 3:4). I, I am He, 
My majesty is inestimable.','רְאֵה עַתָּה (דברים לב,לט), וְעַתָּה יִשְׂרָאֵל (דברים י,יב) — מִי שֶׁלָּמַד זֹאת יִמְצָא בָּהּ מְנוּחָה. רְאֵה עַתָּה (דברים לב,לט), הִנֵּה לִמַּדְתִּי (דברים ד,ה) — אֲנִי אֲנִי הוּא. אַךְ רַק הִשָּׁמֶר לְךָ וּשְׁמֹר נַפְשְׁךָ (דברים ד,ט) מִיּוֹם הַדִּין. אֵין אֱלֹהִים עִמָּדִי (דברים לב,לט). וְכֵן: וּשְׁמֹר נַפְשְׁךָ מְאֹד (דברים ד,ט) — אַשְׁרֵי הָאִישׁ הַבּוֹטֵחַ בְּאדוֹנוֹ וְהוֹלֵךְ לְפִי רְצוֹנוֹ. רְאֵה עַתָּה (דברים לב,לט). רָאִיתִי [...] וָאֵרֵד לְהַצִּילוֹ (שמות ג,ז–ח). אֲנִי אֲנִי הוּא — הָרֵאשִׁית וְהָאַחֲרִית. אֲנִי הוּא שֶׁאָמַר: אַבְרָהָם אַבְרָהָם (בראשית כב,יא) וְאָמַר: מֹשֶׁה מֹשֶׁה (שמות ג,ד). אֲנִי אֲנִי הוּא — גְּדֻלָּתִי אֵין לְשַׁעֲרָהּ.');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (277,'IV','48','מימר על שירתה רבתה',4000481,'אלין מליה דמלל משה לבדיל יפקד אברהם ית בריו וית ביתה בתרה וקטעו תריון קיאם על קשטה אל תצור את מואב ואל תתיגר בו ואמר כדו הרוח יהוה לנן אדיק ממעון קדשך מן השמים כל אלין מליה צמתון נביה רבה משה במלה חדה בהדה שירתה יאכל יעקב וישבע מן מלי תשבחתה ישמן כשירה ויבעט בברכהתה טב הוא פמה דמשה משבח מבתר מה דחכם עסרתי נביוהתה פרס כפיו קמי מרה וכרז בקל רם ולבה ונפשה מליאן מן דחלתה אה מן כללני בנהרה ורבה יתי בסימניה ויקרני בכבודה וכסני בכפה ואעלני בגו משכן כסיאתה ואלבשתני שמך דבראת בו העולם וגלית לי שמך רבה וחכמתני רזיך ואימנתני על מד בחרת ומללתני פה אל פה ואקמתני למשמע ואנהרת לבי בחכמתה וארשיך לי מעבד משכן מדור לכבוד מלכותך ומשרוי למלאכיה וטהרתה לשני למקדשהתך ודכית לבי לצלוהתה מלי לי הך מה שריך וחסל הך מה דאמרת עד אטר מצוהתך בחילה ואף בשרוה ואקים תרוהתך ואכשיר מקרתה הך מה דארשיך דאתה אקמתני לכן ובה פקדתני','These are the words which Moses spoke: that Abraham may charge his 
children and his household afer him (SP ibid.). The two of them made a covenant 
of truth: Do not harass Moab, nor contend with them (Deut. 2:19). He said: For 
now the Lord has granted ample space for us (Gen. 26:22), look down from Your 
holy abode, from heaven (Deut. 26:15). All these words, the great prophet Moses 
included in one sentence in this Song: Jacob shall eat and be ﬁlled (Deut. 32:15) – 
with words of praise, Jeshurun grew fat and prospered (ibid.) – through the 
blessings. Good is the mouth of Moses in praise. Afer he had expounded the ten 
prophecies, he spread out his hands before his Master and proclaimed aloud 
with heart and soul full with fear: “O the One who has crowned me with His light 
and exalted me with the wonders and honored me with His glory and covered 
me with His palm and brought me into the Sanctuary of the Concealed; You 
adorned me with Your name, by which You created the world, and revealed to 
me Your great name and taught me your secrets, entrusted me over what You 
have chosen, addressed me mouth to mouth, appointed me to hear, enlightened 
my heart with wisdom, commanded me to make a sanctuary, an abode for the 
glory of Your kingship and a dwelling place of the angels, and puriﬁed my tongue 
for sanctifying You, and cleansed my heart for prayers – entrust me as I was 
when you began, and end as You promised, that I may keep Your command-
ments with power and also with might. And I shall apply Your laws and properly 
carry out the proclamation as You commanded, for You appointed me for this 
and commanded me thus.”','אלה הדברים אשר דיבר משה: שאברהם יצווה את בניו ואת ביתו אחריו (שם). שניהם כרתו ברית אמת: אל תצר את מואב ואל תתגר בם (דברים ב,יט). אמר: כי עתה הרחיב ה'' לנו (בראשית כו,כב), הַשקיפה ממעון קדשך מן השמים (דברים כו,טו). את כל הדברים האלה כלל הנביא הגדול משה במשפט אחד בשירה זו: וַיֹּאכַל יעקב וַיִּשְׂבַּע (דברים לב,טו) – בדברי שבח, וַיִּשְׁמַן יְשֻׁרוּן וַיִּבְעָט (שם) – על ידי הברכות. טוב פיו של משה בשבח. אחרי שפירש את עשר הנבואות, פרש את ידיו לפני אדונו וקרא בקול גדול, בלב ובנפש מלאי יראה: "הוי אתה אשר עטרתני באורך ורוממתני בנפלאות וכבדתני בכבודך וכסיתני בכפך והבאתני אל מקדש הנסתר; קישטתני בשמך אשר בו בראת את העולם, וגילית לי את שמך הגדול ולימדתני את סודותיך, והפקדתני על אשר בחרת בו, ודיברת אתי פה אל פה, ומינתני לשמוע, והארת את לבי בחכמה, וציוויתני לעשות מקדש, משכן לכבוד מלכותך ומדור למלאכים, וטיהרת את לשוני לקדשך, וזיכית את לבי לתפילות – הפקידני כאשר הייתי בתחילה, וסיים כאשר הבטחת, למען אשמור את מצוותיך בכוח ובגבורה. ואקיים את חוקיך ואוציא לפועל כראוי את הקריאה כאשר ציוויתני, כי לזאת מינתני ועל כך ציוויתני."');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (278,'IV','70b','מימר על שירתה רבתה',4000703,'מלתה ] חמ [ ישתה ] יפר [ ש כנפיו ] סבל [ כון על ] כנפ [ י נשריה ] ואנ [ דה יתכון , ליד [ ה ברחמו ] בדיל [ ך אה ישר ] ] אן תח [ כם אהן ] איק [ רה רבה ] ולא תפ [ סל ] גרמך תתנצ [ ל ] מן יד דבב [ ך ] נסבתך ל [ גו ] ענני נגד [ תך ] ובימה אגיז [ תך ] ועל אבר [ תי ] סבלתך וכד את [ א ] עמלק מן רחי [ ק וקטלת יתה וכל עמה קמיך אתא בלעם למשפנך הפכת , בפמה וברכך ולא צבית למ › ש ‹ מע מנה צפי מה עבד עמך מרך ורחם יתה כמה רחמך ולא תמרינה והלך בפניה אולי ישוב עליך ויקבץ נדחך ורחמך כמה דאמר ותרחם ית יה אל בכל לבבך ובכל נפשך טובך הן תהי מלוא בדאה רחמותה','The ﬁfh statement: He spread His wings (Deut. 32:11). He bore you on 
eagles’ wings and brought you to Him with mercy. For your sake, O Israel, that 
you may know this great glory and not discredit yourself, (then) you will be 
rescued. From the hands of your enemy I took you, in my cloud I led you, and in 
the sea I made you to pass, and on my pinions I bore you. When Amaleq came 
from afar, I slew him and his people in front of you. Bileam came to curse you – I 
changed his speech and he blessed you. I did not want to listen to him. See what 
your Master has done with you and love Him as he loves you, and do not disobey 
him walking in apostasy; perchance He will return to you and gather your scat-
tered and love you, as He said: And you shall love the Lord your God with all your 
heart, and with all your soul (Deut. 6:5). Happy are you, if you are worthy of this 
love.','האמירה החמישית: "יִפְרֹשׂ כְּנָפָיו" (דברים לב,יא). נשאך על כנפי נשרים והביאך אליו ברחמים. למענך, ישראל, כדי שתדע את הכבוד הגדול הזה ולא תבזה את עצמך, תינצל. מידי אויבך לקחתיך, בעננִי הדרכתיך, ובים העברתיך, ועל אברותי נשאתיך. כשבא עמלק מרחוק, הכיתי אותו ואת עמו לפניך. בלעם בא לקללך – שיניתי את דבריו וברכך. לא רציתי לשמוע לו. ראה מה עשה אדונך עמך ואהבהו כאשר הוא אוהב אותך, ואל תמרה את פיו בלכתך בדרך מרד; אולי ישוב אליך ויקבץ נפוצותיך ויאהב אותך, כפי שאמר: "וְאָהַבְתָּ אֵת ה'' אֱלֹהֶיךָ בְּכָל לְבָבְךָ וּבְכָל נַפְשְׁךָ" (דברים ו,ה). אשריך, אם תזכה לאהבה הזו.');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (279,'IV','24','מימר על שירתה רבתה',4000241,'אמונה בגדלה תדיר לגרמה אלהותה ונביותה ובריאתה וכהנתה וארהותה ועל ריש אלין אגלת ואין א אלהותה מ נביותה ו בריאתה נ כהנתה ה חמשתי ספריה דביאר נביה רבה משה האנא מוזף חכמה בדיל לא יהי בלבך מן חכמתה גשש א שמה רבה מודע דו אחד כתבה ושמה מדמין דן לדן מ מניאן שניה דהות רחותה לגוה מתחילה בנביות משה כד אזדמנו תריון הגדל עלמה ואתית ו דרבת כלה לאיטבו בפם אלהותה נ מניאן חלקי קדשיה אשר הפרשת לכהנתה ו לית צורך למבקר עליה דכלה בה הכלל ביכלתה דאלה גיבורה ונוראה עבוד פליאתה מרה דכלה דזכי מכל שקר אלה הממן עד לעלם אורכותה לה שליט ברומה ובמכה גדול בנפלאו חייה לה מן ישום מהו רביאנה אי ידע מהו אלא הוא ישתבח בלב אנציר כני ויכבד בנפש דכיה מליה דחלה דו אחד לגרמה','Faithfulness (Deut. 32:4) – in His greatness, He alone is everlasting. The 
Divinity, the prophethood, the Creation, the priesthood, and the Torah. And 
above these ואיןwas revealed. They are: – אthe Divinity; – מthe prophethood; – ו
the Creation; – נthe priesthood; – הthe ﬁve books that the great prophet Moses 
wrote. Behold I add wisdom (for you) so that there will not be dissension with 
the wisdom in your heart. – אthe Great Name – makes known that He is one; the 
Book and the Name resemble to each other (in uniqueness). – מthe number of 
years that the Divine Favor reigned in him from the beginning of the 
prophethood of Moses – when they both were joined the world was elevated. 
Now comes וthat increased everything for better by the mouth of the Divinity. – נ
the number of the sacred parts that have been allocated for the priesthood. – ה
there is no need to inquire about it, for everything is completed in it by the might 
of God, the mighty and awesome, maker of the wonders, the Master of all, who is 
clear of any deceit. The ever enduring God. The everlastingness is His, ruler of 
heaven and earth, great in His wonders. The life is His, who (can) estimate what 
is His majesty, or know what He is? But let Him be praised with a devoted and 
humble heart, and be gloriﬁed with a pure soul, full of fear, for he is One, alone.','אמונה (דברים לב,ד) – בגדולתו, הוא לבדו נצחי. האלהות, הנבואה, הבריאה, הכהונה, והתורה. ומעל אלה נגלתה המילה ואין. הם: א – האלהות; מ – הנבואה; ו – הבריאה; נ – הכהונה; ה – חמשת הספרים שכתב הנביא הגדול משה. הנה אני מוסיף חכמה כדי שלא תהיה מחלוקת עם החכמה שבלבך. א – השם הגדול – מודיע שהוא אחד; הספר והשם דומים זה לזה בייחודם. מ – מספר השנים שהאהבה האלהית מלכה בו מתחילת נבואת משה – כאשר שניהם נחברו יחדיו הועלה העולם. ועכשיו בא ו שהגדיל הכל לטובה מפי האלהות. נ – מספר החלקים הקדושים שהוקצו לכהונה. ה – אין צורך לחקור עליה, כי הכל מושלם בה בגבורת האל, הגבור והנורא, עושה הפלאות, אדון הכל, נקי מכל תרמית. האל הנצחי לעולם. הנצחיות שלו, שולט על שמים וארץ, גדול בנפלאותיו. החיים שלו, מי יוכל לשער את הודו, או לדעת מהו? אך שיהלל בלב נאמן ושפל, וישובח בנשמה טהורה מלאת יראה, כי הוא אחד, לבדו.');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (280,'IV','74','מימר על שירתה רבתה',4000741,'אה ברי דרה אתפוררו לנפשהתכון מן אהן דמכה רבה ועזרו אל קשטה דאתון ברי שלמיה כל טוב אתיהב לוכון בדיל סהביכון אה מן רחמיו כל עת סמיכה אמליתן נרחמך ונטר גזריך ונעבד מה פקדתנן תשתבח בקשט דאתה ברוה דכלה ומשקחה בטובך נאמן בך ובמשה אישך ובכתבך דהורדת על ידו מן מעון קדשך מן השמים כד חסל נביה רבה משה מן דכרן דבשה ומשחה אמר חמת בקר וחלב צאן פתור אברהם דסדרה לגו מישרי ממרא הוה אוצר טמיר לבניו יצחק נדיב בגרמה לדמות כן יעקב יקר יתה עובדה דעבד אבוה והקרב קרבנים לאלהה דאבוה יצחק ובכן פקד לזרעה בהרגריזים תמן תנכס ית פסחה קרבן פרקנה מן עאניך ומן תוריך כמד ברכך יהוה אלהך נדרה ורחבה נשוי כהלן בקשטה הך מה דארשה מרן ונשבח ונשיר ונסיד ונימר לית אלה אלא אחד','O people of this generation, awaken yourselves from this long sleep and 
turn back to the True One, for you are the children of the perfect ones. Every 
good has been given to you because of your ancestors. O the One whose mercies 
are ever a support, empower us to love You and to keep Your commandments, 
and to do what you have commanded us. Praised be You indeed, for You are the 
creator of all and its inventor in Your goodness. We shall believe in You and in 
Moses Your Man and in Your Scripture, which You sent down through him from 
Your holy abode, from heaven (Deut. 26:15). When the great prophet Moses had 
ﬁnished mentioning the honey and the oil, he said: Curds from the herd, and milk 
from the ﬂock (Deut. 32:14). The table which Abraham set out in the plain of 
Mamre was a hidden treasure for his sons. Isaac presented himself for the likes 
of that. Jacob honored the deed that his father did and gave oﬀerings to the God 
of his father Isaac. Therefore, (God) commanded this to (Jacob’s) descendants on 
Mount Gerizim: There you shall oﬀer the Passover sacriﬁce (Deut. 16:2), the oﬀer-
ing for the deliverance, from your ﬂock and your herd (ibid.), as the Lord your God 
blessed you, votive oﬀering and pleasing (gif). Let us all reside in truth as our 
Lord has commanded, and let us give praise and song, and testify and say: 
“There is no god but One.”','הוי עם הדור הזה, התעוררו משינה ארוכה זו ושובו אל האמת, כי אתם בני השלמים. כל טוב נִתַּן לכם בזכות אבותיכם. הוי מי שרחמיו תמיד לסמוכה, חזקנו לאהבך ולשמור את מצוותיך ולעשות כאשר ציוויתנו. ברוך אתה אמנם, כי אתה בורא הכל וממציאו בטובך. נאמין בך ובמשה איש שלך ובכתובך, אשר שלחת בידו מִמְּעוֹן קָדְשְׁךָ מִן הַשָּׁמָיִם (דברים כו,טו). כשסיים הנביא הגדול משה לזכור את הדבש ואת השמן, אמר: חֶמְאַת בָּקָר וַחֲלֵב צֹאן (דברים לב,יד). השולחן שערך אברהם באלוני ממרא היה אוצר נסתר לבניו. יצחק הציג עצמו לדבר כזה. יעקב כיבד את המעשה שעשה אביו והביא קרבנות לאלהי אביו יצחק. לפיכך ציווה זאת לצאצאיהם על הר גריזים: וְזָבַחְתָּ פֶּסַח (דברים טז,ב), קרבן הגאולה, מִן הַצֹּאן וּמִן הַבָּקָר (שם), כַּאֲשֶׁר בֵּרַכְךָ יְהוָה אֱלֹהֶיךָ, נדר ונדבה. נשב כולנו באמת כאשר ציווה אדוננו, ונתן שבח ושיר ונעיד ונאמר: "אין אלהים כי אם אחד."');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (281,'IV','109','מימר על שירתה רבתה',4001091,'חי אנכי לעולם גדלי וכתב אדי אברהם ומשה תרי אקריה מן פנה מן אברהם הוה בר ארדאי ומעזי ומן פנה מן משה הוה כברה דשלומית תריון יתרגמו דאזלו ית אבהתון ולא אכו בתרון וכל דמנון עזר לעקרה נרכן קדמיו ונשתעבד לגדלה דו מרן וקניאן ונהימן בה ובמשה אישה דגלה לן שביל חייה כמה דאמר כי הו חייך וארך ימיך תוב לידה תמלך כל איקר מדלה','I live for ever (Deut. 32:40): My greatness and My Scripture. Abraham 
and Moses are the two fundaments. He who turns away from Abraham is a 
rebellious and capricious son (Deut. 21:18), and he who turns away from Moses is 
like the Son of Shelomith – both will be stoned, for they despised their fathers 
and did not follow them, and everything of theirs returned to its origin. Let us 
bow down before Him and submit to His greatness, for He is our Master and 
Creator. And let us believe in Him and in Moses the Man, who revealed to us the 
path of life, as He said: for that is life to you and length of days (Deut. 30:20). 
Come back to Him (and) you will possess every honor.','חַי אָנֹכִי לְעֹלָם (דברים לב,מ): גְּדֻלָּתִי וּכְתָבִי. אַבְרָהָם וּמֹשֶׁה הֵם שְׁנֵי הַיְסוֹדוֹת. הַפּוֹרֵשׁ מֵאַבְרָהָם הוּא בֵּן סוֹרֵר וּמוֹרֶה (דברים כא,יח), וְהַפּוֹרֵשׁ מִמֹּשֶׁה דּוֹמֶה לִבְנוֹ שֶׁל שְׁלֹמִית — שְׁנֵיהֶם יִסָּקֵלוּ, שֶׁכֵּן בָּזוּ לַאֲבוֹתֵיהֶם וְלֹא הָלְכוּ בְּדַרְכֵיהֶם, וְכָל אֲשֶׁר לָהֶם שָׁב לְמָקוֹר מוֹצָאוֹ. נִכְרְעָה לְפָנָיו וְנִכָּנַע לִגְדֻלָּתוֹ, שֶׁהוּא אֲדוֹנֵנוּ וּבוֹרְאֵנוּ. וְנַאֲמִין בּוֹ וּבְמֹשֶׁה הָאִישׁ, שֶׁגִּלָּה לָנוּ אֶת דֶּרֶךְ הַחַיִּים, כְּמוֹ שֶׁאָמַר: כִּי הוּא חַיֶּיךָ וְאֹרֶךְ יָמֶיךָ (דברים ל,כ). שׁוּבוּ אֵלָיו וְתִזְכּוּ בְּכָל כָּבוֹד.');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (282,'IV','12','מימר על שירתה רבתה',4000121,'ועסרתי » א « ה דבשבתה בכתבה דמשה אצטמתו בריתה וקדשה וברכתה ואנשמותה ואזהרותה ומטרתה וחייה ומותה והנחותה ואשבתותה אקרים טבים מרבים מלוכון בכל דרי עלמה בריתה למחילה וקדשה למרבאה בתריון אוקר אלה לישראל וברכתה לסגין אגר פעל עבד ואנשמותה מוקרה לאנשים נטרו ואזהרותה עבידה לדלא עבדו ומטרתה לאנשים אתיקרו ואנחותה בדיל מילפותה ואשבתותה מכללה למן דמלך לאלין','The ten (fundaments) pertaining to the Sabbath were assembled in the 
Book of Moses: the covenant, the consecration, the blessing, the relief, the 
warning, the observance, the life, the death, the rest, and the cessation (from 
work) – good foundations that elevate their possessor in all the generations of 
the world. The covenant for strengthening, the consecration for elevation – God 
honored Israel with both. The blessing for increasing the reward for the work of 
the worker. The relief for honoring the people who keep (it). The warning is 
intended for those who do not keep it, the observance for people who were 
honored, the rest for learning. The rest crowns the one who possesses (all) these.','עשרת הדברים השייכים לשבת נאספו בספר משה: הברית, הקדושה, הברכה, הנחה, האזהרה, השמירה, החיים, המוות, המנוחה, והשביתה ממלאכה – יסודות טובים המרוממים את בעליהם בכל דורות העולם. הברית לחיזוק, הקדושה להרמה – האלוהים כיבד את ישראל בשניהם. הברכה להגדלת שכר עמלו של העמל. ההנחה לכבד את העם השומר אותה. האזהרה מיועדת לאלה שאינם שומרים אותה, השמירה לבני אדם שנכבדו, והמנוחה ללימוד. המנוחה מעטרת את מי שזכה בכל אלה.');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (283,'IV','60','מימר על שירתה רבתה',4000601,'נרגל בתר נביה רבה משה ולמימרה נשמע דמה נתוחי במד יתן אלף נשמע לה והוא משרי באדה אוכחותה וירא יהוה וינאץ כד עמתון על ימה מרנינים גלגל עמון דאנון הוו בעקה רבה והות צפינה בישה הגלת לגו מדברה קץ שבי מנן נקים ריש ונעזר אל מצרימה וכן רננו באילים וסובר יתון ועבדה לון מנוחה והוה פרדיס ביש אנצבותה תמן מן יאכלנן בשר במיכלנן מזון לסבעה ורננו עורי ברפידים ולא אלעיתון דאנון הוו בציותה ותיגרה בישה התיגרו בה עם נביה רבה משה הב לנן מים העיני האנשים ההם עוד מעט וסקלוני ויפל משה ואהרן מן תגר תמן עזר ותגר אכה ורב מכן אלה אלהיך וקבלה ואכל עמה וסגד וירא יהוה וינאץ עמי ומסובר ובכל עת הוא רתי ומסובר וליתו מסובר אלא אולי יהי שיורה מרבי קשטה במדלה ארשי יהי נהי אנן שיורה דמרה בעי לה ולא נהי שיורה דמרה תעב לה נסתרו בחוריה ומרן אזדכי מנן דאתבחרנן ולא צבינן לית על קשטה רנין','Let us rush afer the great prophet Moses and listen to his speech, per-
chance we may live by what he has taught us. Let us listen to him as he begins 
with this reproof: The Lord saw it, and was vexed (Deut. 32:19). When He saw 
them grumbling at the sea, He had mercy for them, for they were in great dis-
tress. There was bad intent manifested in the desert: Let us alone (Ex. 14:12); let 
us choose a captain and go back to Egypt (Num. 14:4). And also they grumbled in 
Elim, but He was patient with them and made it a resting-place for them. It was a 
bad garden that they planted there. Who will give us meat to eat (Num. 11:13) 
when we ate food to satisfy (Exod. 16:3). And they grumbled again in Rephidim, 
but He did not trouble them, for they were thirsty. With a bad quarrel they 
quarreled with the great prophet Moses: Give us water (Exod. 17:2); will you 
(gouge out) those men’s eyes? (Num. 16:14); before long they will be stoning me 
(Exod. 17:4); then Moses and Aaron fell (on their faces) (Num. 14:5). Those who 
quarreled there quarreled again here. More than that: These are your gods (Exod. 
32:4) – the people received it (the calf), and feasted and worshipped. The Lord 
saw it, and was vexed (Deut. 32:19) – He sees and forgives; at all times He pities 
and forgives. He only forgives, perchance the remnant may exalt the True One 
with regard to what He commanded. It is appropriate that we be the remnant 
which their Lord seeks, and not be the remnant which their Lord abominates. 
The chosen ones are hidden away and our Lord is exempt from us, for we were 
chosen but we were reluctant. Let there be no grumbling against the True One.','נרוץ אחר הנביא הגדול משה ונקשיב לדבריו, אולי נחיה ממה שלימד אותנו. נשמע אליו כשהוא פותח בתוכחה זו: וירא ה'' וינאץ (דברים לב,יט). כאשר ראה אותם מתלוננים על הים, ריחם עליהם, כי היו בצרה גדולה. כוונה רעה נגלתה במדבר: חדלו מאתנו (שמות יד,יב); נתנה ראש ונשובה מצרימה (במדבר יד,ד). וגם התלוננו באילם, אך הוא סבל אותם ועשאהו מקום מנוחה להם. גן רע נטעו שם. מי יתן לנו בשר לאכל (במדבר יא,יג) בשעה שאכלנו לחם לשובע (שמות טז,ג). ושוב התלוננו ברפידים, אך לא הצר להם, כי צמאים היו. בריב רע רבו עם הנביא הגדול משה: תנו לנו מים (שמות יז,ב); את עיני האנשים ההם תנקר (במדבר טז,יד); כמעט וסקלוני (שמות יז,ד); ויפל משה ואהרן על פניהם (במדבר יד,ה). אשר רבו שם שבו ורבו כאן. ויתר על כן: אלה אלהיך (שמות לב,ד) – העם קיבל את העגל, וחגג וישתחוה. וירא ה'' וינאץ (דברים לב,יט) – הוא רואה ומוחל; בכל עת הוא מרחם ומוחל. הוא רק מוחל, שמא יקלס השארית את האמיתי על מה שציווה. ראוי שנהיה אנו השארית שריבונם מבקש, ולא השארית שריבונם מתעב. הנבחרים נסתרים וריבוננו פטור ממנו, כי נבחרנו אך מאסנו. לא תהיה תלונה כנגד האמיתי.');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (284,'IV','87','מימר על שירתה רבתה',4000871,'מלתה תלתיתה איך ירדף אחד אלף הא וילה אנש דיהי מרוד וכשלו איש באחו כמפני חרב אוי למי חובה רדופה ואבדתם בגוים אה חתמה בישה והיית לזוע לכל ממלכת הארץ ואבדתם בגוים לא יזדיאן לך דבב דכי דבבך עובדך וחרבה ממללך וילה אנש עובדה יקטל יתה וממללה הוא חרבה דישנק ית רוחה נפני מדן עובדה ולא נקרבנה כי אלה ואישה מנה אזהרונן ונשבח לשם מרן ולא נחלף מליו אנן קדישים למה נתרחי לנפשהתן הן נהי טמאים באידן מדע יהי כן אנן בחורים ובנן חשק יהוה למה נהי פסולים באידן מדע יהי כן אנן כהנים וסגולה הך נחלל דמעה באידן מדע יהי כן לינן אלין ולא יאי לן כן ברן נחדד תתובה ונבכי בדמעים רבים על כל מה דעבדנן וננחם על מה דעבר ונספד על כל מד קדמנן ונוכח נפשהתן בכל עובדינן מה ביש עובד ינדי מדון מה ביש › עובד ‹ ייתי רגז מה ביש עובד יצדי עבודה','The third statement: How should one chase a thousand (Deut. 32:30). 
Behold, woe to the man who is a rebel – they should stumble over one another as 
before a sword (Lev. 26:37). Woe to the one whom his sin pursues. You shall 
perish among the nations (Lev. 26:38) – behold, a bad end. You shall become a 
horror to all the kingdoms of the earth (Deut. 28:25). You shall perish among the 
nations (Lev. 26:38) – it is not an enemy girt against you; it is your own deed that 
is your enemy, and your word is his sword. Woe to the man whom his deed kills, 
and his speech is the sword that aﬄicts his soul. Let us turn away from such 
deed and not draw near to it, for God and the Man warned us against it. Let us 
praise the name of our Master and not change His words. We are sanctiﬁed; why 
should we desire to be deﬁled? By what reason would that be so? We are chosen, 
and upon us the Lord set his love, why should we be rejected? By what reason 
would that be so? We are priests and choicest, how should we profane the 
oﬀering? By what reason would that be so? We are not (like) these and this is not 
appropriate for us. But (we should) renew repentance and mourn with many 
tears for what we have done, and regret what has passed and lament for what 
preceded us, and reprove ourselves for all our deeds. Is it that an evil deed brings 
punishment? Is it that an evil deed brings anger? Is it that an evil deed ruins its 
doer?','האמירה השלישית: כיצד יִרדֹּף אחד אלף (דברים לב,ל).
הנה, אוי לאיש המורד – יִכָּשְׁלוּ איש באחיו כלפני חרב (ויקרא כו,לז). אוי לזה שחטאו רודף אחריו. ואבדתם בגויים (ויקרא כו,לח) – הנה, סוף רע. והייתָ לזַעֲוָה לכל ממלכות הארץ (דברים כח,כה). ואבדתם בגויים (ויקרא כו,לח) – אין אויב חגור נגדך; מעשֵׂך הוא האויב לך, ודבריך הם חרבו. אוי לאיש שמעשׂהו ממיתו, ודיבורו הוא החרב המייסרת את נפשו. נסור מן המעשֶׂה הזה ולא נִקרב אליו, שהרי האל והאיש הזהירונו מפניו. נהלל את שם אדוננו ולא נשנה את דבריו. קדושים אנו; מדוע נחפוץ להיטמא? מה הסיבה לכך? בחורים אנו, ועלינו שם ה'' את אהבתו; מדוע נידחה? מה הסיבה לכך? כוהנים ומיוחדים אנו; כיצד נחלל את הקרבן? מה הסיבה לכך? לא כאלה אנחנו, ואין זה הולם אותנו. אלא עלינו לחדש את התשובה ולהתאבל בדמעות רבות על מה שעשינו, ולהצטער על העבר ולהתאונן על מה שקדם לנו, ולגעור בעצמנו על כל מעשינו. האמנם המעשֶׂה הרע מביא עונש? האמנם המעשֶׂה הרע מביא זעם? האמנם המעשֶׂה הרע מחריב את עושׂהו?');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (285,'IV','28','מימר על שירתה רבתה',4000281,'כד זעק אלה למשה מהימנה למבאר כתבה קוה במשכן זימונה תלתה כבודה וקשטה ומלאכיה אזדמנו למוקר משה מדו משה קעם וקשטה מתחזי והשבעים דאתנבאו והשנים עשר נשיאים ואהרן ואלעזר ואית ופינחס וכלב ויהושע ועננה ואשתה אזדמנו באיקר גדיל ואתעבדו דמס בהדה מניאנה ק אתקוממת עם אברהם בהולד לה את יצחק דאברהם ארש במה דעבד מנה קעם מעבד מד אלה ארשה לה ועמר פרדיס אתרחי בה אלה וכד אתו מלאכיה למבסרתה עמר מנה פתור ואזדמנו למיכל ומה דעבד הקבע ארש ליתו מטלטל עד לעלם לכן נביה רבה משה קרא ומלל חדד עובד › י ‹ אבהתה במקעמון בקדם מרון ואמר עזר מן תקוף רגזך וחיאצה אף בדכרן טביה דבגו כל ארעה מחדד דכרנון דמרון בון אתרחי ירום נביה רבה משה במה דגלה מן חכמה כהלה אצלחו','When God called Moses the faithful to arrange the Book, he gathered 
three in the Tent of Assembly: The Glory, the True One, and the Angels, assembled 
to honor Moses. As Moses stands, and the True One appears, and the seventy 
who prophesied and the twelve princes and Aaron and Eleazar and Ithamar and 
Phinehas and Caleb and Joshua and the Cloud and the Fire gathered in great 
glory and became a fundament in this number. קwas present with Abraham 
when Isaac was born to him (Gen. 21:5). For Abraham is a foundation due to what 
he has done. By him a deed was set up, which God had commanded him. And he 
planted a garden with which God was pleased. And when the angels came to 
bring him tidings, he set up from it a table (where) they gathered to eat. What he 
did was established as a foundation that is never shaken. Therefore, the great 
prophet Moses called and spoke renewing the deeds of the fathers when they 
stood before their Master, and said: Turn from Your ﬁerce wrath (Exod. 32:12). And 
he strengthened it also with the mention of the good ones (ibid., v. 13), renewing 
their memory in the entire land, for their master was pleased with them. Exalted 
be the great prophet Moses who showed wisdom wholly beneﬁcial.','כאשר קרא אלוהים למשה הנאמן לסדר את הספר, כינס שלושה באוהל מועד: הכבוד, האמת, והמלאכים, שנאספו לכבד את משה. כשמשה עומד והאמת נגלית, נאספו שבעים הנביאים ושנים עשר הנשיאים ואהרן ואלעזר ואיתמר ופינחס וכלב ויהושע והענן והאש בכבוד רב, והיו ליסוד במניין הזה. ק היה נוכח עם אברהם כשנולד לו יצחק (בראשית כא,ה). כי אברהם הוא יסוד בשל מה שעשה. על ידו נכונן מעשה שאלוהים ציווה אותו. והוא נטע גן שאלוהים רצה בו. וכשבאו המלאכים לבשרו, ערך מן הגן שולחן ונאספו לאכול ממנו. מה שעשה נכונן כיסוד שלעולם אינו מתמוטט. לפיכך קרא הנביא הגדול משה ודיבר, מחדש את מעשי האבות כאשר עמדו לפני אדונם, ואמר: שוב מחרון אפך (שמות לב,יב). וחיזק זאת גם בהזכרת הטובים (שם, פסוק יג), מחדש את זכרם בכל הארץ, כי אדונם רצה בהם. יתרומם הנביא הגדול משה שהראה חכמה שכולה מועילה.');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (286,'IV','57','מימר על שירתה רבתה',4000571,'עמו מה } מה { טב אהן אלה רחמנה ורתאה דליתו טרף עובד עבד עמה ארכן קלומה מוכח לישראל עד יתפורר ויילף לקשטה ויהונו אלין מליה פתח עינה } א { יסתמך לבה ותחכם עם לבך הן כמד ירדי גברה ית ברה יהוה אלהך מרדינך דאה אחיוס רב אחס עליך עבודך לאוי עליך תהי אתה רתי לנפשך שנן באלפן קשטה ואטר ית מליו כי מרך יהי מטענ } ע {› לך נטור הך מה דאמר ואטרנך › ב ‹ כל דתיזל אסו לכל י ‹ נך כתבה דמשה מתאסי בסמן מן תעתידה דקשטה פשר מרגל למן עמה נגד מהלך בשביל כהלה אצלחו } אתצלח { פרוק הוא מנשם למן אתלחץ מן רג › י ‹ לותה ליד מרה נגוד טב ליתו טעי בשביל מד נגדותה מרחיה למרה מה רחמן ורתאה אהן מלכה רבה דשגר משה אישה ואוקרה בכן מה רחמן ורתי אהן מלכה רבה דנבא משה ואימנה על כל מאדלה מה רחמן ורתאה אהן מלכה רבה דשכר לנן משה בכל טוב מה רחמן ורתי ] אהן מלכה רבה [ דאשמע יתה קעלה בעסרתי מליה חייה לנן ולדרינן עד לעלם ירום משה אישה דקעם מוכיח ושרי בקדמהיתה ואמר שאל אבוך ויחוי לך מה בדילך עביד כד אמר אלה בני בכורי ישראל חילון בכל טב עמו רבות אהן מלכה רבה דארכן וזעק ישראל בני בכורי ויהב לה כל איקר מה עבדנא אברה } י { ם וקימה אלה ויהב אברהם ית כל דלה ליצחק ברה מן שוי אתרה דאבוה יסב ירתתה וכן עבד לזרעה וזעקון בר בכור אה אלה רחמן ולית עורי לבר מנה ארכן ויהב לישראל כל טוב וחסד','See how good is this merciful and pitying God, who does not reject any 
deed by one who deals with Him. He decided to reprove Israel, that they may 
awake and learn the truth, and these words are eye-opening. Let the heart draw 
near that you may know in your heart that just as a man disciplines his son, the 
Lord your God disciplines you (Deut. 8:5). This is great compassion that your 
Maker shows you. If only you would have mercy on yourself! Learn the teaching 
of the True One and keep its words, for your Master will be your guard, as He 
said: I will protect you wherever you go (Gen. 28:15) – a healing for all your sick-
nesses. The book of Moses heals with a medicine prepared by the True One; a 
quick relief for him who is led along a path wholly of beneﬁt. He redeems (and) 
relieves the one who extricates himself from his own habit (and clings) to his 
Master. A good leader does not stray from the path whose course pleases his 
Master. How merciful and gracious this great King, who sent Moses the Man and 
honored him by this. How merciful and gracious this great King, who granted 
Moses prophethood and appointed him over all His possessions. How merciful 
and gracious this great King, who sent to us Moses with every good. How merci-
ful and gracious this great King, who made His voice heard to him in the Ten 
Words – life to us and to our generations forever. Exalted be Moses the Man who 
stood reproving and began at the beginning and said: Ask your father and he will 
tell you (Deut. 32:7) what has been done for your sake. When God said: Israel is 
My ﬁrstborn son (Exod. 4:22), He strengthened them with every good thing. See 
the greatness of this great King, who decided and called Israel my ﬁrstborn son 
and gave him every glory. What Abraham did, God fulﬁlled. And Abraham gave 
all that was his to Isaac his son (Gen. 25:5). He who is worthy of his father’s place 
will take his inheritance. And thus He acted to his descendants and called them 
ﬁrstborn. Behold, a merciful and gracious God, and there is none except him. He 
decided and gave Israel every good and grace.','רְאוּ כַּמָּה טוֹב הָאֵל הָרַחוּם וְהַחַנּוּן הַזֶּה, שֶׁאֵינוֹ דּוֹחֶה שׁוּם מַעֲשֶׂה שֶׁל מִי שֶׁמִּתְעַסֵּק בּוֹ. גָּמַר לְהוֹכִיחַ אֶת יִשְׂרָאֵל כְּדֵי שֶׁיִּתְעוֹרְרוּ וְיִלְמְדוּ אֶת הָאֱמֶת, וּדְבָרִים אֵלּוּ פּוֹקְחִים אֶת הָעֵינַיִם. יִתְקָרֵב הַלֵּב כְּדֵי שֶׁתֵּדַע בִּלְבָבֶךָ כִּי כַּאֲשֶׁר יְיַסֵּר אִישׁ אֶת בְּנוֹ יְהוָה אֱלֹהֶיךָ מְיַסְּרֶךָּ (דברים ח,ה). זֶה הוּא הַחֶמְלָה הַגְּדוֹלָה שֶׁעוֹשֶׂה עִמְּךָ יוֹצְרֶךָ. לוּ רַק תָּחֹס עַל עַצְמְךָ! לְמַד אֶת תּוֹרַת הָאֱמִתִּי וּשְׁמֹר אֶת דְּבָרֶיהָ, כִּי אֲדוֹנֶיךָ יִהְיֶה שׁוֹמְרֶךָ, כְּמוֹ שֶׁאָמַר: וּשְׁמַרְתִּיךָ בְּכֹל אֲשֶׁר תֵּלֵךְ (בראשית כח,טו) – מַרְפֵּא לְכָל חֳלָיֶיךָ. סֵפֶר מֹשֶׁה מְרַפֵּא בִּרְפוּאָה שֶׁהֵכִין הָאֱמִתִּי; הַצָּלָה מְהִירָה לְמִי שֶׁמּוּנְחֶה בְּדֶרֶךְ שֶׁכֻּלָּהּ תּוֹעֶלֶת. הוּא פּוֹדֶה וּמַצִּיל אֶת מִי שֶׁמּוֹצִיא עַצְמוֹ מֵהֶרְגֵּלוֹ (וְנִדְבָּק) בַּאֲדוֹנָיו. מַנְהִיג טוֹב אֵינוֹ סָר מִן הַדֶּרֶךְ שֶׁהִלּוּכָהּ מְרַצֶּה אֶת אֲדוֹנָיו. כַּמָּה רַחוּם וְחַנּוּן הַמֶּלֶךְ הַגָּדוֹל הַזֶּה, שֶׁשָּׁלַח אֶת מֹשֶׁה הָאִישׁ וְכִבְּדוֹ בְּכָךְ. כַּמָּה רַחוּם וְחַנּוּן הַמֶּלֶךְ הַגָּדוֹל הַזֶּה, שֶׁנָּתַן לְמֹשֶׁה נְבוּאָה וּמִנָּהוּ עַל כָּל קִנְיָנָיו. כַּמָּה רַחוּם וְחַנּוּן הַמֶּלֶךְ הַגָּדוֹל הַזֶּה, שֶׁשָּׁלַח אֵלֵינוּ אֶת מֹשֶׁה עִם כָּל טוֹב. כַּמָּה רַחוּם וְחַנּוּן הַמֶּלֶךְ הַגָּדוֹל הַזֶּה, שֶׁהִשְׁמִיעַ לוֹ אֶת קוֹלוֹ בָּעֲשֶׂרֶת הַדְּבָרִים – חַיִּים לָנוּ וּלְדוֹרוֹתֵינוּ לְעוֹלָם. יִתְרוֹמֵם מֹשֶׁה הָאִישׁ שֶׁעָמַד מוֹכִיחַ וְהִתְחִיל מִן הַהַתְחָלָה וְאָמַר: שְׁאַל אָבִיךָ וְיַגֵּדְךָ (דברים לב,ז) מַה שֶּׁנַּעֲשָׂה לְמַעַנְךָ. כְּשֶׁאָמַר אֱלֹהִים: בְּנִי בְכֹרִי יִשְׂרָאֵל (שמות ד,כב), חִזְּקָם בְּכָל טוֹב. רְאוּ אֶת גְּדֻלָּתוֹ שֶׁל הַמֶּלֶךְ הַגָּדוֹל הַזֶּה, שֶׁגָּמַר וְקָרָא לְיִשְׂרָאֵל בְּנִי בְכֹרִי וְנָתַן לוֹ כָּל כָּבוֹד. מַה שֶּׁעָשָׂה אַבְרָהָם, אֱלֹהִים קִיֵּם. וַיִּתֵּן אַבְרָהָם אֶת כָּל אֲשֶׁר לוֹ לְיִצְחָק בְּנוֹ (בראשית כה,ה). מִי שֶׁרָאוּי לִמְקוֹם אָבִיו יִירַשׁ אֶת נַחֲלָתוֹ. וְכֵן עָשָׂה לְצֶאֱצָאָיו וְקָרָא אוֹתָם בְּכוֹר. הִנֵּה אֵל רַחוּם וְחַנּוּן וְאֵין בִּלְתּוֹ. גָּמַר וְנָתַן לְיִשְׂרָאֵל כָּל טוֹב וָחֶסֶד.');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (287,'IV','51','מימר על שירתה רבתה',4000511,'אלה מרבי ישראל מדו קעניה וישראל מגדל בחכמתה דמרה ואנון ילכו לרגליך דמרך קעניך ויילפון מן מימריך הן שמעת בקלה נסיא את לכל העמים דמרך בחרך רבינך מן ישום דמרך קעניך ותדחל מנך דבביך הן שמעת מן קלה מי כמוך ישראל דמרך קעניך תשכן לבטח הן תטר מצוהתה נקום אהן דאנן ונשמע לקשטה וכי מרן וקענין מתרחם עלינן נקד ארצה בכל עת קדם יהוה אלהנן ונתפלל לידה בדחלה רבה ונשבח יתה בדכיו דמה דנתקבל דו אמר ותגזרו ית ערלת לבוכון נרגל בתר נביה רבה משה דו נגודה טבה דשגרה מרן לידנן האן נביא כות משה דהוה אב טב לכל ישראל מרבי יתון ומעיני לון ומפיס עליון בצומה ואף מוחי יתון בצלותה פרקון מן אדי דבביון ואקימון על אימנו שלמה אסאי טב מחסי ויהב אגר לסהביה אוקר לגבריה שרר לרבקיה אנהר לטפליה רבי לטליה חיל לילידיה חוי כד אתנבה פרקון כד קבל לוחיה פלטון מליו מן מלי מרה אימנו בה תאמנו מכל רגז וביום נקם תנשמו באשתה לא תקומו לית לה עליכון יכלה המהימן בה מהימן במרה אוי לן הן לא ננער לכן ונאמן ביהוה ובמשה עבדה','God exalts Israel, for He is the Owner, and Israel is magniﬁed through 
the knowledge of his Master. They (the nations) will follow your steps, for your 
Master is your owner and they learn from your words. If you listen to His voice, 
you will be a prince over all the nations, for your Master has chosen you. Who 
can estimate your greatness, for your Master is your owner. Your enemies will 
fear you, if you listen to His voice. Who is like you, O Israel, for your Master is 
your owner? You will dwell securely, if you keep His commandments. Let us 
stand where we are and listen to the True One; indeed our Master and Owner will 
have mercy on us. Let us continuously bow to the ground before the Lord our 
God and pray to Him in great awe and praise Him in purity. Perchance we may be 
accepted, for He said: Circumcise the foreskin of your heart (Deut. 10:16). Let us 
rush afer the great prophet Moses, for he is the good leader sent by our Master to 
us. Where is there any prophet like Moses, who was a good father to all Israel, 
bringing them up and protecting them, atoning for them by his fast, and also 
giving them life through his prayer. He delivered them from the hands of their 
enemies and established them in perfect faith – a good physician, healing and 
giving reward. The Elders he honored, the men he strengthened, the young he 
enlightened, the infants he brought up, the youths he made strong, the children 
he kept alive. When he prophesied he delivered them. When he received the 
tablets he saved them. His words were from the words of his Master. Believe in 
him and you will live with no wrath, and in the Day of Vengeance you will ﬁnd 
rest. You will not be in the ﬁre, it will have no power over you. He who believes 
in him believes in his Master. Woe to us if we do not remember that, (and do not) 
believe in the Lord and in Moses His servant.','אלוהים מרומם את ישראל, כי הוא הקונה, וישראל מתגדל בדעת אדונו. הם (האומות) ילכו בעקבותיך, כי אדונך הוא קונך והם לומדים מדבריך. אם תשמע בקולו, תהיה שר על כל האומות, כי אדונך בחר בך. מי יוכל לשער את גדולתך, כי אדונך הוא קונך. אויביך יראו ממך, אם תשמע בקולו. מי כמוך ישראל, כי אדונך הוא קונך? תשב לבטח, אם תשמור מצוותיו. נעמדה במקומנו ונקשיב לאמיתי; אכן אדוננו וקוננו ירחם עלינו. נשתחווה תמיד לפני ה'' אלוהינו ונתפלל אליו ביראה גדולה ונשבחהו בטהרה. אולי נתקבל, כי אמר: ומלתם את ערלת לבבכם (דברים י,טז). נרוץ אחרי הנביא הגדול משה, כי הוא המנהיג הטוב אשר שלח אדוננו אלינו. היש נביא כמשה, שהיה אב טוב לכל ישראל, מגדלם ושומרם, מכפר עליהם בצומו, ומחיֶּה אותם גם בתפילתו. הצילם מיד אויביהם וכוננם באמונה שלמה – רופא טוב, מרפא ומשיב שכר. את הזקנים כיבד, את האנשים חיזק, את הצעירים האיר, את התינוקות גידל, את הנוער אמץ, את הילדים הקים לחיים. כשנבא הצילם. כשקיבל את הלוחות פדאם. דבריו היו מדברי אדונו. האמן בו ותחיה ללא זעם, וביום הנקמה תמצא מנוחה. לא תהיה באש, ולא תהיה לה שליטה עליך. המאמין בו מאמין באדונו. אוי לנו אם לא נזכור את זאת ולא נאמין בה'' ובמשה עבדו.');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (288,'IV','10','מימר על שירתה רבתה',4000101,'מכן צמת במקרתה תלתים חלק חיולים וכד הזדמנו קמיו שרי וקרי חזו הך החל ואמר כי הודע דתלתים הזדמנו לידה בראשית ומה בה הקוה וכלול ארעה ומד אסחנת וחילי כסיהתה ויסדי גליאתה עסרה הועדו וקמיו הגלו רבין יום שבתה ועסרתיתה דלה וצורתה דאדם ועסרתיתה דלה עמי רבין כל אלין ושמע מן מרך וכלל מדעך במלי חכמתה חילי כסיהתה דאזדמנו עסרה כבודה רבה ומלאכיה ואורה וחשכה ורוחה ואשתה ומיה ויסדיה ותרי מאוריה ועוד כוכביה אלין אנון יסדי כסיאתה כבודה מעתד לה וגם כוכביה מרבים לה בדיל יתיעל קלה למשמע קהלה','Therefore, he included in his reading thirty mighty constituents, and, 
when they gathered before him, he begun proclaiming. See how he began and 
said ( כיDeut. 32:3) – he made known that thirty were gathered before him: 
Genesis and what it included, and the whole earth and what it consisted of, and 
the hosts of the Concealed, and the foundations of the Overt. Ten were gathered 
and were revealed before him. The greatness of the Sabbath and the ten belong-
ing to it, and the creation of Adam and the ten that belong to it. See the majesty 
of all these, and listen to your Master, and crown your mind with words of wis-
dom. The hosts of the Concealed that gathered were ten: the Great Glory, the an-
gels, the light, the darkness, the wind, the ﬁre, the water, the foundations, the 
two luminaries, and the stars – these are the fundaments of the Concealed. The 
Glory is ready for him, and the stars also glorify him, so that his voice may be 
strengthened and let the congregation hear.','לפיכך כלל בקריאתו שלושים יסודות אדירים, וכשנקבצו לפניו החל להכריז. ראה כיצד פתח ואמר (כי – דברים לב,ג) – הודיע ששלושים נקבצו לפניו: בראשית ומה שכללה, וכל הארץ ומה שהורכבה ממנו, וצבאות הנסתר ויסודות הגלוי. עשרה נקבצו ונגלו לפניו. גדולת השבת ועשרת הדברים השייכים לה, ובריאת אדם ועשרה הדברים השייכים לה. ראה את הוד כל אלה, והקשב לאדונך, ועטר את שכלך בדברי חכמה. צבאות הנסתר שנקבצו היו עשרה: הכבוד הגדול, המלאכים, האור, החושך, הרוח, האש, המים, היסודות, שני המאורות והכוכבים – אלה הם יסודות הנסתר. הכבוד ערוך לו, והכוכבים אף הם מפארים אותו, כדי שקולו יתחזק והקהל ישמע.');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (289,'IV','52','מימר על שירתה רבתה',4000521,'נסתכל לנביה רבה משה והו אמר הוא עשך ויכוננך קדם ו וי כדו הודע עלמה די מלת אלהו מן אתבונן בה חכם הן כלה בה עביד ובה אתחדד ובה יעזר כלה לאקרה אמר הוא עשך לא אמר אלהים ולא יהוה בכתב אחד אקים שמה מכן אזדעק ביד קשטה נביא נביה רבה משה שבח לאלה באדה מלתה הודע דהוא עבוד כלה עשה משפט עשה פליה עשה פליאתה יהוה אלהינו יהוה אחד וראה כל עמה מה דאנה עבד עמך אותות גדלים כהם לא נבראו כד שמע נביה רבה משה דן ממללה אמר לישראל הוא עשך ויעש האותות לעיני העם מכן אמר הוא עשך וכלל הדה תשבחתה במימרה ויכוננך } עבוד { » עובד « גדיל לית בה חסרן כל אמן בעלמה לגו אמנותה חסרן וכל עובדי מרן תמימים ישתבח עבודה דשכלל בריתה ולית עמה אל עורן','Let us contemplate the great prophet Moses, when he says: It is He who 
made you and established you (Deut. 32:6). He put ﬁrst וand ,יfrom which he has 
made the world know that it is a divine word. He who contemplates it knows that 
all was made by it and renewed by it, and by it all returns to its origin. He said: It 
is He who made you; he did not say אלהיםnor – יהוהin one letter he established 
the name, and so he was called by the True One “prophet”. The great prophet 
Moses praised God. With this word he made known that He is the Maker of all: 
who deals justly (Deut. 10:18), the Doer of wonders (Exod. 15:11), the Doer of 
miracles, the Lord our God is one Lord (Deut. 6:4). And all the people will see […] 
what I will do with you (Exod. 34:10). Great signs like them have never been 
created. When the great prophet Moses heard this statement, he said to Israel: 
He made you (Deut. 32:6) and he did the signs in the sight of the people (Exod. 
4:30). Therefore he said: It is He who made you, and completed this praise by 
saying: and established you (Deut. 32:6) – a great deed, without blemish. Every 
crafsman in the world has a ﬂaw in his craf, but the works of our Master are 
perfect. Praised be the Maker who perfected Creation and had no other god with 
Him.','נתבונן בנביא הגדול משה, כאשר אמר: הוא עשך ויכוננך (דברים לב,ו). הקדים ו'' וי'', שמהם הודיע לעולם כי זהו דבר אלוהי. המתבונן בו יודע שהכל נעשה בו והתחדש בו, ועל ידו שב הכל אל מקורו. אמר: הוא עשך; לא אמר אלהים ולא יהוה – באות אחת כונן את השם, ולכן נקרא על ידי האמיתי "נביא". הנביא הגדול משה שיבח את אלוהים. במילה זו הודיע כי הוא עושה הכל: עושה משפט (דברים י,יח), עושה נפלאות (שמות טו,יא), עושה נסים, ה'' אלוהינו ה'' אחד (דברים ו,ד). וכל העם יראו [...] את אשר אני עושה עמך (שמות לד,י). אותות גדולות כאלה מעולם לא נבראו. כאשר שמע הנביא הגדול משה את הדבר הזה, אמר לישראל: הוא עשך (דברים לב,ו) ועשה את האותות לעיני העם (שמות ד,ל). לפיכך אמר: הוא עשך, והשלים את השבח באמרו: ויכוננך (דברים לב,ו) – מעשה גדול, ללא מום. כל אומן בעולם יש פגם במלאכתו, אך מעשי אדוננו שלמים הם. ברוך הבורא שהשלים את הבריאה ולא היה עמו אל אחר.');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (290,'IV','101','מימר על שירתה רבתה',4001011,'בעין מדעה נטול לגו עלמה ונעמי נביה רבה משה קעום מבסר לישראל כד הודעון רבין יום ] נ [ קם בסרנון ] בפ [ צותון מנה ] ול [ ית פצותה ] ל [ חיביה ] אלא [ לטבים ] דממנין [ על ] מטר קש [ טה ] תאב [ יה ] זכאי [ הן ] אימנו [ על ] קש [ טה ימלכו בסרתה ובאיקרה יתוחון ייתי תהבה דמלך אתרה דבחרה מרה ליתון טביה סהב בית אביה הוה טלי כארז עלוי נהר בה רוח חכמה ולבה מלי דעה ממה דאתלף מן אבוה והוא סעיר במשכנה אתחיל במטר שביל זכותה וכד נפל בלחצה הוה ממן על כן ונסב מלכותה בתר עבדותה ודלחצונה בלשו איקרה לא ישרו אחיו במה דעבדו וישר מדעה במד תמן אמר רוח אלהה בה מלך אתרה מכן אסתבלת גרמיו ביד נביא מהימן ביתה דמרה לית כיוסף מלכה ולא כות משה נביה תריון מלכו תרי דרגין רמין משה מלך נביותה ויוסף מלך טורה טבה לית רב מן אהן ולא מן אהן רבותה לאלהנו הממן לקלומה מלוך עלמיה ולית עמה עורנה','With the eye of the mind let us stride within the world and contemplate 
the great prophet Moses standing and giving tidings to Israel. When he taught 
them (about) the majesty of the Day of Vengeance, he brought them tidings 
about their redemption from it, and (that) the redemption is not for sinners but 
for the good ones who persevere in preserving the truth. The righteous repen-
tants, if they persevere in the truth, will possess these tidings and will live by its 
glory. Let the Taheb come who possesses the place that his Master chose for 
those good ones. The eldest of his father’s house was a youngster, like a cedar 
tree beside the river, in whom was the spirit of wisdom, and his heart was full 
with knowledge of what he learned from his father while he was sitting in the 
tent. He was strengthened by guarding the path of righteousness, and when he 
fell into oppression, he was appointed for this and took the kingdom afer the 
slavery. And those who oppressed him sought to honor him. His brothers were 
not right in what they did. Right it is for the mind to be in what He said there: [in 
whom is the spirit of God (Gen. 41:38). He possessed the place. Therefore his 
bones were borne by a prophet appointed to his Master’s house. There is none 
like Joseph the king and there is none like Moses the prophet. Both of them pos-
sessed two high ranks. Moses possessed prophethood, Joseph possessed the 
Good Mountain. There is none greater than either of them. Greatness to our God, 
who endures by Himself, owner of the worlds. There is no other with Him.','בעין השכל נצעד בתוך העולם ונתבונן בנביא הגדול משה העומד ומבשר לישראל. כשלימד אותם על גדולת יום הנקמה, הביא להם בשורה על גאולתם ממנו, ושהגאולה אינה לחוטאים אלא לטובים המתמידים לשמור את האמת. הצדיקים השבים בתשובה, אם יתמידו באמת, יירשו את הבשורה הזאת ויחיו בתפארתה. יבוא התהב שבידו המקום שאדונו בחר לאותם טובים. בכור בית אביו היה ילד, כארז על יד הנהר, שבו היה רוח חכמה ולבו היה מלא בידיעת מה שלמד מאביו בשבתו באוהל. התחזק בשמירת דרך הצדקה, וכאשר נפל בצרה, הוּעד לכך ולקח את המלוכה אחר העבדות. ואלה שדיכאו אותו ביקשו לכבדו. אחיו לא פעלו נכון במה שעשו. ראוי לשכל לעמוד על מה שנאמר שם: [אשר רוח אלוהים בו (בראשית מא,לח). ירש את המקום. לפיכך עצמותיו נישאו על ידי נביא שנועד לבית אדונו. אין כיוסף המלך ואין כמשה הנביא. שניהם ירשו שני מעמדות רמים. משה ירש את הנבואה, יוסף ירש את ההר הטוב. אין גדול מאחד מהם. גדולה לאלוהינו, המתקיים בפני עצמו, אדון העולמות. אין אחר עמו.');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (291,'IV','110','מימר על שירתה רבתה',4001101,'נקום באתרן ונעמי נביה רבה משה אמר ואין מציל מידי היד יהוה תקצר וגם יד יהוה היתה בם יד העדים תהיה בו בדיל עובד קשטה כי יד יהוה שרת ובראת ובה יעזר כלה לעקרה ומימרו יד העדים הן הוה זכי אוי לסהדה והן הוה שקר שקר יתוקר סהדה ואין מידי מציל אקים הדה מלתה מוקרה לסהדותה דלא תתפרש סהדת שקרה והן אתפרשת אד סהדה וקטל זכי ואין מידי מציל ולא יתפרק מני והן קטל חיב משה קדמיו קטל המצרי וחוי לקהלה ברוך אלהינו לעולם וברוך שמו לעולם','Let us stand in our place and contemplate the great prophet Moses 
saying: none can deliver from My hand (Deut. 32:39); is the Lord’s hand short-
ened? (Num. 11:23) The hand of the Lord struck them (Deut. 2:15); the hand of the 
witnesses shall be (ﬁrst) against him (Deut. 17:7) – about the act of truth. For the 
hand of the Lord began and created and by it everything will return to its source. 
As for His statement the hand of the witnesses – if he was innocent, woe to the 
witness. And if he was a treacherous liar, the witness will be honored? This state-
ment honors the testimony, lest the false testimony spreads out. And if the hand 
of the witness stretched out [and he killed an innocent, none can deliver from My 
hand – he will not be delivered from me. And if he killed a guilty man – Moses, 
before him, killed the Egyptian and gave life to the congregation. Blessed is our 
God forever and blessed is His name forever!]','נַעַמְדָה בִּמְקוֹמֵנוּ וְנִתְבּוֹנֵן בִּדְבַרֵי הַנָּבִיא הַגָּדוֹל מֹשֶׁה: וְאֵין מִיָּדִי מַצִּיל (דברים לב,לט); הֲיִקְצַר יַד ה''? (במדבר יא,כג) יַד ה'' הָיְתָה בָּם (דברים ב,טו); יַד הָעֵדִים תִּהְיֶה (רִאשׁוֹנָה) בּוֹ (דברים יז,ז) — עַל מַעֲשֵׂה הָאֱמֶת. שֶׁכֵּן יַד ה'' הֵחֵלָּה וּבָרְאָה, וּבָהּ יָשׁוּב הַכֹּל לִמְקוֹרוֹ. לְגַבֵּי דִּבְרוֹ יַד הָעֵדִים — אִם הָיָה הַנֶּאֱשָׁם חַף מִפֶּשַׁע, אוֹי לָעֵד. וְאִם הָיָה בּוֹגֵד וְשַׁקְרָן, הֲיֻכַּבַּד הָעֵד? דִּבּוּר זֶה מְכַבֵּד אֶת הָעֵדוּת, כְּדֵי שֶׁלֹּא תִּתְפַּשֵּׁט עֵדוּת הַשֶּׁקֶר. וְאִם יַד הָעֵד נִשְׁתְּלְחָה [וְהָרַג חַף מִפֶּשַׁע — וְאֵין מִיָּדִי מַצִּיל, לֹא יִנָּצֵל מִמֶּנִּי. וְאִם הָרַג אֶת הֶחָיָּב — מֹשֶׁה, לְפָנָיו, הָרַג אֶת הַמִּצְרִי וְנָתַן חַיִּים לָעֵדָה. בָּרוּךְ אֱלֹהֵינוּ לְעוֹלָם וּבָרוּךְ שְׁמוֹ לְעוֹלָם!]');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (292,'IV','16','מימר על שירתה רבתה',4000161,'עזר ואמר מלת הצור בעה מרבהתה מכל צורה מכן אמר צור ילדך שראה בהדה וחסל בהדה מלתה קדמאיתה ביספר דתשבחן דמות פרדיסה דאנצבה אברהם צור ילדך תשא בר ארדאי ומעזי וילה ברה דיהי כן יצחק בקדושה לפרדיסה עמר חדו בה אבהתה וכל חכימי קרתה בר ארדאי ומעזי לפרדיסה חרב אצדו בה אבהתה וכל אנשי קרתה צורתה דאדם תתיקר בכלה דחילה מרה מביני כל צורהתה מן ארבעה עקרים כונן צורתה מכן עבד משה הדה מלתה שרוי עקרה קדמאה רבינה דמיה מה דו ארש וכלה בה מוקם תניאנה אתעבד מן קמצה דעפרה כי הוא מזוג למיה מד אלין אתעבדו ארשי בריתה כן אנון אתעבדו ארשי גויתה ומכן משה אמר אציתו שומיה ותשמק ארעה 17] [ ב עקריה שרה למזעק בון וחילון עורי דאנון אוצרים רוחה נוף טב סבל לעובד איך עבד טב הלך בתשמישה ואשתה מנמיה לכל עבדהתה מד הי בבריתה ארש לכלה כהלון עבידים מן ארבעה עקרים כל אחד לגנוסה מקים מיה מן ארבעה עפרה מן ארבעה רוחה מן ארבעה אשתה מן ארבעה עמי אקרי מיה וקומם מדעך במחכום כתבה אתפלג ארבעה פלגים זכי ענינך ועמי איך ה » נ « ון משתוי מחלי ועוד חלופה ומשתוי מעפץ ועוד חלופה וכן אשתה על אהן דברה ולגו משכנה אתעבד עקריה על מנהרתה אהרן ירבינה וכן על מדבחה הות תדירה ואשתה דעבידה לאועדו דאמיר עליה גומרי אש מלקדם יהוה מכן לא ייעל למשכנה אשתה בראיתה וכד אתנדית עבדת תפוך ובשעה הטפת ועפרה ורוחה אף אנון אתחזו בעבידת משכנה ומתמן אתיתבו','He said further the word the Rock (Deut. 32:4 – ,)הצורseeking to exalt 
him more than any form. Further he said: the Rock that begot you (v. 18) – he 
begun with this ( )הצורand ended with that ( .)צורThe ﬁrst word is a collection of 
praises, like the garden that Abraham planted, while you disdained the Rock that 
begot you – stubborn and rebellious son (Deut. 21:18) – woe to the son who is like 
that. Isaac in his holiness cultivated the garden, the fathers and all the elders of 
the city rejoiced in it. A stubborn and rebellious son ruined the garden, the fa-
thers and all the people of the city were dismayed by it. The image of Adam is 
gloriﬁed over all, for its Master empowered it from amongst all creatures. He 
established its image from four elements, therefore, Moses made this word ( )הצור
the beginning. The ﬁrst element is the glory of the water, because it is a 
fundament, and everything is established by it. The second is a handful of dust. 
Indeed it is mixed with water. As these become the fundaments of the creation, 
so they became the fundaments of the body. Therefore Moses said: Give ear, O 
heavens […], let the earth hear (Deut. 32:1).','עוד אמר את המילה "הצור" (דברים לב,ד), ביקש לרוממו מעל כל צורה. עוד אמר: "צור ילדך" (שם פסוק יח) – פתח ב"הצור" וסיים ב"צור". המילה הראשונה היא קובץ תהילות, כגן שנטע אברהם, ואילו אתם בזיתם "לצור ילדך" – "בן סורר ומורה" (דברים כא,יח) – אוי לבן שכזה. יצחק בקדושתו טיפח את הגן, האבות וכל זקני העיר שמחו בו. בן סורר ומורה חרב את הגן, האבות וכל אנשי העיר נחפזו בגללו. צלם אדם מפואר על כולם, שכן אדונו העצים אותו מבין כל הנבראים. כונן צלמו מארבעה יסודות, לפיכך עשה משה את המילה "הצור" לפתיחה. היסוד הראשון הוא כבוד המים, כי הוא יסוד וכל דבר נכון על ידו. השני הוא קומץ עפר, שאכן מעורב במים. כשם שאלה נעשים יסודות הבריאה, כך נעשים יסודות הגוף. לפיכך אמר משה: "האזינו השמים [...] ותשמע הארץ" (דברים לב,א).');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (293,'IV','36','מימר על שירתה רבתה',4000361,'וינבלו צור ישועתו } טרף הודע דליתו { » הודע דליתו טרף « עובד מן עבד עמה ומגזי כל עבוד לפם עובדה ומגלי קשטה ביתה מקומה עמי הך אמר הצור תמים כד אמרה תמן חדדה אכה וילה אנש דלא מקדם טובוהאן וידמי לטביה במה דעבדו ולא יקים קנומה כדמות קין אבד גרמה ואשתיר כלי וטמי קטל אחוה בקנאה ריקנה מה דאה סכאה בהדה עובדה תפך מדעה ועכר עלמה והוה בצערה ומרה מרגז עליו מכן עוד אלין דאנפלו בתחמדתון ושבקו קשטה ואדמו למרודיה ועבדו עגל מסכה והדבבו לאלה אמסר עליון חוביון אל יום דינה רבה אב בלך לא תדבב למרך תקום במדון לית לך בה יכלו ואין לך מפשר ודיהונו לך חברים יהיו לך דבבים וילה לאנש דיעבד דן עובדה בישה בקנומה בריך הוא מרן ויהי לן נברך יתה ונהימן בה ובמשה נביה דלא קעם ולא יקום לעלם כותה','And scoﬀed at the Rock of his salvation (Deut. 32:15) – He made known 
that He does not reject the action of one who acts with Him, and He recompenses 
every doer according to his deed, and He reveals justice on the spot. See how he 
said: The Rock, perfect (Deut. 32:4) – he said it there, he renewed it here. Woe to 
a man who does not advance good actions, resembling the good ones in what 
they did, (instead) shaping himself afer Cain, who destroyed himself and was 
lef withheld and isolated (ST Gen. 4:12). He killed his brother through 
meaningless jealousy; what did he expect by this act? His mind was turned and 
he disturbed the world, and he was in aﬄiction, his Lord wrathful at him. Like-
wise those who scoﬀed in their desire and forsook the True One and were like the 
rebels, and made a molten calf and became enemies to God, their sins will be 
retained for them for the great Day of Judgement. Pay attention, do not be an 
enemy to your Lord, lest you fall under judgement, over which you have no 
power, and have no deliverer. Those who are your companions will become your 
enemies. Woe to a man who does this evil deed to himself. Blessed is our Lord. It 
is appropriate that we bless Him and believe in Him and in Moses His prophet, 
like whom none has arisen and will never arise.','וַיִּנְבֵּל צוּר יְשֻׁעָתוֹ (דברים לב,טו) – הודיע שאינו דוחה את מעשהו של מי שפועל עמו, ושהוא גומל לכל עושה לפי מעשהו ומגלה משפט במקום. ראה כיצד אמר: הַצּוּר תָּמִים (דברים לב,ד) – אמרה שם, חידשה כאן. אוי לאדם שאינו מקדים מעשים טובים, דומה לטובים במה שעשו, אלא מעצב עצמו על פי קין שאיבד את עצמו ונשאר מרוחק ובודד (תרגום שומרוני בראשית ד,יב). הרג את אחיו מתוך קנאה חסרת טעם; מה ציפה להשיג בכך? דעתו נהפכה והוא הטריד את העולם, ונשאר בייסורים, ואדונו כועס עליו. כך גם מי שנבלו ביצרם ועזבו את האמת והיו כמורדים, ועשו עגל מסכה ונעשו אויבים לאל – חטאיהם יישמרו להם ליום הדין הגדול. שים לב, אל תהיה אויב לאדונך, פן תיפול תחת משפט שאין בידך לעמוד בפניו ואין לך מושיע. אלה שהם חבריך יהיו לאויביך. אוי לאדם העושה לעצמו את המעשה הרע הזה. ברוך אדוננו. ראוי שנברכהו ונאמין בו ובמשה נביאו, שכמוהו לא קם ולא יקום לעולם.');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (294,'IV','3','מימר על שירתה רבתה',4000031,'כד הדה מלת ] ה [ ביד קשטה מתמרה אמיר לאיקר שמה לאמר והן אתמרת עורי בפמה דנביותה לית יתמר מלת לאמר מכן אמר נביה וידבר משה ולא יכל אמר במקרתה לאמר כד קרא קשטה עסרתי מליה אמר לאמר חיל למקרתה וידבר אלהים ואכה אמר וידבר משה וידבר אלהים חיצה במלת לאמר ואכהן אמר וידבר משה ולא חיצה במלת לאמר אוקרה לקדמאיתה אלפה משה וחילה תמן כי עבידה רז אקבע בנביותה אקר אדם הגלית ואקר בריתה הקבעת דמס גדיל כהלה אצלחו אה רז לא בטל אה דמס גדיל מלת וידבר דשררה משה','When this word ( )וידברis said by the True One, לאמרis said (in addition) 
for the glory of His name. But if ( )וידברis also said by the mouth of the prophet-
hood, לאמרwill not be said. Therefore, the prophet said: And Moses spoke (Deut. 
31:30), without being enabled to say in his reading .לאמרWhen the True One pro-
claimed the Ten Words, He said .לאמרHe emphasized His proclamation: And God 
spoke (Exod. 20:1). But here he said: And Moses spoke (Deut. 31:30). And God 
spoke – He strengthened it with the word .לאמרAnd Moses spoke – He did not 
strengthen it with the word .לאמרGlory to the former (sequence). Moses taught it 
and emphasized it there. Indeed, it was a mystery set up in his prophecy. It was 
revealed in connection with Adam. In connection with Creation it was estab-
lished as a great foundation, wholly prosperity (Gen. 1:22). Behold a secret that 
will never be abolished, behold a great foundation: the word וידברthat Moses 
emphasized.','כאשר מילה זו, וידבר, נאמרת על ידי האמת, נאמר לאמר לכבוד שמו. אך אם וידבר נאמר גם מפי הנבואה, לא ייאמר לאמר. לפיכך אמר הנביא: וידבר משה (דברים לא,ל), מבלי שניתן לו לומר בקריאתו לאמר. כאשר הכריז האמת את עשרת הדברים, אמר לאמר. הוא הדגיש את הכרזתו: וידבר אלוהים (שמות כ,א). אבל כאן נאמר: וידבר משה (דברים לא,ל). וידבר אלוהים – חיזק אותו במילה לאמר. וידבר משה – לא חיזק אותו במילה לאמר. תהילה לסדר הראשון. משה לימד זאת והדגיש אותה שם. אכן, היה זה סוד שנקבע בנבואתו. הוא נגלה בקשר לאדם. בקשר לבריאה הוא נקבע כיסוד גדול, כולו שגשוג (בראשית א,כב). הנה סוד שלא יבוטל לעולם, הנה יסוד גדול: המילה וידבר שמשה הדגיש.');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (295,'IV','96','מימר על שירתה רבתה',4000961,'וטביה זהין וחדין ברצון מרון תכסיהתון לא בלת › אלא ‹ בדיל דאנון רחמו גיורה ותנו לה לחם ותכסיתה ואפיון מופעים דלא פנו אפיון מן דרוש וכפיון מלים אור כיון לא כפצוה מן צדקתה וית לבביון שמחין כי לא דברה בני בלעיל ונפשהתון זכיהן דאנון רחמו לאלה בלבביהון ובנפשותיון ובכל שרוון כמה דאמר ותרחם ית יה אלהך בכל לבבך ובכל נפשך ובכל מאדך ורגליהון לא בזקת כיון הלכו בתר יהוה כמה דאמר אחרי יהוה אלהי תל ] כו [ ן כל הדה ביום דינה יתגלי','And the good ones will be joyful and cheerful because of the favor of 
their Master. Their clothes will not wear out, only because they loved the so-
journer and gave him bread and clothing. Their faces will shine, because they 
did not turn their faces away from a seeker (of charity). Their palms will be full 
of light, because they did not shut them out from (giving) charity. Those hearts 
of theirs will be joyful, for the Sons of Belial did not lead them on. Their souls 
will be pure, for they loved God with their hearts and souls and all their might, 
as He said: You shall love the Lord your God with all your heart, and with all your 
soul, and with all your might (Deut. 6:5). Their foot will not swell, for they walked 
afer the Lord, as He said: You shall walk afer the Lord your God (Deut. 13:5). All 
this will be revealed on the Day of Judgement.','והטובים ישמחו ויעלזו בחסד אדוניהם. בגדיהם לא יבלו, רק מפני שאהבו את הגר ונתנו לו לחם ולבוש. פניהם יזרחו, מפני שלא הסבו פניהם מן המבקש. כפות ידיהם יהיו מלאות אור, מפני שלא קפצו אותן מנתינת צדקה. לבבותיהם ישמחו, שכן בני בליעל לא הדיחו אותם. נפשותיהם יהיו טהורות, מפני שאהבו את האלוהים בלבבם ובנפשם ובכל מאודם, כפי שאמר: "וְאָהַבְתָּ אֵת ה'' אֱלֹהֶיךָ בְּכָל לְבָבְךָ וּבְכָל נַפְשְׁךָ וּבְכָל מְאֹדֶךָ" (דברים ו,ה). רגלם לא תצבה, מפני שהלכו אחר ה'', כפי שאמר: "אַחֲרֵי ה'' אֱלֹהֵיכֶם תֵּלֵכוּ" (דברים יג,ה). כל זה ייגלה ביום הדין.');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (296,'IV','90','מימר על שירתה רבתה',4000901,'מלתה רביעיתה אם לא צורם מכרם ויהוה אסגרם בדיל בישיה דאמרו דן אלהך כד עמו יתה מתוקד טחון מדרי על אפי מיה מה דאמרו עמו מדעה דנביה רבה משה במימרה אם לא צורם מכרם ויהוה אסגירם מה אנון טעו ואמרו אלין אלהך כעטף עינה אתוקד עגלה כד עמו יתה סגודי ] ה ד [ ו מתוקד באשתה ומטחן ומדרי ולית לה יכלה למפשר קנומה אסגיר יהוה חזון ונפלו כהלון בחרבה וכתב לון חוב לא ימחק עד יום נקם ירום שבט לוי מכל שבטיה דקם דיאן ואדין בקהלה בקשטה נביה רבה משה מנה אהרן כהנה מנה ומרים נביתה מנה האן הך משה ומן מדמי למשה נביא לא קם כותה ולא יקום עד לעלם','The fourth statement: Unless their Rock had sold them and the Lord had 
given them up (Deut. 32:30) – about the evil ones who said: This is your god 
(Exod. 32:8). When they saw it burnt, ground, scattered on the face of the water, 
what did they say? See the mind of the great prophet Moses saying: Unless their 
Rock had sold them and the Lord had given them up. As soon as they strayed and 
said: This is your god, in a wink of the eye the calf was burnt. When the 
worshippers saw that it was being burnt in ﬁre, and ground and scattered, and it 
had no power to rescue itself, the Lord blocked their vision, and they all fell by 
the sword. And He recorded for them a sin that will not be blotted out until the 
Day of Vengeance. Exalted be the tribe of Levi above all the tribes, for he stood as 
a judge and judged the congregation in truth. The great prophet Moses (stems) 
from it and Aaron the priest (stems) from it and Miriam the prophetess (stems) 
from it. Where is anyone like Moses and who resembles Moses, a prophet like 
whom none has arisen and never will arise.','האמירה הרביעית: כי לא כצורם מכרם וה'' הסגירם (דברים לב,ל) – על הרשעים שאמרו: אֵלֶּה אלוהיך (שמות לב,ח). כאשר ראו אותו נשרף, נטחן ומפוזר על פני המים, מה אמרו? ראה את דעת משה הנביא הגדול האומרת: כי לא כצורם מכרם וה'' הסגירם. מיד שתעו ואמרו: אֵלֶּה אלוהיך, כהרף עין נשרף העֵגֶל. כאשר ראו העובדים שהוא נשרף באש, ונטחן ומפוזר, ולא היה בידו כוח להציל את עצמו, חסם ה'' את ראייתם, וכולם נפלו בחרב. ורשם להם חטא שלא יימָחה עד יום הנקמה. תרוֹמַם שבט לוי על כל השבטים, שעמד כשופט ודן את הקהל באמת. משה הנביא הגדול ממנו, ואהרן הכוהן ממנו, ומרים הנביאה ממנו. מי כמשה ומי דומה למשה, נביא שלא קם כמותו ולא יקום לעולם.');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (297,'IV','54','מימר על שירתה רבתה',4000541,'נעמי נביה רבה משה קדם לקדם קהלה אמור ראו עתה כי אני אני הוא וילון סגודי אלהי נכר דאקימו לון צלמין וסגדו לון וילה אלהי נכר כד יתגלי קשטה לא יהי לון תקומה רבה היא אדה תשבחתה דאמרה וכלה רתת ודחל ואין אלהים עמדי ירכנו בוראיה וידעו אנון אזלים האן אנון תפכיה דכפרו ואמרו הן אלה לבר מנה דמי לה תמן יקומו באשדה חיולה שומיה אמרין בידן גזוי הדה אלהי נכר לא קבלנן ולא סעדנן יתה כוכביה אמרין ככן על אלהי נכר לא אנירנן ולה לא רבינן שמשה וזהרה אף אנון אמרים ככן אלהי נכר לא שמענן לה ארעה ומה אסחנת אף אנון אמרים אנן לא קבלנן אלהי נכר } ולאלה { » ולא לה « עלינן דבח באידן גזוי אתגזינן על כן אתא האגבו לכל בפמה דקשטה מן שרואה הכון עקבאה יתרבי נביה רבה משה מהימאנה דחכם כל אדה וגלאה לגו שירתה וילון דסגדו לאלהי נכר ועבדוה רחצונון ובלשו מנה פרקן מנון נערק ובון לא נתקרב דמה דנמלט ביום נקם','Let us contemplate the great prophet Moses approaching the congrega-
tion, saying: See now that I, I am He (Deut. 32:39). Woe to those who worship 
alien gods, who have set up for themselves images and worshipped them. Woe to 
the alien gods; when the True One reveals Himself they will have no survival. 
Great is the praise which (Moses) uttered, while all were trembling and fearful: 
And there is no god beside Me (ibid.). Let people submit and know that they are 
going (to a place) where those apostates are, who denied and said that there 
exists another god apart from Him, resembling Him. There, they will be in severe 
aﬄiction. The heavens say: “With us is requital for this. Alien gods we have not 
accepted nor assisted.” The stars say likewise: “We have not shone on alien gods 
and have not elevated them.” The sun and moon also say likewise: “We have not 
obeyed alien gods.” Earth and what it contains also say: “We have not accepted 
alien gods, and sacriﬁce to them is not on us.” “With what repayment should we 
be repaid for this?” An answer comes to everyone from the mouth of the True 
One: “From the beginning the end has been prepared.” Elevated be the great 
prophet Moses, the faithful one who knew all this and revealed it in the Song. 
Woe to those who worshiped alien gods and made them their trust and sought 
deliverance from them. Let us ﬂee from them and not approach them, perchance 
we may be saved in the Day of Vengeance.','נָתְבּוֹנֵן בְּנָבִיא הַגָּדוֹל מֹשֶׁה כְּשֶׁהִתְקָרֵב אֶל הַקָּהָל וְאָמַר: רְאוּ עַתָּה כִּי אֲנִי אֲנִי הוּא (דברים לב,לט). אוֹי לְאוֹתָם הָעוֹבְדִים אֵלֹהִים זָרִים, שֶׁהֵקִימוּ לָהֶם צְלָמִים וְעָבְדוּם. אוֹי לָאֱלֹהִים הַזָּרִים; כְּשֶׁיִּגָּלֶה הָאֱמִתִּי לֹא תִּהְיֶה לָהֶם תְּקוּמָה. גָּדוֹל הַשֶּׁבַח שֶׁאָמַר (משה), בְּעוֹד כֻּלָּם רוֹעֲדִים וּפוֹחֲדִים: וְאֵין אֱלֹהִים עִמָּדִי (שם). יִכָּנְעוּ הָאֲנָשִׁים וְיֵדְעוּ שֶׁהֵם הוֹלְכִים אֶל הַמָּקוֹם שֶׁבּוֹ נְמָצָאִים אוֹתָם הַמּוּמָרִים, שֶׁכָּפְרוּ וְאָמְרוּ שֶׁיֵּשׁ אֱלֹהִים אַחֵר מִלְּבַדּוֹ, הַדּוֹמֶה לוֹ. שָׁם יִהְיוּ בְּיִסּוּרִים קָשִׁים. הַשָּׁמַיִם אוֹמְרִים: "אֶצְלֵנוּ הַגְּמוּל עַל כָּךְ. אֱלֹהִים זָרִים לֹא קִבַּלְנוּ וְלֹא סִיַּעְנוּ לָהֶם." הַכּוֹכָבִים אוֹמְרִים כָּכָה: "לֹא הֵאַרְנוּ לָאֱלֹהִים הַזָּרִים וְלֹא רוֹמַמְנוּם." הַשֶּׁמֶשׁ וְהַיָּרֵחַ אוֹמְרִים אַף הֵם כָּכָה: "לֹא שָׁמַעְנוּ לָאֱלֹהִים הַזָּרִים." הָאָרֶץ וּמַה שֶּׁבְּתוֹכָהּ אוֹמְרִים אַף הֵם: "לֹא קִבַּלְנוּ אֱלֹהִים זָרִים, וְקָרְבָּן לָהֶם אֵינוֹ עָלֵינוּ." "בְּאֵיזֶה שָׂכָר נִשָּׂכַר עַל כָּךְ?" תְּשׁוּבָה בָּאָה לַכֹּל מִפִּי הָאֱמִתִּי: "מִן הַהַתְחָלָה הוּכַן הַסּוֹף." יִתְרוֹמֵם הַנָּבִיא הַגָּדוֹל מֹשֶׁה, הַנֶּאֱמָן שֶׁיָּדַע כָּל זֹאת וְגִלָּהוּ בַּשִּׁירָה. אוֹי לְאוֹתָם שֶׁעָבְדוּ אֱלֹהִים זָרִים וְשָׂמוּם לְמִבְטָחָם וּבִקְּשׁוּ מֵהֶם יְשׁוּעָה. נִבְרַח מֵהֶם וְלֹא נִתְקָרֵב אֲלֵיהֶם, שֶׁמָּא נִנָּצֵל בְּיוֹם הַנָּקָם.');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (298,'IV','81','מימר על שירתה רבתה',4000811,'ותלתה מלים אזדוגו ברבו ותהבה אף עמון הרנינו גוים עמו אנון עמי ונחלתי לכל עלמה ימלכו מודאה לאלה רחמנה דרחמיו ממנים עם כל דר ודר והו חי לעולם בעודנו לא יתר ולא פעת מן ידע הך הו אי ישום מה הו אי יחכם האן הו אי מטי בה הו אלה אלהיה מורכה ממנה לית לה שותף רב כל רברביה נצוחי קרביה לית עמה אל אחר ברא ושכלל לא על דמו נברכנה באימנו ונשתעבד לה בזכו ונסיד ונימר בקשט לית אלה אלא אחד','Three words are joined together in greatness, the Taheb is with them: 
Acclaim His people, O you nations (Deut. 32:43) – they are my people, and my 
heritage shall possess the whole world. Thanks be to the Merciful God whose 
mercies endure with every generation and who lives forever in His own state, no 
more and no less. Who knows how He exists or estimates what He is, or knows 
where He is, or can reach Him? He is the God of gods (Deut. 10:17), enduring, 
everlasting. He has no associate; greatest of all great ones who are victorious in 
battles (Exod. 15:3), there is no other god with Him. He created and perfected; He 
shaped without design. Let us bless Him in faith and submit to Him in purity, 
testifying and saying with truth: “There is no god but One.”','שלושה דברים קשורים יחדיו בגדולה, והתאיב עמהם: הַרְנִינוּ גוֹיִם עַמּוֹ (דברים לב,מג) – הם עמי, ונחלתי תירש את כל העולם. תודה לאל הרחמן אשר רחמיו מתקיימים בכל דור ודור והוא חי לעולם במצבו שלו, לא יותר ולא פחות. מי יודע כיצד הוא קיים, או מעריך מהו, או יודע היכן הוא, או יכול להגיע אליו? הוּא אֱלֹהֵי הָאֱלֹהִים (דברים י,יז), קיים ונצחי. אין לו שותף; גדול מכל הגדולים הגוברים במלחמות (שמות טו,ג), אין אלוהים אחר עמו. הוא ברא והשלים; הוא יצר ללא תכנית. נברכהו באמונה ונכנע לו בטהרה, נעיד ונאמר באמת: "אין אלוהים כי אם אחד."');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (299,'IV','97','מימר על שירתה רבתה',4000971,'ובישיה במגוי רב וחיול ית תכסיהתון מקדדין בדיל חבלו רקיע ארמלתה ואפיון קבלין כיון פנונון מכל עני ואביון ודל וכפיון קציצין בדיל דכפצוה מן צדקתה ולבביהון מקניאן חליפת דלא עבדו ית יהו בשמחה ובטוב לבב ומשל עליה בני בלעיל נפשהתון גליטה כי לא מלאו אחרי יהוה כמ ] ד [ פקד ולבביון עכירין הלא זנו בתחמדהן בישהן וכחון נשיש כיון לא הדבקו במצות יהוה ומעואן מן כף רגלה ועד קדקדה כיון הלכו רכילי ] ן [ ולא דחלו ולא שבו מ ] ן [ אלין עובדי ] ה [ בישה דא ] וכחו [ אלה ו ] נביה [ מן עוב ] דה הא [ יום דינ ] ה [ עת ] יד לדע [ בד ] ו כל בי [ שה ] דאה [ דעבדו יתה דבבי אלה דעליהון אמר ולא תעבד כעובדיון מן עבד כדן ולא יתוב יום דינה קדמה לא ישקח תמן פשר וילה חיבה דעבד גרמה אסכי לכל ] מ [ כה ביום נקם ] טובי [ טביה דמלכו זכותה לגו עדן מנשמין ומקרין כתי ענני רחמיה הא חלק גדיל חלקה דזכותה מן עלל לגוה יהי באיקר רב בעלמה ובאחראה יתרבי נביה רבה משה דקדם יתה מרה ויתבה על דרג לא אמטה לידה אנש מכל בניו דאדם לא קדמה ולא בתרה','The evil ones will be in great and mighty punishment. Their garment 
torn, because they took the garment of widows in pledge. Their faces darkened, 
because they turned them away from everyone poor and needy and a pauper. 
Their palms cut oﬀ, for they shut them from (giving) charity. Their hearts in 
bitterness, since they did not worship the Lord with joy and gladness of heart, 
and Sons of Belial govern them. Their souls in abhorrence, for they did not 
follow the Lord, as He commanded. Their minds disturbed, for they played har-
lotry with bad desires. Their strength weak, for they did not cling to the Lord’s 
commandments, and plagues (befall them) from the sole of the foot to the crown 
of the head, for they walked in slander, and did not fear nor withdraw from these 
evil deeds, which God and his prophet admonished them from doing. Behold, 
the Day of Judgement is prepared for these who committed all this evil, which 
the enemies of God did, about whom He said: You shall not do according to their 
deeds (Exod. 23:24). He who did such deeds and does not repent, the Day of 
Judgement will encounter him, and he will ﬁnd no rescue there. Woe to the 
sinner for he made himself a good ﬁt for every plague on the Day of Vengeance. 
Happy the righteous who possess righteousness, they will be tranquil in Eden 
and will rest under the clouds of mercy. Behold, a great share is the share of the 
righteousness. He who enters into it will be in great honor in this world and in 
the world to come. Exalted be the great prophet Moses, whom his Master ad-
vanced and placed in a status which no man of all the descendants of Adam 
reached, neither before him nor afer him.','הרשעים יהיו בעונש גדול ואדיר. בגדם קרוע, כי לקחו בגד אלמנות בעבוט. פניהם מושחרות, כי הסבו אותן מכל עני ואביון ודל. כפותיהם כרותות, כי סגרו אותן מלתת צדקה. לבותיהם במרירות, שכן לא עבדו את ה'' בשמחה ובטוב לבב, ובני בליעל שולטים בהם. נפשותיהם בתועבה, כי לא הלכו אחר ה'' כאשר ציווה. מחשבותיהם מבולבלות, כי זנו אחרי תאוות רעות. כוחם חלש, כי לא דבקו במצוות ה'', ומכות פוקדות אותם מכף הרגל ועד קדקוד הראש, כי הלכו בדרך לשון הרע ולא יראו ולא נסוגו מן המעשים הרעים הללו, שאלוהים ונביאו הזהירו אותם מלעשות. הנה, יום הדין מוכן לאלה שעשו את כל הרע הזה, שעשו אויבי ה'', שעליהם אמר: לא תעשה כמעשיהם (שמות כג,כד). מי שעשה מעשים כאלה ואינו חוזר בתשובה, יום הדין יפגוש אותו ולא ימצא שם מפלט. אוי לחוטא, כי הכשיר את עצמו לכל מכה ביום הנקמה. אשרי הצדיקים אשר בידם הצדקה, ינוחו בשלווה בעדן וינוחו בצל ענני הרחמים. הנה, חלק גדול הוא חלק הצדיקים. הנכנס אליו יהיה בכבוד גדול בעולם הזה ובעולם הבא. יתרומם הנביא הגדול משה, שאדונו העלה אותו ושם אותו במעמד שלא הגיע אליו שום אדם מכל צאצאי אדם, לא לפניו ולא אחריו.');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (300,'IV','2','מימר על שירתה רבתה',4000021,'דאקימת לך סהדים מרבים למדעך והאנה מוזף לך נער דחכמה בדיל תחכם סוד וידבר וידבר לנביותה צומה ונביותה עד אמטה לדרג לא אמטתה אנש מאתים ושנים ועשרים אתמנו ביד קשטה למרבאה אימנו תרים ועסרים לקבל תרים ועסרים דכתב אלהים עליון אתבנה ואנון בשרוי הדה מלתה ו י ד ב ור היא חתמה צומה ונביותה והוו כסין עד אתא משה והגלו על אדה כי כל מצוה בה אשתררת וכל ברכה בה אתחילת אלולי משה לא אתחכם כל אהן ולא הגלה כלום ממה דאתירד ובריתה עורי בה הוקמת וכל מה אתעבד במניאנה הוא ו מניאנה אשתתי יומיה דהוו אוצר לכל מה נברא י רבינה רב לית צורכה למחדדה אכה ] ד בה המלאת שומיה [ ב בה הגדל כל איקר בעלמה מפתוח ומצנוק ורבין דברה מצנוקה למה דאזל ומפתוחה למה דאתי והיא כהלה רבו בבראשית אתת צנקת ופתחת צנקת למה דעבר ופתחת לדאתי ובה אתיחתו עסרתי מליה לגו תרי לוחים מדילה דאלה למפתח ולמצנוק למפתח אוצר קשטה ולמרבאה איקרה ומצנוק תרח בישתה ולמכלה ] סנ [ ותה','Behold, I have set up for you witnesses that increase your knowledge, 
and lo, I add to you the insight of wisdom, that you may know the mystery of 
 וידבר .וידברrefers to the prophethood – his (Moses’) fast and his prophethood (by 
which) he reached a rank that nobody else attained. Two hundred and twenty 
two were counted by the True One in order to increase faith. Twenty two corre-
sponds to the twenty two upon which God’s Book was built, they are at the be-
ginning of this word: .וידבAnd רis the end – his fast and his prophethood. They 
were concealed until Moses came, and they were revealed by him. For every 
commandment is reinforced by them and every blessing is strengthened by 
them. If not by Moses, all this would not have been known and nothing would 
have been revealed of that which was brought down. And the Creation too was 
performed by it ( ,)וידברand all that was done (is represented) by its number. וre-
presents the six days, which were a treasury for everything that was created. The 
majesty of יis great, there is no need to repeat it here. [ ,דby it the heavens were 
completed.] By בevery glory increased in the world, the opening and the closure 
and the majesty of its movement; the closure of what had passed and the open-
ing of what is to come, which is entirely greatness. In )ב( בראשיתcame, closing 
and opening; closing what had passed and opening what was yet to come. By it, 
the Ten Words have been brought down on two tablets from God, to open and to 
close; to open the treasury of truth and to increase its glory, and to close the gate 
of evil and to make an end to hatred.','הנה הקמתי לכם עדים המרבים את דעתכם, והנה אני מוסיף לכם את תבונת החכמה, למען תדעו את סוד וידבר. וידבר מכוון לנבואה – לצומו של משה ולנבואתו, שבאמצעותם השיג מדרגה שאיש אחר לא השיג. מאתיים ועשרים ושתיים נמנו על ידי האמת כדי להגדיל את האמונה. עשרים ושתיים כנגד עשרים ושתיים שעליהן נבנה ספר האלוהים, והן בראשית המילה: וידב. ור היא הסוף – צומו ונבואתו. הן היו גנוזות עד שבא משה, וגלה אותן. שכל מצווה מתחזקת בהן וכל ברכה נאמצת בהן. אלמלא משה, לא היה כל זה נודע ולא היה נגלה דבר ממה שהורד. אף הבריאה נעשתה בו, בוידבר, וכל מה שנברא כלול במספרו. ו מייצגת את ששת הימים, שהיו אוצר לכל הנברא. גדולת י רבה, ואין צורך לחזור עליה כאן. [ד – בה הושלמו השמיים.] בב גדלה כל תפארת בעולם, הפתיחה והסגירה וגדולת תנועתה; סגירת מה שעבר ופתיחת מה שעתיד לבוא, שכולו גדולה. בב בא בראשית, סוגר ופותח; סוגר את מה שעבר ופותח את מה שעתיד לבוא. בו הורדו עשרת הדברים על שני לוחות מאת האלוהים, לפתוח ולסגור; לפתוח את אוצר האמת ולהגדיל את תפארתו, ולסגור את שער הרע ולהשמיד את השנאה.');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (301,'V','20','מימר על וימת שם משה',5000201,'ונביה קעום בין קהלה תלי קלה ואמר הוו בשלם הוו בשלם אה קהל ישראל ליתי בתר אהן יומה נסב ויהב עמוכון עד לעלם אמר לה כל קהלה כתר עמן שעה ומרן כרז לה בכסי אה משה מהר אמר לה כל קהלה בחייך אה נביה כתר עמן שעה עורנה ואלה אמר בכסי לית בה רוח אריכה אמר לה כל קהלה בחייך אה נביה כתר עמן שעה עורנה ומלאכי רומה כרזין לה אה משה זרז תמן אמר לה כל קהלה אזל שלם אה נביה אזל שלם אה אורה אזל שלם אה מאורה אזל שלם אה מהימנה שלם לך מדרס לגו אשתה שלם לך גבאה דעלל לכסיהתה שלם לך אה לביבה דאלהותה שלם לך אה מאורה דנביותה כי בהדה שעתה אתה אזל ובתר כן לינן עמין לך לעלם וילה קהלה מבתרך אה אישה קדישה דלא קם כותה ולא יקום לעלם','The prophet stood among the congregation lifing up his voice and said: 
“Be in peace, be in peace, O congregation of Israel. Afer this day, I will not deal 
with you ever again.” All the congregation said to him: “Stay with us a moment.” 
But our Master called him stealthily: “O Moses, hurry.” All the congregation said 
to him: “By your life, O prophet, stay with us another moment.” But God said to 
him in secret: “I have no patience.” All the congregation said to him: “By your 
life, O prophet, stay with us another moment.” But the angels of the heights 
called him: “O Moses, hurry.” Then all the congregation said to him: “Go in 
peace, O prophet. Go in peace, O light. Go in peace, O luminary. Go in peace, O 
faithful. Peace to you, the one who treads on ﬁre. Peace on you, the inner, who 
entered into the Concealed. Peace to you, the beloved of Divinity, Peace to you, O 
luminary of the prophethood. Indeed, at this moment you are going, and afer-
wards we will not see you ever again. Woe to the congregation afer you, O holy 
man, like whom none has arisen and will never arise.”','עָמַד הַנָּבִיא בְּתוֹךְ הַקָּהָל וַיִּשָּׂא אֶת קוֹלוֹ וַיֹּאמַר: "לְכוּ לְשָׁלוֹם, לְכוּ לְשָׁלוֹם, קְהַל יִשְׂרָאֵל. אַחֲרֵי הַיּוֹם הַזֶּה לֹא אֶהְיֶה עִמָּכֶם עוֹד לְעוֹלָם." כָּל הַקָּהָל אָמַר לוֹ: "שְׁהֵה עִמָּנוּ עוֹד רֶגַע." אַךְ אֲדוֹנֵנוּ קָרָא לוֹ בַּחֲשַׁאי: "הוֹי מֹשֶׁה, מַהֵר." כָּל הַקָּהָל אָמַר לוֹ: "חֵי נַפְשְׁךָ, הוֹי נָבִיא, שְׁהֵה עִמָּנוּ עוֹד רֶגַע." אַךְ הָאֱלֹהִים אָמַר לוֹ בַּסֵּתֶר: "אֵין לִי עוֹד סַבְלָנוּת." כָּל הַקָּהָל אָמַר לוֹ: "חֵי נַפְשְׁךָ, הוֹי נָבִיא, שְׁהֵה עִמָּנוּ עוֹד רֶגַע." אַךְ מַלְאֲכֵי הַמְּרוֹמִים קָרְאוּ לוֹ: "הוֹי מֹשֶׁה, מַהֵר." אָז אָמַר לוֹ כָּל הַקָּהָל: "לֵךְ לְשָׁלוֹם, הוֹי נָבִיא. לֵךְ לְשָׁלוֹם, הוֹי אוֹר. לֵךְ לְשָׁלוֹם, הוֹי מָאוֹר. לֵךְ לְשָׁלוֹם, הוֹי נֶאֱמָן. שָׁלוֹם לְךָ, הַדּוֹרֵךְ עַל הָאֵשׁ. שָׁלוֹם לְךָ, הַפְּנִימִי, שֶׁנִּכְנַס אֶל הַנִּסְתָּר. שָׁלוֹם לְךָ, יְדִיד הָאֱלֹהוּת. שָׁלוֹם לְךָ, הוֹי מְאוֹר הַנְּבוּאָה. הֵן בָּרֶגַע הַזֶּה אַתָּה הוֹלֵךְ, וְאַחֲרֵי כֵן לֹא נִרְאֶה אֹתְךָ עוֹד לְעוֹלָם. אוֹי לַקָּהָל אַחֲרֶיךָ, הוֹי אִישׁ קָדוֹשׁ, שֶׁכָּמוֹהוּ לֹא קָם וְלֹא יָקוּם."');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (302,'V','35','מימר על וימת שם משה',5000351,NULL,'Moses was a hundred and twenty years old when he died (Deut. 34:7): 
twenty (years) in Egypt and sixty in Midian and forty in the desert, with mighty 
exaltation in priesthood and prophethood, with prayer and fasting, his eyes were 
undimmed and his vigor unabated (ibid.). We learned from the words his eyes 
were undimmed that it was like the eyes of all the righteous; his eyes were 
undimmed for he had to write the Law and see the four ends of the world. And 
his vigor was unabated – we learned and know that he wore the ray of light, 
which illuminated his face till the day of his death. And his tongue was not 
confused, for he detailed the words of the Torah, as he taught the reading to six 
hundred thousand. The people of Israel wept for Moses […] thirty days (Deut. 
34:8) and mourning for him will never cease.','וּמֹשֶׁה בֶּן מֵאָה וְעֶשְׂרִים שָׁנָה בְּמֹתוֹ (דברים לד,ז): עשרים שנה במצרים ושישים במדיין וארבעים במדבר, בגדולת רוממות בכהונה ובנבואה, בתפילה ובצום, לֹא כָהֲתָה עֵינוֹ וְלֹא נָס לֵחֹה (שם). למדנו מן הדברים לֹא כָהֲתָה עֵינוֹ שהיה כעיני כל הצדיקים; לא כהתה עינו כי היה עליו לכתוב את התורה ולראות את ארבע כנפות העולם. וְלֹא נָס לֵחֹה – למדנו ויודעים אנו שלבש את קרן האור, אשר האירה את פניו עד יום מותו. ולשונו לא נבלבלה, כי פירט את דברי התורה, כשלימד את הקריאה לשש מאות אלף. וַיִּבְכּוּ בְנֵי יִשְׂרָאֵל אֶת מֹשֶׁה [...] שְׁלֹשִׁים יוֹם (דברים לד,ח), והאבל עליו לא יפסק לעולם.');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (303,'V','13','מימר על וימת שם משה',5000131,'אי יעקב אי משה תרין ספרין אחד מוכח בזכו ואחד ברך בנביו יעקב צוה וברך תרין עסר שבט ומשה צוה וברך שת מון דאלף יעקב ברך בניו איש כברכתו ומשה ברך קהלה כל שבט כברכתו יעקב ברך בניו וברכתה סקפנה ומשה ברך קהלה וברכתה רבין וזאת הברכה אשר ברך משה איש האלהים רבה בה תולדת שבטי יעקב וזאת הברכה אשר ברך משה איש האלה גלג קמאי וחיל עקבאי איש האלהים את בני ישר לפני מותו נביותה משררה אקרי זכותה ויאמר יהוה מסיני בא זכר יומה רבה דקרא בה אנכי יהוה אלהיך ושב ודכר שעיר ופראן בדיל מן דהוה שקחי לגון מן זרעה דאברהם ועגלו מקום הר סיני אקים עליון סהד בכן כיון לא אתו לאימנות קשטה','O Jacob, O Moses, two teachers! One exhorts in righteousness (Gen. 49), 
and one blesses in prophethood (Deut. 33). Jacob bequeathed and blessed twelve 
tribes, Moses bequeathed and blessed six hundred thousand. Jacob blessed his 
sons each one with the blessing suitable to him (SP Gen. 49:28) and Moses blessed 
the congregation, each tribe with the blessing suitable to him. Jacob blessed his 
sons, and his blessing is eminence, and Moses blessed the congregation, and his 
blessing is majesty. This is the blessing with which Moses the man of God blessed 
(Deut. 33:1) – he exalted with it the descendants of the tribes of Jacob. This is the 
blessing with which Moses the man of God blessed – he praised the ancients and 
strengthened those present. With which Moses the man of God blessed the 
children of Israel before his death (ibid.) – the prophethood invigorates the fun-
daments of righteousness. He said: The Lord came from Sinai (Deut. 33:2) – he 
mentioned the great day when He proclaimed: I am the Lord your God (Exod. 
20:2). He mentioned further Seʿir and Paran, because in them some of the seed 
of Abraham were found. They saw the place of Mount Sinai where He set a testi-
mony about this, although they did not come to the true faith.','הו יעקב, הו משה, שני מורים! האחד מזהיר בצדק (בראשית מט), והשני מברך בנבואה (דברים לג). יעקב הוריש וברך שנים עשר שבטים, משה הוריש וברך שש מאות אלף. יעקב ברך את בניו, כל אחד בברכה הראויה לו (שומרוני בראשית מט,כח), ומשה ברך את העדה, כל שבט בברכה הראויה לו. יעקב ברך את בניו, וברכתו היא נשגבות, ומשה ברך את העדה, וברכתו היא הוד. זאת הברכה אשר ברך משה איש האלהים (דברים לג,א) – הוא הרים בה את צאצאי שבטי יעקב. זאת הברכה אשר ברך משה איש האלהים – הוא שיבח את הקדמונים וחיזק את ההווים. אשר ברך משה איש האלהים את בני ישראל לפני מותו (שם) – הנבואה מחיה את יסודות הצדק. הוא אמר: ה'' מסיני בא (דברים לג,ב) – הוא הזכיר את היום הגדול שבו קרא: אנכי ה'' אלהיך (שמות כ,ב). הוא הזכיר עוד את שעיר ופארן, לפי שבהם נמצאו מקצת מזרע אברהם. הם ראו את מקום הר סיני שבו נתן עליהם עדות, אף על פי שלא באו לאמונה האמיתית.');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (304,'V','30b','מימר על וימת שם משה',5000303,'רב הוא משה ברה דעמרם דיתר על אבהתה במה הזדמן בה מן גוני תמחיה הכללת גויתה בעשרה סימנים רמין לא התשקחת באנש מבני אדם הראש ברגליו דהלך בון על האש והות כתיה כות טלה ולא הכהתה השני בגויתה הוה כהן תמים המשח בזית קדש במשכן כסיהתה וקעם ביני מלאכיה ארבעים יום וארבעים לילה תרין זבנין לא אכל ולא שתה ולא התנשש לכן השלישי בתרי ידיו דסבל בון תרי לוחי בריתה ונחת מטור סיני בכיר אדה דאלה הרביעי ברישה דבה קרב לערפלה כמה דאמר ומשה נגש אל הערפל אשר שם האלהים החמישי בלשנה ענינה אלה בקלה עד שמעו ממללה שת מון דאלף כמה דאמר משה ידבר והאלהים יעננו בקול הששי בעיניו צפה בון משכן כסיהתה ועבד דמותה בגלי כמה דאמר וראה ועשה בתבניתם אשר אתה מראה בהר ומטור נבא חזה ית כל ארעה מנהר מצרים עד הנהר הגד נהר פרת ועד הים האחרון השביעי בצלמה דבלד כל עמיו ולא יכלו למקעם קמיו כמה דאמר וייראו מגשת אליו השמיני הות כות ימה אתנבוא ממו שבעים נביא והוא בעודנו בנביותו לא יתר ולא פעת התשיעי בלבו דנטר כל ממללי יהוה וביר יתון ארוה מירתה לקהל יעקב לעולם העשירי קביר ביד אלה ואתכסית קבורתו לא תתודע עד יום נקם כמה דאמר ולא ידע איש את קברתו עד היום הזה יתרבי דן נביה קדישה דסלק מן דרג דאנשין אל דרג דאלהו ומן דאלין עקובאת נביותה ודן רבינה רבינה מנו דיהי כותה בעלמה והך יכל מותה יקרב לה אלאן דינה דמותה פשרון קשט פשר בה אלה על כל בני אדם ולא יפלט מנה אנש בעלמה ולא נביא ולא זכאה ולא כהן ולא שופט ולא שליט יכל יפלט מנה','Great is Moses, the son of Amram, who surpassed the ancestors in 
terms of what occurred to him in the various wonders. His body was perfected by 
ten high wonders, never found in any man among the sons of Adam. (1) The ﬁrst 
in his feet, with which he walked on the ﬁre, and it was under him like dew, and 
did not harm him. (2) The second in his body. He was a perfect priest, anointed 
with holy oil in the abode of the Concealed and stood among the angels forty 
days and forty nights, twice; he neither ate nor drank and was not weakened. 
(3) The third in both his hands, with which he carried the two tablets of the cove-
nant and went down from Mount Sinai with God’s handwriting. (4) The fourth in 
his head with which he approached the thick cloud, as He said: Moses ap-
proached the thick cloud where God was (Exod. 20:21). (5) The ﬁfh in his tongue. 
God answered him with His voice so that six hundred thousand heard the 
speech, as He said: Moses spoke, God answered him aloud (Exod. 19:19). (6) The 
sixth in his eyes. He saw with them the abode of the Concealed and made its like-
ness in the Overt, as He said: See and make them afer their pattern, which is 
being shown you on the mountain (Exod. 25:40), and from Mount Nebo he saw the 
whole land, from the river of Egypt till the great river, river Euphrates and till the 
last sea (Deut. 34:1). (7) The seventh in his face which frightened all those who 
saw him, and they were unable to stand before him, as He said: And they were 
afraid to come near him (Exod. 34:30). (8) The eighth: he was like the sea – 
seventy prophets prophesied from him, and he (remained) in his stature regard-
ing his prophethood, neither more nor less. (9) The ninth in his heart, for he kept 
all the words of the Lord and wrote them down, a law […] as the heritage of the 
congregation of Jacob forever (Deut. 33:4). (10) The tenth, he was buried by God 
and his tomb was concealed. It will not be known until the Day of Vengeance, as 
He said: No one knows his burial place to this day (Deut. 34:6). Exalted be this 
holy prophet who ascended from the rank of men to the rank of divinity. From 
these (wonders) are his prophetic glories, and this majesty is his. Who will be 
like him in the world? How can death approach him? Unless death sentence is a 
just judgement, which God ruled for all humanity, and nobody can escape it in 
the world. Neither prophet nor righteous, or priest or judge or ruler can escape it.','גדול משה בן עמרם, שעלה על האבות בכל אשר אירע לו במופתים השונים. גופו נשתלם בעשרה מופתים עליונים, שלא נמצאו באיש מבני האדם. (1) הראשון ברגליו, אשר בהן הלך על האש, והיתה תחתיו כטל ולא הזיקה לו. (2) השני בגופו. היה כוהן שלם, משוח בשמן הקודש במעון הנסתר, ועמד בין המלאכים ארבעים יום וארבעים לילה, פעמיים; לא אכל ולא שתה ולא נחלש. (3) השלישי בשתי ידיו, אשר בהן נשא את שני לוחות הברית וירד מהר סיני עם כתב ידו של אלוהים. (4) הרביעי בראשו, אשר בו נגש אל הערפל, כפי שנאמר: ונגש משה אל הערפל אשר שם האלוהים (שמות כ,כא). (5) החמישי בלשונו. אלוהים ענה אותו בקולו, כך ששש מאות אלף שמעו את הדיבור, כפי שנאמר: משה ידבר והאלוהים יעננו בקול (שמות יט,יט). (6) השישי בעיניו. ראה בהן את מעון הנסתר ועשה את דמותו בנגלה, כפי שנאמר: וראה ועשה בתבניתם אשר אתה מראה בהר (שמות כה,מ), ומהר נבו ראה את כל הארץ, מנהר מצרים עד הנהר הגדול נהר פרת ועד הים האחרון (דברים לד,א). (7) השביעי בפניו, אשר הפחידו את כל רואיו ולא יכלו לעמוד לפניו, כפי שנאמר: ויראו מגשת אליו (שמות לד,ל). (8) השמיני: היה כים – שבעים נביאים נבאו ממנו, והוא עמד בקומתו בנבואתו, לא פחות ולא יותר. (9) התשיעי בלבו, שבו שמר את כל דברי ה'' וכתבם, תורה [...] מורשה קהילת יעקב לעולם (דברים לג,ד). (10) העשירי, נקבר על ידי אלוהים וקברו נסתר. לא יוודע עד יום הנקמה, כפי שנאמר: ולא ידע איש את קבורתו עד היום הזה (דברים לד,ו). מרומם יהיה נביא קדוש זה, שעלה ממדרגת אנשים למדרגת האלוהות. מאלה הן תפארות נבואתו, וזה הדרו. מי יהיה כמוהו בעולם? כיצד יוכל המוות לגשת אליו? אלא שגזר המוות הוא דין צודק, אשר אלוהים גזרו על כל האנושות, ואיש אינו יכול להימלט ממנו בעולם. לא נביא ולא צדיק, לא כוהן ולא שופט ולא שליט יוכל להימלט ממנו.');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (305,'V','6','מימר על וימת שם משה',5000061,NULL,'Afer this the great prophet Moses entreated at the gate of the tent, and 
when he ﬁnished his entreaty, he called Joshua bin Nun and informed him about 
all this, and said to him: “O Joshua, go quickly to the gate of the holy Sanctuary 
and inform all the house of priesthood. Tell Eleazar, Ithamar, and Phinehas to 
come at once, that we may enjoy their presence and send them in peace.” All this 
speech to Joshua from the great prophet Moses (took place) at the gate of the tent 
which Moses pitched far from the camp and called it Tent of Gathering (Exod. 
33:7). From that place Joshua went out, the servant of Moses the Man, and came 
in a hurry to the holy Sanctuary. He stood there in front of the gate and raised his 
voice in lament. When the keepers of the watch heard Joshua’s voice raised in 
great lament, they passed by the Sanctuary and told the high priests. They went 
out shining like luminaries, Eleazar, Ithamar, and Phinehas, and looked at 
Joshua, as he was weeping, and his tears like a liquid heap. They told him: “O 
Joshua, why are you weeping?” He answered them: “My Master Moses is about to 
go up and die.” When they heard this speech, the three priests were in distress 
because of it, and went quickly, and all the tribe of Levi with them, and they 
came to Moses.','לאחר כל זאת התחנן הנביא הגדול משה בפתח האוהל, וכשסיים את תחינתו קרא ליהושע בן נון והודיעו את כל זאת, ואמר לו: "יהושע, לך מהרה אל פתח המקדש הקדוש והודע לכל בית הכהונה. אמור לאלעזר, לאיתמר ולפינחס שיבואו מיד, למען נהנה מנוכחותם ונשלחם בשלום." כל הדיבור הזה אל יהושע מפי הנביא הגדול משה היה בפתח האוהל שנטה משה מחוץ למחנה וקרא לו אוהל מועד (שמות לג,ז). משם יצא יהושע, משרת משה האיש, ובא בחפזה אל המקדש הקדוש. עמד שם בפני השער ונשא קולו בקינה. כאשר שמעו שומרי המשמר את קול יהושע הנישא בקינה גדולה, עברו ליד המקדש והודיעו לכוהנים הגדולים. יצאו מאירים כמאורות, אלעזר, איתמר ופינחס, והביטו ביהושע, כשהוא בוכה ודמעותיו כגל נוזל. אמרו לו: "יהושע, מדוע אתה בוכה?" ענה אותם: "אדוני משה עומד לעלות ולמות." כששמעו את הדיבור הזה, שלושת הכוהנים נצטערו על כך, והלכו בחפזה, וכל שבט לוי עמהם, ובאו אל משה.');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (306,'V','8','מימר על וימת שם משה',5000081,'מה מריר שעתה דבה אמטה דברה ואמיר הן נביה רבה משה אזל ימות אתעכר כל קהלה מן אהן מגדה וזרזו שבט בתר שבט עד אתו ליד אגן נב ; רבה משה ראשי שבטיה וכל דיאניה והשבעים הזקנים וקעמו קדמיו עפל יחכמון מה דארשה אלה ואסתדרו קדמיו כמה דעבדו בזבן דקרא שירתה עבד לה דרג וסלק עליה עד עמהתון כהלון מסתדרין קדמיו וכהלון הוו עמין יתה וליתון סבעין מן מצפיתה קעם על תרי רגליו ועמה כל קהלה מסתדר בכה בדמעים כות מטרה ופתח פמה ואלפון דברי אימנותה ומקרת ארהותה והזהרון מן חלופה ומקדם קרא גלה אנקילה מן על אפיו עד יעמון כל עמה מליה הך הי נפקה מן פמה וכהניה רברביה ויהושע בן נון וסהביה ודיאניה וכל ראשי שבטיה וכל נשיה וכל טפליה וכל עמה מיסטר מציתין ושמעין ית ממללי נביה רבה משה ומוכחיה','How bitter the hour when the speech arrived, and it was announced that 
the great prophet Moses was about to die. All the congregation was distraught by 
this statement and they rushed headlong, tribe afer tribe, until they came to the 
tent of the great prophet Moses: the chiefs of the tribes and all the judges and the 
seventy elders. They stood before him and he begun to tell them what God 
commanded. They assembled before him just as they did when he read the Song. 
He made a platform and climbed it until he saw them, all of them arrayed before 
him, and all of them could see him. Looking at him did not satisfy them, as he 
stood on his two feet, seeing the entire congregation arrayed, weeping with tears 
like rain. He opened his mouth and taught them matters of faith and the reading 
of the Law and he warned them against changing them. Before reading (Moses) 
removed the veil from his face, so that all the people might see how the words go 
out from his mouth. And the high priests and Joshua bin Nun and the elders and 
the judges and all the chiefs of the tribes and all the women and all the children 
and all the people to the last man (Gen. 19:4), listen and hear the speech of the 
great prophet Moses and his reproofs.','מה מרה הייתה השעה שבה הגיעה הבשורה, ונודע שמשה הנביא הגדול עומד למות. כל העדה נסערה מהדבר הזה ונהרה במרוצה, שבט אחר שבט, עד שבאו אל אוהל משה הנביא הגדול: ראשי השבטים וכל השופטים ושבעים הזקנים. עמדו לפניו והוא החל לספר להם את אשר ציווה האל. נקהלו לפניו כשם שנקהלו בעת שקרא את השירה. עשה לו במה ועלה עליה עד שראה אותם, את כולם ערוכים לפניו, וכולם יכלו לראות אותו. לא שבעו מהביט בו כשעמד על רגליו, רואה את כל הקהל ערוך לפניו, בוכה בדמעות כגשם. פתח את פיו ולימד אותם עניינים שבאמונה ובקריאת התורה, והזהירם מלשנותם. לפני הקריאה הסיר משה את המסוה מעל פניו, למען יוכל כל העם לראות כיצד יוצאות המילים מפיו. והכוהנים הגדולים ויהושע בן נון והזקנים והשופטים וכל ראשי השבטים וכל הנשים וכל הילדים וכל העם עד אחרון שבהם (בראשית יט,ד), הקשיבו ושמעו את דברי משה הנביא הגדול ואת תוכחותיו.');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (307,'V','14','מימר על וימת שם משה',5000141,'תורה צוה לנו משה ברה דעמרם ארוה קדישה מירתה לקהלי יעקב תורה צוה לנו משה ברה דעמרם ארוה קדישה יהיבה לעם קדיש תורה צוה לנו משה ברה דעמר מהימנה דאתימן על אוצרה רבה ישמר כל מה דלגוה תורה צוה לנו משה ברה דעמרם קראהה לא טעי ושמועה לא מנשי יאי מעמינה כד חסל מן ברכת קהלי יעקב שבטי ישראל צפה אל כל שבטיה ואנון סדירין קמיו והוה מפקד לון ודמעיון כות גללי ימה ערפין מן עיניון שרי ואמר לון אה שבטי רחותה אה כוכבי יעקב אה עם יה דנגדת לאכה שמרו מצוהתי ולא תנשון יתון ולא תתנו פנותה תעיל ביניכון','Moses, the son of Amram, commanded us a Law (Deut. 33:4) – a holy 
Law as the heritage of the congregations of Jacob (ibid.). Moses, the son of 
Amram, commanded us a Law – a holy Law given to a holy people. Moses, the 
son of Amram, commanded us a Law – the faithful entrusted with great treasure, 
(so that they) will keep all that is in it. Moses, the son of Amram, commanded us 
a Law – its reader does not err and the listener does not forget. It is good to see 
him when he ﬁnished blessing the congregations of Jacob, the tribes of Israel; he 
looked at all the tribes arrayed before him and gave commands to them, while 
their tears were dropping like the waves of the sea from their eyes. He began, 
saying: “O tribes of Favor, O stars of Jacob, O people of the Lord, whom I led 
hither, keep my commandments and do not forget them, and do not let Disfavor 
enter among you.”','תורה צוה לנו משה בן עמרם (דברים לג,ד) – תורה קדושה כמורשה לקהלות יעקב (שם). תורה צוה לנו משה בן עמרם – תורה קדושה שניתנה לעם קדוש. תורה צוה לנו משה בן עמרם – הנאמנים שהופקד בידיהם אוצר גדול, ישמרו את כל אשר בה. תורה צוה לנו משה בן עמרם – קוראה אינו טועה ושומעה אינו שוכח. יפה לראותו כאשר סיים לברך את קהלות יעקב, שבטי ישראל; הביט על כל השבטים הסדורים לפניו ונתן להם מצוות, ודמעותיהם נשרות כגלי הים מעיניהם. הוא פתח ואמר: "הו שבטי החסד, הו כוכבי יעקב, הו עם ה'', אשר הבאתי הלום, שמרו את מצוותי ואל תשכחום, ואל תנו לדיסחון לבוא בתוככם."');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (308,'V','23','מימר על וימת שם משה',5000231,'ומלאכי רומה חדו במקדומה תמן נחתו חילי שומיה בדיל מוקר משה ורבות נביותה וכבוד יהוה נחת וכלל כל טורה ורבואת קדשה וכל גבוראתה שרת על טור נבא כמד ארשתון מרון ועבודון נפקו לזימון משה נביה ויהבו שלם עליו דו מהימן בית אלה כמד אמר בדילה בכל ביתי נאמן הו נאמן על מה דחזה נאמן על מד שמע נאמן על מד קבל אנפקו קעימיה לזימונה והגפפו יתה וקרב לידה כבודה ולא כבה נורה דבסרה וכן אשתה וגם ערפלה וכל בוראי עלמה הוו מוקרין לה יתרבי לעלם משה נביה ספרה דכל דריה לאוי עלינן נוקרנה הלא יקרונה מיני בוראיה','The angels of heaven rejoiced at his approach. Then the hosts of heaven 
descended for the honor of Moses and the majesty of his prophethood. The Glory 
of God descended and crowned the entire mountain and the ten thousands of 
holy ones (Deut. 33:2) and all the Powers hovered on Mount Nebo, as their Master 
and Maker commanded them. They came to meet Moses the prophet and saluted 
him, for he is entrusted with the House of God, as He said about him: He is en-
trusted throughout My house (Num. 12:7). Entrusted with all he has seen, entrust-
ed with all he has heard, entrusted with all he has received. The Immortals wel-
comed him and embraced him. And the Glory approached him, and the light of 
his ﬂesh was not quenched. The Fire and also the Thick Cloud and all the crea-
tures of the world were honoring him: “Exalted be Moses the prophet forever, the 
teacher of all the generations. It is appropriate for us to glorify him, for many 
kinds of creatures glorify him.”','מלאכי השמים שמחו עם התקרבותו. אז ירדו צבאות השמים לכבוד משה ולהדר נבואתו. כבוד האל ירד וכיתר את כל ההר, ורבבות קדושיו (דברים לג,ב) וכל הכוחות ריחפו על הר נבו, כפי שציווה עליהם אדונם ויוצרם. באו לקראת משה הנביא ושאלו בשלומו, שהרי הוא נאמן בית האל, כפי שאמר עליו: נֶאֱמָן הוּא בְּכָל בֵּיתִי (במדבר יב,ז). נאמן בכל אשר ראה, נאמן בכל אשר שמע, נאמן בכל אשר קיבל. בני האלמוות קידמו את פניו וחיבקו אותו. הכבוד התקרב אליו, ואור בשרו לא כבה. האש והערפל הכבד וכל יצורי העולם כיבדוהו: "יתרומם משה הנביא לעולם, מורה כל הדורות. ראוי לנו לפארו, שהרי מינים רבים של יצורים מפארים אותו."');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (309,'V','31','מימר על וימת שם משה',5000311,'יאי מעמי למשה קעום על טור נבא ומלאכי רומה מרבין לה ואסקפה מרה וגלה נאר עיניה ועמתה ארבעת רבעת עלמה רבה הי זהותה דהות בלבה דמשה שעתה דעמתה מרה מה בתר יום נקם וכל מלאכי רומה קעמים סהרתה מימין ומשמאל ומקדמה ומבתרה וכבודה רבה צעד בימינה ומגפפנה והזל קדמיו מתמן חזה משה הרגריז וגען על אפיו וסגד וכד קעם נביה רבה משה מן סגדתה חזה תרח מערתה פתחי קדמיו וכד עמה תרח מערתה פתחי בכה לאדם ושבח למרה רבה היא שעתה דבה ארכן נביה רבה משה רישה ועלל לגו מערתה וצלה וסגד להרגריזים ודמך על ארצה ושבה צלמה כבונה ומרה אפל עליו שנתה רבתה ואנפקת רוחה בלא צער והוא לא ידע ואנון ארבעה מערין מעתדים מן ימי הבריה מערת מכפלתה לזכאי עלמה ומערת הרגרי למשכנה ומערת הר ההר לכהנתה ומערת הר נבא לנביותה וימת שם משה עבד יהוה כמה דאמר מרה עליו עבדי משה','It is appropriate to see Moses standing on Mount Nebo, and the celestial 
angels exalting him. His master elevated him and unveiled the light of his eyes 
and showed him the four edges of the world. Great the joy that was in Moses’ 
heart when his Master showed him what will be afer the Day of Vengeance, 
while all the celestial angels stood around him on his right and on his lef and 
before and behind him, and the Great Glory held his right hand and embraced 
him and walked before him. From there Moses saw Mount Gerizim, and bowed 
down and prostrated. When the great prophet arose from his prostration, he saw 
the entrance of the cave open before him. And when he saw the entrance of the 
cave open he wept for Adam and praised his Master. Great was the moment 
when the great prophet Moses lowered his head and entered the cave and prayed 
and prostrated towards Mount Gerizim and lay down on the ground and directed 
his face toward it. His Master cast a great sleep upon him, and his soul departed 
with no distress, while he was unconscious. These are four caves prepared from 
the days of the Creation: the cave of Machpelah for the Righteous of the world, 
and the cave of Mount Gerizim for the Sanctuary, and the cave of the Mountain 
of Mountains for the priesthood, and the cave of Mount Nebo for the 
prophethood. Moses the servant of the Lord died there (Deut. 34:5), as his Master 
said about him: My servant Moses (Num. 12:7).','ראוי לראות את משה עומד על הר נבו, ומלאכי השמים מרוממים אותו. אדונו הגביהו וגילה את אור עיניו והראה לו את ארבע כנפות העולם. גדולה השמחה שהייתה בלב משה כאשר הראה לו אדונו את אשר יהיה אחרי יום הנקם, בעוד כל מלאכי השמים עמדו סביבו מימינו ומשמאלו ולפניו ומאחוריו, והכבוד הגדול אחז בידו הימנית וחבקו והלך לפניו. משם ראה משה את הר גריזים, וכרע וישתחו. וכאשר קם הנביא הגדול מהשתחוויתו, ראה את פתח המערה פתוח לפניו. וכאשר ראה את פתח המערה פתוח, בכה על אדם ושיבח את אדונו. גדול היה הרגע שבו הרכין הנביא הגדול משה את ראשו ונכנס אל המערה והתפלל והשתחווה לעבר הר גריזים ושכב על הארץ והפנה את פניו אליה. אדונו הפיל עליו תרדמה גדולה, ונשמתו יצאה ללא ייסורים, בעודו שרוי בחוסר הכרה. אלו הן ארבע מערות שהוכנו מימי הבריאה: מערת המכפלה לצדיקי העולם, ומערת הר גריזים למקדש, ומערת הר ההרים לכהונה, ומערת הר נבו לנבואה. וַיָּמָת שָׁם מֹשֶׁה עֶבֶד יְהוָה (דברים לד,ה), כפי שאמר עליו אדונו: עַבְדִּי מֹשֶׁה (במדבר יב,ז).');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (310,'V','7','מימר על וימת שם משה',5000071,'וכד אמטו לידה נפלו על רגליו ונשקו צלמה מן אכה ומן אכה ופינחס בן אלעזר סבל חציצריה באדה והוא קעום קדמיו בכי אמר לה נביה רבה משה אה בר ברה דאחי קום אתה ואיתמר בתרח אהל מועד ותרי חציצריה באדיכון ואתקעו תרועה עד ישמעו כל קהלה וייתו לאכה ויסתדרו לקדמי ובתר כן אפשט לון שלמה קעם איתמר ופינחס ותקעו תרועה בפתח משכנה וכד שמעו עמה קל חציצריה הבלדו שריר ואמרו מה דאה אתקעותה בהדה שעתה לא זבן קרב ולא זבן מטל ולא זבן קרבן וכל קהל ישראל דחל ורתת','And when they reached him they fell upon his feet and kissed his face on 
both sides, and Phinehas the son of Eleazar, who was carrying the trumpets in 
his hand, was standing before him weeping. The great prophet Moses said to 
him: “O son of the son of my brother, you and Ithamar stand you at the gate of 
the Tent of Gathering with the two trumpets in your hands and blow a blast, that 
all the congregation may hear and come and be arrayed before me. Afer this I 
shall extend greetings to them.” Ithamar and Phinehas arose and blew a blast at 
the gate of the Sanctuary. When the people heard the sound of the trumpets, 
they were very frightened and said: “What is this blast? Right now it is neither 
time for battle, nor time for journey, nor time for sacriﬁce.” And all the congrega-
tion of Israel was fearful and trembling.','וכאשר הגיעו אליו נפלו על רגליו ונישקו את פניו משני עבריו, ופינחס בן אלעזר, שהחזיק את החצוצרות בידו, עמד לפניו ובכה. אמר לו משה הנביא הגדול: "בן בן אחי, עמוד אתה ואיתמר בשער אוהל מועד עם שתי החצוצרות בידיכם ותקעו תקיעה, למען ישמע כל הקהל ויבוא ויעמוד לפניי. לאחר מכן אשא את ברכתי אליהם." קם איתמר ופינחס ותקעו תקיעה בשער המקדש. כשמעו העם את קול החצוצרות נבהלו מאוד ואמרו: "מהי התקיעה הזאת? עתה לא עת מלחמה היא, ולא עת מסע, ולא עת קרבן." וכל עדת ישראל הייתה מלאת יראה ורעד.');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (311,'V','5','מימר על וימת שם משה',5000051,'ומשה ברה דעמרם קעום לקדם מרה שמע כל אלין בוראיה שאלין לאלה בדילה הן לא יקרב לידה מותה ואלה מגיב יתון יום געוזה אמטי לית שיאל מהאני מרירה שעתה דבה שמע משה מן מרה כל הדה אגבוהתה דאגיב בדילה לכל בוראיה בחסול יומי חייה יאי מעמי לנביה רבה משה כד שמע כל הדה קעם מצלי וסגד ובכי ודמעיו כות גללין ולית הוה בכוה על קנומה אלא על ישראל תלה ית קלה ואמר אוי לך אה קהלה אנה געוז ושבק יתך ואתה טעי בתר מותי מנו דיצלי בדילך מנו דיתחנן בגללך מנו דיאחס עליך בתרי מן חייה אנה מתפני ורמי לגו גובה דחפסה אדם וליני עלל ליד ארעה טבתה וסכומי מטי ויומה אנה אזל מן אכה מזבן במלתה דנחשה מנסב במיכלה דחוה מגמל על עמלה דאדם ולית בי סוברו עד לעלם זכותה דילך מרי כליל חייה לגלדך ליתה נסב אפים לא לנביא ולא למלך ולא לעתיר ולא למסכין ולא מעלם על פשרון זכותה דילך אה דיאנה אה סגי חסדה וקשטה 6] [ ובתר כן אתחנן נב רבה משה בתרע אגנה וכד אתסכם מן תחנונה זעק ליהושע בן נון וחכמה בכל אהן דברה ואמר לה אה יהושע זרז במהלך אל תרח משכנה קדישה וחכם כל בית כהנתה ואמר לאלעזר ואיתמר ופינחס ייתו באפרי עד נסבע מנון ונשגר יתון בשלם כל אהן דברה עם יהושע מן נביה רבה משה בתרח אגנה דנטה יתה משה רחיק מן משריה וזעק לה משכן זימונה מן יתה אתרה נפק יהושע שמש משה אישה ואתא בזרוז ליד משכנה קדישה וקעם לקבל תרחה ויהב ית קלה בבכי וכד שמעו שמשי מטרתה קלה דיהושע מתלי בבכיה רבה געזו ליד משכנה וחוו לכהניה רברביה נפקו כות בוצינין מנירין אלע ואי ופינחס וצפו ליד יהושע והוא בכי ודמעיו כנד נוזלים אמרו לה אה יהושע על מה אתה בכי אמר לון אדני משה אתבעי יסק ימות וכד שמעו אהן ממללה תלתי כהניה אתלחצו מנה וזרזו במהלכון וכל שבט לוי עמון ואתו לאקר משה','And Moses, the son of Amram, was standing before his Master, hearing 
all these creatures imploring God on his behalf that death should not approach 
him. God was answering them: “The day of his passing away approaches; 
supplication is of no avail.” Bitter (was) the hour when Moses heard these 
answers, that God answered on his behalf to all the creatures about the end of 
the days of his life. It is appropriate to see the great prophet Moses at the time 
when he heard all of this. He was standing, supplicating and bowing down and 
weeping, his tears like waves. He was not weeping for himself, but for Israel. He 
raised his voice and said: “Woe to you, O congregation. I pass away and leave 
you, and you will go astray afer my death. Who is he who will pray for you? Who 
will supplicate for you? Who will have compassion for you afer me? I turn away 
from life and am cast into the pit which Adam dug out, and I will not enter the 
good land (Deut. 11:17). My end arrives, and to day I go from here, sold by the 
word of the serpent, taken away through the eating of Eve, repaid for the act of 
Adam, and I have no hope forever. The righteousness is Yours, O my Master, the 
crown of Life belongs to Your greatness – He is not partial (Deut. 10:17) neither to 
a prophet nor to a king, nor to a rich man or to a poor man; He does not ignore 
judgement – righteousness is Yours, O Judge, O abundant in grace and truth.”','ומשה בן עמרם עמד לפני אדונו ושמע את כל הבריות הללו מתחננות לאל בעדו שלא יקרבנו המוות. האל ענה אותן: "יום פטירתו מתקרב; אין בתחינה כדי להועיל." מרה הייתה השעה בה שמע משה את התשובות הללו, שענה האל בעדו לכל הבריות על קץ ימי חייו. ראוי לראות את הנביא הגדול משה בשעה שבה שמע את כל זאת. עמד, מתחנן ומשתחווה ובוכה, ודמעותיו כגלים. לא על עצמו בכה, אלא על ישראל. נשא קולו ואמר: "אוי לך, קהל. אני הולך ועוזב אתכם, ואחרי מותי תתעו. מי הוא שיתפלל בעדכם? מי יתחנן בעדכם? מי ירחם עליכם אחרי? אני פונה מן החיים ומושלך אל הבור שחפר אדם, ולא אכנס אל הארץ הטובה (דברים יא,יז). קצי מגיע, והיום אני הולך מכאן, מכור בדבר הנחש, נלקח בעטיו של מאכל חוה, ומשתלם על מעשה אדם, ואין לי תקווה לעולם. הצדק שלך, אדוני, כתר החיים שייך לגדולתך – הוא אֲשֶׁר לֹא-יִשָּׂא פָנִים (דברים י,יז) לא לנביא ולא למלך, לא לעשיר ולא לעני; הוא אינו מתעלם מן הדין – הצדק שלך, שופט, רב חסד ואמת."');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (312,'V','24','מימר על וימת שם משה',5000241,'מיה אוקרותה שבעה זבנין לגו מי נהרה אטלק מימי נהרה עבדה אדם מימי מיה פלג באטרה מימי מרה חלה בטרף מימי בוראה כתב באדה במי כיורה אתרחץ וכן ספרותה דמיה למיה יתרבי לעלם דן נביה דיקרה ברואה','The Waters honored him seven times: (1) Into the waters of the river he 
was cast; (2) the waters of the river he turned into blood; (3) the waters of the sea 
he divided with his staﬀ; (4) the waters of Mara he sweetened with a twig; (5) the 
waters of ordeal he wrote with his hand; (6) in the waters of the basin he 
washed; (7) also, his teaching resembles water. Exalted be this prophet forever, 
whom his Creator honored.','המים כיבדוהו שבע פעמים: (1) אל מי היאור הושלך; (2) את מי היאור הפך לדם; (3) את מי הים בקע במטהו; (4) את מי מרה המתיק בענף עץ; (5) את מי הסוטה כתב בידו; (6) במי הכיור רחץ; (7) וגם תורתו דומה למים. יתרומם הנביא הזה לעולם, אשר יוצרו כיבדו.');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (313,'V','32','מימר על וימת שם משה',5000321,'וימת שם משה עבד יהוה כפת גרמה למרה כות עבד עם מרה וימת שם משה על מימר יה רב הוא נביה דכל דלה על מימר יה אדכיר לטב עד לעלם נביה רבה משה דגלה בתר מותה שבעה קנואן שמש רחותה הכסית ועלת לגו מערת וקנתה ליתה סלקה ולא מתגליה לעלם פמה דמערתה אצטנק בכבוד וקנה ליתי מתפתחה ולא מתחכמה לעלם עמוד עננה דהוה הלך לקדמיו קנא דו סליק ולא מתעמי לעלם עמוד אשתה דהוה מניר בליליה בקנאה רבה וליתו מתגלי לעלם מנה דאעתה אלה מן שומיה בצלותה אקטע וליתו נחת בתרה לעלם קרן אורה דהוה שרי על צלמה אטפה ועל צלם חורנה לא יתחזי לעלם נביותה דלבשה והוה מלוא בה אזלת ולית אנש לבשה לעלם עלמין','Moses the servant of the Lord died there (Deut. 34:5) – he submitted 
himself to his Master like a servant to his master. Moses the servant of the Lord 
died there according to the word of the Lord. Great is the prophet, for everything 
he has done is according to the word of the Lord. Of blessed memory be the great 
prophet Moses forever who revealed seven passions afer his death. (1) The sun 
of Divine Favor has been hidden and has entered the cave, and his (Moses’) 
ardor will never rise nor appear (again). (2) The entrance of the cave has been 
shut in glory, and zeal will never be opened up nor be known. (3) The pillar of 
cloud that walked before him was in passion, for it is about to ascend and will 
never be seen again. (4) The pillar of ﬁre which was illuminating in the night is 
in great passion; it will never appear (again). (5) The Manna, which God made 
descend from heaven through his prayer, ceased and will never descend afer 
(his death). (6) The ray of light that dwelt on his face was extinguished and will 
never appear on another face. (7) The prophethood which he wore and was en-
trusted with went away and none will wear it, forever and ever.','וַיָּמָת שָׁם מֹשֶׁה עֶבֶד יְהוָה (דברים לד,ה) – הכניע את עצמו לאדונו כעבד לאדונו. מֹשֶׁה עֶבֶד יְהוָה מֵת שָׁם עַל פִּי יְהוָה. גדול הנביא, כי כל אשר עשה היה על פי ה''. יהא זכרו לברכה לנביא הגדול משה לעולמים, אשר גילה שבע אבלות לאחר מותו. (1) שמש החסד הסתתרה ונכנסה אל המערה, ולהבתו של משה לא תזרח ולא תיראה לעולם. (2) פתח המערה נסגר בכבוד, והקנאה לא תיפתח ולא תיוודע לעולם. (3) עמוד הענן שהלך לפניו היה בהתלהבות, כי הוא עתיד לעלות ולא יֵראה עוד. (4) עמוד האש אשר האיר בלילה נתון בצרה גדולה; הוא לא יופיע עוד. (5) המן, אשר הוריד אלוהים מן השמים בתפילתו, פסק ולא יֵרד עוד אחרי מותו. (6) קרן האור ששכנה על פניו כבתה ולא תופיע על פנים אחרים לעולם. (7) הנבואה אשר לבש ואשר נאמן לה הלכה לה, ואיש לא ילבשנה, לעולם ועד.');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (314,'V','12','מימר על וימת שם משה',5000121,'הוה משה אמר אה קהלה טובך הן תשמע כל אהן ממללה דאנה אמר קמיך תלתה זבנין אמר לי עבודי סוק לידי וסלקת לידה במדע נביותה תרין אנדית לוחין קמאין ועוד תניאנים ובהדה אנה נסב חלקי דירתתה מן אדם אבוה דבשר בתרין סלקת ונחתת הך דארשתי אלה ואכה אני סלק ולא נחת כמד שפט עלי מרי אדלא אמות אנה מברכך ברכה מצלה משמה דאלה וסדר קהלה קמיו סדירין והוא מוכח ומלף ומזהר ומברך מפני מותה','Moses was saying: “O congregation, happy are you that take notice of all 
this speech that I speak before you. Three times my Maker said to me: Come up to 
me (Exod. 24:12; Deut. 10:1), and I ascended to Him with the mind of prophet-
hood. Twice: (when) I brought the ﬁrst tablets and also the second ones. And 
this (third) time I take my share inherited from Adam, the father of ﬂesh. Twice I 
ascended and descended, as God ordered me. And now I ascend and will not de-
scend, as God sentenced me. Before I die, I bless you with a blessing derived 
from the name of God.” He arrayed the congregation before him rank by rank, 
admonishing and teaching and warning and blessing before his death.','משה אמר: "הו עדה, אשריכם שאתם שמים לב לכל הדברים האלה שאני מדבר לפניכם. שלוש פעמים אמר לי בוראי: עלה אלי (שמות כד,יב; דברים י,א), ועליתי אליו ברוח הנבואה. פעמיים: כאשר הבאתי את הלוחות הראשונות וגם את האחרונות. ובפעם הזאת, השלישית, אני נוטל את חלקי הירושה מאדם, אבי הבשר. פעמיים עליתי וירדתי, כאשר ציוה אותי האל. ועתה אעלה ולא ארד, כאשר גזר עלי האל. בטרם אמות, אברך אתכם בברכה הנגזרת משם האל." הוא סידר את העדה לפניו שורות שורות, ומוכיח ומלמד ומזהיר ומברך לפני מותו.');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (315,'V','9','מימר על וימת שם משה',5000091,'והוא קעום כות זהר באמלאו תלה נביה רבה משה ית קלה בבכיה רבה על כל קהלה לא על קנומה ואמר אה דמוכי מערת המכפלה אתעירו אה תדע רוחך אה אבאה טבה ארשה דזכותה ושלמותה הן פרדיסך דאנצבת בזכותך עתיד מנתש בחוביה אה תדע רוחך אה יצחק דבחה קדישה דלא הנכס דסחנתך דעמרת באנצירותך מחרב ומלקי במטר אבק ואפר בחובי פנותה אה יעקב אבי שבטי רחותה אה תדע רוחך דשבטיה דקמו ממך ובניהון דאתפרקו בסימניה ופליהתה וגעזו ימה וקעמו בשפול טור סיני ושמעו קל מרה דעלמה קרי עסרתי מליה מפם גבורתה ובדילון כתיב לגו ארהותה מה טבו אהליך יע ומשכנו ישר כנחלי נטו באיקר רב כגנות עלי נהר בחסד חיול כאהל נטע יה בקדש כארז עלי מים בטהרה כל אלין עקובהתון ] ב [ רחותה ] ו [ מבתרי ] ב [ פנותה מס ] תל [ קה מנון ובילהתה סגיה ומשכן יה יתכסי והרגריזים יתחרב באדי דבבי אלה ופנאיה יגלי בכל אתר ותיזל דכיותה ותיתי טמתה ויתקף רגז יהוה ולא יתשקח מן לה קנאה תריח לאלה כמד קנא פינחס וכלה מגיפתה מן שת מאון דאלפין','He was standing like the moon in its fullness. The great prophet Moses 
raised his voice in lament over all the congregation, not over himself, and said: 
“O these who lie in the cave of Machpelah, awake! Does your spirit know, O good 
father, the origin of righteousness and perfection, that the garden you planted 
by your righteousness, will be uprooted because of sins? Does your spirit know, 
O Isaac, the holy oﬀering which was not slaughtered, that your estate, which you 
built by your devotion, is ruined and smitten by the downpour of dust and ashes 
because of the sins of Disfavor? O Jacob, father of the tribes of Favor, does your 
spirit know, that the tribes which arose from you, and their sons who were re-
deemed with wonders and miracles, and passed over the sea, and stood at the 
foot of Mount Sinai, and heard the voice of the Master of the world proclaiming 
the Ten Words from the mouth of the Divinity, and for their sake it is written in 
the Law: How fair are your tents, O Jacob, Your dwellings, O Israel! Like palm-
groves that stretch out in great glory, like gardens beside a river in mighty grace, 
like aloes that the Lord planted in holiness, like cedars beside the water in purity 
(Num. 24:5–6)? All these, their glories are in the Divine Favor, and afer me, 
during the Disfavor, they will be removed from them. Fear will increase, and the 
Sanctuary of the Lord will be concealed, and Mount Gerizim will be ruined by 
the enemies of God, and apostasy will appear in every place, and purity will dis-
appear and deﬁlement will come. The Lord’s wrath will grow, and nobody with 
passion will be there to reconcile God in the way that Phinehas was impassioned 
and (thus) removed the plague from six hundred thousand.”','עמד כירח במלואו. משה הנביא הגדול נשא את קולו בקינה על כל הקהל, לא על עצמו, ואמר: "אתם השוכבים במערת המכפלה, עורו! האם יודע רוחך, אבינו הטוב, מקור הצדק והתמימות, כי הגן שנטעת בצדקתך ייעקר בגלל החטאים? האם יודע רוחך, יצחק, הקרבן הקדוש שלא נשחט, כי נחלתך שבנית במסירותך חרבה ומוכה בזרם עפר ואפר בגלל חטאי הסתר הפנים? יעקב, אבי שבטי הרצון, האם יודע רוחך, כי השבטים שיצאו ממך, ובניהם שנגאלו באותות ובמופתים, ועברו את הים, ועמדו לרגלי הר סיני, ושמעו את קול אדון העולם מכריז את עשרת הדברות מפי האלוהות, ולמענם כתוב בתורה: מַה טֹּבוּ אֹהָלֶיךָ יַעֲקֹב מִשְׁכְּנֹתֶיךָ יִשְׂרָאֵל, כִּנְחָלִים נִטָּיוּ בכבוד עצום, כְּגַנֹּת עֲלֵי נָהָר בחסד אדיר, כַּאֲהָלִים נָטַע יְהוָה בקדושה, כַּאֲרָזִים עֲלֵי מָיִם בטהרה (במדבר כד,ה-ו)? כל אלה, כבודם הוא ברצון האלוהי, ואחריי, בעת ההסתר, יילקח מהם. הפחד יגדל, ומקדש ה'' יסתר, וסיני הגריזים ייחרב בידי שונאי האל, והמרד יופיע בכל מקום, והטהרה תיעלם והטומאה תבוא. חרון ה'' יגבר, ולא יהיה איש בוער-קנאה שיפייס את האל בדרך שקינא בה פינחס וסילק בכך את המגפה משש מאות אלף."');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (316,'V','26','מימר על וימת שם משה',5000261,'ארעה אוקרת יתה שבעה זבנין כתב בבראשית והארץ היתה תהו ובהו ארתת ארעה בגללה ביום השלישי כמד כתב באגרתה ויחרד כל ההר מאד גלה אמנות ארעה במימרה ונתנה הארץ יבולה ארעה בלעת דבביו קרח וכל עדתו אסתקף על כל בני אדם וכתב גלגיו בידו וגם האיש משה גדל מאד מכל האדם אשר על פני האדמה ולה אמר אלהים עלי אל הר העברים הזה וראה את הארץ וסלק לטור נבא ויריאהו יהוה את כל הארץ ודן סימנה לית כותה ארעה כד עמת שומיה אזינת אל ממלליו ארכנת למשמע מימרה כמד כתב ותשמע הארץ אמרי פיי כל אהן הוה למשה דלית אנש דמי לה לעלם','The earth honored him seven times: (1) He wrote in Genesis: the earth 
was unformed and void (Gen. 1:2); (2) the earth trembled because of him on the 
third day as he wrote in his book: and the whole mountain quaked greatly (Exod. 
19:18); (3) he revealed the habit of the land by his saying: the earth shall yield its 
produce (Lev. 26:4); (4) the earth swallowed up his enemies, Korah and all his 
party. He was exalted above all the sons of Adam and (God) wrote his praises 
with His hand: The man Moses was very great, more than all men that were on the 
face of the earth (Exod. 11:3); (5) to him God said: Ascend this mountain of the 
Hebrews and view the land (Num. 27:12); (6) he ascended Mount Nebo and the 
Lord showed him all the land (Deut. 34:1) – and this is a great wonder, there is 
none like it; (7) when earth saw heaven giving ear to his words, bending down to 
listen to his speech, (it gave ear too) as He wrote: Let the earth hear the words of 
my mouth (Deut. 32:1). All this was (done) to Moses, the like of whom nobody 
resembles ever.','הארץ כיבדתו שבע פעמים: (1) כתב בבראשית: וְהָאָרֶץ הָיְתָה תֹהוּ וָבֹהוּ (בראשית א,ב); (2) הארץ רעדה בגללו ביום השלישי, כפי שכתב בספרו: וְכָל הָהָר חָרַד מְאֹד (שמות יט,יח); (3) גילה את טבע הארץ באומרו: וְנָתְנָה הָאָרֶץ יְבוּלָהּ (ויקרא כו,ד); (4) הארץ בלעה את אויביו, את קורח ואת כל עדתו. הוא התרומם על כל בני האדם, וה'' כתב את שבחיו בידו: וְהָאִישׁ מֹשֶׁה גָּדוֹל מְאֹד מִכָּל הָאָדָם אֲשֶׁר עַל פְּנֵי הָאֲדָמָה (שמות יא,ג); (5) אליו אמר האל: עֲלֵה אֶל הָהָר הָזֶה הָעֲבָרִים וּרְאֵה אֶת הָאָרֶץ (במדבר כז,יב); (6) עלה הר נבו וַיַּרְאֵהוּ ה'' אֶת כָּל הָאָרֶץ (דברים לד,א) — וזהו פלא גדול, אין כמוהו; (7) כאשר ראתה הארץ את השמים מאזינים לדבריו ומתכופפים לשמוע את דברי פיו, האזינה גם היא, כפי שכתב: וְתִשְׁמַע הָאָרֶץ אִמְרֵי פִי (דברים לב,א). כל זאת היה למשה, שאין דומה לו לעולם.');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (317,'V','19','מימר על וימת שם משה',5000191,'וכד חסל נביה רבה משה מפקד ומוכח ומלף ומברך קעם על רגליו וחזה יתון מסתדרין אזדזע עלמה שעתה דקעם על רגליו והוא מהלך בעי יסק ימות ואלעזר ברה דאחוה צעד בימינה ופינחס ברה צעד בשמאלה ואיתמר ויהושע הלכים קדמיו וכל ביתה דכהנתה הוו מוקרין יתה מן שאם יתה שעתה ובכיתה דהות בגוה ביני קהלה שעתה דאמטה משה לשפולי טור נבא כל שבטיה אתקדמו לידה שבט בתר שבט ואפשטו לה שלמה וכל אנש הוה אתי מנשק אדיו אחד בתר אחד וכל קהל ישראל ואלעזר ואיתמר ופינחס גפפונה ונשקו יתה ואפשטוה שלמה ויהושע תלמידה נשק צלמה ונשק ידיו וגען בצלמה על רגליו ואמר שלם עליך אה מהימן בית אלהים צוקתך רבה עלי יומה בפרוקך','When the great prophet Moses had ﬁnished commanding and exhorting 
and teaching and blessing the congregation, he rose to his feet and saw them ar-
rayed. The world shuddered at the moment he rose to his feet, when he went, 
about to climb and die. Eleazar the son of his brother held his right hand, and 
Phinehas his son held his lef hand, and Ithamar and Joshua walked before him 
and all the house of the priesthood gloriﬁed him. Who can envision that hour 
and the weeping which was in it among the congregation? When Moses reached 
the foot of Mount Nebo, all the tribes went forward to him, tribe afer tribe, and 
saluted him. Every man was coming, kissing his hands one by one. All the con-
gregation of Israel and Eleazar and Ithamar and Phinehas embraced him and 
kissed him and saluted him. Joshua his disciple kissed his face and kissed his 
hands, and prostrated with his face to his feet and said: “Peace to you, O one 
entrusted with the House of God, the distress of your departure is hard for me 
today.”','כַּאֲשֶׁר כִּלָּה הַנָּבִיא הַגָּדוֹל מֹשֶׁה לְצַוּוֹת וּלְהַזְהִיר וּלְלַמֵּד וּלְבָרֵךְ אֶת הַקָּהָל, קָם עַל רַגְלָיו וְרָאָה אוֹתָם עֲרוּכִים. הָעוֹלָם נָרַד בָּרֶגַע שֶׁקָּם עַל רַגְלָיו, בְּלֶכְתּוֹ כְּשֶׁהוּא עוֹמֵד לַעֲלוֹת וָמוּת. אֶלְעָזָר בֶּן אָחִיו אָחַז בְּיָמִינוֹ, וּפִינְחָס בְּנוֹ אָחַז בִּשְׂמֹאלוֹ, וְאִיתָמָר וִיהוֹשֻׁעַ הָלְכוּ לְפָנָיו וְכָל בֵּית הַכְּהֻנָּה כִּבְּדוֹ. מִי יָכוֹל לְהַעֲלוֹת בְּדַעְתּוֹ אֶת אוֹתָהּ שָׁעָה וְאֶת הַבְּכִי שֶׁהָיָה בָּהּ בְּתוֹךְ הַקָּהָל? כְּשֶׁהִגִּיעַ מֹשֶׁה לְרַגְלֵי הַר נְבוֹ, כָּל הַשְּׁבָטִים יָצְאוּ לִקְרָאתוֹ שֵׁבֶט אַחַר שֵׁבֶט וְשָׁאֲלוּ בִּשְׁלוֹמוֹ. כָּל אִישׁ בָּא וְנָשַׁק אֶת יָדָיו אֶחָד אֶחָד. כָּל קְהַל יִשְׂרָאֵל וְאֶלְעָזָר וְאִיתָמָר וּפִינְחָס חִבְּקוּהוּ וְנָשְׁקוּ לוֹ וְשָׁאֲלוּ בִּשְׁלוֹמוֹ. יְהוֹשֻׁעַ תַּלְמִידוֹ נָשַׁק אֶת פָּנָיו וְנָשַׁק אֶת יָדָיו, וְהִשְׁתַּחֲוָה בְּפָנָיו לְרַגְלָיו וְאָמַר: "שָׁלוֹם לְךָ, הַנֶּאֱמָן עַל בֵּית הָאֱלֹהִים, צַעַר פְּרֵדָתְךָ קָשֶׁה עָלַי הַיּוֹם."');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (318,'V','28','מימר על וימת שם משה',5000281,'עננה אוקרה שבעה זבנין שרוי אלין שבעתיתה עננה הזל לקדמיו יומם ולילה כד נגד שת מון דאלף ממצרים כמד כתב ויהוה הלך לפניהם יומם בעמוד ענן להנחתם דרך הדה רבו רבה למשה מן יכל ימני רבותה אי יאמר ציבעד מן גלגיו עננה אניר וחשיך לקדמיו ואהן סימן רב לית כותה כי אמנות עננה חשכה תדירה וארום כתיב ויהי הענן החשיך ויאיר את הלילה וכד אסתכל משה ועמה אקר פלוג מימי ימה עננה מחשיך ומניר שבח לעבוד פליהתה ואמר מי כמוך באלים יהוה יתרבי לעלם דן נביה קדישה דאסקף מרה דרגה בעללה ירום שמה ויכבד דאמר לה מרה דעלמה הנה אנכי בא אליך בעבי הענן בעבור ישמע העם בדברי עמך וגם בך יאמנו לעולם','The Cloud honored him seven times: (1) The ﬁrst of these seven was 
when the cloud walked before him day and night, when he was leading six hun-
dred thousand from Egypt, as He wrote: The Lord went before them in a pillar of 
cloud by day, to guide them along the way (Exod. 13:21). This is great majesty for 
Moses. Who can estimate his greatness or tell (even) a little of his praises? 
(2) The cloud shone and darkened before him – this is a great wonder, like which 
there is no other – for the habit of the cloud is always to darken. Nevertheless, it 
is written: There was the cloud darkening, and it lit up the night (SP Exod. 14:20). 
And when Moses looked at the splitting of the waters of the sea and saw the 
cloud darkening and illuminating, he praised the Maker of wonders and said: 
Who is like you, O Lord, among the gods? (Exod. 15:11) Exalted be this holy 
prophet forever, whose rank his Master elevated in the sky. (3) Elevated be his 
name and gloriﬁed, for the Master of the world said: Behold, I am coming to you 
in a thick cloud, that the people may hear when I speak with you, and may also 
believe you forever (Exod. 19:9).','הענן כיבדו שבע פעמים: (1) הראשונה שבשבע הללו היתה כאשר הלך הענן לפניו יומם ולילה, בהנהיגו שש מאות אלף מתוך מצרים, כפי שכתב: וה'' הולך לפניהם יומם בעמוד ענן לנחותם הדרך (שמות יג,כא). זהו הדר גדול למשה. מי יוכל לאמוד את גדולתו, או לספר אפילו מעט מתהילותיו? (2) הענן האיר והחשיך לפניו – זהו מופת גדול, שאין כמוהו – שהרי דרכו של הענן להחשיך תמיד. ואף על פי כן כתוב: ויהי הענן מחשיך ויאר את הלילה (שמות יד,כ, נוסח שומרוני). וכאשר הביט משה בקריעת מימי הים וראה את הענן מחשיך ומאיר, שיבח את יוצר המופתים ואמר: מי כמוך באלים ה'' (שמות טו,יא). מרומם יהיה נביא קדוש זה לעולם, אשר אדונו הגביה את מעלתו בשמים. (3) מרומם שמו ומפואר, כי אמר אדון העולם: הנה אנכי בא אליך בעב הענן, בעבור ישמע העם בדברי עמך, וגם בך יאמינו לעולם (שמות יט,ט).');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (319,'V','11','מימר על וימת שם משה',5000111,'אה לאוי מתשקח תמן בכוי מקשט מזזעים קנאה בדיל לא יתכסי אה לאוי הוית אנה אמר משה נביה תלי אדי לשומיה בדיל לא אתכסי אה לאוי הוית אנה אמר משה נביה יכל קעם תמן מצלי בדיל לא אתכסי על סכית נביותה אנה קעם עמי עקבאי דריה ומה עתיד לגון הדה בסרתה דאנה מבסר לך בסרה ממטיה יתכון אל דרי שלמותה','“Would that there be a truthful mourner (who would) stir up zeal, so that 
it may not be concealed. Would that I”, said Moses the prophet, “could raise my 
hands toward heaven, and not be concealed. Would that I”, said Moses the 
prophet, “could stand there and pray and not be concealed. On the watchtower 
of prophethood I stand, looking at the end of the generations and what is pre-
pared therein. These tidings that I announce you are tidings that will lead you to 
the generations of perfection.”','"מי יתן ויהיה אבל אמת שיעורר קנאה, למען לא יסתר. מי יתן", אמר משה הנביא, "שאוכל לשאת ידיי אל השמים, ולא ייסתר. מי יתן", אמר משה הנביא, "שאוכל לעמוד שם ולהתפלל ולא ייסתר. על מצפה הנבואה אנכי עומד, מביט אל קץ הדורות ואל המוכן בהם. הבשורה שאני מבשר לכם היא בשורה שתוביל אתכם אל דורות השלמות."');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (320,'V','22','מימר על וימת שם משה',5000221,'והוה נביה צפי לרישה דטורה ועמי מלאכיה קעמין למוקרה במקדומה מרירה שעתה דבה אמטה משה לטורה ועמה מלאכיה קעמין לזימונה וכל ישראל עיניון עמה עגלין לה כן הוה משה עגל לידון מרירה שעתה דהוה בה משה נביה עלל לגו עננה וכסה יתה כות מאור וכד השגב משה מן עיני קהלה הוה כל אחד מנון מציק עם חברה וכהלון אמרין זה לזה אזל משה נביה מבינן בשלם איעשה רבה בין כל קהל ישראל וצוקה חיולה שרת עליון מן פרוקה','The prophet was looking at the top of the mountain, seeing the angels 
who stood to honor him at his approach. Bitter was the moment at which Moses 
arrived to the mountain and saw the angels standing to meet him, and all Israel, 
their eyes were with him, seeing him. Likewise, Moses saw them. Bitter was the 
moment at which Moses entered the cloud, which covered him like a luminary. 
And when Moses was hidden from the eyes of the congregation, every one of 
them was in distress (together) with his fellow, and all of them said to one anoth-
er: “Moses the prophet departed from among us in peace.” A great despair was 
among all the congregation of Israel and a mighty distress hovered over them 
because of his departure.','הנביא הביט אל ראש ההר, וראה את המלאכים שעמדו לכבדו עם התקרבותו. מר היה הרגע שבו הגיע משה אל ההר וראה את המלאכים עומדים לקראתו, וכל ישראל — עיניהם היו אתו, רואים אותו. וכן גם משה ראה אותם. מר היה הרגע שבו נכנס משה אל תוך הענן, אשר כיסה אותו כמאור. וכאשר נסתר משה מעיני העדה, היה כל אחד מהם שרוי בצרה יחד עם רעהו, וכולם אמרו זה לזה: "משה הנביא עזב אותנו בשלום." יאוש גדול אחז את כל עדת ישראל ומצוקה עצומה ריחפה עליהם בגלל לכתו.');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (321,'V','21','מימר על וימת שם משה',5000211,'נתן אפרשו גדיל ודחיל אדלא אתין עמין משה סליק לטור נבא בעינה דלבה נעמי משה נביה שעתה דאתפרש מן קהלה וסלק הוו ספין על רישיון עפרה ובכיתון סלקה לשומיה והוא סליק ציבעד ומשאם לאחריו ועיניה ממכין דמעין כות מטרה והוא סליק ציבעד ומסתכל לאחריו מדמי לילידה לה בנים ינוקים בכים על חסרנה והוא סליק ציבעד וצפי לאחריו ובכי ואמר אוי עליך אה קהלה והוא סליק ציבעד וצפי לאחריו ורוחה משנקה מן רב בכותה','Let us set forth a great and frightful separation before (we) come to con-
template Moses ascending to Mount Nebo. With the eye of the heart let us see 
Moses the prophet when he departs from the congregation and ascends. They 
would scatter dust on their heads and their lament went up to heaven. And he 
would ascend a little and look behind him, while his eyes shed tears like rain. 
And he would ascend a little and look behind him, resembling a mother who has 
suckling sons sobbing on her absence. And he would ascend a little and look 
behind him and weep saying: “Woe to you, O congregation.” And he would 
ascend a little and look behind him, and his spirit was aﬄicted with his intense 
weeping.','נָשִׂים לְפָנֵינוּ פְּרֵדָה גְּדוֹלָה וְנוֹרָאָה בְּטֶרֶם נָבוֹא לְהִתְבּוֹנֵן בְּמֹשֶׁה עוֹלֶה אֶל הַר נְבוֹ. בְּעֵין הַלֵּב נִרְאֶה אֶת מֹשֶׁה הַנָּבִיא בְּעָזְבוֹ אֶת הַקָּהָל וּבַעֲלוֹתוֹ. הֵם זָרְקוּ עָפָר עַל רָאשֵׁיהֶם וְקִינָתָם עָלְתָה הַשָּׁמַיְמָה. וְהוּא הָיָה עוֹלֶה מְעַט וּמַבִּיט לַאֲחוֹרָיו, בְּעוֹד עֵינָיו מוֹרִידוֹת דְּמָעוֹת כְּגֶשֶׁם. וְהָיָה עוֹלֶה מְעַט וּמַבִּיט לַאֲחוֹרָיו, דּוֹמֶה לְאֵם שֶׁיֵּשׁ לָהּ יוֹנְקִים הַסּוֹבְבִים עַל הֱיוֹתָהּ נֶעְדֶּרֶת. וְהָיָה עוֹלֶה מְעַט וּמַבִּיט לַאֲחוֹרָיו וּבוֹכֶה וְאוֹמֵר: "אוֹי לָכֶם, הוֹי קָהָל." וְהָיָה עוֹלֶה מְעַט וּמַבִּיט לַאֲחוֹרָיו, וְרוּחוֹ הָיְתָה מְעֻנָּה מִבְּכִיּוֹ הַגָּדוֹל.');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (322,'V','10','מימר על וימת שם משה',5000101,'מה הוה יאי מעמי נביה רבה משה מוכח לכל קהלה ואמר לון סגי מכן ממרין הויכון עם יה בחיי ואף כי אחרי מותי תהונו רב מכן שירתה דקרית ואציתו לי שומיה ושמעת ארעה מימרי פמי כן אתה עבד עליך תצית ותשמע למלי אה קהלה דנגדת ועמה דפרקת אה קהלה דקדש ועמה דאתסגל לא יאבד כשרני לגוך לעלם אה עמה דאתפרק מן מצר ביד ] ר [ מה לא ] י [ אבד עובדי ] ע [ מך בתר ] מ [ ו ] ת [ י כיי ] אזל [ בשבילה ] דאדם הלך [ בה ] ו [ לבי ] מעיק [ עליך ] כיי מר [ ך ] עבדך על [ יון על כל גועיה הטר הן תתהפך ותהי לרע כלה את אתקרית מלך וכהן וגוי קדש אלין עקובהתה ממחקים בידך הרגריזים ביתה דאלה דאתחמדת אסק לידה אדלא מותי אה יהושע נגדך לידה ואלעזר הכהן משמש עליו ומקרב כל הדה בידך יסטי ורחותה מנך תתכסי ובשבילה דנחש תלכון מה בי אעבד ויום מותי אמטי מה בי אעבד אמר נביה רבה משה וקרבי נציע בפרי דאכלנה אדם ויומי רחותה דאלה מכסיה בזבן ליתי שקיח לגוה','How appropriate to see the great prophet Moses admonishing all the 
congregation. He said to them more than that: “You have been deﬁant toward the 
Lord (Deut. 31:27) during my life, how much more, then, afer my death (ibid.) – 
you will be even more so. While I uttered the song heaven gave ear and earth lis-
tened to the words of my mouth, thus it is appropriate for you to lend an ear and 
listen to my words. O congregation that I led, and people that I delivered. O holy 
congregation and chosen people, let my glory never perish (from) among you. O 
people who was delivered from Egypt deﬁantly, let not my exploit perish (from) 
among you afer my death. Indeed, I am taking the path in which Adam went 
and my heart disturbs (me because) of you. Indeed, your Master set you high 
[above all nations (Deut. 26:19). Beware lest you be reversed to become lesser 
than any. You have been called ‘king’ and ‘priest’ and ‘holy nation’. These appel-
lations will be blotted out by your own hands. Mount Gerizim, the House of God, 
which I have desired to climb before my death, behold, Joshua will lead you 
towards it. Eleazar the priest will minister upon it and make oﬀerings. All this 
will stray through your own hand, and Favor will be concealed from you, and 
you will walk on the path of the serpent. What can I do when the day of my 
death has arrived? What can I do”, said the great prophet Moses, “and my battle 
is lost through the fruit that Adam has eaten, and the days of the Favor of God 
will be concealed in the time when I will not exist in it.”]','כמה ראוי לראות את משה הנביא הגדול מוכיח את כל הקהל. עוד אמר להם: "אַתֶּם הַמֹּרִים הֱיִיתֶם עִם יְהוָה (דברים לא,כז) בחיי, וְאַף כִּי אַחֲרֵי מוֹתִי (שם) – עוד תוסיפו לכך. בעת שנשאתי את השירה האזין שמים והאזינה ארץ לדברי פי, לכן ראוי שתטו אוזן ותשמעו לדברי. הו קהל שהנהגתי, ועם שגאלתי. הו קהל קדוש ועם נבחר, אל תיעלם כבודי מביניכם. הו עם שיצא ממצרים ביד רמה, אל ייאבד מעשי מביניכם לאחר מותי. הנה אני הולך בדרך שהלך בה אדם ולבי דואג עליכם. אכן, אדונכם נתנכם עֶלְיוֹן עַל כָּל הַגּוֹיִם (דברים כו,יט). היזהרו פן תתהפכו ותהיו פחותים מכל אחד. נקראתם ''מלך'' ו''כוהן'' ו''גוי קדוש''. כינויים אלה יימחקו בידיכם אתם. הר גריזים, בית האלוהים, שנכספתי לעלות עליו לפני מותי, הנה יהושע יוליך אתכם אליו. אלעזר הכוהן ישרת עליו ויקריב קרבנות. כל זה יסטה בידיכם אתם, והרצון יסתר מכם, ותלכו בדרך הנחש. מה אוכל לעשות כאשר הגיע יום מותי? מה אוכל לעשות", אמר משה הנביא הגדול, "ומלחמתי אבודה בגלל הפרי שאכל אדם, וימי רצון האל יסתרו בזמן שלא אהיה עוד בתוכם."');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (323,'V','18','מימר על וימת שם משה',5000181,'אה נשיאי שבטיה אתון ארשיה הן סטת תחומיכון בניאנה מדרי אה דיאניה לא תסבון אפים הנארו מה יתעבד בסהדי שקרה אה ספריה הנארו ואלפו כל קהלה גזריה ותרוהתה ופקודיה ודיניה וכל מן לה דרגה יתב עליה לא ייחת מנה באשפו רבה סלק אנה אל טור נבא לא תסכו דאני נחת מנה חסילה הי מני מיחת עד לעלם ליתי מפיס עליכון כדו עתיד אנה בקבורתי וחורן לא יפרקני גרשם ואליעזר תרי בניה דמני אימנו דו שלם מני עד לעלם ותרי עיניה קדישיה עגלין קהלה ודמעיו הך שהקין נחתין דו לא הוה בכי על גרמה אלא עליהון דו ידע דאנון סטין','“O princes of the tribes, you are the foundations. If your boundaries are 
altered, the building is scattered. O judges, do not show partiality. Remember 
what will be done to lying witnesses. O teachers, remember and teach to all the 
congregation the decrees and the laws and the commandments and the precepts. 
Let everyone who has a rank maintain it and not descend from it with great con-
tempt. I go up to Mount Nebo. Do not expect that I come down from it. It is pre-
cluded for me to ever descend. I do not entreat for you now – I am about to be 
buried, and no other will redeem me. Gershom and Eliezer, my own two sons, 
believe that my farewell is irreversible.” The two holy eyes watched the congre-
gation while tears descend like brooks. He was not weeping for himself but for 
them, since he knew that they would stray.','"הוֹי שָׂרֵי הַשְּׁבָטִים, אַתֶּם הַיְסוֹדוֹת. אִם גְּבוּלֵיכֶם יְשֻׁנּוּ, הַבִּנְיָן יִתְפַּזֵּר. הוֹי שׁוֹפְטִים, אַל תַּכִּירוּ פָנִים. זִכְרוּ מַה יֵּעָשֶׂה לְעֵדֵי שֶׁקֶר. הוֹי מְלַמְּדִים, זִכְרוּ וְלַמְּדוּ לְכָל הַקָּהָל אֶת הַחֻקִּים וְאֶת הַמִּשְׁפָּטִים וְאֶת הַמִּצְוֹת וְאֶת הַפִּקּוּדִים. כָּל מִי שֶׁיֵּשׁ לוֹ מַעֲמָד יַחֲזִיק בּוֹ וְלֹא יֵרֵד מִמֶּנּוּ בְּגָדוֹל בִּזָּיוֹן. אֲנִי עוֹלֶה אֶל הַר נְבוֹ. אַל תְּצַפּוּ שֶׁאֵרֵד מִמֶּנּוּ. נִמְנַע מִמֶּנִּי לָרֶדֶת עוֹד לְעוֹלָם. אֵינִי מִתְחַנֵּן בַּעַדְכֶם עַתָּה – אֲנִי עוֹמֵד לְהִקָּבֵר, וְלֹא יִגְאַל אוֹתִי אַחֵר. גֵּרְשֹׁם וֶאֱלִיעֶזֶר, שְׁנֵי בָּנַי, דְּעוּ כִּי פְּרֵדָתִי אֵינָהּ הֲפִיכָה." שְׁתֵּי הָעֵינַיִם הַקְּדוֹשׁוֹת צָפוּ בַּקָּהָל בְּעוֹד הַדְּמָעוֹת יוֹרְדוֹת כִּנְחָלִים. לֹא עַל עַצְמוֹ בָּכָה אֶלָּא עֲלֵיהֶם, שֶׁכֵּן יָדַע כִּי יִתְעוּ.');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (324,'V','27','מימר על וימת שם משה',5000271,'אשתה אוקרת יתה שבעה זבנין ארש מה דאוקרת יתה כד בא לטור חורב בשרוי נביותה מגו ס }} י {{ נ » י « ה אזדעק מן אשתה וחזה תמח חיול לית כותה אילן נשיש ואשתה אכלה וסניה ליתה מתוקד ואזדעק בצפר יומה תליתה ברבו רבה וטור סיני עשן כלו מפני אשר ירד יהוה עליו באש כד אתקרא מן מרה דרס ברגליו לגוה והות כתיה כות טלה שלום יהוה עליו ואשתה עורי לגו משכנה אוקרת יתה יומה דאקרב קרבנה תלמוד לאהרן וארבעתי בניו ותצא אש מלפני יה ותאכל על המזבח את העלה ואת החלבים וכד הוה קעם קבלה אמר מלי תשבחן לעבוד גוני תמחיה יתרבי לעלם דן נביה קדישה דאכל מותרי אשתה וצלותה טפת אשתה כמד כתב ויתפלל משה אל יה ותשקע האש אשתה אוקדת דבביו כמה דאמר ואש יצאה מאת יה ותאכל את חמשים ומאת איש מקריבי הקטרת יתרבי לעלם דן נביה מהימנה דכל אהן אתעבד בגללה ולית אנש יסבע מדכרה לעלם','The Fire honored him seven times: (1) At ﬁrst in how it honored him 
when he came to Mount Horeb at the beginning of his prophethood. From within 
the bush he was called, from the ﬁre, and he saw a mighty wonder – there is 
none like it: a humble tree and a devouring ﬁre (Exod. 24:17), and the bush was 
not consumed (Exod. 3:2); (2) he was called on the morning of the third day in 
great majesty, Mount Sinai was all in smoke, for the Lord descended upon it in ﬁre 
(Exod. 19:18); (3) when he was called by his Master, he trod with his feet in it, 
and it was under him like dew. The Lord’s peace upon him; (4) the ﬁre honored 
him again in the Sanctuary on the day when the sacriﬁce was oﬀered, a lesson to 
Aaron and his four sons: And ﬁre came forth from before the Lord and consumed 
the burnt oﬀering and the fat upon the altar (Lev. 9:24); (5) and when he was 
standing in front of it, he said words of praise to the Maker of many kinds of 
wonders. Exalted be this holy prophet, who has eaten that lef behind by the ﬁre; 
(6) and his prayer extinguished the ﬁre, as He wrote: And Moses prayed to the 
Lord and the ﬁre died out (Num. 11:2); (7) the ﬁre consumed his enemies, as He 
said: And ﬁre came forth from the Lord, and consumed the two hundred and ﬁfy 
men oﬀering the incense (Num. 16:35). Exalted be this faithful prophet forever, 
because of whom all this has been done. None is sated of remembering him.','האש כיבדה אותו שבע פעמים: (1) בראשונה, כיצד כיבדתו כאשר בא אל הר חורב בראשית נבואתו. מתוך הסנה נקרא, מתוך האש, וראה מופת עצום – אין כמוהו: עץ שפל ואש אוכלת (שמות כד,יז), והסנה איננו אוכל (שמות ג,ב). (2) נקרא בבוקר היום השלישי בהדר גדול; הר סיני עשן כולו, כי ירד עליו ה'' באש (שמות יט,יח). (3) כאשר נקרא על ידי אדונו, דרך ברגליו בתוכה, והיתה תחתיו כטל. שלום ה'' עליו. (4) האש כיבדתו שנית במשכן, ביום הקרבת הקרבן, מוסר לאהרן ולארבעת בניו: ותצא אש מלפני ה'' ותאכל על המזבח את העולה ואת החלבים (ויקרא ט,כד). (5) וכאשר עמד לפניה, אמר דברי שבח ליוצר מיני מופתים רבים. מרומם יהיה נביא קדוש זה, אשר אכל את שהותירה האש. (6) ותפילתו כיבתה את האש, כפי שכתב: ויתפלל משה אל ה'' ותשקע האש (במדבר יא,ב). (7) האש אכלה את אויביו, כפי שנאמר: ותצא אש מאת ה'' ותאכל את החמישים ומאתים איש מקריבי הקטרת (במדבר טז,לה). מרומם יהיה נביא נאמן זה לעולם, אשר בזכותו נעשו כל אלה. אין שובע לזכרו.');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (325,'V','4','מימר על וימת שם משה',5000041,NULL,'The Sea too was proclaiming with a loud voice saying: “He who dried me 
up with his staﬀ, far be it that death should approach him.” The Fire said: “I was 
with my ﬂames to the heart of heaven at the day of Horeb, and when God called 
him, he trod on me with his feet, and I was to him like dew, and he was not 
harmed. How could I not pray on his behalf: ‘Let death not approach him?’” The 
Cloud said: “I covered his body on the top of the Mountain six days, and by me 
the Master of the world came to him, and (abiding) in me he saw the pattern of 
the Sanctuary. Therefore I beg: ‘Let death not come to him.’”','גם הים הכריז בקול גדול ואמר: "מי שייבש אותי במטהו, חלילה שיקרבנו המוות." האש אמרה: "הייתי עם להבותיי עד לב השמים ביום חורב, וכאשר קרא אליו האל, דרך עלי ברגליו, והייתי לו כטל, ולא ניזוק. כיצד לא אתפלל בעדו: ''אל יקרבנו המוות?''" הענן אמר: "כיסיתי את גופו בראש ההר שישה ימים, ובאמצעותי בא אדון העולם אליו, ובתוכי ראה את תבנית המשכן. לכן אני מתחנן: ''אל יקרבנו המוות.''"');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (326,'V','37','מימר על וימת שם משה',5000371,'אדכירים לטב עד לעלם זכאי עלמה ארשי זכותה אברהם ויצחק ויעקב דמוכי מערת המכפלה דכל צלו בשמון מתקבלה אדכיר לטב עד לעלם יוסף הצדיק בן פרת הדמוך בחלקת השדה אדכיר לטב עד לעלם הנביא הצדיק הנאמן משה שליח אלהים ומהימן אלהותה ובר ביתה ולבוש קרן עורה וספרון דחייה ומקבל תרי לוחיה ומהימן כסיהתה וגליהתה אשר פה אל פה דברת בו במראה ולא בחידות ותמונת יה יביט וגלית לו שמך הגדול שלום יהוה עליו ועל אבהתיו הטהורים אדכירים לטב עד לעלם שמשי משכן קדשך אהרן ואלעזר ואיתמר ופינחס אדכירים לטב עד לעלם יהושע וכלב והשבעים הזקנים ברוך אלהינו לעולם וברוך שמו לעולם לית אלה אלא אחד','Of blessed memory be to eternity the righteous of the world, the origin of 
righteousness, Abraham, Isaac, and Jacob, these who lie in the cave of Mach-
pelah, for every prayer (said) in their name is received. Of blessed memory be to 
eternity Joseph the righteous, the son of abundance (Gen. 49:22), who lies in the 
Piece of Land (Gen. 33:19). Of blessed memory be to eternity the just and faithful 
prophet Moses, the messenger of God and entrusted by Divinity, and son of His 
House, who wears the ray of light, the teacher of the living ones, the receiver of 
the two tablets, entrusted with the Concealed and the Overt, with whom I spoke 
mouth to mouth, plainly and not in riddles, and he beholds the likeness of the 
Lord (Num. 12:8). You revealed to him Your Great Name. The Lord’s peace be on 
him and on his pure ancestors. Of blessed memory be to eternity the servants of 
Your Holy Sanctuary, Aaron and Eleazar and Ithamar and Phinehas. Of blessed 
memory be to eternity Joshua and Caleb and the seventy Elders. Blessed be our 
God and blessed be His Name to eternity. There is no god but One.','יהא זכרם בָּרוּךְ לנצח לצדיקי עולם, שורש הצדקה: אברהם, יצחק ויעקב, השוכנים במערת המכפלה, שכל תפילה הנאמרת בשמם מתקבלת. יהא זכרו בָּרוּךְ לנצח ליוסף הצדיק, "בֶּן פֹּרָת" (בראשית מט,כב), השוכן ב"חֶלְקַת הַשָּׂדֶה" (בראשית לג,יט). יהא זכרו בָּרוּךְ לנצח למשה הנביא הצדיק והנאמן, שליח האל ונאמן האלוהות ובן ביתו, עוטה קרן האור, מורה החיים, מקבל שני הלוחות, נאמן הנסתר והנגלה, "אֲשֶׁר אֲדַבֶּר-בּוֹ פֶּה אֶל-פֶּה, מַרְאֶה וְלֹא בְחִידֹת, וּתְמֻנַת ה'' יַבִּיט" (במדבר יב,ח). גילית לו את שמך הגדול. שלום ה'' עליו ועל אבותיו הטהורים. יהא זכרם בָּרוּךְ לנצח לעבדי מקדשך הקדוש: אהרן, אלעזר, איתמר ופינחס. יהא זכרם בָּרוּךְ לנצח ליהושע ולכלב ולשבעים הזקנים. בָּרוּךְ אלוהינו וּבָרוּךְ שמו לנצח. אין אלוה כי אם אחד.');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (327,'V','17','מימר על וימת שם משה',5000171,'אה כל בית לוי טרו קדושכון וחזו מה תעבד פנותה עם בניה','“O, all the House of Levi, keep your holiness and see what Disfavor will 
do to the sons.”','"הוֹי, כָּל בֵּית לֵוִי, שִׁמְרוּ אֶת קְדֻשַּׁתְכֶם וּרְאוּ מַה תַּעֲשֶׂה הַחֵרְפָּה לַבָּנִים."');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (328,'V','29','מימר על וימת שם משה',5000291,'יקיר הוא צפרה דטור סיני צפר יומה תליתה דבה הגלת חילין וגבוראן ויסדין ומלאכים וקלין וברקין ולפידין ואש להבה עד לבב שומיה וכן עננה דאנן בדכרה בגלל משה אישה כלל הר סיני הך פרכה ומנה זעק למשה וסלק ברבו רבה ושמעו ממלל אלה למשה ומשה יגיבה תמן אוקרה עננה כד אתא בה אלה ואשמע קלה קרי אנכי יה אלהיך עננה כסתה כמה דאמר ויכסהו הענן ששת ימים ועוד אטל עליו עננה זבן דאמר לה אלה כד אמר הריאני נא את כבודך הגיבה במימרה והיה בעבר כבודי עד מימרה ושכתי כפי עליך עד עברי וגבוראתה סמכו יתה ומלאכיה נפשו לה וכן כבודה נפק לזימונה ומרה אתא בעננה לתמן ואוקרה כמה דאמר וירד יהוה בענן ויתיצב עמו שם לא אמטה לאהן אתרה אנש מכל בני אדם אלא משה ברה דעמרם','Glorious the morning of Mount Sinai, the morning of the third day, in 
which were revealed hosts and powers and fundaments and angels and thun-
ders and lightnings and torches and ﬁre blazing to the heart of heaven (Deut. 
4:11). (4) And also the cloud we are dealing with, by reason of Moses the Man, 
crowned Mount Sinai like a curtain, and from within (God) called Moses, and he 
went up in great majesty. And (the congregation) heard the speech of God to 
Moses, and Moses answering Him. Then the cloud honored him, when God came 
and made heard His voice proclaiming: I am the Lord your God (Exod. 20:2). The 
cloud covered him as He spoke: And the cloud covered it six days (Exod. 24:16). (5) 
Also the cloud shadowed him when God spoke to him. When he said: Show me 
Your glory (Exod. 33:18), God answered him with His speech: While my glory 
passes by, until his saying: I will cover you with my hand until I have passed by 
(Exod. 33:22). The Powers supported him, and the angels relieved him, (6) and 
also Glory came to meet him and his Master came there in the cloud and honored 
him, as He said: And the Lord descended in the cloud and stood with him there 
(Exod. 34:5). None reached this place out of all the sons of Adam except Moses, 
the son of Amram.','מפואר בוקרו של הר סיני, בוקר היום השלישי, שבו נגלו צבאות וכוחות ויסודות ומלאכים ורעמים וברקים ולפידים ואש בוערת עד לב השמים (דברים ד,יא). (4) וגם הענן שאנו עוסקים בו, בזכות משה האיש, עטר את הר סיני כווילון, ומתוכו קרא אלוהים למשה, ועלה בהדר גדול. ושמעו את דבר אלוהים אל משה, ומשה עונה אותו. אז כיבדו הענן, כאשר בא אלוהים והשמיע את קולו וקרא: אנכי ה'' אלוהיך (שמות כ,ב). הענן כיסהו כדבּרו: ויכס הענן את ההר ששת ימים (שמות כד,טז). (5) וגם הענן הצל עליו בדבּר אלוהים אליו. כאשר אמר: הראני נא את כבודך (שמות לג,יח), ענהו אלוהים בדברו: בעבור כבודי, עד אמרו: ושמתי כפי עליך עד עברי (שמות לג,כב). הכוחות סמכוהו והמלאכים הקלו עליו. (6) וגם הכבוד יצא לקראתו, ואדונו בא שם בענן וכיבדו, כפי שנאמר: וירד ה'' בענן ויתיצב עמו שם (שמות לד,ה). לא הגיע למקום הזה אף אחד מכל בני האדם, זולתי משה בן עמרם.');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (329,'V','30a','מימר על וימת שם משה',5000302,'וכד עבד משה נביה משכנה כסתה עננה כמה דאמר ויכס הענן את אהל מועד וישכן הענן על המשכן ובזבן מטלה יאמר קומה ובזבן מקרה יאמר שובה כהדה רבותה מן עמה רבו לחילה דלית לה דמו האן הך משה ומן מדמי למשה נביא לא קם כותה ולא יקום לעלם עננה כסה גויתה ובדילה אתעבד משכנה','(7) When Moses the prophet made the Sanctuary, the cloud covered it, 
as He said: The cloud covered the tent of meeting (Exod. 40:34), the cloud stayed 
over the Sanctuary (Num. 9:18). At the time for departure it was said: Arise (Num. 
10:35), and at the time of rest it was said: Return (Num. 10:36). Who saw such a 
majesty? Greatness to the Mighty One who has no image! Where is there anyone 
like Moses and who resembles Moses, a prophet like whom none has arisen and 
will never arise. The cloud covered his body, and for his sake the Sanctuary was 
made.','(7) כאשר עשה משה הנביא את המשכן, כיסהו הענן, כפי שנאמר: ויכס הענן את אוהל מועד (שמות מ,לד), הענן שכן על המשכן (במדבר ט,יח). בעת הנסיעה נאמר: קומה (במדבר י,לה), ובעת החנייה נאמר: שובה (במדבר י,לו). מי ראה הדר כזה? גדולה לגבורה שאין לה צורה! היכן יש מי כמשה ומי דומה למשה, נביא שלא קם כמוהו ולא יקום לעולם. הענן כיסה את גופו, ובזכותו נעשה המשכן.');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (330,'V','1','מימר על וימת שם משה',5000011,'מלין רמין עד מותר אנן אתין למימר מן דבה בוננו יצית וישמע למליו רב הו ממללה דאנן אמרים דו מבלד אמורה ומ } ש {› ת ‹ מע שמועה קמיכון דן ממללה יתמר דו ממלל טב אה טובי אמורה ואה טובי כל שמועיה אה שמועיה אציתו ואנדו עניניכון למשמע אלין מליה נעפל בדכרן גלגי משה ברה דעמרם דלא קם כותה ולא יקום לעלם חכם בראשית הך אתת ועבר על יום נקם האן הך משה ומן מתשקח כות משה דאימנה מרה על ] כ [ סיאתה ] ועל גל [ יאתה','Exceedingly great words we come to say: let the one who has insight 
listen and hear the words. Great is the statement that we say, for it frightens the 
speaker and startles the listener. In front of you this statement will be said, for it 
is a good statement. O, happy the speaker! O, happy all the listeners! O listeners, 
listen and pay attention to hear these words. Let us begin with mention of the 
praises of Moses, the son of Amram, like whom none has arisen and will never 
arise. He knew how בראשיתhappened, and went on to .יום נקםWhere is there 
anyone like Moses, and who is like Moses, whom his Master appointed with the 
Concealed and the Overt.','דְּבָרִים נִשְׂגָּבִים מְאֹד בָּאנוּ לוֹמַר: יִשְׁמַע וְיַקְשִׁיב בַּעַל הַתְּבוּנָה. גָּדוֹל הַדָּבָר שֶׁאָנוּ אוֹמְרִים, שֶׁכֵּן הוּא מַחֲרִיד אֶת הַמְדַבֵּר וּמַפְחִיד אֶת הַשּׁוֹמֵעַ. לְפָנֶיךָ יֵאָמֵר הַדָּבָר הַזֶּה, כִּי דָּבָר טוֹב הוּא. אַשְׁרֵי הַמְדַבֵּר! אַשְׁרֵי כָּל הַשּׁוֹמְעִים! שׁוֹמְעִים, שִׁמְעוּ וְהַטּוּ אֹזֶן לִשְׁמֹעַ דְּבָרִים אֵלֶּה. נָחֵל בְּהַזְכָּרַת שְׁבָחָיו שֶׁל מֹשֶׁה בֶּן עַמְרָם, אֲשֶׁר לֹא קָם כָּמוֹהוּ וְלֹא יָקוּם לְעוֹלָם. הוּא יָדַע כֵּיצַד אֵרַע בְּרֵאשִׁית, וְהָלַךְ עַד יוֹם נָקָם. הֵיכָן יֵשׁ מִי כְּמֹשֶׁה, וּמִי הוּא כְּמֹשֶׁה, אֲשֶׁר אֲדוֹנוֹ הִפְקִידוֹ עַל הַנִּסְתָּר וְהַנִּגְלֶה.');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (331,'V','16','מימר על וימת שם משה',5000161,'וצפה אל יהושע תלמידה ובכה ואמר לה שלם עליך לעלם חזק ואמץ דאתה נגד שת מון דאלף זרע אברהם ונוף יצחק ושבטי יעקב אתהו דתביא עמה אדן לארעה דאשתבע יהוה לזכאי עלמה דו יהבנה לבניון ויה הוא ההלך לפניך והוא יהיה עמך ומן דאלה עמה לית כלום מכה לה אל תירא ואל תחת חתמת ממללה עם יהושע כי מן דאלה עמה ממן הו דחל','He looked at Joshua his disciple and wept and said to him: “Peace to you 
forever. Be strong and resolute (Deut. 31:23), for you will lead six hundred thou-
sand descendants of Abraham, oﬀshoots of Isaac, tribes of Jacob. It is you who 
will bring this people to the land that the Lord swore to the righteous of the 
world to give to their children. And the Lord Himself will go before you. He will be 
with you (Deut. 31:8), and the one who has God with him – nothing aﬄicts him. 
Fear not and be not dismayed (ibid.).” The sealing of the speech with Joshua: 
“The one who has God with him, of whom is he afraid?”','הביט על יהושע תלמידו ובכה ואמר לו: "שלום לך לעולם. חזק ואמץ (דברים לא,כג), כי אתה תנהיג שש מאות אלף צאצאי אברהם, ענפי יצחק, שבטי יעקב. אתה הוא שיביא את העם הזה אל הארץ אשר נשבע ה'' לצדיקי העולם לתתה לבניהם. וה'' עצמו ילך לפניך. הוא יהיה עמך (דברים לא,ח), ואשר האל עמו – אין דבר מציק לו. אל תירא ואל תחת (שם)." חתימת הדברים אל יהושע: "אשר האל עמו – ממי יירא?"');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (332,'V','36','מימר על וימת שם משה',5000361,'ויהושע בן נון תלמיד נביה רבה משה רמת מיתוביתה בעיני קהל ישראל ויהושע בן נון מלא רוח חכמה כי סמך משה את ידו עליו בכן אסתקף בעיני בני ישראל ושמעו מנה ועבדו כמד פקד יהוה ית משה יתרבי לעלם משה ברה דעמרם דלא ישבע אנש מן דכרה לעלם יתרבי לעלם משה ברה דעמרם דאתוקר ביד אלה בחייו ובמותה כתב ארהותה על מימר יהוה כתבה ועל מימרה אלפה לכל ישראל כמה דאמר ולמדה את בני ישראל שימה בפיהם וכתב עורי על עקב הדה ארהותה דקבלה ולא קם עוד נביא בישראל כמשה לא קעם ולא יקום לעלם מן עבד סימנים הך מה עבד משה לעיני כל ישראל תורה צוה לנו משה ברה דעמרם שם אלה על רישה ושם משה על עקבה','Joshua bin Nun, the disciple of the great prophet Moses, his rank was 
raised in the eyes of the congregation of Israel: And Joshua the son of Nun was 
full of the spirit of wisdom, for Moses had laid his hands upon him (Deut. 34:9). By 
this he was exalted, and they obeyed him and did as the Lord commanded 
Moses. Exalted be Moses the son of Amram forever – nobody will ever grow tired 
of his memory. Exalted be Moses the son of Amram forever, who was honored by 
God in his life as well as in his death. He wrote the Torah. According to the word 
of the Lord he wrote it, and according to the word of the Lord he taught it to all 
Israel, as He said: And teach it to the people of Israel; put it in their mouths (Deut. 
31:19). And he also wrote at the end of the Torah which he received: And there 
has not arisen a prophet since in Israel like Moses (Deut. 34:10) – has not arisen 
and will never arise. Who performed wonders like those Moses performed in the 
sight of all Israel? (Deut. 34:12) Moses the son of Amram commanded us a law – 
the name of God is at its beginning and the name of Moses at its end.','יהושע בן נון, תלמידו של משה הנביא הגדול, מעלתו הוּרמה בעיני עדת ישראל: "וִיהוֹשֻׁעַ בִּן-נוּן מָלֵא רוּחַ חָכְמָה, כִּי-סָמַךְ מֹשֶׁה אֶת-יָדָיו עָלָיו" (דברים לד,ט). בזאת נתעלה, ושמעו לו ועשו כאשר ציווה ה'' את משה. יתעלה משה בן עמרם לעולם – לא יִלאה אדם לעולם מזכרו. יתעלה משה בן עמרם לעולם, אשר נכבד על ידי האל בחייו וגם במותו. הוא כתב את התורה. על פי דבר ה'' כתבה, ועל פי דבר ה'' לימדה לכל ישראל, כפי שאמר: "וְלַמְּדָהּ אֶת-בְּנֵי יִשְׂרָאֵל, שִׂימָהּ בְּפִיהֶם" (דברים לא,יט). וכן כתב בסוף התורה שקיבל: "וְלֹא-קָם נָבִיא עוֹד בְּיִשְׂרָאֵל כְּמֹשֶׁה" (דברים לד,י) – לא קם ולא יקום. מי עשה נפלאות כאשר עשה משה לעיני כל ישראל? (דברים לד,יב). משה בן עמרם ציווה לנו תורה – שם האל בראשיתה ושם משה בסופה.');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (333,'V','3','מימר על וימת שם משה',5000031,'ובתר כן הבלדו כל בוראיה שריר כד שמעו מרון ימלל לנביה רבה משה אהן ממללה גבוראתה דדער עמון בטור סיני צבעין לאלה הן לא יקרב לה מותה חמשתי ספריה וכל גזירהתה דלגון שאלין מרון הן לא יקרב לה מותה שמה דלבש יתה על רישה דט ס › י ‹ ני \ שאל מרה הן לא יקרבנה מותה אלאף אמרת בארכנו על דדיו חסלה חסלה הן ייתי לה מו אנה במניאן חדה ולית אלה אלא אחד ולא נביא אלא אחד אלאף אמרת וכרזת בכסי חסלה הן יקרב לידה מותה אלאף אמרת ושאלת בדילה וזעקת קדם ברואה הן לא יקרב לה מותה לבאת כרזת ואמרת בדילה בשיאל לברוה הן לא יקרב לה מותה בדיל דכתבי בעקב ארהותה דעל מימר יהוה כתב לעיני כל ישראל כתבי חתמת ארהותה דקבלה והות הך נטור על אוצר על כן אנה שיאלה בדילה טכח לא יקרב לה מותה ולא יכינה נפש היא אמרת וכרזת בדילה אנה חשבני חמשה וכתבה חמשה ספרים ולבש חמשה כתבין ואנון אלהים על כן אנה שאלה לא יקרב לה מותה יות אמרת וכרזת בדילה אף אנה בחשבנה עשרה דאתחכם בה ישראל ועקרי בריתה ופרקנה ועורי רחמיה וריש שמה רבה על כן אנה שאלה בדילה לא יקרב לה מותה מים אמרת וכרזת בדילה אנה ריש שמה ואחר שם אדם ושם אברהם ובשם אבוה השתננת פעמים ובמניאני הוה ציאמה לגו יומיה ולילוהתה הך דאמיר ארבעים יום וארבעים לילה על כן אנה שאלה הן לא יקרב לידה , מותה 4] [ ימה אף הוא כ › ר ‹ ז בקל רם ואמר מן אנגבי באטרה חסלה הן יק לה מותה אשתה אמרת אנה הוית בלהבי עד לבב שומיה יום חורב וכד זעקה אלה דרס לגוי ברגליו והוית לה כות טלה ולא אתנכי הך לא אצלי בדילה הן לא יקרב לידה מותה עננה אמר › אנה ‹ כסית גויתה על ריש טורה אשתה יומין ובי אתא לה מרה דעלמה ובי חזה ית תשבית משכנה על כן אנה שאלה לא ייתי לידה מותה','Afer this all creatures were greatly frightened, when they heard their 
Master speaking to the great prophet Moses this speech. The Powers with which 
he dwelt on Mount Sinai were calling to God: “Let death not approach him.” The 
Five Books and all the precepts they contain were entreating their master: “Let 
death not approach him.” The name with which he was vested on the peak of 
Mount Sinai begged his Master: “Let death not approach him.” Aleph spoke in 
submission on his behalf: “Far be it! Far be it that death should come to him. I 
have the value of one, and there is no god but One, and no prophet but one.” 
Aleph spoke and proclaimed within the Concealed: “Far be it! Let death not 
approach him.” Aleph spoke, begging on his behalf, and called before the 
Creator: “Let death not approach him.” [Lamed proclaimed, speaking a request 
on his behalf to its Creator: “Let death not approach him, because he wrote me at 
the end of the Law; according to the commandment of the Lord he wrote: In the 
sight of all Israel (Deut. 34:12). The letter, myself, is the end of the Law which he 
received and it was like a guard for treasure. Therefore I beg on his behalf, that 
death may not approach him, and will not take his life.” He said, proclaiming on 
his behalf: “I have the value of ﬁve. His Scripture has ﬁve books and he was 
vested with ﬁve letters (which) are: Aleph, Lamed, He, Yod, Mem for .אלהים
Therefore I beg: ‘Let death not approach him.’” Yod said, proclaiming on his 
behalf: “I too have the value of ten, by which Israel was known, the number of 
the elements of Creation and the deliverance, as well as the mercies as well as 
the ﬁrst letter of the Great Name. Therefore I beg on his behalf: ‘Let death not 
approach him.’” Mem said, proclaiming on his behalf: “I am the ﬁrst letter of his 
name, and the last of the name Adam and of the name Abraham; in the name of 
his father I was repeated twice. His fasting during the days and nights was 
according to my number, as it was said: Forty days and forty nights (Exod. 34:28). 
Therefore I beg:] ‘Let death not approach him.’”','לאחר כל זאת חרדו הבריות מאוד כשמעם את אדונם מדבר אל הנביא הגדול משה את הדיבור הזה. הכוחות שבהם שכן בהר סיני קראו אל האל: "אל יקרבנו המוות." חמשת הספרים וכל המצוות שבהם התחננו לפני אדונם: "אל יקרבנו המוות." השם שבו הוא הלביש אותו בראש הר סיני ביקש מאדונו: "אל יקרבנו המוות." האלף דיבר בהכנעה בעדו: "חלילה! חלילה שיבוא אליו המוות. ערכי הוא אחד, ואין אל אלא אחד, ואין נביא אלא אחד." האלף דיבר והכריז מתוך הנסתר: "חלילה! אל יקרבנו המוות." האלף דיבר והתחנן בעדו, וקרא לפני הבורא: "אל יקרבנו המוות." הלמד הכריז ודיבר בקשה בעדו לפני בוראו: "אל יקרבנו המוות, כי הוא כתבני בסוף התורה; על פי ציווי יהוה כתב: לְעֵינֵי כָל-יִשְׂרָאֵל (דברים לד,יב). האות אני, סוף התורה אשר קיבל, והייתי כשומר לאוצר. לכן אני מתחנן בעדו שלא יקרבנו המוות ולא יקח את נפשו." אמר והכריז בעדו: "ערכי הוא חמש. כתובתו חמישה ספרים והוא הולבש בחמש אותיות שהן: אלף, למד, הא, יוד, מם – לשם אלהים. לכן אני מתחנן: ''אל יקרבנו המוות.''" היוד אמר והכריז בעדו: "אף לי ערך עשר, שבו נודע ישראל, מספר יסודות הבריאה והגאולה, וכן הרחמים, וכן האות הראשונה של השם הגדול. לכן אני מתחנן בעדו: ''אל יקרבנו המוות.''" המם אמר והכריז בעדו: "אני האות הראשונה של שמו, והאחרונה של שם אדם ושל שם אברהם; בשם אביו נכתבתי פעמיים. צומותיו בימים ובלילות היו לפי מספרי, כמו שנאמר: אַרְבָּעִים יוֹם וְאַרְבָּעִים לַיְלָה (שמות לד,כח). לכן אני מתחנן: ''אל יקרבנו המוות.''"');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (334,'V','25','מימר על וימת שם משה',5000251,'שומיה אוקרותה שבעה זבנין גלה בשרוי כתבה איך אשתרת בריתה רגם דבביו מן שומיה בברדה דנחת עליון והכה כל בהמהתון וכל אילניון וכל עשב שדיון כבש מרודיה מן שומיה זבן דעבד סימנה דחשכה צלותה המכת מנה מן שומיה מללה אלה מן שומיה ברבו רבה על רישה דטור דסיני כתב ברכת שומיה ונתן מטר ארצך בעתו יורא ומלקוש וגם אציתו לה שומיה זבן דאמר האזינו השמים ואדבר יתרבי לעלם דן מאורה דאניר מן עמרם ויוכבד','Heaven honored him seven times: (1) He revealed at the beginning of his 
Book how Creation began; (2) he stoned his enemies from heaven with the hail 
that descended on them – he aﬄicted their cattle and all their trees and all the 
grass of their ﬁelds; (3) from heaven he subdued the rebels, when he performed 
the wonder of darkness; (4) his prayer lowered manna from heaven; (5) God 
spoke with him from heaven with great majesty on the top of Mount Sinai; (6) he 
wrote the blessing of heaven: He will give the rain for your land in its season, the 
early rain and the later rain (Deut. 11:14); (7) and also heaven gave ear to him at 
the time when he said: Give ear, O heaven, and I will speak (Deut. 32:1). Exalted 
be forever this luminary, who caught alight from Amram and Yochebed.','השמים כיבדוהו שבע פעמים: (1) גילה בתחילת ספרו כיצד החלה הבריאה; (2) סקל את אויביו מן השמים בברד שירד עליהם — הכה את מקניהם ואת כל עציהם ואת כל עשב שדותיהם; (3) מן השמים כנע את המורדים, כאשר עשה את מופת החושך; (4) תפילתו הורידה מן מן השמים; (5) האל דיבר עמו מן השמים בהדר רב בראש הר סיני; (6) כתב את ברכת השמים: וְנָתַתִּי מְטַר אַרְצְכֶם בְּעִתּוֹ יוֹרֶה וּמַלְקוֹשׁ (דברים יא,יד); (7) וגם השמים האזינו לו בעת שאמר: הַאֲזִינוּ הַשָּׁמַיִם וַאֲדַבֵּרָה (דברים לב,א). יתרומם לעולם המאור הזה, שהאיר מעמרם ויוכבד.');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (335,'V','34','מימר על וימת שם משה',5000341,'לית מותה דאהרן מדמיה למותה דמשה אהרן קביר ביד אנשין ומשה קביר בידה דאלה ואנון תלתה טבין אתוקרו במותון יעקב ואהרן ונביה רבה משה זכאה קביר ביד מלך וכהן קביר ביד נביא ומשה קביר ביד אלה רב הוא אילנה דסלק בפרדיס עמרם ומפריו כל דריה זאנין לעלם רב הוא אילנה דאנצב במצרים ואקלע לגו מדברה ואקצץ בטור נבא האן הך משה ומן מדמי למשה נביא דלא קעם קמיו ולא בתרה כותה האן הך משה ומן מדמי למשה שמשה דבארעה ואורה בעללה האן הך משה ומן מדמי למשה אילנה דבארעה וטרפיה ברומה האן הך משה ומן מדמי למשה מעין בארעה ועקרה ברקיעיה האן הך משה ומן מדמי למ תהום בארעה ומתנגד במעונה האן הך משה ומן מדמי למ אורה בארעה ומופע בשומיה האן הך משה ומן מדמי למשה נביא לא אחריו ולא קמיו האן הך משה ומן מדמי למשה דאתיקר בכסיהתה ורבה בגליהתה האן הך משה ומן מדמי למ דאתימן ביד קשטה והוה מלו בכן האן הך משה ומן מדמי למ דיקרה מרה בכל מקומוהתה האן הך משה ומן מדמי למ דבלש ואמטה והגדל בכלה האן הך משה ומן מדמי למ דגלה על ידיו גוני תמחיה האן הך משה ומן מדמי למשה דאתרבה בחייו ובמותו 35] ומשה בן מאה ועשר [ שנה במותו עשרים במצר וששים במדין וארבעים במדברה בסקפן חיול ובכהנה ובנביותה ובצלו ובציאם לא כמעת עיניה ולא ערק רטובה חכמנן מן מימרה לא כמעת עיניה כות עיני כל זכאיה לא כמעת עיניה דו צריך כתיב ארהותה וצפי ארבעתי רבעת עלמה ולא ערק רטובה חכמנן וידענן דו לבש קרן אורה ואניר על צלמה עד יום מותה ולא אטלטל לשנה דו פרוט מלי ארהותה דהוה מלף מקרתה לשת מון דאלפין ובכותה בני ישר תלתין יום ולית בכותה בטלה עד לעלם','The death of Aaron does not resemble the death of Moses. Aaron was 
buried by men and Moses was buried by God. There are three good ones who 
were gloriﬁed in their death: Jacob and Aaron and the great prophet Moses. A 
righteous one is buried by a king, and a priest is buried by a prophet, and Moses 
is buried by God. Great is the tree that grew up in the garden of Amram, and 
from the fruit of which all the generations are fed forever. Great is the tree that 
was planted in Egypt and grew up in the desert and was cut oﬀ on Mount Nebo. 
Where is there anyone like Moses and who resembles Moses, a prophet like 
whom none arose before him or afer him? Where is there anyone like Moses and 
who resembles Moses, the sun which is on earth and its light is in the sky? 
Where is there anyone like Moses and who resembles Moses, the tree which is on 
earth and its branches in heaven? Where is there anyone like Moses and who 
resembles Moses, a fountain on earth, and its origin in heaven. Where is there 
anyone like Moses and who resembles Moses, an abyss on earth that is attracted 
to the Divine Abode. Where is there anyone like Moses and who resembles 
Moses, his light is on earth and it shines in heaven? Where is there anyone like 
Moses and who resembles Moses, a prophet – none afer and before him. Where 
is there anyone like Moses and who resembles Moses, who was honored among 
the Concealed and was exalted in the Overt? Where is there anyone like Moses 
and who resembles Moses, who was entrusted by the True One, and was 
ordained to this? Where is there anyone like Moses and who resembles Moses, 
whom his Master honored in all places? Where is there anyone like Moses and 
who resembles Moses, who sought and reached and was exalted in everything? 
Where is there anyone like Moses and who resembles Moses, by whom many 
kinds of wonders have been revealed? Where is there anyone like Moses and who 
resembles Moses, who was exalted in his life as well as in his death?','מותו של אהרן אינו דומה למותו של משה. אהרן נקבר בידי בני אדם ומשה נקבר בידי האל. שלושה טובים זכו לכבוד במותם: יעקב ואהרן והנביא הגדול משה. צדיק נקבר בידי מלך, וכהן נקבר בידי נביא, ומשה נקבר בידי האל. גדול העץ שצמח בגנו של עמרם, ומפרי תנובתו ניזונות כל הדורות לעולמים. גדול העץ שנשתל במצרים וצמח במדבר ונכרת בהר נבו. היכן יש מי כמשה ומי דומה למשה, נביא שלא קם כמוהו לפניו ולא אחריו? היכן יש מי כמשה ומי דומה למשה, שמש הנמצאת בארץ ואורה בשמים? היכן יש מי כמשה ומי דומה למשה, עץ הנמצא בארץ וענפיו בשמים? היכן יש מי כמשה ומי דומה למשה, מעיין בארץ ומקורו בשמים? היכן יש מי כמשה ומי דומה למשה, תהום בארץ הנמשכת אל מעון האלוהים? היכן יש מי כמשה ומי דומה למשה, אורו בארץ ומאיר בשמים? היכן יש מי כמשה ומי דומה למשה, נביא – לא אחריו ולא לפניו? היכן יש מי כמשה ומי דומה למשה, שנכבד בנסתר ונתרומם בנגלה? היכן יש מי כמשה ומי דומה למשה, שנאמן בידי האמת ונתמנה לכך? היכן יש מי כמשה ומי דומה למשה, שכיבדו אדונו בכל מקום? היכן יש מי כמשה ומי דומה למשה, שבקש והגיע ונתרומם בכל? היכן יש מי כמשה ומי דומה למשה, שעל ידו נגלו פלאים רבים מיני רבים? היכן יש מי כמשה ומי דומה למשה, שנתרומם בחייו וכמו כן במותו?');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (336,'V','15','מימר על וימת שם משה',5000151,'וצפה אל אלעזר והוא יתיב על ימינה ואנשק צלמה ויהב לה שלמה ואמר לה אה ברה דאחי אה ירות כהנתה אתה יתיב בדרג כהנתה דירתה יתה ואת מהימן על משכנה קדישה ועל כל מד יתעבד בה ואתה תניאנתה דאלה ואת מלוא בכן וצפה אל איתמר ואמר לה והו בכי אה ברה דאחי אתה כהן המשחת בשמן קדשה והכנת אתה ואלעזר כמד כתבת ויכהן אלעזר ואיתמר על פני אהרן אביהם שמר כהנתך וכל קדשיה דבידך ושבח לדיאנה דלא נסב אפים וצפה אל פינחס קדישה והוא יתיב על שמאלה ובכה ונשק ימינה דסבל בה ית רמחה ודקר זנוה וזנ › ו ‹ תה ותלה רגזה מעל ישראל ואמר לה אה בר ברה דאחי קנאתך גליה כד תעמי אנש שטי על דרך יהוה הקטלנה כמד עבדת בזמרי וכזבית דאנצירותך גליה לכל דרי עלמה','He looked at Eleazar who was sitting on his right and kissed his face, 
and saluted him and said to him: “O son of my brother, O heir of the priesthood, 
you are sitting in the priestly rank that you inherited and you are entrusted with 
the holy Sanctuary and with all that is done therein. You are second in charge to 
God, and you are appointed to that.” He looked at Ithamar and said to him while 
he was weeping: “O son of my brother, you are a priest; you have been anointed 
with the holy oil, and become priest, you and Eleazar, as I have written: Eleazar 
and Ithamar served as priests in the lifetime of Aaron their father (Num. 3:4). Keep 
your priesthood and all the holy things which are in your hand and praise the 
Judge who is impartial.” He looked at the holy Phinehas who was sitting on his 
lef, and wept and kissed the hand by which he had taken the spear and stabbed 
the fornicator and the harlot and lifed anger from over Israel. He said to him: “O 
son of my brother’s son, your zeal is manifest. When you see a person acting 
foolishly on the path of the Lord, kill him, as you did to Zimri and Cazbit, for 
your devotion is manifest to all the generations of the world.”','הוא הביט על אלעזר שישב לימינו ונישק את פניו, ושאל בשלומו ואמר לו: "הו בן אחי, הו יורש הכהונה, אתה יושב במעלת הכהונה שירשת ואתה מופקד על המקדש הקדוש ועל כל הנעשה בו. אתה משנה לאל, ואתה ממונה על כך." הביט על איתמר ואמר לו בבכייה: "הו בן אחי, אתה כהן; נמשחת בשמן הקדש, ונהיית לכהן, אתה ואלעזר, כאשר כתבתי: ואלעזר ואיתמר כיהנו לפני אהרן אביהם (במדבר ג,ד). שמור את כהנתך ואת כל הקדשים שבידך ושבח את השופט שאינו נושא פנים." הביט על פינחס הקדוש שישב לשמאלו, ובכה ונישק את היד שבה אחז את הרמח ודקר את הזונה ואת המנאפת, והסיר את הזעם מעל ישראל. אמר לו: "הו בן בן אחי, קנאותך גלויה. כאשר תראה אדם הפועל בסכלות בדרך ה'', הרגהו, כאשר עשית לזמרי ולכזבי, כי מסירותך גלויה לכל דורות העולם."');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (337,'V','33','מימר על וימת שם משה',5000331,'עלמין רברבין בין תרין אחין משה ואהרן תרין קדישין אהרן בטור טורה ומשה בטור נבא','Great worlds (distinguish) between two brothers, Moses and Aaron, two 
holy ones. Aaron on the Mountain of Mountains and Moses on Mount Nebo.','עולמות גדולים מפרידים בין שני אחים, משה ואהרן, שני קדושים. אהרן בהר ההרים ומשה בהר נבו.');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (338,'V','2','מימר על וימת שם משה',5000021,'] ומלל יהוה אל משה בקנום יומה הדן דן ממללה הוה בתרח אגן זימונה ומלל יהוה [ אל משה בעצם היום הזה תבכי עניכון כל קהלי ישראל ומלל יהוה אל משה בקנום יומה הדן יצטדון כל לבבי דריה דעתידין לבדורה עלה אל הר עבראי הדן הר נבא ומות תמן כות אהרן תלימך ומות בטור נבא כמד מת אהרן אחוך בטור טורה בפשרון קשטה מרירה שעתה דבה שמע מן מרה אהן ממללה תלנ ] ה [ נביה רבה משה קלה ואמר ] ר [ בותה ] לך אה מר [ י ] אה מ [ ורכה ] אה נצ [ חן ומשבח וסגד למרה ופמה ליתו בטל מן ודי הרבואן רב חילך דיאנה קשיטה דלא נסב אפים לא לזכאי ולא לנביא ולא לכהן','[The Lord spoke to Moses that very day (Deut. 32:48) – this speech was at 
the gate of the Tent of Gathering. The Lord spoke ] to Moses that very day – let 
your eyes weep, all the congregations of Israel. The Lord spoke to Moses that very 
day – let all the hearts of the generations destined for dispersion be frightened. 
Ascend this mountain of the Hebrews, Mount Nebo (v. 49) and die there, like 
Aaron, your brother. Die on Mount Nebo as died Aaron your brother on the Mount 
of Mountains (v. 50) – in just judgement. Bitter was the hour when he heard this 
speech from his Master. The great prophet Moses raised his voice and said: 
“Greatness to You, O my Master, O the enduring, O the victorious.” He was prais-
ing and bowing down to his Master, and his mouth did not cease revealing 
praises: “Great is Your power, the truthful Judge, who is not partial, neither to a 
righteous nor to a prophet or to a priest.”','וַיְדַבֵּר יְהוָה אֶל-מֹשֶׁה בְּעֶצֶם הַיּוֹם הַזֶּה (דברים לב,מח) – דיבור זה היה בפתח אוהל מועד. וַיְדַבֵּר יְהוָה אֶל-מֹשֶׁה בְּעֶצֶם הַיּוֹם הַזֶּה – תבכינה עיניכם, כל קהלות ישראל. וַיְדַבֵּר יְהוָה אֶל-מֹשֶׁה בְּעֶצֶם הַיּוֹם הַזֶּה – יחרדו כל לבבות הדורות העתידים לגלות. עֲלֵה אֶל-הַר הָעֲבָרִים הַזֶּה הַר-נְבוֹ (שם, מט) וָמֻת שָׁם, כְּאַהֲרֹן אָחִיךָ. מות בהר נבו כשם שמת אהרון אחיך בהר ההרים (שם, נ) – בדין צדק. מרה הייתה השעה בה שמע את הדיבור הזה מפי אדונו. הנביא הגדול משה נשא את קולו ואמר: "גדולה לך, אדוני, הנצחי, המנצח." היה משבח ומשתחווה לאדונו, ופיו לא פסק מגלות תהילות: "גדולה גבורתך, השופט האמת, שאינו נושא פנים, לא לצדיק ולא לנביא ולא לכוהן."');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (339,'VI','35','מימר מדבק בשנים והעשרים אות',6000351,'כד חסלת נון מן ממללה עם משה נביה אתת ס וקעמת קמיו ואמרת אה נביה רבה למה לא הוה לי נמי בשרוי ראשי קצי ארהותה מה גלית ליצחק ית מניאני ברבו ואקימת מנה זרע ירת מיתוביתה אלבשתה בשמי פדיון קהלה ואתא האגבו בשמי על מדי ועבדי אלה ארש לכל איקר ובי יתעזר דינה אל דברה ובי יקום אהרן ואנה בפמה יומה דבה יגלי רגזה וקשטה על מה דו וטובה מגדל וכבודה מתחזי וכל מלאכיה חדים ואלה מתנחם וקדשה מתחיל ורחמיה פריסה יומה דבה קהלה מתפרק מן חוביה דרבת עליו','When נhad ﬁnished speaking with Moses the prophet, סcame and stood 
before him and said: “O great prophet, why do I have no share at the beginning 
of the headers of the Qiṣṣīm of the Torah? Did I not reveal to Isaac my number in 
greatness and founded descendants from him to inherit his rank? With my name 
I clothed him – a deliverance to the congregation. And there came a response to 
this in my name. God made me a foundation for all glory. By me, judgement will 
be reversed from its course. By me Aaron will stand, and I will be in his mouth 
on the day when wrath and truth are revealed for what they are. The Good will 
be magniﬁed, Glory will appear and all the angels will be joyful. God will be 
merciful and Holiness will increase. Mercy will be spread forth on the day when 
the congregation are delivered from their sins, which had multiplied upon 
them.”','כאשר סיים נ לדבר עם משה הנביא, בא ס ועמד לפניו ואמר: "הו נביא גדול, מדוע אין לי חלק בראשית ראשי הקיסים של התורה? האם לא גיליתי ליצחק את מספרי בגדולה, ויסדתי ממנו צאצאים שיירשו את מעמדו? בשמי לבשתיו – ישועה לעדה. וּבא מענה לכך בשמי. האלוהים שמני ליסוד לכל הכבוד. על ידי יתהפך הדין ממסלולו. על ידי יעמוד אהרן, ואהיה בפיו ביום שבו ייגלו הזעם והאמת כמות שהם. הטוב יתגדל, הכבוד יופיע וכל המלאכים ישמחו. האלוהים יהיה רחמן והקדושה תגבר. הרחמים יתפרשו ביום שבו תינצל העדה מחטאיה, שרבו עליה."');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (340,'VI','13','מימר מדבק בשנים והעשרים אות',6000131,'עבד לדבביך אתה וליתון רצין בך אהן גזוי אהן לקבל עובדה יהי גזוה ואלה מזדכי מנך בכן טכח תבהת ותאחס על קנומך מן תחמדות לבך ותתנצל מנה בשרוך ולא תהי דבב לאלה תאבד נפשך ואלה ממן בעודנו ליתו מנכי במרדך וארום אתהו המנכי בכן כי לא אתברית לכן ולא אתחילת לדן ולא אתוקרת בדילה עבד יכלותך בזכותך תהי יכל על כלה אתה בר טבים מכור הברזל אתפדו בגוני סימנים רבים וגעזו ים סוף ושמעו קול אלהים ואזינו לה וחזו דבבון אביד טמע בימה ואנון מתפרקין ובישה דאתא בלש מד לית לה קטיל בחילה דאלה ואת › ו ‹ קרו בכתב כהלה חיים מכלל במצוהן מוחין למי יטרון באצבע אלהים כתיב ומן שומיה נחת בתרי לוחי אבניה מן בראשית הקבע ובגוף אורה אתעבד ומפם כתובה אשתמע וקבלה נביא הוה מלוא באהן איקרה מן שרוי מולדה הגלה פרקנה לקהל עבראי כבודה בדילה הגלה למרבהתה מלאכיה הזדמנו בדיל שלמותה כמד אזדמנת סימניה קבלה איקרה אתא למחילנה כמד אתא טובה ואלבשה כליל קדשה הגלה ומשח גביתה אימנותה אתת ושבת לה נימוזים','You are a slave to your enemy, and they are not pleased with you! This is 
the requital for this – the recompense is according to the deed, and thus God is 
exempt from you. Perhaps you will be ashamed and have mercy on yourself and 
(be distant) from the lust of your heart, and save yourself from it by your own 
eﬀort. Do not be an enemy to God, (lest) you destroy yourself. God is enduring in 
His state. He will not be harmed through your rebellion; indeed, it is you who 
will be harmed by this. Indeed, you were not created for this nor were you grown 
for this. You were not honored for the sake of this. Make (every eﬀort) you can to 
be righteous, and (then) you will prevail over all. You are the son of good people 
who were redeemed from the iron furnace by all kinds of great wonders. They 
passed through the Sea of Reeds and heard the voice of God and they gave ear to 
it. They saw their enemy perish, sinking into the sea, while they were saved. The 
wicked one who came seeking what was not (ﬁt for) him – he was slain by the 
power of God. And they were honored with a book wholly of life, made perfect 
with commandments, life-giving to those who keep them. It was written by the 
ﬁnger of God and it descended from heaven in two stone tablets. It was estab-
lished from Creation; it was made from the substance of the Light, and it was 
heard from the mouth of its Writer, and a prophet received it who was worthy of 
this glory. From the beginning of his birth, salvation was revealed for the congre-
gation of the Hebrews. The Glory was revealed for his sake, to elevate him; the 
angels assembled for his perfection, like when the wonders were brought togeth-
er before him. Glory came to strengthen him, like when the Good One came and 
vested him with a crown. Holiness appeared and anointed his body. The Torah 
came and set out laws for him.','אתה עבד לאויבך, והם אינם שבעי רצון ממך! זוהי הגמול על כך – השכר לפי המעשה, ובכך אלוהים פטור ממך. שמא תבוש ותרחם על עצמך ותתרחק מתאוות לבך, ותציל את עצמך ממנה במאמצך אתה. אל תהי אויב לאלוהים, פן תאבד את עצמך. אלוהים קיים בעצמותו. לא ייפגע הוא על ידי מרדך; אכן, אתה הוא שתיפגע על ידי כך. אכן, לא לכך נוצרת ולא לכך גדלת. לא כובדת למענו. עשה כל שביכולתך להיות צדיק, ואז תנצח את הכול. אתה בן אנשים טובים שנגאלו מכור הברזל בכל מיני נפלאות גדולות. הם עברו את ים סוף ושמעו את קול אלוהים והאזינו לו. הם ראו את אויבם אובד, שוקע בים, בעוד הם ניצלו. הרשע שבא לבקש מה שלא היה ראוי לו – נהרג בכוחו של אלוהים. והם כובדו בספר שכולו חיים, מושלם במצוות, מחיה למשמריו. נכתב הוא באצבע אלוהים וירד מן השמים בשני לוחות אבן. הוא נקבע מן הבריאה; נעשה מחומר האור, ונשמע מפי כותבו, ונביא קיבלו שהיה ראוי לכבוד הזה. מראשית לידתו נגלתה ישועה לעדת העברים. הכבוד נגלה למענו כדי לרוממו; המלאכים נאספו לשלמותו, כמו שהנפלאות נקבצו לפניו. הכבוד בא לחזקו, כמו שהטוב בא ועיטרו בכתר. הקדושה נגלתה ומשחה את גופו. התורה באה ופרשה לו את חוקיה.');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (341,'VI','70','מימר מדבק בשנים והעשרים אות',6000701,'שמעו ה הך הי ממללה ממלל מרבי אלופה מה מניאני עביד מניאן שמה דאתברא בה עלמה מה השתננת בתרי שמיה רברביה אהיה יהוה וחתמת שמך אה נביה ובי אתרבה אברהם ושרה ופתחת קמיך כל תרח צניק עד לא יתכסי עליך כלום דאת אתברית לאהן עובדה ואתה מלוא בסגי מנה ועלמה לך אתגלה ובך אתחילו כל דיראיו וכל מד את שאל למרך הוא מגיבך לידה עסרה זבנין אתגלה רגזה ואת שאל למרך בעזרותה','Hear הas it speaks a speech that exalts the one who learns it: “Was not 
my number made the number of the name by which the world was created? Was 
I not repeated in both great names, אהיהand ,יהוהand did I not seal your name, 
O prophet? By me, Abraham and Sarah were made great. I opened before you 
every closed gate, that nothing might be hidden from you. For you were created 
for this deed and you are appointed to more than this. The world was revealed to 
you and by you all its inhabitants were strengthened. All that you ask of your 
Master He consents to. Ten times His wrath was manifested and you asked your 
Master to reverse it.','שמע את ה"א כשהיא מדברת דבר המרומם את מי שלומד אותו: "האם לא נעשה מספרי מספר השם שבו נברא העולם? האם לא נשניתי בשני השמות הגדולים, אהיה ויהוה, ואם לא חתמתי את שמך, הו נביא? על ידי, נעשו אברהם ושרה גדולים. פתחתי לפניך כל שער נעול, כדי שלא יסתתר ממך דבר. כי לצורך מעשה זה נוצרת, ואתה ממונה על יותר מזה. העולם נגלה לך ועל ידך התחזקו כל יושביו. כל אשר תבקש מאדונך הוא מסכים לו. עשר פעמים נגלה חרונו ואתה ביקשת מאדונך להשיבו."');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (342,'VI','71','מימר מדבק בשנים והעשרים אות',6000711,'שרוה זבן דעבדו עגלה וסגדו לה תניאנה כד התאוו תהוה ובלשו בלישה הות בכניזה תליתה כד סלקו לטברה ואמיר לון לא תעלו ולא תלחמו רביעיתה כד סלקו למגשש ית ארעה למחזי טבהתה דבה חמישה זבן דשתלחת נחשיה ונכתו גביאת ישראל השתיתה זבן דיצאת אשתה והוקדת בעמה יקידה בישה שביעיה זבן דפנו בתחמדותון למקים ארש למעזרה למצר תמינה זבן דקעמו למגלי ביש בחזות יהוה תשעיתה זבן דטמאו גזרתה במקרוב ליד זנותה עסירה זבן קרח כד בלש מד ליתו עבד לה תתיקרי ה אמר לה נביה רבה משה חכמת איקרה דבה אתיקרתי בדיל כן עבדת ספרי התורה במניאניך','The ﬁrst, when they made the Calf and worshipped it. The second, when 
they expressed desire and sought something that was bad intent. The third, 
when they went up the mountain and they were told: Do not go up or ﬁght (Deut. 
1:42). The fourth, when they went up to scout the land, to see the good things in 
it. The ﬁfh, when the serpents were sent and they stung the bodies of the Israel-
ites. The sixth, the time when the ﬁre went forth and burnt the people badly. The 
seventh, the time when they deviated in their desire to appoint a leader to take 
them back to Egypt. The eighth, the time when they arose to manifest evil in the 
sight of the Lord. The ninth, the time when they deﬁled circumcision by being in-
volved in fornication. The tenth, the time of Korah, when he requested what was 
not appropriate for him.” “Be gloriﬁed, ,”הthe great prophet Moses said to it. “I 
know the honor by which you were gloriﬁed. For this very reason I made the 
books of the Law in your number.”
This is the end of what I found written before me in the ark of Mårqe, the 
favor of the Lord be upon him, Amen! Blessed be our God forever and blessed be 
His name forever! There is no god but One.
This book has been written for our good master, the honorable and learned 
and insightful, expounding every nice thing with a full heart, Phinehas the son 
of the master of the community, the high priest at Damascus, Ithamar the son of 
Aaron, the son of Ithamar, the son of Aaron, the son of Abi ʿAzzi, the son of 
Phinehas, the son of Eleazar, the son of Netanel, the son of Eleazar, the high 
priests. Let the Lord bless him and favor him with good sons, who will learn all 
that is written in it. Amen, amen.','הראשונה, כשעשו את העגל והשתחוו לו. השנייה, כשהביעו תאווה ובקשו דבר שהיה כוונה רעה. השלישית, כשעלו ההרה ונאמר להם: אל תעלו ואל תילחמו (דברים א,מב). הרביעית, כשעלו לרגל את הארץ, לראות את טובותיה. החמישית, כשנשלחו הנחשים ועקצו את גופות ישראל. השישית, העת שיצאה האש ושרפה את העם קשות. השביעית, העת שסטו בתאוותם למנות מנהיג שיחזירם למצרים. השמינית, העת שקמו לגלות רעה לעיני ה''. התשיעית, העת שטימאו את המילה על ידי שנכרכו בזנות. העשירית, עת קורח, כשתבע מה שלא היה ראוי לו." "תתכבד, ה"א," אמר לה משה הנביא הגדול. "אני יודע את הכבוד שבו נתכבדת. לכן ממש עשיתי את ספרי התורה במספרך."
זה הוא סוף מה שמצאתי כתוב לפני בתיבת מרקה, חסד ה'' עליו, אמן! ברוך אלוהינו לעולם וברוך שמו לעולם! אין אלוה אלא אחד.
ספר זה נכתב לאדוננו הטוב, הנכבד והלמדן והנבון, המפרש כל דבר נאה בלב שלם, פינחס בן ראש הקהילה, הכהן הגדול בדמשק, איתמר בן אהרן, בן איתמר, בן אהרן, בן אבי עזי, בן פינחס, בן אלעזר, בן נתנאל, בן אלעזר, הכהנים הגדולים. יברכהו ה'' ויחננו בבנים טובים, אשר ילמדו את כל הכתוב בו. אמן, אמן.');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (343,'VI','47','מימר מדבק בשנים והעשרים אות',6000471,'אנשה התילפו אנשה אתבוננו ולא תהונו מתנצלים מן דעת דעתה כי לית חיי אנשה אורכות יומיו חיי אנשה אוזפות דעתו אוי לאנש זהי בימים לית לאלה בון נמי יחידי בעותר ייזל וישבקנה אזלת זהותה ולית בידה כלום והן אדבר מנה מקדם מיזלה דו חדי חדו חיולה אתילף חכמתה די ריש כל מהדל מרביה מלוכה בכל דרי עלמה מטי הו בה לאהן דו כשרנה הן בחייו והן במותו לבה דער במעונה עלאה ומנדי לה רחמים דו כים מגלגל רתואן מיה דבה מרבי חייה טוב לבה דיהי מניר בהחכמה בעלה שרי בגנתה תחת אילנים טבים ישתבח נהירה דממלי לידועים רוח החכמה עד יהונו הך מאורין ינירו בעלמה ויסטו ית חשכה אלולי ידועיה לא הוה עלמה מתיטב ולא מתכלל בחסד ירבון בעלמה מסחני דעתה עד תהי ימיהם טבים ומנירים מה טב מה הות ימי זכאי עלמה לא הגלה בון דבר רע לעלם נודי לחילה דאנדה לן כתב קדיש כהלה חיין וברכהן ורחמ','O people, learn! O people, think and do not be emptied of the knowledge 
of His wisdom. For a man’s life does not consist merely of the length of his days. 
A man’s life consists of increasing his own knowledge. Woe to the man who 
rejoices in days in which God has no share! He is happy in wealth, (but) when it 
leaves and forsakes him his joy departs and he has nothing. But if he saved some 
of it before it vanishes, then he is very happy. He has learned wisdom, the 
beginning of all possession, which elevates its possessor throughout all the 
generations of the world. By it he reaches wherever there is success, whether in 
his life or in his death. His heart abides in the Upper Abode, and it brings mercy 
for him, for it is like a sea that shows compassion. The water in it increases life. 
Happy the heart that illumines with wisdom. Its owner dwells in the Garden 
under good trees. Praise be to the Illuminator who ﬁlls the wise with the spirit of 
wisdom, so that they are like luminaries shining in the world and removing the 
dark. If it were not for men of knowledge, the world would not be in (a state of) 
well-being nor crowned with grace. Let those who possess knowledge multiply 
in the world, so that their days may be prosperous and illumining. How good 
were the days of the Righteous of the world! No evil thing was ever wrought in 
them. Let us give thanks to the Powerful one who brought us a holy Scripture, 
wholly of life and blessings and mercies!','עם, למד! עם, חשוב ואל תתרוקן מידיעת חכמתו. שכן חיי האדם אינם תלויים אך ורק באורך ימיו. חיי האדם תלויים בהגדלת ידיעתו. אוי לאדם השמח בימים שאין לאל בהם חלק! הוא שמח בעושר, אך כשהעושר עוזב אותו ומניח אותו — שמחתו חולפת ואין לו דבר. אבל אם חסך ממנו מעט לפני שנעלם, הרי הוא אשרי מאוד. הוא למד חכמה, ראשית כל הקניינים, המרוממת את בעליה בכל דורות העולם. בה מגיע לכל מקום של הצלחה, בין בחייו ובין במותו. לבו שוכן בדירת המעלה, והיא מביאה לו רחמים, שכן היא כים הנוהג ברחמים. המים שבו מגדילים את החיים. אשרי הלב המאיר בחכמה. בעליו שוכן בגן תחת עצים טובים. תהילה לְמֵאִיר המְמַלֵּא את החכמים ברוח החכמה, עד שהם כמאורות המאירים בעולם ומסירים את החושך. אלמלא אנשי הדעת, לא היה העולם בשלום ולא עטור בחסד. יתרבו בעולם בעלי הדעת, למען יהיו ימיהם שגשוגיים ומאירים. כמה טובים היו ימי הצדיקים שבעולם! לא נעשתה בהם שום דבר רע. נודה לבעל הגבורה שהביא לנו כתוב קדוש, שכולו חיים וברכות ורחמים!');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (344,'VI','6','מימר מדבק בשנים והעשרים אות',6000061,'מד את חכם אהן רבינה רבה אמן עליו ימן טובה עליך תמיד אדם חכמה ובה אמן פצתה מן תפוך מה עבדה הבל חכמה ועבד עובד מרחי אוי לקין במה עבד בנפשה חנוך חכמה ולידה רחט והלך בריחותה קבלה והוה חלקה אנוש חכמה וקרא בשמה עבדה ריש לכל זרע אדם נח חכמה ולה אתנגד פצתה מן מבולה בתיבותה אברהם חכמה והתהלך פניו אתעבד בכן ארש זכאי עלמה יצחק חכמה והפשט לה צברה אתעבד אקר לכל נציריה יעקב חכמה ולידה רחט שמרה בטובה וכללה באיקרה יוסף חכמה ולידה ערק פלטה מכל עובד ביש משה חכמה וקעם האן אקימה אמטתה לדרגה כהלה אצלחו אהרן חכמה ובה הגדל אתעבד פמה ים סליחן אלעזר חכמה ובה אתחיד ירת כל דלאבוה ויתב בדרגה פינחס חכמה ולידה זרז אוחי זרעה וקהלה עמה יהושע חכמה ובלשה בצדק אתיהב לה חלק לא אתיהב לחורנה כלב חכמה וקעם לותה אקימה מרה במקום קשטה','Since you understand (now) this great magniﬁcence, persevere in it, (so 
that) He may steadfastly (grant) His grace to you, always. Adam knew Him and 
persevered in it. He saved him from the opposite of what he did. Abel knew Him 
and did a pleasing deed; woe to Cain for what he did to himself. Enoch knew 
Him and ran to Him and walked in accordance with His will – He accepted him 
and (made him) His portion. Enosh knew Him and called on His name, and He 
made him a root for all human posterity. Noah knew Him and was led to Him; He 
delivered him from the Flood in his ark. Abraham knew Him and walked before 
Him; thus he became the ﬁrst of the Righteous of the world. Isaac knew Him and 
stretched out his neck to Him; he became the root for all the devotees. Jacob 
knew Him and ran to Him; He preserved him in wellbeing and crowned him with 
honor. Joseph knew Him and ﬂed to Him; He saved him from any evil deed. 
Moses knew Him and stood where He placed him; He brought him to a rank 
wholly successful. Aaron knew Him and by Him was made great; his mouth 
became a sea of forgiveness. Eleazar knew Him and held fast to Him; he inher-
ited all that was his father’s and occupied his position. Phinehas knew Him and 
hastened to Him; He brought life to his descendants and the congregation as 
well. Joshua knew Him and sought Him with justice; he was given a portion not 
granted to another. Caleb knew Him and stood by Him; his Master placed him in 
the place of truth.','מאחר שאתה מבין כעת את הגדולה הרמה הזו, התמדה בה, למען ייתן לך חסדו בנאמנות, תמיד. אדם הכירו והתמיד בכך. הוא הצילו מהיפך מה שעשה. הבל הכירו ועשה מעשה רצוי; אוי לקין על מה שעשה לעצמו. חנוך הכירו ורץ אליו והלך לפי רצונו — הוא קיבלו ועשאו חלקו. אנוש הכירו וקרא בשמו, והוא שמו שורש לכל צאצאי האדם. נוח הכירו והוביל אליו; הוא הצילו מן המבול בתיבתו. אברהם הכירו והלך לפניו; כך נעשה ראשון לצדיקי העולם. יצחק הכירו ופשט את צווארו אליו; נעשה שורש לכל הנכנעים. יעקב הכירו ורץ אליו; הוא שמרו בשלום וכיתרו בכבוד. יוסף הכירו וברח אליו; הוא הצילו מכל מעשה רע. משה הכירו ועמד במקום שהעמידו; הוא הביאו למדרגה מוצלחת לגמרי. אהרן הכירו ועל ידו הוגדל; פיו נעשה ים של סליחה. אלעזר הכירו ודבק בו; הוא ירש את כל אשר לאביו ותפס את מקומו. פינחס הכירו ומהר אליו; הוא הביא חיים לצאצאיו ולעדה כולה. יהושע הכירו ובקשו ביושר; הוא ניתן לו חלק שלא ניתן לאחר. כלב הכירו ועמד לצידו; אדונו שמו במקום האמת.');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (345,'VI','39','מימר מדבק בשנים והעשרים אות',6000391,'כד חכמת ס מד לה עביד מן גוני איקרה והגלה לה די מרביה ] סלוחה [ ומנה יהי פרקן נפשהתה והי לכנהתה וגם לנביותה עד לא תיזל מלה למגן מד הות ס מקימה לאלין 12296 . אתקוממת על עודנה לא מוזפה ולא בצרה הב בלך אה סגלה דאתסגל ביד אלה לא תחלף מה דאלפך אלהך דמבדר דילה איך יבלש מד ליתו לה אבדת דילך בביש תחמדותך ואיתיך ברחיו תבלש מד לחורנים מום עליך כל עת אה חסירה דמדעה ומה עבדת בנפשך עד מתי אתה מתוכח בביש העובדים אלולי הות גליגאן הות בישה עד אמת חובין עד אמת דינין עד אמת חסרן עד אמת קלל עד אמת אבהן יולדו ובנים לית לון עד אמת מדורין פנין מן שכונין לית עד אמת כרמים נצבים ומחליל לית לון עד אמת שורך טבוח וכל קניאניך בזיזין ביד דבביך לעיניך כל אהן גזוי עובד בישתה דעבדת ולידה זרזת שבקת שביל קשטה והלכת בשביל בישתה זרז אתי וצבע בכיור דחלתה דו מצבוע מדכי מכל טמא ומחי לכל חוב כל הדה וס קעמה תמן זריקה מי נדה למגלי שלמותך ולמנשם דושך ולהשיבך על כנך כמשפט הראישון','When סrealized the various honors done to it, it was revealed to it that it 
increases forgiveness, and from it will [come the deliverance of souls, and it is 
(tied) to the priesthood as well as to the prophethood, so that no word goes in 
vain.] Once סhad established these, it remained in its position, neither more nor 
less. Pay attention, O chosen one, who was chosen by God; do not alter what 
your God has taught you. He who squanders his (possessions), how should he 
seek what is not his? You lost your (possession) through the evil of your lust and 
you come in (your) will to seek what belongs to others. Blemish be upon you 
always, O the one whose intelligence is deﬁcient. What have you done to your-
self? How long will you be chastened for evildoings? Were not praises, it would 
be evil! How long sins? How long punishments? How long destitution? How long 
curses? How long fathers beget and have no children? How long dwellings 
devoid of inhabitants? How long vineyards planted without having a harvester? 
How long will your cattle be slaughtered and all your beasts plundered by your 
enemies before your very eyes? All this is the penalty for the evil you have done. 
You rushed to do it. You forsook the way of truth and went in the way of evil. 
Make haste to come and immerse yourself in the trough of fear, for it is an im-
mersion that cleanses from all uncleanness and blots out all sin. Thus, סstands 
there sprinkling the water for impurity to reveal your perfection and to relieve 
your weariness and to restore you to your status, as was your former custom.','כאשר ס'' הבחינה בכבודות השונים שנעשו לה, נגלה לה כי היא מגדילה סליחה, וממנה תבוא גאולת הנשמות, והיא קשורה גם לכהונה וגם לנבואה, כך שאין דבר הולך לבטלה. משקבעה ס'' את אלה, נשארה במקומה, לא יותר ולא פחות. הקשב, הנבחר, אשר נבחר על ידי אלוהים; אל תשנה את מה שאלוהיך למדך. מי שמבזבז את רכושו, כיצד יתבע את מה שאינו שלו? איבדת את רכושך ברוע תאוותך ובאת ברצונך לתבוע את השייך לאחרים. חרפה עליך תמיד, אתה אשר שכלך חסר. מה עשית לעצמך? עד מתי תיוסר בשל מעשי הרשע? לולא השבחים, היה זה רע! עד מתי חטאים? עד מתי עונשים? עד מתי עוני? עד מתי קללות? עד מתי אבות מולידים ואין להם בנים? עד מתי בתים ריקים מיושבים? עד מתי כרמים נטועים ואין להם בוצר? עד מתי יישחטו בקרך וכל מקנך יישדד על ידי אויביך לנגד עיניך? כל זאת היא עונשך על הרע שעשית. מיהרת לעשותו. עזבת את דרך האמת והלכת בדרך הרע. מהר לבוא וטבול עצמך בבור היראה, שהיא טבילה המטהרת מכל טומאה ומוחקת כל חטא. כך עומדת ס'' שם ומזה מי נידה לגלות את שלמותך ולהקל את עייפותך ולהשיבך למעמדך, כמנהגך הקדום.');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (346,'VI','56','מימר מדבק בשנים והעשרים אות',6000561,'אנשה התעירו ליתה מחכומה ואלפו יתה באימנו דלב אלו הויך ריקן לא אתיהב לך ולא הוה לך לבר מן אהן עובדה יתרבי חילה דלא עבדך צריך ללפן בראי ולא לחכמת פגול רק יהב לך כתב מכלל בחיים כתבה באצבעה והושטה מן ימינה לנביא מהימן כללה בסימנין ורבינה במופתים וחילה באותת אה רבין רב אתרבה בה משה והסתקף בה סגי מכל אנש מיסתה סהדות מרה עליו לא קם כותה ולא יקום לעלם אהנו נביה דנביותה סימי לא מתעלם עליו ועלמה עלם אב סימניה כרי פליהתה חבר קיאמיה מאור עלמיה שמש נביותה לא כותה נביא מכל בניו דאדם קעימיה שמעו לה ומאתיה דחלו מנה ושומיה וארעה לא עצו מליו','“O people, wake up to this knowledge and learn it with belief of the 
heart. If you were vain, Torah would not have been given to you, and you would 
have had nothing but this. Exalted be the Mighty One who did not make you to 
need alien teaching or false wisdom, but gave you a Scripture crowned with life, 
which He wrote with His own ﬁnger, and handed with His right hand to a faith-
ful prophet. He crowned it with wonders and magniﬁed it with miracles and re-
inforced it with signs. Behold great majesty! Moses was magniﬁed by it and was 
elevated by it above all men. The testimony of his Master about him suﬃces: And 
there has not arisen a prophet […] like him and never will arise (Deut. 34:10). This 
is the prophet whose prophethood is a treasure which cannot be ignored for as 
long as the world lasts. The father of wonders, the foundation of miracles, the 
owner of the covenants, the light of the worlds, the sun of prophethood, like 
whom there is no prophet from amongst all the sons of man. The immortals lis-
tened to him, the mortals feared him. Heaven and earth did not rebel against his 
words.”','"הה עם, התעוררו לדעת זאת ולמדוה באמונת הלב. אילו הייתם הבל, לא הייתה התורה ניתנת לכם, ולא היה לכם דבר מלבד זאת. יתרומם האדיר שלא גרם לכם להזדקק לתורה זרה או לחכמה כוזבת, אלא נתן לכם כתב עטור חיים, אשר כתב באצבעו הוא, ומסר בימינו לנביא נאמן. עטרו בנפלאות וגידלו בנסים וחיזקו באותות. הנה גדולה עצומה! משה נתגדל על ידה ונתרומם על ידה מעל כל בני האדם. עדות אדונו עליו מספיקה: ולא קם נביא [...] כמוהו ולא יקום (דברים לד,י). זהו הנביא שנבואתו היא אוצר שאי אפשר להתעלם ממנו כל זמן שהעולם קיים. אבי הנפלאות, יסוד הנסים, בעל הבריתות, אור העולמות, שמש הנבואה, שאין נביא כמוהו מבין כל בני האדם. האלמוותיים הקשיבו לו, בני התמותה יראו ממנו. השמים והארץ לא מרדו בדבריו."');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (347,'VI','40','מימר מדבק בשנים והעשרים אות',6000401,'כד חכמת ס דן רבינה רבה עזרת בנפשה והי טעינה חסד ומללת עם ט ממלל חכמה יחיל מסחנה ביני כל דרי עלמה אני ואתי אתקוממנן לעובד אתי מחילה ואני מרביה אתי עבידה לבוש דמלכו ואני עבידה לבוש דפוגגו אתי עבידה נחמה ואני עבידה מיקרה מודאה לאלה רחמנה דרחמיו ממנים ולית בחיל אנש ידע גבורתה ישתבח מלכה מלוך חיי עולם דכל חייה שאילה מדלה נסגד לגדלה ונדחל מן אימתה רבתה אנשה זרזו למביע מן אלה הן יקרב רחמיו וינפש צרעתן דו רחמן ורתאי וכן כתב על קלומה','When סknew this great majesty, it retracted bearing grace, and spoke a 
speech of wisdom with ,טwhich strengthens its owner throughout the genera-
tions of the world: “I and you are destined for action: you give strength, I exalt; 
you bring about the garment of kingship, I bring about the garment of delight, 
you bring about relief, I bring about glory.” Thanks be to the Merciful God whose 
mercies are everlasting; no man can know His might. Praise to the King who 
possesses eternal life, from whom all life is borrowed. Let us bow down to His 
greatness and fear His great awfulness. O people, rush to ask God that His mercy 
may draw near, and that He may relieve our distress, for He is merciful and full 
of pity, and thus He wrote about Himself.','כאשר ידעה ס'' את ההדר הגדול הזה, נמנעה מנשיאת חסד, ודיברה דברי חכמה עם ט'', המחזק את בעליו לאורך דורות העולם: "אני ואתה נועדנו למעשה: אתה נותן עוז, אני מרומם; אתה מביא לבוש מלכות, אני מביא לבוש עונג; אתה מביא הקלה, אני מביא כבוד." תודה לאל הרחמן אשר רחמיו לעד; אין אדם יכול לדעת את גבורתו. שבח למלך אשר חיי נצח לו, שממנו כל חיים שאולים. נשתחווה לגדולתו וניירא מנוראותו הגדולה. עם, מהרו לבקש מאלוהים שרחמיו יקרבו, וכי יקל את מצוקתנו, שהרי הוא רחמן ומלא חמלה, וכן כתב על עצמו.');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (348,'VI','45','מימר מדבק בשנים והעשרים אות',6000451,'זבנה שביעיה זבנה דקעמת עמך ואת טלי רמי בשילולה לגו תיבת והפתחת תרחי סימניה בדילך עד תמחו כל דבביך שרוי מה אתעבד לך השדכת מיה עד הבלדת מצראי מדן וסגי מכן כד נסבת יתך ברת פרעה פתחת פמה במלים טבים כמד עבדת בשרוי חזותך זבנה תליתה רבית לשנך עדהן אמטיך למיתובה רמה זבנה רביעיה כד עללת עמך ורבית ממללך וכן ממלל אחוך זבנה חמישה כד קעמת לגו ימה והפלגת מימיו קמיך הזבן הששי קעמת קדמיך ופתחת לך תרח עננה הזבן השביעי פתחת תרחי שומיה לקבול בלישהתך עובדי עמך כל אהן ואנה כיר אדה ושלחיות ממללה ובתר גלותן לך נחתנן על אדך וכל פי אלהנן בידך מיסתה אימנך מרן עלינן בקשט וכד הוינן לה אימנך על מד לה כל מד בעלמה בחמשה מנן אתברא והכלל בה עוד בראשית ברא אלהים ויכלה אלהים ואנן כיר אד לינן בריה דכל בריה חדתה ועוד כליה ואנן לינן חדתין ולא כליהן כמה דהוינן ברישה כן נהי בעקבה','“The seventh episode: when I stood with you and you were an infant 
cast into the river in an ark. The gates of wonders were opened for your sake, so 
that all your enemies were astonished. The ﬁrst thing done for you: I stilled the 
waters, so that the Egyptians were terriﬁed at it. Moreover, when Pharaoh’s 
daughter took you, she opened her mouth with good words, as she did at the ﬁrst 
sight of you. The third time: I magniﬁed your speech, until I brought you to high 
rank. The fourth time: when I entered with you and magniﬁed your speech as 
well as your brother’s speech. The ﬁfh time: when I stood in the sea and its 
waters were divided before you. The sixth time: I stood before you and opened 
for you the gate of the cloud. The seventh time: I opened the gates of heaven for 
the acceptance of your requests. All these are my dealings with you. I am the 
writing of His hand and the mission of His speech. Afer our revelation to you, 
we came down onto your hand and all God’s commands (are) in your hand. 
Suﬃce that our Lord entrusted you with us in truth, and while we were His He 
entrusted you with what pertained to Him. All that was in the world was created 
with the ﬁve of us and it was completed by those too. In the beginning God 
created (Gen. 1:1) and God ﬁnished (Gen. 2:2). We are mere handwriting, not crea-
ture, for all creature is renewed as well as ﬁnished. We are not renewed nor ﬁn-
ished. As we were in the beginning, so we will be in the end.”','"הפרק השביעי: כשעמדתי עמך ואתה היית תינוק מושלך לנהר בתיבה. שערי הנפלאות נפתחו למענך, עד שכל אויביך נחרדו. הדבר הראשון שנעשה למענך: השקטתי את המים, עד שהמצרים נבעתו מכך. ועוד, כשלקחה אותך בת פרעה, פתחה את פיה בדברים טובים, כפי שעשתה למראה פניך בתחילה. בפעם השלישית: הגדלתי את דבריך עד שהעליתיך למעמד נכבד. בפעם הרביעית: כשנכנסתי עמך והגדלתי את דבריך ואת דברי אחיך כאחד. בפעם החמישית: כשעמדתי בים ומימיו נבקעו לפניך. בפעם השישית: עמדתי לפניך ופתחתי לך את שער הענן. בפעם השביעית: פתחתי את שערי השמים לקבלת בקשותיך. אלה הם כל מעשי עמך. אני כתב ידו ושליחות דברו. לאחר שנגלינו אליך ירדנו על ידך, וכל מצוות האל בידך. די בכך שאדוננו הפקיד אותנו בידך באמת, ובעודנו שלו הפקיד בידך את אשר היה שייך לו. כל שהיה בעולם נברא בחמישייתנו ובה הושלם. בְּרֵאשִׁית בָּרָא אֱלֹהִים (בראשית א,א) וַיְכַל אֱלֹהִים (בראשית ב,ב). אנחנו אינם אלא כתב ידיים, ולא יצורים, שכן כל יצור מתחדש וגם נפסק. אנחנו אין אנו מתחדשים ולא נפסקים. כפי שהיינו בתחילה, כך נהיה בסוף."');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (349,'VI','59','מימר מדבק בשנים והעשרים אות',6000591,'תמן בישתה אמרה לזכותה מה דן חסרנה דגלה אלין בניה דאדמו לכוכבי שומיה בסקפנה ובסגינה ומרון רצי עליון ומתנחם בטובה עליון ואנה טרידה מקמיון בכל עת כאמה תכלה בניה אצערת לקין וכל זרעה בתרה וככן כל אנשי סדם הוקדת יתון בגפרית ואש וכוש וברה הנמרוד ואף מצראי וכל בניון ועמלק ועמו המחו כהלו דלא הוו ובלעם ריש דבבי עבראי הקטל בחרבה והתחרבת קרתה','Then said Evildoing to Righteousness: “What deﬁciency has manifested 
these sons, who resemble the stars of heaven in elevation and abundance, 
whose Master is favorable towards them and in His goodness forgives them? I am 
driven before them always like a mother who bereaved her children! I oppressed 
Cain and all his descendants afer him; likewise, I burnt all the People of Sodom 
with brimstone and ﬁre. Cush and his son Nimrod as well as the Egyptians and 
all their children and Amaleq and his people were all blotted out, as if they never 
existed. Balaam, the chief of the enemies of the Hebrews, was slain with the 
sword and the villages were destroyed.”','אז אמרה הרשעה לצדקה: "מה חסרון גילה את הבנים האלה, הדומים לכוכבי השמים ברוממותם ורבויים, שאדונם חפץ בהם ובטובו סולח להם? אני נדחית מפניהם תמיד כאם שכולה! דיכאתי את קין ואת כל צאצאיו אחריו; וכן שרפתי את כל אנשי סדום בגפרית ואש. כוש ובנו נמרוד, וכן המצרים וכל ילדיהם, ועמלק ועמו – כולם נמחו כאילו לא היו מעולם. בלעם, ראש אויבי העברים, נהרג בחרב והכפרים נחרבו."');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (350,'VI','53','מימר מדבק בשנים והעשרים אות',6000531,'עמו ק הך הי מזרזה ומגליה מלים משפעין טבוהן שלם עליך נביה רבה כי לך לאוי רב מכן במד מלכת מן איקרה דמרך כי לא גלתן אלה אלאן לך ולא סודן לבר מנך איקרי הגלה כדו קדמיך מן קדוש יום הנח בה מרן קדשה בשמי קשטה עורי בכן וכל לב אדור בה רבינה חיול בלב חנוך עברת וגלית שלמותה ובפם אנוש קעמת וגלית איטבותה וללב נח חתמת וגדלת איקרה ועל אברהם שלמת וכללת זכותה ועם יצחק קעמת ואסקפת דרגה ועם יעקב הלכת ואנהרת מדעה וליוסף אלפת ורבית חכמתה אה שלמו רבה אתעבדת בי ולגו לבך דערת ומנך לא פסחת והאן אנה אזלה בנהרך ממלכה אלבשת אהרן כליל מן קדושך בבעו מנך אנהר מרך ואמטתה לכן וכן זרעו אתעבד לון כהנה ממנה לא תתחלף לעלם ואנה דערה במשכנה מרביה לקהלה למה לא הוה לי בריש קציה דכרן עד אדמי לחברי אשר הכתבו והשתרית בון כל קצי ארהותה','See קas it hastens and reveals words rich in blessings: “Peace be to you, 
O great prophet! Indeed, ﬁtting for you (even) more than that, in what you 
acquired from the honor of your Master. For God has not revealed us except to 
you, and our secret is not (overt) except to you. My glory has now been revealed 
before you, since the sanctiﬁcation of the day on which our Master rested. He 
sanctiﬁed it by my name. The True One is also in that. The majesty of any heart 
in which I dwell is great. Into the heart of Enoch I entered and revealed his per-
fection. I was in the mouth of Enosh and revealed his excellence. I sealed the 
heart of Noah and magniﬁed his glory. I perfected Abraham and made his righ-
teousness complete. I stood with Isaac and exalted his status. With Jacob I 
walked, and I illuminated his mind. I instructed Joseph and magniﬁed his wis-
dom. Behold, a great perfection wrought by me. I dwelt in your heart and I did 
not depart from you. Wherever I go I am advised by your light. I vested Aaron 
with a crown from your holiness. Your Lord remembered your request and 
brought him to this. Likewise, his descendants got a perpetual priesthood, unal-
terable forever. I dwell in the Sanctuary to magnify the congregation. Why was 
there no mention of me at the beginning of the Qiṣṣīm, so that I should be like 
my companions which were written and by which all the Qiṣṣīm of the law 
began?”','ראה את ק כשהוא ממהר ומגלה דברים עשירים בברכות: "שלום לך, הו נביא גדול! אכן, ראוי לך אף יותר מכך, במה שרכשת מכבוד אדונך. שהרי לא גילה אותנו האל אלא לך, וסודנו אינו (גלוי) אלא לך. כבודי נגלה עתה לפניך, מאז קדושת היום שבו נח אדוננו. קידש אותו בשמי. גם האמיתי בכך. גדולה היא הוד כל לב שאני שוכן בו. נכנסתי ללבו של חנוך וגיליתי את שלמותו. הייתי בפיו של אנוש וגיליתי את מעלתו. חתמתי את לבו של נח והגדלתי את כבודו. שיכללתי את אברהם והשלמתי את צדקתו. עמדתי עם יצחק ורוממתי את מעמדו. עם יעקב הלכתי, והארתי את שכלו. הדרכתי את יוסף והגדלתי את חכמתו. הנה שלמות גדולה שפעלתי. שכנתי בלבך ולא פרשתי ממך. לכל מקום שאני הולך מנחה אותי אורך. העטרתי את אהרן בכתר מקדושתך. אדונך זכר את בקשתך והביאו לכך. וכך גם צאצאיו זכו לכהונה נצחית, שלא תשתנה לעולם. אני שוכן במקדש להגדיל את הקהילה. מדוע לא נזכרתי בראשית הקיסים, כדי שאהיה כחברַי שנכתבו ובהם פתחו כל קיסי התורה?"');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (351,'VI','68','מימר מדבק בשנים והעשרים אות',6000681,'חסלת גמאל ממללה שרית ד ואמרת אה נביה רבה דרבתה מרה ועבד מדעה מכלל לכל מדעיה יפרס ממללי קמיך עד יתידע בידך רבינה דלי מה אנה מכללה גויתה בארבעתי עקריה ולפי מניאני נהרי גנת עדן בחיל נצובה וכן אתיתב עלמה ופהתיו יתרבי חילה דלה כל תשבחה וכל רוממו תמן הגיב נביה רבה משה לקבל אלין מליה הגבו מרבי ידועיה אנתי מתרביה במד אמרתי כי ליך סגי מכל הדה דתרי שמיה ביך הוקם מניאנון שמה רבה וילה אנש דיהי נקב לה יתרגם כבר שלומית התגזה על עובדה ושמה רבה דאוקרי מרי בה וגלה רבותי בכל דרי עלמה בעיני כל בוראיה ואתי מרביה עלמה בכל עת אסתדרו כדו אה טביה למשמע מה יתאמר במשמעכון ד עבידה כל הדה ורבינה יתר על כל מאום','גﬁnished speaking. דbegan speaking and said: “O great prophet Moses, 
whom his Master exalted and made his mind perfect above all minds, let my 
words spread forth before you, that my excellence may be made known through 
you. Do I not complete the body with the four elements as well as the rivers of 
the Garden of Eden according to my number – by the power of its Planter? And 
thus was set up the world and its ends. Exalted be the Mighty One to whom all 
praise and exaltation belong.” Then the great prophet Moses replied against 
these (assertions) with an answer that elevates the men of knowledge. “In fact 
you are magniﬁed in what you say, for you have more than all that. For the 
number of the two names was established in you. The great name, woe to any 
man who dissociates himself from it! He will be stoned like the son of Shelomith 
– he was repaid for his act. (So is) the great name with which my Lord honored 
me and revealed my greatness throughout all the world’s generations in the sight 
of all creatures. You magnify the world always. Ready yourselves, now, O good 
people, to hear what will be said in your hearing. דdoes all this and its majesty 
is greater than everything.”','סיים ג לדבר. החל ד לדבר ואמר: "הו משה הנביא הגדול, שרוממו אדונו ושכלל את שכלו מעל כל שכל, יתפשטו דבריי לפניך, למען תיוודע מעלתי על ידך. האם אינני משלים את הגוף בארבעת היסודות וכן את נהרות גן עדן לפי מספרי – בכוח נוטעו? וכך הוקם העולם וקצותיו. יתרומם הגיבור שלו כל השבח והרוממות." ואז ענה משה הנביא הגדול על דברים אלה בתשובה המרוממת את בעלי הדעת. "אמנם נתגדלת במה שאמרת, שכן יש לך יותר מכל זה. שכן מספר שני השמות הוצב בך. השם הגדול – אוי לכל אדם המתנכר ממנו! ייסקל כבן שלומית – הושב לו כמעשהו. כן הוא השם הגדול שבו כיבדני אדוני וגילה את גדולתי לאורך כל דורות העולם לעיני כל הברואים. אתה מגדיל את העולם תמיד. הכינו עצמכם, עתה, אנשים טובים, לשמוע את הנאמר באוזניכם. ד עושה כל זאת וגדולתו גדולה מכול."');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (352,'VI','9','מימר מדבק בשנים והעשרים אות',6000091,'אנן אנון עבודי אהן דאנן בעשדה וקמינן רוחה אנן אנון חברי קבלה ובידן אורה רבה מניר אנן אנון חברי קבלה במה דנעבד מן גוני חוביה אנן אנון חברי קבלה במד גלינן מגוני תשניקה נעמי קנומינן בגוני מעבאן ולינן יכלין נכלינון בכל חילן וילן במה דעבדנן בנפשהתן מן אלין עובדיה המכיה לנן עד אמת אנן לקין בדיניה ובכל יום נעבד מהו מחיב לון לא נתוכח ולא נתבשש מן עובד חוביה קצי ברכתה נשמע ולא נעבד לון הך יהי אהן מתעבד לן ואנן לא עבדין פקודה','It is we who do that, and indeed we are in distress, yet there is relief 
before us. We are owners of darkness, yet within our grasp there is great illumin-
ing light. We are owners of darkness, in committing various sins. We are owners 
of darkness in doing what we have done of all kinds of distress. We see ourselves 
in all sorts of plagues and we are unable, with all our power, to prevent them. 
Woe to us for those we have done to ourselves of the actions that harm us. How 
long are we to be smitten with punishments, (while) every day we do what brings 
us guilt? We do not receive admonition nor are we ashamed of committing sins. 
We hear the “Blessing” Qiṣṣīm, but we do not act in accordance with them. How 
can this be appropriate for us, when we do not carry out His precept?','אנחנו הם שעושים זאת, ואכן אנו במצוקה, ואף על פי כן יש לפנינו הקלה. אנו בעלי חושך, ואולם בידינו אור גדול ומאיר. אנו בעלי חושך – בעשיית חטאים שונים. אנו בעלי חושך – בעשותנו את כל מה שעשינו מכל מיני צרות. אנו רואים את עצמנו בכל מיני מכות ואין בכוחנו, בכל עוצמתנו, למנוע אותן. אוי לנו על מה שעשינו לעצמנו מן המעשים המזיקים לנו. עד מתי נוכה בעונשים, בשעה שבכל יום אנו עושים מה שמביא עלינו אשמה? אין אנו מקבלים מוסר ואין אנו בושים בחטא. אנו שומעים את קיצים של ה"ברכה", אך אין אנו נוהגים לפיהם. כיצד יאה לנו הדבר, בשעה שאין אנו מקיימים את מצוותו?');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (353,'VI','26','מימר מדבק בשנים והעשרים אות',6000261,'טית אמרה למה לא הוה לי בריש קציה דכרן דמות חברי כי לית שמי מן ריש בראשית כליל מכלל לכל טוב אלית קעמת לקבלה דאדם זבן דהוה מבחר לכל בחור וקעמת עם הזכאים ושוית לבביון משכן לי בגדל ורחטת ליד יוסף ורביתה בארע מצרים וקעמת עמך למרבה יתך בכל מקום אקימך אלה בו כד לא הוה לי במקרת מליה דקרא יתון אלה על טור סיני עזרת בבלישה עד הגלית לך ואתחזי אלה וכתבי קמיך למה לא הכתבת בריש קצה הך כתביה דכתבו קמי מן נעירותך נעירו לכל עלמה הך הוה כן וכלה בידך עביד ממללך הוא ממלל אלה וכל מד גליך הו עבודה','טsaid: “Why is no mention of me at the beginning of the Qiṣṣīm like my 
companions? Indeed, my name is not in the beginning of Genesis – a crown 
crowned with all good. Was I not in front of Adam at the time when he was the 
chosen of all choices. (Was I not) standing with the Righteous, making their hearts 
my abode with greatness? (Did I not) hasten to Joseph and make him great in the 
land of Egypt? (Was I not) with you to exalt you in every place that God placed 
you in, when I had no (share) in the proclamation of the words which God pro-
claimed on Mount Sinai? I repeated the request so that I was revealed to you: 
God appeared and wrote me before you. Why was I not written at the beginning 
of the Qiṣṣa, like the letters which were written before me? From your wisdom 
comes wisdom for the whole world. How (then) was it so? Everything was made 
by you. Your speech is the speech of God and He is the doer of all that you have 
revealed.”','אמרה ט: "מדוע אין זכרי בראש הקיסים כמו חברותי? הרי שמי אינו בתחילת בראשית — עטרה עטורה בכל טוב. האם לא הייתי לפני אדם בשעה שהיה בחיר כל הבחירות? האם לא עמדתי עם הצדיקים ועשיתי את לבם מעוני בגדולה? האם לא מיהרתי אל יוסף והגדלתי אותו בארץ מצרים? האם לא הייתי עמך לרוממך בכל מקום שהציבך בו אלוהים, כשלא היה לי חלק בהכרזת הדברים שהכריז אלוהים בהר סיני? שניתי את הבקשה עד שנגליתי אליך: אלוהים נגלה וכתב אותי לפניך. מדוע לא נכתבתי בראש הקיסה כמו האותות שנכתבו לפני? מחכמתך יוצאת חכמה לכל העולם. כיצד הייתה זו כך? הכול נעשה על ידך. דבריך הם דבר אלוהים והוא עושה כל אשר גילית."');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (354,'VI','19','מימר מדבק בשנים והעשרים אות',6000191,'נעזר מן אכה אל מליה דאנן בון ונבקר על עקרי חכמתה למה לא הכתבת קצי ארהותה בכלול התרין ועסרים אות אלא בחסרן שבעה אכתבין וגליתון לך עד תחכמנון ואתעבדת שבעה לא תוזף ולא תבצר טב לן נבקר על אהן רזה ט נ ס פ צ ק ת עמי דן רזה דבענה אלה וכתבה קמיך וכתבין גלית קדמיך ועוד מניאנון טב לך תחכמנה ואנון שבע מון ותשעה ושמנים מבין מחוי על עובד גדיל שרון טית וחסולון ת תשעה בשרוה וארבע מון בעקבה ינדי כל אחד בוננותה קדם ימלל ויעבד קנומה מכלל בכל חכמה דחכמתה נאר דלק בלבה וכל לב דלית לגוה חכמה חברה כעור ממשש בקבלה דחכמתה סלם מצב מן לבה אל מעונה הן הוה הלב נציר הוא עמי כל תמח כמה דהוה לבה דיעקב כד הוה מלי רוח חכמה הגלה לה כל טוב דחכמתה דבה חכמת קשט דמך מנשם אתחזי לה כל איקר מתחיל לדזרע הוה קציר מודאה למלכה המגזי לכל עבוד לפם מד קדם מן עובד שלם','Let us return from here to the matters that we deal with, and enquire 
about the roots of wisdom: why the Qiṣṣīm of the Torah were not written with all 
of the twenty two letters, but absent seven letters? I reveal them to you, that you 
may know them. They are seven; no more, nor less. It is good for us to enquire 
into this mystery. .ת ,ק ,צ ,פ ,ס ,נ ,טConsider this mystery which God intended to 
write before you, letters that I reveal to you. Their numeric value as well – it is 
good that you should understand this, their amount is seven hundred and 
eighty-nine – instructs and relates about a great deed. The ﬁrst of them is טand 
the last of them ,תnine at the beginning and four hundred at the end. Let 
everyone pay attention before he speaks, and make himself perfect with all wis-
dom. For wisdom is a light that shines in the heart, and for any heart that has no 
wisdom in it its owner is as a blind man groping in the dark. For wisdom is a 
ladder set up from the heart to the Divine Abode. If the heart is devoted, it sees 
every wonder, as the heart of Jacob was full of the spirit of wisdom, when all 
good was revealed to him. For the wisdom that was in it was true wisdom. He 
slept at ease – all mighty glory appeared to him. What he had sown, he reaped. 
Thanks be to the King who recompenses fully each doer according to the work he 
made ﬁrst.','שובה נא מכאן לעניינים שבהם אנו עוסקים, ונחקור את שורשי החכמה: מדוע ה"קיצים" של התורה לא נכתבו בכל עשרים ושתיים האותיות, אלא נעדרות מהם שבע אותיות? אני מגלה אותן לכם, למען תדעו אותן. הן שבע; לא יותר ולא פחות. טוב לנו לחקור את הסוד הזה. ט, נ, ס, פ, צ, ק, ת — הביטו בסוד הזה שאלוהים התכוון לכתוב לפניכם, אותיות שאני מגלה לכם. גם ערכן המספרי — טוב שתבינו זאת, סכומן הוא שבע מאות ושמונים ותשע — מורה ומספר על מעשה גדול. הראשונה שבהן היא ט והאחרונה ת, תשע בראש וארבע מאות בסוף. יתן כל אדם דעתו לפני שידבר, וישלים את עצמו בכל החכמה. שכן החכמה היא אור המאיר בלב, וכל לב שאין בו חכמה — בעליו כאיש עיוור הממשש בחשכה. שכן החכמה היא סולם הנטוע מן הלב עד מעון האל. אם הלב נתון (לאל), הוא רואה כל פלא, כשם שלב יעקב היה מלא רוח חכמה, כאשר נגלה לו כל טוב. שכן החכמה שהייתה בו הייתה חכמה אמיתית. הוא ישן בשלווה — כל כבוד עוז נגלה לו. מה שזרע — קצר. תהילה למלך המשיב גמול מלא לכל עושה לפי המעשה שעשה בראשונה.');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (355,'VI','43','מימר מדבק בשנים והעשרים אות',6000431,'עמו פ ממללה ממלל מרבי שמועה אה נביה רבה משה דאסגלך אלה בשליחתה ופתח קמיך תרח כסיהתה מה קעמת עמך בשבעה מקומים לא פסחת מנך ארפות עין הך מד קעמת מן בראשית עד הן יצאת לעלמה בשלם קעמת ופתחת תרח אורה ויתבת בה שבעה תרחים תרחה » קמאה « דממזג עם חשכה בחיל יכולה דחזה ואקימה תרחה תניאנה תרח אשתה דאתעבדת עקר בכל בוראיה תרחה תליתה רבית בה שמשה דאנסבת גברו מן אשתה תרחה רביעיה מד אלבשת לזרעך מן רבין איטבו כלה אנחמו תרחה חמישה דאלבשת לכוכביה מן נאר מניר לא יכרת לעלם כי בידון פרנוס ליתו בטל לעלם כמה אתיתבו כן אנון לעלם התרח הששי תרחה רבה דכל אלין תרחיה מנה תרחה שביעיה דהוה צניק עדהן אתיתך והפתח קמיך דהוה לגוה לוחי בריתה דהוו כסין עד אתתיך ונחתו על ידיך','See פspeaking a speech that exalts its listener: “O great prophet Moses, 
whom God chose for His mission and opened before you the gateway to the Con-
cealed. I was with you in seven places; I did not leave you for a moment, as (for 
example) when you arose in ,בראשיתand went forth into the world in peace. I 
stood and opened the gate of light and set within it seven gates. The (ﬁrst) gate, 
the one which (was) merged with the darkness by the power of the Mighty One, 
which He decided and established. The second gate, the gate of ﬁre which was 
made a fundament in all creatures. The third gate, by which I promoted the sun 
which took energy from the ﬁre. The fourth gate, by which I clad your descen-
dants in a state of glory, wholly of comfort. The ﬁfh gate, by which I clothed the 
stars with illuminating light, never to be cut oﬀ. Indeed, in their power there is a 
dominion that never ceases. As they were established, so they are forever. The 
sixth gate, the great gate from which all these gates are derived. The seventh 
gate, that was closed until I came to you and then it was opened before you. For 
it contained the tablets of the covenant, which were hidden, until I came to you 
and then they descended through you.”','ראה את פ'' מדברת דברים המרוממים את שומעם: "משה הנביא הגדול, אשר בחר בך אלוהים לשליחותו ופתח לפניך את שער הנסתר. הייתי עמך בשבעה מקומות; לא עזבתיך אף רגע, כגון כאשר קמת בְּרֵאשִׁית ויצאת לעולם בשלום. עמדתי ופתחתי את שער האור ושמתי בו שבעה שערים. השער הראשון, אשר נמזג עם החושך בכוח הגדול, אשר גזר וקבע. השער השני, שער האש אשר נעשה יסוד בכל הנבראים. השער השלישי, שבו העליתי את השמש שקיבלה אנרגיה מן האש. השער הרביעי, שבו הלבשתי את צאצאיך במצב של כבוד, כולו נחמה. השער החמישי, שבו הלבשתי את הכוכבים באור מאיר, שלא יכרת לעולם. אכן, בכוחם יש ממשלה שאין לה סוף. כפי שנקבעו, כן הם לעד. השער השישי, השער הגדול שממנו נגזרים כל השערים הללו. השער השביעי, שהיה סגור עד שבאתי אליך ואז נפתח לפניך. שהרי בו היו לוחות הברית, שהיו נסתרים, עד שבאתי אליך ואז ירדו על ידך."');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (356,'VI','22','מימר מדבק בשנים והעשרים אות',6000221,'כמה קשטה מסיד בן זעק יתן בנים בכורים ועם קדש וסגולה וכהנים ואף מלכים ונחלה ובחורים ויהב לן כתבה ויקרן במחכומה וכללן בקדשה ורבהתן במצוהן וסבלן על כנפי נשרין ואגיזן › ב ‹ ימה וחלה לן מי מרה ואכילן מנה ואשמענן קלה ויקרן בכתבה מן התוקר בכל אמיה כותן אי אתרבה דמותן איך נהי מתנצלים מן חכמתה ונביה רבה משה ספרן הך נצרך גרמן לבראין וכלה צריך לידן ביש מה עבדנן לקשטה סנינן ולבשהתה רחמנן אהן גזוי אהן הא לב מתברי מן צנם לבה דלנן יומה נעמי נפשהתן בעקה ולא נרתי יתון מה דן עובדה בישה כל הדה קבל תחמדתה דשלטת עלינן והלבשת יתן חשיכות לבה ואבדת דעתה מנן וצרכנן לבראי ילפן אלו עזרנן וללב הגזרנן עזר איקרה דאתבדר מנן תובו ליד אלה תשקחון יתה רחמן מקבל כל תהב דיתוב לידה','How much the True One testiﬁes about us, calling us “ﬁrstborn sons”, 
and “holy people”, “choice”, “priests”, and also “kings”, “heritage”, and “chosen 
ones”. He has given us His Scripture and honored us with knowledge of it. He 
crowned us with holiness, elevated us with precepts, bore us up on eagles’ 
wings, and made us pass through the sea, and sweetened for us the water of 
Marah, gave us Manna to eat, made us to hear His voice, honored us with His 
Scripture. Who among all nations has been honored like us or been elevated like 
us? How could we let ourselves be stripped of knowledge, when the great 
prophet Moses is our teacher? How can we submit ourselves to aliens, when all 
need us? What we have done is evil. We have hated the True One, and evil doings 
we have loved instead. This in exchange for that. Behold, a heart shaped from 
stone (is) our heart. Today, we see our souls in distress and we have no mercy on 
them. What is this evil doing? All this because of the lust that gained control 
over us and dressed us with darkness of heart and destroyed our mind, and 
made us need an alien to teach us. If we were to repent and circumcise the heart, 
the glory removed from us would return. Turn back to God – you will ﬁnd Him 
merciful, the one who accepts every repenting person who turns back to Him.','כמה מעיד האמת עלינו, קורא לנו "בנים בכורים", ו"עם קדוש", "בחירים", "כוהנים", וכן "מלכים", "נחלה" ו"בחירים". הוא נתן לנו את כתבו וכיבד אותנו בידיעתו. עיטרנו בקדושה, הרימנו במצוות, נשאנו על כנפי נשרים, העבירנו בים, המתיק לנו את מי מרה, נתן לנו מן לאכול, השמיענו את קולו, כיבד אותנו בכתבו. מי מכל העמים נכבד כמונו או הורם כמונו? כיצד נסכים להיות מורקים מן הדעת, בעוד שמשה הנביא הגדול הוא מורנו? כיצד נכנע לזרים, בעוד שכולם זקוקים לנו? מה שעשינו הוא רע. שנאנו את האמת, ומעשים רעים אהבנו תחתיה. זה תחת זה. הנה, לב עשוי אבן — זהו לבנו. היום אנו רואים את נפשותינו בצרה ואין אנו חסים עליהן. מה הוא המעשה הרע הזה? כל זאת בגלל התאווה שהשתלטה עלינו, הלבישתנו חשכת לב, השחיתה את שכלנו, וגרמה לנו שנזדקק לזר שילמד אותנו. אילו שבנו בתשובה ומלנו את הלב, הכבוד שנסתלק מאיתנו היה שב. שובו אל האל — תמצאו אותו רחמן, את מי שמקבל כל שב בתשובה הפונה אליו.');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (357,'VI','69','מימר מדבק בשנים והעשרים אות',6000691,'אתת ה כות מלך ועל רישה כליל כבד וקעמת קדם נביה רבה משה ושרית ממללה ואמרת אה בר בית אלהים אה חבר קיאמה אה מהימן אלהותה אה מן אתימן כסיהתה ואתיקר בגליהתה ודער לגו עננה ולבש קרן אורה ואתעתד לה מסו גדול מן רומה למרבהתה מבלד מדעי ישראל עדהן לא יעמו צלמה האן נבי דמותך לא קם ולא יקום יגדל חילה רבה דשגרך רחמת מרך ורחמך יקרת יתה ויקרך ומד פקדך נטרת לא הוזפת ולא בצרת מכן אתה סמן לטביה ועורי דיאן לבישיה טוב מי ילך בתרך ויטר מצוהתה דעל ידיך רדת וילה למן דלא שמע לך דו מקים נפשה בעשדה רבה ירום משה נביה דגלה לן אלין סודיה','הcame like a king with a glorious crown on his head, and stood before 
the great prophet Moses and began speaking and said: “O Son of the House of 
God, O owner of the covenant, O faithful one of Divinity, O you who was entrust-
ed over the Concealed and honored in the Overt, who dwelt in the cloud and 
wore the rays of light, for whom was prepared a great veil from heaven to elevate 
him – terrifying the minds of Israel – so that they might not look upon the face. 
Where is there a prophet like you? He has not arisen and will not arise. Exalted 
be the great Mighty One who sent you! You loved your Master and He loved you. 
You honored Him and He honored you. What He commanded you, you carried 
out – you did not add to the commands nor lessen them. Thus, you are a balsam 
for the good as well as a judge for the wicked. Happy is the one who follows you 
and keeps the precepts which descended by your hands. Woe to the one who 
does not listen to you, for he places himself in great aﬄiction. Exalted be Moses 
the prophet, who revealed to us these secrets.”','בא כמלך עם כתר מפואר על ראשו, ועמד לפני משה הנביא הגדול והחל לדבר ואמר: "הו בן בית האלוהים, הו בעל הברית, הו הנאמן של האלוהות, הו אתה שהופקדת על הנסתר ונכבדת בנגלה, אשר שכנת בענן ולבשת קרני אור, ואשר הוכן לו מסך גדול מן השמים להרימו – כדי לאיים על דעות ישראל – שלא יביטו אל הפנים. היכן יש נביא כמוך? לא קם ולא יקום. יתעלה הגדול הכביר אשר שלחך! אהבת את אדונך והוא אהבך. כיבדת אותו והוא כיבד אותך. את אשר ציווך קיימת – לא הוספת על הציוויים ולא גרעת מהם. לפיכך, אתה בשם לטובים וגם שופט לרשעים. אשרי מי שהולך בדרכך ושומר את המצוות שירדו על ידיך. אוי למי שאינו שומע לך, כי הוא מכניס את עצמו לצרה גדולה. יתעלה משה הנביא, אשר גילה לנו את הסודות הללו."');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (358,'VI','21','מימר מדבק בשנים והעשרים אות',6000211,'וילן דאנן ליתן עבדין רחיק מנן לינן חכמין יתה דו מן שומיה נחת ולנן אתיהב והימנן עליו כות מן דהוה עמון הוה בגו אורה וכבודה פעלה דו ממלל אלה וכתב אדה וקבלה נביא בסימנים רמים ונחת יהוה ואזדמן עמה יהבה לה מן ימינה אל ימינה ואימנה עליו וככן אנן שבקנן הדה אימנותה והוינן אנשים שקרין גנבין שקרנן על קשטה והזלנן בתר תחמדותן וילן במה דעבדנן גנבנן חכמתה וטמרנן יתה מכן אנן צריכים נתילף מן בראים חסרנן מדעינן לה מלכין וביש עובד אנן עבדין עד אמת אבדן עד אמת תשניק ולית יתן מתפוררין לא באהן ולא באהן עד אמת אוכחו ולא בהת לו הוה ספר גלגין הוה ביש › ין ‹ עד אמת גנואן כל עת גלין ולינן בהתין מדן כמה נזדעק ולינן ענין','Woe to us, for we do not accomplish (what is) “far oﬀ” from us. We do 
not recognize that which descended from heaven and was given to us. (God) en-
trusted us with it, like (He entrusted) him who was with them. It was within the 
Light, and Glory was around it. For it was the Word of God and His handwriting. 
The prophet received it with lofy wonders, and the Lord descended and joined 
with him. He gave it to him; from His right hand to his right hand he entrusted 
him with it. We have forsaken this commission, and have been treacherous men, 
thieves. We have betrayed the True One and have walked afer our lusts. Woe to 
us for what we have done. We have stolen the wisdom and concealed it; there-
fore we need to learn from aliens. We deprived our minds; we possess it, but 
nevertheless we do what is evil. How long destruction, how long aﬄiction, and 
we do not wake up for the one or the other? How long reproof without shame? 
Were it (not) a book of praises, it would be of evil. For how long shameful deeds 
appearing all the time, while we are not ashamed of it? How much are we called 
but we do not answer?','אוי לנו, כי אין אנו ממלאים את ה"רחוק" מאיתנו. אין אנו מכירים את אשר ירד מן השמים וניתן לנו. (האל) הפקיד אותו בידינו, כפי שהפקידו בידי מי שהיה עמהם. הוא היה בתוך האור, וכבוד היה מסביבו. שכן היה דבר האל וכתב ידו. הנביא קיבל אותו בפלאות נשגבות, והאדון ירד ונצטרף אליו. הוא נתן אותו לו; מימינו לימינו הפקידו בידיו. עזבנו את הפיקדון הזה, והיינו לאנשי בגידה, גנבים. בגדנו באמת והלכנו אחרי תאוותינו. אוי לנו על מה שעשינו. גנבנו את החכמה והסתרנו אותה; לפיכך אנו צריכים ללמוד מזרים. קיפחנו את שכלנו; היא בידינו, ועם זאת אנו עושים את הרע. עד מתי חורבן, עד מתי ייסורים, ואנו אין אנו מתעוררים לא לזה ולא לזה? עד מתי תוכחה בלי בושה? לולא ספר שבחים היה זה, היה הוא לרע. עד מתי מעשי קלון נגלים כל העת, ואיננו בושים בכך? עד כמה נקראים אנו ואין אנו עונים?');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (359,'VI','18','מימר מדבק בשנים והעשרים אות',6000181,'האן הך משה ומן מדמי למשה נביא לית כותה מכל בני אדם כד אתחזי לה אלה בגו סניה אשכח קדמיו כתיב תרים ועסרים כתבים באש אכלה דבם ביר משה ארהותה והי עקרי מלי שפת עברהותה נעמינה כד כתב ארהותה ופלג קציה כמד ארשתה אלה שבק ט מן אשטרה קדמאה ומן אשטרה תניאנה שבק אשתה כתבין והנון נ ס פ צ ק ת לא ביר משה כתבה קדישה אלא בארשות אלה וזימון כבודה וצמות כל מלאכי רומה ואלהים קמאה כי בידה כתבה ואנון קעמו ורבו מצוהתה והוו מפקדים במד לאוי מתעבד אלהותה אתחזית ואקימת בריתה וכבודה הגלה ורבה טובה ומלאכיה אתו למרבה איקרה ואנון 12296 . כהלון אזדמנו ליד אדם אלהותה צערת יתה והנפחת בה נשמת חייה וכבודה כללה ברוחה גדילה והלבשו תריון תרי כלילין מן אורה רבה אלהותה יהבת בה מדע שלם וכבודה יהב לה נהירו חיולה ואף אלהותה יקרת יתה בממללה וכבודה יקרה בחכמה שלמה ומלאכיה הוו סהדים עליו במה דו עבד ואנון כהלון מצמתין בכל אתר דיתדכר אלה בה בקשט','Where is there the like of Moses and who resembles Moses, a prophet 
like whom there is none among all mankind? When God appeared to him in the 
bush, he found twenty two letters written before him with consuming ﬁre; by 
means of these Moses wrote the law. They are the fundaments of the words of 
Hebrew language. Let us contemplate him writing the Torah and dividing up its 
Qiṣṣīm, as God had commanded him. From the ﬁrst writing he lef out טand from 
the second writing he lef out six letters; they are: .ת ,ק ,צ ,פ ,ס ,נMoses only 
wrote the holy Scripture by God’s command in the presence of Glory and the 
assembly of all the heavenly angels – and God was the ﬁrst. Indeed, His writing 
was within His power, while these stood by and exalted the commandments and 
were commanded to do what is ﬁt to be done. Divinity appeared and established 
the covenant, and Glory appeared and exalted the Good, and the angels came to 
exalt what was glorious as they all assembled for Adam; the Divinity shaped him 
and blew into him breath of life. Glory perfected him with its great spirit; and the 
two of them wore two crowns of the Great Light. Divinity gave him a perfect mind 
and Glory gave him powerful insight. Divinity also gloriﬁed him with speech and 
Glory gloriﬁed him with perfect knowledge. The angels were witnesses to him of 
what he would do and they all gather in every place where God is mentioned in 
truth.','היכן יש כמשה ומי דומה למשה, נביא שאין כמוהו בין כל בני האדם? כאשר נגלה אליו אלוהים בסנה, מצא עשרים ושתיים אותיות כתובות לפניו באש אוכלת; באמצעותן כתב משה את התורה. הן הן יסוד דברי לשון הקודש. נתבונן בו כותב את התורה ומחלק את קִצִּים שלה, כפי שצווה עליו אלוהים. מהכתיבה הראשונה השמיט את ט, ומהכתיבה השנייה השמיט שש אותיות, והן: נ, ס, פ, צ, ק, ת. משה לא כתב את כתבי הקודש אלא על פי ציווי אלוהים, בנוכחות הכבוד וכינוס כל מלאכי מרום – ואלוהים היה הראשון. אכן, כתיבתו הייתה בכוחו, ואלה עמדו שם ורוממו את המצוות וצוּוּו לעשות את הראוי להיעשות. האלוהות נגלתה וכוננה את הברית, והכבוד נגלה ורומם את הטוב, והמלאכים באו לרומם את המפואר כפי שנאספו כולם למען אדם; האלוהות יצרה אותו ונפחה בו נשמת חיים. הכבוד השלימו ברוחו הגדולה; ושניהם לבשו שני כתרים של האור הגדול. האלוהות נתנה לו שכל שלם והכבוד נתן לו תובנה עוצמתית. האלוהות אף פארה אותו בדיבור והכבוד פארו בדעת שלמה. המלאכים היו לו עדים למה שיעשה, וכולם נאספים בכל מקום שבו מוזכר שם אלוהים באמת.');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (360,'VI','27','מימר מדבק בשנים והעשרים אות',6000271,'הגיבה נביה רבה משה ואמר לה רביניך ט מתודע בכלה כיתיך במד עביד ליך בעלמה כמד הויתי ריש צערה בעלמה דרבהנה נחשה וגלתה לכל דריה וכד הוה רביניך חיול מותר עזרת במקרא הנער לי מקרינה ונסבת יתיך מריש בריתה ורבית יתיך הך מד חזה אלה ורבה ביך ית עלמה הגלה בנהירו רבה וארשה יתי ארבי דריה מיסתיך אהן איקרה רבה דאתעבד ליך דכרן מרביה בניה בגסיה וכל מן ביך מתילד שלום הוא בכלה כי רביתינה עדהן הגדל וכן אלפת ישראל מד ארשתי אלה וקרית קדמיו עסרתיתה בגדל בדיל יורכון ימיך ולבדיל יתיטב לך אוי לאנש תתורך ימיו בבישה רבה פניה מן טובה עקתה רבה עד מותר','The great prophet Moses replied to it saying: “Your magniﬁcence, O ,טis 
known in everything. Indeed, you are (magniﬁed) with what was made for you in 
the world when you became the beginning of the pain which the serpent brought 
about and revealed to all the generations. When your magniﬁcence became very 
mighty you called again: ‘Remember me, (when) reading it.’ And I took you from 
the beginning of Genesis and elevated you as God had decided, and through you 
He magniﬁed the world which was revealed in great light, and He commanded 
me to exalt the generations. Enough for you this great honor done to you as a 
memorial: to carry children in the womb. And everyone born in you is perfect in 
everything, for you developed him till he grew up. So, I taught Israel what God 
had commanded me, and proclaimed before them the Ten with greatness, that 
your days may be prolonged and that it may go well with you (Deut. 5:16). Woe to 
the man whose days are prolonged in much evildoing, devoid of good, and in 
exceedingly great aﬄiction.”','ענה הנביא הגדול משה ואמר לה: "גדולתך, הו ט, ידועה בכל. אכן, גדולה היא במה שנעשה בשבילך בעולם, כשנהיית ראשית הכאב שהביאה הנחש וגילה לכל הדורות. כשנתגדלה גדולתך מאוד קראת שוב: ''זכרני בקראך בו.'' ולקחתיך מראשית בראשית ורוממתיך כפי שגזר אלוהים, ועל ידך הגדיל את העולם שנגלה באור גדול, וציוה אותי לרומם את הדורות. די לך בכבוד הגדול הזה שנעשה לך לזיכרון: לשאת ילדים ברחם. וכל הנולד בך שלם בכל, שכן אתה פיתחת אותו עד שגדל. כך לימדתי את ישראל מה שציוה אותי אלוהים, והכרזתי לפניהם את העשרה בגדולה, למען יאריכון ימיך וייטב לך (דברים ה,טז). אוי לאיש שימיו מתארכים בהרשעה מרובה, חסרי טוב, ובייסורים גדולים מאוד."');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (361,'VI','4','מימר מדבק בשנים והעשרים אות',6000041,'שומיה אסקף בלא עמודים וכללה בגוני תמחיה ועבד צורכה מנה ובה עד יודיע בכן רבות יכלותה כי ארעה עבידה עובד לקנומה והני צריכה ליד רוח שומיה לא תימר במדעך הן ארעה מיתבה על תהומה דמיה ביכלו רבה התב מדעך והבקר על חכמתה עד יהי ממללך על אהן דברה לית ארעה מתקוממה על מיה לוד מתקוממה אלא על אש ומים אלו הות על מיה הוה קנומה מאבד כל דבה מן אילן עד עשב ולזה מתלים רבים לו הוה לון חיל מרבי לון תקומה ואשתה לא מזיגה במיה הות רטובתה מכיה לכל מד בה מן אילן עד עשב עד דשא על כל דבר דבה לוד מקימה עקרים ומרביה נופים ואנשין אמרו דדן עובדה מן גרם שמשה חלצה מרן הגיבון הכה לא קצרתון באהן מימרה לא מללתון אלא על חכמה גרם שמשה מנהן אתחלץ אלא מן אורה רבה ואשתה מנה והלבשה נאר דיכלו כי לית בחיל גרם קעום לקבלה אמר לה אהן ואבקר עמה בה וליתך צריך מוזפה על כן טב לך תחכם אהן ותדע רבות באריה דכן ברא','He lifed up heaven without pillars and perfected it with various wonders. 
He supplies its needs from itself, thereby making known the greatness of His 
power. Indeed, the earth is created of its own substance, and, behold, it needs 
the plenitude of heaven. Say not in your mind that the earth is founded upon the 
depths of water by much power. Set up your mind and investigate wisdom, so 
that your word may follow this way: The earth does not rest on the water alone, 
but it rests on ﬁre and water. If it were on water only, its own substance would 
destroy all that is in it, from tree to grass. There are many examples for this. Even 
if they had any power in them that assures their existence, while ﬁre is not 
mixed with water, its moisture would harm all that is in it, from trees to grass 
and vegetation, everything that is in it. But it does carry roots and multiply 
branches. People said that our Master derived this creation from the substance 
of the sun. Reply to them now: “You have not erred in this speech. You have 
spoken only with wisdom. Whence was the substance of the sun derived unless 
from the Great Light? And the ﬁre (came) from it and vested (the sun) with the 
light of might. For it is not within the power of a substance to stand before it.” 
Tell him this and inquire along with him about this, and you need do no more. It 
is good for you to know this and realize the might of the Creator who created this.','הוא הרים את השמיים ללא עמודים והשלים אותם בנפלאות שונות. הוא מספק את צרכיהם מתוך עצמם, ובכך מודיע על גדולת כוחו. אכן, הארץ נבראה מחומרה שלה, והנה היא זקוקה למלאות השמיים. אל תאמר בלבך שהארץ יסודה על תהומות המים בכוח רב. כוון את דעתך וחקור את החכמה, כדי שדבריך יילכו בדרך זו: הארץ אינה נשענת על המים בלבד, אלא היא נשענת על אש ומים. אילו הייתה על מים בלבד, חומרה עצמה הייתה מחריבה את כל אשר בה, מעץ ועד עשב. ישנן דוגמאות רבות לכך. אפילו אם הייתה בהם כלשהי עוצמה המבטיחה את קיומם, כל עוד אין האש מעורבת במים, לחותם הייתה מזיקה לכל אשר בה, מעצים ועד עשב וצמחייה, כל אשר בה. אך היא נושאת שורשים ומכפילה ענפים. אנשים אמרו שאדוננו הוציא את הבריאה הזו מחומר השמש. השב להם עתה: "לא טעיתם בדבר זה. דיברתם בחכמה בלבד. מניין הובא חומר השמש אם לא מהאור הגדול? והאש יצאה ממנו ועטתה את השמש באור הגבורה. שכן אין ביכולת חומר כלשהו לעמוד לפניו." אמור לו זאת ובחון יחד אתו את הדבר הזה, ואין לך צורך ביותר מזה. טוב לך לדעת זאת ולהכיר את גבורת הבורא שברא את כל אלה.');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (362,'VI','37','מימר מדבק בשנים והעשרים אות',6000371,'עמי איקר כל אחד מן אלין ורבי כל אחד על פי דרגה קדישות יצרה לא יחשב תועבה אלאן טבה ואדכיות פגרה לא יקרב ליד מאדם טמא ויזהר גרמה מן מקרוב חובה ואף קשיטות ממלל יברר נפשה מכל תחמדה בישה וישבע אנו לא יקרב יתה לעלם ולא יסיד על חברה סהדה שקרה ולא יקלל חרש וטוב תעתיד יהי כנוז לגרמה כניזה טבה עד ישקחנה בעקבהיתה לא תחמד מד לחברך כניזה בישה ובלש מן אלהך כניזה קשיטה והי ריש דחלתה מן מרה דכל עלמה הלא מן דחל מנה לא ידחל מן דבב דחלתה מן אלה היא תעתידה רבה מרביה מלוכה בכל זבן ועדן וכשרן גולה יקרב נפושה ומסחנה צרך יקים פקודיה דפקד אלה הלא גזוה כתיב קמיו ושלמות עובד לא יעבד תלתה עובדים בישים לא יקטל נפש ולא יסגד לצלם ולא ישכב עם אתה בעילת בעל ואנצירות לבה בדחלתה מן אלה לא יהי בר מנה','See the glory of each one of them and exalt each one according to rank. 
Holiness of conscience – let (man) not think of abhorrence, only of good. Purity 
of body – let him not approach anything unclean, and guard himself against 
drawing near guilt. True speech – let him separate himself from all wrong desire 
and swear never to approach it, or testify falsely against his fellow, or curse the 
deaf. Well-preparedness – let him hoard for himself a good treasure, so that he 
may ﬁnd it at the end. Do not desire what belongs to your fellow – an ill treasure. 
But ask your God for a righteous treasure, which is the beginning of the fear of 
the Master of all the world. For the one who fears Him will not fear any enemy. 
The fear of God is that great preparedness which elevates its possessor at any 
time and period. Fervent righteousness draws relief close, and its possessor will 
carry out the commandments which God commanded, for the reward is written 
down before him. Perfection in action – he will not do any of the three evil deeds: 
he will not kill anyone, he will not worship an idol, and will not lie with a mar-
ried woman. Devotion of heart – in the fear of God not being apart from Him.','ראו את כבוד כל אחד מהם ורוממו כל אחד לפי מעמדו. קדושת המצפון – שלא יחשוב האדם על תועבה, אלא על טוב בלבד. טהרת הגוף – שלא יתקרב לשום דבר טמא, וישמור את עצמו מהתקרבות לאשמה. דיבור אמת – שיפרוש עצמו מכל תאווה רעה וישבע שלא יתקרב אליה לעולם, ולא יעיד עדות שקר בחברו, ולא יקלל חרש. הכנה נאותה – שיצבור לו אוצר טוב, כדי שימצאנו בסוף. אל תחמוד את אשר לחברך – אוצר רע הוא. אלא בקש מאלוהיך אוצר צדיק, שהוא ראשית יראת אדון כל העולם. כי מי שירא ממנו לא יירא מאויב כלשהו. יראת האלוהים היא ההכנה הגדולה ההיא המרוממת את בעליה בכל עת ובכל זמן. הצדקה הלוהטת מקרבת את ההקלה, ובעליה יקיים את המצוות שציווה האלוהים, שכן השכר רשום לפניו. שלמות במעשה – לא יעשה שום אחת משלוש המעשים הרעים: לא יהרוג איש, לא יעבוד עבודה זרה, ולא ישכב עם אשת איש. מסירות לב – ביראת האלוהים שלא להיפרד ממנו.');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (363,'VI','17','מימר מדבק בשנים והעשרים אות',6000171,'שיאלה כדו אזין וקבע בלך ושמע לה אמת כתב אלה עסרתי מליה הוה מקדם כתב תרין ועשרים אות דאנון עקרי מלי ארהותה כד קרא כבודה קמיו עסרתי מליה דגדל בון בשרואה קרתה ואת תשקחנה לא אתחסרת אלא אות ז מיסתה יהוה אל רחום וחנון ארך אפים ורב חסד ואמת נצר חסד לאלפים נשא עון ופשע וחטאה ונקה לו ינקה פקד עון אבות על בנים ועל בני בנים על שלי ועל רביעים כד קרא קשטה קדמיו עסרתיתה קדמאיתה עזר כבודה וקרתה קמיו הגיב הוא וקרא עסרה עורי זבנה דקרא קשטה לא אתרשי לה מקרי וכד קרא כבודה אתרשי לה למקרי שרוי עסרתיתה דקראון כבודה יהוה וחסולון מלת ואמת ושרוי עסרתיתה דקרא יתון משה יהוה ארך אפים וחסולון מלת רביעים','A question – listen now and pay attention and hear it. When God wrote 
the Ten Words, He already had written twenty two letters which are the funda-
ments of the words of the Torah. When Glory proclaimed the Ten Words before 
him, by which He is exalted, the ﬁrst time He proclaimed them you will ﬁnd that 
they lack only the letter זalone: The Lord […], a God merciful and gracious, slow 
to anger, and abounding in kindness and faithfulness, keeping kindness to thou-
sands, forgiving iniquity and transgression and sin, but who will not clear (the 
guilty), visiting the iniquity of the fathers upon the children and the children’s 
children, to the third and fourth generation (Exod. 34:6–7). When the True One 
proclaimed the ﬁrst ten before him, Glory proclaimed them before him further. 
(Moses) responded, and also proclaimed ten. When the True One proclaimed, he 
(Moses) was not permitted to proclaim, but when Glory proclaimed he was per-
mitted to do so. The beginning of the ten which the Glory proclaimed is ,יהוהand 
their end is the word .ואמתThe beginning of the ten which Moses proclaimed is 
 ,יהוה ארך אפיםand their end is the word .רביעים','שאלה – הקשב נא ושים לב ושמע אותה. כאשר כתב אלוהים את עשרת הדברים, כבר כתב עשרים ושתיים אותיות שהן יסוד דברי התורה. כאשר הכריז הכבוד את עשרת הדברים לפניו, שבהם הוא מתעלה, תמצא בהכרזה הראשונה שחסרה רק האות ז בלבד: ה'' [...], אל רחום וחנון, ארך אפים ורב חסד ואמת, נוצר חסד לאלפים, נושא עוון ופשע וחטאה, ונקה לא ינקה, פוקד עוון אבות על בנים ועל בני בנים, על שלשים ועל רבעים (שמות לד,ו-ז). כאשר הכריז האמיתי את עשרת הראשונים לפניו, הכריז הכבוד אותם לפניו שוב. (משה) ענה והכריז אף הוא עשרה. כאשר הכריז האמיתי, לא הותר ל(משה) להכריז, אך כאשר הכריז הכבוד הותר לו לעשות כן. תחילת עשרת הדברים שהכריז הכבוד היא יהוה, וסיומם המילה ואמת. תחילת עשרת הדברים שהכריז משה היא יהוה ארך אפים, וסיומם המילה רביעים.');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (364,'VI','55','מימר מדבק בשנים והעשרים אות',6000551,NULL,'Then ( )קarose and replied to him: “Perhaps it is appropriate to return to 
the True One. For the Concealed acts concern the Lord […] and the Overt (Deut. 
29:28); when He wants, He does it. Behold an evil house, a provocative one, and 
all which is in it is wicked. O congregation, beware of that house and do not pass 
over to it, for it is not in your power to alter it. If you hate it, your honor will be as 
it is, and if you love it, it will be your end. If you say: ‘I will not pass over to it’, 
the name of the Lord will be called over you, and all your foes will fear you. The 
glory of your fathers will last for you and what they covenanted for you will never 
be changed for you. Be awake to that which you understand of a perfect action 
which elevates its owner.”','אז קמה קוף והשיבה לו: "אולי ראוי לשוב אל האמת. כי הנסתרות עניינן לה'' [...] והנגלות (דברים כט,כח); כאשר הוא חפץ, הוא עושה. הנה בית רע, מרגיז, וכל אשר בו הוא רשע. הה עדה, היזהרי מן הבית ההוא ואל תעברי אליו, כי אין בכוחך לשנותו. אם תשנאי אותו, כבודך יישמר כפי שהוא, ואם תאהבי אותו, הוא יהיה קצך. אם תאמרי: ''לא אעבור אליו'', שם ה'' יקרא עליך וכל אויביך יירָאו ממך. כבוד אבותיך יתמיד לך ומה שכרתו בריתם לך לא יוחלף לך לעולם. היי ערנית לאשר תבינו ממעשה שלם המרומם את בעליו."');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (365,'VI','50','מימר מדבק בשנים והעשרים אות',6000501,'כד שמע משה אלין מליה הגיב הגבו כהלה קשט לך נמי סגי מכל הדה בך צורהתה הכללו ליתיך בעיה סהד לבר מן אהן מכן אתי ארש וכל איטבו לך וסגי מן הדה אתעבדתי ריש חייה במצות אלה לא הנער אלה מצוה אלא בשמיך ואתי שקחיה בה דצ יקרת לשרה וקעמת עם משה ואף עם ישראל בכל צבעתה דתסק מנון וכל מצות יהוה אנון מוקמים בה וארהותה בכן סהדה והוא גלי קמיכון בלשת דכרן בריש קציה ולא תהי חדלה מכן אנן למה דן נבטל מן דכרנה בארהותה והיא בנן קעמת','When Moses heard these words, he replied with an answer wholly true: 
“You have a larger share than all this. By you, creations were perfected. You do 
not need testimony apart from this. You are an origin, all wellbeing is yours, and 
more than that: you were made the head of life by the command of God. He did 
not record His commandment except by your name and you are found in it.” For 
 צhonored Sarah and stood with Moses as well as with Israel in every cry that 
came forth from them. All the Lord’s commandments are established by it, and 
the Torah testiﬁes of that – and this is obvious to you. צsought a mention in the 
beginning of the Qiṣṣīm and it will not be cut oﬀ from that! Why should we cease 
from its mention in the Torah, while צis within us?','כששמע משה את הדברים האלה, השיב תשובה שכולה אמת: "חלקך גדול מכל זה. בך נתשלמו הבריאות. אין אתה צריך לעדות מעבר לכך. אתה מקור, כל הטוב שלך, ויתר על כן: הוצבת לראש החיים בפקודת האל. הוא לא רשם את מצוותו אלא בשמך ואתה נמצא בה." כי צ כיבד את שרה ועמד עם משה וגם עם ישראל בכל זעקה שיצאה מהם. כל מצוות ה'' מבוססות עליו, והתורה מעידה על כך – והדבר גלוי לך. צ ביקש אזכרה בראשית הקיסים ולא יינתק ממנה! מדוע נחדל מהזכרתו בתורה, בעוד שצ בתוכנו?');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (366,'VI','1','מימר מדבק בשנים והעשרים אות',6000011,'מודאה לאלה אלהיה קני אלהותה מסחן אורכותה ממן שלטנותה מר יחידאותה אחד פרד גדול נורא נאמן צעור תקן כלה במימרה בלא עזר ולא שותף ולא תניאן ולא בעל ולא חבר עמו רבותה ושבחו יכלותה על גוני עבידהתה','Thanks be to the Great God, Owner of divinity, Eternal, enduring in sov-
ereignty, Master of uniqueness, One, Alone, Great, Awesome, Faithful, Creator, 
Establisher of all with His word, with no aid and no associate, and no deputy, 
and no partner, and no companion. Contemplate His greatness and praise the 
power he has over His various creations.','תודה לאל הגדול, בעל האלוהות, הנצחי, המתמיד במלכותו, אדון הייחוד, אחד, לבדו, גדול, נורא, נאמן, בורא, מכונן הכל בדברו, ללא עזר וללא שותף, ללא סגן וללא חבר וללא מלווה. התבונן בגדולתו ושבח את הכוח אשר לו על ברואיו השונים.');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (367,'VI','25','מימר מדבק בשנים והעשרים אות',6000251,'ועמונה קעם וט ונ וס ופ וצ וק ות ממללים עם נביה רבה משה ממלל ברבו וכל אחד מחיל שילה דאנון חזין חבריון קמיון כתיב בון שרוי קציה ואנון לא הכתבו שרוי ולא קצה לגו אהן ביורה והן הוה כתבה לא הוה בצר במליה מנון דצריך מליו יסחן אהן ולא יגרע מנון אות אחד כי לית מליה דבון הכלל כתבה רבה בצר שרוי קציה דפלגו ב » י « כולה גדילה עמו כל מלה מן אלין מליה ממללה עם נביה רבה משה ממלל ברבו','See him standing while ת ,ק ,צ ,פ ,ס ,נ ,טspoke a speech in greatness with 
the great prophet Moses, each one emphasizing its question. For they saw their 
companions before them written as beginnings of the Qiṣṣīm, while they 
remained unwritten at the beginning and in (the headings of) any Qiṣṣa of this 
composition, although the Book was not deﬁcient in words that (contain) them. 
For there is need that its words contain (all of) them, and not one letter of them 
would be absent. Indeed, the words of which the Great Book was completed are 
not deﬁcient (in letters) at the beginning of the Qiṣṣīm, which were divided with 
great ability. See how each one of these letters speaks with the great prophet 
Moses a speech of greatness.','ראה אותו עומד בשעה שט, נ, ס, פ, צ, ק, ת נשאו דברים בגדולה עם הנביא הגדול משה, כל אחד מדגיש את שאלתו. שכן ראו את חבריהם לפניהם כתובים כראשי הקיסים, בעוד שהם נותרו לא כתובים בראש ובפתיחת כל קיסה בחיבור זה, אף שהספר לא היה חסר תיבות המכילות אותם. שכן יש צורך שתיבותיו יכילו את כולם, ולא תיעדר מהם אות אחת. ואמנם התיבות שבהן הושלם הספר הגדול אינן חסרות בראשי הקיסים, שחולקו בכישרון רב. ראה כיצד כל אחת מן האותות הללו מדברת עם הנביא הגדול משה דברי גדולה.');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (368,'VI','15','מימר מדבק בשנים והעשרים אות',6000151,'אלהותה אמרת לה אתי בשלם בדילך אתחזית למגלי סימני כבודה אמר לה אתי בשלם אני מעביר יקירותי קמיך מלאכיה אמרים לה אתי בשלם מהימן אלהים לינן יכלין פסחים מנך לעלם איקרה אמר לה שלם לך מיסטה ליתי לאוי לאנש בר מנך טובה אמר לה שלם עליך נומיקה דאנה עתיד למוקרך קדשה אמר לה שלם עליך אישה בדילך אתעבדת ארבי כל איטבו אימנותה אמרת לה שלם עליך נגודה דנגד שת מון דאלף זכותה אמרת לה שלם עליך ילידה דתרבה בתדי תרביה חסידה','The Divinity said to him: “Come in peace. For your sake I appeared to 
reveal my wonders.” Glory said to him: “Come in peace. I will make my glory 
pass before you.” The angels said to him, “Come in peace, O faithful one of God. 
We cannot turn away from you ever.” Honor said to him: “Peace to you, O middle 
man, I am ﬁtted for no man (to deal with) but you.” The Good One said to him: 
“Peace to you, O Lawgiver. I am about to honor you.” The Holiness said to him: 
“Peace to you, O Man, for your sake I was made, to multiply all good.” The Faith 
said to him: “Peace to you, O leader who led six hundred thousand.” The Righ-
teousness said to him: “Peace to you, O child reared at the breast of a good 
nurse.”','האלוהות אמרה לו: "בוא בשלום. למענך נגליתי לגלות את נפלאותי." הכבוד אמר לו: "בוא בשלום. אעביר את כבודי לפניך." המלאכים אמרו לו: "בוא בשלום, נאמן האלוהים. לעולם לא נוכל להתרחק ממך." הכבוד אמר לו: "שלום לך, אמצעי, אני ראוי לאיש אחד בלבד והוא אתה." הטוב אמר לו: "שלום לך, מחוקק. אני עומד לכבדך." הקדושה אמרה לו: "שלום לך, איש, למענך נוצרתי, להרבות כל טוב." האמונה אמרה לו: "שלום לך, מנהיג שהנהיג שש מאות אלף." הצדק אמר לו: "שלום לך, ילד שגדל על ברכי מינקת טובה."');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (369,'VI','63','מימר מדבק בשנים והעשרים אות',6000631,'כד שמע נביה רבה משה הדה מימרה זרז בהגבו ואמר כל קצה דאתעבד לה שרוי בכתב מנוכון קשטה על עודנה לית תמן בצר והן הוו אלין לא הכתבו בשרוי קציה דברון ממן על מהו לא יתר ולא פעת וספר ארהותה צמת לכהלון לא בצר מנון כתב אחד תמן הגבותה הגבו חיולה בלשו בה מה ירבי יתון אנן בעין מנך כדו תגלי רבינה דלנן דמות חברינן הגיבון נביה רבה משה הגבו מרבי השמועים ומיקר אלופים ישרי כל אחד ימלל ממללה ויחכם הך הי מיתוביתה','When the great prophet Moses heard this speech, he hurried to answer 
and said: “Every Qiṣṣa which has a beginning with one of your letters is right in 
its own case. There is no deﬁciency there. Even if they are not written in the be-
ginnings of the Qiṣṣīm, their state remains just as it was, no more and no less, 
and the book of the Torah included them all, lacking not a single letter.” Then 
they replied to him in a vehement response in which they requested that which 
would magnify them: “We ask you now that you reveal our majesty like (you did 
with) our companions.” The great prophet Moses answered them with an an-
swer, elevating the listeners and honoring those who learn: “Let each one begin 
and say its speech and realize what its rank is.”','כשמשה הנביא הגדול שמע דברים אלה, מיהר לענות ואמר: "כל קיסה שתחילתה באחת מאותיותיכם צודקת בעניינה. אין שם כל חסרון. ואפילו אינן כתובות בראשי הקיסות, מצבן נותר כשהיה, לא פחות ולא יותר, וספר התורה כלל את כולן ולא חסרה אות אחת." אז השיבו לו בתשובה נמרצת שבה ביקשו את אשר ירוממם: "אנו מבקשים ממך עתה שתגלה את רוממותנו כמו שעשית לחברותינו." משה הנביא הגדול ענה להם תשובה המרוממת את השומעים ומכבדת את הלומדים: "שתחל כל אחת ותאמר את דבריה ותכיר מה היא מעלתה."');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (370,'VI','33','מימר מדבק בשנים והעשרים אות',6000331,'ואנון מוקדים לגו משכנה › ב ‹ נורה מן יכל יקרב ליתה אתרה מן יכל קעם לפני כרוביה וקלה דאלה ממלל עמה מנו משרי מלי סליחתה ובניו עמה מן יכל ידמי לון מד אנון מחסלין מן יכל עמון ימלל מלה חדה מן יכל יטהר מדאנון מטהרין אי יטמי מדאנון מטמאין מן לון הדה מיתוביתה רמתה כהלון לבשו כליל דנביותה האן דמות כהנתה דגלת בעלמה והות נון שרוה ועקבה מיסתיך נון במד הוה לך ליתיך צריכה לחורן כן אנשי דרה הדבקו בדן ודעו למה לא אתעבדת שרוי קצה דהי שרוי נביותה ועקר כהנתה ומניאן חלקי כהנתה ורחב משכנה במניאני וכן ארכה כפלי לכן צרך אהרן יקום בתשמיש מקדשה כי דרג כהנתה חיול › ה ‹ שריר וריש כל איקרים בידיך הוא','“They burn (it) on the ﬁre within the Sanctuary – who can attain that 
rank? Who can stand before the Cherubim when the voice of God speaks to him? 
Who begins the words of Forgiveness while his sons are with him? Who can 
compare with them when they pass sentence? Who can speak one word with 
them? Who can purify what they purify, or declare deﬁled as they declare 
deﬁled? Who possesses such lofy rank? All of them wear the crown of prophet-
hood. Where is there the like of the priesthood, revealed in the world the begin-
ning and end of which was .נThat which took place for you is enough for you, O 
 .נYou do not need anything else.” “O people of this generation, cling to this and 
know why ( )נwas not put in the beginning of any Qiṣṣa. For it is the beginning of 
prophethood and the essence of priesthood, and the number of the portions of 
the priesthood and the breadth of the Sanctuary correspond to my number. Fur-
thermore, its length is double my number.” Therefore, Aaron needed to remain 
in the service of the holy place. Indeed, the rank of the priesthood is very mighty 
and the ﬁrst of all honors is in your hands.','"הם שורפים אותו באש בתוך המקדש – מי יכול להגיע למעמד זה? מי יכול לעמוד לפני הכרובים כאשר קול אלוהים מדבר אליו? מי פותח בדברי הסליחה כשבניו עמו? מי יכול להידמות להם בשפטם? מי יכול לדבר עמהם מילה אחת? מי יכול לטהר את מה שהם מטהרים, או לטמא את מה שהם מטמאים? מי מחזיק במעמד כה נשגב? כולם עוטים את כתר הנבואה. היכן יש כמו הכהונה, הנגלית בעולם, שתחילתה וסופה היו נ? מה שאירע לך די לך, הו נ. אינך צריך דבר נוסף." "הו אנשי הדור הזה, דבקו בזה ודעו מדוע לא הושמה (נ) בראשית שום קיסה. כי היא תחילת הנבואה ועצם הכהונה, ומספר חלקי הכהונה ורוחב המקדש תואמים את מספרי. ועוד, ארכו כפול ממספרי." לפיכך היה על אהרן להישאר בעבודת המקום הקדוש. אמנם, מעמד הכהונה אדיר מאוד, והראשון שבכל הכבודות נמצא בידיכם.');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (371,'VI','67','מימר מדבק בשנים והעשרים אות',6000671,'אזלת ב אתת ג ושרית דברה ואמרת אה נביה רבה משה ארשי לי אמלל דמות חברי דשרו ממללה אלית שמי עביד פוגגו לנפשהן מרבי חכמה ומחיל דעה האן אנה דעארה לית יהי עכר והאן אנה מתחזיה לית תמן צדו מה אנה מרביה גדולים האן דאנה קעמה לא יהי גדול אלאן בשמי ינהר ידועה לכן ויבלשנה יתיטב נהרה ותגדל שלמותה כי חכמתה בעלמה כות גוזל יון בידה אגרה מבסרה ברחם ובעלי דעתה כבוצינים מנירים האן דאנון שרין קבלין חשכה מודאה לאלה דאמלתון בכן ורבה נאר לבון סגי מכל אנשיה','בdeparted and גcame and began its speech, saying: “O great prophet 
Moses, permit me to speak like my companions speaking (before me). Was not 
my name made a delight to souls, increasing wisdom and strengthening knowl-
edge? Where I dwell, there is no distress, and where I appear, there is no fear. Do 
I not magnify great men? Wherever I am, no one is great except in my name. Let 
the man of knowledge remember this and seek it – (his) illumination will im-
prove and his perfection increase. For wisdom in the world is like the nestling of 
a dove bearing a message that heralds love. And those who possess knowledge 
are like shining candlesticks; wherever they abide, they remove the darkness. 
Thanks be to God, who thus ﬁlled them with this, and magniﬁed the light of 
their heart above all men.”','ב עזב ובא ג והחל את דברו ואמר: "הו משה הנביא הגדול, הרשה לי לדבר כפי שדיברו חבריי לפניי. האם לא נעשה שמי תענוג לנפשות, מרבה חכמה ומחזק דעת? באשר אני שורה, אין מצוקה, ובאשר אני מופיע, אין פחד. האם אינני מגדיל גדולים? בכל מקום שאני שם, אין איש גדול אלא בשמי. יזכור זאת בעל הדעת ויבקשנו – אורו ישתפר וכמלותו תגדל. שכן החכמה בעולם דומה לאפרוח יונה הנושא שליחות המבשרת אהבה. ובעלי הדעת דומים למנורות מאירות; בכל מקום שהם שוכנים, הם מסירים את החשך. תודה לאל שכך מילא אותם בזאת, והגדיל את אור לבם מעל כל בני האדם."');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (372,'VI','20','מימר מדבק בשנים והעשרים אות',6000201,'אה גנה טבה בה כל אילן טב פריו מכללין מן מעונה עלאה אה גנה טבה בה כל אילן טב שרשה במכה וטרפה במעונה אה גנה טבה בה כל אילן טב הנטע במעונה ובמכה אתחיל אלהותה נטעת יתה וכבודה פרנסתה וקשטה כסתה עד האן אתא משה אה ביר מים חיים חפיר ביד נביא לא קם מן אדם כותה ומיה דלגוה מפם אלהותה נסבע מן פריה דלגו הדה גנתה ונשתי מן מימיה דלגו אהן בירה לינן צרכין נבלשנה באתר לית לן יכלה למברטה לידה לא בשומיה הוא ולא במגוז ימה בפמה ובלבה הו עביד','Behold a ﬁne garden in which every ﬁne tree has its fruit perfected from 
the Heavenly Abode. Behold a ﬁne garden in which every ﬁne tree has its root in 
earth and its foliage in the Divine Abode. Behold a ﬁne garden in which every 
ﬁne tree is planted in the Divine Abode and strengthened on earth. The Divinity 
planted it and Glory tended it and the True One concealed it until Moses came. 
Behold a well of living water dug by a prophet, like whom none has arisen from 
Adam onwards. The water in it comes from the mouth of the Divinity. Let us be 
sated by the fruit in this garden and drink of the waters in this well. We do not 
need to seek it in a place which we are unable to reach. It is not in heavens […] 
neither is it in the crossing of the sea […] (Deut. 30:12–13). It is in the mouth and in 
the heart.','הנה גן נאה שבו לכל עץ נאה פרי משוכלל ממעון השמים. הנה גן נאה שבו לכל עץ נאה שורש בארץ ועליוותיו במעון האל. הנה גן נאה שבו כל עץ נאה נטוע במעון האל ומושרש בארץ. האלוהות נטעה אותו והכבוד טיפח אותו והאמת הסתירה אותו עד שבא משה. הנה באר מים חיים שחפר נביא, אשר כמוהו לא קם מאדם ואילך. המים שבה באים מפי האלוהות. נשבע מפרי הגן הזה ונשתה מהמים שבבאר הזו. אין אנו צריכים לבקשה במקום שאיננו יכולים להגיע אליו. היא אינה בשמים [...] ולא מעבר לים [...] (דברים ל,יב-יג). היא בפה ובלב.');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (373,'VI','65','מימר מדבק בשנים והעשרים אות',6000651,'הגיבה נביה רבה משה ואמר לה לך סגי מכן אתי עקר מפתח פמה לא יפק מנה מלה אלא ואתי שרוה ואתי שרוי אהיה אשר אהיה אני אני הוא כל הדה לך עביד','The great prophet Moses answered, saying to it: “You have more than 
that – you are the origin of the opening of the mouth; no word exits from it 
unless you come ﬁrst, for you are the beginning of ( אהיה אשר אהיהExod. 3:14) and 
of ( אני אני הואDeut. 32:39). All this has been done for you.”','ענה משה הנביא הגדול ואמר לו: "יש לך יותר מזה – אתה מקור פתיחת הפה; אין דבר יוצא ממנו אלא אם כן אתה בא ראשון, שכן אתה ראשית אֶהְיֶה אֲשֶׁר אֶהְיֶה (שמות ג,יד) וראשית אֲנִי אֲנִי הוּא (דברים לב,לט). כל זה נעשה למענך."');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (374,'VI','41','מימר מדבק בשנים והעשרים אות',6000411,'עמו ס קעמה קדם נביה רבה משה אמרה אה מהימנה דביאר ארהותה אה מן נבתה אלה ואלבשה שמה וזעק שמה עבדה ואישה ומהימן ביתה ומיסטה טבה ונגודה יקירה ונומיקה דל ה עמו כל מלה מן אלין מליה עבדה דאלה דרס לגו אשתה והות כטל כתי רגליה ואיש חבר יכלתה דגלת יכלותה בכל עובדיו ומהימן ביתה כד קבל לוחיה ושבינון לגו ארונה ולא יכל למקרוב לידון סעד אזדעק והמלל ומיסטה טבה דשמע מן מרה אלפה לישראל כמה דאמר כמד פקדני יהוה אלהי ונגודה יקירה דו נגד כל ישראל והוה לבון עמה לא אמטה בון רגז וכד סטו ובלשו לון נגד בר מנה הוו בבישה רבת לון אבדנה ואלולי בלישת משה מהימנה הוו כהלון אבדין כאנשי סדם ונומיקה דעלמה הודעת יתן דו פרד לא קם כותה ולא יקום לעלם','See סstanding before the great prophet Moses, saying: “O faithful one, 
who wrote the Law, O (you) to whom God gave prophethood, and whom He 
vested with His name, and whose name He called “servant” and “Man” and “the 
faithful of His House” and “good middle man” and “honored leader” and “His 
lawgiver”. Contemplate each of these words. The servant of God (Deut. 34:5) – he 
trod in the ﬁre and it was like dew under his feet. Man (Exod. 11:3) – the 
powerful, whose power was manifest in all his deeds. The faithful one of His 
House (Num. 12:7) – when he received the tablets and placed them in the ark, he 
was unable to draw near to them until he was called and addressed. Good middle 
man – what he heard from his Master he taught Israel, as He said: As the Lord my 
God commanded me (Deut. 4:5). Honored leader, for he led all Israel – when their 
heart was with him, no anger came upon them; when they went astray and 
requested a leader other than him, they were in evil, which increased 
destruction upon them. Were it not for the request of Moses the faithful one, they 
would all have perished like the People of Sodom. The lawgiver of the world – 
(this) informs us that he is unique; none like him has arisen and will never arise.','ראה את ס'' עומדת לפני משה הנביא הגדול ואומרת: "אמונתי, אשר כתב את התורה, אתה אשר נתן לך אלוהים את הנבואה והלבישך בשמו, וקרא לשמך ''עבד'' ו''איש'' ו''נאמן ביתו'' ו''מתווך טוב'' ו''מנהיג נכבד'' ו''מחוקק שלו''." התבונן בכל אחד ואחד מן המילות הללו. עבד אלוהים (דברים לד,ה) – דרך באש והייתה כטל תחת רגליו. איש (שמות יא,ג) – הגיבור, אשר גבורתו הייתה נגלית בכל מעשיו. נאמן ביתו (במדבר יב,ז) – כאשר קיבל את הלוחות והניחם בארון, לא יכול היה להתקרב אליהם עד שנקרא ונדובר אליו. מתווך טוב – מה שמעה מאדוניו לימד לישראל, כמו שאמר: כאשר ציווני ה'' אלוהי (דברים ד,ה). מנהיג נכבד, שהנהיג את כל ישראל – כאשר ליבם היה עמו, לא באה עליהם כל זעם; וכאשר תעו וביקשו מנהיג אחר מלבדו, היו ברע שהרבה השמדה עליהם. לולא בקשת משה הנאמן, כולם היו אובדים כאנשי סדום. מחוקק העולם – מודיע לנו שהוא יחיד במינו; כמוהו לא קם ולא יקום לעולם.');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (375,'VI','8','מימר מדבק בשנים והעשרים אות',6000081,'עמי כל אלין דכעסו לאלה הך אתעבדו אלפן לכל דרי עלמה לא תשבק לקשטה אה בר › י ‹ רחומיה ולא תתנשי מה דאלפו יתך אבהתך לית לאוי לך תהי מרוד ולא תזדעק בר ארדאי ומעזי אה עלמה מכללה בכל איקר וכל דבה מן איקרה אמסיר הוא לך אה איקרי שומיה מרבים לך ומחילים לך איטבו בדיל מקוממאתך לא תשבק קנומך פסול מכן ותהי מסרבך ביני כל בוראי עלמה טול מן ארח פנותה דהי אכלה דיאריה ומרביה לון כל תשניק וילה לאנש דידור לגו אתר יחזי בה אבדנה ולא יטול מנה חסיר מדעה מן יעבד אהן ויקים נפשה בעקה רבה','See all these who provoked God – and how they became an example to 
all the generations of the world. Do not desert the truth, O son of the beloved, 
and do not forget what your fathers have taught you. It is not appropriate for you 
to be rebellious, and to be called rebellious and capricious son (Deut. 21:18). 
Behold the world, perfect in every glory; all the glory in it is appointed for you. 
These heavenly glories exalt you and strengthen you with beneﬁts for main-
taining you. Do not remain rejected from this, for you would become confused 
among all the creatures of the world. Move away from the path of Disfavor, for it 
devours its inhabitants and increases all aﬄiction for them. Woe to any man who 
dwells in a place where he sees destruction yet does not move away from it! 
Mindless is he who acts like this and places himself in great trouble.','ראה את כל אלה שהכעיסו את האל — וכיצד נעשו לאות מוסר לכל דורות העולם. אל תעזוב את האמת, בן האהוב, ואל תשכח את מה שאבותיך לימדוך. אין זה ראוי לך להיות סורר, ולהיקרא בן סורר ומורה (דברים כא,יח). הנה העולם, שלם בכל הדרו; כל ההדר שבו מיועד לך. הדרות השמיים הללו מרוממות אותך ומחזקות אותך בטובות לקיומך. אל תישאר מנודה מזה, שאם כן תתבלבל בין כל יצורי העולם. סור מדרך החרון, שכן הוא אוכל יושביו ומרבה להם כל צרה. אוי לכל אדם הדר במקום שהוא רואה בו השחתה ואינו סר ממנו! חסר דעת הוא מי שנוהג כך ומכניס עצמו לצרה גדולה.');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (376,'VI','14','מימר מדבק בשנים והעשרים אות',6000141,'עמי דן נביה רבה משה דאסקף אלה אתרה בתרי עלמיה ויקר קנומך במד לה תשמע עמי אורה הך ארכן קדמיו כד עלל לגוה וקבל לוחיה עמי חשכה הך הטרד מקמיו ולא הוה לה עליו יכלה עמי אשתה הך ארכנת גבורתה עד דרס לגוה והות לה כות טלה עמי מיה הך אמתנת גלליה דחלה מנה כד אתרמי בה','Consider this great prophet Moses whose position God exalted in both 
worlds, and honor yourself in what you will hear. See how the light submitted 
before him when he entered into it and received the tablets. See how the dark-
ness was banished before him and had no power over him. See how the ﬁre 
submitted its power, so that he trod in it and it was like dew to him. See how the 
water stilled its waves in fear of him, when he was cast into it.','התבונן בנביא הגדול הזה, משה, אשר אלוהים רומם את מעמדו בשני העולמות, וכַבֵּד את עצמך במה שתשמע. ראה כיצד האור נכנע לפניו כשנכנס אליו וקיבל את הלוחות. ראה כיצד החושך גורש מפניו ולא היה לו כל שליטה עליו. ראה כיצד האש השפילה את כוחה, עד שדרך בה והייתה לו כטל. ראה כיצד המים השקיטו את גליהם מיראתו, כאשר הושלך לתוכם.');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (377,'VI','23','מימר מדבק בשנים והעשרים אות',6000231,'טב לן נעזר אל מד הוינן בה מן מליה אנן עליה מבקרין כד אשמע אלה קלה בטור סיני מרבאה למשה ומעמי שלמותה הוה ישראל הך אמר לית מרה דעלמה ממלל עם משה אתחזי גדלה ומלל עמה ואנון כהלון שמעין ודחלין תמן אמרו למשה מהימנה קרב אתה ושמע לית בנן לכן אהן הך משה שלחי קשטה ומהימן בית אלה ועבדה נגש לערפלה קדישה דתמן אלהותה ועמה תמחי כסיהתה חזו לית בחיל חורנה יחזי יתה צלמה שרה בה מד בלד כל חזוי ולא יכל אנש יקום קבלה פמה הוה הך פרת מגלגל מים חיים מרוים למן דשתי מנון לשנה כחרב שליף מנצע לרגזה ומעזר יתה בפרי לבה הוה הך הגן כל פר דבה חיים וברכה יצרה הוה כאילן חייה אכל מנה לא יקרבנה מותה ענינה הוה כפתור מברך וטעמה דעליו מן טעמה דקשטה חשבה דלה כמנורה ובוציניה מעמרים ביד מלכה דבראתה מן דאמלך בה לא טעי לעלם אורה קמיו ימטינה לפצותה אדיו קבל בון כיר אדה דאלה והוה אוצר לכל חכמה גויתה המזג עם מלאכי רומה ודער עמון והוה מלוא בכן ממללה דמי לממלל מרה וכל דאמר לה מרה הוה עשה קלה הזדוג עם קלה דמרה ואתחיל בכן מכל בני אדם רגליו דרס בון אשתה רבתה והות לה כטל רסס כתי רגליה האן בעלמה נביא ידמי למשה בסימניו דגלה אי כפליהתה דעבד','It is good for us to return to what we were dealing with, to the matters 
about which we were inquiring. When God made His voice heard on Mount 
Sinai, to elevate Moses and to manifest perfection, it was as though Israel were 
saying: “The Master of the world does not speak with Moses.” (Then) His Great-
ness appeared and spoke with him, while they were all listening and fearful. 
They then said to Moses: “O faithful one, draw near and listen (Deut. 5:27), for we 
cannot (do) so.” Where is there anyone like Moses, messenger of the True One, 
appointed to the House of God, and His servant? He drew near to the holy thick-
ness where Divinity was, and saw the wonders of the Concealed – a sight no one 
else can see. His face – on it dwelt that which frightens every beholder, and no 
one can stand before it. His mouth was like the Euphrates, rolling with living 
waters which quench the thirst of all who drink of them. His tongue was like a 
drawn sword that defeats wrath and turns it back quickly. His heart was like the 
Garden; all its fruit was life and blessing. His conscience was like the Tree of Life; 
he who eats of it, death does not approach him. His thought was like a blessed 
table, its food is the food of the True One. His reason was like a candlestick, its 
candles set up by the King who created it; he who receives its counsel will never 
stray; the light before him will bring him to salvation. His hands – with them he 
received the handwriting of God and it was a treasury of all knowledge. His body 
mingled with the angels of the height and he dwelt with them, being worthy to 
do so. His speech resembled the speech of his Master; he carried out all that his 
Master said to him. His voice mingled with the voice of his Master, and thus he 
was exalted above all mankind. His feet – he trod with them (in) the great ﬁre 
and it was like dew sprinkled under his feet to him. Where in the world is there a 
prophet resembling Moses in the wonders he revealed, or like him in the 
miracles which he performed?','טוב לנו לשוב אל מה שעסקנו בו, אל העניינים שחקרנו. כאשר השמיע האל את קולו בהר סיני, להרים את משה ולגלות שלמות, היה כאילו ישראל אומרים: "אדון העולם אינו מדבר עם משה." אז נגלה גדלו ודיבר עמו, בעוד שכולם שומעים ויראים. אמרו אז למשה: "אמן, גשה ושמע (דברים ה,כז), כי אין אנו יכולים (לעשות) כן." היש כמשה, שליח האמת, הממונה על בית האל ועבדו? הוא ניגש אל הערפל הקדוש שבו הייתה האלוהות, וראה פלאות הנסתר — מראה שאיש אחר אינו יכול לראות. פניו — עליהן שכן אשר מפחיד כל רואה, ואיש אינו יכול לעמוד בפניהן. פיו היה כנהר פרת, גואה במים חיים המרווים את כל השותים מהם. לשונו הייתה כחרב שלופה המביסה את הזעם ומשיבה אותו מהרה. לבו היה כגן העדן; כל פריו חיים וברכה. מצפונו היה כעץ החיים; מי שאוכל ממנו — המוות אינו מתקרב אליו. מחשבתו הייתה כשולחן מבורך, אוכלו הוא אוכל האמת. שכלו היה כמנורה, נרותיה ערוכים בידי המלך שבראה; מי שמקבל עצתה לא יתעה לעולם; האור שלפניו יביאנו לישועה. ידיו — בהן קיבל את כתב יד האל, והיה אוצר כל הדעת. גופו נתערב עם מלאכי המרום, ודר עמהם, בהיותו ראוי לכך. דיבורו דמה לדיבור אדונו; קיים את כל אשר אמר לו אדונו. קולו נתערב בקול אדונו, וכך הורם מעל כל בני האדם. רגליו — בהן דרך באש הגדולה, והייתה לו כטל מזולף תחת רגליו. היש בעולם נביא הדומה למשה בפלאות שגילה, או כמוהו בנסים שעשה?');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (378,'VI','31','מימר מדבק בשנים והעשרים אות',6000311,'עמי נון אתיה ממללה בדיל קנומה הן הות טית לה כל אלין עקובהתה כי מרי רבה בי עסרה עקרים במניאני הות ארבעה גדלת בריתה והן הות עסרה עקרים אתחזי אלה ופלגון ואתית ליד שבתה וקעמת קבלה ואנסבת מנה חלק ליתה רבינה ואתית ליד נח ואזדמנת עמה וארשתה מרה ימלכני ועבדי עקר › ב ‹ שמה וחדה בכן וחכם דו איקר לה ואמרת למשה מה אתית לך ואת רמי לגו › נהרה ‹ ולא יהבת אד תקרב לידך מה הגלית לך בסימנים רמין וחילת יתך רבו רבה מה שמשתך מן ספת ימה עד ספת ימה מה פוררת אחוך והוית עליו כליל קדש וחלקיו במניאני כי יתון חלקים רמין לית בון פגול כהלון קדישים ובשם אהרן ובמשכן הכל במניאני עביד ואלהה דכלה כדן בלש ומן אהרן ומן משכנה רביאני קעם ורבית פינחס ועבדת לה אתר וליתי פריקה מנה לעלם דו ארשה דפרקנה ולה כהנתה רבתה ולזרעה בתרה','See how נcomes speaking on its own behalf: “If טhad all these qualities, 
then my Lord has magniﬁed ten fundaments in me. In my number are the four 
that developed the Creation. And if there are ten fundaments, God appeared and 
divided them. And I came to the Sabbath and stood before it and took from it a 
part of its grandeur. I came to Noah and joined him. The Master commanded him 
to possess me and He made me a fundament in his name, and he rejoiced at this 
and realized that it was an honor to him. I said to Moses: Did I not come to you 
when you were cast into the river and did I not let a hand reach you? Was I not 
revealed to you in great wonders and did I not strengthen you with great power? 
Did I not serve you from one shore of the sea to the other? Did I not spur your 
brother on and become a holy crown on him, the parts of which are in my 
number? Indeed, these were lofy portions with no ﬂaw, all of them holy. (I am) 
in the name Aaron and in the Sanctuary, all made by my number. When the God 
of all sought it, majesty arose from both Aaron and the Sanctuary. I elevated 
Phinehas and made for him a rank and I am never removed from it. For it is the 
root of deliverance. The High-priesthood is his and his descendants’ afer him.”','ראה כיצד האות נ באה ומדברת מטעם עצמה: "אם ל-ט היו כל התכונות הללו, הרי אדוני הגדיל בי עשרה יסודות. במספרי נמצאים ארבעת אלה שפיתחו את הבריאה. ואם ישנם עשרה יסודות, נגלה אלוהים וחילקם. באתי אל השבת ועמדתי לפניה ולקחתי ממנה חלק מגדולתה. באתי אל נח והצטרפתי אליו. האדון ציווה אותו לקחת אותי לנחלה ושמני יסוד בשמו, והוא שמח בכך והבין כי זו כבוד לו. אמרתי למשה: האם לא באתי אליך כשהושלכת אל היאור, והאם לא הגעתי לידים שיושיטו אליך? האם לא נגליתי לך בנפלאות גדולות והאם לא חיזקתי אותך בכוח גדול? האם לא שירתי אותך מקצה הים ועד קצהו? האם לא זירזתי את אחיך ונעשיתי לו כתר קדוש עליו, שחלקיו הם במספרי? אמנם, אלו היו חלקים נשגבים ללא מום, כולם קדושים. (אני) בשם אהרן ובמקדש, הכל עשוי במספרי. כאשר אל הכל ביקש זאת, עלה הוד מאהרן ומן המקדש כאחד. הרוממתי את פינחס ועשיתי לו מעמד ואיני נעקרת ממנו לעולם. כי הוא שורש הגאולה. הכהונה הגדולה שלו ושל צאצאיו אחריו."');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (379,'VI','7','מימר מדבק בשנים והעשרים אות',6000071,'עמי אלין דחכמו יתה והדבקו בו בלבב ובנפש כתב בדילון ספר גלגין והכרת לון קיאם לעלם לא יבטל ובדיל מה אתעבד לקבל עמלון אנן מתוחין עם כל דר ודור וכדו חזו בישות אנשים חכמו יתה ובלשו חלופה נחשה בישה מלל בשמה וקעם באגדדו וגלה ערימה נפל מן גברו והמחק ולבש ארירה לא תסטי מנה לעלם קין חכמה ולבש אגדדותה הוקם בקלל רב מותר חנוך ובניו וכל משפחתו חכמונה ועם זה כעסותה אתו אנשי המבול ככן אתא מבולה ואבדון כעטף וכל היקום דעל ארעה אבד עמון כוש ונמרוד עורי חכמוה וקנאונה במה דעבדו וכן אנשי סדם כד שבקו מחכומה אבדו כהלון כעטף עינה אבדן ביש מותר פרעה וסיעתה כד שבקו מחכומה עמי מה בא עליון עמלק ועמו כד שבקו מחכומה אמחי דכרנון מן על אפי ארעה עבודי עגלה כד נשונה אבדו כהלון במגיפתה וחובתון משתירה עליון עד יום נקם ושלם קרח וסיעתה כד שבקו מחכ בלעתון ארעה וכסת עליון','See those who knew Him and clung to Him with heart and soul. He wrote 
a book of praises for them, and a covenant was made with them that will never 
be abolished. Due to what has been done, according to their merit, we live 
throughout all generations. And now see the wickedness of men. Know it and 
seek its opposite. The evil serpent spoke in His name and acted rebelliously and 
showed cunning; it fell from might and was blotted out and wore a curse that 
will never depart from it. Cain knew Him and wore rebellion; he was placed 
under an exceeding great curse. Enoch, his sons and all his family, knew Him, 
and despite that they provoked Him; then came the People of the Flood. Thus 
the Flood came and destroyed them in a ﬂash, and all who lived on earth 
perished with them. Cush and Nimrod also knew Him but made Him angry in 
what they did. Similarly, when the People of Sodom deserted the knowledge of 
Him, they all perished in an instant – a very bad perdition. When Pharaoh and 
his host deserted the knowledge of Him, see what befell them. When Amaleq 
and his people deserted the knowledge of Him, memory of them was obliterated 
from oﬀ the face of the earth. When the Calf-makers forgot Him, they all perished 
in the pestilence, and their guilt remains upon them until the Day of Vengeance 
and Requital. When Korah and his party deserted the knowledge of Him, the 
earth swallowed them up and covered them.','ראה את אלה שהכירוהו ודבקו בו בלב ובנפש. הוא כתב עבורם ספר שבחים, וכרות אתם ברית שלא תבוטל לעולם. בזכות מה שנעשה, לפי זכותם, אנו חיים בכל הדורות. ועתה ראה את רשעת בני האדם. דע אותה ובקש את הפכה. הנחש הרע דיבר בשמו ומרד וגילה ערמה; הוא נפל מגדולתו ונמחה ולבש קללה שלא תסור ממנו לעולם. קין הכירו ולבש מרד; הוא הושם תחת קללה גדולה מאוד. חנוך, בניו וכל משפחתו הכירוהו, ואף על פי כן הכעיסוהו; ואז בא דור המבול. כך בא המבול והחריבם ברגע, וכל היושבים על פני האדמה אבדו עמם. כוש ונמרוד גם הם הכירוהו אך הכעיסוהו במה שעשו. וכן אנשי סדום כאשר עזבו את הכרתו, כולם אבדו ברגע אחד — אובדן רע מאוד. כאשר פרעה וחילו עזבו את הכרתו, ראה מה קרה להם. כאשר עמלק ועמו עזבו את הכרתו, זכרם נמחה מעל פני האדמה. כאשר עושי העגל שכחוהו, כולם אבדו בדבר, ואשמתם עומדת עליהם עד יום הנקמה והגמול. כאשר קורח וכיתתו עזבו את הכרתו, הארץ בלעה אותם וכיסתה עליהם.');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (380,'VI','48','מימר מדבק בשנים והעשרים אות',6000481,'עמו צ קעמה ממללה ממלל ברבו וכלה שמיע ממללה ומשה קבלה מתמח מן ממללה אמרת אה נביה רבה משה אתהו דנאר לבך יתיר על נהרה דשמשה כי שמשה מרביה צורכי נפשהתה ואתהו דאנדיך מד בה תתוחי נפשהתה שמשה בלבה דשומ » י « ה דנחה ביומה אתעבד שלטנה בחיל דברתה ולבך דאר במעונה עלאה בפם יכולה דברא יתה ויתבה לכן אתה דמלאת ארעה נאר דחיים מרבי אנשים יאמנו בה אה נביה רבה למה לית לי בריש קציה שם מה כללת ית שומיה בכל תמחיה ומה קעמת בגנתה ומלתה מכל איקר ולא אתפרשת בארעה וכללת יתה מה קעמת בכסי וסבלת ממלל שרה ונחתת בפם מלאך בכלול מניאני ורבית יתה בשלמו וגלית צערה ועבדת יתה תמח ביני נשיה מה קעמת עמך ואתה הזל למדין מה אתנגדת עמך ואתה מפרש לעלמה מהו בלבך מה קעמת עמך ואתה נגד רוח מערבה ארבעה כנשהן רמהן וצבעת לגו כל כנשה מנון ואנה עמך ולא אתפרקת מנך ורביתך כמד רבתך קשטה','See צstanding, speaking a speech in majesty while all listen to its 
speech, and Moses in front of it, amazed at its speech. It said to him: “O great 
prophet Moses, you are the one the light of whose heart shines more than the 
light of the sun. For the sun supplies abundantly the needs of souls, and you are 
the one who brought into being that by which souls live. The sun shines in the 
heart of the sky by day; its dominion was made by the power of Him who created 
it, while your heart dwells in the Upper Abode, by the mouth of the Powerful One 
who created it and established it for this. You are the one who ﬁlled the world 
with the light of life that exalts men who believe in Him. O great prophet Moses, 
why have I no name among the beginning of the Qiṣṣīm? Did I not crown the 
heavens with all wonders? Was I not in the Garden and did I not ﬁll it with all 
honor? Was I not spread forth into the earth, and did I not crown it? Stood I not 
in the hidden place and bore the speech of Sarah? I descended in the mouth of 
an angel with the whole of my number and I increased it with perfection, and I 
revealed Sarah’s distress and made her an object of amazement among women. 
Was I not with you while you were going to Midian? Did I not go with you while 
you were expounding to the world what was in your heart? Was I not with you 
while you led the West wind to four great assemblies? You rebuked each of these 
assemblies and I was with you. I did not depart from you, but I exalted you just 
as the True One exalted you.”','ראה את צ עומד, נושא דבר בגדלות בעוד כולם מקשיבים לדבריו, ומשה לפניו, תמה על דבריו. אמר לו: "הה נביא גדול משה, אתה הוא שאור לבך מאיר יותר מאור השמש. שכן השמש מספקת בשפע את צורכי הנפשות, ואתה הוא שהביא לעולם את מה שבו הנפשות חיות. השמש זורחת בלב השמים ביום; ממשלתה נעשתה בכוחו של מי שבראה, ואילו לבך שוכן בדירת המעלה, על פי הכל-יכול שבראו וייסדו לכך. אתה הוא שמילאת את העולם באור החיים המרומם את בני האדם המאמינים בו. הה נביא גדול משה, מדוע אין לי שם בראשית הקִצִּים? האם לא עיטרתי את השמים בכל הנפלאות? האם לא הייתי בגן ולא מילאתיו בכל כבוד? האם לא נפרשתי על האדמה ולא עיטרתיה? האם לא עמדתי במקום הנסתר ונשאתי את דברי שרה? ירדתי בפי מלאך עם כל מספרי והוספתי אותו בשלמות, וגיליתי את צרת שרה ועשיתיה לפלא בין הנשים. האם לא הייתי עמך בלכתך אל מדיין? האם לא הלכתי עמך בעת שדרשת לעולם את אשר בלבך? האם לא הייתי עמך בהנהיגך את רוח המערב לארבע קהילות גדולות? גערת בכל אחת מן הקהילות הללו ואני הייתי עמך. לא פרשתי ממך, אלא רוממתיך כשם שרוממך האמיתי."');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (381,'VI','5','מימר מדבק בשנים והעשרים אות',6000051,'אה בוראים רמין וחיולין לית בחיל ידוע ידע רבות ברואה אה בוראים חיולין רב הוא ברואון לית בחיל ידוע ידע רבותה אה בוראים רמין מחכמין הן ברוון גדול וגיבור ולית בחיל מדע ידע יכלותה אה אלהו רבה אה שלטנו חיולה אה מלכו תדירה אה רבותה מורכה אה אדרעה נתחיה מנו דיכל קעם לקבלה אי יכל ידמי לה מן לה בוראים כותה אי סימנים כסימניו אי בלודים כבלודיו חילה בשומיה מלעל ובארעה מלרע לית פני מנה אתר דכל אתריה הוא עבודון וצעורון ושכללון ותקנון ועתדון וספק צורכיון מדו בשומיה הוא לגו לבה כן הו בארעה לגו ענינה מדו ברבעתה הו בחשבתה מדו בכל אתר הוא בכל טמירהתה מן ישום מה הו אי ידע הכהו מן בוראיו אתחכם מן עובדיו אתידע ננצר קדמיו ונסגד לרבינה ונימר לית אלה אלא אחד','Behold lofy and mighty creations! It is not in the power of (even) a man 
of knowledge to know the greatness of the Creator. Behold mighty creations – 
great is their Creator! It is not in the power of (even) a man of knowledge to know 
His greatness. Behold lofy creations! They make known that their Creator is 
great and mighty. It is not for the power of the mind to know His might. Behold, 
a great divinity! Behold, a strong sovereignty! Behold, an eternal kingdom! Be-
hold, an everlasting greatness! Behold, His outstretched arm! Who can stand 
before it or can come to resemble it? Who possesses creations like His or won-
ders like His, or frightening (deeds) as His? His power is in the heavens above 
and in the earth beneath. There is no place empty of Him, for He made, formed, 
perfected, set in order, made ready all places, and He supplied their needs. What 
is in the heavens is in the heart; likewise, (what is) in the earth is in the mind. 
What is in the (four) quarters (of the world) is in reason, just as what is in any 
place is in every conscience. Who can estimate what He is or know how He is? 
From His creations He is known; from what He has made He is renowned. Let us 
be devoted before Him and bow down to His majesty and say, “There is no god 
but One.”','הנה בריאות נשגבות ועצומות! אין ביכולתו אפילו של איש דעת לדעת את גדולת הבורא. הנה בריאות עצומות — גדול בוראן! אין ביכולתו אפילו של איש דעת לדעת את גדולתו. הנה בריאות נשגבות! הן מודיעות שבוראן גדול ועצום. אין ביכולת השכל לדעת את גבורתו. הנה אלוהות גדולה! הנה מלכות עזה! הנה מלכות נצחית! הנה גדולה עולמית! הנה זרועו הנטויה! מי יוכל לעמוד לפניה או להידמות לה? מי מחזיק בבריאות כמותו או בנפלאות כמותו, או במעשים נוראים כמותו? כוחו בשמיים ממעל ובארץ מתחת. אין מקום הריק ממנו, שכן הוא עשה, יצר, השלים, סידר, הכין את כל המקומות, וסיפק את צרכיהם. מה שבשמיים הוא בלב; כמו כן, מה שבארץ הוא בדעת. מה שבארבע רוחות העולם הוא בשכל, כשם שמה שבכל מקום הוא בכל מצפון. מי יוכל להעריך מה הוא או לדעת כיצד הוא? מבריאותיו הוא נודע; ממעשיו הוא מפורסם. נהיה נכנעים לפניו ונשתחווה לגאונו ונאמר: "אין אלוהים אלא אחד."');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (382,'VI','24','מימר מדבק בשנים והעשרים אות',6000241,'עמו כמה זבן אתוקר וכמה זבן אתחיל לית בחיל ידוע ידע רבות משה מודאה לאלה דאמלתה בכל אלין ואקימה באתר לא קם בה אנש קטל מצראי ופרעה וכל חיליו ומרה אוקרה בעיני תרי חלקיה הוה רעי צאן קבל טורה בנה משכן מכלל בכל איקר עד אתחזי לה מרה בלהבת אש בגוני תמחיה והו רחט לידה בקדישו עד קעם ביקירו רבה שריר והוא קעם ומרה מקרינה עד דרס לגו אשתה ומללה ועלל ליד פרעה כפורה מכלל בסימנים עד כבש גבורתה והפך מימי נהרה דם ואפק מנה עורי ערדאנים ומן עפרה כלמיה ואנדה ערבה בכל ארץ מצרים ועבד אבק ואפר וגלה אבדנה באנשה ובבהמהתה ופתח ימה ברבו רבה וצנק יתה ביכלו רבה ועמו הך קטל פרעה וכל מן דהוה עמה ופרק ישראל ומן אמטה בה ועמונה מחלי מי מרה בטרף ומפק מן צנמה מים ועמונה קעם תלי אדיו בקרב עמלק עד קטל יתה וכל סיעתה ועמותה דער לגו עננה ברבו רבה וכל מלאכי רומה סדירין עליו ועמו יתה מצלי בדיל פרקן ישראל בדיל עובד עגלה ועמותה סלק ליד כבודה עד אתחיל במקראה דפמה ועמונה קעם מעמר משכנה ומכללה כמה ארשתה אלה ועמותה מלף לאהרן אחוה ברכתה רבתה כמד אלפה קשטה ועמונה קעום קמי הסלע ואפק מים ושתה כל ישראל ועמונה מצלי בדיל אסות מרים ופסח בדיל אהרן עד לא יהי ערבוב הלא בשרוה צלה בדילה ואכהן דחל לא יהי דכרן ביש ועמונה קעם מבאר ארהותה וכתבה כמה ארשתה אלה','See how ofen he was honored and for how long he was empowered. It is 
not in the power of a man of knowledge to realize the greatness of Moses. Thanks 
be to God who appointed him to all this and set him in a place where nobody 
else stood. He slew the Egyptians and Pharaoh and all his army. His Master 
honored him in the eyes of the two divisions. He was a shepherd before the 
mountain. He built a sanctuary perfect in every glory, till his Master appeared to 
him in the ﬂame of ﬁre (SP Exod. 3:2) with various wonders. He hastened to Him 
in holiness, till he was in very great honor. And he was standing and his Master 
called him, till he trod in the ﬁre and He spoke to him. He went to Pharaoh the 
unbeliever crowned with wonders so that he subdued (Pharaoh’s) might. He 
turned the water of the river into blood, and he also made frogs come out of it, 
and gnats from the dust. He brought forth ravens throughout the land of Egypt 
and made dust and ashes and brought about destruction among men and beasts. 
He opened up the sea with great majesty and then closed it with great power. See 
how he slew Pharaoh and all who were with him, and delivered Israel and those 
accompanying them. See him sweetening the water of Marah with a twig and 
bringing forth water from the rock. See him standing, lifing up his hands, in the 
war (against) Amaleq, till he slew them and all their party. See him dwelling in 
the cloud with great majesty and all the heavenly angels arrayed about him. See 
him praying for the deliverance of Israel concerning of the making of the Calf. 
See him going up to Glory, till he strengthened himself through the calling of His 
mouth. See him building the Sanctuary and making it perfect as God had 
commanded him. See him teaching Aaron his brother the Great Blessing as the 
True One had instructed him. See him standing before the rock; he brought forth 
water and all Israel drank. See him praying for the healing of Miriam and 
supplicating for the sake of Aaron, that there might be no blemish. For ﬁrst he 
prayed for him, and then he was afraid lest there should be an evil memory. See 
him standing and inscribing the Law and writing it as God had commanded him.','ראה כמה פעמים זכה לכבוד וכמה זמן היה מוסמך לפעול. אין ביכולתו של אדם בעל דעת לתפוס את גדולתו של משה. תודה לאל שמינה אותו לכל זאת והציבו במקום שאיש אחר לא עמד בו. הוא הכה את המצרים ואת פרעה ואת כל חילו. אדונו כיבד אותו בעיני שתי הכיתות. היה רועה לפני ההר. בנה מקדש שלם בכל הדרו, עד שאדונו נגלה אליו בלהב האש (שמות ג,ב) עם מופתים שונים. מיהר אליו בקדושה עד שהיה בכבוד גדול מאוד. עמד שם ואדונו קרא לו, עד שדרך באש ודיבר אתו. הלך אל פרעה הכופר כשהוא עטור מופתים עד שהכניע את גבורתו. הפך את מי הנהר לדם, גם הוציא ממנו צפרדעים, וכינים מן העפר. הביא ערוב בכל ארץ מצרים, והביא אבק ואפר וגרם שחין באנשים ובבהמות. פצח את הים בגאון רב ואחר כך סגרו בכוח עצום. ראה כיצד הכה את פרעה ואת כל אשר אתו, והציל את ישראל ואת הנלווים עליהם. ראהו ממתיק את מי מרה בענף ומוציא מים מן הסלע. ראהו עומד ומרים ידיו במלחמה נגד עמלק עד שהכה אותם ואת כל חבריהם. ראהו שוכן בענן בגאון רב וכל מלאכי השמים ערוכים סביבו. ראהו מתפלל על גאולת ישראל בעניין עשיית העגל. ראהו עולה אל הכבוד עד שהתחזק על ידי הקריאה מפיו. ראהו בונה את המקדש ומשלימו כאשר ציוה אותו אלוהים. ראהו מלמד את אהרן אחיו את הברכה הגדולה כפי שהורהו האמיתי. ראהו עומד לפני הסלע, הוציא מים וכל ישראל שתו. ראהו מתפלל לרפואת מרים ומתחנן בעד אהרן שלא יהיה בו מום. שכן תחילה התפלל בעדו, ואחר כך חשש שמא תישאר זכרון רע. ראהו עומד וחוקק את התורה וכותב אותה כאשר ציוה אותו אלוהים.');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (383,'VI','32','מימר מדבק בשנים והעשרים אות',6000321,'יאי עליך תדעי רביאניך נון דלית אות כותיך דאתי ארש לנביה וכהנה חלק לי ולאהרן אחי מד לית דמו לכהנתה ולנביותה כן לית לך דמו בכל כתביה לבוש כהנתה מן לבושי אתחלץ מן האן לבראי יקרב לידנן כל לבושיה דאתעבדת לאהרן לית בראי יכל יקרב ילבשון כל בניו דמשחו במשח רבותה לה יסעדו ועמה יקומו ואלה גלה לן אהן איקרה בעסרה מיתובין אתמסרו לה המשחו כלם במשח רבותה ובראה דיקרב יתקטל יזבח זבחי קשט ובניו עורי עמה וייעלו כהלון לגו משכנה וזר לא יקרב יזבח זבחי קשט ובניו עמה וייעלו אל מקדשה ובראי לא יקרב וכל דיתותר מנון לא יפק מנה מאדם אל בראה אלא נורה תיכלנה על אדיון לא ייכל בראי ייכל עמון לחם מן לחם דבחה דבידון הדבח אי ברכתה דאלפה לון אלה לית לבראי עמון בה נמי','“It is beﬁtting for you to know your greatness, O ,נfor there is no letter 
like you. You are an element in the prophethood and the priesthood, a portion 
for me and for Aaron my brother. As there is nothing like the priesthood and the 
prophethood, thus there is none like you among all the letters. The garment of 
Aaron was extracted from my clothing. How can an outsider reach us? All the 
garments made for Aaron, no outsider can approach to wear them. All his sons, 
anointed with the oil of majesty, will join him and stand with him. God has 
revealed to us this glory in ten prerogatives handed down to him. They were all 
anointed with the oil of majesty and the alien who comes near shall be killed. He 
shall oﬀer right sacriﬁces (Deut. 33:19), and his sons as well with him, and they 
all enter the Sanctuary and no outsider may draw near. They shall oﬀer right 
sacriﬁces, and his sons as well with him; they shall enter the holy place and no 
outsider may draw near. Of what is lef over by them, nothing leaves the holy 
place to go outside, but ﬁre consumes it by their hands. No outsider may eat 
bread with them from the sacriﬁcial bread which has been sacriﬁced by them. 
Likewise, the Blessing which God taught them; the outsider has no part in it with 
them.”','"ראוי לך לדעת את גדולתך, הו נ, כי אין אות כמוך. אתה יסוד בנבואה ובכהונה, חלק לי ולאהרן אחי. כשם שאין כמו הכהונה והנבואה, כך אין כמוך בין כל האותות. בגד אהרן נלקח מלבושי. כיצד יוכל זר להגיע אלינו? כל הבגדים שנעשו לאהרן, אין זר יכול להתקרב ללובשם. כל בניו, המשוחים בשמן ההוד, יצטרפו אליו ויעמדו עמו. אלוהים גילה לנו את הכבוד הזה בעשרה זכויות שמסורות לו. כולם נמשחו בשמן ההוד, והזר הקרב יומת. יזבחו זבחי צדק (דברים לג,יט), ובניו גם עמו, וכולם נכנסים אל המקדש ואין זר יכול להתקרב. יזבחו זבחי צדק, ובניו גם עמו; יכנסו אל המקום הקדוש ואין זר יכול להתקרב. ממה שנותר להם, אין דבר יוצא מן המקום הקדוש החוצה, אלא האש אוכלת אותו בידיהם. אין זר יכול לאכול לחם עמהם מלחם הקרבן שהקריבו. כמו כן, הברכה שאלוהים לימדם – לזר אין בה חלק עמהם."');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (384,'VI','12','מימר מדבק בשנים והעשרים אות',6000121,'עמי לאהן איקרה דלא כותה איקר וחכם הן לא התוקר גוי דמותך ולא יהב לה כמד יהב לך לא תחלפה בפגול ותקים גרמך בהת קמי מרה דעלמה הו דאסגלך בכן ואשמעך קלה ואלפך ואקים משה לך ספר טב מלף יתך כל אלפן חסיד הן תשבקנה וילך בכן בריש ובעקב וילך במה עבדת מן עובד ביש מאבד עבודה } וילך במה עבדת מן עובד ביש מאבד עבודה { לא תתוכח במלים ולא במחוהן ולא בחסרן ולא בטלטול ולא בנזפו ולא בקלל ולא בנסיון ולא באבדנה במה תתוכח אה מסכינה דרבה אבדנה בלב חדי באידן מדע עבדת כל הדה באידן אור צפיך אי למן אדמיך אי ממן אלפת בישהתה דקטלת יתך ושרת בגוך והשלחת ית כלילך ואתנסבת מנך מלכותה והכסית ימי רחותה מנך ושבקת דחלת אדם ואתילפת אקנאות קין קם לך כלי וטמי וכלה נזף לך ומקלל יתך וטרידך בכל אתר','Consider this honor, like which there is no honor, and know that no 
people have been honored as you (have been), and (that) He has not given to 
them as He has given to you. Do not substitute abomination for it, (lest) you will 
bring shame on yourself before the Master of the world. It was He who selected 
you for this and made you (so as) to hear His voice, and taught you and appoint-
ed Moses for you as a good teacher to teach you every ﬁne teaching. If you aban-
don it woe to you for that, in the beginning and in the end! Woe to you for what 
you have done – an evil action that destroys its doer. You are not chastened by 
words and not by aﬄictions and not by deprivation and not by hurling and not 
by rejection and not by cursing and not by trial and not by destruction. By what 
will you be chastened? O poor one, who has increased his (own) destruction 
while his heart is merry? By what reason have you done all this? What light have 
you seen, or whom do you resemble, or from whom have you learned the evil 
things which have slain you, and dwell in you, and removed your crown, and 
taken kingship from you, and hidden the days of Divine Favor from you, so that 
you have forsaken the fear of Adam and learned the jealousy of Cain? Withheld 
and isolated (ST Gen. 4:12) becomes realized in you, and everyone rebukes you 
and curses you and banishes you in every place.','הביטו בכבוד הזה, שאין כמוהו, ודעו שלא כובד עם כמוכם, ושלא נתן להם כמו שנתן לכם. אל תמירו בו תועבה, פן תביאו בושה על עצמכם לפני אדון העולם. הוא הוא שבחר בכם לכך ועשה אתכם לשמוע בקולו, ולימד אתכם ומינה לכם את משה למורה טוב ללמד אתכם כל תורה נאה. אם תעזבוה – אוי לכם על כך, בתחילה ובסוף! אוי לכם על מה שעשיתם – מעשה רע המשחית את עושהו. אינכם מתיסרים לא בדברים ולא בייסורים ולא בחסרון ולא בהשלכה ולא בדחייה ולא בקללה ולא בניסיון ולא בחורבן. במה תתיסרו? אוי לאומלל שהרבה את חורבנו בעוד לבו שמח! מה סיבה הניעה אתכם לכל זאת? איזה אור ראיתם, או למי דמיתם, או ממי למדתם את הדברים הרעים שהרגו אתכם ושוכנים בכם והסירו כתרכם ולקחו מכם את המלוכה והסתירו מכם את ימי הרצון, עד שעזבתם את יראת אדם ולמדתם את קנאת קין? נע ונד (בר'' ד,יב בתרגום השומרוני) מתגשם בכם, וכולם גוערים בכם ומקללים אתכם ומגרשים אתכם בכל מקום.');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (385,'VI','58','מימר מדבק בשנים והעשרים אות',6000581,'אוי לכל המתשקחין בה עלם תפוך כל המשקחין בה בעשדה חיולה יבדר קהלה בתר אלהי נכר ויזבחו לשידים ויכעסו למרון וזה ביש לון עלם חסרן דן עלמה דבה יכעסו לאלה בתובעתון ויגלי רגזה ויקטל אבהן ויכלי בניה וישבק נשיה טמעים בטמא ויעמרו אתרי בישהתה וישבקו אתרי קשטה וקשטה מסתלק וימי רחותה פליה ופנותה גליה ועלמה מציק על מד אתדבר מנה מן גוני ברכהתה וזכותה רישה מרכן מן תפוך בניה ובישתה חדיה במהי עמיה','“Woe to all who are found in it, in a world of overturn, for all who are 
found in it are in a mighty distress. The congregation will be dispersed, follow-
ing alien gods and sacriﬁcing to demons (Deut. 32:17) and provoking their Master. 
This will go badly for them. This world in which they provoke God with their 
abominations is a world of deﬁciency, and wrath will be revealed and He will 
slay fathers and make an end of sons and forsake women immersed in unclean-
ness. They will build places for evil and forsake the places of the True One. The 
True One will remove Himself and the days of Favor will be remote and the days 
of Disfavor revealed. The world will be in distress because all kinds of blessings 
and righteousness will be removed from it. Its head will be humiliated by the 
sons’ apostasy, and evildoing will rejoice at what it sees.”','"אוי לכל הנמצאים בו, בעולם ההפיכה, כי כל הנמצאים בו נתונים בצרה עצומה. העדה תתפזר, תלך אחרי אלוהים זרים ותזבח לשדים (דברים לב,יז) ותכעיס את אדונה. זה יסתיים רע להם. עולם זה שבו הם מכעיסים את האלוהים בתועבותיהם הוא עולם החסר, והחמה תתגלה והוא יהרוג אבות ויכלה בנים ויעזוב נשים טבולות בטומאה. הם יבנו מקומות לרוע ויעזבו את מקומות האמת. האמת יסלק את עצמו ויָמי הרצון יתרחקו ויְמֵי חוסר הרצון יתגלו. העולם יהיה בצרה כי כל מיני ברכות וצדקה יוסרו ממנו. ראשו יושפל בגלל כפירת הבנים, והרשעות תשמח במה שהיא רואה."');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (386,'VI','60','מימר מדבק בשנים והעשרים אות',6000601,'תמן הגיבת זכותה באפרי ואמרת מיסתיך אלין מליה דמללתי ליתי בעיה בנים כות בנים מתוקדים באשתה ואני בכן חדיה כותיך עמי בניה דרבית יתון אנה ומה הוה לון נח כד הוה בה זכו סבלתה על אפי מיה ובניך אבדו אברהם כד הוה ככן קעמת עמה ודבלשו העקה העקת עליון יצחק כד הוה נציר רבית יתה אצרכת כל סניו אליו יעקב כד הוה כן מללת לב אחיו אליו ורבית שלמותה יוסף כד הוה לי המשילתה על תלימיו נביה מהימנה משה כד הוה חברי סגי דקטל חיבין ולא רתי לון הן הויתי אתי חדיה במה חזיתי מן תפוך מסחני קשטה ליתי כדן ייזל בישה לאשתה ולא אחוס עליו הן השתיר עם זעור הך מד עבדת מרישה כן אעבד בעקבה על כלול מניאנה אתחזית בגדל ורבית יתון עד מותר כמה דעבדת תמן כן אעבד אכה ברבין מלכו ותעתיד איטבו','Then Righteousness answered and said: “Enough for you these words 
which you have spoken. I do not seek children like those (to be) burnt in the ﬁre! 
I rejoice in motherhood just like you. See the children whom I raised and what 
happened to them: When Noah was righteous, I bore him on the face of the wa-
ter, while your children perished. When Abraham was likewise, I stood with him, 
and aﬄicted those who sought aﬄiction. When Isaac was devoted, I elevated 
him and made all his foes need him. When Jacob was likewise, I diverted his 
brother’s heart towards him and increased his well-being. When Joseph was 
mine, I gave him dominion over his brothers. When the faithful prophet Moses 
was my companion, he was great, for he slew sinners and did not pity them. If 
you are joyful at what you have seen of the overturning of the possessors of truth 
– I am not like that. Let the sinner go to the ﬁre – I have no compassion for him, 
even if there will be few people lef. As I did at the beginning, so will I do at the 
end. At the completion of the number, I appeared in greatness and elevated them 
exceedingly. As I did then, so will I now do, with majestic sovereignty and well-
preparedness.”','אז ענתה הצדקה ואמרה: "די לך בדברים אלה שאמרת. אין אני מבקשת בנים כאלה שיישרפו באש! אני שמחה באימהות בדיוק כמוך. ראי את הבנים שגידלתי ומה אירע להם: כשנח היה צדיק, נשאתיו על פני המים, ואילו בניך אבדו. כשאברהם היה כן, עמדתי עמו וייסרתי את המבקשים לייסרו. כשיצחק היה מסור, רוממתיו והכרחתי את כל אויביו להזדקק לו. כשיעקב היה כן, הטיתי את לב אחיו כלפיו והרביתי את שלומו. כשיוסף היה שלי, נתתי לו שלטון על אחיו. כשמשה הנביא הנאמן היה חברי, היה גדול, כי הרג חוטאים ולא חמל עליהם. אם את שמחה במה שראית מהפיכת בעלי האמת – אין אני כן. שילך החוטא אל האש – אין לי רחמים עליו, ואפילו יוותרו מעט אנשים. כאשר עשיתי בראשית, כן אעשה באחרית. בהשלמת המספר, נגליתי בגדולה ורוממתים למעלה למעלה. כאשר עשיתי אז, כן אעשה עתה, במלכות הוד ובהכנה נאותה."');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (387,'VI','28','מימר מדבק בשנים והעשרים אות',6000281,'ליעקב אמיר והוא מסחן זכותה הסתמך בעשרה עובדים רמין בבסור אמה בה חכמת יתרה וכד צא לעלמה רמת מיתוביתה וכד מלך קנומה מלך כל חכמתה ועמר משכן אברהם סהבה ולא שבק משכן יצחק אבוה ריקן לבדיל אמיר עליו ויעקב איש תם ישיב אהלים וברכה אלה ועוד אבוה והנדר וקם בנדרה והתפך לב אחוה לשלם עזרת דבבותה לרחמותה לא תבלד בעובד אלאן בעובדה דעבדו יתה בניו הארבעה בארבעה זבנים עובדה קמאה ביד ראובן ותניאנה ביד שמעון ולוי ותליתה בידון עורי ורביעיה ביד יהודה עובדה קמאה דעבדה ראובן טמא משכב אבוה במדמך זנו ותניאנה דביד שמעון ולוי חרבו קריה וקטלו מלכיה ודחל יעקב מן דאה עובדה לאלא תשתלח לידון אד ברהתיה ותליתה מה עבדו ביוסף עאקו עליו ולחצוה לחץ קשי לא אחסו על קנומון מן רגז אלה ולא רתו לטליותה במה דעבדו','It was said of Jacob that he is the righteous one, supported by ten lofy 
deeds. When his mother received announcement about him, she realized his 
superiority. When he appeared in the world, his rank was high. When he 
matured, he was the possessor of all wisdom. He (re)built the tent of Abraham 
his grandfather and he did not leave the tent of Isaac his father empty. Therefore 
it was said of him: And Jacob was a righteous man, dwelling in tents (Gen. 25:27). 
God blessed him and so did his father. He made a vow and he kept to his vow. 
His brother’s heart was turned to peace; enmity was changed into love. Do not be 
shocked by any deed except the deed which his four children did on four 
occasions. The ﬁrst deed by Reuben, the second by Simeon and Levi, the third by 
these two also, the fourth by Judah. The ﬁrst deed, by Reuben: he deﬁled his 
father’s bed as a bed of adultery. The second, by Simeon and Levi: they de-
stroyed a town and slew its owners. Jacob was afraid because of that action, lest 
the hand of outsiders should be directed against them. The third, they did to 
Joseph: they oppressed him and aﬄicted him severely. They had no compassion 
for themselves in the face of God’s anger, nor did they have compassion for his 
youth in what they did.','נאמר על יעקב שהוא הצדיק, הנסמך על עשרה מעשים נשגבים. כשקיבלה אמו בשורה עליו, הכירה בעליונותו. כשנגלה בעולם, מעמדו היה רם. כשהבשיל, היה בעל כל החכמה. הוא בנה מחדש את אוהל אברהם זקנו ולא הניח את אוהל יצחק אביו ריק. לפיכך נאמר עליו: ויעקב איש תם יושב אוהלים (בראשית כה,כז). אלוהים ברכו וכן גם אביו. נדר נדר ועמד בנדרו. לב אחיו נהפך לשלום; האיבה נהפכה לאהבה. אל תתמה על שום מעשה זולת המעשה שעשו ארבעת בניו בארבע הזדמנויות. המעשה הראשון על ידי ראובן, השני על ידי שמעון ולוי, השלישי גם הוא על ידי שניהם, הרביעי על ידי יהודה. המעשה הראשון, על ידי ראובן: טימא את משכב אביו כמשכב ניאוף. השני, על ידי שמעון ולוי: החריבו עיר והרגו את בעליה. יעקב חשש בגלל המעשה ההוא, שמא תופנה יד הזרים כנגדם. השלישי, עשו ליוסף: עינו אותו וציערו אותו קשות. לא חמלו על עצמם מפני כעס אלוהים, ולא חמלו על נעוריו במה שעשו.');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (388,'VI','38','מימר מדבק בשנים והעשרים אות',6000381,'כי דחלתה מן › אלה ‹ סלם דרגיה חייה מוחיה למן דסלק בון הדחול מן אלה לא יקרב עובד ביש ידע הן גזוה קדמיו לא יקרבנה לעלם הדחול מן אלה קני רחמותה ומן רחמותה לא יעצינה רק ילך בשביליה ומן ילך בשביליה יבלש ריחותה ותמימות דעתה ידע הן יה הוא האלה ואין עוד מלבדו ריש מחכומה יהי ברנשה ידע רבות ברוה ויזע מן גדלה ויפחד מן גבורתה דו חכום כל נסתר וכל נגלא ו ] לית [ עמה ] אל [ חור ] ן טובי [ מן ] יקים [ קנ ] ומה בריחות מרה בכל זבן ויעבד יכלותה בקוממות זכותה דהי יכלה מרביה כל יכלה ועורי תרבי אנחמו למד הוא מלף לא ייזל אלפנה נבל אלא מרבי בה מנו דמותה הן מלכת כל אהן את בכל איקר מכלל ודע דאתה מקדם יום צומה גמיל בכל חסד וכל טוב','Indeed, fear of God is a ladder whose steps are life, life-giving to him 
who climbs them. He who fears God does not approach any evil deed. Knowing 
that there is recompense ahead of him, he will never draw near to it. He who 
fears God possesses love of Him, and because of his love he does not rebel 
against Him but walks in the Lord’s ways. He who walks in His ways seeks to do 
His will. Presence of mind – he knows that the Lord is God and that there is none 
besides Him (Deut. 4:35). The beginning of knowledge is that the man knows the 
majesty of his Creator and trembles at His greatness and is frightened at His 
power, for He knows all that is concealed and all that is revealed, and there is no 
other god beside Him. Happy is he who sets himself in the will of his Master at 
all times, and who uses his power to maintain righteousness. For it is a power 
that exalts every power and even increases relief for him who teaches. His teach-
ing does not lead to disgrace, but it exalts all who are like him. If you possess all 
this, you are crowned with all honor. Know that you will meet the day of the Fast 
perfected in all grace and goodness.','אכן, יראת האלוהים היא סולם שמעלותיו הן חיים, מחיים למי שעולה בהם. מי שירא מאלוהים לא מתקרב לשום מעשה רע. בידעו שיש גמול לפניו, לא יתקרב אליו לעולם. מי שירא מאלוהים בידו אהבתו, ומתוך אהבתו אינו מורד בו אלא הולך בדרכי ה''. מי שהולך בדרכיו מבקש לעשות את רצונו. נוכחות התבונה – הוא יודע כי ה'' הוא האלוהים ואין עוד מלבדו (דברים ד,לה). ראשית הדעת היא שהאדם יכיר את הוד בוראו, ויחרד מגדולתו ויירא מכוחו, שכן הוא יודע את כל הנסתר ואת כל הנגלה, ואין אלוהים אחר מלבדו. אשרי מי שמשים את עצמו ברצון אדונו בכל עת, ומשתמש בכוחו לקיים את הצדק. שכן זהו כוח שמרומם את כל כוח, ואף מגביר את ההקלה למי שמלמד. תורתו אינה מובילה לבושה, אלא מרוממת את כל הדומים לו. אם כל זאת בידך, הרי אתה מוכתר בכל הכבוד. דע שתפגוש את יום הצום שלם בכל חן וטוב.');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (389,'VI','64','מימר מדבק בשנים והעשרים אות',6000641,'תמן שרית א ואמרת מלים מרבים לכל מן בה דעה יאזין כל נבון למלי חכמתה דהי פריסה קמיו א אמרה עמו איקרי דבה אתרבית אנה אתעבדת שרוי כתביה ושרוי לשמה רבה דבה מרי אמצא עלמה פתחת תרח בראשית וכללתה בכל תמח ורביתה בכל רבין חסיד וכד אתעבד לך כלילה דמלכו קרבת ליד ערפלה ודערת בגו עננה והכללת באורה ולגו אשתה דרסת וקעמת באתרין לא קעם בון אנש חורנך לשומיה זעקת וענתך וארעה עבדת כן ומיה השדכת למליך ולא יכלו ישרו הכפתה דכפתון וכן אשתה כד דרסת יתה קלת גבורתה ואת לגוה הלך מלאכיה יקרו יתך ורבו אתרך וכבודה הגלה לך מה אנה ריש מקרתה דקרתה קשטה במשמע כל קהלה היא כריזת דפוררת מדעיון וקטרת לבביון על קשטה אנכי יהוה אלהיך תמן הרתת ישראל והבלד ואלולי רחמיו ורב רתותה לא הוה לישראל קוממו כד חכם אלה בלוד ישראל וארתקות לבה שרי וקרא קמיון עסרתי מליה בדיל ייטב לון ואנה יה שרוי מליה דיקרך מרך בון קדם ישראל אני יה וילון מרגזיה דהי עבידה לון תשניק רב עד מותר ידעו טביה די מרביה לון וידעו בישיה די מדינה לון ואלה חכמן בכן וגלתה קמינן אתילף אלין מליה בדיל תצלח בכל עובדיך','Then אbegan to say words that elevate all who have knowledge. Let 
every wise man give ear to the words of wisdom that are set out before him! א
said: “See my glory, by which I was elevated. I was made the ﬁrst of the letters 
and the ﬁrst of the great name by which my Master created the world. I opened 
the gate of Genesis and perfected it with every wonder, and I magniﬁed it with 
every ﬁne greatness. And when the crown of sovereignty was made for you, you 
drew near to the deep darkness and dwelt in the cloud. You were crowned with 
the light and you trod the ﬁre and you stood in places where other than you no 
man had ever been. You called to heaven and it answered you, and earth did 
likewise. You stilled the waters at your words and they could not untie the 
binding that subdued them. So too when you trod on the ﬁre, its might dimin-
ished when you walked in it. The angels honored you and elevated your position 
and Glory revealed to you what I am. The beginning of the proclamation which 
the True One proclaimed in the hearing of the whole congregation was the an-
nouncement that awakened their minds and linked their hearts to the True One: 
I am the Lord your God (Ex. 20:2). Then Israel trembled and was frightened. Were 
it not for His mercy and great clemency, Israel would not have stood. When God 
knew the dread of Israel and the beat of their heart, He started to proclaim before 
them the Ten Words to relieve them. I am the Lord is the beginning of the words 
by which our Master honored you in the presence of Israel. I am the Lord – woe 
to those who produce wrath, for it becomes to them an exceedingly great 
aﬄiction. Let the good know that it will elevate them, and the evil know that it 
will punish them. God has taught us this and revealed it before us. Learn these 
Words, that you may prosper in all your deeds.”','אָז החל א לומר דברים המרוממים את כל בעלי הדעת. יטה כל חכם אוזנו לדברי החכמה הפרוסים לפניו! אמר א: "ראה את כבודי, שבו נתרוממתי. נעשיתי ראשון האותיות וראשון השם הגדול שבו ברא אדוני את העולם. פתחתי את שער בראשית וכיליתיו בכל פלא, והגדלתיו בכל גדולה נאה. וכאשר נעשתה לך עטרת המלכות, נגשת אל החשך הכבד ושכנת בענן. הוכתרת באור ודרכת על האש ועמדת במקומות שמעולם לא עמד בהם אדם זולתך. קראת אל השמים והם ענוך, וכך גם הארץ. הרגעת את המים בדבריך ולא יכלו להתיר את האסר ששלט בהם. וכך גם כשדרכת על האש, גבורתה פחתה בהלכך בה. המלאכים כיבדוך ורוממו את מעמדך, והכבוד גילה לך מה שאני. תחילת ההכרזה שהכריז האמיתי באוזני כל הקהל הייתה ההודעה שעוררה את רוחם וקשרה את לבם אל האמיתי: אָנֹכִי יְהוָה אֱלֹהֶיךָ (שמות כ,ב). אז רעד ישראל ונבהל. אלמלא רחמיו וחסדו הגדול, לא היה ישראל יכול לעמוד. כשידע האלוהים את אימת ישראל ואת פעימת לבם, החל להכריז לפניהם את עשרת הדברים להקל מעליהם. אָנֹכִי יְהוָה הוא ראשית הדברים שבהם כיבד אדוננו אותך לפני ישראל. אָנֹכִי יְהוָה – אוי לאלה המעוררים חמה, כי תהיה להם לצרה גדולה מאוד. יידעו הטובים שהיא תרוממם, וידעו הרעים שהיא תענישם. האלוהים לימד אותנו זאת וגילה אותה לפנינו. למדו דברים אלה, למען תצליחו בכל מעשיכם."');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (390,'VI','42','מימר מדבק בשנים והעשרים אות',6000421,'מנו דלה דרגה כאהן דרגה בה פרק אלה ישראל מבית עבדותה ועל ידו גלה אימנותה מיסתה מד כתב מרה בדילה ולא קם עוד נביא בישר כמשה נרבי למרן ונאמן בנביא לא כותה נביא בעלמה ונצפי אל ס אמרה לה מה קעמת עמך במרה ואף ברפידים ובחצירות למה שבקתני לא שרית בי קצה מקצי ארהותה הגיבה נביה רבה משה כיתיך דעבדתי עם שרה כד בטנת ביצחק והולדת יתה וקעמיך עם ישראל במצרים ועל ים סוף דליך אלין עובדיה ליתיך צריכה לבר מן הדה נרבי למרן דאמלתן בכל איקר ננצר קדמיו ונשתעבד לה ונודי לחילה על סגאי טבהתה גלה לן פקודיו ויהב לן תורה תמימה וגלה לן נבי צדיק אלפן מד בה מכל איקר רב עד מותר אה שלמו יתרה אה שלטנו רבה לא אתיקר בה גוי בר מנן','Who is the one who has a rank like this rank? By him God delivered 
Israel from the House of Bondage, and through him He revealed the faith. 
Enough for him what his Master wrote of him: And there has not arisen a prophet 
since in Israel like Moses (Deut. 34:10). Let us exalt our Lord and believe in a 
prophet, like whom there is no prophet in the world. Let us consider סas it says 
to him: “Was I not with you in Mara and in Rephidim and in Hazeroth? Why did 
you leave me out and have not started even one Qiṣṣa of the Qiṣṣīm of the Torah 
with me?” The great prophet Moses answered: “Indeed you are (ﬁtted for this) by 
what you did with Sarah when she was pregnant with Isaac and then gave birth 
to him, and your standing with Israel in Egypt and at the Sea of Reeds. They are 
yours, these deeds; you do not need more than this.” Let us exalt our Lord who 
has ﬁlled us with all glory! Let us be devoted before Him and be submissive to 
Him and thank His power for many good things. He revealed His precepts to us 
and gave us a perfect law and revealed to us a righteous prophet. He taught us 
that which contains all exceedingly great glory. Behold, an excellent perfection! 
Behold, a great sovereignty! No nation except for us has thus been honored.','מי הוא אשר לו מעמד כמעמד זה? על ידו הציל אלוהים את ישראל מבית העבדים, ועל ידו גילה את האמונה. די לו במה שכתב עליו אדוניו: וְלֹא קָם נָבִיא עוֹד בְּיִשְׂרָאֵל כְּמֹשֶׁה (דברים לד,י). נרומם את אדוננו ונאמין בנביא אשר אין כמוהו נביא בעולם. נתבונן בס'' כשהיא אומרת לו: "הלא הייתי עמך במרה וברפידים ובחצרות? מדוע השמטת אותי ולא פתחת אפילו קיצה אחת מן הקיצּות של התורה בי?" ענה משה הנביא הגדול: "אמנם אתה (ראויה לכך) על מה שעשית עם שרה כאשר הייתה בהריון ביצחק ואחר כך ילדה אותו, ועמידתך עם ישראל במצרים ועל ים סוף. שלך הם המעשים האלה; אינך צריכה יותר מזה." נרומם את אדוננו אשר מילא אותנו בכל כבוד! נהיה מסורים לפניו ונכנע לו ונודה לגבורתו על רבות טובות. גילה לנו את מצוותיו ונתן לנו תורה שלמה וגילה לנו נביא צדיק. לימד אותנו את אשר כולל כבוד גדול ביותר. הנה שלמות נאה! הנה מלכות גדולה! שום אומה מלבדנו לא נכבדה כך.');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (391,'VI','11','מימר מדבק בשנים והעשרים אות',6000111,'טב לן נדכי לבבן ונחכם קשטה ונמלי לבבן מן אלפן דעתה דאנן ספרין לכל אמיה ובכן מרן חכמן דבידן נאר מופע מניר על כל עלמה כתיב באצבע אלה ונחת מן מעון קדשה עקריו נשמעו מן שומיה בעשרה תמחים חיולים רמים אש ולפידים וחשך וענן וקולות וברק וקול השופר ובלוד תקיף ושדכה רבה וזימון סדרי מלאכיה רבין חיול ליתו משתאם והוה ביום לית לה שני ולא יתחזי כותה לעלם מכתב קשט כתבה דבידן וכל כתבי אמיה פגולין ובכן מרן חכמן בכתבה והם תכו לרגליך ושאו מדבירותיך ואקף אהן במימר תורה צוה לנו משה','It is good for us to purify our hearts and know the truth and ﬁll our 
hearts with the teaching of knowledge, for we are teachers to all the nations. 
Thus our Lord has taught us that we possess a shining light that illumines the 
entire world, written by God’s ﬁnger and descended from the Holy Abode. Its 
principles have been heard from heaven with ten lofy, mighty wonders: ﬁre, 
torches, darkness, cloud, thunders, lightnings, the sound of the trumpet, great 
fright, great stillness, the assembly of the angelic arrays. A mighty majesty, ines-
timable. It happened on a day that has no peer, and the likes of it will never be 
seen again. The book we possess is a book of truth, and all the writings of the 
nations are abomination. Therefore, our Lord has taught us in His Scripture: So 
they will submit at Your feet and receive Your pronouncements (Deut. 33:3). He 
joined to this the saying: Moses commanded us a law (Deut. 33:4).','טוב לנו לטהר את לבנו ולדעת את האמת ולמלא את לבנו בתורת הדעת, שכן אנו מורים לכל האומות. כך לימדנו אדוננו שיש בידינו אור זורח המאיר את כל העולם, כתוב באצבע אלוהים וירד מן המעון הקדוש. עיקריו נשמעו מן השמים בעשרה נפלאות נשגבות ועצומות: אש, לפידים, חושך, ענן, קולות, ברקים, קול השופר, פחד גדול, דממה גדולה, קהל מערכות המלאכים. הוד עצום, שאין לשערו. אירע ביום שאין לו כמוהו, ודומה לו לא יראה עוד לעולם. הספר שבידינו הוא ספר אמת, וכל כתבי האומות הם תועבה. לכן לימדנו אדוננו בכתבו: ואכן יתכרעו לרגלך, ישאו מדברותיך (דברים לג,ג). וצירף לכך את הדברים: תורה ציווה לנו משה (דברים לג,ד).');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (392,'VI','30','מימר מדבק בשנים והעשרים אות',6000301,'עובדה רביעיה דעבדה יהודה רבה בנים דזנו ובלש לון פלגה בדיל אלין ארבעתיתה דעבדו שאל פרעה ליעקב בדיל ימי חייה עמי מה עבד ומה הגיב עבד עובד אלפה יוסף והגיב במה דארשתה אלה וארום חסלה דיעקב יהי בימיו רע תמן חכם לבניו מהו עתיד לון במגירותה דאנון מתמגרין ורחותה תהי לקיה יתון ובכן מרן לאברהם גלה מה נימר וכל ימינן הלכים בבישהתה ולינן שהבין תרום טית במד לה הוה מן שרוה עד עקבה כד חכמת ט אהן איקרה דאתוקרת בה שרת חדיה וידעת למה לא הכתבת בריש קצה מן קצי ארהו ואתעבד לה תלתה חלקין רמין חלקה קמאה בריש בריתה מרה דעלמה עבדה לה כליל חלקה תניאנה רבת לזכאים ואוזפת לון כל איקר האן דאנון שרין חלקה תליתה רבת בניה בבטניה סעד המלאו וצאו לעלמה שלמין יקום מדעה על אהן רזה וידע מה דאמיר בדיל אות טית','The fourth deed, done by Judah: he bred children of harlotry and sought 
estate for them. Because of the four things which they had done, Pharaoh asked 
Jacob about the years of (his) life. See what he did and what he replied. He did a 
deed that Joseph had instructed him and answered in accordance with what God 
had commanded him. But far be it from Jacob to be evil in his days! Then he in-
formed his sons what was prepared for them in the sojourn in which they 
sojourn, and how they will lack the Divine Favor. This our Master revealed to 
Abraham. What should we say, while all our days pass in evildoings and we do 
not repent? טis exalted by what happened to it from beginning to end. When ט
knew the glory with which it was gloriﬁed, it began to rejoice, and realized why 
it had not been written in the beginning of any section of the Qiṣṣīm of the Torah. 
Three lofy portions had been provided for it. The ﬁrst portion at the beginning 
of the Creation: the Master of the world made it a crown for .טThe second 
portion: טmagniﬁed the Righteous and increased all glory for them wherever 
they dwelt. The third portion exalted children in the wombs, until they were 
perfected and came forth into the world ﬂawless. Let the mind comprehend this 
mystery and know what has been said concerning the letter .ט','המעשה הרביעי, שעשה יהודה: הוליד בני זנות ובקש להשיג נחלה עבורם. בשל ארבעת הדברים שעשו, שאל פרעה את יעקב על שנות חייו. ראה מה עשה ומה השיב. עשה מעשה כפי שיוסף הורה לו, והשיב כפי שציווה אותו אלוהים. ברם, חלילה ליעקב לנהוג ברשעה בימיו! אז הודיע לבניו מה צפוי להם בגלות שבה יגורו, וכיצד יחסר מהם הרצון האלוהי. זאת גילה אדוננו לאברהם. מה נאמר, כאשר כל ימינו עוברים במעשי רשע ואין אנו שבים בתשובה? האות ט מתעלה על ידי מה שאירע לה מתחילה ועד סוף. כאשר ידעה ט את הכבוד שבו התכבדה, החלה לשמוח, והבינה מדוע לא נכתבה בראשית שום פרשה מפרשיות הקיסים של התורה. שלושה חלקים נשגבים הוכנו לה. החלק הראשון בראשית הבריאה: אדון העולם עשה אותה כתר ל-ט. החלק השני: ט גידלה את הצדיקים והרבתה להם את כל הכבוד בכל מקום שישבו. החלק השלישי העלה ילדים ברחמות, עד שנשלמו ויצאו לעולם ללא מום. שיבין השכל את המסתורין הזה וידע מה נאמר על האות ט.');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (393,'VI','57','מימר מדבק בשנים והעשרים אות',6000571,'עמו ת הך הי קעמה ממללה עם נביה רבה משה ממלל בגדל אנה מן שרואה קעמת בבראשית ועלמה תהו ובהו וגדל בי קשטה עקריה דהי ארשי בריתה אני פתחת תרח טובה וקעמת עם אברהם בשלמו גדילה ועבר מרי טובי לפניו וגלה לה כל תמח חיול ולא כסה מנה כלום ממה דו בעי עבד ולא מהו אתי במניאני והוית לה ולזרעה ספר על כלולה נפקת צבאות יהוה ובלשו מד אמרת והוה לון כל איקר לא הוית חתמת למה הכתב בדיל מרבאה כל מה אתעבד עדהן יתרבי בי כל טוב מבתר עלם','See תas it stands speaking with the great prophet Moses, a speech in 
greatness: “From the beginning I was in ,בראשיתwhile the earth was without form 
and void (Gen. 1:2). Through me the True One made the roots grow, which are the 
foundations of Creation. I opened the gate of goodness and I stood with Abra-
ham in great perfection. My Master paraded my excellence before him (Abraham) 
and revealed to him every great wonder, and did not conceal from him anything 
of what He sought to do nor of what was to take place through my number. I was 
a number for him and his descendants, at the completion of which the hosts of 
the Lord went out and sought what I had promised, and they came to have all 
glory. Was I not a seal for what was written, to magnify all that was done, so that 
in me every good thing would be magniﬁed afer (this) world?”','ראה את התיו כשהוא עומד ומדבר עם משה הנביא הגדול, דיבור בגדולה: "מן הראשית הייתי בבראשית, בעוד הארץ הייתה תוהו ובוהו (בראשית א,ב). על ידי עשה האמת את השורשים לצמוח, שהם יסודות הבריאה. פתחתי את שער הטוב ועמדתי עם אברהם בשלמות גדולה. אדוני הציג בפניו את מעלתי והגלה לו כל נפלאות גדולות, ולא הסתיר ממנו דבר מאשר ביקש לעשות ולא מאשר עתיד היה להתרחש על ידי מספרי. הייתי מספר לו ולצאצאיו, עם השלמתו יצאו צבאות ה'' ובקשו את אשר הבטחתי, ובאו לקבל כל הכבוד. האם לא הייתי חותם למה שנכתב, לרומם כל מה שנעשה, כדי שבי יתרומם כל דבר טוב לאחר עולם זה?"');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (394,'VI','49','מימר מדבק בשנים והעשרים אות',6000491,'כל אהן אתעבד מקדם נביותך ובשרוה עבדת רב מכן ובמניאני רבית מקומהתה דלך עדהן קבלתני ואדירת יתי בעלמה בשרוה סבלת ממלל ישראל ואקימת יתה קבל כרסי קרבה והשרית בלבון דחלת אימנותה בך ובאלה אה נביה רבה דאסגלך אלה על כל נביא דיהי בעלמה כד קעמת על ימה קעמת עמך וסבלת צבעתך אל מעונה עלאה וכן צבעת ישראל וצאו בשלם ורבית צבעתך על מימי מרה ואתחזית לך בשעתה דצבעת כל אהן דברה לקבל אברהם דו הוה ארש למקים זרע במניאני אתרבית שרה ובמנאין חברתי הגדל אברהם מה רבה מיתובית נביה רבה משה בכל מד עבד מן גוני תמחיה בארשות מרה','“All this was done before you (were granted) prophethood, and at the 
beginning of it I did more than that. With my number I elevated your places, so 
that you received me and lodged me in the world. At the beginning, I bore the 
speech of Israel and set it before the seat of war. I lodged in their heart a fearful 
belief in you and in God. O great prophet, whom God selected above every 
prophet who may come to be in the world. When you stood at the sea I stood 
with you and I bore your cry to the upper abode, as well as the cry of Israel, so 
that they went forth in safety. I elevated your cry at the water of Marah and I 
appeared to you at the time when you cried. All these exploits – with regard to 
Abraham, who was a root for the establishing of descendants. By my number, 
Sarah was magniﬁed and by the number of my companion Abraham was elevat-
ed. How great is the rank of the mighty prophet Moses, in all the various won-
ders that he performed at his Master’s command!”','"כל זה נעשה לפניך (בטרם קיבלת) את הנבואה, ובראשיתה עשיתי יותר מכך. במספרי הרוממתי את מעמדך, עד שקיבלתני והושבתני בעולם. בראשית, נשאתי את דיבורם של ישראל ושמתי אותו לפני כסא המלחמה. השרשתי בלבם אמונה יראה בך ובאלוהים. הו, הנביא הגדול, אשר בחר בו האל מעל כל נביא שעתיד לקום בעולם. כאשר עמדת על הים עמדתי עמך ונשאתי את זעקתך אל המשכן העליון, וכן את זעקתם של ישראל, עד שיצאו בשלום. הרוממתי את זעקתך על מי מרה ונגליתי אליך בשעה שצעקת. כל המעשים הגדולים האלה – הן בעניינו של אברהם, שהיה שורש לייסוד הצאצאים. במספרי גדלה שרה, ובמספרו של חברי הורם אברהם. כמה גדול מעמדו של משה, הנביא האדיר, בכל הנפלאות השונות שעשה בפקודת אדונו!"');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (395,'VI','51','מימר מדבק בשנים והעשרים אות',6000511,'לא מקרתה מאניה ולא צלוה מתקבלה אלא מן לבב מלי תתובה הן נקרי ולא נטר מד לה קרינן מה חנאה בדן מקרתה והן צלינן בלב מתשגל בחורן אלה ליתה צלוה מקבלה ולא בלישה מתהגבה נהי הלכים בתר תהות נפשה לא בתר תחמדות מרן באליל בכל יום אנן מזדמנים ודברי קשטה אנן מבטלים עד אמת חובים עד אמת מדונין לית מרה דעלמה בעי מנן דאה נבלש רתו ולית בן זכו נבלש איטבו בלא נצירו אי איטבו יתגלי לנן נבלש רחמים בלא דחלה אי רוחה יהי עם כן נבלש אנחמו בלא ארכנו אי אנחמו תיתי עם אהן אידנו מדעה דישום אהן אי יסברה','The reading is not beneﬁcial, the prayer not accepted, unless (they 
come) from a heart full of repentance. If we read and do not keep what we have 
read, what is the beneﬁt of such reading? If we pray with a heart preoccupied 
with something other than God, the prayer is not accepted and the request not 
answered. We walk afer the lust of (our own) soul, not afer the desire of our 
Master. We are involved in idolatry every day, and we abolish the words of the 
True One. How long sins, how long punishments? The Master of the world does 
not want this from us. We seek pity and there is no righteousness in us. We seek 
prosperity without devotion – what prosperity will be wrought to us? We seek 
mercy without fear – what relief will come with this? We seek comfort without 
humility – what comfort will come with this? What mind can appreciate this or 
hope for it?','הקריאה אינה מועילה, התפילה אינה מתקבלת, אלא אם כן (הן באות) מלב מלא בתשובה. אם אנו קוראים ואיננו שומרים את מה שקראנו, מה התועלת בקריאה כזו? אם אנו מתפללים בלב הטרוד בדבר מה שאינו האל, התפילה אינה מתקבלת והבקשה אינה נענית. אנו הולכים אחר תאוות נפשנו ולא אחר רצון אדוננו. אנו שקועים בעבודה זרה בכל יום ומבטלים את דברי האמיתי. עד מתי חטאים, עד מתי עונשים? אדון העולם אינו רוצה זאת מאיתנו. אנו מבקשים חנינה ואין בנו צדקה. אנו מבקשים שגשוג ללא מסירות – איזה שגשוג ייגרם לנו? אנו מבקשים רחמים ללא יראה – איזה הקלה תבוא עם זאת? אנו מבקשים נחמה ללא ענווה – איזו נחמה תבוא עם זאת? איזה שכל יכול להבין זאת או לקוות לו?');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (396,'VI','72','מימר מדבק בשנים והעשרים אות',6000721,'דן חראה דשקחת קמי כתוב בתיבת מרקה רצון יהוה עליו אמן ברוך אלהינו לעולם וברוך שמו לעולם לית אלה אלא אחד הכתב אהן כתבה על שם רבנה טבה ויקירה וידועה ומבוננה ומביר כל מימר חסיד מלב מלי פינחס בן רבה דקהלה הכהן הֿ גֿ דֿ וֿלֿ בדמשק איתמר בן אהרן בן איתמר בן אהרן בן אבי עזי בן פינחס בן אלעזר בן נתנאל בן אלעזר הכהנים הגדולים ישימו יהוה מברך עליו ויחננו בנים טבים יתילפו כל דכתיב לגוה אמן אמן',NULL,NULL);
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (397,'VI','10','מימר מדבק בשנים והעשרים אות',6000101,'אנשה יבעי אגר ועמל לית לה לית אגר אלא לקבל עמל רבותה לאלהנו דארשה לן עמלים עד יהב לן אגרים בקשיטו כל דבלש יהב צדקה בריחות נפשה הן בעה יהב והן בעה לא יהב ודעמל עם אנש ובלש מנה אגרה ליתו יכל יעזרנה ריקן עמי מה אמר אלה בדילה לא תלין פעלת שכיר אתך עד בקר גלה דתמן חוב גדול לא תכפץ את ידך מאחיך האביון ועבד אהן עובדה דו מטמר אקרה דו מצוי מצוה ואנשה דיקים יתה יתגזי בכל איקר','Man seeks his reward (even) while he has no merit. There is no reward 
but according to (appropriate) deed. Greatness to our God, who commanded 
actions so that He may give us rewards justly. Anyone who seeks to give charity 
by his own will – if he wants, he gives, and if he wants, he does not give. But he 
who has dealings with a man and (the man) asks for his pay from him, he is not 
permitted to turn him away empty-handed. See what God said concerning it: The 
wages of a laborer shall not remain with you all night until the morning (Lev. 19:13). 
He shows there is a great guilt: You shall not shut your hand against your needy 
brother (Deut. 15:7). Do such a deed, for it is kept with Him; He commands a 
commandment and the man who carries it out will be recompensed with all 
glory.','האדם מבקש את שכרו אף כשאין לו זכות. אין שכר אלא לפי המעשה הראוי. גדולה לאלוהינו, שציווה על מעשים כדי שיתן לנו שכר בצדק. כל מי שמבקש לתת צדקה מרצונו החופשי – אם ירצה, יתן, ואם ירצה, לא יתן. אך מי שיש לו עסק עם אדם ואותו אדם תובע ממנו את שכרו, אינו רשאי לשלחו ריקם. ראו מה אמר אלוהים על כך: לא תלין פעולת שכיר אתך עד בוקר (ויקרא יט,יג). הוא מראה שיש בכך אשמה גדולה: לא תאמץ את לבבך מאחיך האביון (דברים טו,ז). עשה מעשה כזה, כי הוא שמור אצלו; הוא מצווה מצווה, והאיש שיקיימנה יגמל בכל כבוד.');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (398,'VI','52','מימר מדבק בשנים והעשרים אות',6000521,'דאנה דחל לא נסתפי באדי בישים בעין מכלהתן כי מן אדם אנן עמין אהן חברי בישתה דבבי חברי קשטה רחם קין בישתה קטל הבל רבה קנאה בישה בדרי עלמה וכן עורי חזינן פנוי חכמתה דבבים לנהירי לבה לוט ואברהם השקחנן הדה אקרון כד הזדמנו לא הסתחנו ועוד יוסף עם תלימיו כד חזותה חכים גלו סנותה וילה אנש יהי לבה כדן ולא יזרז לאלפנה דו צריך לכן לבדיל כן הזהרן וכתב קמינן לא תשנא את אחיך בלבך בישה סנתה דבישתה רחמה יתה וטובי סנתה דקשטה חדי בה עמי סנתה דבישתה חדת בה סנת בר שלומית לקבל קהלה התרגם ולא התותר ביני חייה וסגי כותה אזלו עמה וחזו סנתה דקשטה חדי בה סנתה דפינחס מן עבודי בישתה כד קעם וגלה סנאה חוי בה קנומה וכל זרעה בתרה ופרק לישראל מן דינה וסלח עליון ועצר מגיפתה הדה סנתה כלה חיים טובי אנשה דישימה חלקה יתודי יכולה רבה דגלה לנן אלפן כהלה › חיים ‹ נתוחי בה לעלם','I fear lest we perish at the hands of evil men who seek to destroy us. 
Indeed, ever since Adam we have seen this. The owners of evil are the enemies of 
the owners of truth. Cain loved evil – he slew Abel. He propagated evil jealousy 
throughout the generations of the world. So too we have seen those devoid of 
wisdom, enemies of those illuminated in mind. Lot and Abraham – we have 
found this in their case. When they gathered, they were not friendly. Further-
more, Joseph with his brothers – when they saw that he was wise they manifest-
ed hatred. Woe to a man whose heart is like that, and who does not rush to learn 
what he needs to! Thus, He warned us and wrote before us: You shall not hate 
your brother in your heart (Lev. 19:17). Evil is the hatred which the one doing evil 
loves and blessed is the hatred over which the True One rejoices! See the hatred 
over which evildoing rejoices, the hatred of the son of Shelomith – he was 
stoned before the congregation and was not lef among the living. Many like that 
went with him. See the hatred with which the True One is pleased: the hatred of 
Phinehas for the doers of evil. When he rose up and manifested zeal, he thereby 
gave life to himself and (to) all his descendants afer him, and delivered Israel 
from punishment, and atoned for them, and halted the plague. Such hatred is 
wholly of life. Happy the man who makes it his share! Thanks be to the great 
Mighty One who revealed to us a teaching wholly of life, by which we will live 
forever.','אני ירא פן נאבד בידי אנשים רשעים המבקשים לאבדנו. אכן, מאז אדם ראינו זאת. בעלי הרשע הם אויבי בעלי האמת. קין אהב את הרשע – הרג את הבל. הפיץ קנאת רשע לאורך כל הדורות של העולם. כך גם ראינו את חסרי החכמה, אויבים של בהירי הדעת. לוט ואברהם – מצאנו זאת בעניינם. כשנאספו יחד לא היו ביניהם יחסי ידידות. יתר על כן, יוסף עם אחיו – כשראו שהוא חכם גילו שנאה. אוי לאיש שלבו כן, ושאינו ממהר ללמוד את מה שנחוץ לו! כך הזהיר אותנו וכתב לפנינו: לא תשנא את אחיך בלבבך (ויקרא יט,יז). רעה היא השנאה שאוהב עושה הרשע, וברוכה היא השנאה שבה שמח האמיתי! ראה את השנאה שבה שמחה הרשעה – שנאתו של בן שלומית: הוּרגם באבנים לפני הקהל ולא נשאר בין החיים. רבים כמוהו הלכו עמו. ראה את השנאה שבה רצה האמיתי: שנאתו של פינחס לעושי הרשע. כשקם וגילה קנאה, נתן בכך חיים לעצמו ולכל צאצאיו אחריו, והציל את ישראל מן העונש, וכיפר עליהם, ועצר את המגפה. שנאה כזו כולה חיים היא. אשרי האיש שהיא חלקו! תודות לגדול האדיר שגילה לנו תורה שכולה חיים, שבזכותה נחיה לעולם.');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (399,'VI','62','מימר מדבק בשנים והעשרים אות',6000621,'כד חסלו שבעתי כתביה דאתדכרו מן מגלי היטבוהתון במד בלשו והגלה רבינון למדעי הידעו » י « ם בלשו מדכרה במד חכמו והגלה לון מה חיב מדכרון ורבה דעתון בכל דר ודור שרו כתביה אמרים אף אנון לנביה רבה משה אה מן בחרה מרה דעלמה מאז אתיצר בקרב אמה ועתדה לפרקן מן יתה זבנה הן הות כתביה דבלשו מנך למה לא הזכרו בשרוי קציה וגלית לכל אחד מנון רבינה דלה אנחן למה דן הכתבנן בשרוי קציה אלית לכל אחד מנן מיתובה רמה','When the seven letters mentioned ﬁnished revealing their qualities, in 
regard to what they requested, and (when) their majesty had been revealed to 
the minds of the wise, they sought to mention what they knew and what had 
been revealed to them, and what was imperative to mention (in order to) in-
crease the knowledge of them throughout the generations. The (other) letters 
also began talking to the great prophet Moses: “O (you), the one whom the 
Master of the world chose from the time he was conceived in his mother’s womb, 
and He prepared him for deliverance (of Israel) from that time! If for each of the 
letters which asked you why they were not mentioned at the beginnings of the 
Qiṣṣīm you revealed to each of them its majesty, why then were we written in the 
beginning of the Qiṣṣīm since not one of us has a lofy rank?”','כשסיימו שבע האותיות האמורות לגלות את מעלותיהן, בנוגע למה שביקשו, וכשנתגלתה רוממותן לדעת החכמים, ביקשו להזכיר את מה שידעו ואת מה שנגלה להם, ואת מה שהיה מחויב להזכיר כדי להרבות את הכרתן בכל הדורות. גם האותיות האחרות החלו לדבר אל משה הנביא הגדול: "הו אתה, שאדון העולם בחר בו מעת שנוצר ברחם אמו, והכינו לגאולה מאותה שעה! אם לכל אחת מן האותיות שביקשו ממך מדוע לא הוזכרו בראשי הקיסות גילית לכל אחת מהן את רוממותה, מדוע אפוא נכתבנו אנו בראש הקיסות, כשאין לאחת מאיתנו מעלה רמה?"');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (400,'VI','29','מימר מדבק בשנים והעשרים אות',6000291,'עסרה כעסוהן › א ‹ כעסו והוה עובד אלפונה בניון מכן אמר אלה בדיל בניון וצרפו יתי עסרה זבנין עמי כעסוהתה דהוו עבדים בדיל יוסף הפכו חשבנון מן טובה אל בישה ואתנכלו למקטלנה והרמו יתה בגבוה אלין לבבים ברהים סכו דאנון מכסים שמש דזרחת מן יעקב ויתבו לאכל לחם אקשהו רבה לכן צרכו לה והזדהנו מנה וקעמו קדמיו , בדחלה רבה וזבנותה עבד ביש מה עבדו ואכלו כספה אה עובד ביש דגלותה לאבון ותמי › ע ‹ ון לבב הקימון בבהתה רבה דגלו לאבון והדמו בקין כד נפק לבראה וקטל ית הבל ולא ידעו דלב יוסף זכי לא יקרב לה בישה לעלם','They annoyed with ten provocations, which became a deed their chil-
dren learned. Therefore, God said concerning their children: They have put me to 
the proof ten times (ST Num. 14:22). See the provocations which they wrought 
regarding Joseph. They turned their thinking from good to the evil and they 
conspired against him to kill him and they cast him into the pit. These are alien 
hearts. They sought to conceal the sun which shone from Jacob. They sat down to 
eat bread (Gen. 37:25) – great mercilessness. For that they had need of him and 
were supplied by him and stood before him in great fear. They sold him – what 
they did is an evil deed! They ate his purchase price. Behold, an evil action 
which they wrought against their father. Consternation placed them in great 
shame. They lied to their father and became like Cain when he went out into the 
ﬁeld and slew Abel. They did not know that the heart of Joseph was pure, no evil 
will ever touch him.','הם הכעיסו בעשרה ניסיונות, שנעשו למעשה שלמדו ילדיהם. לפיכך אמר אלוהים על ילדיהם: וינסו אותי זה עשר פעמים (תרגום שומרוני במדבר יד,כב). ראה את ההכעסות שעשו בעניין יוסף. הם הסיטו את מחשבתם מן הטוב אל הרע, וקשרו עליו להרגו והשליכו אותו אל הבור. אלו הם לבבות זרים. ביקשו להסתיר את השמש שזרחה מיעקב. וישבו לאכול לחם (בראשית לז,כה) – אכזריות גדולה. כי על כן נזקקו לו, והוא כלכל אותם והם עמדו לפניו ביראה גדולה. מכרוהו – מה שעשו הוא מעשה רע! אכלו את מחיר מכירתו. הנה מעשה רע שעשו כלפי אביהם. הבהלה שמה אותם בבושה גדולה. שיקרו לאביהם ונעשו כקין כשיצא אל השדה והרג את הבל. לא ידעו כי לב יוסף טהור היה, ולא תיגע בו רעה לעולם.');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (401,'VI','16','מימר מדבק בשנים והעשרים אות',6000161,'כמד יקרותה אלין ארכן עלמה קדמיו ואמר יתרבי דן נביה דרבתה מרה והוה מלוא בכן עמונה עלול לגו אשתה עד יסב מן ימין אלה לוחי בריתה כיר אדה דקשטה כד צבה אלה ויהב כיר אדה לנביה רבה משה לגו תרי לוחי בריתה מבתר דשמע קלה לישראל לעל מטור סיני כתבון מתרי איצרי לוחיה מדן ומדן בתר כן עזר משה ודרש מלי רחמיה דאנון שמהת עקובאן אתחזי מרן וכתב קדמיו אלין כתביה דכתבון בגדלה','Just as these honored him, so the world bowed before him and said: 
“Exalted is this prophet; his Master elevated him and he was worthy of it.” See 
him enter into the ﬁre to receive from the right hand of God the tablets of the 
covenant, the handwriting of the True One. When God willed it and gave His 
handwriting to the great prophet Moses in the two tablets of the covenant, afer 
He had made Israel to hear His voice above Mount Sinai, He wrote them on both 
sides of the tablets, on this side and on this side. Afer this Moses went back and 
requested the “words of mercy” which are attributive names. Our Master ap-
peared and wrote before him these letters, which He wrote by His greatness.','כשם שאלה כיבדוהו, כך השתחווה העולם לפניו ואמר: "נשגב הנביא הזה; אדונו הרימו והוא היה ראוי לכך." ראהו נכנס אל האש לקבל מימין האלוהים את לוחות הברית, כתב ידו של האמיתי. כאשר חפץ אלוהים ונתן את כתב ידו לנביא הגדול משה בשני לוחות הברית, לאחר שהשמיע את ישראל לשמוע את קולו מעל הר סיני, כתב אותם משני עבריהם, מצד זה ומצד זה. לאחר מכן חזר משה וביקש את "דברי הרחמים", שהם שמות התואר. אדוננו נגלה וכתב לפניו את האותיות הללו, שכתב בגדולתו.');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (402,'VI','46','מימר מדבק בשנים והעשרים אות',6000461,'תמן הגיב משה אלין מליה הגבו קשיטה מכללה בחכמה כהלה אור רב הוא הדה דבה הפרדתי ואתי מרביה לי ולבריתה אורה לך ארעה לך מיה לך ושרוי ממללה לך ואוצרי רקיעיה לך וממלל יצחק לך וממלל יוסף עם פרעה לך וכל מה דאתעבד לי בידיך הוא ואתי סהד רב על כן ובסור אנש באיקר לך הו פם ברנשה ריש אוצרה אמת דיפתח יתחכם מד בה הן הוה דמע הוא ליהוה אי פסול יהי משתבק וגזוי אהן ואהן מתחכם וכן אמר לי מרי ולאהרן אחי ואנכי אהיה עם פיך ועם פיו ובזבן יקרי וגלה יקירותי אמר לאהרן ולמרים פה אל פה אדבר בו מן אהן מקומה התודעת מיתוביתך אקר מרך מיסתיך פ כל אהן איקרה רבה דבה התוקרתי רבותה לאלה דלית במליו מלה אלא ובה חכמה טובי לאנש דימלכה','Then Moses answered: “These words are a true answer, crowned with 
wisdom, all of it light. Great is this (matter) by which you set me apart. You ele-
vate me as well as Creation. The light belongs to you; the earth belongs to you; 
the water belongs to you. The beginning of speech belongs to you; the treasures 
of the ﬁrmament belong to you. The speech of Isaac belongs to you, and Joseph’s 
speech with Pharaoh belongs to you. Everything that has happened to me has 
come about through you. You are a great witness to this. The good tidings of 
glory to men belong to you. The mouth of men is the doorway to treasure – when 
it is opened, what is in it will be known. If it is choicest, it is for the Lord; if it is 
blemished, it should be abandoned; the recompense for the one and the other is 
known. So my Lord said to me and to Aaron my brother: And I will be with your 
mouth and with his mouth (Ex. 4:15). At the time when He honored me and re-
vealed my glory, He said to Aaron and Miriam: With him I speak mouth to mouth 
(Num. 12:8). From this place, your status with your Lord was made known. 
Enough for you, O ,פthis great glory with which you were gloriﬁed.” Greatness to 
God, in whose words there is nothing but wisdom. Happy the man who pos-
sesses it.”','אז ענה משה: "דברים אלה הם תשובה אמיתית, עטורה בחכמה, כולה אור. גדול הדבר הזה שבו הבדלת אותי. אתה מרומם אותי ואת הבריאה כאחד. האור שייך לך; האדמה שייכת לך; המים שייכים לך. ראשית הדיבור שייכת לך; אוצרות הרקיע שייכים לך. דברי יצחק שייכים לך, ודברי יוסף עם פרעה שייכים לך. כל שאירע לי בא על ידך. אתה עד גדול לכך. הבשורות הטובות של הכבוד לבני אדם שייכות לך. פי האדם הוא פתח האוצר — כשהוא נפתח, יודעים מה בתוכו. אם הוא מובחר, הרי הוא לשם ה''; אם הוא פגום, יש להניחו; שכר האחד ועונש השני ידועים. כך אמר לי אדוני ולאהרן אחי: וְהָיִיתִי עִם פִּיךָ וְעִם פִּיהוּ (שמות ד,טו). בשעה שכיבד אותי וגילה את כבודי, אמר לאהרן ולמרים: פֶּה אֶל פֶּה אֲדַבֶּר בּוֹ (במדבר יב,ח). מכאן נודע מעמדך לפני אדונך. די לך, פ, בכבוד הגדול הזה שבו נתכבדת." גדולה לאל, שאין בדבריו אלא חכמה. אשרי האיש שיש בידו אותה.');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (403,'VI','36','מימר מדבק בשנים והעשרים אות',6000361,'אה קהלה הדבק בדן יומה וחכם איקרה יומה דבה בישתה אזלה ולית לה תקומה יומה דבה פנותה מקצעה מן עלמה ורחותה מתגליה יומה דבה › ה ‹ צרר מתנפש ולא ישתיר בעבדותה עמו רביאן אהן יומה ואתחידו בה ולא תשתבקו מן איקרה מה טב אהן יומה טובי כל רחמיו ביתה יומה יסלח יהוה לכל נפש דבה תנצר נודי לאלה דגלתה לנן ועבדה הך יובל יפרק בה כל נפש אה נשישי חילו כחיכון ותפשו אהן איקרה רבה דעתיד לוכון אה ארצמיה הולו רבחה ואנשמותה אה אסירי חוביה קוו סליחתה וקדמו אהן יומה רבה בעסרה גונין טבין קדישות יצר ודכיות פגר וקשיטות ממלל ותעתיד טב וכשרן גול ושלמות עובד ולבב אנציר וענין אתי וחיל מתקומם ורב אנחמו אלין אנון מרבין אשר ימלך יתון','O congregation, cling to that day and know the glory of the day when 
evils will depart with no return, the day when Disfavor will be cut oﬀ from the 
world and Favor will be revealed, the day when distress will be relieved and 
(nobody) will remain in slavery. See the majesty of this day and cling to it, and 
you will not be abandoned by its glory. How good is this day! Happy are all His 
devotees. On that day the Lord will forgive every soul who is devoted (to Him). 
Let us thank God who revealed it to us and made it as a jubilee upon which every 
soul is released. O weak ones, strengthen your power and take hold of this great 
glory prepared for you. O oppressed ones, cling to relief and rest. O prisoners of 
sins, hope for forgiveness and meet that great day with ten good things: holiness 
of conscience, purity of body, true speech, well-preparedness, fervent 
righteousness, perfection in action, devotion of heart, presence of mind, stead-
fast strength, abundant repentance. These are (matters) which will exalt him 
who possesses them!','הו עדה, דבקו באותו יום ודעו את כבוד היום שבו יסורו הרעות ולא ישובו, היום שבו תיכרת הרוגזה מן העולם ותיגלה הרצוּן, היום שבו תוּקל הצרה ולא ישאר איש בשעבוד. ראו את הוד היום הזה ודבקו בו, ולא תיעזבו על ידי כבודו. כמה טוב היום הזה! אשרי כל חסידיו. באותו יום יסלח ה'' לכל נפש הדבוקה בו. נודה לאלוהים שגילה אותו לנו ועשאו כיובל שבו משתחררת כל נפש. הו חלשים, חזקו את כוחכם ואחזו בכבוד הגדול הזה המוכן לכם. הו מדוכאים, דבקו בהקלה ובמנוחה. הו אסורי החטאים, יחלו לסליחה ופגשו את היום הגדול ההוא בעשרה דברים טובים: קדושת המצפון, טהרת הגוף, דיבור אמת, הכנה נאותה, צדקה לוהטת, שלמות במעשה, מסירות לב, נוכחות התבונה, חוזק מוצק, תשובה שופעת. אלו הם הדברים שירוממו את מי שבידו הם!');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (404,'VI','61','מימר מדבק בשנים והעשרים אות',6000611,'ירום נביה רבה משה דכתב בקצה דבה ברך ישראל קבע ארש לא יבטל לעלם אה קהלה למה דן תעבד קנומך ריק מכל אהן ותשבק אורה ותלך בחשכה ותעבד לבראיה עליך אד יכלה למה תהי אכפן וקמיך פתור סדיר עליו כל איקר למה תהי עבד ואת אמסיר למלכו ולך דרגה רמה ירתה מן אבהתך למה תהלך בתר דבביך בבהתה ולית לך ריש תתלינה קמיו ואלה אמר לך והם תכו לרגליך ומד תימרנה מן פמך ישמעו יתודי אלה דבחרך אה ישראל ואוי לך ישראל במד בחרת לנפשך שוב אל מרך דו רחמן ורתאה מקבל כל תהב דיתוב לידה בנצירו טבה היא תתובתה וטבין רחומיה אנון זעיקין עם קדש הפתחו תרח טובה ועלו בה בשלם ודערו תמן בשלם טבה תתובתה דהי תרח גנתה דאילניה טובים טוב למן ילקט ממנה וייכל לברכתה יהי נסב ומרה לה מעיני וכל איקר יחזה רגזה מנה מסתלק ומרה רצי עליו ולבה חדי הנה ושמה','Exalted be the great prophet Moses who wrote in the Qiṣṣa (words) in 
which he blessed Israel – he established a foundation which will never be 
abolished. O congregation, why do you make yourself devoid of all this and 
forsake the light and walk in the darkness and let the aliens have control over 
you? Why are you hungry when there is a table set out before you on which 
appears every glory? Why are you a slave when you were appointed for kingship 
and you have a lofy rank – heritage from your forefathers? Why do you follow 
your enemies in shame and have no head to lif before them when God said to 
you: They submitted to your steps (Deut. 33:3) – and they listen to what you say 
with your mouth? Thanks be to God, who chose you, O Israel; and woe to you, O 
Israel, for what you have chosen for yourself. Turn back to your Master, for He is 
merciful and pitiful (Exod. 34:6), accepts every penitent who turns back to him in 
devotion. The repentance is good and those who love it are also good. They are 
called a holy people (Exod. 19:6). Open the gate of good and enter by it in safety 
and dwell there in peace! Repentance is good, for it is the gate of the Garden 
whose trees are good. Happy the one who plucks from it and eats. He will take 
the blessing and his Master will guard him. He will see all glory. Wrath will 
depart from him, and his Master will be favorable towards him, and his heart 
will rejoice both here and there.”','מרומם יהיה משה הנביא הגדול, שכתב בקיסה דברים שבהם בירך את ישראל – הניח יסוד שלא יבוטל לעולם. הו עדה, מדוע אתם מרוקנים עצמכם מכל זה ועוזבים את האור והולכים בחשכה ומניחים לנכרים לשלוט בכם? מדוע אתם רעבים כשיש לפניכם שולחן ערוך שעליו נגלה כל כבוד? מדוע אתם עבדים כשנועדתם למלכות ויש לכם מעלה רמה – נחלה מאבותיכם? מדוע אתם הולכים אחרי אויביכם בבושה ואין לכם ראש להרים לפניהם, כשאלוהים אמר לכם: "תכו לרגליך" (דברים לג,ג) – והם מקשיבים לכל מה שאתם אומרים בפיכם? תודה לאל שבחר בכם, ישראל; ואוי לכם, ישראל, על מה שבחרתם לעצמכם. שובו אל אדונכם, כי הוא "רחום וחנון" (שמות לד,ו), מקבל כל שב בתשובה החוזר אליו במסירות. התשובה טובה ואוהביה טובים גם הם. הם נקראים "עם קדוש" (שמות יט,ו). פתחו את שער הטוב וכנסו בו בשלום ושכנו שם בשלווה! התשובה טובה, כי היא שער הגן שעציו טובים. אשרי מי שקוטף ממנו ואוכל. הוא יקבל את הברכה ואדונו ישמרנו. הוא יראה כל כבוד. החרון יסור ממנו, ואדונו יחפוץ בו, ולבו ישמח גם כאן וגם שם."');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (405,'VI','3','מימר מדבק בשנים והעשרים אות',6000031,'ועמי ארבעתיתה דגדלת צעורתה ודע דבך סהדים רמים כד הכללת צעורתה בצבית עבודה מן ארבעה אקרים חלצון בגדלה עבד בגוך ארבעה חלקים עדהן קעמת והגדלת ביכלו יצר וענין ורז וחשבה אכסין בך ודברא יתון ידע אמנון וכל אחד מהם לה פרנוס חיול בגויתך אנדי בוננותך אה בלוש חכמתה ואתב נפשך ואתילף מד בה טובך ולא תתרחק מן צעורך בעובד מהו מכה לך תהי דבב לקשטה וישרי בך כל ערוי וכרז בכל עת בלבך ונפשך לית אלה אלא אחד צדיק » ו « ישר נכבד כסי וגלי אידן מלך יכל קעם קבלה כלילה חיי עולם חייה שאילה מנה עד זבן והוא מלוך כל זבניה לכלה ברא ולכלה צער ולכלה סבל ברב יכלותה','See the four (things) that developed the form and know that in yourself 
there are elevated witnesses. When the form was perfected by the will of its 
Maker from four elements that He created in His greatness, He made in you four 
properties, until you were set up and grew up with strength: conscience, thought, 
innerness, and reason, hidden within you. He who created them knows their 
habits. Each one of them has a powerful control over your body. Pay attention, O 
seeker afer wisdom, settle yourself and learn what is good for you. Do not dis-
tance yourself from your Creator by a deed that will harm you, for you would 
then be an enemy to the True One, and there would dwell within you every 
mishap. Proclaim at all times in your heart and soul: “There is no god but One, 
Just and Upright (Deut. 32:4), Glorious, Hidden, Manifest.” What king can stand 
before Him? His crown is eternal life. Life is borrowed from Him for a moment, 
and He is the owner of all moments. He created all and shaped all, and He sus-
tains all by His great power.','ראה את הארבעה שפיתחו את הצורה ודע כי בך עדים נעלים. כשהושלמה הצורה ברצון יוצרה מארבעה יסודות שברא בגדולתו, עשה בך ארבע תכונות, עד שנכוננת וגדלת בעוצמה: מצפון, מחשבה, פנימיות ושכל, הסמויים בקרבך. מי שבראם יודע את דרכיהם. לכל אחד מהם שליטה עצמית על גופך. הקשב, מבקש החכמה, יישב עצמך ולמד מה טוב לך. אל תתרחק מבוראך במעשה שיזיק לך, שכן אז תהיה אויב לאמת, וישכון בך כל אסון. הכרז בכל עת בלבך ובנפשך: "אין אלוה כי אם אחד, צדיק וישר" (דברים לב,ד), "מפואר, נסתר, נגלה." איזה מלך יוכל לעמוד לפניו? כתרו הוא חיי נצח. החיים שאולים ממנו לרגע, והוא בעל כל הרגעים. ברא את הכל ויצר את הכל, ומחיה את הכל בכוחו הגדול.');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (406,'VI','34','מימר מדבק בשנים והעשרים אות',6000341,'דעי אה נון כל איקרה דאוקריך בה אלהים כהנתה ביך מתקוממה עד לעלם עלמים וילה אנש דיהי קמיו אור וילך לגו חשך אפיל אה אור מניר נורה דכהנתה › על ‹ כל קהל ישר בה ממלכין לא לאוי לן נשבק אהן נהרה רבה דמרבי יתן בכל דר ודר דמות אהרן מן יהי לגו עלם יהי אי אלעזר אי פינחס אי שבשביה דמנה נפקת עבידה בריה מרביה ישר כי אמר אלה והיתה לו ולזרע אחר ברית כהנת עולם בסרה לה ולישראל כל דבב דלון ימחק קדמון כמה דאמר מחץ מתני קעמיו יתודי אלה רחמנה דיקר כהנתה ורבה מיתוביתה סגי מכל מיתובהתה','“Know, O ,נall the glory with which God has honored you. The priest-
hood subsists in you for ever and ever. Woe to any man before whom there is 
light and yet who walks in deep darkness. Behold a light, the light of the priest-
hood, that illumines the whole of the congregation of Israel. They are led by it. It 
is not appropriate for us to forsake this great light, which elevates us throughout 
the generations. Who is ﬁt, like Aaron, to exist in the world? Or Eleazar, or 
Phinehas, or the descendants which emerged from him? The covenant was made 
to elevate Israel, for God said: And it shall be to him, and to his descendants afer 
him, the covenant of a perpetual priesthood (Num. 25:13) – good tidings for him 
and for Israel: every enemy of theirs will be blotted out before them, as He said: 
Crush the loins of his adversaries (Deut. 33:11). Thanks be to the Merciful God who 
honored the priesthood and magniﬁed its rank above all ranks.”','דע, הו נ, כל הכבוד שבו כיבד אותך האלוהים. הכהונה שוכנת בך לעולם ועד. אוי לאדם שלפניו אור ועם זאת הולך בחשכת אפלה. הנה אור, אור הכהונה, המאיר את כל עדת ישראל. הם מונהגים על ידו. אין זה ראוי לנו לזנוח את האור הגדול הזה, המרומם אותנו לאורך הדורות. מי ראוי, כמו אהרן, להתקיים בעולם? או אלעזר, או פינחס, או הצאצאים שיצאו ממנו? הברית נכרתה כדי לרומם את ישראל, שכן אמר האלוהים: וְהָיְתָה לּוֹ וּלְזַרְעוֹ אַחֲרָיו בְּרִית כְּהֻנַּת עוֹלָם (במדבר כה,יג) – בשורה טובה לו ולישראל: כל אויביהם יימחו מלפניהם, כפי שאמר: מְחַץ מָתְנַיִם קָמָיו (דברים לג,יא). תודה לאל הרחמן שכיבד את הכהונה והגדיל את מעמדה על פני כל המעמדות.');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (407,'VI','54','מימר מדבק בשנים והעשרים אות',6000541,'תמן הגיב נביה רבה משה לקבל אלין מליה הגבו מרבי שמועה לך אה קוף רב מכן מד רביך לאברהם והכלל איקרה במניאניך עורי וביום שבתה קעמתי ורביתי יתה וגליתי איקרה לכל דריה וביומה דבה קהל יהוה מתפרק גליתי פרקן מרבי מלוכה ובה ישראל חדים פריד בקדש ואמר נביה מהימנה מימר כהלה כשרן אנשמי אה מלתה בריכה כי בקוממותיך חייה ובבטוליך אבדנה אמת דאתי מוקמה חיים ואמת דאתי בטלה אבדן יתר שלמו לקהל דו לך נטיר וחסרן לקהל דו לך חסיר אוי לדר אתי בה חסיכה לית לגוה נאר ולא נחום מתעמי 55] תמן קעמת והגיבת יתה טכח יהי מעזרה ליד קשטה הלא כסיהתה ליה [ וגליהתה אמת דו בעי יעבד אהן אה בית ביש מכעס וכל לגוה ביש אה קהלה הב בלך מן יתה ביתה ולא תעבר לידה כי לית בחילך מהפך יתה הן תסנינה איקרך על מה דו והן תרחמנה חסילה הי מנך הן תימר ליתי עבר לידה שם יהוה מתקרי עליך וידחלו כל דבביך מנך ואיקר אבהתך ממן לך ומד כרתו לך ליתו מתחלף מנך לעלם אתעיר לגרמך במד לה תחכם מן שלמות עובד ירבי מלוכה','Then the great prophet Moses answered these words, an answer that 
magniﬁes the hearer: “For you, O ,קthere is greater than that, for you exalted 
Abraham and his glory was perfected by your number as well. On the day of 
Sabbath you stood and exalted it and revealed its glory to all the generations. On 
the day when the congregation of the Lord was delivered, you revealed a salva-
tion which magniﬁes its possessor. In it Israel rejoices, unique (it is) in holiness.” 
The faithful prophet spoke a word entirely right: “Be at rest, O blessed word 
( ,)קוףfor in your existence there is life, and in your ceasing, destruction. For as 
long as you exist there is life, but when you cease there comes exceptional 
destruction. Perfection to the congregation which keeps you, and loss for the 
congregation which lacks you. Woe to a generation from which you are withheld! 
There is no light in it, and no comfort is seen.”','אז ענה משה הנביא הגדול דברים אלה, תשובה המרוממת את שומעה: "בשבילך, הה קוף, יש דבר גדול מזה, כי אתה רוממת את אברהם וכבודו הושלם על ידי מספרך גם כן. ביום השבת עמדת ורוממת אותו וגילית את כבודו לכל הדורות. ביום שבו נגאלה עדת ה'', גילית ישועה המרוממת את בעליה. בה שמח ישראל, יחיד הוא בקדושה." הנביא הנאמן אמר דבר נכון לגמרי: "נוחי, הה מילה ברוכה, קוף, כי בקיומך יש חיים ובחדלונך יש כליון. כל זמן שאת קיימת יש חיים, אך כאשר את פוסקת בא כליון יוצא דופן. שלמות לעדה השומרת אותך, וחסרון לעדה הנעדרת אותך. אוי לדור שממנו את נמנעת! אין בו אור ואין נחמה נראית."');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (408,'VI','66','מימר מדבק בשנים והעשרים אות',6000661,'וחסלת א מן ממללה אתת ב וקעמת ומללת ואמרת אה נביה רבה דאנשא אתרה בכל דרי עלמה אתהו מהימנה דאימנך אלה על מה דאזל ועל מה דאתי מד קמי בראשית לך הגלה ומד בתר יום נקם חכמתנה מודאה לאלה דאסגל יתך בכן האן נביא בעלמה כותך שמע ממללי דאני ממללה כל חכמה מנך אתחכמת מה אנה שרוי כתבה דארשך מרך בבירו מה תרי לוחיה במניאני וכל זבוג חסד בי יהי הגיבה נביה רבה משה לך סגי מכן אתי הוקמתי עקר בגוני טבהתה בשבעה חזואן טבהן אתחברתי וביך הכלל אורה וביך אתחסל עלמה ורביניך סגי מכן','When אﬁnished speaking, בcame and stood; it spoke saying: “O great 
prophet whose position has been exalted throughout the generations of the 
world. You are the faithful one whom God appointed over what has passed and 
what is yet to come. That which preceded Creation was revealed to you and you 
know that which (is to be) afer the Day of Vengeance. Thanks be to God who 
chose you for this. Where is there a prophet in the world like you? Hear the 
speech that I say: all wisdom has been made known from you. Am I not the be-
ginning of the book which your Master commanded you to write? Are not the two 
tablets in my number? And is not every good coupling in me?” The great prophet 
Moses answered to it: “You have more than that. You were established (as) a fun-
dament in all kinds of good things. You were associated with seven good visions, 
and by you the light was perfected. By you the world was completed. Your state 
is (even) greater than that.”','כשסיים א לדבר, בא ב ועמד; דיבר ואמר: "הו נביא גדול שמעמדו נתרומם לאורך דורות העולם. אתה הנאמן שמינה אותו האלוהים על מה שעבר ועל מה שעתיד לבוא. מה שקדם לבריאה נגלה לך ואתה יודע את שיהיה אחר יום הנקם. תודה לאל שבחר בך לכך. היש בעולם נביא כמוך? שמע את הדברים שאני אומר: כל החכמה נודעה ממך. האם אינני ראשית הספר שציווה אדונך לכתוב? האם אין שתי הלוחות במספרי? והאם אין כל זיווג טוב בי?" ענה אליו משה הנביא הגדול: "יש לך יותר מזה. הוצבת כיסוד לכל מיני טובות. נקשרת לשבע חזיונות טובות, ובך נשתלם האור. בך נסתיים העולם. מעמדך גדול אף מכך."');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (409,'VI','44','מימר מדבק בשנים והעשרים אות',6000441,'אהנו מקומה קמאה דקעמת לגוה עמי כל מה עביד לגוה מקומה תניאנה קעמת בארעה ופתחת בה כל אוצר טב דמלא יתון רחמנה מכל איקר מספק לצריכים מקומה תליתה קעמת בארעה עד הכללת בתרי זבנין מקומה רביעיה קעמת במיה עד הפקת מנה גוני תמחים מק חמישה קעמת על תרח זכותה ורבית בניון מקומה אשתיתה קעמת עם יצחק בתלתה זבנין זבנה קמאה והוא טלי פתח ית פמה ושאל שיאל קשט זבנתה תניאנתה על מד שאל התאגב וכן הוה תמן פתח פמה וברך לאלה אלהיה דבחר יתה לכן זבנתה תליתה לבש ברכהן רברבהן לה ולזרעה בתרה טב לי כדו אודי למלכה רחמנה דאפרשי לדן עובדה ובחרנה לי','“This is the ﬁrst episode in which I stood. See all that took place therein. 
The second episode: I stood on the earth and I opened up all good treasure in it, 
which the Merciful One ﬁlled with all glory to supply those in need. The third 
episode: I stood on the earth, until it was made perfect twice over. The fourth 
episode: I stood in the water, until I took out from it all kinds of wonders. The 
ﬁfh episode: I was at the gate of righteousness and brought up their children. 
The sixth episode: I was with Isaac on three occasions, the ﬁrst when he was a 
child, when he opened his mouth and asked a right question. On the second 
occasion, he received an answer concerning what he asked. And so it was afer 
that: he opened his mouth and blessed the God of gods who chose him for that. 
On the third occasion, he wore great blessings, for him and his descendants afer 
him. It is good for me now to give thanks to the Merciful King, who selected me 
for this deed and chose it for me.”','"זהו הפרק הראשון שבו עמדתי. ראה את כל שאירע בו.
הפרק השני: עמדתי על האדמה ופתחתי בה את כל אוצרות הטוב, שהרחמן מילא בכל כבוד כדי לספק את צורכי הנזקקים. הפרק השלישי: עמדתי על האדמה עד שנשלמה פעמיים. הפרק הרביעי: עמדתי במים עד שהוצאתי מהם כל מיני נפלאות. הפרק החמישי: הייתי בשער הצדק והעליתי את ילדיהם. הפרק השישי: הייתי עם יצחק בשלוש הזדמנויות — הראשונה כשהיה ילד, כשפתח את פיו ושאל שאלה נכונה. בהזדמנות השנייה קיבל תשובה על מה שביקש. וכך היה אחרי כן: פתח את פיו וברך את אלוהי האלוהים שבחר בו לכך. בהזדמנות השלישית לבש ברכות גדולות, לו ולצאצאיו אחריו. טוב לי עתה להודות למלך הרחמן, שבחר בי למעשה זה ובחרו עבורי."');
INSERT INTO tm_sections (id,book,section,book_title,sort_key,aramaic,english,hebrew) VALUES (410,'VI','2','מימר מדבק בשנים והעשרים אות',6000021,'עבד עשרה סהדים בחילה מודעים דו גדול וגיבור זבן אורה וזבן חשכה תרין סהדין לא מטלט » ל « ין לעלם וארבעתי זבניה דיתבון בחילה אקימון ארבעה סהדים וכן ארבעתי ארשיה דרבו צעורתה עמי אלין ודע דאנון סהדין מסידין עליו דו אחד לקלומה כד גלה אורה ואתחזי לכל עלמה ויתבה בגדלה חלץ מנה אורה דשמשה ואף } ו { זהרה וגם כל כוכביה כמד אתריח לאורה זבן ולחשכה זבן הדה על יתוב והדה על יתוב ארבעתי זבניה לית לאחד עם אחד נמי עם חברה שרוי זבניה הך אמה טבה מולדה בנים ואחסה עליון דאנון רכיכים צריכין אל אחסה עליון לאלא תיתי עקה ייאבדו כהלון כעטף זבנה תניאנה כות אב טב מרבי בניה באיקרה עדהן יגדלו ויתעמי מנון כל פר נחמד למראה וטוב למאכל והן אמטת בון אד גברו לא פר יתחזי ולא טרף זבנה תליתה זבנה דכלולה כל מה אתעבד בתריה מכלל הוא לגוה והן הוה תמן ניוש בחילה כלה אביד בשעתה לית לה קוממו זבנה רביעיה מרבי העקרים לכל אלין זבניה דאתדכרו עמי יתוב דאה הארבעה ודע דאתה צריך תהי מדמי לון אתילף מן אלין והכשב מדעך נעירו','He created ten witnesses by His might, which attest that He is great and 
mighty: the period of light and the period of darkness, two witnesses that never 
change. And the four seasons which He established by His might, He set them 
(as) four witnesses, and also the four fundaments which fostered the creation. 
See these things and know that these witnesses testify of Him that He is one by 
Himself. When He created the Light, it was manifest to the whole world, and He 
established it by His greatness. He extracted from it the light of the sun, as well 
as that of the moon and of all the stars at will: a time for the light and a time for 
the darkness, each according to order. The four seasons – none of them has a 
share with another. The ﬁrst of the seasons is like a good mother giving birth to 
children and having compassion for them, when they are weak and need com-
passion, lest mishap should come and all of them perish in an instant. The 
second season is like a good father, who brings up his children in comfort so that 
they may grow up, and that every fruit desirable to behold and good to eat may 
be seen in them. For if the hand of violence were to reach them, no fruit would 
appear and no bough. The third season is the season during which all that took 
place in the (preceding) two is perfected. If there was any weakness in its power, 
everything would perish in an instant, without any survival. The fourth season 
develops the elements of all these seasons that have been mentioned. See the 
order of these four and know that you should resemble them. Learn from these 
and submit your mind to wisdom.','ברא עשרה עדים בגבורתו, המעידים כי גדול הוא ועצום: תקופת האור ותקופת החושך – שני עדים שאינם משתנים לעולם. וארבע העונות שכונן בגבורתו – הציבן כארבעה עדים, וכן ארבעת היסודות שטיפחו את הבריאה. ראה את הדברים האלה ודע כי עדים אלה מעידים עליו שהוא אחד בפני עצמו. כשברא את האור, נגלה לכל העולם, וכוננו בגדולתו. הוציא ממנו את אור השמש, וכן את אור הירח וכל הכוכבים כרצונו: עת לאור ועת לחושך, כל אחד לפי סדרו. ארבע העונות – אין לאחת מהן חלק באחרת. הראשונה שבעונות דומה לאם טובה היולדת ילדים ומרחמת עליהם בהיותם חלשים וזקוקים לרחמים, פן יבוא אסון ויאבדו כולם ברגע אחד. העונה השנייה דומה לאב טוב המגדל את ילדיו בנוחות למען יגדלו, וייראה בהם כל פרי נחמד למראה וטוב למאכל. שכן אם הייתה יד האלימות מגיעה אליהם, לא היה נראה פרי ולא ענף. העונה השלישית היא העונה שבה מושלם כל אשר התרחש בשתיים הקודמות. לו היה חולשה בכוחה, היה הכל אובד ברגע אחד, ללא שריד. העונה הרביעית מפתחת את יסודות כל העונות שנזכרו. ראה את סדרן של ארבע אלה ודע שעליך להידמות להן. למד מהן ושעבד את מחשבתך לחכמה.');

